# Optional background OTP mail worker (kept off by default; enable via config.ENABLE_OTP_MAIL_WORKER=True)
OTP_WORKER_THREAD = None
OTP_WORKER_ENABLED = bool(getattr(config, "ENABLE_OTP_MAIL_WORKER", False))
OTP_WORKER_INIT_LOCK = Lock()
OTP_WORKER_INIT_ATTEMPTED = False
OTP_WORKER_DISABLED_REASON = ""
def _start_otp_worker_if_enabled():
    """
    Start the OTP mail worker loop in a background thread (once per process).
    Uses config.OTP_WORKER_POLL_SECONDS for polling frequency if provided.
    """
    global OTP_WORKER_THREAD, OTP_WORKER_INIT_ATTEMPTED, OTP_WORKER_DISABLED_REASON
    if not OTP_WORKER_ENABLED:
        return
    if OTP_WORKER_DISABLED_REASON:
        return
    # Avoid double start under Werkzeug reloader
    if app.debug and os.environ.get("WERKZEUG_RUN_MAIN") != "true":
        return
    if OTP_WORKER_THREAD and OTP_WORKER_THREAD.is_alive():
        return
    with OTP_WORKER_INIT_LOCK:
        if OTP_WORKER_THREAD and OTP_WORKER_THREAD.is_alive():
            return
        if OTP_WORKER_INIT_ATTEMPTED:
            return
        OTP_WORKER_INIT_ATTEMPTED = True
        try:
            otp_mail_worker = importlib.import_module("modules.otp_mail_worker")
            interval = int(getattr(config, "OTP_WORKER_POLL_SECONDS", 5))
            t = Thread(
                target=otp_mail_worker.main_loop,
                kwargs={"poll_interval_seconds": interval},
                daemon=True,
            )
            t.start()
            OTP_WORKER_THREAD = t
            print(f"OTP mail worker started (poll every {interval}s)")
        except ModuleNotFoundError as e:
            OTP_WORKER_DISABLED_REASON = f"Missing dependency: {getattr(e, 'name', str(e))}"
            print(f"OTP mail worker disabled: {OTP_WORKER_DISABLED_REASON}")
        except Exception as e:
            OTP_WORKER_DISABLED_REASON = str(e)
            print(f"OTP mail worker disabled: {OTP_WORKER_DISABLED_REASON}")

# ===================== Session policies ======================
IDLE_TIMEOUT_SECONDS = 30 * 60  # 30 minutes
ACTIVE_SESSIONS = {}  # username -> session id (sid)
_ACTIVE_USERS_LAST_SNAPSHOT = None
_ACTIVE_USERS_LOG_LOCK = Lock()


def _safe_bool_setting(name: str, default=False) -> bool:
    raw = os.getenv(name)
    if raw is None:
        raw = getattr(config, name, default)
    if isinstance(raw, bool):
        return raw
    return str(raw).strip().lower() in {"1", "true", "yes", "y", "on"}


ACTIVE_USER_LOG_ENABLED = _safe_bool_setting("ACTIVE_USER_LOG_ENABLED", True)


def _active_usernames_snapshot() -> tuple[list[str], str]:
    """
    Return currently active usernames from Redis session:* keys when available,
    else from in-memory ACTIVE_SESSIONS fallback map.
    """
    client = _get_redis_client()
    if client:
        users = []
        try:
            for key in client.scan_iter(match="session:*", count=200):
                key_text = str(key or "")
                if key_text.startswith("session:"):
                    uname = key_text.split("session:", 1)[1].strip()
                    if uname:
                        users.append(uname)
        except Exception:
            users = []
        users = sorted(set(users), key=str.lower)
        return users, "redis"

    users = []
    for uname, sid in list(ACTIVE_SESSIONS.items()):
        key_text = str(uname or "")
        if not key_text:
            continue
        if key_text.startswith("hist:") or key_text.startswith("hist_pending:"):
            continue
        if not isinstance(sid, str):
            continue
        users.append(key_text)
    users = sorted(set(users), key=str.lower)
    return users, "memory"


def _log_active_users(reason: str, actor: str | None = None, force: bool = False):
    if not ACTIVE_USER_LOG_ENABLED:
        return
    try:
        users, source = _active_usernames_snapshot()
        snapshot = tuple(users)
        global _ACTIVE_USERS_LAST_SNAPSHOT
        with _ACTIVE_USERS_LOG_LOCK:
            if (not force) and snapshot == _ACTIVE_USERS_LAST_SNAPSHOT:
                return
            _ACTIVE_USERS_LAST_SNAPSHOT = snapshot

        actor_text = (actor or "").strip()
        actor_part = f" actor={actor_text}" if actor_text else ""
        print(f"[SESSION] {reason}{actor_part} active_users={len(users)} source={source} users={users}")
    except Exception as e:
        print(f"[SESSION] active-user logging failed reason={reason}: {e}")

# Fiscal year lock: block historical data without session-scoped approval
FISCAL_START_MONTH = getattr(config, "FISCAL_START_MONTH", 4)  # default Apr 1
HIST_GRANT_TTL_SECONDS = 8 * 60 * 60  # 8 hours


def _session_store_key(username: str) -> str:
    return f"session:{username}"


def _session_store_set(username: str, sid: str):
    client = _get_redis_client()
    if client:
        try:
            client.setex(_session_store_key(username), IDLE_TIMEOUT_SECONDS, sid)
            _log_active_users("login", username, force=True)
            return
        except Exception:
            pass
    ACTIVE_SESSIONS[username] = sid
    _log_active_users("login", username, force=True)


def _session_store_get(username: str):
    client = _get_redis_client()
    if client:
        try:
            return client.get(_session_store_key(username))
        except Exception:
            pass
    return ACTIVE_SESSIONS.get(username)


def _session_store_clear(username: str, sid: str | None = None):
    client = _get_redis_client()
    if client:
        try:
            key = _session_store_key(username)
            if sid is None or client.get(key) == sid:
                client.delete(key)
                _log_active_users("logout", username, force=True)
                return
        except Exception:
            pass
    if sid is None or ACTIVE_SESSIONS.get(username) == sid:
        ACTIVE_SESSIONS.pop(username, None)
        _log_active_users("logout", username, force=True)


def _session_store_touch(username: str, sid: str):
    client = _get_redis_client()
    if client:
        try:
            client.expire(_session_store_key(username), IDLE_TIMEOUT_SECONDS)
            return
        except Exception:
            pass
    # fallback: nothing else to do for in-memory


def fiscal_year_start(now):
    """Return datetime for the start of the current fiscal year in LOCAL_TZ."""
    month = getattr(now, "month", 1)
    year = now.year if month >= FISCAL_START_MONTH else now.year - 1
    return datetime(year, FISCAL_START_MONTH, 1, tzinfo=now.tzinfo)


def _hist_grant_key(user: str, sid: str | None) -> str:
    return f"hist:{user}:{sid or ''}"


def _hist_pending_key(user: str) -> str:
    return f"hist_pending:{user}"


def grant_historical(user: str, sid: str | None, ttl: int | None = None):
    """Grant historical access for this session; stored in Redis or in-memory."""
    if not user:
        return
    ttl_seconds = max(1, int(ttl or HIST_GRANT_TTL_SECONDS))
    expires = int(time.time()) + ttl_seconds
    payload = {"exp": expires}
    if sid:
        key = _hist_grant_key(user, sid)
        if not _redis_set_json(key, payload, ttl_seconds):
            ACTIVE_SESSIONS[key] = payload
    else:
        # Only set pending when no session id is known (user offline)
        pending_key = _hist_pending_key(user)
        if not _redis_set_json(pending_key, {"exp": expires}, ttl_seconds):
            ACTIVE_SESSIONS[pending_key] = {"exp": expires}


def has_historical_grant(user: str, sid: str | None) -> bool:
    if not user or not sid:
        return False
    key = _hist_grant_key(user, sid)
    payload = _redis_get_json(key) or ACTIVE_SESSIONS.get(key)
    return bool(payload and payload.get("exp", 0) > time.time())


def revoke_historical(user: str, sid: str | None = None):
    if not user:
        return
    key = _hist_grant_key(user, sid or "")
    _redis_delete(key)
    ACTIVE_SESSIONS.pop(key, None)


def _consume_pending_historical(user: str) -> int | None:
    """Return remaining TTL for pending grant and clear the pending marker."""
    if not user:
        return None
    key = _hist_pending_key(user)
    payload = _redis_get_json(key) or ACTIVE_SESSIONS.get(key)
    _redis_delete(key)
    ACTIVE_SESSIONS.pop(key, None)
    if not payload:
        return None
    remaining = int(payload.get("exp", 0) - time.time())
    return remaining if remaining > 0 else None


