# ---------------- Redis (optional) for shared state ----------------
try:
    import redis  # type: ignore
except Exception:
    redis = None

_REDIS_CLIENT = None  # type: ignore


def _get_redis_client():
    """
    Return a shared Redis client if REDIS_URL is configured; otherwise None.
    On any connection error, disable Redis use for this process.
    """
    global _REDIS_CLIENT
    if _REDIS_CLIENT is False:
        return None
    if _REDIS_CLIENT:
        return _REDIS_CLIENT
    url = os.getenv("REDIS_URL") or getattr(config, "REDIS_URL", None)
    if not url or not redis:
        _REDIS_CLIENT = False
        return None
    try:
        client = redis.Redis.from_url(url, decode_responses=True)
        client.ping()
        _REDIS_CLIENT = client
        return client
    except Exception as e:
        print(f"Redis unavailable: {e}")
        _REDIS_CLIENT = False
        return None

def _redis_set_json(key: str, value, ttl: int):
    client = _get_redis_client()
    if not client:
        return False
    try:
        client.setex(key, ttl, json.dumps(value))
        return True
    except Exception:
        return False


def _redis_get_json(key: str):
    client = _get_redis_client()
    if not client:
        return None
    try:
        raw = client.get(key)
        if raw is None:
            return None
        return json.loads(raw)
    except Exception:
        return None


def _redis_delete(key: str):
    client = _get_redis_client()
    if not client:
        return False
    try:
        client.delete(key)
        return True
    except Exception:
        return False

# ---------------- Export cache (bytes) ----------------
EXPORT_CACHE = {}
EXPORT_CACHE_LOCK = Lock()
EXPORT_CACHE_TTL = 15 * 60  # seconds
EXPORT_EXECUTOR = ThreadPoolExecutor(max_workers=2)

EXCEL_JOBS = {}
EXCEL_JOBS_TTL = 30 * 60  # seconds
EXCEL_JOBS_LOCK = Lock()


def _export_cache_key(name: str, *parts) -> str:
    return f"{name}::" + "::".join(str(p) for p in parts)


def _export_cache_get_bytes(name: str, *parts):
    key = _export_cache_key(name, *parts)
    redis_key = f"export:{key}"
    entry = _redis_get_json(redis_key)
    now = int(time.time())
    if entry and (now - entry.get("ts", 0) <= EXPORT_CACHE_TTL):
        try:
            import base64
            return base64.b64decode(entry.get("data") or b"")
        except Exception:
            pass
    with EXPORT_CACHE_LOCK:
        entry = EXPORT_CACHE.get(key)
        if not entry:
            return None
        if now - entry.get("ts", 0) > EXPORT_CACHE_TTL:
            EXPORT_CACHE.pop(key, None)
            return None
        return entry.get("data")


def _export_cache_put_bytes(name: str, data: bytes, *parts):
    key = _export_cache_key(name, *parts)
    now = int(time.time())
    try:
        import base64
        _redis_set_json(
            f"export:{key}",
            {"ts": now, "data": base64.b64encode(data).decode("ascii")},
            EXPORT_CACHE_TTL,
        )
    except Exception:
        pass
    with EXPORT_CACHE_LOCK:
        EXPORT_CACHE[key] = {"ts": now, "data": data}


def _excel_job_update(job_id: str, **payload):
    now = int(time.time())
    with EXCEL_JOBS_LOCK:
        entry = EXCEL_JOBS.get(job_id, {})
        entry.update(payload)
        entry["ts"] = now
        EXCEL_JOBS[job_id] = entry
        expired = [k for k, v in EXCEL_JOBS.items() if now - v.get("ts", 0) > EXCEL_JOBS_TTL]
        for k in expired:
            EXCEL_JOBS.pop(k, None)


def _excel_job_get(job_id: str):
    now = int(time.time())
    with EXCEL_JOBS_LOCK:
        entry = EXCEL_JOBS.get(job_id)
        if not entry:
            return None
        if now - entry.get("ts", 0) > EXCEL_JOBS_TTL:
            EXCEL_JOBS.pop(job_id, None)
            return None
        return entry.copy()

# ======== provision #3: pooled SQLAlchemy engines (not altering existing logic) ========
try:
    from sqlalchemy import create_engine
    from sqlalchemy.engine import URL

    def _make_engine(cfg):
        url = URL.create(
            "mssql+pyodbc",
            username=cfg.get("UID") or cfg.get("USER"),
            password=cfg.get("PWD"),
            host=cfg.get("SERVER"),
            database=cfg.get("DATABASE") or cfg.get("DB"),
            query={"driver": (cfg.get("DRIVER") or "ODBC Driver 17 for SQL Server"),
                   "TrustServerCertificate": "yes"}
        )
        return create_engine(
            url,
            pool_size=5,
            max_overflow=2,
            pool_pre_ping=True,
            pool_recycle=180,
            pool_timeout=30,
        )

    ENGINE_MAP = {unit: _make_engine(cfg) for unit, cfg in getattr(config, "DB_CONFIGS", {}).items()}
except Exception as _e:
    ENGINE_MAP = {}
    print(f"Engine pooling setup skipped: { _e }")

