def _gss_cache_get(key):
    now = int(time.time())
    with GSS_CACHE_LOCK:
        entry = GSS_CACHE.get(key)
        if not entry:
            return None
        if now - entry.get("ts", 0) > GSS_CACHE_TTL:
            GSS_CACHE.pop(key, None)
            return None
        return entry.get("df")

def _gss_cache_put(key, df):
    now = int(time.time())
    with GSS_CACHE_LOCK:
        expired = [k for k, v in GSS_CACHE.items() if now - v.get("ts", 0) > GSS_CACHE_TTL]
        for k in expired:
            GSS_CACHE.pop(k, None)
        GSS_CACHE[key] = {"ts": now, "df": df}
        if len(GSS_CACHE) > 6:
            oldest = sorted(GSS_CACHE.items(), key=lambda item: item[1].get("ts", 0))[: len(GSS_CACHE) - 6]
            for k, _ in oldest:
                GSS_CACHE.pop(k, None)


