def _clean_df_columns(df):
    """Standardize column names: strip whitespace."""
    if df is not None and not df.empty:
        df.columns = [str(c).strip() for c in df.columns]
    return df

def _first_numeric_value(row, cols):
    for col in cols:
        if not col:
            continue
        try:
            num = float(row.get(col))
        except Exception:
            continue
        if math.isfinite(num):
            return num
    return None

def _get_item_master_rate_mrp_map(unit: str, item_ids: list[int]) -> dict[int, dict[str, float | None]]:
    if not item_ids:
        return {}
    df = data_fetch.fetch_item_master_rate_mrp(unit, item_ids)
    if df is None or df.empty:
        return {}
    df = _clean_df_columns(df)
    cols = {str(c).strip().lower(): c for c in df.columns}
    id_col = cols.get("itemid") or cols.get("id")
    rate_col = cols.get("standardrate") or cols.get("standard_rate") or cols.get("rate")
    mrp_col = cols.get("salesprice") or cols.get("sales_price") or cols.get("mrp")
    tax_col = cols.get("salestax") or cols.get("sales_tax") or cols.get("tax") or cols.get("vat")
    if not id_col:
        return {}
    out = {}
    for _, row in df.iterrows():
        item_id = row.get(id_col)
        try:
            item_id = int(item_id)
        except Exception:
            continue
        rate_val = _safe_float(row.get(rate_col), None) if rate_col else None
        mrp_val = _safe_float(row.get(mrp_col), None) if mrp_col else None
        tax_val = _safe_float(row.get(tax_col), None) if tax_col else None
        out[item_id] = {"rate": rate_val, "mrp": mrp_val, "tax": tax_val}
    return out

def _bkey(from_date, to_date, unit, mode):
    return (from_date, to_date, (unit or "").upper(), (mode or "").lower())

def _bput(from_date, to_date, unit, mode, payload):
    key = _bkey(from_date, to_date, unit, mode)
    payload_with_ts = {**payload, "ts": int(time.time())}
    if not _redis_set_json(f"breakdown:{key}", payload_with_ts, CACHE_TTL_SECONDS):
        with B_CACHE_LOCK:
            BREAKDOWN_CACHE[key] = payload_with_ts

def _bget(from_date, to_date, unit, mode):
    key = _bkey(from_date, to_date, unit, mode)
    entry = _redis_get_json(f"breakdown:{key}")
    if entry:
        if int(time.time()) - entry.get("ts", 0) <= CACHE_TTL_SECONDS:
            return entry
    with B_CACHE_LOCK:
        entry = BREAKDOWN_CACHE.get(key)
        if not entry:
            return None
        if int(time.time()) - entry.get("ts", 0) > CACHE_TTL_SECONDS:
            BREAKDOWN_CACHE.pop(key, None)
            return None
        return entry

def _compute_breakdown_payload(df, mode):
    if df is None or df.empty:
        return None
    
    # 1. Clean columns
    df.columns = [str(c).strip() for c in df.columns]
    
    # 2. Setup Mode & Map
    mode = (mode or "").lower().strip()
    cols_map = {str(c).strip().lower(): c for c in df.columns}
    
    # 3. Define Candidates
    candidates = []
    if mode == "department":
        candidates = ["Department", "DeptName", "DepartmentName", "Dept", "Dept_Name", "Dept Name", "Department_Name"]
    elif mode == "category":
        candidates = ["PatientCategory", "Category", "PatientType", "PatCategory", "Patient_Category", "PayCategory", "BillCategory"]
    elif mode in ("typeofvisit", "type_of_visit", "visit_type", "visittype", "visittype", "visitType"):
        candidates = ["TypeOfVisit", "VisitType", "Type Of Visit", "Type_Of_Visit", "TypeOf Visit"]
    elif mode in ("corptype", "corp_type", "corporate"):
        candidates = ["CorpType", "CorporateName", "Corporate_Name", "Company", "CompanyName", "Company_Name", "Panel", "TPA", "Organization"]

    # 4. Find Group Column
    group_col = next((cols_map[c.lower()] for c in candidates if c.lower() in cols_map), None)
            
    # 5. Find Value Column
    value_col = None
    if "netamount" in cols_map:
        value_col = cols_map["netamount"]
    elif "amount" in cols_map:
        value_col = cols_map["amount"]
        
    if not group_col or not value_col:
        return None

    # 6. Aggregation Logic
    try:
        # A. Create full sorted series
        full_series = (df.groupby(group_col)[value_col]
                         .sum()
                         .sort_values(ascending=False))
        
        # B. Calculate True Total (Sum of ALL rows before slicing)
        true_total = full_series.sum()

        # C. Slice Top 15 for the chart
        # agg_top = full_series.head(15).reset_index()
        agg_top = full_series.reset_index()

        # D. Return complete payload
        return {
            "labels": agg_top[group_col].astype(str).tolist(),
            "values": agg_top[value_col].astype(float).tolist(),
            "group_col": group_col,
            "true_total": float(true_total) 
        }
    except Exception as e:
        print(f"[WARN] Aggregation error in breakdown ({mode}): {e}")
        return None
def start_prefetch_breakdowns(from_date: str, to_date: str):
    modes_to_warm = ["typeofvisit", "category"]
    units = _analytics_units_upper()

    def _job(_unit, _mode):
        if _bget(from_date, to_date, _unit, _mode):
            return
        try:
            df = _fetch_revenue_limited(_unit, from_date, to_date)
            if df is not None and not df.empty:
                df = _clean_df_columns(df)
                payload = _compute_breakdown_payload(df, _mode)
                if payload:
                    _bput(from_date, to_date, _unit, _mode, payload)
        except Exception as e:
            print(f"Prefetch breakdown failed for unit={_unit}, mode={_mode}: {e}")

    try:
        for u in units:
            for m in modes_to_warm:
                WARM_EXECUTOR.submit(_job, u, m)
    except Exception:
        pass

