def _role_base(role_name: str) -> str:
    return (role_name or "").split(":", 1)[0].strip()

def _is_departmental_head(role_name: str) -> bool:
    return _role_base(role_name).lower().startswith("departmental head")

def _role_rank(role_name: str) -> int:
    """Higher number means higher privilege (IT > Management > Departmental Head > Executive)."""
    r = (role_name or "").strip()
    if _is_departmental_head(r):
        return 1
    mapping = {
        "Executive": 0,
        "Departmental Head": 1,
        "Management": 2,
        "IT": 3,
    }
    return mapping.get(r, -1)

# ============================================================
# Section-level rights (DB-backed)
# ============================================================
def _normalize_section_list(raw_sections):
    """
    Normalize section rights coming from DB. Accepts comma separated string,
    JSON-like stringified list/dict, or list/tuple.
    """
    if raw_sections is None:
        return []

    # Already a list/tuple
    if isinstance(raw_sections, (list, tuple, set)):
        return [str(x).strip().lower() for x in raw_sections if str(x).strip()]

    # Try JSON payload first
    if isinstance(raw_sections, str):
        txt = raw_sections.strip()
        if not txt:
            return []
        try:
            parsed = json.loads(txt)
            return _normalize_section_list(parsed)
        except Exception:
            pass
        # Fallback: comma separated
        return [s.strip().lower() for s in txt.split(",") if s.strip()]

    return []

def has_section_access(section_key: str) -> bool:
    """
    True if the current session can access a specific section.
    IT is always allowed. For everyone else we look at section_rights stored
    on session (wildcard "*" grants all sections).
    """
    if not section_key:
        return True

    role = (session.get("role") or "").strip()
    if role == "IT":
        return True

    allowed = [str(x).strip().lower() for x in (session.get("section_rights") or []) if str(x).strip()]
    norm = section_key.strip().lower()

    if norm.startswith("mis_"):
        return "*" in allowed or "mis" in allowed or norm in allowed
    if norm == "mis":
        if "*" in allowed or "mis" in allowed:
            return True
        return any(item.startswith("mis_") for item in allowed)

    if norm.startswith("service_addition_"):
        return "*" in allowed or "service_addition" in allowed or norm in allowed
    if norm == "service_addition":
        if "*" in allowed or "service_addition" in allowed:
            return True
        return any(item.startswith("service_addition_") for item in allowed)

    return "*" in allowed or norm in allowed


def _forbidden_response(message: str, status_code: int = 403):
    text = str(message or "Forbidden")
    if (request.path or "").startswith("/api/"):
        return jsonify({"status": "error", "message": text}), int(status_code)
    return (text, int(status_code))

