def _all_section_keys():
    keys = set(ROUTE_SECTION_MAP.values())
    # Always include user_management for admin workflows
    keys.add("user_management")
    # Additional fine-grained right for corporate reconciliation write-off action.
    keys.add(CORP_RECON_WRITEOFF_SECTION)
    return sorted(keys)

def _resolve_section_for_request(path: str) -> str | None:
    """Return the section key for the given request path."""
    if not path:
        return None
    clean = "/" + path.split("?", 1)[0].strip().strip("/").lower()
    if clean == "/":
        return None

    # Exact or prefix match (longest routes first).
    for route, section in sorted(ROUTE_SECTION_MAP.items(), key=lambda item: len(item[0]), reverse=True):
        if clean == route or clean.startswith(route + "/"):
            return section

    # Fallback: first segment becomes the section key
    first = clean.lstrip("/").split("/", 1)[0]
    return first or None

def _available_sections():
    """Return sorted unique section keys derived from route map (auto-updates when new paths are added)."""
    return sorted({sec for sec in ROUTE_SECTION_MAP.values() if sec})

