# Auth helpers
# ============================================================
def login_required(allowed_roles=None, required_section: str | None = None):
    def decorator(view_func):
        @wraps(view_func)
        def wrapped(*args, **kwargs):
            username = session.get("username")
            role = session.get("role")
            if not username or not role:
                return redirect(url_for("login"))

            if allowed_roles is not None:
                role_base = _role_base(role)
                allowed = (role in allowed_roles) or (role_base in allowed_roles) or (
                    "Departmental Head" in allowed_roles and _is_departmental_head(role)
                )
                if not allowed and "Departmental Head" in allowed_roles and role_base == "Executive":
                    allowed = True
                if not allowed:
                    return _forbidden_response("Access denied for your role.", 403)

            if required_section and not has_section_access(required_section):
                return _forbidden_response("Access denied for this section.", 403)

            return view_func(*args, **kwargs)
        return wrapped
    return decorator

# ---------- NEW: Unit-scope helper (rights) ----------
def _normalize_unit_scope(raw_units):
    """
    Normalize unit scope input into a unique, ordered list of uppercase unit codes.
    Accepts comma/slash/pipe separated strings or JSON-like lists.
    """
    if raw_units is None:
        return []

    items = []
    if isinstance(raw_units, (list, tuple, set)):
        items = list(raw_units)
    elif isinstance(raw_units, str):
        txt = raw_units.strip()
        if not txt:
            return []
        try:
            parsed = json.loads(txt)
            if isinstance(parsed, (list, tuple, set)):
                items = list(parsed)
            else:
                items = [parsed]
        except Exception:
            items = [txt]
    else:
        items = [raw_units]

    units = []
    seen = set()
    for item in items:
        if item is None:
            continue
        parts = re.split(r"[,\|/]+", str(item))
        for part in parts:
            unit = part.strip().upper()
            if not unit or unit in seen:
                continue
            units.append(unit)
            seen.add(unit)
    return units


def _normalize_unit_scope_text(raw_units):
    units = _normalize_unit_scope(raw_units)
    return ", ".join(units)

FUND_POSITION_DEFAULT_FIRMS = [
    "ASARFI HOSPITAL LTD",
    "ASARFI CANCER INSTITUTE",
    "ASAP IMPACT PVT LTD",
    "DHANBAD EDUCATION FOUNDATION",
]

def _normalize_firm_name(value) -> str:
    text = re.sub(r"\s+", " ", str(value or "").strip())
    return text.upper()

def _normalize_firm_scope(raw_firms):
    """Normalize firm scope into a unique, ordered list of uppercase firm names."""
    if raw_firms is None:
        return []

    items = []
    if isinstance(raw_firms, (list, tuple, set)):
        items = list(raw_firms)
    elif isinstance(raw_firms, str):
        txt = raw_firms.strip()
        if not txt:
            return []
        try:
            parsed = json.loads(txt)
            if isinstance(parsed, (list, tuple, set)):
                items = list(parsed)
            else:
                items = [parsed]
        except Exception:
            items = [txt]
    else:
        items = [raw_firms]

    firms = []
    seen = set()
    for item in items:
        if item is None:
            continue
        parts = re.split(r"[,\|/\n;]+", str(item))
        for part in parts:
            firm = _normalize_firm_name(part)
            if not firm:
                continue
            if firm == "*":
                return ["*"]
            if firm in seen:
                continue
            firms.append(firm)
            seen.add(firm)
    return firms

def _normalize_firm_scope_text(raw_firms):
    firms = _normalize_firm_scope(raw_firms)
    return "*" if firms == ["*"] else ", ".join(firms)

def _fund_tracker_known_firms():
    """Return canonical firm names used by fund tracker, with DB-discovered values first."""
    discovered = []
    seen = set()

    def add_firm(raw):
        firm = _normalize_firm_name(raw)
        if not firm or firm in seen:
            return
        seen.add(firm)
        discovered.append(firm)

    try:
        with _get_login_db_connection() as conn:
            cursor = conn.cursor()
            for table_name in [
                "dbo.HID_Fund_Master_Accounts",
                "dbo.HID_Fund_Daily_Position",
                "dbo.HID_Fund_WC_Loan_Position",
                "dbo.HID_Fund_FDR_Tracker",
            ]:
                try:
                    cursor.execute(f"""
                        SELECT DISTINCT LTRIM(RTRIM(FirmName)) AS name
                        FROM {table_name}
                        WHERE FirmName IS NOT NULL AND LTRIM(RTRIM(FirmName)) <> ''
                        ORDER BY name
                    """)
                    for row in cursor.fetchall():
                        add_firm(row[0] if row else "")
                except Exception:
                    continue
    except Exception:
        pass

    for firm in FUND_POSITION_DEFAULT_FIRMS:
        add_firm(firm)
    return discovered

def _allowed_fund_firms_for_session():
    """
    Resolve fund-tracker firm access for current session.
    Returns {"all": bool, "firms": [..]}.
    """
    known_firms = _fund_tracker_known_firms()
    role = (session.get("role") or "").strip()
    role_base = _role_base(role)

    if role_base == "IT":
        return {"all": True, "firms": known_firms}

    scoped = _normalize_firm_scope(session.get("firm_scope") or "")
    if scoped == ["*"]:
        return {"all": True, "firms": known_firms}
    if not scoped:
        return {"all": False, "firms": []}

    if not known_firms:
        return {"all": False, "firms": scoped}

    known_set = {f.upper() for f in known_firms}
    allowed = [f for f in scoped if f.upper() in known_set]
    extras = [f for f in scoped if f.upper() not in known_set]
    return {"all": False, "firms": allowed + extras}


def _all_units_upper():
    return [u.upper() for u in getattr(config, "DB_CONFIGS", {}).keys()]

def _analytics_units_upper():
    units_all = _all_units_upper()
    explicit = getattr(config, "ANALYTICS_UNITS", None)
    if explicit:
        explicit_set = {str(u).strip().upper() for u in explicit if str(u).strip()}
        return [u for u in units_all if u in explicit_set]
    excluded = {str(u).strip().upper() for u in getattr(config, "ANALYTICS_EXCLUDE_UNITS", [])}
    if excluded:
        return [u for u in units_all if u not in excluded]
    return units_all

def _analytics_allowed_units_for_session():
    """Session-limited units, filtered by analytics exclusions."""
    allowed = _allowed_units_for_session()
    if not allowed:
        return []
    analytics = set(_analytics_units_upper())
    if not analytics:
        return []
    return [u for u in allowed if u.upper() in analytics]

def _allowed_units_for_session():
    """
    IT/Management -> all units.
    Departmental Head -> unit list from session['unit_scope'] or 'Departmental Head: <UNIT>'.
    Others -> none.
    """
    role = (session.get("role") or "").strip()
    role_base = _role_base(role)
    units_all = _all_units_upper()

    if role_base in {"IT", "Management"}:
        return units_all

    if _is_departmental_head(role) or role_base == "Executive":
        units = _normalize_unit_scope(session.get("unit_scope") or "")
        if not units and _is_departmental_head(role) and ":" in role:
            units = _normalize_unit_scope(role.split(":", 1)[1])
        if not units:
            return []
        allowed_set = {u.upper() for u in units_all}
        return [u for u in units if u in allowed_set]

    return []

def _allowed_purchase_units_for_session():
    """
    Purchase-module unit scope:
    - Defaults to normal session units.
    - If session['purchase_unit_scope'] is set, restrict Purchase to that subset.
    """
    allowed = _allowed_units_for_session()
    if not allowed:
        return []
    purchase_scope = _normalize_unit_scope(session.get("purchase_unit_scope") or "")
    if not purchase_scope:
        return allowed
    allowed_set = {str(u or "").strip().upper() for u in allowed}
    return [u for u in purchase_scope if str(u or "").strip().upper() in allowed_set]

STORE_MIS_UNITS = {"AHLSTORE", "CANCERUNITSTORE", "BALLIASTORE"}

def _allowed_store_units_for_session():
    allowed = _allowed_units_for_session()
    if not allowed:
        return []
    return [u for u in allowed if str(u).strip().upper() in STORE_MIS_UNITS]

NON_MEDICAL_ITEM_UNITS = {"AHLSTORE", "CANCERUNITSTORE", "BALLIASTORE"}
NON_MEDICAL_DEFAULT_STORE_NAME = "Main Store"

def _unit_allows_zero_rate_mrp(unit: str) -> bool:
    unit_norm = str(unit or "").strip().upper()
    return unit_norm in NON_MEDICAL_ITEM_UNITS

def _default_store_name_for_unit(unit: str) -> str:
    unit_norm = str(unit or "").strip().upper()
    if unit_norm in NON_MEDICAL_ITEM_UNITS:
        return NON_MEDICAL_DEFAULT_STORE_NAME
    return ""

def _modification_units(units: list[str] | None):
    allowed = {"AHL", "BALLIA", "ACI"}
    blocked = {"AHLSTORE", "CANCERUNITSTORE", "BALLIASTORE"}
    filtered = []
    for u in (units or []):
        u_clean = str(u or "").strip().upper()
        if not u_clean or u_clean in blocked:
            continue
        if u_clean in allowed:
            filtered.append(u_clean)
    return filtered

# --- DB login helpers ---
def _get_login_db_connection():
    cfg = getattr(config, "LOGIN_DB", None)
    if not cfg:
        raise RuntimeError("LOGIN_DB is not configured in config.py")

    driver = cfg.get("DRIVER", "{ODBC Driver 18 for SQL Server}")
    server = cfg.get("SERVER", "192.168.20.100")
    database = cfg.get("DATABASE", cfg.get("DB") or "ACI")
    uid = cfg.get("UID") or cfg.get("USER")
    pwd = cfg.get("PWD")

    if not all([driver, server, database, uid, pwd]):
        raise RuntimeError("LOGIN_DB missing one of DRIVER/SERVER/DATABASE/UID/PWD")

    conn_str = (
        f"DRIVER={driver};"
        f"SERVER={server};"
        f"DATABASE={database};"
        f"UID={uid};PWD={pwd};"
        "TrustServerCertificate=yes;"
    )
    return pyodbc.connect(conn_str, timeout=5)

def fetch_user_from_db(username: str):
    if not username:
        return None
    try:
        with _get_login_db_connection() as conn:
            cursor = conn.cursor()
            try:
                cursor.execute(
                    """
                    SELECT TOP 1
                        UserName,
                        PasswordW,
                        AccountId,
                        RoleName,
                        UnitScope,
                        SectionRights,
                        ISNULL(IsActive, 1) AS IsActive
                    FROM dbo.HID_User_Mst
                    WHERE UserName = ?
                    """,
                    (username,)
                )
            except Exception:
                # Fallback to legacy table if new table is not yet present
                cursor.execute(
                    "SELECT TOP 1 username, passwordw, accountid FROM dbo.user_mst WHERE username = ?",
                    (username,)
                )

            row = cursor.fetchone()
            if not row:
                return None

            cols = [c[0].lower() for c in (cursor.description or [])]
            row_map = {cols[i]: row[i] for i in range(len(cols))}

            # Respect IsActive flag when provided
            active_val = row_map.get("isactive")
            if active_val is not None and str(active_val).strip().lower() not in ("1", "true", "yes", "y"):
                return None

            acctid_raw = row_map.get("accountid")
            acctid = int(acctid_raw) if acctid_raw is not None else None
            role_from_id = ACCOUNTID_ROLE.get(acctid)
            role = (row_map.get("rolename") or row_map.get("role") or role_from_id or "").strip()

            unit_scope_raw = (row_map.get("unitscope") or row_map.get("unit_scope") or row_map.get("unit") or "").strip()
            unit_list = _normalize_unit_scope(unit_scope_raw)
            unit_scope = ", ".join(unit_list)
            firm_scope_raw = (row_map.get("firmscope") or row_map.get("firm_scope") or "").strip()
            if not firm_scope_raw:
                try:
                    cursor.execute("SELECT TOP 1 FirmScope FROM dbo.HID_User_Mst WHERE UserName = ?", (username,))
                    firm_row = cursor.fetchone()
                    if firm_row and firm_row[0]:
                        firm_scope_raw = str(firm_row[0]).strip()
                except Exception:
                    pass
            firm_scope = _normalize_firm_scope_text(firm_scope_raw)
            purchase_scope_raw = (
                row_map.get("purchaseunitscope")
                or row_map.get("purchase_unit_scope")
                or row_map.get("purchaseunits")
                or ""
            ).strip()
            if not purchase_scope_raw:
                try:
                    cursor.execute("SELECT TOP 1 PurchaseUnitScope FROM dbo.HID_User_Mst WHERE UserName = ?", (username,))
                    purchase_scope_row = cursor.fetchone()
                    if purchase_scope_row and purchase_scope_row[0]:
                        purchase_scope_raw = str(purchase_scope_row[0]).strip()
                except Exception:
                    pass
            purchase_unit_scope = _normalize_unit_scope_text(purchase_scope_raw)

            if _role_base(role) == "Departmental Head":
                if not unit_list and ":" in role:
                    unit_list = _normalize_unit_scope(role.split(":", 1)[1])
                    unit_scope = ", ".join(unit_list)
                if unit_list:
                    role = f"Departmental Head: {unit_list[0]}" if len(unit_list) == 1 else "Departmental Head"
                else:
                    role = "Departmental Head"
            elif not role:
                role = role_from_id

            sections = _normalize_section_list(row_map.get("sectionrights") or row_map.get("sections") or row_map.get("section_rights"))

            return {
                "username": row_map.get("username") or row_map.get("user_name") or username,
                "passwordw": row_map.get("passwordw") or row_map.get("password") or row_map.get("pwd"),
                "accountid": acctid,
                "role": role,
                "unit_scope": unit_scope,
                "firm_scope": firm_scope,
                "purchase_unit_scope": purchase_unit_scope,
                "sections": sections,
            }
    except Exception as e:
        print(f"[WARN] Login DB fetch failed: {e}")
        return None

