def _ensure_audit_log_table(conn):
    cursor = conn.cursor()
    cursor.execute("""
    IF OBJECT_ID('dbo.HID_Audit_Log', 'U') IS NULL
    BEGIN
        CREATE TABLE dbo.HID_Audit_Log (
            LogId INT IDENTITY(1,1) PRIMARY KEY,
            EventTime DATETIME2 NOT NULL DEFAULT(SYSDATETIME()),
            Module NVARCHAR(40) NOT NULL,
            Action NVARCHAR(40) NOT NULL,
            Status NVARCHAR(20) NOT NULL,
            EntityType NVARCHAR(40) NULL,
            EntityId NVARCHAR(80) NULL,
            Unit NVARCHAR(20) NULL,
            Username NVARCHAR(100) NULL,
            RoleName NVARCHAR(100) NULL,
            AccountId INT NULL,
            Summary NVARCHAR(300) NULL,
            Details NVARCHAR(MAX) NULL,
            RequestId NVARCHAR(80) NULL,
            IpAddress NVARCHAR(60) NULL,
            UserAgent NVARCHAR(255) NULL
        );
    END
    """)
    cursor.execute("""
    IF NOT EXISTS (
        SELECT 1 FROM sys.indexes
        WHERE name = 'IX_HID_Audit_Log_Time'
          AND object_id = OBJECT_ID('dbo.HID_Audit_Log')
    )
    CREATE INDEX IX_HID_Audit_Log_Time ON dbo.HID_Audit_Log(EventTime);
    """)
    cursor.execute("""
    IF NOT EXISTS (
        SELECT 1 FROM sys.indexes
        WHERE name = 'IX_HID_Audit_Log_Module'
          AND object_id = OBJECT_ID('dbo.HID_Audit_Log')
    )
    CREATE INDEX IX_HID_Audit_Log_Module ON dbo.HID_Audit_Log(Module);
    """)
    cursor.execute("""
    IF NOT EXISTS (
        SELECT 1 FROM sys.indexes
        WHERE name = 'IX_HID_Audit_Log_Entity'
          AND object_id = OBJECT_ID('dbo.HID_Audit_Log')
    )
    CREATE INDEX IX_HID_Audit_Log_Entity ON dbo.HID_Audit_Log(EntityType, EntityId);
    """)
    cursor.execute("""
    IF NOT EXISTS (
        SELECT 1 FROM sys.indexes
        WHERE name = 'IX_HID_Audit_Log_Unit'
          AND object_id = OBJECT_ID('dbo.HID_Audit_Log')
    )
    CREATE INDEX IX_HID_Audit_Log_Unit ON dbo.HID_Audit_Log(Unit);
    """)
    cursor.execute("""
    IF NOT EXISTS (
        SELECT 1 FROM sys.indexes
        WHERE name = 'IX_HID_Audit_Log_Status'
          AND object_id = OBJECT_ID('dbo.HID_Audit_Log')
    )
    CREATE INDEX IX_HID_Audit_Log_Status ON dbo.HID_Audit_Log(Status);
    """)
    conn.commit()


def _clip_text(value, max_len: int):
    if value is None:
        return None
    text = str(value)
    if max_len <= 0:
        return ""
    if len(text) <= max_len:
        return text
    if max_len <= 3:
        return text[:max_len]
    return text[: max_len - 3] + "..."


def _audit_json(details):
    if details is None:
        return None
    try:
        payload = _sanitize_json_payload(details)
    except Exception:
        payload = details
    try:
        return json.dumps(payload, default=str, ensure_ascii=True)
    except Exception:
        return json.dumps(str(payload), ensure_ascii=True)


def _audit_log_event(
    module: str,
    action: str,
    *,
    status: str = "success",
    entity_type: str | None = None,
    entity_id: str | None = None,
    unit: str | None = None,
    summary: str | None = None,
    details: dict | list | str | None = None,
    request_id: str | None = None,
    username: str | None = None,
    role: str | None = None,
    account_id: int | None = None,
):
    try:
        if username is None:
            username = session.get("username") or session.get("user") or ""
        if role is None:
            role = session.get("role") or ""
        if account_id is None:
            account_id = session.get("accountid") or session.get("account_id") or None
        ip_addr = request.remote_addr if request else None
        user_agent = request.headers.get("User-Agent") if request else None

        with _get_login_db_connection() as conn:
            _ensure_audit_log_table(conn)
            cursor = conn.cursor()
            cursor.execute(
                """
                INSERT INTO dbo.HID_Audit_Log
                (Module, Action, Status, EntityType, EntityId, Unit, Username, RoleName, AccountId,
                 Summary, Details, RequestId, IpAddress, UserAgent)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    _clip_text(module, 40),
                    _clip_text(action, 40),
                    _clip_text(status, 20),
                    _clip_text(entity_type, 40),
                    _clip_text(entity_id, 80),
                    _clip_text(unit, 20),
                    _clip_text(username, 100),
                    _clip_text(role, 100),
                    account_id,
                    _clip_text(summary, 300),
                    _audit_json(details),
                    _clip_text(request_id, 80),
                    _clip_text(ip_addr, 60),
                    _clip_text(user_agent, 255),
                ),
            )
            conn.commit()
    except Exception as e:
        print(f"Audit log failed: {e}")


def _normalize_po_header_for_audit(header: dict, totals: dict | None = None, status_code: str | None = None) -> dict:
    header = header or {}
    totals = totals or {}

    def pick(keys, default=None):
        return _row_value(header, keys, default)

    amount = _safe_float(totals.get("grand_total"), None)
    if amount is None:
        amount = _safe_float(pick(["Amount", "amount", "GrandTotal", "grand_total"]), None)

    tax_total = _safe_float(totals.get("tax_total"), None)
    if tax_total is None:
        tax_total = _safe_float(pick(["Tax", "tax_total", "TaxTotal", "tax"]), None)

    discount_total = _safe_float(totals.get("discount_total"), None)
    if discount_total is None:
        discount_total = _safe_float(pick(["Discount", "discount_total", "DiscountTotal", "discount"]), None)

    return {
        "po_id": pick(["ID", "Id", "po_id"]),
        "po_no": pick(["PONo", "PoNo", "po_no"]),
        "po_date": pick(["PODate", "PoDate", "po_date"]),
        "supplier_id": pick(["SupplierID", "SupplierId", "supplier_id"]),
        "supplier_name": pick(["SupplierName", "supplier_name", "Supplier"]),
        "purchasing_dept_id": pick(["PurchasingDeptId", "PurchasingDeptID", "purchasing_dept_id"]),
        "senior_approval_authority_name": pick(["SeniorApprovalAuthorityName", "senior_approval_authority_name"]),
        "senior_approval_authority_designation": pick(["SeniorApprovalAuthorityDesignation", "senior_approval_authority_designation"]),
        "status": status_code or pick(["Status", "status"]),
        "amount": amount,
        "tax_total": tax_total,
        "discount_total": discount_total,
        "notes": pick(["Notes", "notes"]),
        "special_notes": pick(["SpecialNotes", "special_notes"]),
        "subject": pick(["Subject", "subject"]),
        "ref_no": pick(["RefNo", "Ref_No", "ref_no"]),
    }


def _diff_simple_fields(old: dict, new: dict, fields: list[str]) -> list[dict]:
    old = old or {}
    new = new or {}
    changes = []
    for field in fields:
        if old.get(field) != new.get(field):
            changes.append({
                "field": field,
                "from": old.get(field),
                "to": new.get(field),
            })
    return changes


def _po_item_key(item: dict, idx: int) -> str:
    def _safe_int_local(val):
        try:
            return int(val)
        except Exception:
            return 0

    item_id = _safe_int_local(
        item.get("item_id")
        or item.get("ItemId")
        or item.get("ItemID")
        or item.get("itemid")
        or item.get("ItemID")
        or 0
    )
    if item_id:
        return f"id:{item_id}"
    name = str(item.get("item_name") or item.get("ItemName") or item.get("name") or "").strip()
    if name:
        return f"name:{name.lower()}"
    return f"idx:{idx}"


def _po_item_summary(item: dict) -> dict:
    return {
        "item_id": item.get("item_id") or item.get("ItemId") or item.get("ItemID") or item.get("itemid"),
        "name": item.get("item_name") or item.get("ItemName") or item.get("name"),
        "qty": _safe_float(item.get("qty") or item.get("Qty") or item.get("ItemQty") or item.get("itemqty"), None),
        "rate": _safe_float(item.get("rate") or item.get("Rate") or item.get("ItemRate") or item.get("itemrate"), None),
        "net_amt": _safe_float(item.get("net_amt") or item.get("NetAmount") or item.get("NetAmt") or item.get("netamount"), None),
    }


def _diff_po_items(old_items: list, new_items: list, max_changes: int = 50) -> dict:
    old_items = old_items or []
    new_items = new_items or []
    old_map = {}
    new_map = {}
    for idx, item in enumerate(old_items):
        key = _po_item_key(item, idx)
        old_map[key] = _po_item_summary(item)
    for idx, item in enumerate(new_items):
        key = _po_item_key(item, idx)
        new_map[key] = _po_item_summary(item)

    added = [new_map[k] for k in new_map.keys() if k not in old_map]
    removed = [old_map[k] for k in old_map.keys() if k not in new_map]

    changed = []
    for key in new_map.keys():
        if key not in old_map:
            continue
        diffs = _diff_simple_fields(old_map[key], new_map[key], ["qty", "rate", "net_amt"])
        if diffs:
            changed.append({"item": new_map[key], "changes": diffs})
        if len(changed) >= max_changes:
            break

    return {
        "counts": {
            "old": len(old_items),
            "new": len(new_items),
            "added": len(added),
            "removed": len(removed),
            "changed": len(changed),
        },
        "added": added[:max_changes],
        "removed": removed[:max_changes],
        "changed": changed[:max_changes],
    }


def _row_has_any_value(row: dict, fields: list[str]) -> bool:
    if not row:
        return False
    for field in fields:
        val = row.get(field)
        if val is None:
            continue
        if isinstance(val, str) and not val.strip():
            continue
        return True
    return False


def _diff_rows_indexed(old_rows: list, new_rows: list, fields: list[str], label_field: str | None = None, max_changes: int = 50) -> dict:
    old_rows = old_rows or []
    new_rows = new_rows or []
    max_len = max(len(old_rows), len(new_rows))
    changes = []
    for idx in range(max_len):
        old = old_rows[idx] if idx < len(old_rows) else {}
        new = new_rows[idx] if idx < len(new_rows) else {}
        if not (_row_has_any_value(old, fields) or _row_has_any_value(new, fields)):
            continue
        diffs = []
        for field in fields:
            if old.get(field) != new.get(field):
                diffs.append({
                    "field": field,
                    "from": old.get(field),
                    "to": new.get(field),
                })
        if diffs:
            label_val = None
            if label_field:
                label_val = new.get(label_field) or old.get(label_field)
            changes.append({
                "row": idx + 1,
                "label": _clip_text(label_val, 120) if label_val else None,
                "changes": diffs,
            })
        if len(changes) >= max_changes:
            break

    return {
        "rows_total": max_len,
        "rows_changed": len(changes),
        "changes": changes,
    }


def _row_norm_for_diff(row) -> str:
    if row is None:
        return ""
    if isinstance(row, dict):
        items = [(k, row.get(k)) for k in sorted(row.keys())]
        return json.dumps(items, default=str, ensure_ascii=True)
    return json.dumps(row, default=str, ensure_ascii=True)


def _diff_rows_generic(old_rows: list, new_rows: list, max_changes: int = 50) -> dict:
    old_rows = old_rows or []
    new_rows = new_rows or []
    max_len = max(len(old_rows), len(new_rows))
    changes = []
    for idx in range(max_len):
        old = old_rows[idx] if idx < len(old_rows) else None
        new = new_rows[idx] if idx < len(new_rows) else None
        old_norm = _row_norm_for_diff(old)
        new_norm = _row_norm_for_diff(new)
        if old_norm != new_norm:
            changes.append({
                "row": idx + 1,
                "from": _clip_text(old_norm, 200),
                "to": _clip_text(new_norm, 200),
            })
        if len(changes) >= max_changes:
            break
    return {
        "rows_total": max_len,
        "rows_changed": len(changes),
        "changes": changes,
    }


def _build_morning_report_diff(old_payload: dict | None, new_payload: dict) -> dict:
    if not old_payload:
        return {"status": "new", "changes": {}}
    changes = {
        "header": _diff_simple_fields(
            {
                "report_time": old_payload.get("report_time"),
                "mod_name": old_payload.get("mod_name"),
            },
            {
                "report_time": new_payload.get("report_time"),
                "mod_name": new_payload.get("mod_name"),
            },
            ["report_time", "mod_name"],
        ),
        "summary_rows": _diff_rows_indexed(
            old_payload.get("summary_rows"), new_payload.get("summary_rows"),
            ["label", "asarfi", "cardiac", "total", "manual"], "label"
        ),
        "investigations": _diff_rows_indexed(
            old_payload.get("investigations"), new_payload.get("investigations"),
            ["label", "asarfi", "cardiac", "total"], "label"
        ),
        "key_procedures": _diff_rows_indexed(
            old_payload.get("key_procedures"), new_payload.get("key_procedures"),
            ["label", "count"], "label"
        ),
        "admissions": _diff_rows_indexed(
            old_payload.get("admissions"), new_payload.get("admissions"),
            ["dept", "doctor", "prev_count", "night_count"], "dept"
        ),
        "doctorwise_rows": _diff_rows_indexed(
            old_payload.get("doctorwise_rows"), new_payload.get("doctorwise_rows"),
            ["department", "opd", "ipd"], "department"
        ),
        "occupancy_rows": _diff_rows_indexed(
            old_payload.get("occupancy_rows"), new_payload.get("occupancy_rows"),
            ["ward", "patient_count", "occupied_count", "clinically_discharged_count", "beds"], "ward"
        ),
        "doctor_night_visits": _diff_rows_indexed(
            old_payload.get("doctor_night_visits"), new_payload.get("doctor_night_visits"),
            ["patient_name", "admission_time", "consultant", "visiting"], "patient_name"
        ),
        "staff_rows": _diff_rows_indexed(
            old_payload.get("staff_rows"), new_payload.get("staff_rows"),
            ["department", "doctor", "nursing", "aaya", "ward_boy", "housekeeping"], "department"
        ),
        "non_medical_rows": _diff_rows_indexed(
            old_payload.get("non_medical_rows"), new_payload.get("non_medical_rows"),
            ["left_label", "left_count", "right_label", "right_count"], "left_label"
        ),
        "referral_rows": _diff_rows_indexed(
            old_payload.get("referral_rows"), new_payload.get("referral_rows"),
            ["patient_name", "visit_time", "consultant", "reason"], "patient_name"
        ),
    }
    return {"status": "updated", "changes": changes}


def _build_night_report_diff(old_payload: dict | None, new_payload: dict) -> dict:
    if not old_payload:
        return {"status": "new", "changes": {}}
    changes = {
        "particulars": _diff_rows_generic(old_payload.get("particulars"), new_payload.get("particulars")),
        "occupancy_paytype": _diff_rows_generic(old_payload.get("occupancy_paytype") or old_payload.get("occupancy"), new_payload.get("occupancy_paytype")),
        "equipment_rows": _diff_rows_generic(old_payload.get("equipment_rows"), new_payload.get("equipment_rows")),
        "doctor_entries": _diff_rows_generic(old_payload.get("doctor_entries"), new_payload.get("doctor_entries")),
        "doctor_volume": _diff_rows_generic(old_payload.get("doctor_volume"), new_payload.get("doctor_volume")),
        "ward_occupancy": _diff_rows_generic(old_payload.get("ward_occupancy"), new_payload.get("ward_occupancy")),
    }
    return {"status": "updated", "changes": changes}

