def _fund_parse_date_value(value, default: date | None = None) -> date | None:
    if value is None:
        return default
    if isinstance(value, datetime):
        return value.date()
    if isinstance(value, date):
        return value
    raw = str(value).strip()
    if not raw:
        return default
    raw = raw.split("T")[0].split(" ")[0]
    for fmt in ("%Y-%m-%d", "%d-%m-%Y", "%d/%m/%Y", "%Y/%m/%d", "%d.%m.%Y", "%m/%d/%Y"):
        try:
            return datetime.strptime(raw, fmt).date()
        except Exception:
            continue
    try:
        parsed = pd.to_datetime(raw, errors="coerce", dayfirst=True)
        if pd.isna(parsed):
            return default
        return parsed.date()
    except Exception:
        return default

def _fund_parse_decimal(value, default: float = 0.0) -> float:
    if value is None:
        return float(default)
    if isinstance(value, (int, float, Decimal)):
        try:
            return float(value)
        except Exception:
            return float(default)
    text = str(value).strip()
    if not text:
        return float(default)
    text = (
        text.replace(",", "")
        .replace("INR", "")
        .replace("ÃƒÂ¢Ã‹â€ Ã¢â‚¬â„¢", "-")
        .replace("ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Å“", "-")
        .replace("ÃƒÂ¢Ã¢â€šÂ¬Ã¢â‚¬Â", "-")
        .strip()
    )
    # Keep only numeric characters used in amounts after symbol/encoding cleanup.
    text = re.sub(r"[^0-9.\-()]", "", text)
    neg = False
    if text.startswith("(") and text.endswith(")"):
        neg = True
        text = text[1:-1].strip()
    try:
        val = float(text)
        return -val if neg else val
    except Exception:
        return float(default)

def _fund_text(value, max_len: int | None = None) -> str:
    text = str(value or "").strip()
    if max_len and len(text) > max_len:
        return text[:max_len]
    return text

def _fund_has_business_value(row: dict, fields: list[str]) -> bool:
    if not isinstance(row, dict):
        return False
    for field in fields:
        val = row.get(field)
        if val is None:
            continue
        if isinstance(val, str) and not val.strip():
            continue
        return True
    return False

