def _fund_delete_rows_for_date(cursor, table_name: str, entry_date: date, firm_acl: dict):
    if firm_acl.get("all"):
        cursor.execute(f"DELETE FROM dbo.{table_name} WHERE EntryDate = ?", (entry_date,))
        return
    firms = firm_acl.get("firms") or []
    if not firms:
        return
    placeholders = ",".join("?" * len(firms))
    sql = f"""
        DELETE FROM dbo.{table_name}
        WHERE EntryDate = ?
          AND UPPER(LTRIM(RTRIM(FirmName))) IN ({placeholders})
    """
    cursor.execute(sql, (entry_date, *firms))

def _fund_fetch_rows_for_date(cursor, table_name: str, columns: str, entry_date: date, firm_acl: dict):
    params = [entry_date]
    sql = f"SELECT {columns} FROM dbo.{table_name} WHERE EntryDate = ?"
    if not firm_acl.get("all"):
        firms = firm_acl.get("firms") or []
        if not firms:
            return []
        placeholders = ",".join("?" * len(firms))
        sql += f" AND UPPER(LTRIM(RTRIM(FirmName))) IN ({placeholders})"
        params.extend(firms)
    sql += " ORDER BY FirmName, BankName"
    try:
        cursor.execute(sql, params)
    except Exception:
        return []
    rows = cursor.fetchall()
    cols = [c[0] for c in cursor.description]
    return [{cols[i]: row[i] for i in range(len(cols))} for row in rows]

def _fund_fetch_latest_daily_before(cursor, entry_date: date, firm_acl: dict):
    params = [entry_date]
    sql = "SELECT MAX(EntryDate) AS LastDate FROM dbo.HID_Fund_Daily_Position WHERE EntryDate < ?"
    if not firm_acl.get("all"):
        firms = firm_acl.get("firms") or []
        if not firms:
            return None, []
        placeholders = ",".join("?" * len(firms))
        sql += f" AND UPPER(LTRIM(RTRIM(FirmName))) IN ({placeholders})"
        params.extend(firms)
    cursor.execute(sql, params)
    row = cursor.fetchone()
    if not row or not row[0]:
        return None, []
    prev_date = row[0]
    prev_rows = _fund_fetch_rows_for_date(
        cursor,
        "HID_Fund_Daily_Position",
        "EntryDate, FirmName, BankName, AccountType, AccountLast4, CreditLimit, OpeningBalance, Receipts, PaymentsUsed, ClosingBalance, Remarks, UpdatedBy, UpdatedAt",
        prev_date,
        firm_acl,
    )
    return prev_date, prev_rows

def _fund_fetch_daily_memory_profiles(cursor, entry_date: date, firm_acl: dict):
    """
    Return latest known account profiles up to selected date.
    Used for UI autofill memory (editable by user).
    """
    params = [entry_date]
    sql = """
        SELECT
            LTRIM(RTRIM(FirmName)) AS FirmName,
            LTRIM(RTRIM(BankName)) AS BankName,
            LTRIM(RTRIM(AccountType)) AS AccountType,
            LTRIM(RTRIM(AccountLast4)) AS AccountLast4,
            MAX(CAST(CreditLimit AS DECIMAL(18,2))) AS CreditLimit,
            MAX(EntryDate) AS LastDate
        FROM dbo.HID_Fund_Daily_Position
        WHERE EntryDate <= ?
    """
    if not firm_acl.get("all"):
        firms = firm_acl.get("firms") or []
        if not firms:
            return []
        placeholders = ",".join("?" * len(firms))
        sql += f" AND UPPER(LTRIM(RTRIM(FirmName))) IN ({placeholders})"
        params.extend(firms)
    sql += """
        GROUP BY
            LTRIM(RTRIM(FirmName)),
            LTRIM(RTRIM(BankName)),
            LTRIM(RTRIM(AccountType)),
            LTRIM(RTRIM(AccountLast4))
        ORDER BY MAX(EntryDate) DESC
    """
    try:
        cursor.execute(sql, params)
    except Exception:
        return []

    rows = cursor.fetchall()
    cols = [c[0] for c in cursor.description]
    out = []
    for row in rows:
        rec = {cols[i]: row[i] for i in range(len(cols))}
        out.append({
            "firm_name": _normalize_firm_name(rec.get("FirmName")),
            "bank_name": _fund_text(rec.get("BankName"), 120),
            "account_type": _fund_text(rec.get("AccountType"), 40),
            "account_last4": _fund_text(rec.get("AccountLast4"), 20),
            "credit_limit": round(_fund_parse_decimal(rec.get("CreditLimit")), 2),
            "last_date": rec.get("LastDate").isoformat() if isinstance(rec.get("LastDate"), (date, datetime)) else None,
        })
    return out

def _fund_fetch_master_accounts(cursor, firm_acl: dict, only_active: bool = False):
    params = []
    sql = """
        SELECT Id, FirmName, BankName, AccountType, AccountLast4, CreditLimit, IsActive, UpdatedBy, UpdatedAt
        FROM dbo.HID_Fund_Master_Accounts
        WHERE 1 = 1
    """
    if only_active:
        sql += " AND ISNULL(IsActive, 1) = 1"
    if not firm_acl.get("all"):
        firms = firm_acl.get("firms") or []
        if not firms:
            return []
        placeholders = ",".join("?" * len(firms))
        sql += f" AND UPPER(LTRIM(RTRIM(FirmName))) IN ({placeholders})"
        params.extend(firms)
    sql += " ORDER BY FirmName, BankName, AccountType, AccountLast4"
    try:
        cursor.execute(sql, params)
    except Exception:
        return []
    rows = cursor.fetchall()
    cols = [c[0] for c in cursor.description]
    out = []
    for row in rows:
        rec = {cols[i]: row[i] for i in range(len(cols))}
        out.append({
            "id": rec.get("Id"),
            "firm_name": _normalize_firm_name(rec.get("FirmName")),
            "bank_name": _fund_text(rec.get("BankName"), 120),
            "account_type": _fund_text(rec.get("AccountType"), 40),
            "account_last4": _fund_text(rec.get("AccountLast4"), 20),
            "credit_limit": round(_fund_parse_decimal(rec.get("CreditLimit")), 2),
            "is_active": bool(rec.get("IsActive", 1)),
            "updated_by": _fund_text(rec.get("UpdatedBy"), 100),
            "updated_at": rec.get("UpdatedAt").isoformat() if isinstance(rec.get("UpdatedAt"), datetime) else None,
        })
    return out

def _can_manage_fund_master() -> bool:
    role = (session.get("role") or "").strip()
    if role == "IT":
        return True
    rights = _normalize_section_list(session.get("section_rights"))
    return "fund_position_admin" in rights


def _can_override_fund_snapshot_lock() -> bool:
    role_base = _role_base(session.get("role") or "")
    if role_base == "IT":
        return True
    username = (session.get("username") or "").strip().lower()
    return username == "admin"

FUND_SNAPSHOT_EDIT_WINDOW_DAYS = 7

def _fund_snapshot_edit_state(entry_date: date):
    today_local = datetime.now(tz=LOCAL_TZ).date()
    age_days = (today_local - entry_date).days
    cutoff_date = today_local - timedelta(days=FUND_SNAPSHOT_EDIT_WINDOW_DAYS)
    can_override = _can_override_fund_snapshot_lock()
    is_locked = (age_days > FUND_SNAPSHOT_EDIT_WINDOW_DAYS) and not can_override

    message = ""
    if is_locked:
        message = (
            f"Snapshot {entry_date.isoformat()} is locked for regular users "
            f"because it is older than {FUND_SNAPSHOT_EDIT_WINDOW_DAYS} days "
            f"(today: {today_local.isoformat()}). Only Admin or IT can edit."
        )

    return {
        "is_edit_locked": bool(is_locked),
        "can_override_edit_lock": bool(can_override),
        "edit_lock_age_days": int(age_days),
        "edit_lock_window_days": int(FUND_SNAPSHOT_EDIT_WINDOW_DAYS),
        "edit_lock_cutoff_date": cutoff_date.isoformat(),
        "edit_lock_today": today_local.isoformat(),
        "edit_lock_message": message,
    }


def _fund_amount_class(amount) -> str:
    val = _fund_parse_decimal(amount)
    if val < 0:
        return "NEGATIVE"
    if val > 0:
        return "POSITIVE"
    return "ZERO"


def _fund_row_key(row: dict, key_fields: list[str]) -> str:
    row = row or {}
    return "|".join(str(row.get(field) or "").strip().upper() for field in key_fields)


def _fund_normalize_rows_for_diff(rows: list[dict], key_fields: list[str]) -> dict:
    out = {}
    for idx, row in enumerate(rows or []):
        if not isinstance(row, dict):
            continue
        key = _fund_row_key(row, key_fields) or f"row:{idx + 1}"
        if key in out:
            key = f"{key}#{idx + 1}"
        out[key] = row
    return out


def _fund_diff_rows_by_key(
    old_rows: list[dict],
    new_rows: list[dict],
    *,
    key_fields: list[str],
    compare_fields: list[str],
    label_fields: list[str],
    max_changes: int = 200,
) -> dict:
    old_map = _fund_normalize_rows_for_diff(old_rows, key_fields)
    new_map = _fund_normalize_rows_for_diff(new_rows, key_fields)
    keys = sorted(set(old_map.keys()) | set(new_map.keys()))
    added = []
    removed = []
    changed = []
    changed_fields = {}

    for key in keys:
        old = old_map.get(key)
        new = new_map.get(key)
        if old is None and new is not None:
            label = " | ".join(str(new.get(f) or "").strip() for f in label_fields if str(new.get(f) or "").strip())
            added.append({"key": key, "label": _clip_text(label, 180)})
            continue
        if new is None and old is not None:
            label = " | ".join(str(old.get(f) or "").strip() for f in label_fields if str(old.get(f) or "").strip())
            removed.append({"key": key, "label": _clip_text(label, 180)})
            continue
        field_changes = []
        for field in compare_fields:
            old_val = old.get(field)
            new_val = new.get(field)
            if old_val != new_val:
                field_changes.append({
                    "field": field,
                    "from": old_val,
                    "to": new_val,
                })
                changed_fields[field] = changed_fields.get(field, 0) + 1
        if field_changes:
            label = " | ".join(str((new or old).get(f) or "").strip() for f in label_fields if str((new or old).get(f) or "").strip())
            changed.append({
                "key": key,
                "label": _clip_text(label, 180),
                "changes": field_changes,
            })

    total_changed = len(added) + len(removed) + len(changed)
    return {
        "counts": {
            "old": len(old_rows or []),
            "new": len(new_rows or []),
            "added": len(added),
            "removed": len(removed),
            "changed_rows": len(changed),
            "total_changed": total_changed,
        },
        "changed_fields": changed_fields,
        "added": added[:max_changes],
        "removed": removed[:max_changes],
        "changed": changed[:max_changes],
    }


def _fund_build_save_diff(old_payload: dict | None, new_payload: dict) -> dict:
    old_payload = old_payload or {}
    new_payload = new_payload or {}
    daily_diff = _fund_diff_rows_by_key(
        old_payload.get("daily_rows") or [],
        new_payload.get("daily_rows") or [],
        key_fields=["firm_name", "bank_name", "account_type", "account_last4"],
        compare_fields=[
            "credit_limit", "opening_balance", "receipts", "payments_used", "closing_balance", "remarks"
        ],
        label_fields=["firm_name", "bank_name", "account_type", "account_last4"],
    )
    wc_diff = _fund_diff_rows_by_key(
        old_payload.get("wc_rows") or [],
        new_payload.get("wc_rows") or [],
        key_fields=["firm_name", "bank_name", "facility_type", "due_date"],
        compare_fields=[
            "sanction_limit", "drawing_power", "utilised", "available_limit", "roi_pct", "due_date", "remarks"
        ],
        label_fields=["firm_name", "bank_name", "facility_type", "due_date"],
    )
    fdr_diff = _fund_diff_rows_by_key(
        old_payload.get("fdr_rows") or [],
        new_payload.get("fdr_rows") or [],
        key_fields=["firm_name", "bank_name", "fdr_no"],
        compare_fields=[
            "fdr_amount", "start_date", "maturity_date", "roi_pct", "lien_flag", "linked_loan", "remarks"
        ],
        label_fields=["firm_name", "bank_name", "fdr_no"],
    )

    firms = set()
    for section_rows in [new_payload.get("daily_rows"), new_payload.get("wc_rows"), new_payload.get("fdr_rows")]:
        for row in (section_rows or []):
            firm = _normalize_firm_name((row or {}).get("firm_name") or "")
            if firm:
                firms.add(firm)

    totals = new_payload.get("totals") or {}
    return {
        "sections": {
            "daily": daily_diff,
            "wc": wc_diff,
            "fdr": fdr_diff,
        },
        "summary": {
            "rows_daily": len(new_payload.get("daily_rows") or []),
            "rows_wc": len(new_payload.get("wc_rows") or []),
            "rows_fdr": len(new_payload.get("fdr_rows") or []),
            "total_changed_rows": (
                daily_diff["counts"]["total_changed"]
                + wc_diff["counts"]["total_changed"]
                + fdr_diff["counts"]["total_changed"]
            ),
        },
        "totals": {
            "ca_balance": _fund_parse_decimal(totals.get("ca_balance")),
            "wc_available": _fund_parse_decimal(totals.get("wc_available")),
            "fdr_value": _fund_parse_decimal(totals.get("fdr_value")),
            "net_fund_position": _fund_parse_decimal(totals.get("net_fund_position")),
            "status": totals.get("status") or ("ALERT" if _fund_parse_decimal(totals.get("net_fund_position")) < 0 else "OK"),
        },
        "firms": sorted(firms),
    }

def _build_fund_dashboard_rows(daily_rows: list[dict], wc_rows: list[dict], fdr_rows: list[dict], firm_acl: dict):
    summary_map = {}

    def _pick_firm(row):
        return _normalize_firm_name(row.get("FirmName") or row.get("firm_name") or "")

    for row in daily_rows:
        firm = _pick_firm(row)
        if not firm:
            continue
        ent = summary_map.setdefault(firm, {"firm_name": firm, "ca_balance": 0.0, "wc_available": 0.0, "fdr_value": 0.0})
        ent["ca_balance"] += _fund_parse_decimal(row.get("ClosingBalance"))

    for row in wc_rows:
        firm = _pick_firm(row)
        if not firm:
            continue
        ent = summary_map.setdefault(firm, {"firm_name": firm, "ca_balance": 0.0, "wc_available": 0.0, "fdr_value": 0.0})
        ent["wc_available"] += _fund_parse_decimal(row.get("AvailableLimit"))

    for row in fdr_rows:
        firm = _pick_firm(row)
        if not firm:
            continue
        ent = summary_map.setdefault(firm, {"firm_name": firm, "ca_balance": 0.0, "wc_available": 0.0, "fdr_value": 0.0})
        ent["fdr_value"] += _fund_parse_decimal(row.get("FdrAmount"))

    if not summary_map and not firm_acl.get("all"):
        for firm in (firm_acl.get("firms") or []):
            summary_map.setdefault(firm, {"firm_name": firm, "ca_balance": 0.0, "wc_available": 0.0, "fdr_value": 0.0})

    rows = []
    for firm in sorted(summary_map.keys()):
        ent = summary_map[firm]
        net = float(ent["ca_balance"] + ent["wc_available"] + ent["fdr_value"])
        rows.append({
            "firm_name": firm,
            "ca_balance": round(float(ent["ca_balance"]), 2),
            "wc_available": round(float(ent["wc_available"]), 2),
            "fdr_value": round(float(ent["fdr_value"]), 2),
            "net_fund_position": round(net, 2),
            "status": "ALERT" if net < 0 else "OK",
        })
    return rows

def _fund_fetch_rows_for_range(cursor, table_name: str, columns: str, from_date: date, to_date: date, firm_acl: dict):
    params = [from_date, to_date]
    sql = f"SELECT {columns} FROM dbo.{table_name} WHERE EntryDate >= ? AND EntryDate <= ?"
    if not firm_acl.get("all"):
        firms = firm_acl.get("firms") or []
        if not firms:
            return []
        placeholders = ",".join("?" * len(firms))
        sql += f" AND UPPER(LTRIM(RTRIM(FirmName))) IN ({placeholders})"
        params.extend(firms)
    sql += " ORDER BY EntryDate, FirmName, BankName"
    try:
        cursor.execute(sql, params)
    except Exception:
        return []
    rows = cursor.fetchall()
    cols = [c[0] for c in cursor.description]
    return [{cols[i]: row[i] for i in range(len(cols))} for row in rows]


def _fund_group_rows_by_date(rows: list[dict]) -> dict:
    grouped = {}
    for row in (rows or []):
        entry_date = _fund_parse_date_value((row or {}).get("EntryDate"))
        if not entry_date:
            continue
        grouped.setdefault(entry_date, []).append(row)
    return grouped


def _fund_export_iso_date(val):
    if isinstance(val, datetime):
        return val.date().isoformat()
    if isinstance(val, date):
        return val.isoformat()
    return None


def _fund_export_iso_datetime(val):
    if isinstance(val, datetime):
        return val.isoformat()
    return None


def _fund_export_daily_row(row: dict, entry_date: date) -> dict:
    opening = _fund_parse_decimal(row.get("OpeningBalance"))
    receipts = _fund_parse_decimal(row.get("Receipts"))
    payments = _fund_parse_decimal(row.get("PaymentsUsed"))
    closing_raw = row.get("ClosingBalance")
    closing = _fund_parse_decimal(closing_raw, opening + receipts - payments) if closing_raw is not None else (opening + receipts - payments)
    return {
        "entry_date": _fund_export_iso_date(row.get("EntryDate")) or entry_date.isoformat(),
        "firm_name": _normalize_firm_name(row.get("FirmName")),
        "bank_name": _fund_text(row.get("BankName"), 120),
        "account_type": _fund_text(row.get("AccountType"), 40),
        "account_last4": _fund_text(row.get("AccountLast4"), 20),
        "credit_limit": round(_fund_parse_decimal(row.get("CreditLimit")), 2),
        "opening_balance": round(opening, 2),
        "receipts": round(receipts, 2),
        "payments_used": round(payments, 2),
        "closing_balance": round(closing, 2),
        "remarks": _fund_text(row.get("Remarks"), 500),
        "updated_by": _fund_text(row.get("UpdatedBy"), 100),
        "updated_at": _fund_export_iso_datetime(row.get("UpdatedAt")),
    }


def _fund_export_wc_row(row: dict, entry_date: date) -> dict:
    sanction = _fund_parse_decimal(row.get("SanctionLimit"))
    utilised = _fund_parse_decimal(row.get("Utilised"))
    available_raw = row.get("AvailableLimit")
    available = _fund_parse_decimal(available_raw, sanction - utilised) if available_raw is not None else (sanction - utilised)
    return {
        "entry_date": _fund_export_iso_date(row.get("EntryDate")) or entry_date.isoformat(),
        "firm_name": _normalize_firm_name(row.get("FirmName")),
        "bank_name": _fund_text(row.get("BankName"), 120),
        "facility_type": _fund_text(row.get("FacilityType"), 80),
        "sanction_limit": round(sanction, 2),
        "drawing_power": round(_fund_parse_decimal(row.get("DrawingPower")), 2),
        "utilised": round(utilised, 2),
        "available_limit": round(available, 2),
        "roi_pct": round(_fund_parse_decimal(row.get("ROIPct")), 4),
        "due_date": _fund_export_iso_date(row.get("DueDate")),
        "remarks": _fund_text(row.get("Remarks"), 500),
        "updated_by": _fund_text(row.get("UpdatedBy"), 100),
        "updated_at": _fund_export_iso_datetime(row.get("UpdatedAt")),
    }


def _fund_export_fdr_row(row: dict, entry_date: date) -> dict:
    return {
        "entry_date": _fund_export_iso_date(row.get("EntryDate")) or entry_date.isoformat(),
        "firm_name": _normalize_firm_name(row.get("FirmName")),
        "bank_name": _fund_text(row.get("BankName"), 120),
        "fdr_no": _fund_text(row.get("FdrNo"), 200),
        "fdr_amount": round(_fund_parse_decimal(row.get("FdrAmount")), 2),
        "start_date": _fund_export_iso_date(row.get("StartDate")),
        "maturity_date": _fund_export_iso_date(row.get("MaturityDate")),
        "roi_pct": round(_fund_parse_decimal(row.get("ROIPct")), 4),
        "lien_flag": _fund_text(row.get("LienFlag"), 10),
        "linked_loan": _fund_text(row.get("LinkedLoan"), 200),
        "remarks": _fund_text(row.get("Remarks"), 500),
        "updated_by": _fund_text(row.get("UpdatedBy"), 100),
        "updated_at": _fund_export_iso_datetime(row.get("UpdatedAt")),
    }


def _fund_build_range_timeline(from_date: date, to_date: date, firm_acl: dict):
    with _get_login_db_connection() as conn:
        _ensure_fund_tracker_tables(conn)
        cursor = conn.cursor()
        daily_range_rows = _fund_fetch_rows_for_range(
            cursor,
            "HID_Fund_Daily_Position",
            "EntryDate, FirmName, BankName, AccountType, AccountLast4, CreditLimit, OpeningBalance, Receipts, PaymentsUsed, ClosingBalance, Remarks, UpdatedBy, UpdatedAt",
            from_date,
            to_date,
            firm_acl,
        )
        wc_range_rows = _fund_fetch_rows_for_range(
            cursor,
            "HID_Fund_WC_Loan_Position",
            "EntryDate, FirmName, BankName, FacilityType, SanctionLimit, DrawingPower, Utilised, AvailableLimit, ROIPct, DueDate, Remarks, UpdatedBy, UpdatedAt",
            from_date,
            to_date,
            firm_acl,
        )
        fdr_range_rows = _fund_fetch_rows_for_range(
            cursor,
            "HID_Fund_FDR_Tracker",
            "EntryDate, FirmName, BankName, FdrNo, FdrAmount, StartDate, MaturityDate, ROIPct, LienFlag, LinkedLoan, Remarks, UpdatedBy, UpdatedAt",
            from_date,
            to_date,
            firm_acl,
        )
        carry_seed_date, carry_seed_rows = _fund_fetch_latest_daily_before(cursor, from_date, firm_acl)

    daily_by_date = _fund_group_rows_by_date(daily_range_rows)
    wc_by_date = _fund_group_rows_by_date(wc_range_rows)
    fdr_by_date = _fund_group_rows_by_date(fdr_range_rows)

    timeline = []
    day = from_date
    while day <= to_date:
        current_daily_raw = daily_by_date.get(day, [])
        current_wc_raw = wc_by_date.get(day, [])
        current_fdr_raw = fdr_by_date.get(day, [])

        carried_from = None
        if current_daily_raw:
            effective_daily_raw = current_daily_raw
            carry_seed_date = day
            carry_seed_rows = current_daily_raw
        elif carry_seed_rows:
            carried_from = carry_seed_date
            effective_daily_raw = []
            for prev in carry_seed_rows:
                prev_open = _fund_parse_decimal(prev.get("OpeningBalance"))
                prev_receipts = _fund_parse_decimal(prev.get("Receipts"))
                prev_payments = _fund_parse_decimal(prev.get("PaymentsUsed"))
                carried_closing = _fund_parse_decimal(prev.get("ClosingBalance"), prev_open + prev_receipts - prev_payments)
                effective_daily_raw.append({
                    "EntryDate": day,
                    "FirmName": prev.get("FirmName"),
                    "BankName": prev.get("BankName"),
                    "AccountType": prev.get("AccountType"),
                    "AccountLast4": prev.get("AccountLast4"),
                    "CreditLimit": prev.get("CreditLimit"),
                    "OpeningBalance": carried_closing,
                    "Receipts": 0.0,
                    "PaymentsUsed": 0.0,
                    "ClosingBalance": carried_closing,
                    "Remarks": "",
                    "UpdatedBy": prev.get("UpdatedBy"),
                    "UpdatedAt": None,
                })
        else:
            effective_daily_raw = []

        daily_rows = [_fund_export_daily_row(row, day) for row in effective_daily_raw]
        wc_rows = [_fund_export_wc_row(row, day) for row in current_wc_raw]
        fdr_rows = [_fund_export_fdr_row(row, day) for row in current_fdr_raw]
        dashboard_rows = _build_fund_dashboard_rows(effective_daily_raw, current_wc_raw, current_fdr_raw, firm_acl)
        totals = {
            "ca_balance": round(sum(row["ca_balance"] for row in dashboard_rows), 2),
            "wc_available": round(sum(row["wc_available"] for row in dashboard_rows), 2),
            "fdr_value": round(sum(row["fdr_value"] for row in dashboard_rows), 2),
        }
        totals["net_fund_position"] = round(totals["ca_balance"] + totals["wc_available"] + totals["fdr_value"], 2)
        totals["status"] = "ALERT" if totals["net_fund_position"] < 0 else "OK"

        timeline.append({
            "date": day,
            "date_iso": day.isoformat(),
            "has_entry": bool(current_daily_raw or current_wc_raw or current_fdr_raw),
            "carried_forward_from": carried_from.isoformat() if isinstance(carried_from, (date, datetime)) else None,
            "daily_rows": daily_rows,
            "wc_rows": wc_rows,
            "fdr_rows": fdr_rows,
            "dashboard_rows": dashboard_rows,
            "totals": totals,
        })

        day += timedelta(days=1)

    return timeline


def _fund_history_row_key(section: str, row: dict) -> str:
    if section == "daily":
        parts = [
            _normalize_firm_name(row.get("firm_name")).upper(),
            _fund_text(row.get("bank_name"), 120).upper(),
            _fund_text(row.get("account_type"), 40).upper(),
            _fund_text(row.get("account_last4"), 20).upper(),
        ]
    elif section == "wc":
        parts = [
            _normalize_firm_name(row.get("firm_name")).upper(),
            _fund_text(row.get("bank_name"), 120).upper(),
            _fund_text(row.get("facility_type"), 80).upper(),
        ]
    else:
        parts = [
            _normalize_firm_name(row.get("firm_name")).upper(),
            _fund_text(row.get("bank_name"), 120).upper(),
            _fund_text(row.get("fdr_no"), 200).upper(),
        ]
    key = "|".join(parts).strip("|")
    return key


def _fund_history_row_label(section: str, row: dict) -> str:
    firm = _normalize_firm_name(row.get("firm_name"))
    bank = _fund_text(row.get("bank_name"), 60)
    if section == "daily":
        acct_type = _fund_text(row.get("account_type"), 24)
        last4 = _fund_text(row.get("account_last4"), 20)
        return " | ".join([x for x in [firm, bank, acct_type, last4] if x]) or "Daily Row"
    if section == "wc":
        facility = _fund_text(row.get("facility_type"), 36)
        return " | ".join([x for x in [firm, bank, facility] if x]) or "WC Row"
    fdr_no = _fund_text(row.get("fdr_no"), 40)
    return " | ".join([x for x in [firm, bank, fdr_no] if x]) or "FDR Row"


def _fund_build_history_trace_rows(timeline: list[dict]) -> list[dict]:
    section_specs = {
        "daily": {
            "rows_key": "daily_rows",
            "fields": [
                ("credit_limit", "Credit Limit", "amount"),
                ("opening_balance", "Opening Balance", "amount"),
                ("receipts", "Receipts", "amount"),
                ("payments_used", "Payments Used", "amount"),
                ("closing_balance", "Closing Balance", "amount"),
                ("remarks", "Remarks", "text"),
            ],
        },
        "wc": {
            "rows_key": "wc_rows",
            "fields": [
                ("sanction_limit", "Sanction Limit", "amount"),
                ("drawing_power", "Drawing Power", "amount"),
                ("utilised", "Utilised", "amount"),
                ("available_limit", "Available Limit", "amount"),
                ("roi_pct", "ROI %", "number"),
                ("due_date", "Due Date", "date"),
                ("remarks", "Remarks", "text"),
            ],
        },
        "fdr": {
            "rows_key": "fdr_rows",
            "fields": [
                ("fdr_amount", "FDR Amount", "amount"),
                ("start_date", "Start Date", "date"),
                ("maturity_date", "Maturity Date", "date"),
                ("roi_pct", "ROI %", "number"),
                ("lien_flag", "Lien Flag", "text"),
                ("linked_loan", "Linked Loan", "text"),
                ("remarks", "Remarks", "text"),
            ],
        },
    }

    def _fmt_value(kind: str, value) -> str:
        if kind == "amount":
            return _format_indian_currency(_fund_parse_decimal(value))
        if kind == "number":
            val = _fund_parse_decimal(value)
            text = f"{val:.4f}".rstrip("0").rstrip(".")
            return text or "0"
        txt = _fund_text(value, 200)
        return txt or "-"

    history_rows = []
    prev_state = {section: None for section in section_specs.keys()}

    ordered = sorted(timeline or [], key=lambda x: str((x or {}).get("date_iso") or ""))
    for snap in ordered:
        if not (snap or {}).get("has_entry"):
            continue
        snap_date = str((snap or {}).get("date_iso") or "")
        for section, spec in section_specs.items():
            rows = (snap or {}).get(spec["rows_key"]) or []
            curr_map = {}
            for row in rows:
                key = _fund_history_row_key(section, row)
                if key:
                    curr_map[key] = row

            if prev_state.get(section) is None:
                prev_state[section] = curr_map
                continue

            prev_map = prev_state.get(section) or {}
            all_keys = sorted(set(prev_map.keys()) | set(curr_map.keys()))
            for key in all_keys:
                prev_row = prev_map.get(key)
                curr_row = curr_map.get(key)
                account = _fund_history_row_label(section, curr_row or prev_row or {})
                updated_by = _fund_text((curr_row or prev_row or {}).get("updated_by"), 100) or "-"

                if prev_row is None and curr_row is not None:
                    history_rows.append({
                        "date": snap_date,
                        "section": section.upper(),
                        "account": account,
                        "field": "Row Status",
                        "previous": "-",
                        "current": "Added",
                        "delta": "-",
                        "updated_by": updated_by,
                    })
                    continue
                if prev_row is not None and curr_row is None:
                    history_rows.append({
                        "date": snap_date,
                        "section": section.upper(),
                        "account": account,
                        "field": "Row Status",
                        "previous": "Present",
                        "current": "Removed",
                        "delta": "-",
                        "updated_by": updated_by,
                    })
                    continue

                for field, label, kind in spec["fields"]:
                    prev_val = prev_row.get(field)
                    curr_val = curr_row.get(field)
                    if kind in {"amount", "number"}:
                        prev_num = _fund_parse_decimal(prev_val)
                        curr_num = _fund_parse_decimal(curr_val)
                        if abs(curr_num - prev_num) <= 0.0001:
                            continue
                        if kind == "amount":
                            prev_txt = _format_indian_currency(prev_num)
                            curr_txt = _format_indian_currency(curr_num)
                            delta_txt = _format_indian_currency(curr_num - prev_num)
                        else:
                            prev_txt = _fmt_value(kind, prev_num)
                            curr_txt = _fmt_value(kind, curr_num)
                            delta_txt = _fmt_value(kind, curr_num - prev_num)
                    else:
                        prev_txt = _fmt_value(kind, prev_val)
                        curr_txt = _fmt_value(kind, curr_val)
                        if prev_txt == curr_txt:
                            continue
                        delta_txt = "-"

                    history_rows.append({
                        "date": snap_date,
                        "section": section.upper(),
                        "account": account,
                        "field": label,
                        "previous": prev_txt,
                        "current": curr_txt,
                        "delta": delta_txt,
                        "updated_by": updated_by,
                    })

            prev_state[section] = curr_map

    return history_rows


def _build_fund_position_history_pdf(from_date: date, to_date: date, timeline: list[dict], history_rows: list[dict], exported_by: str, firm_acl: dict) -> bytes:
    from html import escape
    from reportlab.lib.pagesizes import A4, landscape
    from reportlab.lib import colors
    from reportlab.lib.units import mm
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer, PageBreak
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_LEFT, TA_CENTER, TA_RIGHT

    def _p(text: str, style):
        return Paragraph(str(text or ""), style)

    def _styled_table(data, col_widths, align_right_cols=None, align_center_cols=None):
        align_right_cols = align_right_cols or []
        align_center_cols = align_center_cols or []
        if not data:
            data = [["-"]]
        body_left_style = ParagraphStyle(
            "fund_pdf_cell_left",
            parent=styles["Normal"],
            fontName="Helvetica",
            fontSize=7.8,
            leading=9.2,
            alignment=TA_LEFT,
            wordWrap="CJK",
            textColor=colors.HexColor("#0f172a"),
        )
        body_right_style = ParagraphStyle(
            "fund_pdf_cell_right",
            parent=body_left_style,
            alignment=TA_RIGHT,
        )
        body_center_style = ParagraphStyle(
            "fund_pdf_cell_center",
            parent=body_left_style,
            alignment=TA_CENTER,
        )

        prepared = [list(data[0])]
        for row in data[1:]:
            out_row = []
            for idx, cell in enumerate(row):
                text = escape(str(cell if cell is not None else ""))
                if idx in align_right_cols:
                    out_row.append(Paragraph(text, body_right_style))
                elif idx in align_center_cols:
                    out_row.append(Paragraph(text, body_center_style))
                else:
                    out_row.append(Paragraph(text, body_left_style))
            prepared.append(out_row)

        tbl = Table(prepared, colWidths=[w * mm for w in col_widths], repeatRows=1)
        style = [
            ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#0f172a")),
            ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
            ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
            ("FONTSIZE", (0, 0), (-1, -1), 8),
            ("ROWBACKGROUNDS", (0, 1), (-1, -1), [colors.white, colors.HexColor("#f8fafc")]),
            ("GRID", (0, 0), (-1, -1), 0.25, colors.HexColor("#cbd5e1")),
            ("LEFTPADDING", (0, 0), (-1, -1), 4),
            ("RIGHTPADDING", (0, 0), (-1, -1), 4),
            ("TOPPADDING", (0, 0), (-1, -1), 3),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 3),
            ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
            ("ALIGN", (0, 0), (-1, 0), "LEFT"),
        ]
        for idx in align_right_cols:
            style.append(("ALIGN", (idx, 1), (idx, -1), "RIGHT"))
            style.append(("ALIGN", (idx, 0), (idx, 0), "RIGHT"))
        for idx in align_center_cols:
            style.append(("ALIGN", (idx, 1), (idx, -1), "CENTER"))
            style.append(("ALIGN", (idx, 0), (idx, 0), "CENTER"))
        tbl.setStyle(TableStyle(style))
        return tbl

    styles = getSampleStyleSheet()
    title_style = ParagraphStyle(
        "fund_pdf_title",
        parent=styles["Title"],
        fontName="Helvetica-Bold",
        fontSize=18,
        leading=21,
        alignment=TA_LEFT,
        textColor=colors.HexColor("#0f172a"),
    )
    sub_style = ParagraphStyle(
        "fund_pdf_sub",
        parent=styles["Normal"],
        fontName="Helvetica",
        fontSize=10,
        leading=13,
        textColor=colors.HexColor("#334155"),
    )
    section_style = ParagraphStyle(
        "fund_pdf_section",
        parent=styles["Heading3"],
        fontName="Helvetica-Bold",
        fontSize=12,
        leading=14,
        alignment=TA_LEFT,
        textColor=colors.HexColor("#0f172a"),
        spaceBefore=8,
        spaceAfter=6,
    )
    note_style = ParagraphStyle(
        "fund_pdf_note",
        parent=styles["Normal"],
        fontName="Helvetica",
        fontSize=9,
        leading=12,
        textColor=colors.HexColor("#475569"),
    )
    meta_key_style = ParagraphStyle(
        "fund_pdf_meta_key",
        parent=styles["Normal"],
        fontName="Helvetica-Bold",
        fontSize=9,
        leading=11,
        alignment=TA_LEFT,
        wordWrap="CJK",
        textColor=colors.HexColor("#0f172a"),
    )
    meta_val_style = ParagraphStyle(
        "fund_pdf_meta_val",
        parent=styles["Normal"],
        fontName="Helvetica",
        fontSize=9,
        leading=11,
        alignment=TA_LEFT,
        wordWrap="CJK",
        textColor=colors.HexColor("#0f172a"),
    )

    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%d-%b-%Y %I:%M %p")
    from_iso = from_date.isoformat()
    to_iso = to_date.isoformat()
    total_days = (to_date - from_date).days + 1
    snapshot_days = sum(1 for row in (timeline or []) if row.get("has_entry"))
    scope_text = "All assigned firms" if firm_acl.get("all") else ", ".join((firm_acl.get("firms") or []))
    scope_text = scope_text or "No firm scope"

    daily_detail_rows = []
    wc_detail_rows = []
    fdr_detail_rows = []
    summary_rows = []
    for snap in (timeline or []):
        source_text = "Actual Entry"
        if not snap.get("has_entry"):
            carried_from = snap.get("carried_forward_from")
            source_text = f"Carry-forward from {carried_from}" if carried_from else "No Data"

        totals = snap.get("totals") or {}
        summary_rows.append([
            snap.get("date_iso") or "",
            source_text,
            _format_indian_currency(totals.get("ca_balance")),
            _format_indian_currency(totals.get("wc_available")),
            _format_indian_currency(totals.get("fdr_value")),
            _format_indian_currency(totals.get("net_fund_position")),
            str(totals.get("status") or "OK"),
        ])

        source_short = "Actual" if snap.get("has_entry") else ("Carry" if snap.get("carried_forward_from") else "No Data")
        for row in (snap.get("daily_rows") or []):
            daily_detail_rows.append([
                snap.get("date_iso") or "",
                source_short,
                _fund_text(row.get("firm_name"), 28),
                _fund_text(row.get("bank_name"), 28),
                _fund_text(row.get("account_type"), 16),
                _fund_text(row.get("account_last4"), 12),
                _format_indian_currency(row.get("opening_balance")),
                _format_indian_currency(row.get("receipts")),
                _format_indian_currency(row.get("payments_used")),
                _format_indian_currency(row.get("closing_balance")),
                _fund_text(row.get("updated_by"), 20) or "-",
            ])

        for row in (snap.get("wc_rows") or []):
            wc_detail_rows.append([
                snap.get("date_iso") or "",
                _fund_text(row.get("firm_name"), 28),
                _fund_text(row.get("bank_name"), 28),
                _fund_text(row.get("facility_type"), 24),
                _format_indian_currency(row.get("sanction_limit")),
                _format_indian_currency(row.get("utilised")),
                _format_indian_currency(row.get("available_limit")),
                f"{_fund_parse_decimal(row.get('roi_pct')):.2f}",
                _fund_text(row.get("due_date"), 12) or "-",
                _fund_text(row.get("updated_by"), 20) or "-",
            ])

        for row in (snap.get("fdr_rows") or []):
            fdr_detail_rows.append([
                snap.get("date_iso") or "",
                _fund_text(row.get("firm_name"), 28),
                _fund_text(row.get("bank_name"), 24),
                _fund_text(row.get("fdr_no"), 24),
                _format_indian_currency(row.get("fdr_amount")),
                _fund_text(row.get("start_date"), 12) or "-",
                _fund_text(row.get("maturity_date"), 12) or "-",
                f"{_fund_parse_decimal(row.get('roi_pct')):.2f}",
                _fund_text(row.get("lien_flag"), 8),
                _fund_text(row.get("linked_loan"), 22),
                _fund_text(row.get("updated_by"), 20) or "-",
            ])

    max_history_rows = 1500
    history_render_rows = history_rows[:max_history_rows]
    history_truncated = len(history_rows) > max_history_rows
    history_table_rows = []
    for row in history_render_rows:
        history_table_rows.append([
            _fund_text(row.get("date"), 12),
            _fund_text(row.get("section"), 8),
            _fund_text(row.get("account"), 70),
            _fund_text(row.get("field"), 24),
            _fund_text(row.get("previous"), 60),
            _fund_text(row.get("current"), 60),
            _fund_text(row.get("delta"), 30),
            _fund_text(row.get("updated_by"), 24),
        ])

    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=landscape(A4),
        leftMargin=10 * mm,
        rightMargin=10 * mm,
        topMargin=11 * mm,
        bottomMargin=16 * mm,
    )
    elements = []
    elements.append(_p("Fund Position Tracker - History Report", title_style))
    elements.append(_p("Professional export for daily fund position review and traceability", sub_style))
    elements.append(Spacer(1, 5))

    meta_data = [
        [_p("Date Range", meta_key_style), _p(f"{from_iso} to {to_iso}", meta_val_style), _p("Exported By", meta_key_style), _p(exported_by or "-", meta_val_style)],
        [_p("Exported At", meta_key_style), _p(exported_at, meta_val_style), _p("Firm Scope", meta_key_style), _p(_fund_text(scope_text, 120), meta_val_style)],
        [_p("Total Calendar Days", meta_key_style), _p(str(total_days), meta_val_style), _p("Snapshots with Entries", meta_key_style), _p(str(snapshot_days), meta_val_style)],
    ]
    # Wider key columns prevent label spillover (e.g., "Snapshots with Entries").
    meta_tbl = Table(meta_data, colWidths=[40 * mm, 72 * mm, 44 * mm, 121 * mm])
    meta_tbl.setStyle(TableStyle([
        ("GRID", (0, 0), (-1, -1), 0.25, colors.HexColor("#cbd5e1")),
        ("BACKGROUND", (0, 0), (-1, -1), colors.HexColor("#f8fafc")),
        ("LEFTPADDING", (0, 0), (-1, -1), 5),
        ("RIGHTPADDING", (0, 0), (-1, -1), 5),
        ("TOPPADDING", (0, 0), (-1, -1), 4),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 4),
        ("VALIGN", (0, 0), (-1, -1), "TOP"),
    ]))
    elements.append(meta_tbl)
    elements.append(Spacer(1, 8))

    elements.append(_p("Daily Net Position Timeline", section_style))
    summary_header = ["Date", "Snapshot Source", "CA Balance", "WC Available", "FDR Value", "Net Position", "Status"]
    summary_table = _styled_table([summary_header] + (summary_rows or [["-", "No data", "0.00", "0.00", "0.00", "0.00", "OK"]]), [20, 52, 30, 30, 28, 30, 18], align_right_cols=[2, 3, 4, 5])
    elements.append(summary_table)
    elements.append(Spacer(1, 8))

    elements.append(_p("Detailed Daily Fund Rows", section_style))
    if daily_detail_rows:
        daily_header = ["Date", "Source", "Firm", "Bank", "Type", "Last4", "Opening", "Receipts", "Payments", "Closing", "Updated By"]
        elements.append(_styled_table([daily_header] + daily_detail_rows, [18, 16, 28, 28, 18, 12, 24, 22, 22, 24, 20], align_right_cols=[6, 7, 8, 9]))
    else:
        elements.append(_p("No Daily Fund rows found in the selected range.", note_style))

    elements.append(PageBreak())
    elements.append(_p("Detailed WC and Loan Rows", section_style))
    if wc_detail_rows:
        wc_header = ["Date", "Firm", "Bank", "Facility", "Sanction", "Utilised", "Available", "ROI %", "Due Date", "Updated By"]
        elements.append(_styled_table([wc_header] + wc_detail_rows, [18, 28, 28, 28, 22, 22, 22, 14, 20, 20], align_right_cols=[4, 5, 6, 7]))
    else:
        elements.append(_p("No WC and Loan rows found in the selected range.", note_style))

    elements.append(Spacer(1, 8))
    elements.append(_p("Detailed FDR Rows", section_style))
    if fdr_detail_rows:
        fdr_header = ["Date", "Firm", "Bank", "FDR No", "Amount", "Start", "Maturity", "ROI %", "Lien", "Linked Loan", "Updated By"]
        elements.append(_styled_table([fdr_header] + fdr_detail_rows, [18, 26, 24, 26, 22, 18, 18, 14, 12, 26, 20], align_right_cols=[4, 7]))
    else:
        elements.append(_p("No FDR rows found in the selected range.", note_style))

    elements.append(PageBreak())
    elements.append(_p("Field History Trace (Day-over-Day on Snapshot Dates)", section_style))
    if history_truncated:
        elements.append(_p(f"Showing first {max_history_rows} changes out of {len(history_rows)} total changes.", note_style))
        elements.append(Spacer(1, 4))
    if history_table_rows:
        history_header = ["Date", "Sec", "Account", "Field", "Previous", "Current", "Delta", "Updated By"]
        elements.append(
            _styled_table(
                [history_header] + history_table_rows,
                [18, 12, 46, 30, 35, 35, 20, 24],
                align_right_cols=[4, 5, 6],
                align_center_cols=[0, 1, 7],
            )
        )
    else:
        elements.append(_p("No field-level changes detected across snapshot dates in this range.", note_style))

    footer_line_1 = f"Fund Position History Report | Date Range: {from_iso} to {to_iso}"
    footer_line_2 = f"Exported By: {exported_by or '-'} | Exported At: {exported_at}"

    def _on_page(canvas, doc_obj):
        canvas.saveState()
        canvas.setStrokeColor(colors.HexColor("#cbd5e1"))
        canvas.setLineWidth(0.5)
        canvas.line(doc_obj.leftMargin, 11 * mm, doc_obj.pagesize[0] - doc_obj.rightMargin, 11 * mm)
        canvas.setFont("Helvetica", 8)
        canvas.setFillColor(colors.HexColor("#475569"))
        canvas.drawString(doc_obj.leftMargin, 7 * mm, footer_line_1)
        canvas.drawString(doc_obj.leftMargin, 4.2 * mm, footer_line_2)
        canvas.drawRightString(doc_obj.pagesize[0] - doc_obj.rightMargin, 4.2 * mm, f"Page {doc_obj.page}")
        canvas.restoreState()

    doc.build(elements, onFirstPage=_on_page, onLaterPages=_on_page)
    return buffer.getvalue()

