def _ensure_user_request_table(conn):
    cursor = conn.cursor()
    cursor.execute("""
    IF NOT EXISTS (
        SELECT 1 FROM INFORMATION_SCHEMA.TABLES
        WHERE TABLE_SCHEMA='dbo' AND TABLE_NAME='HID_User_Requests'
    )
    BEGIN
        CREATE TABLE dbo.HID_User_Requests (
            RequestId INT IDENTITY(1,1) PRIMARY KEY,
            RequestedBy NVARCHAR(100) NOT NULL,
            NewUserName NVARCHAR(100) NOT NULL,
            RequestedPassword NVARCHAR(200) NOT NULL,
            RequestedRole NVARCHAR(100) NOT NULL,
            RequestedAccountId INT NULL,
            RequestedUnit NVARCHAR(50) NULL,
            RequestedPurchaseUnits NVARCHAR(MAX) NULL,
            RequestedFirms NVARCHAR(MAX) NULL,
            RequestedSections NVARCHAR(MAX) NULL,
            Note NVARCHAR(500) NULL,
            ActionType NVARCHAR(20) NOT NULL DEFAULT('Create'),
            RequestedIsActive BIT NULL,
            RequestedSessionId NVARCHAR(200) NULL,
            Status NVARCHAR(20) NOT NULL DEFAULT('Pending'),
            RequestedAt DATETIME2 NOT NULL DEFAULT(SYSDATETIME()),
            DecidedBy NVARCHAR(100) NULL,
            DecidedAt DATETIME2 NULL,
            RemindAt DATETIME2 NULL
        );
        CREATE INDEX IX_HID_User_Requests_Status ON dbo.HID_User_Requests(Status);
    END
    """)
    # Backfill ActionType column if table already exists
    try:
        cursor.execute("ALTER TABLE dbo.HID_User_Requests ADD ActionType NVARCHAR(20) NOT NULL DEFAULT('Create')")
        conn.commit()
    except Exception:
        conn.rollback()
    try:
        cursor.execute("ALTER TABLE dbo.HID_User_Requests ADD RequestedIsActive BIT NULL")
        conn.commit()
    except Exception:
        conn.rollback()
    try:
        cursor.execute("ALTER TABLE dbo.HID_User_Requests ADD RequestedSessionId NVARCHAR(200) NULL")
        conn.commit()
    except Exception:
        conn.rollback()
    try:
        cursor.execute("ALTER TABLE dbo.HID_User_Requests ADD RequestedFirms NVARCHAR(MAX) NULL")
        conn.commit()
    except Exception:
        conn.rollback()
    try:
        cursor.execute("""
        IF COL_LENGTH('dbo.HID_User_Requests', 'RequestedUnit') IS NOT NULL
           AND COL_LENGTH('dbo.HID_User_Requests', 'RequestedUnit') <> -1
           AND COL_LENGTH('dbo.HID_User_Requests', 'RequestedUnit') < 4000
        BEGIN
            ALTER TABLE dbo.HID_User_Requests ALTER COLUMN RequestedUnit NVARCHAR(MAX) NULL
        END
        """)
        conn.commit()
    except Exception:
        conn.rollback()
    try:
        cursor.execute("ALTER TABLE dbo.HID_User_Requests ADD RequestedPurchaseUnits NVARCHAR(MAX) NULL")
        conn.commit()
    except Exception:
        conn.rollback()
    conn.commit()


