def _fetch_purchase_incharge_recipients_by_department(unit: str):
    unit_val = (unit or "").strip().upper()
    out: dict[int, list[str]] = {}
    try:
        with _get_login_db_connection() as conn:
            _ensure_purchase_incharge_table(conn)
            cursor = conn.cursor()
            cursor.execute("""
                SELECT TOP 1 1
                FROM INFORMATION_SCHEMA.COLUMNS
                WHERE TABLE_SCHEMA='dbo'
                  AND TABLE_NAME='HID_Purchase_Incharge'
                  AND COLUMN_NAME='PurchasingDeptId'
            """)
            if cursor.fetchone() is None:
                return out
            cursor.execute("""
                SELECT
                    pi.PurchasingDeptId,
                    pi.Email
                FROM dbo.HID_Purchase_Incharge AS pi
                WHERE ISNULL(pi.IsActive, 1) = 1
                  AND (
                        pi.Unit IS NULL
                        OR LTRIM(RTRIM(pi.Unit)) = ''
                        OR UPPER(pi.Unit) = 'ALL'
                        OR UPPER(pi.Unit) = ?
                  )
                ORDER BY
                    pi.PurchasingDeptId,
                    CASE
                        WHEN UPPER(LTRIM(RTRIM(ISNULL(pi.Unit, '')))) = ? THEN 0
                        WHEN pi.Unit IS NULL OR LTRIM(RTRIM(pi.Unit)) = '' OR UPPER(pi.Unit) = 'ALL' THEN 1
                        ELSE 2
                    END,
                    pi.Id
            """, (unit_val, unit_val))
            rows = cursor.fetchall()
            for row in rows:
                try:
                    dept_id = int(row[0] or 0)
                except Exception:
                    dept_id = 0
                email_val = str(row[1] or "").strip()
                if dept_id <= 0 or not email_val:
                    continue
                out.setdefault(dept_id, [])
                if email_val not in out[dept_id]:
                    out[dept_id].append(email_val)
    except Exception as e:
        print(f"Purchase incharge recipient map fetch failed: {e}")
    return out


