def _ensure_purchase_approval_recipient_table(conn):
    cursor = conn.cursor()
    _ensure_purchasing_department_table(conn)
    try:
        cursor.execute("""
        IF OBJECT_ID('dbo.HID_Purchase_Approval_Recipients', 'U') IS NULL
        BEGIN
            CREATE TABLE dbo.HID_Purchase_Approval_Recipients (
                Id INT IDENTITY(1,1) PRIMARY KEY,
                Name NVARCHAR(120) NOT NULL,
                Email NVARCHAR(200) NOT NULL,
                Unit NVARCHAR(20) NULL,
                PurchasingDeptId INT NULL,
                IsActive BIT NOT NULL DEFAULT(1),
                CreatedAt DATETIME2 NOT NULL DEFAULT(SYSDATETIME()),
                CreatedBy NVARCHAR(100) NULL
            );
        END

        IF COL_LENGTH('dbo.HID_Purchase_Approval_Recipients', 'Unit') IS NULL
        BEGIN
            ALTER TABLE dbo.HID_Purchase_Approval_Recipients ADD Unit NVARCHAR(20) NULL;
        END

        IF COL_LENGTH('dbo.HID_Purchase_Approval_Recipients', 'PurchasingDeptId') IS NULL
        BEGIN
            ALTER TABLE dbo.HID_Purchase_Approval_Recipients ADD PurchasingDeptId INT NULL;
        END

        IF NOT EXISTS (
            SELECT 1
            FROM sys.indexes
            WHERE name = 'IX_HID_Purchase_Approval_Recipients_Active'
              AND object_id = OBJECT_ID('dbo.HID_Purchase_Approval_Recipients')
        )
        BEGIN
            CREATE INDEX IX_HID_Purchase_Approval_Recipients_Active
            ON dbo.HID_Purchase_Approval_Recipients(IsActive);
        END

        IF NOT EXISTS (
            SELECT 1
            FROM sys.indexes
            WHERE name = 'IX_HID_Purchase_Approval_Recipients_Unit'
              AND object_id = OBJECT_ID('dbo.HID_Purchase_Approval_Recipients')
        )
        BEGIN
            CREATE INDEX IX_HID_Purchase_Approval_Recipients_Unit
            ON dbo.HID_Purchase_Approval_Recipients(Unit);
        END

        IF NOT EXISTS (
            SELECT 1
            FROM sys.indexes
            WHERE name = 'IX_HID_Purchase_Approval_Recipients_Dept'
              AND object_id = OBJECT_ID('dbo.HID_Purchase_Approval_Recipients')
        )
        BEGIN
            CREATE INDEX IX_HID_Purchase_Approval_Recipients_Dept
            ON dbo.HID_Purchase_Approval_Recipients(PurchasingDeptId);
        END

        BEGIN TRY
            IF COL_LENGTH('dbo.HID_Purchase_Approval_Recipients', 'PurchasingDeptId') IS NOT NULL
               AND OBJECT_ID('dbo.FK_HID_Purchase_Approval_Recipients_PurchasingDept', 'F') IS NULL
            BEGIN
                ALTER TABLE dbo.HID_Purchase_Approval_Recipients
                ADD CONSTRAINT FK_HID_Purchase_Approval_Recipients_PurchasingDept
                FOREIGN KEY (PurchasingDeptId) REFERENCES dbo.HID_Purchasing_Dept(Id);
            END
        END TRY
        BEGIN CATCH
            -- Leave boot resilient if legacy rows block FK creation.
        END CATCH
        """)
        conn.commit()
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        print(f"Purchase approval recipient table create failed: {e}")
        return


def _fetch_purchase_approval_recipients(unit: str | None = None, purchasing_dept_id: int | None = None):
    try:
        with _get_login_db_connection() as conn:
            _ensure_purchase_approval_recipient_table(conn)
            cursor = conn.cursor()
            cursor.execute("SELECT OBJECT_ID('dbo.HID_Purchase_Approval_Recipients', 'U')")
            exists_row = cursor.fetchone()
            if not exists_row or not exists_row[0]:
                return []
            dept_id = _safe_int(purchasing_dept_id)
            if unit:
                unit_val = unit.strip().upper()
                if dept_id > 0:
                    cursor.execute("""
                        SELECT
                            pr.Id,
                            pr.Name,
                            pr.Email,
                            pr.Unit,
                            pr.PurchasingDeptId,
                            pd.PurchasingDeptName,
                            pr.IsActive,
                            pr.CreatedAt
                        FROM dbo.HID_Purchase_Approval_Recipients AS pr
                        LEFT JOIN dbo.HID_Purchasing_Dept AS pd
                            ON pr.PurchasingDeptId = pd.Id
                        WHERE ISNULL(pr.IsActive, 1) = 1
                          AND (
                                pr.Unit IS NULL
                                OR LTRIM(RTRIM(pr.Unit)) = ''
                                OR UPPER(pr.Unit) = 'ALL'
                                OR UPPER(pr.Unit) = ?
                          )
                          AND (
                                pr.PurchasingDeptId IS NULL
                                OR pr.PurchasingDeptId = ?
                          )
                        ORDER BY
                            CASE WHEN pr.PurchasingDeptId = ? THEN 0 ELSE 1 END,
                            CASE
                                WHEN UPPER(LTRIM(RTRIM(ISNULL(pr.Unit, '')))) = ? THEN 0
                                WHEN pr.Unit IS NULL OR LTRIM(RTRIM(pr.Unit)) = '' OR UPPER(pr.Unit) = 'ALL' THEN 1
                                ELSE 2
                            END,
                            pr.Name
                    """, (unit_val, dept_id, dept_id, unit_val))
                else:
                    cursor.execute("""
                        SELECT
                            pr.Id,
                            pr.Name,
                            pr.Email,
                            pr.Unit,
                            pr.PurchasingDeptId,
                            pd.PurchasingDeptName,
                            pr.IsActive,
                            pr.CreatedAt
                        FROM dbo.HID_Purchase_Approval_Recipients AS pr
                        LEFT JOIN dbo.HID_Purchasing_Dept AS pd
                            ON pr.PurchasingDeptId = pd.Id
                        WHERE ISNULL(pr.IsActive, 1) = 1
                          AND (
                                pr.Unit IS NULL
                                OR LTRIM(RTRIM(pr.Unit)) = ''
                                OR UPPER(pr.Unit) = 'ALL'
                                OR UPPER(pr.Unit) = ?
                          )
                          AND pr.PurchasingDeptId IS NULL
                        ORDER BY
                            CASE
                                WHEN UPPER(LTRIM(RTRIM(ISNULL(pr.Unit, '')))) = ? THEN 0
                                WHEN pr.Unit IS NULL OR LTRIM(RTRIM(pr.Unit)) = '' OR UPPER(pr.Unit) = 'ALL' THEN 1
                                ELSE 2
                            END,
                            pr.Name
                    """, (unit_val, unit_val))
            else:
                cursor.execute("""
                    SELECT
                        pr.Id,
                        pr.Name,
                        pr.Email,
                        pr.Unit,
                        pr.PurchasingDeptId,
                        pd.PurchasingDeptName,
                        pr.IsActive,
                        pr.CreatedAt
                    FROM dbo.HID_Purchase_Approval_Recipients AS pr
                    LEFT JOIN dbo.HID_Purchasing_Dept AS pd
                        ON pr.PurchasingDeptId = pd.Id
                    ORDER BY
                        CASE WHEN pr.PurchasingDeptId IS NULL THEN 0 ELSE 1 END,
                        pd.PurchasingDeptName,
                        CASE
                            WHEN pr.Unit IS NULL OR LTRIM(RTRIM(pr.Unit)) = '' OR UPPER(pr.Unit) = 'ALL' THEN 0
                            ELSE 1
                        END,
                        pr.Unit,
                        pr.Name
                """)
            rows = cursor.fetchall()
            cols = [c[0] for c in cursor.description]
            return [{cols[i]: row[i] for i in range(len(cols))} for row in rows]
    except Exception as e:
        print(f"Purchase approval recipient fetch failed: {e}")
        return []


def _add_purchase_approval_recipient(
    name: str,
    email: str,
    unit: str | None = None,
    created_by: str | None = None,
    purchasing_dept_id: int | None = None,
):
    unit_val = (unit or "").strip().upper() or None
    email_val = (email or "").strip().lower()
    dept_id_val = _safe_int(purchasing_dept_id)
    if dept_id_val <= 0:
        dept_id_val = None
    with _get_login_db_connection() as conn:
        _ensure_purchase_approval_recipient_table(conn)
        cursor = conn.cursor()
        cursor.execute("SELECT OBJECT_ID('dbo.HID_Purchase_Approval_Recipients', 'U')")
        exists_row = cursor.fetchone()
        if not exists_row or not exists_row[0]:
            return {"error": "Approval recipient table not created (permission issue)."}
        try:
            cursor.execute("""
                SELECT TOP 1 Id
                FROM dbo.HID_Purchase_Approval_Recipients
                WHERE Email = ? AND (
                    (Unit IS NULL AND ? IS NULL) OR Unit = ?
                ) AND (
                    (PurchasingDeptId IS NULL AND ? IS NULL) OR PurchasingDeptId = ?
                )
            """, (email_val, unit_val, unit_val, dept_id_val, dept_id_val))
        except pyodbc.ProgrammingError as e:
            if "42S02" in str(e):
                _ensure_purchase_approval_recipient_table(conn)
                cursor.execute("""
                    SELECT TOP 1 Id
                    FROM dbo.HID_Purchase_Approval_Recipients
                    WHERE Email = ? AND (
                        (Unit IS NULL AND ? IS NULL) OR Unit = ?
                    ) AND (
                        (PurchasingDeptId IS NULL AND ? IS NULL) OR PurchasingDeptId = ?
                    )
                """, (email_val, unit_val, unit_val, dept_id_val, dept_id_val))
            else:
                raise
        row = cursor.fetchone()
        if row:
            cursor.execute("""
                UPDATE dbo.HID_Purchase_Approval_Recipients
                SET Name = ?, Email = ?, Unit = ?, PurchasingDeptId = ?, IsActive = 1
                WHERE Id = ?
            """, (name, email_val, unit_val, dept_id_val, row.Id))
        else:
            cursor.execute("""
                INSERT INTO dbo.HID_Purchase_Approval_Recipients (
                    Name, Email, Unit, PurchasingDeptId, IsActive, CreatedBy
                )
                VALUES (?, ?, ?, ?, 1, ?)
            """, (name, email_val, unit_val, dept_id_val, created_by))
        conn.commit()
    return {"status": "success"}


