def _fetch_fund_position_recipients(firms: list[str] | None = None, only_active: bool = False):
    firms_norm = sorted({str(f or "").strip().upper() for f in (firms or []) if str(f or "").strip()})
    try:
        with _get_login_db_connection() as conn:
            _ensure_fund_position_recipient_table(conn)
            cursor = conn.cursor()

            params = []
            sql = """
                SELECT Id, Name, Email, FirmName, IsActive, CreatedAt
                FROM dbo.HID_Fund_Position_Recipients
                WHERE 1 = 1
            """
            if only_active:
                sql += " AND ISNULL(IsActive, 1) = 1"

            if firms_norm:
                placeholders = ",".join("?" * len(firms_norm))
                sql += f"""
                    AND (
                        FirmName IS NULL
                        OR LTRIM(RTRIM(FirmName)) = ''
                        OR UPPER(LTRIM(RTRIM(FirmName))) = 'ALL'
                        OR UPPER(LTRIM(RTRIM(FirmName))) IN ({placeholders})
                    )
                """
                params.extend(firms_norm)

            sql += " ORDER BY FirmName, Name"
            cursor.execute(sql, params)
            rows = cursor.fetchall()
            cols = [c[0] for c in cursor.description]
            return [{cols[i]: row[i] for i in range(len(cols))} for row in rows]
    except Exception as e:
        print(f"Fund position recipient fetch failed: {e}")
        return []


def _add_fund_position_recipient(name: str, email: str, firm_name: str | None = None, created_by: str | None = None):
    email_val = str(email or "").strip()
    firm_val = _normalize_firm_name(firm_name) if firm_name else None
    if firm_val and firm_val.upper() == "ALL":
        firm_val = None

    with _get_login_db_connection() as conn:
        _ensure_fund_position_recipient_table(conn)
        cursor = conn.cursor()
        cursor.execute("""
            SELECT TOP 1 Id
            FROM dbo.HID_Fund_Position_Recipients
            WHERE UPPER(LTRIM(RTRIM(Email))) = UPPER(LTRIM(RTRIM(?)))
              AND (
                   (FirmName IS NULL AND ? IS NULL)
                   OR UPPER(LTRIM(RTRIM(FirmName))) = UPPER(LTRIM(RTRIM(?)))
              )
        """, (email_val, firm_val, firm_val))
        row = cursor.fetchone()
        if row:
            cursor.execute("""
                UPDATE dbo.HID_Fund_Position_Recipients
                SET Name = ?, FirmName = ?, IsActive = 1
                WHERE Id = ?
            """, (name, firm_val, row.Id))
        else:
            cursor.execute("""
                INSERT INTO dbo.HID_Fund_Position_Recipients (Name, Email, FirmName, IsActive, CreatedBy)
                VALUES (?, ?, ?, 1, ?)
            """, (name, email_val, firm_val, created_by))
        conn.commit()
    return {"status": "success"}


