def _po_val_sync_cache_prune(now_ts: float | None = None):
    now_ts = now_ts if now_ts is not None else time.time()
    cutoff = now_ts - PO_VAL_SYNC_TTL_SECS
    with PO_VAL_SYNC_LOCK:
        for key in list(PO_VAL_SYNC_CACHE.keys()):
            if PO_VAL_SYNC_CACHE.get(key, {}).get("ts", 0) < cutoff:
                PO_VAL_SYNC_CACHE.pop(key, None)


def _po_val_sync_key(units: list[str]) -> str:
    return ",".join(sorted({str(u or "").strip().upper() for u in (units or []) if str(u or "").strip()}))


def _po_val_should_sync(units: list[str], from_norm: str, force: bool = False) -> bool:
    now_ts = time.time()
    _po_val_sync_cache_prune(now_ts)
    key = _po_val_sync_key(units)
    with PO_VAL_SYNC_LOCK:
        entry = PO_VAL_SYNC_CACHE.get(key)
    if force or not entry:
        return True
    last_ts = float(entry.get("ts", 0))
    last_from = str(entry.get("from") or "").strip()
    if last_from and from_norm < last_from:
        return True
    return (now_ts - last_ts) >= PO_VAL_SYNC_TTL_SECS


def _po_val_sync_cache_put(units: list[str], from_norm: str):
    now_ts = time.time()
    _po_val_sync_cache_prune(now_ts)
    key = _po_val_sync_key(units)
    with PO_VAL_SYNC_LOCK:
        entry = PO_VAL_SYNC_CACHE.get(key)
        last_from = str(entry.get("from") or "").strip() if entry else ""
        min_from = from_norm if (not last_from or from_norm < last_from) else last_from
        PO_VAL_SYNC_CACHE[key] = {"ts": now_ts, "from": min_from}


def _ensure_purchase_po_valuation_table(conn):
    cursor = conn.cursor()
    cursor.execute("""
    IF NOT EXISTS (
        SELECT 1 FROM INFORMATION_SCHEMA.TABLES
        WHERE TABLE_SCHEMA='dbo' AND TABLE_NAME='HID_Purchase_PO_Valuation'
    )
    BEGIN
        CREATE TABLE dbo.HID_Purchase_PO_Valuation (
            Id INT IDENTITY(1,1) PRIMARY KEY,
            Unit NVARCHAR(20) NOT NULL,
            POID INT NOT NULL,
            DetailID INT NOT NULL,
            PONo NVARCHAR(50) NULL,
            PODate DATE NULL,
            Status NVARCHAR(10) NULL,
            SupplierId INT NULL,
            SupplierName NVARCHAR(200) NULL,
            PurchasingDeptId INT NULL,
            PurchasingDeptName NVARCHAR(150) NULL,
            StoreId INT NULL,
            StoreName NVARCHAR(200) NULL,
            ItemId INT NULL,
            ItemName NVARCHAR(200) NULL,
            Qty DECIMAL(18,3) NOT NULL DEFAULT(0),
            Rate DECIMAL(18,4) NOT NULL DEFAULT(0),
            LineValue DECIMAL(18,2) NOT NULL DEFAULT(0),
            DeptName NVARCHAR(120) NULL,
            CategoryName NVARCHAR(120) NULL,
            SubCategoryName NVARCHAR(120) NULL,
            CreatedAt DATETIME2 NOT NULL DEFAULT(SYSDATETIME()),
            UpdatedAt DATETIME2 NOT NULL DEFAULT(SYSDATETIME())
        );
        CREATE UNIQUE INDEX UX_HID_Purchase_PO_Valuation_UnitDetail
            ON dbo.HID_Purchase_PO_Valuation(Unit, DetailID);
        CREATE INDEX IX_HID_Purchase_PO_Valuation_Date
            ON dbo.HID_Purchase_PO_Valuation(PODate);
        CREATE INDEX IX_HID_Purchase_PO_Valuation_Store
            ON dbo.HID_Purchase_PO_Valuation(Unit, StoreName);
        CREATE INDEX IX_HID_Purchase_PO_Valuation_Supplier
            ON dbo.HID_Purchase_PO_Valuation(Unit, SupplierName);
        CREATE INDEX IX_HID_Purchase_PO_Valuation_PurchasingDept
            ON dbo.HID_Purchase_PO_Valuation(Unit, PurchasingDeptId);
    END
    """)
    conn.commit()
    # Backfill columns/indexes if table already exists
    for stmt in [
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD PODate DATE NULL",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD Status NVARCHAR(10) NULL",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD SupplierId INT NULL",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD SupplierName NVARCHAR(200) NULL",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD PurchasingDeptId INT NULL",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD PurchasingDeptName NVARCHAR(150) NULL",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD StoreId INT NULL",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD StoreName NVARCHAR(200) NULL",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD ItemId INT NULL",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD ItemName NVARCHAR(200) NULL",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD Qty DECIMAL(18,3) NOT NULL DEFAULT(0)",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD Rate DECIMAL(18,4) NOT NULL DEFAULT(0)",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD LineValue DECIMAL(18,2) NOT NULL DEFAULT(0)",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD DeptName NVARCHAR(120) NULL",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD CategoryName NVARCHAR(120) NULL",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD SubCategoryName NVARCHAR(120) NULL",
        "ALTER TABLE dbo.HID_Purchase_PO_Valuation ADD UpdatedAt DATETIME2 NOT NULL DEFAULT(SYSDATETIME())",
    ]:
        try:
            cursor.execute(stmt)
            conn.commit()
        except Exception:
            conn.rollback()
    for stmt in [
        "CREATE UNIQUE INDEX UX_HID_Purchase_PO_Valuation_UnitDetail ON dbo.HID_Purchase_PO_Valuation(Unit, DetailID)",
        "CREATE INDEX IX_HID_Purchase_PO_Valuation_Date ON dbo.HID_Purchase_PO_Valuation(PODate)",
        "CREATE INDEX IX_HID_Purchase_PO_Valuation_Store ON dbo.HID_Purchase_PO_Valuation(Unit, StoreName)",
        "CREATE INDEX IX_HID_Purchase_PO_Valuation_Supplier ON dbo.HID_Purchase_PO_Valuation(Unit, SupplierName)",
        "CREATE INDEX IX_HID_Purchase_PO_Valuation_PurchasingDept ON dbo.HID_Purchase_PO_Valuation(Unit, PurchasingDeptId)",
    ]:
        try:
            cursor.execute(stmt)
            conn.commit()
        except Exception:
            conn.rollback()


def _sync_purchase_po_valuation_rows(units: list[str], from_date: str):
    def _coerce_po_date(val):
        if val is None:
            return None
        try:
            if isinstance(val, datetime):
                return val.date()
        except Exception:
            pass
        try:
            if isinstance(val, date):
                return val
        except Exception:
            pass
        try:
            if isinstance(val, pd.Timestamp):
                if pd.isna(val):
                    return None
                return val.date()
        except Exception:
            pass
        raw = str(val).strip()
        if not raw:
            return None
        raw = raw.split("T")[0].split(" ")[0]
        for fmt in ("%Y-%m-%d", "%d-%m-%Y", "%d/%m/%Y", "%Y/%m/%d", "%m/%d/%Y", "%m-%d-%Y"):
            try:
                return datetime.strptime(raw, fmt).date()
            except Exception:
                continue
        try:
            parsed = pd.to_datetime(raw, errors="coerce", dayfirst=True)
            if pd.isna(parsed):
                return None
            return parsed.date()
        except Exception:
            return None

    dept_name_by_id = {}
    for dept in _fetch_purchasing_departments(include_inactive=True):
        dept_id = _safe_int(dept.get("Id"), 0)
        dept_name = str(dept.get("PurchasingDeptName") or "").strip()
        if dept_id > 0 and dept_name:
            dept_name_by_id[dept_id] = dept_name

    rows = []
    for unit in units:
        try:
            data_fetch.ensure_po_purchasing_dept_column(unit)
        except Exception:
            pass
        df = data_fetch.fetch_purchase_po_valuation_rows(unit, from_date)
        if df is None or df.empty:
            continue
        df = _clean_df_columns(df)
        for _, row in df.iterrows():
            detail_id = _safe_int(row.get("DetailID"), 0)
            po_id = _safe_int(row.get("POID"), 0)
            if not detail_id or not po_id:
                continue
            po_date = _coerce_po_date(row.get("PODate"))
            purchasing_dept_id = _safe_int(row.get("PurchasingDeptId"), None)
            purchasing_dept_name = (
                dept_name_by_id.get(int(purchasing_dept_id or 0))
                if purchasing_dept_id not in (None, 0)
                else None
            )
            rows.append((
                (row.get("Unit") or unit or "").strip().upper(),
                detail_id,
                po_id,
                str(row.get("PONo") or "") or None,
                po_date,
                str(row.get("Status") or "") or None,
                _safe_int(row.get("SupplierID"), None),
                str(row.get("SupplierName") or "") or None,
                purchasing_dept_id,
                purchasing_dept_name,
                _safe_int(row.get("StoreId"), None),
                str(row.get("StoreName") or "") or None,
                _safe_int(row.get("ItemID"), None),
                str(row.get("ItemName") or "") or None,
                _safe_float(row.get("Qty")),
                _safe_float(row.get("Rate")),
                _safe_float(row.get("LineValue")),
                str(row.get("DeptName") or "") or None,
                str(row.get("CategoryName") or "") or None,
                str(row.get("SubCategoryName") or "") or None,
            ))
    if not rows:
        return 0
    with _get_login_db_connection() as conn:
        _ensure_purchase_po_valuation_table(conn)
        cursor = conn.cursor()
        try:
            cursor.fast_executemany = True
        except Exception:
            pass
        merge_sql = """
            MERGE dbo.HID_Purchase_PO_Valuation AS tgt
            USING (
                SELECT
                    ? AS Unit,
                    ? AS DetailID,
                    ? AS POID,
                    ? AS PONo,
                    ? AS PODate,
                    ? AS Status,
                    ? AS SupplierId,
                    ? AS SupplierName,
                    ? AS PurchasingDeptId,
                    ? AS PurchasingDeptName,
                    ? AS StoreId,
                    ? AS StoreName,
                    ? AS ItemId,
                    ? AS ItemName,
                    ? AS Qty,
                    ? AS Rate,
                    ? AS LineValue,
                    ? AS DeptName,
                    ? AS CategoryName,
                    ? AS SubCategoryName
            ) AS src
            ON tgt.Unit = src.Unit AND tgt.DetailID = src.DetailID
            WHEN MATCHED THEN UPDATE SET
                POID = src.POID,
                PONo = src.PONo,
                PODate = src.PODate,
                Status = src.Status,
                SupplierId = src.SupplierId,
                SupplierName = src.SupplierName,
                PurchasingDeptId = src.PurchasingDeptId,
                PurchasingDeptName = src.PurchasingDeptName,
                StoreId = src.StoreId,
                StoreName = src.StoreName,
                ItemId = src.ItemId,
                ItemName = src.ItemName,
                Qty = src.Qty,
                Rate = src.Rate,
                LineValue = src.LineValue,
                DeptName = src.DeptName,
                CategoryName = src.CategoryName,
                SubCategoryName = src.SubCategoryName,
                UpdatedAt = SYSDATETIME()
            WHEN NOT MATCHED THEN INSERT (
                Unit, DetailID, POID, PONo, PODate, Status, SupplierId, SupplierName, PurchasingDeptId, PurchasingDeptName, StoreId, StoreName,
                ItemId, ItemName, Qty, Rate, LineValue, DeptName, CategoryName, SubCategoryName
            ) VALUES (
                src.Unit, src.DetailID, src.POID, src.PONo, src.PODate, src.Status, src.SupplierId, src.SupplierName, src.PurchasingDeptId, src.PurchasingDeptName, src.StoreId, src.StoreName,
                src.ItemId, src.ItemName, src.Qty, src.Rate, src.LineValue, src.DeptName, src.CategoryName, src.SubCategoryName
            );
        """
        cursor.executemany(merge_sql, rows)
        conn.commit()
    return len(rows)


def _insert_user_request(payload: dict):
    with _get_login_db_connection() as conn:
        _ensure_user_request_table(conn)
        cursor = conn.cursor()
        cursor.execute("""
            INSERT INTO dbo.HID_User_Requests
              (RequestedBy, NewUserName, RequestedPassword, RequestedRole, RequestedAccountId,
               RequestedUnit, RequestedPurchaseUnits, RequestedFirms, RequestedSections, Note, ActionType, RequestedIsActive, RequestedSessionId, Status, RequestedAt)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'Pending', SYSDATETIME())
        """, (
            payload.get("requested_by"),
            payload.get("new_username"),
            payload.get("passwordw"),
            payload.get("role"),
            payload.get("accountid"),
            payload.get("unit_scope"),
            payload.get("purchase_unit_scope"),
            payload.get("firm_scope"),
            payload.get("sections"),
            payload.get("note"),
            payload.get("action_type") or "Create",
            payload.get("requested_is_active"),
            payload.get("requested_session_id"),
        ))
        conn.commit()


def _fetch_user_requests(viewer_role: str, viewer_username: str):
    with _get_login_db_connection() as conn:
        _ensure_user_request_table(conn)
        cursor = conn.cursor()
        base_sql = """
            SELECT RequestId, RequestedBy, NewUserName, RequestedRole, RequestedUnit, RequestedPurchaseUnits, RequestedFirms,
                   RequestedSections, Status, RequestedAt, DecidedBy, DecidedAt, Note, RemindAt, ActionType, RequestedSessionId
            FROM dbo.HID_User_Requests
        """
        # All privileged roles can view all requests
        sql = base_sql + " ORDER BY RequestedAt DESC"
        params = []
        cursor.execute(sql, params)
        rows = cursor.fetchall()
        cols = [c[0] for c in cursor.description]
        res = []
        for r in rows:
            res.append({cols[i]: r[i] for i in range(len(cols))})
        return res


