def _upsert_hid_user(row: dict):
    """Create or update HID_User_Mst based on approved request."""
    with _get_login_db_connection() as conn:
        _ensure_hid_user_scope_columns(conn)
        cursor = conn.cursor()
        cursor.execute("SELECT 1 FROM dbo.HID_User_Mst WHERE UserName = ?", (row["NewUserName"],))
        exists = cursor.fetchone() is not None
        is_active = row.get("RequestedIsActive")
        is_active = 1 if is_active in (1, True, "1", "true", "yes", "on") else (0 if is_active is not None else 1)
        requested_purchase_units = _normalize_unit_scope_text(row.get("RequestedPurchaseUnits") or "")
        requested_firms = _normalize_firm_scope_text(row.get("RequestedFirms") or "")
        if exists:
            try:
                cursor.execute("""
                    UPDATE dbo.HID_User_Mst
                    SET PasswordW = ?, AccountId = ?, RoleName = ?, UnitScope = ?, PurchaseUnitScope = ?, FirmScope = ?, SectionRights = ?, IsActive = ?, UpdatedAt = SYSDATETIME()
                    WHERE UserName = ?
                """, (
                    row.get("RequestedPassword") or "",
                    row.get("RequestedAccountId"),
                    row.get("RequestedRole"),
                    row.get("RequestedUnit"),
                    requested_purchase_units,
                    requested_firms,
                    row.get("RequestedSections"),
                    is_active,
                    row.get("NewUserName"),
                ))
            except Exception:
                cursor.execute("""
                    UPDATE dbo.HID_User_Mst
                    SET PasswordW = ?, AccountId = ?, RoleName = ?, UnitScope = ?, SectionRights = ?, IsActive = ?, UpdatedAt = SYSDATETIME()
                    WHERE UserName = ?
                """, (
                    row.get("RequestedPassword") or "",
                    row.get("RequestedAccountId"),
                    row.get("RequestedRole"),
                    row.get("RequestedUnit"),
                    row.get("RequestedSections"),
                    is_active,
                    row.get("NewUserName"),
                ))
        else:
            try:
                cursor.execute("""
                    INSERT INTO dbo.HID_User_Mst
                        (UserName, PasswordW, AccountId, RoleName, UnitScope, PurchaseUnitScope, FirmScope, SectionRights, IsActive, CreatedAt, UpdatedAt)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, SYSDATETIME(), NULL)
                """, (
                    row.get("NewUserName"),
                    row.get("RequestedPassword") or "",
                    row.get("RequestedAccountId"),
                    row.get("RequestedRole"),
                    row.get("RequestedUnit"),
                    requested_purchase_units,
                    requested_firms,
                    row.get("RequestedSections"),
                    is_active,
                ))
            except Exception:
                cursor.execute("""
                    INSERT INTO dbo.HID_User_Mst
                        (UserName, PasswordW, AccountId, RoleName, UnitScope, SectionRights, IsActive, CreatedAt, UpdatedAt)
                    VALUES (?, ?, ?, ?, ?, ?, ?, SYSDATETIME(), NULL)
                """, (
                    row.get("NewUserName"),
                    row.get("RequestedPassword") or "",
                    row.get("RequestedAccountId"),
                    row.get("RequestedRole"),
                    row.get("RequestedUnit"),
                    row.get("RequestedSections"),
                    is_active,
                ))
        conn.commit()


