def _pending_notifications_for_it():
    """Return requests needing IT attention (pending or hold and remind_at due)."""
    with _get_login_db_connection() as conn:
        _ensure_user_request_table(conn)
        cursor = conn.cursor()
        cursor.execute("""
            SELECT RequestId, RequestedBy, NewUserName, RequestedRole, RequestedUnit, Status, RequestedAt, RemindAt
            FROM dbo.HID_User_Requests
            WHERE Status = 'Pending'
               OR (Status = 'Hold' AND RemindAt IS NOT NULL AND RemindAt <= SYSDATETIME())
            ORDER BY RequestedAt DESC
        """)
        rows = cursor.fetchall()
        cols = [c[0] for c in cursor.description]
        return [{cols[i]: r[i] for i in range(len(cols))} for r in rows]


def _notification_file_path():
    if NOTIFICATIONS_FILE:
        return NOTIFICATIONS_FILE
    return os.path.join(os.path.dirname(__file__), "modules", "notifications.json")


def _notification_read_file_path():
    if USER_NOTIFICATIONS_FILE:
        return USER_NOTIFICATIONS_FILE
    return os.path.join(os.path.dirname(__file__), "modules", "user_notifications.json")


def _notification_next_id(data):
    max_id = 0
    for n in data:
        try:
            max_id = max(max_id, int(n.get("id", 0)))
        except Exception:
            continue
    read_path = _notification_read_file_path()
    try:
        if os.path.exists(read_path):
            with open(read_path, "r", encoding="utf-8") as f:
                read_data = json.load(f)
            for user_vals in (read_data or {}).values():
                for notif_id in (user_vals or {}).keys():
                    try:
                        max_id = max(max_id, int(notif_id))
                    except Exception:
                        continue
    except Exception:
        pass
    return max_id + 1


def _clear_user_notification_read(username: str, notif_id: int | str):
    if not username or not notif_id:
        return
    path = _notification_read_file_path()
    try:
        if not os.path.exists(path):
            return
        with open(path, "r", encoding="utf-8") as f:
            read_data = json.load(f)
        user_key = str(username)
        user_map = read_data.get(user_key)
        if not isinstance(user_map, dict):
            return
        notif_key = str(notif_id)
        if notif_key in user_map:
            del user_map[notif_key]
            read_data[user_key] = user_map
            with open(path, "w", encoding="utf-8") as f:
                json.dump(read_data, f, indent=2)
    except Exception:
        return


def _push_user_notification(username: str, title: str, message: str, link: str = "", ref: str | int | None = None):
    """Append a user-scoped notification to the shared notifications file."""
    if not username or not title or not message:
        return
    path = _notification_file_path()
    try:
        data = []
        if os.path.exists(path):
            try:
                with open(path, "r", encoding="utf-8") as f:
                    data = json.load(f)
            except Exception:
                # corrupted/invalid JSON: start fresh
                data = []
        else:
            data = []
        # If ref provided, skip if already sent for same ref/user (but refresh link/message).
        if ref is not None:
            for n in data:
                try:
                    if str(n.get("user", "")).lower() == str(username).lower() and str(n.get("ref", "")) == str(ref):
                        if link:
                            n["link"] = link
                        if title:
                            n["title"] = title
                        if message:
                            n["message"] = message
                        with open(path, "w", encoding="utf-8") as f:
                            json.dump(data, f, indent=2)
                        _clear_user_notification_read(username, n.get("id"))
                        return
                except Exception:
                    continue
        # Deduplicate only when no ref is provided: skip if same user/title/message exists in last 24h
        if ref is None:
            cutoff = datetime.now(tz=LOCAL_TZ) - timedelta(hours=24)
            for n in data:
                try:
                    if str(n.get("user", "")).lower() != str(username).lower():
                        continue
                    if (n.get("title") or "") != title or (n.get("message") or "") != message:
                        continue
                    ts = datetime.fromisoformat(n.get("created_at"))
                    if ts >= cutoff:
                        return
                except Exception:
                    continue
        new_id = _notification_next_id(data)
        entry = {
            "id": new_id,
            "title": title,
            "message": message,
            "type": "alert",
            "link": link or "",
            "created_at": datetime.now(tz=LOCAL_TZ).isoformat(),
            "user": username,
            "ref": str(ref) if ref is not None else "",
        }
        data.append(entry)
        with open(path, "w", encoding="utf-8") as f:
            json.dump(data, f, indent=2)
        _clear_user_notification_read(username, new_id)
    except Exception as e:
        print(f"Notification write failed: {e}")


def _get_it_usernames():
    """Return active IT usernames from login DB."""
    try:
        with _get_login_db_connection() as conn:
            cursor = conn.cursor()
            cursor.execute("""
                SELECT UserName
                FROM dbo.HID_User_Mst
                WHERE RoleName = 'IT' AND ISNULL(IsActive, 1) = 1
            """)
            return [row[0] for row in cursor.fetchall() if row and row[0]]
    except Exception:
        return []


def _notify_it_service_approval(service_id: int, service_code: str, service_name: str, unit: str, requested_by: str):
    title = "Service approval required"
    name = service_name or service_code or f"Service {service_id}"
    by_user = requested_by or "A user"
    message = f"{by_user} created {name} in unit {unit}. Awaiting IT approval."
    link = f"/service-addition?unit={unit}&service_id={service_id}"
    ref = f"service_approval:{unit}:{service_id}"
    for username in _get_it_usernames():
        _push_user_notification(username, title, message, link=link, ref=ref)


def _update_user_password(username: str, new_password: str):
    with _get_login_db_connection() as conn:
        cursor = conn.cursor()
        try:
            cursor.execute("""
                UPDATE dbo.HID_User_Mst
                SET PasswordW = ?, UpdatedAt = SYSDATETIME()
                WHERE UserName = ?
            """, (new_password, username))
            if cursor.rowcount == 0:
                cursor.execute("""
                    UPDATE dbo.user_mst
                    SET passwordw = ?
                    WHERE username = ?
                """, (new_password, username))
            conn.commit()
            return cursor.rowcount > 0
        except Exception:
            conn.rollback()
            raise
# ============================================================
def _build_summary_for_range(from_date: str, to_date: str):
    all_data = []
    fetch_results = {}

    units = _analytics_units_upper()
    with ThreadPoolExecutor(max_workers=_revenue_pool_workers(len(units))) as executor:
        futures = {
            executor.submit(_fetch_revenue_limited, unit, from_date, to_date): unit
            for unit in units
        }
        for future in as_completed(futures):
            unit = futures[future]
            try:
                df = future.result()
                if df is not None and not df.empty:
                    df["Unit"] = unit.upper()
                    all_data.append(df)
                    fetch_results[unit] = len(df)
                else:
                    fetch_results[unit] = 0
            except Exception:
                fetch_results[unit] = 0

    if not all_data:
        return None

    for i, _df in enumerate(all_data):
        all_data[i] = _df.dropna(axis=1, how='all')

    combined_df = pd.concat(all_data, ignore_index=True, copy=False)

    try:
        summary = (
            combined_df.groupby("Unit")["NetAmount"]
            .sum()
            .reset_index()
            .to_dict(orient="records")
        )
    except Exception:
        summary = [{"Unit": u, "Records": fetch_results.get(u, 0)} for u in units]

    return {
        "summary": summary,
        "units": units,
        "records": sum(fetch_results.values())
    }

def _cache_put(from_date: str, to_date: str, payload: dict):
    full = {**payload, "ts": int(time.time())}
    key = f"prefetch:{from_date}:{to_date}"
    if not _redis_set_json(key, full, CACHE_TTL_SECONDS):
        with CACHE_LOCK:
            PREFETCH_CACHE[(from_date, to_date)] = full

def _cache_get(from_date: str, to_date: str):
    key = f"prefetch:{from_date}:{to_date}"
    entry = _redis_get_json(key)
    if entry:
        if int(time.time()) - entry.get("ts", 0) <= CACHE_TTL_SECONDS:
            return entry
    with CACHE_LOCK:
        entry = PREFETCH_CACHE.get((from_date, to_date))
        if not entry:
            return None
        if int(time.time()) - entry["ts"] > CACHE_TTL_SECONDS:
            PREFETCH_CACHE.pop((from_date, to_date), None)
            return None
        return entry

def start_prefetch(from_date: str, to_date: str):
    if _cache_get(from_date, to_date):
        return

    def _job():
        payload = _build_summary_for_range(from_date, to_date)
        if payload:
            _cache_put(from_date, to_date, payload)

    try:
        WARM_EXECUTOR.submit(_job)
    except Exception:
        pass

