# --- ADD-ONLY: Safe ODBC helpers & config picker -------------
# ============================================================
def _brace_driver(name: str) -> str:
    n = (name or "ODBC Driver 17 for SQL Server").strip()
    while n.startswith("{") and n.endswith("}") and len(n) > 2:
        n = n[1:-1].strip()
    return "{" + n + "}"

def _build_conn_str_from_dbconfig(cfg: dict) -> str:
    driver_name = _brace_driver(cfg.get("DRIVER") or "ODBC Driver 17 for SQL Server")
    server      = cfg.get("SERVER")
    database    = cfg.get("DATABASE") or cfg.get("DB")
    uid         = cfg.get("UID") or cfg.get("USER")
    pwd         = cfg.get("PWD")
    trusted     = cfg.get("Trusted_Connection") or cfg.get("TrustedConnection") or None

    if not all([server, database]):
        raise RuntimeError("DB_CONFIGS missing SERVER/DATABASE")

    if uid and pwd:
        return (
            f"DRIVER={driver_name};"
            f"SERVER={server};"
            f"DATABASE={database};"
            f"UID={uid};PWD={pwd};"
            "TrustServerCertificate=yes;"
        )

    if trusted and str(trusted).lower() in ("yes", "true", "1"):
        return (
            f"DRIVER={driver_name};"
            f"SERVER={server};"
            f"DATABASE={database};"
            "Trusted_Connection=yes;"
            "TrustServerCertificate=yes;"
        )

    raise RuntimeError("DB_CONFIGS must provide either UID/PWD or Trusted_Connection=yes")

def _pick_db_cfg_for_proc():
    db_cfgs = getattr(config, "DB_CONFIGS", {}) or {}
    for cfg in db_cfgs.values():
        if not isinstance(cfg, dict):
            continue
        srv = cfg.get("SERVER")
        db  = cfg.get("DATABASE") or cfg.get("DB")
        uid = cfg.get("UID") or cfg.get("USER")
        pwd = cfg.get("PWD")
        trusted = cfg.get("Trusted_Connection") or cfg.get("TrustedConnection")
        if srv and db and ( (uid and pwd) or (str(trusted).lower() in ("yes","true","1")) ):
            return cfg

    login_cfg = getattr(config, "LOGIN_DB", None)
    if isinstance(login_cfg, dict):
        srv = login_cfg.get("SERVER")
        db  = login_cfg.get("DATABASE") or login_cfg.get("DB")
        uid = login_cfg.get("UID") or login_cfg.get("USER")
        pwd = login_cfg.get("PWD")
        trusted = login_cfg.get("Trusted_Connection") or login_cfg.get("TrustedConnection")
        if srv and db and ( (uid and pwd) or (str(trusted).lower() in ("yes","true","1")) ):
            return login_cfg

    return None

# ============================================================
# Local store for occupancy snapshots + revenue cache
# ============================================================
def _abs_local_db_path():
    p = getattr(config, "LOCAL_DB", "data/local/app_cache.db")
    p = os.path.abspath(p)
    os.makedirs(os.path.dirname(p), exist_ok=True)
    return p

def _connect_local_db():
    conn = sqlite3.connect(_abs_local_db_path(), timeout=30)
    try:
        conn.execute("PRAGMA journal_mode=WAL")
        conn.execute("PRAGMA busy_timeout=5000")
    except Exception:
        pass
    return conn

def _with_local_db(action, retries: int = 5, base_delay: float = 0.3):
    last_err = None
    for attempt in range(retries):
        try:
            with _connect_local_db() as conn:
                action(conn)
                conn.commit()
            return
        except sqlite3.OperationalError as e:
            if "locked" in str(e).lower():
                last_err = e
                time.sleep(base_delay * (attempt + 1))
                continue
            raise
    if last_err:
        raise last_err

def _ensure_local_store():
    # FIX: use absolute path dirname (avoid missing config.LOCAL_DB)
    os.makedirs(os.path.dirname(_abs_local_db_path()), exist_ok=True)
    def _setup(conn):
        conn.execute("""
        CREATE TABLE IF NOT EXISTS occupancy_snapshot (
            snapshot_date TEXT NOT NULL,
            unit TEXT NOT NULL,
            occupied INTEGER NOT NULL,
            clinically_discharged INTEGER NOT NULL,
            vacant INTEGER NOT NULL,
            total_beds INTEGER NOT NULL,
            occupancy_rate REAL NOT NULL,
            raw_json TEXT,
            PRIMARY KEY (snapshot_date, unit)
        )
        """)
    _with_local_db(_setup)

