def _night_snapshot_metrics(payload: dict | None) -> dict:
    particulars = payload.get("particulars") if payload else []
    doctor_volume = payload.get("doctor_volume") if payload else []
    ward_rows = payload.get("ward_occupancy") if payload else []

    def _has_value(val) -> bool:
        if val is None:
            return False
        return str(val).strip() != ""

    particular_value_rows = 0
    for row in particulars or []:
        if _has_value(row.get("admission")) or _has_value(row.get("discharge")):
            particular_value_rows += 1

    doctor_volume_value_rows = 0
    for row in doctor_volume or []:
        doctor = str(row.get("doctor") or "").strip().upper()
        if doctor == "TOTAL":
            continue
        if _has_value(row.get("count")):
            doctor_volume_value_rows += 1

    ward_count = 0
    for row in ward_rows or []:
        ward = str(row.get("ward") or "").strip().upper()
        if ward and ward != "TOTAL":
            ward_count += 1

    return {
        "particular_rows": len(particulars or []),
        "particular_value_rows": particular_value_rows,
        "doctor_volume_rows": len(doctor_volume or []),
        "doctor_volume_value_rows": doctor_volume_value_rows,
        "ward_rows": ward_count,
    }


def _night_snapshot_should_skip(payload: dict | None) -> tuple[bool, str]:
    m = _night_snapshot_metrics(payload)
    if (
        m["ward_rows"] > 0
        and m["particular_value_rows"] == 0
        and m["doctor_volume_value_rows"] == 0
    ):
        return True, (
            "Skipped auto snapshot: ward rows present but admissions/discharges and doctor volume are empty."
        )
    return False, ""


def _log_night_snapshot_audit(*, target_time: str | None, run_time: str | None, snapshot_date: str, unit: str,
                              status: str, message: str = "", payload: dict | None = None,
                              details_saved: int | None = None, wards_saved: int | None = None):
    metrics = _night_snapshot_metrics(payload)
    try:
        with _get_login_db_connection() as conn:
            _ensure_night_report_snapshot_audit_table(conn)
            conn.execute(
                """
                INSERT INTO dbo.HID_Night_Report_Snapshot_Audit (
                    TargetTime, RunTime, SnapshotDate, Unit, Status, Message,
                    ParticularRows, ParticularValueRows, DoctorVolumeRows, DoctorVolumeValueRows,
                    WardRows, DetailsSaved, WardsSaved
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    target_time or None,
                    run_time or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S"),
                    snapshot_date,
                    (unit or "").strip().upper(),
                    (status or "UNKNOWN").strip().upper(),
                    (message or "").strip()[:500] or None,
                    int(metrics["particular_rows"]),
                    int(metrics["particular_value_rows"]),
                    int(metrics["doctor_volume_rows"]),
                    int(metrics["doctor_volume_value_rows"]),
                    int(metrics["ward_rows"]),
                    details_saved,
                    wards_saved,
                ),
            )
            conn.commit()
    except Exception as e:
        print(f"[WARN] Night snapshot audit log failed for {unit} {snapshot_date}: {e}")


def _save_night_report_ward_snapshot_to_aci(payload: dict, conn=None, commit: bool = True):
    if not payload:
        return 0
    unit = (payload.get("unit") or "").strip().upper()
    if not unit:
        return 0
    date_str = payload.get("date") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    snapshot_time_raw = payload.get("snapshot_time")
    if isinstance(snapshot_time_raw, datetime):
        snapshot_time = snapshot_time_raw.astimezone(LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    elif isinstance(snapshot_time_raw, date):
        snapshot_time = datetime.combine(snapshot_time_raw, datetime.min.time(), tzinfo=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    else:
        snapshot_time = str(snapshot_time_raw or "").strip() or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")

    def _safe_int_or_none(val):
        if val is None:
            return None
        raw = str(val).strip()
        if raw == "":
            return None
        try:
            return int(raw)
        except Exception:
            return None

    rows = []
    for row in payload.get("ward_occupancy") or []:
        ward = str(row.get("ward") or "").strip()
        if not ward or ward.upper() == "TOTAL":
            continue
        patient_count = _safe_int(row.get("patient_count"), 0)
        occupied_count = _safe_int_or_none(row.get("occupied_count"))
        clinically_discharged_count = _safe_int_or_none(row.get("clinically_discharged_count"))
        beds = _safe_int(row.get("beds"), 0)
        physical_count = _safe_int_or_none(row.get("physical_count"))
        rows.append((
            date_str,
            snapshot_time,
            unit,
            ward,
            patient_count,
            occupied_count,
            clinically_discharged_count,
            physical_count,
            beds
        ))

    if not rows:
        return 0

    own_conn = conn is None
    if own_conn:
        conn = _get_login_db_connection()
    try:
        _ensure_night_report_ward_table(conn)
        cursor = conn.cursor()
        try:
            cursor.fast_executemany = True
        except Exception:
            pass
        merge_sql = """
            MERGE dbo.HID_Night_Report_Ward AS tgt
            USING (
                SELECT
                    ? AS SnapshotDate,
                    ? AS SnapshotTime,
                    ? AS Unit,
                    ? AS WardName,
            ? AS PatientCount,
            ? AS OccupiedCount,
            ? AS ClinicallyDischargedCount,
            ? AS PhysicalCount,
            ? AS BedCount
            ) AS src
            ON tgt.SnapshotDate = src.SnapshotDate
               AND tgt.Unit = src.Unit
               AND tgt.WardName = src.WardName
            WHEN MATCHED THEN UPDATE SET
                SnapshotTime = src.SnapshotTime,
                PatientCount = src.PatientCount,
                OccupiedCount = src.OccupiedCount,
                ClinicallyDischargedCount = src.ClinicallyDischargedCount,
                PhysicalCount = src.PhysicalCount,
                BedCount = src.BedCount,
                UpdatedAt = SYSDATETIME()
            WHEN NOT MATCHED THEN INSERT (
                SnapshotDate, SnapshotTime, Unit, WardName,
                PatientCount, OccupiedCount, ClinicallyDischargedCount,
                PhysicalCount, BedCount
            ) VALUES (
                src.SnapshotDate, src.SnapshotTime, src.Unit, src.WardName,
                src.PatientCount, src.OccupiedCount, src.ClinicallyDischargedCount,
                src.PhysicalCount, src.BedCount
            );
        """
        cursor.executemany(merge_sql, rows)
        if commit:
            conn.commit()
        return len(rows)
    except Exception:
        if own_conn:
            try:
                conn.rollback()
            except Exception:
                pass
        raise
    finally:
        if own_conn:
            try:
                conn.close()
            except Exception:
                pass
    return len(rows)

def _save_night_report_detail_to_aci(payload: dict, conn=None, commit: bool = True):
    if not payload:
        return 0
    unit = (payload.get("unit") or "").strip().upper()
    if not unit:
        return 0
    date_str = payload.get("date") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    snapshot_time_raw = payload.get("snapshot_time")
    if isinstance(snapshot_time_raw, datetime):
        snapshot_time = snapshot_time_raw.astimezone(LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    elif isinstance(snapshot_time_raw, date):
        snapshot_time = datetime.combine(snapshot_time_raw, datetime.min.time(), tzinfo=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    else:
        snapshot_time = str(snapshot_time_raw or "").strip() or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")

    def _safe_int_or_none(val):
        if val is None:
            return None
        raw = str(val).strip()
        if raw == "":
            return None
        try:
            return int(float(raw))
        except Exception:
            return None

    def _safe_text_or_none(val):
        if val is None:
            return None
        raw = str(val).strip()
        return raw if raw else None

    rows_by_section = {}

    particulars = payload.get("particulars") or []
    part_rows = []
    for idx, row in enumerate(particulars):
        label = str(row.get("label") or "").strip()
        part_rows.append((
            date_str, snapshot_time, unit, "PARTICULARS", idx,
            label, _safe_int_or_none(row.get("admission")) if label else None,
            _safe_int_or_none(row.get("discharge")) if label else None,
            None, None,
            None, None, None, None, None
        ))
    rows_by_section["PARTICULARS"] = part_rows

    occupancy = payload.get("occupancy_paytype") or []
    occ_rows = []
    for idx, row in enumerate(occupancy):
        label = str(row.get("label") or "").strip()
        occ_rows.append((
            date_str, snapshot_time, unit, "OCCUPANCY", idx,
            label, None, None, _safe_int_or_none(row.get("count")) if label else None, None,
            None, None, None, None, None
        ))
    rows_by_section["OCCUPANCY"] = occ_rows

    equipment = payload.get("equipment_rows") or []
    equip_rows = []
    for idx, row in enumerate(equipment):
        label = str(row.get("equipment") or "").strip()
        if not label:
            continue
        equip_neuro = _safe_int_or_none(row.get("neuro_icu"))
        equip_nicu = _safe_int_or_none(row.get("nicu"))
        equip_picu = _safe_int_or_none(row.get("picu"))
        equip_micu = _safe_int_or_none(row.get("micu"))
        equip_ccu = _safe_int_or_none(row.get("ccu"))
        equip_rows.append((
            date_str, snapshot_time, unit, "EQUIPMENT", idx,
            label, None, None, None, None,
            equip_neuro, equip_nicu, equip_picu, equip_micu, equip_ccu
        ))
    rows_by_section["EQUIPMENT"] = equip_rows

    doctor_entries = payload.get("doctor_entries") or []
    entry_rows = []
    for idx, row in enumerate(doctor_entries):
        label = str(row.get("doctor_name") or "").strip()
        entry_time = str(row.get("entry_time") or "").strip()
        if not label and not entry_time:
            continue
        entry_rows.append((
            date_str, snapshot_time, unit, "DOCTOR_ENTRY", idx,
            label, None, None, None, entry_time,
            None, None, None, None, None
        ))
    rows_by_section["DOCTOR_ENTRY"] = entry_rows

    doctor_volume = payload.get("doctor_volume") or []
    vol_rows = []
    for idx, row in enumerate(doctor_volume):
        label = str(row.get("doctor") or "").strip()
        if not label:
            continue
        vol_rows.append((
            date_str, snapshot_time, unit, "DOCTOR_VOLUME", idx,
            label, None, None, _safe_int_or_none(row.get("count")), None,
            None, None, None, None, None
        ))
    rows_by_section["DOCTOR_VOLUME"] = vol_rows

    own_conn = conn is None
    if own_conn:
        conn = _get_login_db_connection()
    try:
        _ensure_night_report_detail_table(conn)
        cursor = conn.cursor()
        try:
            cursor.fast_executemany = True
        except Exception:
            pass
        merge_sql = """
            MERGE dbo.HID_Night_Report_Detail AS tgt
            USING (
                SELECT
                    ? AS SnapshotDate,
                    ? AS SnapshotTime,
                    ? AS Unit,
                    ? AS Section,
                    ? AS RowOrder,
                    ? AS Label,
                    ? AS Admission,
                    ? AS Discharge,
                    ? AS Count,
                    ? AS EntryTime,
                    ? AS EquipNeuroICU,
                    ? AS EquipNICU,
                    ? AS EquipPICU,
                    ? AS EquipMICU,
                    ? AS EquipCCU
            ) AS src
            ON tgt.SnapshotDate = src.SnapshotDate
               AND tgt.Unit = src.Unit
               AND tgt.Section = src.Section
               AND tgt.RowOrder = src.RowOrder
            WHEN MATCHED THEN UPDATE SET
                SnapshotTime = src.SnapshotTime,
                Label = src.Label,
                Admission = src.Admission,
                Discharge = src.Discharge,
                Count = src.Count,
                EntryTime = src.EntryTime,
                EquipNeuroICU = src.EquipNeuroICU,
                EquipNICU = src.EquipNICU,
                EquipPICU = src.EquipPICU,
                EquipMICU = src.EquipMICU,
                EquipCCU = src.EquipCCU,
                UpdatedAt = SYSDATETIME()
            WHEN NOT MATCHED THEN INSERT (
                SnapshotDate, SnapshotTime, Unit, Section, RowOrder, Label, Admission, Discharge, Count, EntryTime,
                EquipNeuroICU, EquipNICU, EquipPICU, EquipMICU, EquipCCU
            ) VALUES (
                src.SnapshotDate, src.SnapshotTime, src.Unit, src.Section, src.RowOrder, src.Label,
                src.Admission, src.Discharge, src.Count, src.EntryTime,
                src.EquipNeuroICU, src.EquipNICU, src.EquipPICU, src.EquipMICU, src.EquipCCU
            );
        """
        total_rows = 0
        for section, rows in rows_by_section.items():
            if not rows:
                cursor.execute(
                    "DELETE FROM dbo.HID_Night_Report_Detail WHERE SnapshotDate = ? AND Unit = ? AND Section = ?",
                    (date_str, unit, section),
                )
                continue
            row_orders = [r[4] for r in rows]
            placeholders = ",".join("?" * len(row_orders))
            cursor.execute(
                f"""
                DELETE FROM dbo.HID_Night_Report_Detail
                WHERE SnapshotDate = ?
                  AND Unit = ?
                  AND Section = ?
                  AND RowOrder NOT IN ({placeholders})
                """,
                (date_str, unit, section, *row_orders),
            )
            cursor.executemany(merge_sql, rows)
            total_rows += len(rows)
        if commit:
            conn.commit()
        return total_rows
    except Exception:
        if own_conn:
            try:
                conn.rollback()
            except Exception:
                pass
        raise
    finally:
        if own_conn:
            try:
                conn.close()
            except Exception:
                pass


def _save_night_report_snapshot_atomic(payload: dict) -> tuple[int, int]:
    if not payload:
        return 0, 0
    with _get_login_db_connection() as conn:
        try:
            _ensure_night_report_detail_table(conn)
            _ensure_night_report_ward_table(conn)
            detail_rows = _save_night_report_detail_to_aci(payload, conn=conn, commit=False)
            ward_rows = _save_night_report_ward_snapshot_to_aci(payload, conn=conn, commit=False)
            conn.commit()
            return detail_rows, ward_rows
        except Exception:
            try:
                conn.rollback()
            except Exception:
                pass
            raise

def _ensure_snapshot_detail_table():
    """Create detailed snapshot table with Ward + PatientSubType breakdown"""
    def _setup(conn):
        # Drop old table if it doesn't have ward column
        try:
            conn.execute("SELECT ward FROM occupancy_snapshot_detail LIMIT 1")
        except sqlite3.OperationalError:
            conn.execute("DROP TABLE IF EXISTS occupancy_snapshot_detail")

        conn.execute("""
        CREATE TABLE IF NOT EXISTS occupancy_snapshot_detail (
            snapshot_date TEXT NOT NULL,
            snapshot_time TEXT NOT NULL,
            unit TEXT NOT NULL,
            ward TEXT NOT NULL,
            patient_subtype TEXT,
            occupied INTEGER NOT NULL,
            clinically_discharged INTEGER NOT NULL,
            vacant INTEGER NOT NULL,
            total_beds INTEGER NOT NULL,
            occupancy_rate REAL NOT NULL,
            PRIMARY KEY (snapshot_date, unit, ward, patient_subtype)
        )
        """)
        conn.execute("""
        CREATE INDEX IF NOT EXISTS idx_snapshot_detail_date 
        ON occupancy_snapshot_detail(snapshot_date)
        """)
        conn.execute("""
        CREATE INDEX IF NOT EXISTS idx_snapshot_detail_unit 
        ON occupancy_snapshot_detail(unit)
        """)
        conn.execute("""
        CREATE INDEX IF NOT EXISTS idx_snapshot_detail_ward 
        ON occupancy_snapshot_detail(ward)
        """)
    _with_local_db(_setup)

def _ensure_snapshot_doctor_table():
    def _setup(conn):
        conn.execute("""
        CREATE TABLE IF NOT EXISTS occupancy_snapshot_doctor (
            snapshot_date TEXT NOT NULL,
            snapshot_time TEXT NOT NULL,
            unit TEXT NOT NULL,
            doctor TEXT NOT NULL,
            occupied INTEGER NOT NULL,
            PRIMARY KEY (snapshot_date, unit, doctor)
        )
        """)
    _with_local_db(_setup)

