    def _draw_footer(canvas, doc_obj):
        canvas.saveState()
        canvas.setFont(font_regular_name, 9)
        footer_y = 5 * mm
        line1 = f"Exported By: {exported_by} | Exported At: {exported_at} | Unit: {unit_label}"
