def _ensure_morning_report_snapshot_audit_table(conn):
    global MORNING_REPORT_AUDIT_SCHEMA_READY
    if MORNING_REPORT_AUDIT_SCHEMA_READY:
        return
    with MORNING_REPORT_SCHEMA_LOCK:
        if MORNING_REPORT_AUDIT_SCHEMA_READY:
            return
    cursor = conn.cursor()
    cursor.execute(
        """
    IF NOT EXISTS (
        SELECT 1 FROM INFORMATION_SCHEMA.TABLES
        WHERE TABLE_SCHEMA='dbo' AND TABLE_NAME='HID_Morning_Report_Snapshot_Audit'
    )
    BEGIN
        CREATE TABLE dbo.HID_Morning_Report_Snapshot_Audit (
            Id INT IDENTITY(1,1) PRIMARY KEY,
            TargetTime DATETIME2 NULL,
            RunTime DATETIME2 NOT NULL,
            SnapshotDate DATE NOT NULL,
            Unit NVARCHAR(20) NOT NULL,
            Status NVARCHAR(20) NOT NULL,
            Message NVARCHAR(500) NULL,
            SummaryRows INT NOT NULL DEFAULT(0),
            InvestigationRows INT NOT NULL DEFAULT(0),
            ProcedureRows INT NOT NULL DEFAULT(0),
            AdmissionRows INT NOT NULL DEFAULT(0),
            DoctorwiseRows INT NOT NULL DEFAULT(0),
            OccupancyRows INT NOT NULL DEFAULT(0),
            DoctorNightVisitRows INT NOT NULL DEFAULT(0),
            StaffRows INT NOT NULL DEFAULT(0),
            StaffValueRows INT NOT NULL DEFAULT(0),
            NonMedicalRows INT NOT NULL DEFAULT(0),
            NonMedicalValueRows INT NOT NULL DEFAULT(0),
            ReferralRows INT NOT NULL DEFAULT(0),
            SavedFlag BIT NULL,
            CreatedAt DATETIME2 NOT NULL DEFAULT(SYSDATETIME())
        );
        CREATE INDEX IX_HID_Morning_Report_Snapshot_Audit_RunTime
            ON dbo.HID_Morning_Report_Snapshot_Audit(RunTime DESC);
        CREATE INDEX IX_HID_Morning_Report_Snapshot_Audit_DateUnit
            ON dbo.HID_Morning_Report_Snapshot_Audit(SnapshotDate, Unit);
    END
    """
    )
    conn.commit()
    for stmt in [
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD TargetTime DATETIME2 NULL",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD RunTime DATETIME2 NOT NULL DEFAULT(SYSDATETIME())",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD SnapshotDate DATE NOT NULL DEFAULT(CONVERT(date, SYSDATETIME()))",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD Unit NVARCHAR(20) NOT NULL DEFAULT('')",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD Status NVARCHAR(20) NOT NULL DEFAULT('UNKNOWN')",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD Message NVARCHAR(500) NULL",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD SummaryRows INT NOT NULL DEFAULT(0)",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD InvestigationRows INT NOT NULL DEFAULT(0)",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD ProcedureRows INT NOT NULL DEFAULT(0)",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD AdmissionRows INT NOT NULL DEFAULT(0)",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD DoctorwiseRows INT NOT NULL DEFAULT(0)",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD OccupancyRows INT NOT NULL DEFAULT(0)",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD DoctorNightVisitRows INT NOT NULL DEFAULT(0)",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD StaffRows INT NOT NULL DEFAULT(0)",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD StaffValueRows INT NOT NULL DEFAULT(0)",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD NonMedicalRows INT NOT NULL DEFAULT(0)",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD NonMedicalValueRows INT NOT NULL DEFAULT(0)",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD ReferralRows INT NOT NULL DEFAULT(0)",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD SavedFlag BIT NULL",
        "ALTER TABLE dbo.HID_Morning_Report_Snapshot_Audit ADD CreatedAt DATETIME2 NOT NULL DEFAULT(SYSDATETIME())",
    ]:
        try:
            cursor.execute(stmt)
            conn.commit()
        except Exception:
            conn.rollback()
    for stmt in [
        "CREATE INDEX IX_HID_Morning_Report_Snapshot_Audit_RunTime ON dbo.HID_Morning_Report_Snapshot_Audit(RunTime DESC)",
        "CREATE INDEX IX_HID_Morning_Report_Snapshot_Audit_DateUnit ON dbo.HID_Morning_Report_Snapshot_Audit(SnapshotDate, Unit)",
    ]:
        try:
            cursor.execute(stmt)
            conn.commit()
        except Exception:
            conn.rollback()
    MORNING_REPORT_AUDIT_SCHEMA_READY = True


def _morning_snapshot_metrics(payload: dict | None) -> dict:
    summary_rows = payload.get("summary_rows") if payload else []
    investigations = payload.get("investigations") if payload else []
    key_procedures = payload.get("key_procedures") if payload else []
    admissions = payload.get("admissions") if payload else []
    doctorwise_rows = payload.get("doctorwise_rows") if payload else []
    occupancy_rows = payload.get("occupancy_rows") if payload else []
    doctor_night_rows = payload.get("doctor_night_visits") if payload else []
    staff_rows = payload.get("staff_rows") if payload else []
    non_medical_rows = payload.get("non_medical_rows") if payload else []
    referral_rows = payload.get("referral_rows") if payload else []

    def _has_value(val) -> bool:
        if val is None:
            return False
        return str(val).strip() != ""

    def _value_count(rows: list[dict] | None, keys: tuple[str, ...]) -> int:
        count = 0
        for row in rows or []:
            if any(_has_value((row or {}).get(k)) for k in keys):
                count += 1
        return count

    return {
        "summary_rows": len(summary_rows or []),
        "investigation_rows": len(investigations or []),
        "procedure_rows": len(key_procedures or []),
        "admission_rows": len(admissions or []),
        "doctorwise_rows": len(doctorwise_rows or []),
        "occupancy_rows": len(occupancy_rows or []),
        "doctor_night_visit_rows": len(doctor_night_rows or []),
        "staff_rows": len(staff_rows or []),
        "staff_value_rows": _value_count(staff_rows, ("doctor", "nursing", "aaya", "ward_boy", "housekeeping")),
        "non_medical_rows": len(non_medical_rows or []),
        "non_medical_value_rows": _value_count(non_medical_rows, ("left_label", "left_count", "right_label", "right_count")),
        "referral_rows": len(referral_rows or []),
    }


def _morning_snapshot_should_skip(payload: dict | None) -> tuple[bool, str]:
    if not payload:
        return True, "Skipped auto snapshot: morning payload is empty."

    summary_has = _rows_have_any_value(payload.get("summary_rows"), ("label", "asarfi", "cardiac", "total"))
    admission_has = _rows_have_any_value(payload.get("admissions"), ("dept", "doctor", "prev_count", "night_count"))
    doctorwise_has = _rows_have_any_value(payload.get("doctorwise_rows"), ("department", "opd", "ipd"))
    occupancy_has = _rows_have_any_value(
        payload.get("occupancy_rows"),
        ("ward", "patient_count", "occupied_count", "clinically_discharged_count"),
    )
    night_visit_has = _rows_have_any_value(
        payload.get("doctor_night_visits"),
        ("patient_name", "admission_time", "consultant", "visiting"),
    )

    if not occupancy_has:
        return True, "Skipped auto snapshot: occupancy section is empty."

    if not (summary_has or admission_has or doctorwise_has or night_visit_has):
        return True, (
            "Skipped auto snapshot: occupancy exists but summary, admissions, doctorwise, and doctor-night-visit sections are empty."
        )

    return False, ""


def _log_morning_snapshot_audit(*, target_time: str | None, run_time: str | None, snapshot_date: str, unit: str,
                                status: str, message: str = "", payload: dict | None = None,
                                saved: bool | None = None):
    metrics = _morning_snapshot_metrics(payload)
    try:
        with _get_login_db_connection() as conn:
            _ensure_morning_report_snapshot_audit_table(conn)
            conn.execute(
                """
                INSERT INTO dbo.HID_Morning_Report_Snapshot_Audit (
                    TargetTime, RunTime, SnapshotDate, Unit, Status, Message,
                    SummaryRows, InvestigationRows, ProcedureRows, AdmissionRows,
                    DoctorwiseRows, OccupancyRows, DoctorNightVisitRows,
                    StaffRows, StaffValueRows, NonMedicalRows, NonMedicalValueRows,
                    ReferralRows, SavedFlag
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    target_time or None,
                    run_time or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S"),
                    snapshot_date,
                    (unit or "").strip().upper(),
                    (status or "UNKNOWN").strip().upper(),
                    (message or "").strip()[:500] or None,
                    int(metrics["summary_rows"]),
                    int(metrics["investigation_rows"]),
                    int(metrics["procedure_rows"]),
                    int(metrics["admission_rows"]),
                    int(metrics["doctorwise_rows"]),
                    int(metrics["occupancy_rows"]),
                    int(metrics["doctor_night_visit_rows"]),
                    int(metrics["staff_rows"]),
                    int(metrics["staff_value_rows"]),
                    int(metrics["non_medical_rows"]),
                    int(metrics["non_medical_value_rows"]),
                    int(metrics["referral_rows"]),
                    (1 if saved else 0) if saved is not None else None,
                ),
            )
            conn.commit()
    except Exception as e:
        print(f"Morning snapshot audit log failed for {unit} {snapshot_date}: {e}")

def _save_morning_report_snapshot_to_aci(payload: dict):
    if not payload:
        return 0
    unit = (payload.get("unit") or "").strip().upper()
    if not unit:
        return 0
    date_str = payload.get("report_date") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    snapshot_time = payload.get("snapshot_time") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    report_time = payload.get("report_time") or ""
    mod_name = payload.get("mod_name") or ""

    def _safe_int_or_none(val):
        if val is None:
            return None
        raw = str(val).strip()
        if raw == "":
            return None
        try:
            return int(float(raw))
        except Exception:
            return None

    def _safe_text_or_none(val):
        if val is None:
            return None
        raw = str(val).strip()
        return raw if raw else None

    with _get_login_db_connection() as conn:
        _ensure_morning_report_tables(conn)
        cursor = conn.cursor()

        # Header
        merge_header = """
            MERGE dbo.HID_Morning_Report_Header AS tgt
            USING (
                SELECT ? AS SnapshotDate, ? AS SnapshotTime, ? AS Unit,
                       ? AS ReportTime, ? AS ModName
            ) AS src
            ON tgt.SnapshotDate = src.SnapshotDate AND tgt.Unit = src.Unit
            WHEN MATCHED THEN UPDATE SET
                SnapshotTime = src.SnapshotTime,
                ReportTime = src.ReportTime,
                ModName = src.ModName,
                UpdatedAt = SYSDATETIME()
            WHEN NOT MATCHED THEN INSERT (
                SnapshotDate, SnapshotTime, Unit, ReportTime, ModName
            ) VALUES (
                src.SnapshotDate, src.SnapshotTime, src.Unit, src.ReportTime, src.ModName
            );
        """
        cursor.execute(merge_header, (date_str, snapshot_time, unit, report_time, mod_name))

        # Summary
        summary_rows = []
        for idx, row in enumerate(payload.get("summary_rows") or []):
            label = str(row.get("label") or "").strip()
            manual = 1 if row.get("manual") else 0
            summary_rows.append((
                date_str, snapshot_time, unit, idx,
                label,
                _safe_int_or_none(row.get("asarfi")),
                _safe_int_or_none(row.get("cardiac")),
                _safe_int_or_none(row.get("total")),
                manual
            ))
        if summary_rows:
            merge_summary = """
                MERGE dbo.HID_Morning_Report_Summary AS tgt
                USING (
                    SELECT
                        ? AS SnapshotDate,
                        ? AS SnapshotTime,
                        ? AS Unit,
                        ? AS RowOrder,
                        ? AS Label,
                        ? AS AsarfiCount,
                        ? AS CardiacCount,
                        ? AS TotalCount,
                        ? AS ManualFlag
                ) AS src
                ON tgt.SnapshotDate = src.SnapshotDate
                   AND tgt.Unit = src.Unit
                   AND tgt.RowOrder = src.RowOrder
                WHEN MATCHED THEN UPDATE SET
                    SnapshotTime = src.SnapshotTime,
                    Label = src.Label,
                    AsarfiCount = src.AsarfiCount,
                    CardiacCount = src.CardiacCount,
                    TotalCount = src.TotalCount,
                    ManualFlag = src.ManualFlag,
                    UpdatedAt = SYSDATETIME()
                WHEN NOT MATCHED THEN INSERT (
                    SnapshotDate, SnapshotTime, Unit, RowOrder, Label,
                    AsarfiCount, CardiacCount, TotalCount, ManualFlag
                ) VALUES (
                    src.SnapshotDate, src.SnapshotTime, src.Unit, src.RowOrder, src.Label,
                    src.AsarfiCount, src.CardiacCount, src.TotalCount, src.ManualFlag
                );
            """
            cursor.executemany(merge_summary, summary_rows)

        # Investigations
        inv_rows = []
        for idx, row in enumerate(payload.get("investigations") or []):
            label = str(row.get("label") or "").strip()
            inv_rows.append((
                date_str, snapshot_time, unit, idx,
                label,
                _safe_int_or_none(row.get("asarfi")),
                _safe_int_or_none(row.get("cardiac")),
                _safe_int_or_none(row.get("total"))
            ))
        if inv_rows:
            merge_inv = """
                MERGE dbo.HID_Morning_Report_Investigation AS tgt
                USING (
                    SELECT
                        ? AS SnapshotDate,
                        ? AS SnapshotTime,
                        ? AS Unit,
                        ? AS RowOrder,
                        ? AS Label,
                        ? AS AsarfiCount,
                        ? AS CardiacCount,
                        ? AS TotalCount
                ) AS src
                ON tgt.SnapshotDate = src.SnapshotDate
                   AND tgt.Unit = src.Unit
                   AND tgt.RowOrder = src.RowOrder
                WHEN MATCHED THEN UPDATE SET
                    SnapshotTime = src.SnapshotTime,
                    Label = src.Label,
                    AsarfiCount = src.AsarfiCount,
                    CardiacCount = src.CardiacCount,
                    TotalCount = src.TotalCount,
                    UpdatedAt = SYSDATETIME()
                WHEN NOT MATCHED THEN INSERT (
                    SnapshotDate, SnapshotTime, Unit, RowOrder, Label,
                    AsarfiCount, CardiacCount, TotalCount
                ) VALUES (
                    src.SnapshotDate, src.SnapshotTime, src.Unit, src.RowOrder, src.Label,
                    src.AsarfiCount, src.CardiacCount, src.TotalCount
                );
            """
            cursor.executemany(merge_inv, inv_rows)

        # Procedures
        proc_rows = []
        for idx, row in enumerate(payload.get("key_procedures") or []):
            label = str(row.get("label") or "").strip()
            proc_rows.append((
                date_str, snapshot_time, unit, idx,
                label,
                _safe_int_or_none(row.get("count"))
            ))
        if proc_rows:
            merge_proc = """
                MERGE dbo.HID_Morning_Report_Procedure AS tgt
                USING (
                    SELECT
                        ? AS SnapshotDate,
                        ? AS SnapshotTime,
                        ? AS Unit,
                        ? AS RowOrder,
                        ? AS Label,
                        ? AS ProcCount
                ) AS src
                ON tgt.SnapshotDate = src.SnapshotDate
                   AND tgt.Unit = src.Unit
                   AND tgt.RowOrder = src.RowOrder
                WHEN MATCHED THEN UPDATE SET
                    SnapshotTime = src.SnapshotTime,
                    Label = src.Label,
                    ProcCount = src.ProcCount,
                    UpdatedAt = SYSDATETIME()
                WHEN NOT MATCHED THEN INSERT (
                    SnapshotDate, SnapshotTime, Unit, RowOrder, Label, ProcCount
                ) VALUES (
                    src.SnapshotDate, src.SnapshotTime, src.Unit, src.RowOrder, src.Label, src.ProcCount
                );
            """
            cursor.executemany(merge_proc, proc_rows)

        # Admissions
        adm_rows = []
        for idx, row in enumerate(payload.get("admissions") or []):
            adm_rows.append((
                date_str, snapshot_time, unit, idx,
                str(row.get("dept") or "").strip(),
                str(row.get("doctor") or "").strip(),
                _safe_int_or_none(row.get("prev_count")),
                _safe_int_or_none(row.get("night_count"))
            ))
        if adm_rows:
            merge_adm = """
                MERGE dbo.HID_Morning_Report_Admission AS tgt
                USING (
                    SELECT
                        ? AS SnapshotDate,
                        ? AS SnapshotTime,
                        ? AS Unit,
                        ? AS RowOrder,
                        ? AS Dept,
                        ? AS Doctor,
                        ? AS PrevCount,
                        ? AS NightCount
                ) AS src
                ON tgt.SnapshotDate = src.SnapshotDate
                   AND tgt.Unit = src.Unit
                   AND tgt.RowOrder = src.RowOrder
                WHEN MATCHED THEN UPDATE SET
                    SnapshotTime = src.SnapshotTime,
                    Dept = src.Dept,
                    Doctor = src.Doctor,
                    PrevCount = src.PrevCount,
                    NightCount = src.NightCount,
                    UpdatedAt = SYSDATETIME()
                WHEN NOT MATCHED THEN INSERT (
                    SnapshotDate, SnapshotTime, Unit, RowOrder, Dept, Doctor, PrevCount, NightCount
                ) VALUES (
                    src.SnapshotDate, src.SnapshotTime, src.Unit, src.RowOrder,
                    src.Dept, src.Doctor, src.PrevCount, src.NightCount
                );
            """
            cursor.executemany(merge_adm, adm_rows)

        # Doctorwise IPD/OPD
        doctorwise_rows = []
        for idx, row in enumerate(payload.get("doctorwise_rows") or []):
            doctorwise_rows.append((
                date_str, snapshot_time, unit, idx,
                _safe_text_or_none(row.get("department")),
                _safe_int_or_none(row.get("opd")),
                _safe_int_or_none(row.get("ipd")),
            ))
        if doctorwise_rows:
            merge_doctorwise = """
                MERGE dbo.HID_Morning_Report_Doctorwise AS tgt
                USING (
                    SELECT
                        ? AS SnapshotDate,
                        ? AS SnapshotTime,
                        ? AS Unit,
                        ? AS RowOrder,
                        ? AS Department,
                        ? AS OPDCount,
                        ? AS IPDCount
                ) AS src
                ON tgt.SnapshotDate = src.SnapshotDate
                   AND tgt.Unit = src.Unit
                   AND tgt.RowOrder = src.RowOrder
                WHEN MATCHED THEN UPDATE SET
                    SnapshotTime = src.SnapshotTime,
                    Department = src.Department,
                    OPDCount = src.OPDCount,
                    IPDCount = src.IPDCount,
                    UpdatedAt = SYSDATETIME()
                WHEN NOT MATCHED THEN INSERT (
                    SnapshotDate, SnapshotTime, Unit, RowOrder, Department, OPDCount, IPDCount
                ) VALUES (
                    src.SnapshotDate, src.SnapshotTime, src.Unit, src.RowOrder, src.Department, src.OPDCount, src.IPDCount
                );
            """
            cursor.executemany(merge_doctorwise, doctorwise_rows)

        # Occupancy @ 08:00
        occ_rows = []
        for idx, row in enumerate(payload.get("occupancy_rows") or []):
            occ_rows.append((
                date_str, snapshot_time, unit, idx,
                _safe_text_or_none(row.get("ward")),
                _safe_int_or_none(row.get("patient_count")),
                _safe_int_or_none(row.get("occupied_count")),
                _safe_int_or_none(row.get("clinically_discharged_count")),
                _safe_int_or_none(row.get("beds")),
            ))
        if occ_rows:
            merge_occ = """
                MERGE dbo.HID_Morning_Report_Occupancy AS tgt
                USING (
                    SELECT
                        ? AS SnapshotDate,
                        ? AS SnapshotTime,
                        ? AS Unit,
                        ? AS RowOrder,
                        ? AS WardName,
                        ? AS PatientCount,
                        ? AS OccupiedCount,
                        ? AS ClinicallyDischargedCount,
                        ? AS BedCount
                ) AS src
                ON tgt.SnapshotDate = src.SnapshotDate
                   AND tgt.Unit = src.Unit
                   AND tgt.RowOrder = src.RowOrder
                WHEN MATCHED THEN UPDATE SET
                    SnapshotTime = src.SnapshotTime,
                    WardName = src.WardName,
                    PatientCount = src.PatientCount,
                    OccupiedCount = src.OccupiedCount,
                    ClinicallyDischargedCount = src.ClinicallyDischargedCount,
                    BedCount = src.BedCount,
                    UpdatedAt = SYSDATETIME()
                WHEN NOT MATCHED THEN INSERT (
                    SnapshotDate, SnapshotTime, Unit, RowOrder, WardName,
                    PatientCount, OccupiedCount, ClinicallyDischargedCount, BedCount
                ) VALUES (
                    src.SnapshotDate, src.SnapshotTime, src.Unit, src.RowOrder, src.WardName,
                    src.PatientCount, src.OccupiedCount, src.ClinicallyDischargedCount, src.BedCount
                );
            """
            cursor.executemany(merge_occ, occ_rows)

        # Doctor Night Visit
        night_rows = []
        for idx, row in enumerate(payload.get("doctor_night_visits") or []):
            night_rows.append((
                date_str, snapshot_time, unit, idx,
                _safe_text_or_none(row.get("patient_name")),
                _safe_text_or_none(row.get("admission_time")),
                _safe_text_or_none(row.get("consultant")),
                _safe_text_or_none(row.get("visiting")),
            ))
        if night_rows:
            merge_night = """
                MERGE dbo.HID_Morning_Report_DoctorNightVisit AS tgt
                USING (
                    SELECT
                        ? AS SnapshotDate,
                        ? AS SnapshotTime,
                        ? AS Unit,
                        ? AS RowOrder,
                        ? AS PatientName,
                        ? AS AdmissionTime,
                        ? AS ConsultantName,
                        ? AS Visiting
                ) AS src
                ON tgt.SnapshotDate = src.SnapshotDate
                   AND tgt.Unit = src.Unit
                   AND tgt.RowOrder = src.RowOrder
                WHEN MATCHED THEN UPDATE SET
                    SnapshotTime = src.SnapshotTime,
                    PatientName = src.PatientName,
                    AdmissionTime = src.AdmissionTime,
                    ConsultantName = src.ConsultantName,
                    Visiting = src.Visiting,
                    UpdatedAt = SYSDATETIME()
                WHEN NOT MATCHED THEN INSERT (
                    SnapshotDate, SnapshotTime, Unit, RowOrder,
                    PatientName, AdmissionTime, ConsultantName, Visiting
                ) VALUES (
                    src.SnapshotDate, src.SnapshotTime, src.Unit, src.RowOrder,
                    src.PatientName, src.AdmissionTime, src.ConsultantName, src.Visiting
                );
            """
            cursor.executemany(merge_night, night_rows)

        # Staff Count
        staff_rows = []
        for idx, row in enumerate(payload.get("staff_rows") or []):
            staff_rows.append((
                date_str, snapshot_time, unit, idx,
                _safe_text_or_none(row.get("department")),
                _safe_text_or_none(row.get("doctor")),
                _safe_text_or_none(row.get("nursing")),
                _safe_text_or_none(row.get("aaya")),
                _safe_text_or_none(row.get("ward_boy")),
                _safe_text_or_none(row.get("housekeeping")),
            ))
        if staff_rows:
            merge_staff = """
                MERGE dbo.HID_Morning_Report_Staff AS tgt
                USING (
                    SELECT
                        ? AS SnapshotDate,
                        ? AS SnapshotTime,
                        ? AS Unit,
                        ? AS RowOrder,
                        ? AS Department,
                        ? AS DoctorCount,
                        ? AS NursingCount,
                        ? AS AayaCount,
                        ? AS WardBoyCount,
                        ? AS HouseKeepingCount
                ) AS src
                ON tgt.SnapshotDate = src.SnapshotDate
                   AND tgt.Unit = src.Unit
                   AND tgt.RowOrder = src.RowOrder
                WHEN MATCHED THEN UPDATE SET
                    SnapshotTime = src.SnapshotTime,
                    Department = src.Department,
                    DoctorCount = src.DoctorCount,
                    NursingCount = src.NursingCount,
                    AayaCount = src.AayaCount,
                    WardBoyCount = src.WardBoyCount,
                    HouseKeepingCount = src.HouseKeepingCount,
                    UpdatedAt = SYSDATETIME()
                WHEN NOT MATCHED THEN INSERT (
                    SnapshotDate, SnapshotTime, Unit, RowOrder, Department,
                    DoctorCount, NursingCount, AayaCount, WardBoyCount, HouseKeepingCount
                ) VALUES (
                    src.SnapshotDate, src.SnapshotTime, src.Unit, src.RowOrder, src.Department,
                    src.DoctorCount, src.NursingCount, src.AayaCount, src.WardBoyCount, src.HouseKeepingCount
                );
            """
            cursor.executemany(merge_staff, staff_rows)

        # Non Medical Staff
        non_med_rows = []
        for idx, row in enumerate(payload.get("non_medical_rows") or []):
            non_med_rows.append((
                date_str, snapshot_time, unit, idx,
                _safe_text_or_none(row.get("left_label")),
                _safe_text_or_none(row.get("left_count")),
                _safe_text_or_none(row.get("right_label")),
                _safe_text_or_none(row.get("right_count")),
            ))
        if non_med_rows:
            merge_non_med = """
                MERGE dbo.HID_Morning_Report_NonMedical AS tgt
                USING (
                    SELECT
                        ? AS SnapshotDate,
                        ? AS SnapshotTime,
                        ? AS Unit,
                        ? AS RowOrder,
                        ? AS LeftLabel,
                        ? AS LeftCount,
                        ? AS RightLabel,
                        ? AS RightCount
                ) AS src
                ON tgt.SnapshotDate = src.SnapshotDate
                   AND tgt.Unit = src.Unit
                   AND tgt.RowOrder = src.RowOrder
                WHEN MATCHED THEN UPDATE SET
                    SnapshotTime = src.SnapshotTime,
                    LeftLabel = src.LeftLabel,
                    LeftCount = src.LeftCount,
                    RightLabel = src.RightLabel,
                    RightCount = src.RightCount,
                    UpdatedAt = SYSDATETIME()
                WHEN NOT MATCHED THEN INSERT (
                    SnapshotDate, SnapshotTime, Unit, RowOrder, LeftLabel, LeftCount, RightLabel, RightCount
                ) VALUES (
                    src.SnapshotDate, src.SnapshotTime, src.Unit, src.RowOrder,
                    src.LeftLabel, src.LeftCount, src.RightLabel, src.RightCount
                );
            """
            cursor.executemany(merge_non_med, non_med_rows)

        # Referral / Refusal / Brought Death
        referral_rows = []
        for idx, row in enumerate(payload.get("referral_rows") or []):
            referral_rows.append((
                date_str, snapshot_time, unit, idx,
                _safe_text_or_none(row.get("patient_name")),
                _safe_text_or_none(row.get("visit_time")),
                _safe_text_or_none(row.get("consultant")),
                _safe_text_or_none(row.get("reason")),
            ))
        if referral_rows:
            merge_ref = """
                MERGE dbo.HID_Morning_Report_Referral AS tgt
                USING (
                    SELECT
                        ? AS SnapshotDate,
                        ? AS SnapshotTime,
                        ? AS Unit,
                        ? AS RowOrder,
                        ? AS PatientName,
                        ? AS VisitTime,
                        ? AS ConsultantName,
                        ? AS Reason
                ) AS src
                ON tgt.SnapshotDate = src.SnapshotDate
                   AND tgt.Unit = src.Unit
                   AND tgt.RowOrder = src.RowOrder
                WHEN MATCHED THEN UPDATE SET
                    SnapshotTime = src.SnapshotTime,
                    PatientName = src.PatientName,
                    VisitTime = src.VisitTime,
                    ConsultantName = src.ConsultantName,
                    Reason = src.Reason,
                    UpdatedAt = SYSDATETIME()
                WHEN NOT MATCHED THEN INSERT (
                    SnapshotDate, SnapshotTime, Unit, RowOrder,
                    PatientName, VisitTime, ConsultantName, Reason
                ) VALUES (
                    src.SnapshotDate, src.SnapshotTime, src.Unit, src.RowOrder,
                    src.PatientName, src.VisitTime, src.ConsultantName, src.Reason
                );
            """
            cursor.executemany(merge_ref, referral_rows)

        conn.commit()

    return 1

def _fetch_morning_report_snapshot(date_str: str, unit: str):
    unit_norm = (unit or "").strip().upper()
    if not unit_norm:
        return None
    _t0 = time.perf_counter()
    def _log(stage: str):
        elapsed = (time.perf_counter() - _t0) * 1000
        print(f"[timing] morning_snapshot {unit_norm} {date_str} {stage}: {elapsed:.1f}ms")
    try:
        with _get_login_db_connection() as conn:
            _ensure_morning_report_tables(conn)
            cur = conn.cursor()
            cur.execute(
                """
                SELECT SnapshotTime, ReportTime, ModName
                FROM dbo.HID_Morning_Report_Header WITH (NOLOCK)
                WHERE SnapshotDate = ? AND Unit = ?
                """,
                (date_str, unit_norm),
            )
            header = cur.fetchone()
            if not header:
                return None
            snapshot_time, report_time, mod_name = header
            _log("header")

            cur.execute(
                """
                SELECT RowOrder, Label, AsarfiCount, CardiacCount, TotalCount, ManualFlag
                FROM dbo.HID_Morning_Report_Summary WITH (NOLOCK)
                WHERE SnapshotDate = ? AND Unit = ?
                ORDER BY RowOrder
                """,
                (date_str, unit_norm),
            )
            summary_rows = [{
                "sl": row_order + 1,
                "label": label,
                "asarfi": asarfi,
                "cardiac": cardiac,
                "total": total,
                "manual": bool(manual_flag) if manual_flag is not None else False
            } for row_order, label, asarfi, cardiac, total, manual_flag in cur.fetchall()]
            _log("summary")

            cur.execute(
                """
                SELECT RowOrder, Label, AsarfiCount, CardiacCount, TotalCount
                FROM dbo.HID_Morning_Report_Investigation WITH (NOLOCK)
                WHERE SnapshotDate = ? AND Unit = ?
                ORDER BY RowOrder
                """,
                (date_str, unit_norm),
            )
            inv_rows = [{
                "sl": row_order + 1 if row_order is not None else "",
                "label": label,
                "asarfi": asarfi,
                "cardiac": cardiac,
                "total": total
            } for row_order, label, asarfi, cardiac, total in cur.fetchall()]
            _log("investigation")

            cur.execute(
                """
                SELECT RowOrder, Label, ProcCount
                FROM dbo.HID_Morning_Report_Procedure WITH (NOLOCK)
                WHERE SnapshotDate = ? AND Unit = ?
                ORDER BY RowOrder
                """,
                (date_str, unit_norm),
            )
            proc_rows = [{
                "sl": row_order + 1 if row_order is not None else "",
                "label": label,
                "count": proc_count
            } for row_order, label, proc_count in cur.fetchall()]
            _log("procedure")

            cur.execute(
                """
                SELECT RowOrder, Dept, Doctor, PrevCount, NightCount
                FROM dbo.HID_Morning_Report_Admission WITH (NOLOCK)
                WHERE SnapshotDate = ? AND Unit = ?
                ORDER BY RowOrder
                """,
                (date_str, unit_norm),
            )
            adm_rows = [{
                "sl": row_order + 1 if row_order is not None else "",
                "dept": dept,
                "doctor": doctor,
                "prev_count": prev_count,
                "night_count": night_count
            } for row_order, dept, doctor, prev_count, night_count in cur.fetchall()]
            _log("admission")

            cur.execute(
                """
                SELECT RowOrder, Department, OPDCount, IPDCount
                FROM dbo.HID_Morning_Report_Doctorwise WITH (NOLOCK)
                WHERE SnapshotDate = ? AND Unit = ?
                ORDER BY RowOrder
                """,
                (date_str, unit_norm),
            )
            doctorwise_rows = [{
                "sl": row_order + 1 if row_order is not None else "",
                "department": dept,
                "opd": opd,
                "ipd": ipd
            } for row_order, dept, opd, ipd in cur.fetchall()]
            _log("doctorwise")

            cur.execute(
                """
                SELECT RowOrder, WardName, PatientCount, OccupiedCount, ClinicallyDischargedCount, BedCount
                FROM dbo.HID_Morning_Report_Occupancy WITH (NOLOCK)
                WHERE SnapshotDate = ? AND Unit = ?
                ORDER BY RowOrder
                """,
                (date_str, unit_norm),
            )
            occupancy_rows = [{
                "sl": row_order + 1 if row_order is not None else "",
                "ward": ward,
                "patient_count": patient,
                "occupied_count": occupied,
                "clinically_discharged_count": discharged,
                "beds": beds
            } for row_order, ward, patient, occupied, discharged, beds in cur.fetchall()]
            _log("occupancy")

            cur.execute(
                """
                SELECT RowOrder, PatientName, AdmissionTime, ConsultantName, Visiting
                FROM dbo.HID_Morning_Report_DoctorNightVisit WITH (NOLOCK)
                WHERE SnapshotDate = ? AND Unit = ?
                ORDER BY RowOrder
                """,
                (date_str, unit_norm),
            )
            doctor_night_visits = [{
                "sl": row_order + 1 if row_order is not None else "",
                "patient_name": patient,
                "admission_time": admit_time,
                "consultant": consultant,
                "visiting": visiting
            } for row_order, patient, admit_time, consultant, visiting in cur.fetchall()]
            _log("doctor_night_visit")

            cur.execute(
                """
                SELECT RowOrder, Department, DoctorCount, NursingCount, AayaCount, WardBoyCount, HouseKeepingCount
                FROM dbo.HID_Morning_Report_Staff WITH (NOLOCK)
                WHERE SnapshotDate = ? AND Unit = ?
                ORDER BY RowOrder
                """,
                (date_str, unit_norm),
            )
            staff_rows = [{
                "sl": row_order + 1 if row_order is not None else "",
                "department": dept,
                "doctor": doctor,
                "nursing": nursing,
                "aaya": aaya,
                "ward_boy": ward_boy,
                "housekeeping": housekeep
            } for row_order, dept, doctor, nursing, aaya, ward_boy, housekeep in cur.fetchall()]
            _log("staff")

            cur.execute(
                """
                SELECT RowOrder, LeftLabel, LeftCount, RightLabel, RightCount
                FROM dbo.HID_Morning_Report_NonMedical WITH (NOLOCK)
                WHERE SnapshotDate = ? AND Unit = ?
                ORDER BY RowOrder
                """,
                (date_str, unit_norm),
            )
            non_medical_rows = [{
                "sl": row_order + 1 if row_order is not None else "",
                "left_label": left_label,
                "left_count": left_count,
                "right_label": right_label,
                "right_count": right_count
            } for row_order, left_label, left_count, right_label, right_count in cur.fetchall()]
            _log("non_medical")

            cur.execute(
                """
                SELECT RowOrder, PatientName, VisitTime, ConsultantName, Reason
                FROM dbo.HID_Morning_Report_Referral WITH (NOLOCK)
                WHERE SnapshotDate = ? AND Unit = ?
                ORDER BY RowOrder
                """,
                (date_str, unit_norm),
            )
            referral_rows = [{
                "sl": row_order + 1 if row_order is not None else "",
                "patient_name": patient,
                "visit_time": visit_time,
                "consultant": consultant,
                "reason": reason
            } for row_order, patient, visit_time, consultant, reason in cur.fetchall()]
            _log("referral")

    except Exception:
        return None

    snap_time_str = None
    if snapshot_time:
        if isinstance(snapshot_time, (datetime, date)):
            snap_time_str = snapshot_time.strftime("%Y-%m-%d %H:%M:%S")
        else:
            snap_time_str = str(snapshot_time)

    summary_rows = _ensure_morning_death_summary_row(unit_norm, date_str, summary_rows)
    summary_rows = _collapse_morning_counts(unit_norm, summary_rows)
    inv_rows = _collapse_morning_counts(unit_norm, inv_rows)

    if not staff_rows:
        staff_rows = _default_staff_rows()
    if not non_medical_rows:
        non_medical_rows = _default_non_medical_rows()
    if not referral_rows:
        referral_rows = _default_referral_rows()

    return {
        "unit": unit_norm,
        "report_date": date_str,
        "report_time": report_time or "",
        "mod_name": mod_name or "",
        "summary_rows": summary_rows,
        "investigations": inv_rows,
        "key_procedures": proc_rows,
        "admissions": adm_rows,
        "doctorwise_rows": doctorwise_rows or [],
        "occupancy_rows": occupancy_rows or [],
        "doctor_night_visits": doctor_night_visits or [],
        "staff_rows": staff_rows or [],
        "non_medical_rows": non_medical_rows or [],
        "referral_rows": referral_rows or [],
        "source": "snapshot",
        "snapshot_time": snap_time_str,
    }


def _normalize_snapshot_date(value) -> str | None:
    if value is None:
        return None
    if isinstance(value, (datetime, date)):
        return value.strftime("%Y-%m-%d")
    raw = str(value).strip()
    if len(raw) >= 10 and raw[4] == "-" and raw[7] == "-":
        return raw[:10]
    return raw or None


def _fetch_previous_morning_report_snapshot(report_date_str: str, unit: str):
    unit_norm = (unit or "").strip().upper()
    if not unit_norm:
        return None, None
    try:
        report_date_val = datetime.strptime(str(report_date_str), "%Y-%m-%d").date()
    except Exception:
        return None, None
    try:
        with _get_login_db_connection() as conn:
            _ensure_morning_report_tables(conn)
            cur = conn.cursor()
            cur.execute(
                """
                SELECT TOP 1 SnapshotDate
                FROM dbo.HID_Morning_Report_Header WITH (NOLOCK)
                WHERE Unit = ? AND SnapshotDate < ?
                ORDER BY SnapshotDate DESC
                """,
                (unit_norm, report_date_val.strftime("%Y-%m-%d")),
            )
            row = cur.fetchone()
            prev_date = _normalize_snapshot_date(row[0] if row else None)
    except Exception:
        prev_date = None
    if not prev_date:
        return None, None
    prev_payload = _fetch_morning_report_snapshot(prev_date, unit_norm)
    return prev_payload, prev_date


def _fetch_last_non_empty_morning_staff_non_medical(report_date_str: str, unit: str) -> dict:
    unit_norm = (unit or "").strip().upper()
    if not unit_norm:
        return {}
    try:
        report_date_val = datetime.strptime(str(report_date_str), "%Y-%m-%d").date()
    except Exception:
        return {}

    staff_date = None
    non_med_date = None
    try:
        with _get_login_db_connection() as conn:
            _ensure_morning_report_tables(conn)
            cur = conn.cursor()

            cur.execute(
                """
                SELECT TOP 1 SnapshotDate
                FROM dbo.HID_Morning_Report_Staff WITH (NOLOCK)
                WHERE Unit = ? AND SnapshotDate < ?
                  AND (
                    NULLIF(LTRIM(RTRIM(ISNULL(Department, ''))), '') IS NOT NULL
                    OR NULLIF(LTRIM(RTRIM(ISNULL(DoctorCount, ''))), '') IS NOT NULL
                    OR NULLIF(LTRIM(RTRIM(ISNULL(NursingCount, ''))), '') IS NOT NULL
                    OR NULLIF(LTRIM(RTRIM(ISNULL(AayaCount, ''))), '') IS NOT NULL
                    OR NULLIF(LTRIM(RTRIM(ISNULL(WardBoyCount, ''))), '') IS NOT NULL
                    OR NULLIF(LTRIM(RTRIM(ISNULL(HouseKeepingCount, ''))), '') IS NOT NULL
                  )
                ORDER BY SnapshotDate DESC
                """,
                (unit_norm, report_date_val.strftime("%Y-%m-%d")),
            )
            staff_row = cur.fetchone()
            staff_date = _normalize_snapshot_date(staff_row[0] if staff_row else None)

            cur.execute(
                """
                SELECT TOP 1 SnapshotDate
                FROM dbo.HID_Morning_Report_NonMedical WITH (NOLOCK)
                WHERE Unit = ? AND SnapshotDate < ?
                  AND (
                    NULLIF(LTRIM(RTRIM(ISNULL(LeftLabel, ''))), '') IS NOT NULL
                    OR NULLIF(LTRIM(RTRIM(ISNULL(LeftCount, ''))), '') IS NOT NULL
                    OR NULLIF(LTRIM(RTRIM(ISNULL(RightLabel, ''))), '') IS NOT NULL
                    OR NULLIF(LTRIM(RTRIM(ISNULL(RightCount, ''))), '') IS NOT NULL
                  )
                ORDER BY SnapshotDate DESC
                """,
                (unit_norm, report_date_val.strftime("%Y-%m-%d")),
            )
            non_med_row = cur.fetchone()
            non_med_date = _normalize_snapshot_date(non_med_row[0] if non_med_row else None)
    except Exception:
        return {}

    staff_keys = ("department", "doctor", "nursing", "aaya", "ward_boy", "housekeeping")
    non_med_keys = ("left_label", "left_count", "right_label", "right_count")
    out = {}

    if staff_date:
        staff_payload = _fetch_morning_report_snapshot(staff_date, unit_norm)
        if staff_payload and _rows_have_any_value(staff_payload.get("staff_rows"), staff_keys):
            out["staff_rows"] = staff_payload.get("staff_rows") or []
            out["staff_source_date"] = staff_payload.get("report_date") or staff_date
            out["staff_source_time"] = staff_payload.get("snapshot_time") or ""

    if non_med_date:
        non_med_payload = _fetch_morning_report_snapshot(non_med_date, unit_norm)
        if non_med_payload and _rows_have_any_value(non_med_payload.get("non_medical_rows"), non_med_keys):
            out["non_medical_rows"] = non_med_payload.get("non_medical_rows") or []
            out["non_med_source_date"] = non_med_payload.get("report_date") or non_med_date
            out["non_med_source_time"] = non_med_payload.get("snapshot_time") or ""

    return out


def _apply_morning_staff_non_med_prefill(payload: dict | None, report_date_str: str, unit: str) -> dict | None:
    if not payload:
        return payload
    out = dict(payload)
    staff_keys = ("department", "doctor", "nursing", "aaya", "ward_boy", "housekeeping")
    non_med_keys = ("left_label", "left_count", "right_label", "right_count")
    needs_staff = not _rows_have_any_value(out.get("staff_rows"), staff_keys)
    needs_non_med = not _rows_have_any_value(out.get("non_medical_rows"), non_med_keys)
    if not needs_staff and not needs_non_med:
        return out

    carry = _fetch_last_non_empty_morning_staff_non_medical(report_date_str, unit)
    copied_sources = []

    if needs_staff and carry.get("staff_rows"):
        out["staff_rows"] = carry.get("staff_rows") or []
        out["prefill_staff_from_snapshot"] = True
        copied_sources.append((
            str(carry.get("staff_source_date") or "").strip(),
            str(carry.get("staff_source_time") or "").strip(),
        ))

    if needs_non_med and carry.get("non_medical_rows"):
        out["non_medical_rows"] = carry.get("non_medical_rows") or []
        out["prefill_non_medical_from_snapshot"] = True
        copied_sources.append((
            str(carry.get("non_med_source_date") or "").strip(),
            str(carry.get("non_med_source_time") or "").strip(),
        ))

    if copied_sources:
        copied_sources = [item for item in copied_sources if item[0]]
        if copied_sources:
            best_date, best_time = max(copied_sources, key=lambda item: item[0])
            out["prefill_snapshot_date"] = best_date
            out["prefill_snapshot_time"] = best_time
    return out


def _fetch_morning_report_header_snapshot_time(date_str: str, unit: str):
    unit_norm = (unit or "").strip().upper()
    if not unit_norm:
        return None
    try:
        with _get_login_db_connection() as conn:
            _ensure_morning_report_tables(conn)
            cur = conn.cursor()
            cur.execute(
                """
                SELECT SnapshotTime
                FROM dbo.HID_Morning_Report_Header WITH (NOLOCK)
                WHERE SnapshotDate = ? AND Unit = ?
                """,
                (date_str, unit_norm),
            )
            row = cur.fetchone()
            return row[0] if row else None
    except Exception:
        return None


def _coerce_local_dt(value):
    if not value:
        return None
    if isinstance(value, datetime):
        dt_val = value
    elif isinstance(value, date):
        dt_val = datetime.combine(value, datetime.min.time())
    else:
        raw = str(value).strip()
        dt_val = None
        for fmt in ("%Y-%m-%d %H:%M:%S", "%Y-%m-%d %H:%M"):
            try:
                dt_val = datetime.strptime(raw, fmt)
                break
            except Exception:
                dt_val = None
        if dt_val is None:
            try:
                dt_val = datetime.fromisoformat(raw.replace("Z", ""))
            except Exception:
                dt_val = None
    if not dt_val:
        return None
    if dt_val.tzinfo is None:
        return dt_val.replace(tzinfo=LOCAL_TZ)
    return dt_val.astimezone(LOCAL_TZ)


def _mod_report_edit_lock_info(unit: str, report_date: str, report_kind: str = "morning") -> dict:
    lock_date = (report_date or "").strip()
    kind_norm = (report_kind or "morning").strip().lower()
    if kind_norm == "night":
        try:
            parsed = datetime.strptime(lock_date, "%Y-%m-%d").date()
            lock_date = (parsed + timedelta(days=1)).strftime("%Y-%m-%d")
        except Exception:
            lock_date = (report_date or "").strip()

    snap_time = _fetch_morning_report_header_snapshot_time(lock_date, unit)
    snap_dt = _coerce_local_dt(snap_time)
    if not snap_dt:
        return {
            "locked": False,
            "snapshot_time": None,
            "lock_at": None,
            "lock_basis_date": lock_date,
        }
    lock_dt = snap_dt + timedelta(hours=6)
    now = datetime.now(tz=LOCAL_TZ)
    return {
        "locked": now >= lock_dt,
        "snapshot_time": snap_dt.strftime("%Y-%m-%d %H:%M:%S"),
        "lock_at": lock_dt.strftime("%Y-%m-%d %H:%M:%S"),
        "lock_basis_date": lock_date,
    }


def _attach_mod_report_lock(payload: dict, unit: str, report_date: str, is_it: bool, report_kind: str = "morning") -> dict:
    if not payload:
        return payload
    info = _mod_report_edit_lock_info(unit, report_date, report_kind=report_kind)
    locked = bool(info.get("locked")) and not is_it
    lock_at = info.get("lock_at") or ""
    snap_time = info.get("snapshot_time") or ""
    lock_basis_date = info.get("lock_basis_date") or report_date
    out = dict(payload)
    out["edit_locked"] = locked
    out["edit_lock_at"] = lock_at
    out["edit_snapshot_time"] = snap_time
    out["edit_lock_basis_date"] = lock_basis_date
    if locked:
        out["edit_lock_message"] = (
            f"Editing locked at {lock_at} (6 hours after morning snapshot)."
            if lock_at
            else "Editing locked (6 hours after morning snapshot)."
        )
    else:
        out["edit_lock_message"] = ""
    return out

def _build_morning_report_payload(unit: str, report_date: date | str, source: str = "live",
                                  mod_name: str | None = None,
                                  report_time: str | None = None,
                                  snapshot_time: str | None = None):
    unit_norm = (unit or "").strip().upper()
    if not unit_norm:
        return None
    if isinstance(report_date, date):
        report_date_str = report_date.strftime("%Y-%m-%d")
        report_date_val = report_date
    else:
        try:
            report_date_val = datetime.strptime(str(report_date), "%Y-%m-%d").date()
        except Exception:
            report_date_val = datetime.now(tz=LOCAL_TZ).date()
        report_date_str = report_date_val.strftime("%Y-%m-%d")

    now = datetime.now(tz=LOCAL_TZ)
    report_time = report_time or now.strftime("%I:%M %p").lstrip("0") or now.strftime("%I:%M %p")
    prev_date = report_date_val - timedelta(days=1)
    prev_date_str = prev_date.strftime("%Y-%m-%d")

    start_prev = datetime.combine(prev_date, datetime.min.time())
    start_today = datetime.combine(report_date_val, datetime.min.time())
    end_night = start_today + timedelta(hours=8)

    adm_disc = _fetch_night_report_adm_disc(unit_norm, prev_date_str, MORNING_REPORT_CARDIAC_DOC_IDS)
    total_adm = int(adm_disc.get("total", {}).get("admission", 0))
    total_dis = int(adm_disc.get("total", {}).get("discharge", 0))
    cardiac_adm = int(adm_disc.get("cardiac", {}).get("admission", 0))
    cardiac_dis = int(adm_disc.get("cardiac", {}).get("discharge", 0))
    asarfi_adm = max(0, total_adm - cardiac_adm)
    asarfi_dis = max(0, total_dis - cardiac_dis)

    total_night_adm = _fetch_unit_ipd_admissions_range(unit_norm, start_today, end_night)
    cardiac_night_adm = _fetch_unit_ipd_admissions_range(unit_norm, start_today, end_night, MORNING_REPORT_CARDIAC_DOC_IDS)
    asarfi_night_adm = max(0, int(total_night_adm) - int(cardiac_night_adm))

    total_occ = _fetch_unit_ipd_active(unit_norm)
    cardiac_occ = _fetch_unit_ipd_active(unit_norm, MORNING_REPORT_CARDIAC_DOC_IDS)
    asarfi_occ = max(0, int(total_occ) - int(cardiac_occ))

    fallback_opd = _fetch_unit_opd_by_doc(unit_norm, prev_date_str, MORNING_REPORT_CARDIAC_DOC_IDS)
    total_opd = int(fallback_opd.get("total", 0))
    cardiac_opd = int(fallback_opd.get("cardiac", 0))
    total_counts, cardiac_counts = _fetch_opd_counts_from_volume([unit_norm], prev_date_str, prev_date_str, MORNING_REPORT_CARDIAC_DOC_IDS)
    if total_counts:
        total_opd = int(total_counts.get(unit_norm, total_opd))
    if cardiac_counts and unit_norm in cardiac_counts:
        cardiac_opd = int(cardiac_counts.get(unit_norm, cardiac_opd))
    asarfi_opd = max(0, total_opd - cardiac_opd)

    death_counts = None
    if unit_norm == "AHL":
        death_counts = _fetch_morning_death_counts_from_discharge(
            unit_norm,
            prev_date_str,
            MORNING_REPORT_CARDIAC_DOC_IDS,
            MORNING_REPORT_CARDIAC_SUBDEPT_KEYWORDS,
        )

    summary_rows = [
        {
            "sl": 1,
            "label": "Discharge Previous Day",
            "asarfi": asarfi_dis,
            "cardiac": cardiac_dis,
            "total": total_dis,
        },
        {
            "sl": 2,
            "label": "Admission Previous Day Upto 00:00 Hrs Night",
            "asarfi": asarfi_adm,
            "cardiac": cardiac_adm,
            "total": total_adm,
        },
        {
            "sl": 3,
            "label": "Night Admission from 00:00 Night to 08:00 AM Today",
            "asarfi": int(asarfi_night_adm),
            "cardiac": int(cardiac_night_adm),
            "total": int(total_night_adm),
        },
        {
            "sl": 4,
            "label": "Occupancy @ 08:00AM Today",
            "asarfi": int(asarfi_occ),
            "cardiac": int(cardiac_occ),
            "total": int(total_occ),
            "emphasis": True,
        },
        {
            "sl": 5,
            "label": "OPD Count Previous Day Upto 00:00 Hours",
            "asarfi": int(asarfi_opd),
            "cardiac": int(cardiac_opd),
            "total": int(total_opd),
        },
        {
            "sl": 6,
            "label": MORNING_REPORT_LAMA_LABEL,
            "asarfi": None,
            "cardiac": None,
            "total": None,
            "manual": True,
        },
    ]

    investigations = _build_investigation_rows(
        unit_norm,
        prev_date_str,
        MORNING_REPORT_CARDIAC_SUBDEPT_KEYWORDS,
        MORNING_REPORT_CARDIAC_DOC_IDS
    )

    summary_rows = _ensure_morning_death_summary_row(unit_norm, report_date_val, summary_rows, death_counts=death_counts)
    summary_rows = _collapse_morning_counts(unit_norm, summary_rows)
    investigations = _collapse_morning_counts(unit_norm, investigations)

    key_procedures = [
        {"sl": idx + 1, "label": label, "count": None}
        for idx, label in enumerate(MORNING_REPORT_KEY_PROCEDURES)
    ]

    df_volume_range = _get_or_fetch_volume_details([unit_norm], prev_date_str, report_date_str)
    if df_volume_range is None or df_volume_range.empty:
        df_volume_range = data_fetch.fetch_volume_raw([unit_norm], prev_date_str, report_date_str)
    admissions = _build_morning_admissions_table(df_volume_range, [unit_norm], start_prev, start_today, start_today, end_night)
    admissions_rows = [
        {"sl": idx + 1, **row}
        for idx, row in enumerate(admissions)
    ]

    doctorwise_rows = _build_morning_doctorwise_ipd_opd(unit_norm, prev_date_str, df_override=df_volume_range)
    occupancy_rows = _fetch_morning_occupancy_8am(unit_norm, report_date_str)
    doctor_night_visits = _build_morning_doctor_night_visit(unit_norm, prev_date_str, report_date_str, df_override=df_volume_range)
    staff_rows = _default_staff_rows()
    non_medical_rows = _default_non_medical_rows()
    referral_rows = _default_referral_rows()

    return {
        "unit": unit_norm,
        "report_date": report_date_str,
        "report_time": report_time,
        "mod_name": mod_name or "",
        "summary_rows": summary_rows,
        "investigations": investigations,
        "key_procedures": key_procedures,
        "admissions": admissions_rows,
        "doctorwise_rows": doctorwise_rows,
        "occupancy_rows": occupancy_rows,
        "doctor_night_visits": doctor_night_visits,
        "staff_rows": staff_rows,
        "non_medical_rows": non_medical_rows,
        "referral_rows": referral_rows,
        "source": source,
        "snapshot_time": snapshot_time,
    }

def _build_morning_report_excel(payload: dict, exported_by: str | None = None) -> bytes:
    if not payload:
        return b""
    exported_by = exported_by or "System"
    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    report_date = payload.get("report_date") or "-"
    report_time = payload.get("report_time") or "-"
    mod_name = payload.get("mod_name") or "-"
    unit_norm = (payload.get("unit") or "").strip().upper()
    segmented = unit_norm == "AHL"
    unit_label = unit_norm or "UNIT"

    summary_rows = _ensure_morning_death_summary_row(unit_norm, report_date, payload.get("summary_rows") or [])
    investigations = payload.get("investigations") or []
    key_procedures = payload.get("key_procedures") or []
    admissions = payload.get("admissions") or []
    doctorwise_rows = payload.get("doctorwise_rows") or []
    occupancy_rows = payload.get("occupancy_rows") or []
    doctor_night_visits = payload.get("doctor_night_visits") or []
    staff_rows = _filter_staff_rows(payload.get("staff_rows") or [])
    non_medical_rows = payload.get("non_medical_rows") or []
    referral_rows = payload.get("referral_rows") or []
    summary_rows = _collapse_morning_counts(unit_norm, summary_rows)
    investigations = _collapse_morning_counts(unit_norm, investigations)

    buffer = io.BytesIO()
    with pd.ExcelWriter(buffer, engine="xlsxwriter") as writer:
        wb = writer.book
        ws = wb.add_worksheet("Morning Report")
        writer.sheets["Morning Report"] = ws

        title_fmt = wb.add_format({
            "bold": True, "font_size": 16, "align": "center", "valign": "vcenter",
            "bg_color": "#9dc3e6", "border": 1
        })
        label_fmt = wb.add_format({
            "bold": True, "align": "left", "valign": "vcenter",
            "bg_color": "#fde2e2", "border": 1
        })
        value_fmt = wb.add_format({
            "bold": True, "align": "center", "valign": "vcenter",
            "bg_color": "#fde2e2", "border": 1
        })
        header_fmt = wb.add_format({
            "bold": True, "align": "center", "valign": "vcenter",
            "bg_color": "#f4b183", "border": 1
        })
        section_fmt = wb.add_format({
            "bold": True, "align": "center", "valign": "vcenter",
            "bg_color": "#b7dee8", "border": 1
        })
        data_fmt = wb.add_format({
            "align": "center", "valign": "vcenter",
            "bg_color": "#ffffff", "border": 1
        })
        left_fmt = wb.add_format({
            "align": "left", "valign": "vcenter",
            "bg_color": "#ffffff", "border": 1
        })
        total_fmt = wb.add_format({
            "bold": True, "align": "center", "valign": "vcenter",
            "bg_color": "#d9d9d9", "border": 1
        })
        total_left_fmt = wb.add_format({
            "bold": True, "align": "left", "valign": "vcenter",
            "bg_color": "#d9d9d9", "border": 1
        })
        meta_fmt = wb.add_format({
            "font_size": 9, "align": "center", "valign": "vcenter",
            "bg_color": "#f1f5f9", "border": 1
        })
        alt_title_fmt = wb.add_format({
            "bold": True, "font_size": 14, "align": "center", "valign": "vcenter",
            "bg_color": "#9dc3e6", "border": 1
        })
        alt_section_fmt = wb.add_format({
            "bold": True, "align": "center", "valign": "vcenter",
            "bg_color": "#d9c2e9", "border": 1
        })
        alt_header_fmt = wb.add_format({
            "bold": True, "align": "center", "valign": "vcenter",
            "bg_color": "#ead1ec", "border": 1
        })

        left_start_col = 0
        if segmented:
            left_end_col = 4
            gap_col = 5
            right_start_col = 6
        else:
            left_end_col = 3
            gap_col = 4
            right_start_col = 5
        right_end_col = right_start_col + 4

        ws.merge_range(0, left_start_col, 0, right_end_col, "Night Shift MOD Daily Report", title_fmt)

        ws.write(1, left_start_col, "Date:", label_fmt)
        ws.write(1, left_start_col + 1, report_date, value_fmt)
        ws.write(1, left_start_col + 2, "Time:", label_fmt)
        ws.write(1, left_start_col + 3, report_time, value_fmt)
        if segmented:
            ws.write(1, left_start_col + 4, "", value_fmt)

        ws.write(1, right_start_col, "MOD Name", label_fmt)
        ws.merge_range(1, right_start_col + 1, 1, right_end_col, mod_name, value_fmt)

        ws.write(2, left_start_col, f"Exported By: {exported_by}", meta_fmt)
        ws.merge_range(2, left_start_col + 1, 2, right_end_col, f"Exported At: {exported_at}", meta_fmt)

        row = 4
        ws.write(row, left_start_col, "Sl. No.", header_fmt)
        ws.write(row, left_start_col + 1, "Particular", header_fmt)
        if segmented:
            ws.write(row, left_start_col + 2, "Asarfi", header_fmt)
            ws.write(row, left_start_col + 3, "Cardiac", header_fmt)
            ws.write(row, left_start_col + 4, "Total", header_fmt)
        else:
            ws.write(row, left_start_col + 2, unit_label, header_fmt)
            ws.write(row, left_start_col + 3, "Total", header_fmt)
        row += 1

        for item in summary_rows:
            ws.write(row, left_start_col, item.get("sl") or "", data_fmt)
            ws.write(row, left_start_col + 1, item.get("label") or "", left_fmt)
            ws.write(row, left_start_col + 2, "" if item.get("asarfi") is None else item.get("asarfi"), data_fmt)
            if segmented:
                ws.write(row, left_start_col + 3, "" if item.get("cardiac") is None else item.get("cardiac"), data_fmt)
                ws.write(row, left_start_col + 4, "" if item.get("total") is None else item.get("total"), data_fmt)
            else:
                ws.write(row, left_start_col + 3, "" if item.get("total") is None else item.get("total"), data_fmt)
            row += 1

        row += 1
        ws.merge_range(row, left_start_col, row, left_end_col, "Investigation/Radiology", section_fmt)
        row += 1
        ws.write(row, left_start_col, "Sl. No.", header_fmt)
        ws.write(row, left_start_col + 1, "Particular", header_fmt)
        if segmented:
            ws.write(row, left_start_col + 2, "Asarfi", header_fmt)
            ws.write(row, left_start_col + 3, "Cardiac", header_fmt)
            ws.write(row, left_start_col + 4, "Total", header_fmt)
        else:
            ws.write(row, left_start_col + 2, unit_label, header_fmt)
            ws.write(row, left_start_col + 3, "Total", header_fmt)
        row += 1

        for item in investigations:
            label = str(item.get("label") or "")
            is_total = label.strip().upper() == "TOTAL"
            fmt_left = total_left_fmt if is_total else left_fmt
            fmt_cell = total_fmt if is_total else data_fmt
            ws.write(row, left_start_col, item.get("sl") or "", fmt_cell)
            ws.write(row, left_start_col + 1, label, fmt_left)
            ws.write(row, left_start_col + 2, "" if item.get("asarfi") is None else item.get("asarfi"), fmt_cell)
            if segmented:
                ws.write(row, left_start_col + 3, "" if item.get("cardiac") is None else item.get("cardiac"), fmt_cell)
                ws.write(row, left_start_col + 4, "" if item.get("total") is None else item.get("total"), fmt_cell)
            else:
                ws.write(row, left_start_col + 3, "" if item.get("total") is None else item.get("total"), fmt_cell)
            row += 1

        row += 1
        if segmented:
            ws.merge_range(row, left_start_col, row, left_start_col + 2, "Key Procedure", section_fmt)
            ws.write(row, left_start_col + 3, "", section_fmt)
            ws.write(row, left_start_col + 4, "", section_fmt)
        else:
            ws.merge_range(row, left_start_col, row, left_end_col, "Key Procedure", section_fmt)
        row += 1
        ws.write(row, left_start_col, "Sl. No.", header_fmt)
        ws.write(row, left_start_col + 1, "Particular", header_fmt)
        ws.write(row, left_start_col + 2, "Count", header_fmt)
        ws.write(row, left_start_col + 3, "", header_fmt)
        if segmented:
            ws.write(row, left_start_col + 4, "", header_fmt)
        row += 1

        total_proc = 0
        for item in key_procedures:
            count_val = item.get("count")
            if count_val is not None:
                try:
                    total_proc += int(count_val)
                except Exception:
                    pass
            ws.write(row, left_start_col, item.get("sl") or "", data_fmt)
            ws.write(row, left_start_col + 1, item.get("label") or "", left_fmt)
            ws.write(row, left_start_col + 2, "" if count_val is None else count_val, data_fmt)
            ws.write(row, left_start_col + 3, "", data_fmt)
            if segmented:
                ws.write(row, left_start_col + 4, "", data_fmt)
            row += 1

        ws.write(row, left_start_col, "", total_fmt)
        ws.write(row, left_start_col + 1, "Total", total_left_fmt)
        ws.write(row, left_start_col + 2, total_proc if total_proc else "", total_fmt)
        ws.write(row, left_start_col + 3, "", total_fmt)
        if segmented:
            ws.write(row, left_start_col + 4, "", total_fmt)

        right_row = 4
        ws.merge_range(right_row, right_start_col, right_row, right_end_col, "Admission", section_fmt)
        right_row += 1
        ws.write(right_row, right_start_col, "Sl. No.", header_fmt)
        ws.write(right_row, right_start_col + 1, "Dept", header_fmt)
        ws.write(right_row, right_start_col + 2, "Doctor", header_fmt)
        ws.write(right_row, right_start_col + 3, "Previous Day Count", header_fmt)
        ws.write(right_row, right_start_col + 4, "Night Admission Count", header_fmt)
        right_row += 1

        total_prev = 0
        total_night = 0
        for item in admissions:
            prev_val = item.get("prev_count") or 0
            night_val = item.get("night_count") or 0
            try:
                total_prev += int(prev_val)
            except Exception:
                pass
            try:
                total_night += int(night_val)
            except Exception:
                pass
            ws.write(right_row, right_start_col, item.get("sl") or "", data_fmt)
            ws.write(right_row, right_start_col + 1, item.get("dept") or "", left_fmt)
            ws.write(right_row, right_start_col + 2, item.get("doctor") or "", left_fmt)
            ws.write(right_row, right_start_col + 3, "" if prev_val is None else prev_val, data_fmt)
            ws.write(right_row, right_start_col + 4, "" if night_val is None else night_val, data_fmt)
            right_row += 1

        ws.write(right_row, right_start_col, "", total_fmt)
        ws.write(right_row, right_start_col + 1, "TOTAL", total_left_fmt)
        ws.write(right_row, right_start_col + 2, "", total_fmt)
        ws.write(right_row, right_start_col + 3, total_prev if total_prev else "", total_fmt)
        ws.write(right_row, right_start_col + 4, total_night if total_night else "", total_fmt)

        ws.set_column(left_start_col, left_start_col, 8)
        ws.set_column(left_start_col + 1, left_start_col + 1, 34)
        if segmented:
            ws.set_column(left_start_col + 2, left_start_col + 4, 12)
        else:
            ws.set_column(left_start_col + 2, left_end_col, 12)
        ws.set_column(gap_col, gap_col, 2)
        ws.set_column(right_start_col, right_start_col, 8)
        ws.set_column(right_start_col + 1, right_start_col + 1, 18)
        ws.set_column(right_start_col + 2, right_start_col + 2, 24)
        ws.set_column(right_start_col + 3, right_start_col + 4, 16)

        # --- Extra Sections (Sheet 2) ---
        ws_extra1 = wb.add_worksheet("Morning Report Extra 1")
        ws_extra1.merge_range(0, 0, 0, 7, "Night Shift MOD Daily Report", alt_title_fmt)

        dw_row = 2
        ws_extra1.merge_range(dw_row, 0, dw_row, 3, "Doctor wise IPD&OPD Details (00:00 to 23:59)", alt_section_fmt)
        dw_row += 1
        ws_extra1.write(dw_row, 0, "SL", alt_header_fmt)
        ws_extra1.write(dw_row, 1, "Department", alt_header_fmt)
        ws_extra1.write(dw_row, 2, "OPD", alt_header_fmt)
        ws_extra1.write(dw_row, 3, "IPD", alt_header_fmt)
        dw_row += 1
        for item in doctorwise_rows:
            dept = str(item.get("department") or "")
            is_total = dept.strip().upper() == "TOTAL"
            fmt_left = total_left_fmt if is_total else left_fmt
            fmt_cell = total_fmt if is_total else data_fmt
            ws_extra1.write(dw_row, 0, item.get("sl") or "", fmt_cell)
            ws_extra1.write(dw_row, 1, dept, fmt_left)
            ws_extra1.write(dw_row, 2, "" if item.get("opd") is None else item.get("opd"), fmt_cell)
            ws_extra1.write(dw_row, 3, "" if item.get("ipd") is None else item.get("ipd"), fmt_cell)
            dw_row += 1
        if not doctorwise_rows:
            ws_extra1.write(dw_row, 1, "No data", left_fmt)
            dw_row += 1

        occ_row = 2
        occ_start_col = 5
        ws_extra1.merge_range(occ_row, occ_start_col, occ_row, occ_start_col + 2, "Occupancy details till 08:00AM", alt_section_fmt)
        occ_row += 1
        ws_extra1.write(occ_row, occ_start_col, "Sl. No.", alt_header_fmt)
        ws_extra1.write(occ_row, occ_start_col + 1, "Ward", alt_header_fmt)
        ws_extra1.write(occ_row, occ_start_col + 2, "Count", alt_header_fmt)
        occ_row += 1
        for item in occupancy_rows:
            ward = str(item.get("ward") or "")
            is_total = ward.strip().upper() == "TOTAL"
            fmt_left = total_left_fmt if is_total else left_fmt
            fmt_cell = total_fmt if is_total else data_fmt
            ws_extra1.write(occ_row, occ_start_col, item.get("sl") or "", fmt_cell)
            ws_extra1.write(occ_row, occ_start_col + 1, ward, fmt_left)
            ws_extra1.write(occ_row, occ_start_col + 2, "" if item.get("patient_count") is None else item.get("patient_count"), fmt_cell)
            occ_row += 1
        if not occupancy_rows:
            ws_extra1.write(occ_row, occ_start_col + 1, "No data", left_fmt)
            occ_row += 1

        night_row = max(dw_row, occ_row) + 2
        ws_extra1.merge_range(night_row, 0, night_row, 4, "DOCTOR NIGHT VISIT", alt_section_fmt)
        night_row += 1
        ws_extra1.write(night_row, 0, "Sl. No.", alt_header_fmt)
        ws_extra1.write(night_row, 1, "Patient Name", alt_header_fmt)
        ws_extra1.write(night_row, 2, "Admission Time", alt_header_fmt)
        ws_extra1.write(night_row, 3, "Consultant Name", alt_header_fmt)
        ws_extra1.write(night_row, 4, "Visiting", alt_header_fmt)
        night_row += 1
        for item in doctor_night_visits:
            ws_extra1.write(night_row, 0, item.get("sl") or "", data_fmt)
            ws_extra1.write(night_row, 1, item.get("patient_name") or "", left_fmt)
            ws_extra1.write(night_row, 2, item.get("admission_time") or "", data_fmt)
            ws_extra1.write(night_row, 3, item.get("consultant") or "", left_fmt)
            ws_extra1.write(night_row, 4, item.get("visiting") or "", data_fmt)
            night_row += 1
        if not doctor_night_visits:
            ws_extra1.write(night_row, 1, "No data", left_fmt)

        ws_extra1.set_column(0, 0, 6)
        ws_extra1.set_column(1, 1, 28)
        ws_extra1.set_column(2, 3, 14)
        ws_extra1.set_column(4, 4, 16)
        ws_extra1.set_column(5, 5, 6)
        ws_extra1.set_column(6, 6, 24)
        ws_extra1.set_column(7, 7, 10)

        # --- Extra Sections (Sheet 3) ---
        ws_extra2 = wb.add_worksheet("Morning Report Extra 2")
        ws_extra2.merge_range(0, 0, 0, 6, "Department wise Count of Staff at Night Shift", alt_title_fmt)
        staff_row = 2
        ws_extra2.write(staff_row, 0, "Sl. No.", alt_header_fmt)
        ws_extra2.write(staff_row, 1, "Department", alt_header_fmt)
        ws_extra2.write(staff_row, 2, "Doctor", alt_header_fmt)
        ws_extra2.write(staff_row, 3, "Nursing", alt_header_fmt)
        ws_extra2.write(staff_row, 4, "Aaya", alt_header_fmt)
        ws_extra2.write(staff_row, 5, "Ward Boy/GDA", alt_header_fmt)
        ws_extra2.write(staff_row, 6, "HouseKeeping", alt_header_fmt)
        staff_row += 1
        staff_total_doctor = _normalize_total_value(_staff_count_total(staff_rows, "doctor"))
        staff_total_nursing = _normalize_total_value(_staff_count_total(staff_rows, "nursing"))
        staff_total_aaya = _normalize_total_value(_staff_count_total(staff_rows, "aaya"))
        staff_total_ward_boy = _normalize_total_value(_staff_count_total(staff_rows, "ward_boy"))
        staff_total_housekeeping = _normalize_total_value(_staff_count_total(staff_rows, "housekeeping"))
        if staff_rows:
            for item in staff_rows:
                dept = str(item.get("department") or "")
                ws_extra2.write(staff_row, 0, item.get("sl") or "", data_fmt)
                ws_extra2.write(staff_row, 1, dept, left_fmt)
                ws_extra2.write(staff_row, 2, item.get("doctor") or "", data_fmt)
                ws_extra2.write(staff_row, 3, item.get("nursing") or "", data_fmt)
                ws_extra2.write(staff_row, 4, item.get("aaya") or "", data_fmt)
                ws_extra2.write(staff_row, 5, item.get("ward_boy") or "", data_fmt)
                ws_extra2.write(staff_row, 6, item.get("housekeeping") or "", data_fmt)
                staff_row += 1
            ws_extra2.write(staff_row, 1, "Total", total_left_fmt)
            ws_extra2.write(staff_row, 2, "" if staff_total_doctor is None else staff_total_doctor, data_fmt)
            ws_extra2.write(staff_row, 3, "" if staff_total_nursing is None else staff_total_nursing, data_fmt)
            ws_extra2.write(staff_row, 4, "" if staff_total_aaya is None else staff_total_aaya, data_fmt)
            ws_extra2.write(staff_row, 5, "" if staff_total_ward_boy is None else staff_total_ward_boy, data_fmt)
            ws_extra2.write(staff_row, 6, "" if staff_total_housekeeping is None else staff_total_housekeeping, data_fmt)
        else:
            ws_extra2.write(staff_row, 1, "No data", left_fmt)
            staff_row += 1

        staff_row += 2
        ws_extra2.merge_range(staff_row, 0, staff_row, 4, "Non Medical Staff", alt_section_fmt)
        staff_row += 1
        ws_extra2.write(staff_row, 0, "Sl", alt_header_fmt)
        ws_extra2.write(staff_row, 1, "Staff", alt_header_fmt)
        ws_extra2.write(staff_row, 2, "Count", alt_header_fmt)
        ws_extra2.write(staff_row, 3, "Staff", alt_header_fmt)
        ws_extra2.write(staff_row, 4, "Count", alt_header_fmt)
        staff_row += 1
        for item in non_medical_rows:
            ws_extra2.write(staff_row, 0, item.get("sl") or "", data_fmt)
            ws_extra2.write(staff_row, 1, item.get("left_label") or "", left_fmt)
            ws_extra2.write(staff_row, 2, item.get("left_count") or "", data_fmt)
            ws_extra2.write(staff_row, 3, item.get("right_label") or "", left_fmt)
            ws_extra2.write(staff_row, 4, item.get("right_count") or "", data_fmt)
            staff_row += 1
        ws_extra2.write(staff_row, 1, "Total", total_left_fmt)
        ws_extra2.write(staff_row, 3, "Total", total_left_fmt)

        staff_row += 2
        ws_extra2.merge_range(staff_row, 0, staff_row, 4, "Referral/Refusal/Brought Death Information (12:00 PM to 11:59 PM)", alt_section_fmt)
        staff_row += 1
        ws_extra2.write(staff_row, 0, "Sl", alt_header_fmt)
        ws_extra2.write(staff_row, 1, "Patient Name", alt_header_fmt)
        ws_extra2.write(staff_row, 2, "Visit Time", alt_header_fmt)
        ws_extra2.write(staff_row, 3, "Consultant Name", alt_header_fmt)
        ws_extra2.write(staff_row, 4, "Reason for Refering", alt_header_fmt)
        staff_row += 1
        for item in referral_rows:
            ws_extra2.write(staff_row, 0, item.get("sl") or "", data_fmt)
            ws_extra2.write(staff_row, 1, item.get("patient_name") or "", left_fmt)
            ws_extra2.write(staff_row, 2, item.get("visit_time") or "", data_fmt)
            ws_extra2.write(staff_row, 3, item.get("consultant") or "", left_fmt)
            ws_extra2.write(staff_row, 4, item.get("reason") or "", left_fmt)
            staff_row += 1

        ws_extra2.set_column(0, 0, 6)
        ws_extra2.set_column(1, 1, 30)
        ws_extra2.set_column(2, 2, 14)
        ws_extra2.set_column(3, 3, 26)
        ws_extra2.set_column(4, 4, 32)
        ws_extra2.set_column(5, 6, 16)

    buffer.seek(0)
    return buffer.getvalue()

def _build_morning_admissions_table(df_raw: pd.DataFrame, units: list[str],
                                    prev_start: datetime, prev_end: datetime,
                                    night_start: datetime, night_end: datetime):
    if df_raw is None or df_raw.empty:
        return []

    df = df_raw.copy()
    unit_col = _pick_df_column(df, ["Unit"])
    if unit_col and units:
        df = df[df[unit_col].astype(str).str.upper().isin(units)]
    vt_col = _pick_df_column(df, ["VisitTypeID", "VisitTypeId", "VisitType_ID", "Visit_Type_ID"])
    if vt_col:
        df = df[pd.to_numeric(df[vt_col], errors="coerce").fillna(0).astype(int) == 1]

    date_col = _pick_df_column(df, ["VisitDate", "Visit_Date", "AdmissionDate", "Admission_Date", "AdmitDate", "Admit_Date"])
    if not date_col:
        return []

    df["_VisitDt"] = pd.to_datetime(df[date_col], errors="coerce")
    df = df[df["_VisitDt"].notna()]
    if df.empty:
        return []

    dept_col = _pick_df_column(df, ["Dept_Name", "Dept", "Department", "DepartmentName", "DeptName"])
    doc_col = _pick_df_column(df, ["DoctorIncharge", "DoctorInCharge", "Consultant", "Doctor", "DoctorName", "Doctor_Name"])
    if not dept_col:
        df["DeptName"] = "Unknown"
        dept_col = "DeptName"
    if not doc_col:
        df["DoctorName"] = "Unknown"
        doc_col = "DoctorName"

    df[dept_col] = df[dept_col].fillna("Unknown").astype(str).str.strip()
    df[doc_col] = df[doc_col].fillna("Unknown").astype(str).str.strip()

    prev_df = df[(df["_VisitDt"] >= prev_start) & (df["_VisitDt"] < prev_end)]
    night_df = df[(df["_VisitDt"] >= night_start) & (df["_VisitDt"] < night_end)]

    prev_counts = prev_df.groupby([dept_col, doc_col]).size()
    night_counts = night_df.groupby([dept_col, doc_col]).size()

    keys = set(prev_counts.index).union(set(night_counts.index))
    rows = []
    for dept, doc in sorted(keys, key=lambda x: (str(x[0]).upper(), str(x[1]).upper())):
        prev_val = int(prev_counts.get((dept, doc), 0))
        night_val = int(night_counts.get((dept, doc), 0))
        if prev_val == 0 and night_val == 0:
            continue
        rows.append({
            "dept": dept,
            "doctor": doc,
            "prev_count": prev_val,
            "night_count": night_val,
        })
    return rows

def _ensure_pharmacy_stock_snapshot_table():
    """Create snapshot table for pharmacy current stock."""
    def _setup(conn):
        conn.execute("""
        CREATE TABLE IF NOT EXISTS pharmacy_stock_snapshot (
            snapshot_date TEXT NOT NULL,
            snapshot_time TEXT NOT NULL,
            unit TEXT NOT NULL,
            store_id INTEGER NOT NULL,
            store_name TEXT,
            item_id INTEGER,
            item_name TEXT,
            batch_id INTEGER,
            batch_name TEXT,
            expiry_date TEXT,
            rate REAL,
            mrp REAL,
            qty REAL,
            purchase_value REAL,
            sale_value REAL,
            generic_name TEXT,
            manufacturer_name TEXT,
            group_name TEXT,
            subgroup_name TEXT,
            PRIMARY KEY (snapshot_date, unit, store_id, item_id, batch_id)
        )
        """)
        try:
            cols = [row[1] for row in conn.execute("PRAGMA table_info(pharmacy_stock_snapshot)").fetchall()]
            if "subgroup_name" not in [c.lower() for c in cols]:
                conn.execute("ALTER TABLE pharmacy_stock_snapshot ADD COLUMN subgroup_name TEXT")
        except Exception:
            pass
        conn.execute("""
        CREATE INDEX IF NOT EXISTS idx_ph_stock_date
        ON pharmacy_stock_snapshot(snapshot_date)
        """)
        conn.execute("""
        CREATE INDEX IF NOT EXISTS idx_ph_stock_unit
        ON pharmacy_stock_snapshot(unit)
        """)
        conn.execute("""
        CREATE INDEX IF NOT EXISTS idx_ph_stock_store
        ON pharmacy_stock_snapshot(store_id)
        """)
    _with_local_db(_setup)

REVENUE_CACHE_TTL_SECS = int(os.getenv("REV_CACHE_TTL_SECS", str(6*3600)))  # default 6h



def _prune_revenue_cache(conn: sqlite3.Connection | None = None):
    """
    Hard-delete expired rows from revenue_cache based on ts + REVENUE_CACHE_TTL_SECS.
    Safe to call frequently.
    """
    try:
        cutoff = int(time.time()) - REVENUE_CACHE_TTL_SECS
        if conn is not None:
            conn.execute("DELETE FROM revenue_cache WHERE ts < ?", (cutoff,))
            return
        # standalone mode
        with _connect_local_db() as c:
            c.execute("DELETE FROM revenue_cache WHERE ts < ?", (cutoff,))
            c.commit()
    except Exception as e:
        print(f"[WARN] revenue cache prune failed: {e}")

