VOLUME_CACHE_TTL_SECS = int(os.getenv("VOLUME_CACHE_TTL_SECS", str(REVENUE_CACHE_TTL_SECS)))
VOLUME_MEM_CACHE = {}
VOLUME_MEM_LOCK = Lock()

# Schema ensure guards to avoid repeated DDL on read paths
MORNING_REPORT_SCHEMA_READY = False
MORNING_REPORT_AUDIT_SCHEMA_READY = False
MORNING_REPORT_SCHEMA_LOCK = Lock()
