# MOD report cache (short TTL to speed repeated loads)
MOD_REPORT_CACHE_TTL = int(getattr(config, "MOD_REPORT_CACHE_TTL", 30))
MOD_REPORT_CACHE: dict[str, dict[str, dict]] = {
    "night": {},
    "morning": {},
}

def _mod_report_cache_key(unit: str, date_str: str, mode: str) -> str:
    return f"{(unit or '').strip().upper()}|{(date_str or '').strip()}|{(mode or '').strip().lower()}"

def _mod_report_cache_get(kind: str, unit: str, date_str: str, mode: str):
    if MOD_REPORT_CACHE_TTL <= 0:
        return None
    bucket = MOD_REPORT_CACHE.get(kind, {})
    key = _mod_report_cache_key(unit, date_str, mode)
    item = bucket.get(key)
    if not item:
        return None
    if (time.time() - item.get("ts", 0)) > MOD_REPORT_CACHE_TTL:
        bucket.pop(key, None)
        return None
    payload = item.get("payload")
    try:
        return copy.deepcopy(payload)
    except Exception:
        return payload

def _mod_report_cache_set(kind: str, unit: str, date_str: str, mode: str, payload: dict):
    if MOD_REPORT_CACHE_TTL <= 0:
        return
    bucket = MOD_REPORT_CACHE.setdefault(kind, {})
    key = _mod_report_cache_key(unit, date_str, mode)
    try:
        bucket[key] = {"ts": time.time(), "payload": copy.deepcopy(payload)}
    except Exception:
        bucket[key] = {"ts": time.time(), "payload": payload}

def _mod_report_cache_clear(kind: str, unit: str | None = None, date_str: str | None = None):
    bucket = MOD_REPORT_CACHE.get(kind)
    if not bucket:
        return
    if not unit and not date_str:
        bucket.clear()
        return
    unit_norm = (unit or "").strip().upper()
    date_val = (date_str or "").strip()
    for key in list(bucket.keys()):
        if unit_norm and not key.startswith(unit_norm + "|"):
            continue
        if date_val and f"|{date_val}|" not in key:
            continue
        bucket.pop(key, None)

def _prune_volume_cache(conn: sqlite3.Connection | None = None):
    """
    Hard-delete expired rows from volume_cache based on ts + VOLUME_CACHE_TTL_SECS.
    Safe to call frequently.
    """
    try:
        cutoff = int(time.time()) - VOLUME_CACHE_TTL_SECS
        if conn is not None:
            # Use existing transaction; caller will handle commit
            conn.execute("DELETE FROM volume_cache WHERE ts < ?", (cutoff,))
            return

        # Standalone mode - we manage the connection and commit
        with _connect_local_db() as c:
            c.execute("DELETE FROM volume_cache WHERE ts < ?", (cutoff,))
            c.commit()
    except Exception as e:
        print(f"[WARN] volume cache prune failed: {e}")



def _ensure_volume_cache():
    os.makedirs(os.path.dirname(_abs_local_db_path()), exist_ok=True)
    def _setup(conn):
        conn.execute("""
        CREATE TABLE IF NOT EXISTS volume_cache (
            unit TEXT NOT NULL,
            from_date TEXT NOT NULL,
            to_date TEXT NOT NULL,
            json_data TEXT NOT NULL,
            ts INTEGER NOT NULL,
            PRIMARY KEY (unit, from_date, to_date)
        )
        """)
        _prune_volume_cache(conn)
    _with_local_db(_setup)
def _volume_mem_key(unit, from_date, to_date):
    return (unit.upper(), from_date, to_date)

def _volume_cache_put_async(unit, from_date, to_date, df: pd.DataFrame):
    if df is None or df.empty:
        return
    unit = (unit or "").strip().upper()
    payload = df.reset_index(drop=True)

    def _job():
        try:
            js = payload.to_json(orient="records")
            ts_now = int(time.time())
            with sqlite3.connect(_abs_local_db_path()) as c:
                c.execute(
                    """
                    INSERT OR REPLACE INTO volume_cache
                    (unit, from_date, to_date, json_data, ts)
                    VALUES (?, ?, ?, ?, ?)
                    """,
                    (unit, from_date, to_date, js, ts_now)
                )
                _prune_volume_cache(c)
                c.commit()
            with VOLUME_MEM_LOCK:
                VOLUME_MEM_CACHE[_volume_mem_key(unit, from_date, to_date)] = {
                    "ts": ts_now,
                    "df": payload.copy(deep=True)
                }
        except Exception as e:
            print(f"[WARN] volume cache write failed: {e}")

    Thread(target=_job, daemon=True).start()

def _volume_cache_evict(unit, from_date, to_date):
    unit = (unit or "").strip().upper()
    key = _volume_mem_key(unit, from_date, to_date)
    with VOLUME_MEM_LOCK:
        VOLUME_MEM_CACHE.pop(key, None)
    try:
        with sqlite3.connect(_abs_local_db_path()) as c:
            c.execute(
                "DELETE FROM volume_cache WHERE unit=? AND from_date=? AND to_date=?",
                (unit, from_date, to_date)
            )
            c.commit()
    except Exception:
        pass

