def _volume_cache_get(unit, from_date, to_date):
    unit = (unit or "").strip().upper()
    if not unit:
        return None
    key = _volume_mem_key(unit, from_date, to_date)
    now = int(time.time())
    with VOLUME_MEM_LOCK:
        entry = VOLUME_MEM_CACHE.get(key)
        if entry:
            if now - entry["ts"] <= VOLUME_CACHE_TTL_SECS:
                df_mem = entry["df"]
                if df_mem is not None and not df_mem.empty:
                    required_cols = {"Gender", "VisitTypeID", "Age"}
                    if required_cols.issubset(set(df_mem.columns)):
                        return df_mem.copy(deep=True)
            VOLUME_MEM_CACHE.pop(key, None)
    try:
        with sqlite3.connect(_abs_local_db_path()) as c:
            row = c.execute(
                """
                SELECT json_data, ts FROM volume_cache
                WHERE unit=? AND from_date=? AND to_date=?
                """,
                (unit, from_date, to_date)
            ).fetchone()
        if not row:
            return None
        js, ts_val = row
        if now - ts_val > VOLUME_CACHE_TTL_SECS:
            _volume_cache_evict(unit, from_date, to_date)
            return None
        df = pd.read_json(io.StringIO(js))
        if df is None or df.empty:
            _volume_cache_evict(unit, from_date, to_date)
            return None
        if "Unit" not in df.columns:
            df["Unit"] = unit
        else:
            df["Unit"] = df["Unit"].astype(str).str.strip().str.upper().replace("", unit)
        required_cols = {"Gender", "VisitTypeID", "Age"}
        if not required_cols.issubset(set(df.columns)):
            _volume_cache_evict(unit, from_date, to_date)
            return None
        with VOLUME_MEM_LOCK:
            VOLUME_MEM_CACHE[key] = {"ts": ts_val, "df": df.copy(deep=True)}
        return df
    except Exception as e:
        print(f"[WARN] volume cache read failed: {e}")
        return None

def _volume_units_normalized(units) -> list[str]:
    cleaned = []
    analytics = set(_analytics_units_upper())
    for u in (units or []):
        u = (u or "").strip().upper()
        if not u or u == "__ALL__":
            continue
        if analytics and u not in analytics:
            continue
        cleaned.append(u)
    return sorted(set(cleaned))

def _get_or_fetch_volume_details(units, from_date, to_date, force_live: bool = False):
    norm_units = _volume_units_normalized(units)
    if not norm_units:
        return pd.DataFrame()

    cacheable = not _is_today_range(from_date, to_date)
    frames = []
    template = None
    for unit in norm_units:
        df = None
        if cacheable and not force_live:
            df = _volume_cache_get(unit, from_date, to_date)
            if df is not None:
                print(f"Volume cache hit for {unit}")
        if df is None:
            df = get_volume_details([unit], from_date, to_date)
            if df is not None and cacheable and not force_live:
                if "Unit" not in df.columns:
                    df = df.copy()
                    df["Unit"] = unit
                _volume_cache_put_async(unit, from_date, to_date, df)
        if df is None:
            continue
        if "Unit" not in df.columns:
            df = df.copy()
            df["Unit"] = unit
        if template is None:
            template = df
        if not df.empty:
            frames.append(df)

    if frames:
        if len(frames) == 1:
            return frames[0].copy(deep=True)
        return pd.concat(frames, ignore_index=True, copy=False)

    return template.copy(deep=True) if template is not None else pd.DataFrame()


