def _build_volume_hcv_doctor_kpi_payload(df: pd.DataFrame) -> dict:
    if df is None or df.empty:
        return {"rows": [], "meta": {"total": 0, "unit_count": 0}}

    data = df.copy()
    if "Unit" in data.columns:
        data["Unit"] = data["Unit"].astype(str).str.strip().str.upper()
        unit_count = int(data["Unit"].replace({"": np.nan}).dropna().nunique())
    else:
        unit_count = 0

    rows = json.loads(data.to_json(orient="records"))
    return {
        "rows": rows,
        "meta": {
            "total": int(len(rows)),
            "unit_count": unit_count,
        },
    }


def _filter_volume_hcv_doctor_rows(df: pd.DataFrame, search: str | None) -> pd.DataFrame:
    if df is None or df.empty:
        return _empty_volume_hcv_doctor_df()

    query = str(search or "").strip().lower()
    if not query:
        return df.copy(deep=True)

    work = df.copy()
    search_cols = [
        "Unit",
        "RegNo",
        "PatientName",
        "CorpType",
        "Dept",
        "Consultant",
        "VisitDate",
        "VisitNo",
        "PackageId",
        "VisitId",
        "HCVId",
    ]
    for col in search_cols:
        if col not in work.columns:
            work[col] = ""

    search_key = (
        work[search_cols]
        .fillna("")
        .astype(str)
        .agg(" ".join, axis=1)
        .str.lower()
    )
    mask = search_key.str.contains(query, regex=False, na=False)
    return work.loc[mask].copy()

