def _capture_morning_report_snapshots(snapshot_date: str | None = None, snapshot_time: str | None = None, target_time: str | None = None, units_override: list[str] | None = None):
    now = datetime.now(tz=LOCAL_TZ)
    date_str = str(snapshot_date or now.strftime("%Y-%m-%d")).strip()
    run_time = str(snapshot_time or now.strftime("%Y-%m-%d %H:%M:%S")).strip()
    target_time = str(target_time or "").strip() or None
    report_time = "8:00 AM"
    staff_keys = ("department", "doctor", "nursing", "aaya", "ward_boy", "housekeeping")
    non_med_keys = ("left_label", "left_count", "right_label", "right_count")
    units = [str(u or "").strip().upper() for u in (units_override or _mod_snapshot_units()) if str(u or "").strip()]
    for unit in units:
        try:
            payload = _build_morning_report_payload(
                unit,
                date_str,
                source="snapshot",
                mod_name="SYSTEM",
                report_time=report_time,
                snapshot_time=run_time
            )
            if not payload:
                _log_morning_snapshot_audit(
                    target_time=target_time,
                    run_time=run_time,
                    snapshot_date=date_str,
                    unit=unit,
                    status="FAILED",
                    message="Failed to build morning snapshot payload.",
                    payload=None,
                    saved=False,
                )
                continue
            needs_staff = not _rows_have_any_value(payload.get("staff_rows"), staff_keys)
            needs_non_med = not _rows_have_any_value(payload.get("non_medical_rows"), non_med_keys)
            if needs_staff or needs_non_med:
                carry = _fetch_last_non_empty_morning_staff_non_medical(date_str, unit)
                if needs_staff and carry.get("staff_rows"):
                    payload["staff_rows"] = carry.get("staff_rows") or []
                    print(
                        f"Morning snapshot carry-forward staff for {unit}: "
                        f"{carry.get('staff_source_date') or '-'} {carry.get('staff_source_time') or ''}".strip()
                    )
                if needs_non_med and carry.get("non_medical_rows"):
                    payload["non_medical_rows"] = carry.get("non_medical_rows") or []
                    print(
                        f"Morning snapshot carry-forward non-medical for {unit}: "
                        f"{carry.get('non_med_source_date') or '-'} {carry.get('non_med_source_time') or ''}".strip()
                    )
            should_skip, skip_msg = _morning_snapshot_should_skip(payload)
            if should_skip:
                print(f"Morning snapshot skipped for {unit} {date_str}: {skip_msg}")
                _log_morning_snapshot_audit(
                    target_time=target_time,
                    run_time=run_time,
                    snapshot_date=date_str,
                    unit=unit,
                    status="SKIPPED",
                    message=skip_msg,
                    payload=payload,
                    saved=False,
                )
                continue
            try:
                _save_morning_report_snapshot_to_aci(payload)
            except Exception as _e:
                print(f"Morning report save failed for {unit}: {_e}")
                _log_morning_snapshot_audit(
                    target_time=target_time,
                    run_time=run_time,
                    snapshot_date=date_str,
                    unit=unit,
                    status="FAILED",
                    message=f"Morning snapshot save failed: {_e}",
                    payload=payload,
                    saved=False,
                )
                continue

            _log_morning_snapshot_audit(
                target_time=target_time,
                run_time=run_time,
                snapshot_date=date_str,
                unit=unit,
                status="SUCCESS",
                message="Morning snapshot saved.",
                payload=payload,
                saved=True,
            )

            try:
                export_dir = os.path.join("data", "exports", "morning_report")
                os.makedirs(export_dir, exist_ok=True)
                filename = f"Morning_Report_{unit}_{date_str}.xlsx"
                path = os.path.join(export_dir, filename)
                with open(path, "wb") as f:
                    f.write(_build_morning_report_excel(payload, exported_by="SYSTEM"))
            except Exception:
                pass
        except Exception as e:
            print(f"Morning report snapshot failed for {unit}: {e}")
            _log_morning_snapshot_audit(
                target_time=target_time,
                run_time=run_time,
                snapshot_date=date_str,
                unit=unit,
                status="FAILED",
                message=f"Morning snapshot loop failed: {e}",
                payload=None,
                saved=False,
            )
