def _build_overall_once():
    """
    Build the same 'overall' structure used by get_occupancy_data()
    without Flask request context.
    """
    try:
        today = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
        db_cfgs = getattr(config, "DB_CONFIGS", {}) or {}
        if not db_cfgs:
            chosen_cfg = _pick_db_cfg_for_proc()
            if not chosen_cfg:
                return None
            db_cfgs = {"_FALLBACK_": chosen_cfg}

        overall = {}

        for unit_name, cfg in db_cfgs.items():
            try:
                conn_str = _build_conn_str_from_dbconfig(cfg)
                with pyodbc.connect(conn_str) as conn:
                    try:
                        df = pd.read_sql(
                            "EXEC dbo.usp_RptIPDPatient_Occupancy @FromDate=?, @ToDate=?",
                            conn,
                            params=(today, today)
                        )
                    except Exception:
                        df = pd.read_sql("EXEC dbo.usp_RptIPDPatient_Occupancy", conn)

                if df is None or df.empty:
                    continue

                df = df.where(pd.notna(df), None)

                ward_col = next((c for c in ["Ward_Name", "WardName", "Ward", "WardDesc", "WardDescription"] if c in df.columns), None)
                bed_label_col = next((c for c in ["Bed_Name", "BedName", "Bed", "BedNo", "Bed_No"] if c in df.columns), None)
                status_col = next((c for c in ["Status", "PatientStatus", "ClinicalStatus", "DischargeStatus", "CurrentStatus", "CaseStatus"] if c in df.columns), None)

                if "Bed_ID" not in df.columns:
                    continue
                if not ward_col:
                    ward_col = "Ward"
                    df[ward_col] = "Unknown Ward"

                import math
                def _sv(v):
                    try:
                        if v is None or (isinstance(v, float) and math.isnan(v)) or pd.isna(v):
                            return None
                    except Exception:
                        pass
                    if isinstance(v, str):
                        s = v.strip()
                        if s == "" or s.lower() in ("nan", "none", "null"):
                            return None
                        return s
                    return v

                def _get(row, *keys):
                    for k in keys:
                        if k and k in row:
                            val = _sv(row.get(k))
                            if val is not None:
                                return val
                    return None

                def _has_patient(row):
                    return any([
                        _get(row, "Patient") is not None,
                        _get(row, "Patient_Name") is not None,
                        _get(row, "Regno") is not None,
                        _get(row, "Visit_ID") is not None
                    ])

                def _row_color(row):
                    st = (_get(row, status_col) or "").lower()
                    if "clinic" in st and "disch" in st:
                        return "yellow"
                    if "occup" in st:
                        return "green"
                    if "vac" in st:
                        return "blue"
                    return "green" if _has_patient(row) else "blue"

                df["_PrefWard"] = unit_name.upper() + " | " + df[ward_col].astype(str)
                dict_rows = df.to_dict(orient="records")

                for ward_name, g_idx in df.groupby("_PrefWard", sort=True).groups.items():
                    rows = [dict_rows[i] for i in g_idx]
                    bedlist = []
                    for r in rows:
                        status_text = (_get(r, status_col) or "").lower()
                        color = _row_color(r)
                        is_vacant = ("vac" in status_text) or (color == "blue")
                        bed = {
                            "Bed_ID": _sv(_get(r, "Bed_ID")),
                            "Bed_Label": _sv(_get(r, bed_label_col, "Bed_Name", "BedName", "Bed", "BedNo", "Bed_No", "Bed_ID")),
                            "Color": color,
                            "Patient_ID": None if is_vacant else _sv(_get(r, "Regno")),
                            "Patient_Name": None if is_vacant else _sv(_get(r, "Patient", "Patient_Name")),
                            "IPD_No": None if is_vacant else _sv(_get(r, "Visit_ID")),
                            "Room": _sv(_get(r, "Room", "Room_Name", "RoomName")),
                        }
                        bedlist.append(bed)
                    overall.setdefault(ward_name, []).extend(bedlist)

            except Exception:
                continue

        return overall if overall else None
    except Exception:
        return None

# ============================================================
# Enforce idle timeout & single-session per user
# ============================================================
@app.before_request
def enforce_session_policies():
    # Lazy-start OTP worker on first incoming request (Flask 3 removed before_first_request)
    _start_otp_worker_if_enabled()

    if request.endpoint in ('login', 'logout', 'static'):
        return

    username = session.get('username')
    role = session.get('role')
    if not username or not role:
        return

    now = int(time.time())

    last = session.get('last_activity', now)
    if now - last > IDLE_TIMEOUT_SECONDS:
        sid = session.get('sid')
        if sid:
            _session_store_clear(username, sid)
        session.clear()
        return redirect(url_for('login'))

    sid = session.get('sid')
    if not sid or _session_store_get(username) != sid:
        session.clear()
        return redirect(url_for('login'))

    # Do not refresh last_activity for passive timer polling
    if request.endpoint != 'session_remaining':
        session['last_activity'] = now
        _session_store_touch(username, sid)

# ============================================================
# Centralized section enforcement (no per-route decorator edits)
# ============================================================
@app.before_request
def enforce_section_rights():
    # Do not enforce for unauthenticated or public endpoints
    if request.endpoint in ('login', 'logout', 'static', 'session_remaining', '_bg_status', 'index', 'dashboard', 'settings', 'settings_change_password', 'historical_status', 'historical_request'):
        return
    if not session.get('username') or not session.get('role'):
        return

    section = _resolve_section_for_request(request.path)
    if not section:
        return
    if not has_section_access(section):
        return _forbidden_response("Access denied for this section.", 403)

EXECUTIVE_BLOCKED_PREFIXES = ("/user_management",)
EXECUTIVE_PURCHASE_MASTER_WRITE = {
    "/api/purchase/suppliers",
    "/api/purchase/supplier_master",
    "/api/purchase/manufacturer_master",
    "/api/purchase/item_master",
    "/api/purchase/purchasing_dept_master",
    "/api/purchase/purchasing_dept_master/action",
}

@app.before_request
def enforce_executive_restrictions():
    if not session.get('username') or not session.get('role'):
        return

    if _role_base(session.get('role')) != "Executive":
        return

    clean = "/" + request.path.split("?", 1)[0].strip().strip("/").lower()
    if any(clean.startswith(prefix) for prefix in EXECUTIVE_BLOCKED_PREFIXES):
        return _forbidden_response("Access denied for your role.", 403)

    if clean in EXECUTIVE_PURCHASE_MASTER_WRITE and request.method != "GET":
        payload = {"status": "error", "message": "Access denied for your role."}
        if clean.startswith("/api/"):
            return jsonify(payload), 403
        return (payload["message"], 403)


def _extract_from_date_param():
    """Best-effort extraction of from_date/start date from args/form/json."""
    keys = ("from_date", "from", "start_date", "date")
    for k in keys:
        v = request.args.get(k) or request.form.get(k)
        if v:
            return v
    if request.is_json:
        data = request.get_json(silent=True) or {}
        for k in keys:
            v = data.get(k)
            if v:
                return v
    return None


@app.before_request
def enforce_historical_lock():
    """
    Block requests with from_date older than fiscal-year start unless IT or session has a grant.
    """
    skip_endpoints = {
        'login', 'logout', 'static', 'session_remaining', '_bg_status', 'index',
        'dashboard', 'settings', 'settings_change_password',
        'historical_status', 'historical_request'
    }
    if request.endpoint in skip_endpoints:
        return
    if not session.get('username') or not session.get('role'):
        return
    if (session.get("role") or "").strip() == "IT":
        return

    from_val = _extract_from_date_param()
    if not from_val:
        return
    try:
        from_dt = datetime.fromisoformat(str(from_val)).date()
    except Exception:
        return  # if parsing fails, do not block

    cutoff = fiscal_year_start(datetime.now(tz=LOCAL_TZ)).date()
    user = (session.get("username") or "").strip()
    sid = session.get("sid")
    if from_dt >= cutoff or has_historical_grant(user, sid):
        return

    payload = {
        "status": "forbidden",
        "message": f"Historical data is locked before {cutoff.isoformat()}. Request IT approval.",
        "cutoff": cutoff.isoformat(),
        "needs_historical_access": True
    }
    wants_json = request.path.startswith("/api/") or request.accept_mimetypes.accept_json
    if wants_json:
        return jsonify(payload), 403
    return (payload["message"], 403)

