@app.route('/')
def index():
    if session.get('username') and session.get('role'):
        return redirect(url_for('dashboard'))
    return redirect(url_for('login'))

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = (request.form.get('username') or '').strip()
        password = request.form.get('password') or ''

        # ---- DB-backed login
        rec = fetch_user_from_db(username)
        if rec and rec.get("role") and rec.get("passwordw") == password:
            sid = token_hex(16)
            _session_store_set(username, sid)
            session['username'] = username
            session['role'] = rec["role"]
            session["accountid"] = rec.get("accountid") or 0
            session['sid'] = sid
            session['last_activity'] = int(time.time())

            # --- unit access scoping
            role = (session.get("role") or "").strip()
            uname = (username or "").strip().lower()
            unit = _normalize_unit_scope_text(rec.get("unit_scope"))

            if role.startswith("Departmental Head"):
                if not unit and ":" in role:
                    unit = _normalize_unit_scope_text(role.split(":", 1)[1])
                if not unit:
                    if uname == "head":
                        unit = "AHL"
                    elif uname == "head_aci":
                        unit = "ACI"
                    elif uname == "head_ballia":
                        unit = "BALLIA"
                session["unit_scope"] = unit or ""
            else:
                session["unit_scope"] = unit or None

            # --- persist section-level rights
            sections = _normalize_section_list(rec.get("sections"))
            if not sections and role in {"IT", "Management"}:
                sections = ["*"]  # grant full access by default
            session["section_rights"] = sections
            firm_scope = _normalize_firm_scope_text(rec.get("firm_scope") or "")
            if not firm_scope and _role_base(role) == "IT":
                firm_scope = "*"
            session["firm_scope"] = firm_scope
            session["purchase_unit_scope"] = _normalize_unit_scope_text(rec.get("purchase_unit_scope") or "")

            # warm caches
            today = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
            try:
                start_prefetch(today, today)
                start_prefetch_breakdowns(today, today)
            except Exception:
                pass

            # Apply any pending historical grant to this new session
            pending_ttl = _consume_pending_historical(username)
            if pending_ttl:
                grant_historical(username, sid, pending_ttl)

            return redirect(url_for('dashboard'))

        # ---- Local fallback login
        local = USER_CREDENTIALS.get(username)
        if local and local["password"] == password:
            sid = token_hex(16)
            _session_store_set(username, sid)
            session['username'] = username
            session['role'] = local["role"]
            session["accountid"] = local.get("accountid") or 0
            session['sid'] = sid
            session['last_activity'] = int(time.time())

            role = (session.get("role") or "").strip()
            uname = (username or "").strip().lower()
            unit = ""

            if role.startswith("Departmental Head"):
                if not unit and ":" in role:
                    unit = _normalize_unit_scope_text(role.split(":", 1)[1])
                if not unit:
                    if uname == "head":
                        unit = "AHL"
                    elif uname == "head_aci":
                        unit = "ACI"
                    elif uname == "head_ballia":
                        unit = "BALLIA"
                session["unit_scope"] = unit or ""
            else:
                session["unit_scope"] = unit or None

            session["section_rights"] = ["*"] if role in {"IT", "Management"} else []
            session["firm_scope"] = "*" if _role_base(role) == "IT" else ""
            session["purchase_unit_scope"] = ""

            today = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
            try:
                start_prefetch(today, today)
                start_prefetch_breakdowns(today, today)
            except Exception:
                pass

            # Apply any pending historical grant to this new session
            pending_ttl = _consume_pending_historical(username)
            if pending_ttl:
                grant_historical(username, sid, pending_ttl)

            return redirect(url_for('dashboard'))

        # ---- invalid credentials
        return render_template('login.html', error="Invalid credentials")

    # GET
    return render_template('login.html')

@app.route('/logout')
def logout():
    username = session.get('username')
    sid = session.get('sid')
    if username and sid:
        _session_store_clear(username, sid)
        revoke_historical(username, sid)
    session.clear()
    return redirect(url_for('login'))

