# >>> TODAY REFRESH ADD-ONLY: small helpers
def _is_truthy(v) -> bool:
    if v is None:
        return False
    s = str(v).strip().lower()
    return s in ("1","true","yes","y","refresh","force")

def _is_today_range(from_date: str, to_date: str) -> bool:
    today = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    return (from_date == today) and (to_date == today)

def _fetch_live_and_refresh_cache(units: list[str], from_date: str, to_date: str):
    """Force live fetch for given units and update sqlite + in-memory prefetch summary."""
    print(f"Forced live refresh for {from_date}->{to_date} units={units}")
    all_data = []
    fetch_results = {}
    with ThreadPoolExecutor(max_workers=_revenue_pool_workers(len(units))) as executor:
        fut = {executor.submit(_fetch_revenue_limited, u, from_date, to_date): u for u in units}
        for f in as_completed(fut):
            u = fut[f]
            try:
                df = f.result()
                if df is not None and not df.empty:
                    df = df.dropna(axis=1, how='all').copy()
                    df.loc[:, "Unit"] = u.upper()
                    all_data.append(df)
                    fetch_results[u] = len(df)
                    _rev_cache_put_async(u, from_date, to_date, df)  # update sqlite cache in background
                else:
                    fetch_results[u] = 0
            except Exception as e:
                fetch_results[u] = 0
                print(f"refresh live fetch failed for {u}: {e}")
    if not all_data:
        return None

    combined = pd.concat(all_data, ignore_index=True, copy=False)
    try:
        summary = (
            combined.groupby("Unit")["NetAmount"].sum().reset_index().to_dict(orient="records")
        )
    except Exception:
        summary = [{"Unit": u, "Records": fetch_results.get(u, 0)} for u in units]

    # set in-memory summary cache for this exact range
    try:
        _cache_put(from_date, to_date, {
            "summary": summary,
            "units": units,
            "records": sum(fetch_results.values())
        })
    except Exception:
        pass

    # also warm breakdowns for today in background (typeofvisit/category)
    try:
        start_prefetch_breakdowns(from_date, to_date)
    except Exception:
        pass

    return {"summary": summary, "units": units, "records": sum(fetch_results.values())}

# ============================================================
# Fetch Revenue Data (Parallel Fetch for All Units) - with hybrid caching
# ============================================================
def _first_matching_col(df: pd.DataFrame, candidates: list[str]) -> str | None:
    if df is None or df.empty:
        return None
    cols_map = {str(c).strip().lower(): c for c in df.columns}
    for cand in candidates:
        key = str(cand).strip().lower()
        if key in cols_map:
            return cols_map[key]
    return None


def _nunique_non_blank(series: pd.Series) -> int:
    if series is None:
        return 0
    s = series.astype(str).str.strip()
    s = s[~s.str.lower().isin({"", "none", "nan", "nat", "null"})]
    return int(s.nunique())


def _fetch_patient_source_bill_map(unit: str, from_date: str, to_date: str, bill_ids: list[int] | None = None) -> pd.DataFrame:
    from modules.db_connection import get_sql_connection

    conn = get_sql_connection(unit)
    if not conn:
        return pd.DataFrame(columns=["Bill_ID", "PatientSourceId", "PatientSourceName"])

    def _qident(name: str) -> str:
        return "[" + str(name or "").replace("]", "").strip() + "]"

    def _list_table_cols(table_name: str) -> dict:
        # 1) Information schema (preferred)
        try:
            col_df = pd.read_sql(
                """
                SELECT COLUMN_NAME
                FROM INFORMATION_SCHEMA.COLUMNS
                WHERE TABLE_SCHEMA='dbo' AND TABLE_NAME=?
                """,
                conn,
                params=[table_name],
            )
            if col_df is not None and not col_df.empty:
                return {str(c).strip().lower(): str(c).strip() for c in col_df["COLUMN_NAME"].tolist()}
        except Exception:
            pass
        # 2) Fallback: TOP 0 metadata
        try:
            meta_df = pd.read_sql(f"SELECT TOP 0 * FROM dbo.{_qident(table_name)}", conn)
            if meta_df is not None:
                return {str(c).strip().lower(): str(c).strip() for c in meta_df.columns.tolist()}
        except Exception:
            pass
        return {}

    def _pick_db_col(table_name: str, candidates: list[str]) -> str | None:
        existing = _list_table_cols(table_name)
        if not existing:
            return None
        try:
            for cand in candidates:
                key = str(cand).strip().lower()
                if key in existing:
                    return existing[key]
        except Exception:
            return None
        return None

    bill_id_col = _pick_db_col("Billing_Mst", ["Bill_ID", "BillId", "bill_id"])
    bill_visit_fk_col = _pick_db_col("Billing_Mst", ["Visit_ID", "VisitId", "visit_id"])
    bill_date_col = _pick_db_col("Billing_Mst", ["BillDate", "billdate", "Bill_Date", "bill_date"])
    visit_pk_col = _pick_db_col("Visit", ["Visit_ID", "VisitId", "visit_id"])
    visit_source_col = _pick_db_col("Visit", ["PatientSourceId", "patientSourceId", "PatientSourceID", "PatientSource_ID"])
    occ_id_col = _pick_db_col("Occupation_Mst", ["Occupation_ID", "OccupationId", "occupation_id"])
    occ_name_col = _pick_db_col("Occupation_Mst", ["Occupation_Name", "OccupationName", "occupation_name"])

    if not all([bill_id_col, bill_visit_fk_col, bill_date_col, visit_pk_col]):
        print(
            f"Error fetching patient source map ({unit}): required columns missing "
            f"(bill_id={bill_id_col}, bill_visit_fk={bill_visit_fk_col}, bill_date={bill_date_col}, visit_pk={visit_pk_col})"
        )
        return pd.DataFrame(columns=["Bill_ID", "PatientSourceId", "PatientSourceName"])

    bill_id_q = _qident(bill_id_col)
    bill_visit_fk_q = _qident(bill_visit_fk_col)
    bill_date_q = _qident(bill_date_col)
    visit_pk_q = _qident(visit_pk_col)

    source_int_expr = "NULL"
    source_id_expr = "CAST(0 AS INT)"
    source_name_expr = "'Unknown'"
    source_join_sql = ""
    if visit_source_col:
        source_text_expr = f"LTRIM(RTRIM(CONVERT(NVARCHAR(100), v.{_qident(visit_source_col)})))"
        source_int_expr = (
            f"CASE WHEN {source_text_expr} <> '' "
            f"AND {source_text_expr} NOT LIKE '%[^0-9]%' "
            f"THEN CONVERT(INT, {source_text_expr}) ELSE NULL END"
        )
        source_id_expr = f"ISNULL({source_int_expr}, 0)"
        if occ_id_col and occ_name_col:
            source_join_sql = (
                f"LEFT JOIN dbo.Occupation_Mst om WITH (NOLOCK) "
                f"ON om.{_qident(occ_id_col)} = {source_int_expr}"
            )
            source_name_expr = f"LTRIM(RTRIM(COALESCE(NULLIF(om.{_qident(occ_name_col)}, ''), 'Unknown')))"

    base_sql = f"""
        SELECT
            bm.{bill_id_q} AS Bill_ID,
            {source_id_expr} AS PatientSourceId,
            {source_name_expr} AS PatientSourceName
        FROM dbo.Billing_Mst bm WITH (NOLOCK)
        LEFT JOIN dbo.Visit v WITH (NOLOCK)
            ON v.{visit_pk_q} = bm.{bill_visit_fk_q}
        {source_join_sql}
    """

    try:
        out = None
        clean_bill_ids = []
        if bill_ids:
            for b in bill_ids:
                try:
                    clean_bill_ids.append(int(b))
                except Exception:
                    continue
            clean_bill_ids = sorted(set(clean_bill_ids))

        if clean_bill_ids:
            chunks = [clean_bill_ids[i:i + 900] for i in range(0, len(clean_bill_ids), 900)]
            parts = []
            for chunk in chunks:
                placeholders = ",".join(["?"] * len(chunk))
                sql = base_sql + f"\nWHERE bm.{bill_id_q} IN ({placeholders})"
                part = pd.read_sql(sql, conn, params=chunk)
                if part is not None and not part.empty:
                    parts.append(part)
            if parts:
                out = pd.concat(parts, ignore_index=True, copy=False)
            else:
                out = pd.DataFrame(columns=["Bill_ID", "PatientSourceId", "PatientSourceName"])
        else:
            sql = base_sql + f"""
                WHERE CONVERT(VARCHAR, bm.{bill_date_q}, 102)
                      BETWEEN CONVERT(VARCHAR, ?, 102)
                          AND CONVERT(VARCHAR, ?, 102)
            """
            out = pd.read_sql(sql, conn, params=[from_date, to_date])

        out = _clean_df_columns(out)
        try:
            non_zero = int(pd.to_numeric(out.get("PatientSourceId"), errors="coerce").fillna(0).astype(int).ne(0).sum())
            print(
                f"Patient source map ({unit}) -> rows={len(out)}, non_zero_source={non_zero}, "
                f"visit_source_col={visit_source_col}, occ_id_col={occ_id_col}, occ_name_col={occ_name_col}, "
                f"bill_ids_input={len(clean_bill_ids)}"
            )
        except Exception:
            pass
        return out
    except Exception as e:
        print(f"Error fetching patient source map ({unit}): {e}")
        return pd.DataFrame(columns=["Bill_ID", "PatientSourceId", "PatientSourceName"])
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _patient_source_unit_summary(unit: str, from_date: str, to_date: str, refresh_flag: bool = False) -> pd.DataFrame:
    if refresh_flag:
        df = _fetch_revenue_limited(unit, from_date, to_date)
        if df is not None and not df.empty:
            df = _clean_df_columns(df)
            df["Unit"] = unit.upper()
            _rev_cache_put_async(unit, from_date, to_date, df)
    else:
        df = _get_or_fetch_unit(unit, from_date, to_date)

    if df is None or df.empty:
        return pd.DataFrame()

    df = _clean_df_columns(df)

    bill_col = _first_matching_col(df, ["Bill_ID", "BillId", "BillID", "Bill_Id"])
    net_col = _first_matching_col(df, ["NetAmount", "Net_Amount", "Amount"])
    visit_col = _first_matching_col(df, ["VisitNo", "Visit_No", "VisitID", "VisitId", "Visit_ID"])
    patient_col = _first_matching_col(df, ["Registration_No", "RegistrationNo", "RegNo", "Reg_No", "PatientID", "PatientId", "Patient_ID"])

    if not bill_col or not net_col:
        return pd.DataFrame()

    base = pd.DataFrame({
        "Bill_ID": pd.to_numeric(df[bill_col], errors="coerce"),
        "NetAmount": pd.to_numeric(df[net_col], errors="coerce").fillna(0.0),
        "VisitKey": (df[visit_col].astype(str).str.strip() if visit_col else pd.Series([""] * len(df))),
        "PatientKey": (df[patient_col].astype(str).str.strip() if patient_col else pd.Series([""] * len(df))),
    })
    base = base[base["Bill_ID"].notna()].copy()
    if base.empty:
        return pd.DataFrame()

    base["Bill_ID"] = base["Bill_ID"].astype("int64")
    if not visit_col:
        base["VisitKey"] = base["Bill_ID"].astype(str)
    if not patient_col:
        base["PatientKey"] = base["Bill_ID"].astype(str)

    source_map = _fetch_patient_source_bill_map(
        unit,
        from_date,
        to_date,
        bill_ids=base["Bill_ID"].tolist(),
    )
    if source_map is None or source_map.empty:
        source_map = pd.DataFrame({
            "Bill_ID": base["Bill_ID"].unique(),
            "PatientSourceId": 0,
            "PatientSourceName": "Unknown",
        })
    else:
        source_map = _clean_df_columns(source_map)
        src_bill_col = _first_matching_col(source_map, ["Bill_ID", "BillId", "BillID", "Bill_Id"])
        src_id_col = _first_matching_col(source_map, ["PatientSourceId", "patientSourceId", "PatientSource_ID"])
        src_name_col = _first_matching_col(source_map, ["PatientSourceName", "Occupation_Name", "OccupationName"])

        if not src_bill_col:
            source_map = pd.DataFrame({
                "Bill_ID": base["Bill_ID"].unique(),
                "PatientSourceId": 0,
                "PatientSourceName": "Unknown",
            })
        else:
            source_map = pd.DataFrame({
                "Bill_ID": pd.to_numeric(source_map[src_bill_col], errors="coerce"),
                "PatientSourceId": pd.to_numeric(source_map[src_id_col], errors="coerce") if src_id_col else 0,
                "PatientSourceName": source_map[src_name_col].astype(str).str.strip() if src_name_col else "Unknown",
            })
            source_map = source_map[source_map["Bill_ID"].notna()].copy()
            source_map["Bill_ID"] = source_map["Bill_ID"].astype("int64")
            source_map["PatientSourceName"] = (
                source_map["PatientSourceName"]
                .replace({"": np.nan, "None": np.nan, "nan": np.nan})
                .fillna("Unknown")
            )
            source_map["PatientSourceId"] = pd.to_numeric(
                source_map["PatientSourceId"], errors="coerce"
            ).fillna(0).astype(int)
            source_map = source_map.drop_duplicates(subset=["Bill_ID"], keep="last")

    merged = base.merge(source_map, on="Bill_ID", how="left")
    merged["PatientSourceId"] = pd.to_numeric(merged["PatientSourceId"], errors="coerce").fillna(0).astype(int)
    merged["PatientSourceName"] = (
        merged["PatientSourceName"]
        .astype(str)
        .str.strip()
        .replace({"": np.nan, "None": np.nan, "nan": np.nan})
        .fillna("Unknown")
    )
    merged["VisitKey"] = merged["VisitKey"].fillna("").astype(str).str.strip()
    merged["PatientKey"] = merged["PatientKey"].fillna("").astype(str).str.strip()

    grouped = (
        merged.groupby(["PatientSourceId", "PatientSourceName"], as_index=False)
        .agg(
            PotentialRevenue=("NetAmount", "sum"),
            VisitCount=("VisitKey", _nunique_non_blank),
            PatientCount=("PatientKey", _nunique_non_blank),
            BillCount=("Bill_ID", "nunique"),
        )
    )
    grouped["Unit"] = unit.upper()
    grouped["PotentialRevenue"] = pd.to_numeric(grouped["PotentialRevenue"], errors="coerce").fillna(0.0)
    grouped["VisitCount"] = pd.to_numeric(grouped["VisitCount"], errors="coerce").fillna(0).astype(int)
    grouped["PatientCount"] = pd.to_numeric(grouped["PatientCount"], errors="coerce").fillna(0).astype(int)
    grouped["BillCount"] = pd.to_numeric(grouped["BillCount"], errors="coerce").fillna(0).astype(int)
    return grouped


def _build_patient_source_kpi(units: list[str], from_date: str, to_date: str, refresh_flag: bool = False) -> dict:
    if not units:
        return {
            "rows": [],
            "unit_rows": [],
            "totals": {
                "total_revenue": 0.0,
                "visit_count": 0,
                "patient_count": 0,
                "bill_count": 0,
                "source_count": 0,
            },
            "top_source": None,
        }

    frames = []
    with ThreadPoolExecutor(max_workers=_revenue_pool_workers(len(units))) as executor:
        futures = {
            executor.submit(_patient_source_unit_summary, unit, from_date, to_date, refresh_flag): unit
            for unit in units
        }
        for future in as_completed(futures):
            unit = futures[future]
            try:
                unit_df = future.result()
                if unit_df is not None and not unit_df.empty:
                    frames.append(unit_df)
            except Exception as e:
                print(f"Error building patient source KPI ({unit}): {e}")

    if not frames:
        return {
            "rows": [],
            "unit_rows": [],
            "totals": {
                "total_revenue": 0.0,
                "visit_count": 0,
                "patient_count": 0,
                "bill_count": 0,
                "source_count": 0,
            },
            "top_source": None,
        }

    unit_summary = pd.concat(frames, ignore_index=True, copy=False)
    unit_summary = unit_summary.sort_values(["Unit", "PotentialRevenue"], ascending=[True, False])

    overall = (
        unit_summary.groupby(["PatientSourceId", "PatientSourceName"], as_index=False)
        .agg(
            PotentialRevenue=("PotentialRevenue", "sum"),
            VisitCount=("VisitCount", "sum"),
            PatientCount=("PatientCount", "sum"),
            BillCount=("BillCount", "sum"),
        )
        .sort_values("PotentialRevenue", ascending=False)
        .reset_index(drop=True)
    )
    overall["Rank"] = overall.index + 1

    def _row_to_record(row, include_unit=False):
        rec = {
            "Rank": int(row.get("Rank", 0) or 0),
            "SourceID": int(row.get("PatientSourceId", 0) or 0),
            "SourceName": str(row.get("PatientSourceName", "") or ""),
            "PotentialRevenue": float(row.get("PotentialRevenue", 0.0) or 0.0),
            "VisitCount": int(row.get("VisitCount", 0) or 0),
            "PatientCount": int(row.get("PatientCount", 0) or 0),
            "BillCount": int(row.get("BillCount", 0) or 0),
        }
        if include_unit:
            rec["Unit"] = str(row.get("Unit", "") or "")
        return rec

    rows = [_row_to_record(r) for _, r in overall.iterrows()]
    unit_rows = [_row_to_record(r, include_unit=True) for _, r in unit_summary.iterrows()]
    top_source = rows[0] if rows else None

    totals = {
        "total_revenue": float(overall["PotentialRevenue"].sum()) if not overall.empty else 0.0,
        "visit_count": int(overall["VisitCount"].sum()) if not overall.empty else 0,
        "patient_count": int(overall["PatientCount"].sum()) if not overall.empty else 0,
        "bill_count": int(overall["BillCount"].sum()) if not overall.empty else 0,
        "source_count": int(len(overall)),
    }
    return {
        "rows": rows,
        "unit_rows": unit_rows,
        "totals": totals,
        "top_source": top_source,
    }


def _build_patient_source_detail_rows(
    units: list[str],
    from_date: str,
    to_date: str,
    refresh_flag: bool = False,
) -> list[dict]:
    if not units:
        return []

    def _unit_details(unit: str) -> pd.DataFrame:
        if refresh_flag:
            df = _fetch_revenue_limited(unit, from_date, to_date)
            if df is not None and not df.empty:
                df = _clean_df_columns(df)
                df["Unit"] = unit.upper()
                _rev_cache_put_async(unit, from_date, to_date, df)
        else:
            df = _get_or_fetch_unit(unit, from_date, to_date)

        if df is None or df.empty:
            return pd.DataFrame()

        df = _clean_df_columns(df)
        bill_col = _first_matching_col(df, ["Bill_ID", "BillId", "BillID", "Bill_Id"])
        net_col = _first_matching_col(df, ["NetAmount", "Net_Amount", "Amount"])
        patient_col = _first_matching_col(df, ["PatientName", "Patient_Name", "Name"])
        reg_col = _first_matching_col(df, ["Registration_No", "RegistrationNo", "RegNo", "Reg_No"])

        if not bill_col or not net_col:
            return pd.DataFrame()

        base = pd.DataFrame({
            "Bill_ID": pd.to_numeric(df[bill_col], errors="coerce"),
            "NetAmount": pd.to_numeric(df[net_col], errors="coerce").fillna(0.0),
            "Patient": df[patient_col].astype(str).str.strip() if patient_col else "",
            "Reg No": df[reg_col].astype(str).str.strip() if reg_col else "",
        })
        base = base[base["Bill_ID"].notna()].copy()
        if base.empty:
            return pd.DataFrame()
        base["Bill_ID"] = base["Bill_ID"].astype("int64")

        src = _fetch_patient_source_bill_map(unit, from_date, to_date, bill_ids=base["Bill_ID"].tolist())
        if src is None or src.empty:
            base["Source"] = "Unknown"
        else:
            src = _clean_df_columns(src)
            src_bill = _first_matching_col(src, ["Bill_ID", "BillId", "BillID", "Bill_Id"])
            src_name = _first_matching_col(src, ["PatientSourceName", "Occupation_Name", "OccupationName"])
            if not src_bill:
                base["Source"] = "Unknown"
            else:
                src_map = pd.DataFrame({
                    "Bill_ID": pd.to_numeric(src[src_bill], errors="coerce"),
                    "Source": src[src_name].astype(str).str.strip() if src_name else "Unknown",
                })
                src_map = src_map[src_map["Bill_ID"].notna()].copy()
                src_map["Bill_ID"] = src_map["Bill_ID"].astype("int64")
                src_map["Source"] = (
                    src_map["Source"]
                    .replace({"": np.nan, "None": np.nan, "nan": np.nan})
                    .fillna("Unknown")
                )
                src_map = src_map.drop_duplicates(subset=["Bill_ID"], keep="last")
                base = base.merge(src_map, on="Bill_ID", how="left")
                base["Source"] = (
                    base["Source"].astype(str).str.strip()
                    .replace({"": np.nan, "None": np.nan, "nan": np.nan})
                    .fillna("Unknown")
                )

        base = base[["NetAmount", "Patient", "Reg No", "Source"]].copy()
        return base

    frames = []
    with ThreadPoolExecutor(max_workers=_revenue_pool_workers(len(units))) as executor:
        futures = {
            executor.submit(_unit_details, unit): unit
            for unit in units
        }
        for future in as_completed(futures):
            try:
                part = future.result()
                if part is not None and not part.empty:
                    frames.append(part)
            except Exception as e:
                print(f"Error building patient source detail rows: {e}")

    if not frames:
        return []

    detail_df = pd.concat(frames, ignore_index=True, copy=False)
    detail_df["NetAmount"] = pd.to_numeric(detail_df["NetAmount"], errors="coerce").fillna(0.0)
    detail_df["Patient"] = detail_df["Patient"].astype(str).str.strip()
    detail_df["Reg No"] = detail_df["Reg No"].astype(str).str.strip()
    detail_df["Source"] = detail_df["Source"].astype(str).str.strip()
    detail_df = detail_df.sort_values("NetAmount", ascending=False).reset_index(drop=True)
    return detail_df.to_dict(orient="records")


def _resolve_patient_source_scope(allowed_units: list[str], unit_param: str | None) -> tuple[list[str], str]:
    requested = (unit_param or "ALL").strip().upper()
    if requested and requested != "ALL":
        if requested not in allowed_units:
            raise PermissionError(f"Unit {requested} not permitted for your role")
        return [requested], requested
    scope = "ALL"
    if allowed_units:
        scope = "ALL (" + ", ".join(allowed_units) + ")"
    return allowed_units, scope


@app.route('/api/revenue_patient_source', methods=['POST'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_revenue_patient_source():
    from_date = request.form.get('from_date')
    to_date = request.form.get('to_date')
    unit_param = request.form.get('unit')
    refresh_flag = _is_truthy(request.form.get('refresh') or request.form.get('force') or request.form.get('refresh_today'))

    if not from_date or not to_date:
        return jsonify({"status": "error", "message": "Missing date range"}), 400

    allowed_units = _analytics_allowed_units_for_session()
    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403

    try:
        target_units, scope_label = _resolve_patient_source_scope(allowed_units, unit_param)
    except PermissionError as e:
        return jsonify({"status": "error", "message": str(e)}), 403

    payload = _build_patient_source_kpi(target_units, from_date, to_date, refresh_flag=refresh_flag)
    return jsonify({
        "status": "success",
        "from_date": from_date,
        "to_date": to_date,
        "units": target_units,
        "unit_scope": scope_label,
        **payload,
    })


@app.route('/export_revenue_patient_source_excel')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def export_revenue_patient_source_excel():
    import io

    from_date = request.args.get('from_date')
    to_date = request.args.get('to_date')
    unit_param = request.args.get('unit')
    refresh_flag = _is_truthy(request.args.get('refresh') or request.args.get('force') or request.args.get('refresh_today'))

    if not from_date or not to_date:
        return jsonify({"status": "error", "message": "Missing date range"}), 400

    allowed_units = _analytics_allowed_units_for_session()
    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403

    try:
        target_units, scope_label = _resolve_patient_source_scope(allowed_units, unit_param)
    except PermissionError as e:
        return jsonify({"status": "error", "message": str(e)}), 403

    payload = _build_patient_source_kpi(target_units, from_date, to_date, refresh_flag=refresh_flag)
    rows = payload.get("rows") or []
    detail_rows = _build_patient_source_detail_rows(
        target_units, from_date, to_date, refresh_flag=refresh_flag
    )
    if not rows:
        return jsonify({"status": "error", "message": "No patient source data available for selected range"}), 404

    exported_by = session.get("username") or session.get("user") or "Unknown"
    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%d-%b-%Y %I:%M %p")

    out = io.BytesIO()
    with pd.ExcelWriter(out, engine="xlsxwriter") as writer:
        wb = writer.book
        ws = wb.add_worksheet("Patient Source KPI")
        writer.sheets["Patient Source KPI"] = ws

        title_fmt = wb.add_format({
            "bold": True,
            "font_size": 14,
            "font_color": "white",
            "bg_color": "#1e3a8a",
            "align": "center",
            "valign": "vcenter",
            "border": 1,
        })
        meta_k_fmt = wb.add_format({"bold": True, "font_color": "#334155", "align": "left"})
        meta_v_fmt = wb.add_format({"font_color": "#0f172a", "align": "left"})
        th_fmt = wb.add_format({
            "bold": True,
            "bg_color": "#dbeafe",
            "font_color": "#1e3a8a",
            "border": 1,
            "align": "center",
            "valign": "vcenter",
        })
        td_fmt = wb.add_format({"border": 1, "align": "left"})
        td_num_fmt = wb.add_format({"border": 1, "align": "center"})
        td_inr_fmt = wb.add_format({"border": 1, "align": "right", "num_format": '[$\u20B9-4009] #,##,##0'})
        total_label_fmt = wb.add_format({"bold": True, "bg_color": "#f1f5f9", "border": 1, "align": "left"})
        total_num_fmt = wb.add_format({"bold": True, "bg_color": "#f1f5f9", "border": 1, "align": "center"})
        total_inr_fmt = wb.add_format({"bold": True, "bg_color": "#f1f5f9", "border": 1, "align": "right", "num_format": '[$\u20B9-4009] #,##,##0'})

        ws.merge_range(0, 0, 0, 6, "Revenue KPI - Patient Source Potential", title_fmt)
        meta_rows = [
            ("Date Range", f"{from_date} to {to_date}"),
            ("Unit Scope", scope_label),
            ("Exported By", exported_by),
            ("Exported At", exported_at),
        ]
        meta_start = 2
        for i, (k, v) in enumerate(meta_rows):
            ws.write(meta_start + i, 0, k, meta_k_fmt)
            ws.write(meta_start + i, 1, v, meta_v_fmt)

        header_row = meta_start + len(meta_rows) + 2
        headers = ["Rank", "Patient Source", "Source ID", "Visit Count", "Patient Count", "Bill Count", "Potential Revenue"]
        for c, h in enumerate(headers):
            ws.write(header_row, c, h, th_fmt)

        data_row = header_row + 1
        for idx, rec in enumerate(rows):
            ws.write(data_row + idx, 0, rec.get("Rank", idx + 1), td_num_fmt)
            ws.write(data_row + idx, 1, rec.get("SourceName", ""), td_fmt)
            ws.write(data_row + idx, 2, rec.get("SourceID", 0), td_num_fmt)
            ws.write(data_row + idx, 3, rec.get("VisitCount", 0), td_num_fmt)
            ws.write(data_row + idx, 4, rec.get("PatientCount", 0), td_num_fmt)
            ws.write(data_row + idx, 5, rec.get("BillCount", 0), td_num_fmt)
            ws.write(data_row + idx, 6, rec.get("PotentialRevenue", 0.0), td_inr_fmt)

        totals = payload.get("totals") or {}
        total_row = data_row + len(rows)
        ws.write(total_row, 0, "Total", total_label_fmt)
        ws.write(total_row, 1, "", total_label_fmt)
        ws.write(total_row, 2, totals.get("source_count", 0), total_num_fmt)
        ws.write(total_row, 3, totals.get("visit_count", 0), total_num_fmt)
        ws.write(total_row, 4, totals.get("patient_count", 0), total_num_fmt)
        ws.write(total_row, 5, totals.get("bill_count", 0), total_num_fmt)
        ws.write(total_row, 6, totals.get("total_revenue", 0.0), total_inr_fmt)

        ws.set_column(0, 0, 8)
        ws.set_column(1, 1, 36)
        ws.set_column(2, 2, 10)
        ws.set_column(3, 5, 13)
        ws.set_column(6, 6, 18)
        ws.freeze_panes(data_row, 0)

        ws_d = wb.add_worksheet("Details")
        writer.sheets["Details"] = ws_d
        ws_d.merge_range(0, 0, 0, 3, "Patient Source Revenue Details", title_fmt)
        ws_d.write(2, 0, "Date Range", meta_k_fmt)
        ws_d.write(2, 1, f"{from_date} to {to_date}", meta_v_fmt)
        ws_d.write(3, 0, "Unit Scope", meta_k_fmt)
        ws_d.write(3, 1, scope_label, meta_v_fmt)
        ws_d.write(4, 0, "Exported By", meta_k_fmt)
        ws_d.write(4, 1, exported_by, meta_v_fmt)
        ws_d.write(5, 0, "Exported At", meta_k_fmt)
        ws_d.write(5, 1, exported_at, meta_v_fmt)

        d_header_row = 7
        d_headers = ["NetAmount", "Patient", "Reg No", "Source"]
        for c, h in enumerate(d_headers):
            ws_d.write(d_header_row, c, h, th_fmt)

        d_data_row = d_header_row + 1
        for idx, rec in enumerate(detail_rows):
            ws_d.write(d_data_row + idx, 0, rec.get("NetAmount", 0.0), td_inr_fmt)
            ws_d.write(d_data_row + idx, 1, rec.get("Patient", ""), td_fmt)
            ws_d.write(d_data_row + idx, 2, rec.get("Reg No", ""), td_fmt)
            ws_d.write(d_data_row + idx, 3, rec.get("Source", ""), td_fmt)

        ws_d.set_column(0, 0, 18)
        ws_d.set_column(1, 1, 36)
        ws_d.set_column(2, 2, 18)
        ws_d.set_column(3, 3, 30)
        ws_d.freeze_panes(d_data_row, 0)

    out.seek(0)
    unit_tag = "ALL" if len(target_units) > 1 else target_units[0]
    filename = f"Revenue_PatientSource_{unit_tag}_{from_date}_to_{to_date}.xlsx"
    return send_file(
        out,
        as_attachment=True,
        download_name=filename,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )


def _build_revenue_patient_source_pdf_buffer(
    rows: list[dict],
    detail_rows: list[dict],
    from_date: str,
    to_date: str,
    unit_scope: str,
    exported_by: str,
):
    import io
    from reportlab.lib import colors
    from reportlab.lib.pagesizes import A4, landscape
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_RIGHT
    from reportlab.lib.units import mm
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer, PageBreak

    def fmt_inr(value):
        try:
            n = float(value or 0)
        except Exception:
            n = 0.0
        sign = "-" if n < 0 else ""
        n = abs(int(round(n)))
        s = str(n)
        if len(s) <= 3:
            return f"{sign}{s}"
        head = s[:-3]
        tail = s[-3:]
        chunks = []
        while len(head) > 2:
            chunks.append(head[-2:])
            head = head[:-2]
        if head:
            chunks.append(head)
        return f"{sign}{','.join(reversed(chunks))},{tail}"

    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%d-%b-%Y %I:%M %p")
    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=landscape(A4),
        topMargin=12 * mm,
        bottomMargin=14 * mm,
        leftMargin=10 * mm,
        rightMargin=10 * mm,
    )
    styles = getSampleStyleSheet()
    s_title = ParagraphStyle("kpi_title", parent=styles["Heading1"], alignment=TA_CENTER, fontSize=15, textColor=colors.HexColor("#1e3a8a"), spaceAfter=6)
    s_meta = ParagraphStyle("kpi_meta", parent=styles["Normal"], alignment=TA_LEFT, fontSize=9, textColor=colors.HexColor("#334155"), leading=12)
    s_section = ParagraphStyle("kpi_section", parent=styles["Heading2"], alignment=TA_LEFT, fontSize=11, textColor=colors.HexColor("#0f172a"), spaceBefore=8, spaceAfter=4)
    s_cell_left = ParagraphStyle("kpi_cell_left", parent=styles["Normal"], alignment=TA_LEFT, fontSize=8)
    s_cell_right = ParagraphStyle("kpi_cell_right", parent=styles["Normal"], alignment=TA_RIGHT, fontSize=8)
    s_cell_center = ParagraphStyle("kpi_cell_center", parent=styles["Normal"], alignment=TA_CENTER, fontSize=8)
    s_head_left = ParagraphStyle("kpi_head_left", parent=s_cell_left, textColor=colors.white, fontName="Helvetica-Bold")
    s_head_center = ParagraphStyle("kpi_head_center", parent=s_cell_center, textColor=colors.white, fontName="Helvetica-Bold")
    s_head_right = ParagraphStyle("kpi_head_right", parent=s_cell_right, textColor=colors.white, fontName="Helvetica-Bold")

    elements = []
    elements.append(Paragraph("Revenue KPI - Patient Source Potential", s_title))
    elements.append(Paragraph(f"Date Range: <b>{from_date} to {to_date}</b> &nbsp;&nbsp;|&nbsp;&nbsp; Unit Scope: <b>{unit_scope}</b>", s_meta))
    elements.append(Paragraph(f"Exported By: <b>{exported_by}</b> &nbsp;&nbsp;|&nbsp;&nbsp; Exported At: <b>{exported_at}</b>", s_meta))
    elements.append(Spacer(1, 6))

    elements.append(Paragraph("Patient Source Summary", s_section))
    summary_data = [[
        Paragraph("Rank", s_head_center),
        Paragraph("Patient Source", s_head_left),
        Paragraph("Source ID", s_head_center),
        Paragraph("Visit Count", s_head_center),
        Paragraph("Patient Count", s_head_center),
        Paragraph("Bill Count", s_head_center),
        Paragraph("Potential Revenue (INR)", s_head_right),
    ]]
    for rec in rows:
        summary_data.append([
            Paragraph(str(rec.get("Rank", "")), s_cell_center),
            Paragraph(str(rec.get("SourceName", "")), s_cell_left),
            Paragraph(str(rec.get("SourceID", 0)), s_cell_center),
            Paragraph(str(rec.get("VisitCount", 0)), s_cell_center),
            Paragraph(str(rec.get("PatientCount", 0)), s_cell_center),
            Paragraph(str(rec.get("BillCount", 0)), s_cell_center),
            Paragraph(fmt_inr(rec.get("PotentialRevenue", 0.0)), s_cell_right),
        ])

    tbl = Table(summary_data, repeatRows=1, colWidths=[14 * mm, 72 * mm, 18 * mm, 24 * mm, 26 * mm, 22 * mm, 38 * mm])
    tbl.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("GRID", (0, 0), (-1, -1), 0.25, colors.HexColor("#cbd5e1")),
        ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
        ("ROWBACKGROUNDS", (0, 1), (-1, -1), [colors.white, colors.HexColor("#f8fafc")]),
        ("TOPPADDING", (0, 0), (-1, -1), 4),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 4),
    ]))
    elements.append(tbl)

    elements.append(PageBreak())
    elements.append(Paragraph("Details", s_section))
    detail_data = [[
        Paragraph("NetAmount (INR)", s_head_right),
        Paragraph("Patient", s_head_left),
        Paragraph("Reg No", s_head_left),
        Paragraph("Source", s_head_left),
    ]]
    if detail_rows:
        for rec in detail_rows:
            detail_data.append([
                Paragraph(fmt_inr(rec.get("NetAmount", 0.0)), s_cell_right),
                Paragraph(str(rec.get("Patient", "") or ""), s_cell_left),
                Paragraph(str(rec.get("Reg No", "") or ""), s_cell_left),
                Paragraph(str(rec.get("Source", "") or ""), s_cell_left),
            ])
    else:
        detail_data.append([
            Paragraph("0", s_cell_right),
            Paragraph("No rows", s_cell_left),
            Paragraph("", s_cell_left),
            Paragraph("", s_cell_left),
        ])

    detail_tbl = Table(detail_data, repeatRows=1, colWidths=[45 * mm, 95 * mm, 55 * mm, 82 * mm])
    detail_tbl.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("GRID", (0, 0), (-1, -1), 0.25, colors.HexColor("#cbd5e1")),
        ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
        ("ROWBACKGROUNDS", (0, 1), (-1, -1), [colors.white, colors.HexColor("#f8fafc")]),
        ("TOPPADDING", (0, 0), (-1, -1), 4),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 4),
    ]))
    elements.append(detail_tbl)

    footer_note = f"Date Range: {from_date} to {to_date} | Unit: {unit_scope} | Exported by: {exported_by} | Exported at: {exported_at}"

    def _on_page(canvas, doc_obj):
        canvas.saveState()
        canvas.setStrokeColor(colors.HexColor("#cbd5e1"))
        canvas.setLineWidth(0.5)
        canvas.line(doc_obj.leftMargin, 10 * mm, doc_obj.pagesize[0] - doc_obj.rightMargin, 10 * mm)
        canvas.setFont("Helvetica", 8)
        canvas.setFillColor(colors.HexColor("#475569"))
        canvas.drawString(doc_obj.leftMargin, 6.5 * mm, footer_note)
        canvas.drawRightString(doc_obj.pagesize[0] - doc_obj.rightMargin, 6.5 * mm, f"Page {doc_obj.page}")
        canvas.restoreState()

    doc.build(elements, onFirstPage=_on_page, onLaterPages=_on_page)
    buffer.seek(0)
    return buffer


@app.route('/export_revenue_patient_source_pdf')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def export_revenue_patient_source_pdf():
    from_date = request.args.get('from_date')
    to_date = request.args.get('to_date')
    unit_param = request.args.get('unit')
    refresh_flag = _is_truthy(request.args.get('refresh') or request.args.get('force') or request.args.get('refresh_today'))

    if not from_date or not to_date:
        return jsonify({"status": "error", "message": "Missing date range"}), 400

    allowed_units = _analytics_allowed_units_for_session()
    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403

    try:
        target_units, scope_label = _resolve_patient_source_scope(allowed_units, unit_param)
    except PermissionError as e:
        return jsonify({"status": "error", "message": str(e)}), 403

    payload = _build_patient_source_kpi(target_units, from_date, to_date, refresh_flag=refresh_flag)
    rows = payload.get("rows") or []
    if not rows:
        return jsonify({"status": "error", "message": "No patient source data available for selected range"}), 404
    detail_rows = _build_patient_source_detail_rows(
        target_units, from_date, to_date, refresh_flag=refresh_flag
    )

    exported_by = session.get("username") or session.get("user") or "Unknown"
    buffer = _build_revenue_patient_source_pdf_buffer(
        rows=rows,
        detail_rows=detail_rows,
        from_date=from_date,
        to_date=to_date,
        unit_scope=scope_label,
        exported_by=exported_by,
    )
    unit_tag = "ALL" if len(target_units) > 1 else target_units[0]
    filename = f"Revenue_PatientSource_{unit_tag}_{from_date}_to_{to_date}.pdf"
    return send_file(buffer, mimetype="application/pdf", as_attachment=True, download_name=filename)


@app.route('/fetch', methods=['POST'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def fetch_data():
    from_date = request.form.get('from_date')
    to_date = request.form.get('to_date')
    refresh_flag = _is_truthy(request.form.get('refresh') or request.form.get('force') or request.form.get('refresh_today'))  # <<< ADD-ONLY

    if not from_date or not to_date:
        return jsonify({"status": "error", "message": "Missing date range"}), 400

    allowed_units = _analytics_allowed_units_for_session()
    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403

    # >>> TODAY REFRESH ADD-ONLY: force live update for today's range if asked
    if refresh_flag and _is_today_range(from_date, to_date):
        forced = _fetch_live_and_refresh_cache(allowed_units, from_date, to_date)
        if forced:
            return jsonify({
                "status": "success",
                "units": allowed_units,
                "records": forced.get("records", 0),
                "summary": forced.get("summary", [])
            })
        # fall through to normal flow if nothing returned

    cached = _cache_get(from_date, to_date)
    if cached:
        filt_summary = [s for s in (cached.get("summary") or []) if str(s.get("Unit","")).upper() in allowed_units]
        return jsonify({
            "status": "success",
            "units": allowed_units,
            "records": sum(int(s.get("Records", 0)) for s in filt_summary) if filt_summary and "Records" in filt_summary[0] else sum(0 for _ in allowed_units),
            "summary": filt_summary
        })

    print(f"Parallel fetching started for {from_date} -> {to_date} (units={allowed_units})")

    all_data = []
    fetch_results = {}

    with ThreadPoolExecutor(max_workers=_revenue_pool_workers(len(allowed_units))) as executor:
        futures = {
            executor.submit(_get_or_fetch_unit, unit, from_date, to_date): unit
            for unit in allowed_units
        }

        for future in as_completed(futures):
            unit = futures[future]
            try:
                df = future.result()
                if df is not None and not df.empty:
                    all_data.append(df)
                    fetch_results[unit] = len(df)
                    print(f"{unit}: {len(df)} rows (cache+live)")
                else:
                    fetch_results[unit] = 0
                    print(f"[WARN] No data for {unit}")
            except Exception as e:
                fetch_results[unit] = 0
                print(f"Error fetching {unit}: {e}")

    if not all_data:
        print("No data fetched from any allowed unit")
        return jsonify({"status": "error", "message": "No data fetched from your units"})

    for i, _df in enumerate(all_data):
        all_data[i] = _df.dropna(axis=1, how='all')

    combined_df = pd.concat(all_data, ignore_index=True, copy=False)

    try:
        summary = (
            combined_df.groupby("Unit")["NetAmount"]
            .sum()
            .reset_index()
            .to_dict(orient="records")
        )
    except Exception as e:
        print(f"[WARN] Summary generation failed: {e}")
        summary = [{"Unit": u, "Records": fetch_results.get(u, 0)} for u in allowed_units]

    print("Parallel fetch completed successfully")

    try:
        _cache_put(from_date, to_date, {
            "summary": summary,
            "units": allowed_units,
            "records": sum(fetch_results.values())
        })
    except Exception:
        pass

    return jsonify({
        "status": "success",
        "units": allowed_units,
        "records": sum(fetch_results.values()),
        "summary": summary
    })

# ============================================================
# Export Revenue to Excel (Multi-Sheet + Summary + INR Formatting) - with date display fix
# ============================================================
@app.route('/export_revenue_excel')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def export_revenue_excel():
    import io
    import math
    import re
    from xlsxwriter.utility import xl_col_to_name

    from_date = request.args.get('from_date')
    to_date = request.args.get('to_date')
    refresh_flag = _is_truthy(request.args.get('refresh') or request.args.get('force') or request.args.get('refresh_today'))

    if not from_date or not to_date:
        return jsonify({"status": "error", "message": "Missing date range"}), 400

    allowed_units = _analytics_allowed_units_for_session()
    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403

    print(f"Exporting revenue data for {from_date} -> {to_date} (units={allowed_units})")

    # --- Helpers ---
    def clean_text_val(val):
        if pd.isna(val): return ""
        return str(val).replace('\xa0', ' ').strip()
    
    def get_safe_sheet_name(u_name):
        s = re.sub(r'[\[\]:*?/\\]', '_', u_name.upper())
        return s[:31]

    def process_df_for_export(df_in, u_name):
        if df_in is not None and not df_in.empty:
            df_in = _clean_df_columns(df_in)
            df_in["Unit"] = get_safe_sheet_name(u_name)
            return df_in
        return None

    # --- 1. Fetch Data ---
    all_data = {}
    
    if refresh_flag and _is_today_range(from_date, to_date):
        _fetch_live_and_refresh_cache(allowed_units, from_date, to_date)
        
    with ThreadPoolExecutor(max_workers=_revenue_pool_workers(len(allowed_units))) as executor:
        futures = {executor.submit(_get_or_fetch_unit, unit, from_date, to_date): unit for unit in allowed_units}
        for future in as_completed(futures):
            unit = futures[future]
            try:
                df = future.result()
                df = process_df_for_export(df, unit)
                if df is not None:
                    all_data[unit.upper()] = df
            except Exception as e:
                print(f"Error fetching {unit}: {e}")

    if not all_data:
        return jsonify({"status": "error", "message": "No data available to export"}), 400

    # --- 2. Standardize Columns ---
    # Keep requested unit-wise detail sheet order.
    metric_cols = [
        "LabAmount", "RadioAmount", "HospAmount", "HospitalConsumables",
        "PHAmount", "PHRetAmount", "DiscountAmount", "NetAmount"
    ]
    final_columns = [
        "PatientCategory", "PatientType", "TypeOfVisit", "CorpType", "Doctor", "Dept",
        "Registration_No", "PatientName", "VisitNo", "VisitDate", "DischargeDate",
        "billdate", "billno",
        "LabAmount", "RadioAmount", "HospAmount", "HospitalConsumables",
        "PHAmount", "PHRetAmount", "DiscountAmount", "NetAmount",
        "BillTypeDescription", "CancelStatus", "Bill_ID"
    ]

    standardized_data = {}
    
    for unit, df in all_data.items():
        std_df = df.copy()
        cols_lower = {c.lower(): c for c in std_df.columns}

        def map_col(target, candidates):
            found = next((cols_lower[c.lower()] for c in candidates if c.lower() in cols_lower), None)
            return std_df[found] if found else None

        new_df = pd.DataFrame()
        new_df["Unit"] = std_df["Unit"]

        # Text Columns
        dept_series = map_col("Dept", ["Department", "DeptName", "Dept", "Dept_Name", "DepartmentName"])
        new_df["Dept"] = dept_series.apply(clean_text_val) if dept_series is not None else "Unknown"

        doctor_series = map_col("Doctor", ["DoctorName", "Doctor", "Consultant", "DoctorIncharge", "DoctorInCharge", "Doctor_Name"])
        new_df["Doctor"] = doctor_series.apply(clean_text_val) if doctor_series is not None else ""

        visit_series = map_col("TypeOfVisit", ["TypeOfVisit", "VisitType", "Visit Type"])
        raw_visits = visit_series.apply(clean_text_val) if visit_series is not None else pd.Series(["Other"] * len(new_df))
        
        def norm_visit(v):
            v_up = v.upper()
            if "OPD" in v_up or "WALK" in v_up: return "OPD"
            if "IPD" in v_up: return "IPD"
            if "DPV" in v_up: return "DPV"
            if "HCV" in v_up: return "HCV"
            return "OPD" 
        new_df["TypeOfVisit"] = raw_visits.apply(norm_visit)

        pt_series = map_col("PatientType", ["PatientType", "Patient_Type", "PatType"])
        new_df["PatientType"] = pt_series.apply(clean_text_val) if pt_series is not None else "Unknown"

        corp_series = map_col("CorpType", ["CorpType", "CorporateName", "Company"])
        new_df["CorpType"] = corp_series.apply(clean_text_val) if corp_series is not None else "Unknown"

        name_series = map_col("PatientName", ["PatientName", "Patient_Name", "Name"])
        new_df["PatientName"] = name_series.apply(clean_text_val) if name_series is not None else ""

        billno_series = map_col("billno", ["BillNo", "Bill_No", "InvoiceNo", "billno"])
        new_df["billno"] = billno_series.apply(clean_text_val) if billno_series is not None else ""

        visitno_series = map_col("VisitNo", ["VisitNo", "Visit_No", "VisitID", "Visit_ID", "IPDNo", "OPDNo"])
        new_df["VisitNo"] = visitno_series.apply(clean_text_val) if visitno_series is not None else ""

        reg_series = map_col("Registration_No", ["Regno", "Reg_No", "UHID", "MRNo", "Registration_No", "RegistrationNo"])
        new_df["Registration_No"] = reg_series.apply(clean_text_val) if reg_series is not None else ""

        cancel_series = map_col("CancelStatus", ["CancelStatus", "IsCancelled", "Status", "Cancelled"])
        new_df["CancelStatus"] = cancel_series.apply(clean_text_val) if cancel_series is not None else ""

        bill_id_series = map_col("Bill_ID", ["Bill_ID", "BillID", "BillId", "Bill_Id"])
        new_df["Bill_ID"] = bill_id_series.apply(clean_text_val) if bill_id_series is not None else ""
        
        # Map Description for Filtering
        desc_series = map_col("BillTypeDescription", ["BillTypeDescription", "Bill_Description", "BillDesc", "Bill_Desc", "Description"])
        new_df["BillTypeDescription"] = desc_series.apply(clean_text_val) if desc_series is not None else "Unknown"

        # Map Patient Category for Cash/Cashless Summary
        cat_series = map_col("PatientCategory", ["PatientCategory", "Patient_Category", "Category", "PayType"])
        new_df["PatientCategory"] = cat_series.apply(clean_text_val) if cat_series is not None else "Unknown"
        # ----------------------

        # --- FIXED DATE CONVERSION LOGIC ---
        def safe_to_date(series, col_label: str = "unknown"):
            """
            Convert a mixed/text/numeric date column to datetime, without blowing up
            on crazy numeric outliers (e.g. garbage epoch values).
            """
            if series is None:
                return pd.Series([pd.NaT] * len(new_df))

            def _to_datetime_epoch(num_series: pd.Series, unit: str) -> pd.Series:
                """
                Parse epoch-like numeric values with a stable integer path.
                This avoids float overflow edge-cases that can corrupt dates to 1970.
                """
                vals = pd.to_numeric(num_series, errors="coerce")
                vals = vals.where(np.isfinite(vals))
                vals = pd.Series(pd.array(vals.round(), dtype="Int64"), index=vals.index)
                return pd.to_datetime(vals, unit=unit, errors="coerce")

            s_raw = pd.Series(series)
            s_str = s_raw.astype(str).str.strip()
            time_only_mask = s_str.str.match(r"^\d{1,2}:\d{2}(:\d{2})?(\.\d+)?$")
            s_raw = s_raw.where(~time_only_mask)
            s_str = s_raw.astype(str).str.strip()
            s_str = s_str.str.replace(r"\.0+$", "", regex=True)

            s_num = pd.to_numeric(s_raw, errors="coerce")
            try:
                num_max = s_num.max(skipna=True)
            except Exception:
                num_max = None
            if num_max is not None and pd.notna(num_max) and num_max > 5e12:
                print(
                    f"[WARN] export_revenue_excel: large numeric date in {col_label} "
                    f"(max={num_max}) unit={unit} from={from_date} to={to_date}"
                )

            ymd_mask = s_str.str.match(r"^\d{8}$")
            ymdhms_mask = s_str.str.match(r"^\d{14}$")
            date_like_mask = s_str.str.contains(r"[-/]", regex=True) | s_str.str.contains("T")

            s_direct = pd.to_datetime(s_str.where(date_like_mask), errors="coerce")
            s_direct = s_direct.fillna(pd.to_datetime(s_str.where(ymd_mask), format="%Y%m%d", errors="coerce"))
            s_direct = s_direct.fillna(pd.to_datetime(s_str.where(ymdhms_mask), format="%Y%m%d%H%M%S", errors="coerce"))

            s = s_direct.copy()

            num_mask = s_num.notna() & s.isna()
            if num_mask.any():
                num_vals = s_num[num_mask]
                median_val = num_vals.median()
                with np.errstate(over="ignore", invalid="ignore"):
                    s_num_safe = pd.to_numeric(s_num, errors="coerce")
                    s_num_safe = s_num_safe.where(s_num_safe.between(0, 5e12))
                    try:
                        if median_val >= 1e11:
                            s_num_conv = _to_datetime_epoch(
                                s_num_safe.where((s_num_safe >= 1e12) & (s_num_safe <= 5e12)),
                                "ms",
                            )
                        elif median_val >= 1e9:
                            s_num_conv = _to_datetime_epoch(
                                s_num_safe.where((s_num_safe >= 1e9) & (s_num_safe <= 1e10)),
                                "s",
                            )
                        elif 30000 <= median_val <= 60000:
                            s_num_conv = pd.to_datetime(
                                s_num_safe,
                                unit="D",
                                origin="1899-12-30",
                                errors="coerce",
                            )
                        else:
                            s_num_conv = pd.to_datetime(
                                s_num_safe.where(s_num_safe >= 30000),
                                errors="coerce",
                            )
                    except FloatingPointError as e:
                        print(
                            f"[WARN] export_revenue_excel: numeric date overflow in {col_label} "
                            f"unit={unit} from={from_date} to={to_date}: {e}"
                        )
                        if median_val >= 1e11:
                            s_num_conv = _to_datetime_epoch(
                                s_num_safe.where((s_num_safe >= 1e12) & (s_num_safe <= 5e12)),
                                "ms",
                            )
                        elif median_val >= 1e9:
                            s_num_conv = _to_datetime_epoch(
                                s_num_safe.where((s_num_safe >= 1e9) & (s_num_safe <= 1e10)),
                                "s",
                            )
                        elif 30000 <= median_val <= 60000:
                            s_num_conv = pd.to_datetime(
                                s_num_safe,
                                unit="D",
                                origin="1899-12-30",
                                errors="coerce",
                            )
                        else:
                            s_num_conv = pd.to_datetime(
                                s_num_safe.where(s_num_safe >= 30000),
                                errors="coerce",
                            )
                s = s.fillna(s_num_conv)

            if hasattr(s, "dt"):
                try:
                    s = s.dt.tz_localize(None)
                except Exception:
                    pass
            return s

        new_df["billdate"] = safe_to_date(map_col("BillDate", ["BillDate", "Bill_Date", "Date", "billdate"]), "BillDate")
        new_df["VisitDate"] = safe_to_date(map_col("VisitDate", ["VisitDate", "Visit_Date", "AdmissionDate"]), "VisitDate")
        new_df["DischargeDate"] = safe_to_date(map_col("DischargeDate", ["DischargeDate", "Discharge_Date"]), "DischargeDate")

        # Metric Columns
        for m in metric_cols:
             ser = map_col(m, [m, m.replace("Amount", ""), m.replace("Amount", "_Amount")])
             new_df[m] = pd.to_numeric(ser, errors='coerce').fillna(0.0) if ser is not None else 0.0

        standardized_data[unit] = new_df[final_columns].copy()

    # --- 3. Excel Generation ---
    export_dir = os.path.join("data", "exports")
    os.makedirs(export_dir, exist_ok=True)
    file_name = f"Revenue_Summary_{from_date}_to_{to_date}.xlsx"
    file_path = os.path.join(export_dir, file_name)

    try:
        with pd.ExcelWriter(file_path, engine="xlsxwriter") as writer:
            wb = writer.book
            
            # --- Formats ---
            header_fmt = wb.add_format({"bold": True, "bg_color": "#1e3a8a", "font_color": "white", "align": "center", "valign": "vcenter", "border": 1})
            sub_header_fmt = wb.add_format({"bold": True, "bg_color": "#dbeafe", "font_color": "#1e3a8a", "align": "center", "valign": "vcenter", "border": 1, "font_size": 9})
            
            unit_fmt = wb.add_format({"bold": True, "border": 1, "bg_color": "#e2e8f0", "valign": "vcenter"})
            dept_fmt = wb.add_format({"bold": True, "border": 1, "bg_color": "#f8fafc", "valign": "vcenter"})
            inr_fmt_border = wb.add_format({"num_format": '[$\u20B9-4009] #,##,##0', "align": "right", "border": 1})
            int_fmt_border = wb.add_format({"num_format": '0', "align": "center", "border": 1})
            
            inr_fmt_noborder = wb.add_format({"num_format": '[$\u20B9-4009] #,##,##0', "align": "right"})
            date_fmt_noborder = wb.add_format({"num_format": "yyyy-mm-dd hh:mm:ss", "align": "center"})
            text_fmt_noborder = wb.add_format({"align": "left"})
            border_only_fmt = wb.add_format({"border": 1})

            # ========================
            # TAB 1: GRAND SUMMARY (Overall, Cash, Cashless)
            # ========================
            ws_sum = wb.add_worksheet("Grand Summary")

            # 1. SETUP COLUMN REFERENCES
            # We need the column letter for PatientCategory to filter Cash vs Cashless
            # CHANGE "PatientCategory" below if your column name is different (e.g., "PayType")
            idx_cat = final_columns.index("PatientCategory") 
            col_cat = xl_col_to_name(idx_cat)

            # Get Column Letter for BillTypeDescription (for filtering count)
            idx_desc = final_columns.index("BillTypeDescription")
            col_desc = xl_col_to_name(idx_desc)

            metric_map = {}
            for m in metric_cols:
                idx = final_columns.index(m)
                metric_map[m] = xl_col_to_name(idx)

            col_dept = xl_col_to_name(final_columns.index("Dept"))
            col_visit = xl_col_to_name(final_columns.index("TypeOfVisit"))
            sorted_units = sorted(standardized_data.keys())
            target_visits = ["OPD", "DPV", "HCV", "IPD"]
            target_metrics = ["Count"] + metric_cols

            # 2. DEFINE SECTIONS TO GENERATE
            # Format: (Title, Filter Logic)
            # Filter Logic: None = Overall, "Cash" = Cash Only, "Cashless" = Not Cash
            sections = [
                ("Overall Summary", None), 
                ("Cash Summary", "Cash"), 
                ("Cashless Summary", "Cashless")
            ]

            row_ptr = 0 # Global row pointer to stack tables vertically

            for section_name, filter_type in sections:
                
                # --- SECTION HEADER ---
                # Optional: Add a main header for the section (e.g., "Cash Summary")
                ws_sum.write(row_ptr, 0, section_name.upper(), header_fmt)
                row_ptr += 1

                # --- TABLE HEADERS ---
                # Unit & Dept Headers
                ws_sum.write(row_ptr, 0, "Unit", header_fmt)
                ws_sum.merge_range(row_ptr, 0, row_ptr + 1, 0, "Unit", header_fmt)
                ws_sum.write(row_ptr, 1, "Department", header_fmt)
                ws_sum.merge_range(row_ptr, 1, row_ptr + 1, 1, "Department", header_fmt)

                col_ptr = 2
                for v_type in target_visits:
                    # Merge for Visit Type (OPD, IPD, etc.)
                    ws_sum.merge_range(row_ptr, col_ptr, row_ptr, col_ptr + len(target_metrics) - 1, v_type, header_fmt)
                    for metric in target_metrics:
                        disp = metric.replace("Amount", "")
                        if metric == "HospitalConsumables": disp = "Consum."
                        ws_sum.write(row_ptr + 1, col_ptr, disp, sub_header_fmt)
                        col_ptr += 1
                
                # Move row pointer past headers
                row_ptr += 2 

                # --- DATA ROWS ---
                for unit in sorted_units:
                    df = standardized_data[unit]
                    depts = sorted(df["Dept"].dropna().unique())
                    depts = [d for d in depts if str(d).strip()]
                    if not depts: continue
                    
                    safe_sheet = get_safe_sheet_name(unit)
                    
                    for dept in depts:
                        ws_sum.write(row_ptr, 0, unit, unit_fmt)
                        ws_sum.write(row_ptr, 1, dept, dept_fmt)
                        
                        col_ptr = 2
                        dept_ref = f"$B{row_ptr+1}"
                        
                        # Prepare Sheet References
                        sheet_ref = f"'{safe_sheet}'"
                        range_dept = f"{sheet_ref}!${col_dept}:${col_dept}"
                        range_visit = f"{sheet_ref}!${col_visit}:${col_visit}"
                        range_desc = f"{sheet_ref}!${col_desc}:${col_desc}"
                        range_cat = f"{sheet_ref}!${col_cat}:${col_cat}" # Ref to Patient Category
                        
                        for v_type in target_visits:
                            for metric in target_metrics:
                                
                                # --- FORMULA CONSTRUCTION ---
                                if metric == "Count":
                                    # Base Formula: Dept + Visit Type + BillType='*Hospital Bill*'
                                    # Note: We construct the string parts to inject the Category filter easily
                                    base_criteria = f"{range_dept}, {dept_ref}, {range_visit}, \"{v_type}\", {range_desc}, \"*Hospital Bill*\""
                                    
                                    if filter_type == "Cash":
                                        formula = f"=COUNTIFS({base_criteria}, {range_cat}, \"Cash\")"
                                    elif filter_type == "Cashless":
                                        formula = f"=COUNTIFS({base_criteria}, {range_cat}, \"<>Cash\")"
                                    else: # Overall
                                        formula = f"=COUNTIFS({base_criteria})"
                                        
                                    ws_sum.write_formula(row_ptr, col_ptr, formula, int_fmt_border)
                                
                                else:
                                    # Sum Metrics
                                    col_m = metric_map[metric]
                                    range_metric = f"{sheet_ref}!${col_m}:${col_m}"
                                    
                                    base_criteria = f"{range_dept}, {dept_ref}, {range_visit}, \"{v_type}\""
                                    
                                    if filter_type == "Cash":
                                        formula = f"=SUMIFS({range_metric}, {base_criteria}, {range_cat}, \"Cash\")"
                                    elif filter_type == "Cashless":
                                        formula = f"=SUMIFS({range_metric}, {base_criteria}, {range_cat}, \"<>Cash\")"
                                    else: # Overall
                                        formula = f"=SUMIFS({range_metric}, {base_criteria})"
                                        
                                    ws_sum.write_formula(row_ptr, col_ptr, formula, inr_fmt_border)
                                    
                                col_ptr += 1
                        row_ptr += 1
                        
                # Add spacing between tables
                row_ptr += 3 

            # Final Formatting
            ws_sum.freeze_panes(3, 2) # Adjusted freeze to account for section header
            ws_sum.set_column(0, 0, 15)
            ws_sum.set_column(1, 1, 30)
            ws_sum.set_column(2, col_ptr, 12)

            # ========================
            # TABS 2+: RAW SHEETS
            # ========================
            for unit in sorted_units:
                sheet_name = get_safe_sheet_name(unit)
                df = standardized_data[unit]
                
                df.to_excel(writer, index=False, sheet_name=sheet_name)
                ws = writer.sheets[sheet_name]
                
                last_row = len(df)
                last_col = len(final_columns) - 1

                for idx, col in enumerate(final_columns):
                    ws.write(0, idx, col, header_fmt)
                    col_lower = col.lower()
                    
                    if "amount" in col_lower or "net" in col_lower or "consumables" in col_lower:
                        ws.set_column(idx, idx, 16, inr_fmt_noborder)
                    elif "date" in col_lower:
                        ws.set_column(idx, idx, 26, date_fmt_noborder) 
                    elif "department" in col_lower or "dept" in col_lower or "doctor" in col_lower or "name" in col_lower or "description" in col_lower or "registration" in col_lower:
                        ws.set_column(idx, idx, 28, text_fmt_noborder)
                    else:
                        ws.set_column(idx, idx, 15, text_fmt_noborder)

                if last_row > 0:
                    ws.conditional_format(1, 0, last_row, last_col, {
                        'type': 'formula', 
                        'criteria': '=TRUE', 
                        'format': border_only_fmt
                    })

                ws.freeze_panes(1, 0)

        print(f"Excel Export Complete -> {file_path}")
        return send_file(file_path, as_attachment=True)

    except Exception as e:
        print(f"Excel export failed: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({"status": "error", "message": "Export failed"}), 500
# ============================================================
# NEW: Breakdown (Department / Patient Category / TypeOfVisit) for a Unit
# ============================================================
@app.route('/breakdown', methods=['POST'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def breakdown():
    from_date  = request.form.get('from_date')
    to_date    = request.form.get('to_date')
    unit       = (request.form.get('unit') or '').strip().upper()
    mode       = (request.form.get('mode') or 'department').lower()
    department = (request.form.get('department') or '').strip()
    pay_split  = (request.form.get('pay_split') or '').strip().lower() in ('1','true','yes','y')
    refresh_flag = _is_truthy(request.form.get('refresh') or request.form.get('force'))

    if not (from_date and to_date and unit):
        return jsonify({"status": "error", "message": "Missing inputs"}), 400

    allowed_units = _analytics_allowed_units_for_session()
    if unit not in allowed_units:
        return jsonify({"status": "error", "message": f"Unit {unit} not permitted for your role"}), 403

    # --- 1. Fetch Data (Cache First, then Live) ---
    df = None
    if not refresh_flag:
        df = _rev_cache_get(unit, from_date, to_date)
    
    if df is None or refresh_flag:
        print(f"Fetching live data for breakdown: {unit}")
        df = _fetch_revenue_limited(unit, from_date, to_date)
        if df is not None and not df.empty:
            # Clean columns immediately upon fetch
            df.columns = [str(c).strip() for c in df.columns]
            df["Unit"] = unit
            _rev_cache_put_async(unit, from_date, to_date, df)

    if df is None or df.empty:
        return jsonify({"status": "error", "message": "No data"}), 404

    # Ensure columns are clean even if loaded from cache
    df.columns = [str(c).strip() for c in df.columns]
    
    print(f"Breakdown: Using {len(df)} rows for {unit}/{mode}")

    # --- 2. Special Logic: Department Pay Split (Cash vs Cashless) ---
    if mode == "department" and pay_split:
        # Create local map for this block
        cols_map = {str(c).strip().lower(): c for c in df.columns}
        
        dept_candidates = ["Department", "DeptName", "DepartmentName", "Dept", "Dept_Name"]
        dept_col = next((cols_map[c.lower()] for c in dept_candidates if c.lower() in cols_map), None)
        
        val_candidates = ["netamount", "amount"]
        value_col = next((cols_map[c] for c in val_candidates if c in cols_map), None)

        if not dept_col or not value_col:
             return jsonify({"status": "error", "message": "Columns not found for Pay Split"}), 400

        # Determine Pay Category
        def _paycat_row(row):
            # Try to use PayType ID if available
            if 'PayType' in row and pd.notna(row['PayType']):
                try:
                    return 'Cash' if int(row['PayType']) == 1 else 'Cashless'
                except: pass
            
            # Fallback to text search
            for k in ['PayCategory','PaymentCategory','PaymentType','PayMode','Mode','Category','PatientCategory']:
                if k in row and pd.notna(row[k]):
                    s = str(row[k]).strip().lower()
                    if any(x in s for x in ['cashless', 'corporate', 'tpa', 'insurance', 'credit']): return 'Cashless'
                    if 'cash' in s: return 'Cash'
            return 'Cash'

        tmp = df.copy()
        tmp['PayCategoryBI'] = tmp.apply(_paycat_row, axis=1)

        # Aggregate
        grp = tmp.groupby([dept_col, 'PayCategoryBI'])[value_col].sum().reset_index()
        pv = grp.pivot(index=dept_col, columns='PayCategoryBI', values=value_col).fillna(0.0)
        
        if 'Cash' not in pv.columns: pv['Cash'] = 0.0
        if 'Cashless' not in pv.columns: pv['Cashless'] = 0.0
        
        pv['__Total__'] = pv['Cash'] + pv['Cashless']
        pv = pv.sort_values('__Total__', ascending=False).drop(columns='__Total__')
        
        # Calculate Bill Counts (Unique Patients)
        bill_counts = {}
        pat_candidates = ["Regno", "Reg_No", "PatientID", "Patient_ID", "RegistrationNo", "UHID", "BillNo", "Bill_No", "InvoiceNo"]
        pat_col = next((cols_map[c.lower()] for c in pat_candidates if c.lower() in cols_map), None)

        labels = pv.index.astype(str).tolist()
        if pat_col:
            for d_name in labels:
                d_df = tmp[tmp[dept_col] == d_name]
                bill_counts[d_name] = {
                    'cash': int(d_df[d_df['PayCategoryBI'] == 'Cash'][pat_col].nunique()),
                    'cashless': int(d_df[d_df['PayCategoryBI'] == 'Cashless'][pat_col].nunique())
                }

        return jsonify({
            "status": "success",
            "unit": unit,
            "labels": labels,
            "cash": pv['Cash'].astype(float).tolist(),
            "cashless": pv['Cashless'].astype(float).tolist(),
            "bill_counts": bill_counts
        })

    # --- 3. Standard Breakdown Logic (Uses Helper for Robustness) ---
    
    # If a specific department filter is applied (for Category view)
    if department and mode == "category":
        cols_map = {str(c).strip().lower(): c for c in df.columns}
        dept_candidates = ["Department", "DeptName", "DepartmentName", "Dept", "Dept_Name"]
        dept_col = next((cols_map[c.lower()] for c in dept_candidates if c.lower() in cols_map), None)
        if dept_col:
            dep_key = department.casefold()
            tmp = df.copy()
            tmp["_depkey"] = tmp[dept_col].astype(str).str.strip().str.casefold()
            df = tmp[tmp["_depkey"] == dep_key].drop(columns=["_depkey"], errors="ignore")

    # Use the helper function (ensures consistency with background warmer)
    payload = _compute_breakdown_payload(df, mode)

    if not payload:
        return jsonify({
            "status": "error", 
            "message": f"Could not aggregate data for mode: {mode}. Check logs."
        }), 400

    # Cache result for dashboard speed (unless filtered by dept)
    if not department:
        try:
            _bput(from_date, to_date, unit, mode, payload)
        except Exception:
            pass

    return jsonify({
        "status": "success",
        "labels": payload["labels"],
        "values": payload["values"],
        "group_col": payload["group_col"],
        "total_revenue": payload["true_total"], # Returns correct total of all rows
        "unit": unit
    })
# ============================================================
# NEW: Revenue Segregation API (Lab, Radio, Hosp, PH, PHRet, Discount)
# ============================================================
@app.route('/api/revenue_segregation', methods=['POST'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_revenue_segregation():
    """
    Returns aggregated revenue component data (Lab, Radio, Hospital, Pharmacy, etc.)
    for each unit across the specified date range.
    """
    from_date = request.form.get('from_date')
    to_date = request.form.get('to_date')
    refresh_flag = _is_truthy(request.form.get('refresh') or request.form.get('force') or request.form.get('refresh_today'))

    if not from_date or not to_date:
        return jsonify({"status": "error", "message": "Missing date range"}), 400

    allowed_units = _analytics_allowed_units_for_session()
    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403

    print(f"Fetching revenue segregation: {from_date} to {to_date} (units={allowed_units})")

    # Fetch data for all allowed units in parallel
    all_data = {}
    with ThreadPoolExecutor(max_workers=_revenue_pool_workers(len(allowed_units))) as executor:
        futures = {
            executor.submit(
                _fetch_revenue_limited if (refresh_flag and _is_today_range(from_date, to_date)) else _get_or_fetch_unit,
                unit, from_date, to_date
            ): unit for unit in allowed_units
        }
        for future in as_completed(futures):
            unit = futures[future]
            try:
                df = future.result()
                if df is not None and not df.empty:
                    df["Unit"] = unit.upper()
                    all_data[unit.upper()] = df
                    if refresh_flag and _is_today_range(from_date, to_date):
                        _rev_cache_put_async(unit, from_date, to_date, df)
                    print(f"{unit}: {len(df)} records")
            except Exception as e:
                print(f"Error fetching {unit}: {e}")

    if not all_data:
        return jsonify({"status": "error", "message": "No data available"}), 404

    # Column name mappings for different database schemas
    # This handles variations in column names across different units
    component_columns = {
        "LabAmount": ["LabAmount", "Lab_Amount", "LabAmt", "Lab"],
        "RadioAmount": ["RadioAmount", "Radio_Amount", "RadioAmt", "Radiology", "RadiologicalAmount"],
        "HospAmount": ["HospAmount", "Hosp_Amount", "HospitalAmount", "Hospital_Amount", "HospAmt"],
        "PHAmount": ["PHAmount", "PH_Amount", "PharmacyAmount", "Pharmacy_Amount", "PharmAmt"],
        "PHRetAmount": ["PHRetAmount", "PH_Ret_Amount", "PharmacyReturnAmount", "PH_Return_Amount", "PHReturn"],
        "DiscountAmount": ["DiscountAmount", "Discount_Amount", "DiscAmt", "Discount"],
        "HospitalConsumables": ["HospitalConsumables", "Hospital_Consumables", "HospConsumables", "Hosp_ConsumableAmount"]
    }

    result = {}
    
    for unit, df in all_data.items():
        unit_totals = {}
        
        for component, possible_cols in component_columns.items():
            # Find the actual column name in the dataframe
            col_name = next((c for c in possible_cols if c in df.columns), None)
            
            if col_name:
                try:
                    # Sum the column, handling any non-numeric values
                    total = pd.to_numeric(df[col_name], errors='coerce').fillna(0).sum()
                    unit_totals[component] = float(total)
                except Exception as e:
                    print(f"[WARN] Error processing {col_name} for {unit}: {e}")
                    unit_totals[component] = 0.0
            else:
                # Column not found in this unit's data
                unit_totals[component] = 0.0
                print(f"Column not found for {component} in {unit} (tried: {', '.join(possible_cols)})")
        
        result[unit] = unit_totals

    print(f"Revenue segregation completed for {len(result)} units")
    
    return jsonify({
        "status": "success",
        "data": result,
        "from_date": from_date,
        "to_date": to_date
    })


