def _fund_snapshot_payload(entry_date: date, firm_acl: dict):
    carried_forward_from = None
    daily_memory = []
    master_accounts = []
    lock_state = _fund_snapshot_edit_state(entry_date)
    with _get_login_db_connection() as conn:
        _ensure_fund_tracker_tables(conn)
        cursor = conn.cursor()
        daily_raw = _fund_fetch_rows_for_date(
            cursor,
            "HID_Fund_Daily_Position",
            "EntryDate, FirmName, BankName, AccountType, AccountLast4, CreditLimit, OpeningBalance, Receipts, PaymentsUsed, ClosingBalance, Remarks, UpdatedBy, UpdatedAt",
            entry_date,
            firm_acl,
        )
        wc_raw = _fund_fetch_rows_for_date(
            cursor,
            "HID_Fund_WC_Loan_Position",
            "EntryDate, FirmName, BankName, FacilityType, SanctionLimit, DrawingPower, Utilised, AvailableLimit, ROIPct, DueDate, Remarks, UpdatedBy, UpdatedAt",
            entry_date,
            firm_acl,
        )
        fdr_raw = _fund_fetch_rows_for_date(
            cursor,
            "HID_Fund_FDR_Tracker",
            "EntryDate, FirmName, BankName, FdrNo, FdrAmount, StartDate, MaturityDate, ROIPct, LienFlag, LinkedLoan, Remarks, UpdatedBy, UpdatedAt",
            entry_date,
            firm_acl,
        )
        daily_memory = _fund_fetch_daily_memory_profiles(cursor, entry_date, firm_acl)
        master_accounts = _fund_fetch_master_accounts(cursor, firm_acl, only_active=True)
        if not daily_raw:
            prev_date, prev_daily_rows = _fund_fetch_latest_daily_before(cursor, entry_date, firm_acl)
            if prev_date and prev_daily_rows:
                carried_forward_from = prev_date
                daily_raw = []
                for prev in prev_daily_rows:
                    carried_closing = _fund_parse_decimal(prev.get("ClosingBalance"))
                    daily_raw.append({
                        "EntryDate": entry_date,
                        "FirmName": prev.get("FirmName"),
                        "BankName": prev.get("BankName"),
                        "AccountType": prev.get("AccountType"),
                        "AccountLast4": prev.get("AccountLast4"),
                        "CreditLimit": prev.get("CreditLimit"),
                        "OpeningBalance": carried_closing,
                        "Receipts": 0.0,
                        "PaymentsUsed": 0.0,
                        "ClosingBalance": carried_closing,
                        "Remarks": "",
                        "UpdatedBy": prev.get("UpdatedBy"),
                        "UpdatedAt": None,
                    })

    def _iso_date(val):
        if isinstance(val, datetime):
            return val.date().isoformat()
        if isinstance(val, date):
            return val.isoformat()
        return None

    def _iso_datetime(val):
        if isinstance(val, datetime):
            return val.isoformat()
        return None

    daily_rows = []
    for row in daily_raw:
        opening = _fund_parse_decimal(row.get("OpeningBalance"))
        receipts = _fund_parse_decimal(row.get("Receipts"))
        payments = _fund_parse_decimal(row.get("PaymentsUsed"))
        closing_raw = row.get("ClosingBalance")
        closing = _fund_parse_decimal(closing_raw, opening + receipts - payments) if closing_raw is not None else (opening + receipts - payments)
        daily_rows.append({
            "entry_date": _iso_date(row.get("EntryDate")) or entry_date.isoformat(),
            "firm_name": _normalize_firm_name(row.get("FirmName")),
            "bank_name": _fund_text(row.get("BankName"), 120),
            "account_type": _fund_text(row.get("AccountType"), 40),
            "account_last4": _fund_text(row.get("AccountLast4"), 20),
            "credit_limit": round(_fund_parse_decimal(row.get("CreditLimit")), 2),
            "opening_balance": round(opening, 2),
            "receipts": round(receipts, 2),
            "payments_used": round(payments, 2),
            "closing_balance": round(closing, 2),
            "remarks": _fund_text(row.get("Remarks"), 500),
            "updated_by": _fund_text(row.get("UpdatedBy"), 100),
            "updated_at": _iso_datetime(row.get("UpdatedAt")),
        })

    wc_rows = []
    for row in wc_raw:
        sanction = _fund_parse_decimal(row.get("SanctionLimit"))
        utilised = _fund_parse_decimal(row.get("Utilised"))
        available_raw = row.get("AvailableLimit")
        available = _fund_parse_decimal(available_raw, sanction - utilised) if available_raw is not None else (sanction - utilised)
        wc_rows.append({
            "entry_date": _iso_date(row.get("EntryDate")) or entry_date.isoformat(),
            "firm_name": _normalize_firm_name(row.get("FirmName")),
            "bank_name": _fund_text(row.get("BankName"), 120),
            "facility_type": _fund_text(row.get("FacilityType"), 80),
            "sanction_limit": round(sanction, 2),
            "drawing_power": round(_fund_parse_decimal(row.get("DrawingPower")), 2),
            "utilised": round(utilised, 2),
            "available_limit": round(available, 2),
            "roi_pct": round(_fund_parse_decimal(row.get("ROIPct")), 4),
            "due_date": _iso_date(row.get("DueDate")),
            "remarks": _fund_text(row.get("Remarks"), 500),
            "updated_by": _fund_text(row.get("UpdatedBy"), 100),
            "updated_at": _iso_datetime(row.get("UpdatedAt")),
        })

    fdr_rows = []
    for row in fdr_raw:
        fdr_rows.append({
            "entry_date": _iso_date(row.get("EntryDate")) or entry_date.isoformat(),
            "firm_name": _normalize_firm_name(row.get("FirmName")),
            "bank_name": _fund_text(row.get("BankName"), 120),
            "fdr_no": _fund_text(row.get("FdrNo"), 200),
            "fdr_amount": round(_fund_parse_decimal(row.get("FdrAmount")), 2),
            "start_date": _iso_date(row.get("StartDate")),
            "maturity_date": _iso_date(row.get("MaturityDate")),
            "roi_pct": round(_fund_parse_decimal(row.get("ROIPct")), 4),
            "lien_flag": _fund_text(row.get("LienFlag"), 10),
            "linked_loan": _fund_text(row.get("LinkedLoan"), 200),
            "remarks": _fund_text(row.get("Remarks"), 500),
            "updated_by": _fund_text(row.get("UpdatedBy"), 100),
            "updated_at": _iso_datetime(row.get("UpdatedAt")),
        })

    dashboard_rows = _build_fund_dashboard_rows(daily_raw, wc_raw, fdr_raw, firm_acl)
    totals = {
        "ca_balance": round(sum(row["ca_balance"] for row in dashboard_rows), 2),
        "wc_available": round(sum(row["wc_available"] for row in dashboard_rows), 2),
        "fdr_value": round(sum(row["fdr_value"] for row in dashboard_rows), 2),
    }
    totals["net_fund_position"] = round(totals["ca_balance"] + totals["wc_available"] + totals["fdr_value"], 2)
    totals["status"] = "ALERT" if totals["net_fund_position"] < 0 else "OK"

    return {
        "date": entry_date.isoformat(),
        "carried_forward_from": (
            carried_forward_from.isoformat()
            if isinstance(carried_forward_from, (date, datetime))
            else None
        ),
        "daily_rows": daily_rows,
        "daily_memory": daily_memory,
        "master_accounts": master_accounts,
        "wc_rows": wc_rows,
        "fdr_rows": fdr_rows,
        "dashboard_rows": dashboard_rows,
        "totals": totals,
        "allowed_firms": firm_acl.get("firms") or [],
        "allow_all_firms": bool(firm_acl.get("all")),
        **lock_state,
    }

