@app.route('/api/fund_position/data')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_fund_position_data():
    entry_date = _fund_parse_date_value(request.args.get("date"), datetime.now(tz=LOCAL_TZ).date())
    if not entry_date:
        _audit_log_event(
            "fund_position",
            "load_snapshot",
            status="error",
            entity_type="fund_snapshot",
            summary="Invalid date",
        )
        return jsonify({"status": "error", "message": "Invalid date"}), 400

    firm_acl = _allowed_fund_firms_for_session()
    if not firm_acl.get("all") and not (firm_acl.get("firms") or []):
        _audit_log_event(
            "fund_position",
            "load_snapshot",
            status="error",
            entity_type="fund_snapshot",
            entity_id=entry_date.isoformat(),
            summary="No firm access assigned",
        )
        return jsonify({"status": "error", "message": "No firm access assigned"}), 403

    try:
        payload = _fund_snapshot_payload(entry_date, firm_acl)
    except Exception as e:
        _audit_log_event(
            "fund_position",
            "load_snapshot",
            status="error",
            entity_type="fund_snapshot",
            entity_id=entry_date.isoformat(),
            summary="Failed to load snapshot",
            details={"error": str(e)},
        )
        return jsonify({"status": "error", "message": f"Failed to load snapshot: {e}"}), 500
    _audit_log_event(
        "fund_position",
        "load_snapshot",
        status="success",
        entity_type="fund_snapshot",
        entity_id=entry_date.isoformat(),
        summary=f"Snapshot loaded ({entry_date.isoformat()})",
        details={
            "is_edit_locked": payload.get("is_edit_locked"),
            "daily_rows": len(payload.get("daily_rows") or []),
            "wc_rows": len(payload.get("wc_rows") or []),
            "fdr_rows": len(payload.get("fdr_rows") or []),
        },
    )
    return jsonify({"status": "success", **payload})

def _fund_build_history_export_payload(from_date: date, to_date: date, firm_acl: dict, exported_by: str):
    timeline = _fund_build_range_timeline(from_date, to_date, firm_acl)
    history_rows = _fund_build_history_trace_rows(timeline)
    pdf_bytes = _build_fund_position_history_pdf(from_date, to_date, timeline, history_rows, exported_by, firm_acl)
    return {
        "timeline": timeline,
        "history_rows": history_rows,
        "pdf_bytes": pdf_bytes,
        "snapshot_days": sum(1 for row in timeline if row.get("has_entry")),
        "daily_rows": sum(len((row or {}).get("daily_rows") or []) for row in timeline),
        "wc_rows": sum(len((row or {}).get("wc_rows") or []) for row in timeline),
        "fdr_rows": sum(len((row or {}).get("fdr_rows") or []) for row in timeline),
    }


def _fund_parse_email_recipients(raw_value) -> list[str]:
    tokens = []
    if isinstance(raw_value, list):
        for item in raw_value:
            text = str(item or "").strip()
            if text:
                tokens.append(text)
    else:
        text = str(raw_value or "").strip()
        if text:
            tokens.extend([part.strip() for part in re.split(r"[,\n;]+", text) if part.strip()])

    clean = []
    seen = set()
    for token in tokens:
        email = token.strip().lower()
        if not email or email in seen:
            continue
        seen.add(email)
        clean.append(email)
    return clean


def _fund_is_valid_email(email: str) -> bool:
    if not email:
        return False
    return bool(re.match(r"^[A-Z0-9._%+\-]+@[A-Z0-9.\-]+\.[A-Z]{2,}$", email, flags=re.IGNORECASE))


