def _fund_env_int(name: str, default: int, min_value: int | None = None, max_value: int | None = None) -> int:
    raw = os.getenv(name, str(default))
    try:
        value = int(str(raw).strip())
    except Exception:
        value = int(default)
    if min_value is not None:
        value = max(min_value, value)
    if max_value is not None:
        value = min(max_value, value)
    return value


FUND_POSITION_SCHEDULE_ENABLED = str(os.getenv("FUND_POSITION_SCHEDULE_ENABLED", "1")).strip().lower() in {"1", "true", "yes", "on"}
FUND_POSITION_SCHEDULE_HOUR = _fund_env_int("FUND_POSITION_SCHEDULE_HOUR", 0, 0, 23)
FUND_POSITION_SCHEDULE_MINUTE = _fund_env_int("FUND_POSITION_SCHEDULE_MINUTE", 10, 0, 59)
FUND_POSITION_SCHEDULE_SECOND = _fund_env_int("FUND_POSITION_SCHEDULE_SECOND", 0, 0, 59)
FUND_POSITION_SCHEDULE_CATCHUP_MAX_HOURS = _fund_env_int("FUND_POSITION_SCHEDULE_CATCHUP_MAX_HOURS", 30, 1, 168)


def _fund_schedule_as_local_naive(dt_val: datetime | None) -> datetime | None:
    if not isinstance(dt_val, datetime):
        return None
    if dt_val.tzinfo is not None:
        dt_val = dt_val.astimezone(LOCAL_TZ).replace(tzinfo=None)
    return dt_val.replace(microsecond=0)


def _next_fund_position_schedule_target(now: datetime | None = None) -> datetime:
    now = now or datetime.now(tz=LOCAL_TZ)
    target = now.replace(
        hour=FUND_POSITION_SCHEDULE_HOUR,
        minute=FUND_POSITION_SCHEDULE_MINUTE,
        second=FUND_POSITION_SCHEDULE_SECOND,
        microsecond=0,
    )
    if now >= target:
        target = target + timedelta(days=1)
    return target


def _last_fund_position_schedule_target(now: datetime | None = None) -> datetime:
    now = now or datetime.now(tz=LOCAL_TZ)
    target = now.replace(
        hour=FUND_POSITION_SCHEDULE_HOUR,
        minute=FUND_POSITION_SCHEDULE_MINUTE,
        second=FUND_POSITION_SCHEDULE_SECOND,
        microsecond=0,
    )
    if now < target:
        target = target - timedelta(days=1)
    return target


def _seconds_until_next_fund_position_schedule_target(now: datetime | None = None) -> int:
    now = now or datetime.now(tz=LOCAL_TZ)
    target = _next_fund_position_schedule_target(now)
    return max(1, int((target - now).total_seconds()))


def _ensure_fund_position_schedule_state_table(conn):
    cursor = conn.cursor()
    cursor.execute("""
    IF OBJECT_ID('dbo.HID_Fund_Position_Schedule_State', 'U') IS NULL
    BEGIN
        CREATE TABLE dbo.HID_Fund_Position_Schedule_State (
            Id INT NOT NULL PRIMARY KEY,
            LastRunTarget DATETIME2 NULL,
            LastRunStatus NVARCHAR(20) NULL,
            LastRunMessage NVARCHAR(500) NULL,
            LastRunAt DATETIME2 NULL,
            LastSentAt DATETIME2 NULL,
            LastSentSignature NVARCHAR(128) NULL,
            LastSentCutoff DATETIME2 NULL,
            LastSentLatestSnapshotDate DATE NULL,
            LastGeneratedAt DATETIME2 NULL,
            UpdatedAt DATETIME2 NOT NULL DEFAULT(SYSDATETIME())
        );
    END
    """)
    conn.commit()
    for stmt in [
        "ALTER TABLE dbo.HID_Fund_Position_Schedule_State ADD LastRunTarget DATETIME2 NULL",
        "ALTER TABLE dbo.HID_Fund_Position_Schedule_State ADD LastRunStatus NVARCHAR(20) NULL",
        "ALTER TABLE dbo.HID_Fund_Position_Schedule_State ADD LastRunMessage NVARCHAR(500) NULL",
        "ALTER TABLE dbo.HID_Fund_Position_Schedule_State ADD LastRunAt DATETIME2 NULL",
        "ALTER TABLE dbo.HID_Fund_Position_Schedule_State ADD LastSentAt DATETIME2 NULL",
        "ALTER TABLE dbo.HID_Fund_Position_Schedule_State ADD LastSentSignature NVARCHAR(128) NULL",
        "ALTER TABLE dbo.HID_Fund_Position_Schedule_State ADD LastSentCutoff DATETIME2 NULL",
        "ALTER TABLE dbo.HID_Fund_Position_Schedule_State ADD LastSentLatestSnapshotDate DATE NULL",
        "ALTER TABLE dbo.HID_Fund_Position_Schedule_State ADD LastGeneratedAt DATETIME2 NULL",
        "ALTER TABLE dbo.HID_Fund_Position_Schedule_State ADD UpdatedAt DATETIME2 NOT NULL DEFAULT(SYSDATETIME())",
    ]:
        try:
            cursor.execute(stmt)
            conn.commit()
        except Exception:
            try:
                conn.rollback()
            except Exception:
                pass
    try:
        cursor.execute("""
        IF NOT EXISTS (SELECT 1 FROM dbo.HID_Fund_Position_Schedule_State WHERE Id = 1)
        BEGIN
            INSERT INTO dbo.HID_Fund_Position_Schedule_State (Id, UpdatedAt)
            VALUES (1, SYSDATETIME());
        END
        """)
        conn.commit()
    except Exception:
        try:
            conn.rollback()
        except Exception:
            pass


def _fund_position_schedule_state_get() -> dict:
    try:
        with _get_login_db_connection() as conn:
            _ensure_fund_tracker_tables(conn)
            _ensure_fund_position_schedule_state_table(conn)
            cursor = conn.cursor()
            try:
                cursor.execute("""
                    SELECT TOP 1
                        Id,
                        LastRunTarget,
                        LastRunStatus,
                        LastRunMessage,
                        LastRunAt,
                        LastSentAt,
                        LastSentSignature,
                        LastSentCutoff,
                        LastSentLatestSnapshotDate,
                        LastGeneratedAt,
                        UpdatedAt
                    FROM dbo.HID_Fund_Position_Schedule_State
                    WHERE Id = 1
                """)
            except Exception as select_err:
                if "HID_Fund_Position_Schedule_State" not in str(select_err):
                    raise
                _ensure_fund_position_schedule_state_table(conn)
                cursor.execute("""
                    SELECT TOP 1
                        Id,
                        LastRunTarget,
                        LastRunStatus,
                        LastRunMessage,
                        LastRunAt,
                        LastSentAt,
                        LastSentSignature,
                        LastSentCutoff,
                        LastSentLatestSnapshotDate,
                        LastGeneratedAt,
                        UpdatedAt
                    FROM dbo.HID_Fund_Position_Schedule_State
                    WHERE Id = 1
                """)
            row = cursor.fetchone()
            if not row:
                return {}
            cols = [c[0] for c in cursor.description]
            return {cols[i]: row[i] for i in range(len(cols))}
    except Exception as e:
        print(f"Fund schedule state read failed: {e}")
        return {}


def _fund_position_schedule_state_save(
    *,
    run_target: datetime,
    run_status: str,
    run_message: str,
    run_at: datetime | None = None,
    sent_at: datetime | None = None,
    sent_signature: str | None = None,
    sent_cutoff: datetime | None = None,
    sent_latest_snapshot_date: date | None = None,
    generated_at: datetime | None = None,
    persist_sent: bool = False,
):
    run_at = run_at or datetime.now(tz=LOCAL_TZ)
    run_target_db = _fund_schedule_as_local_naive(run_target)
    run_at_db = _fund_schedule_as_local_naive(run_at)
    sent_at_db = _fund_schedule_as_local_naive(sent_at) if sent_at else None
    sent_cutoff_db = _fund_schedule_as_local_naive(sent_cutoff) if sent_cutoff else None
    generated_at_db = _fund_schedule_as_local_naive(generated_at) if generated_at else None
    try:
        with _get_login_db_connection() as conn:
            _ensure_fund_tracker_tables(conn)
            _ensure_fund_position_schedule_state_table(conn)
            cursor = conn.cursor()
            if persist_sent:
                cursor.execute(
                    """
                    UPDATE dbo.HID_Fund_Position_Schedule_State
                    SET LastRunTarget = ?,
                        LastRunStatus = ?,
                        LastRunMessage = ?,
                        LastRunAt = ?,
                        LastSentAt = ?,
                        LastSentSignature = ?,
                        LastSentCutoff = ?,
                        LastSentLatestSnapshotDate = ?,
                        LastGeneratedAt = ?,
                        UpdatedAt = SYSDATETIME()
                    WHERE Id = 1
                    """,
                    (
                        run_target_db,
                        _fund_text(run_status, 20),
                        _fund_text(run_message, 500),
                        run_at_db,
                        sent_at_db,
                        _fund_text(sent_signature, 128),
                        sent_cutoff_db,
                        sent_latest_snapshot_date,
                        generated_at_db,
                    ),
                )
            else:
                cursor.execute(
                    """
                    UPDATE dbo.HID_Fund_Position_Schedule_State
                    SET LastRunTarget = ?,
                        LastRunStatus = ?,
                        LastRunMessage = ?,
                        LastRunAt = ?,
                        UpdatedAt = SYSDATETIME()
                    WHERE Id = 1
                    """,
                    (
                        run_target_db,
                        _fund_text(run_status, 20),
                        _fund_text(run_message, 500),
                        run_at_db,
                    ),
                )
            conn.commit()
    except Exception as e:
        print(f"Fund schedule state update failed: {e}")


def _fund_signature_value(value) -> str:
    if value is None:
        return ""
    if isinstance(value, datetime):
        if value.tzinfo is not None:
            value = value.astimezone(LOCAL_TZ)
        return value.replace(microsecond=0).isoformat(sep=" ")
    if isinstance(value, date):
        return value.isoformat()
    if isinstance(value, Decimal):
        text = format(value, "f")
        if "." in text:
            text = text.rstrip("0").rstrip(".")
        return text or "0"
    if isinstance(value, float):
        if math.isnan(value) or math.isinf(value):
            return ""
        text = f"{value:.10f}".rstrip("0").rstrip(".")
        return text or "0"
    if isinstance(value, (int, np.integer)):
        return str(int(value))
    return re.sub(r"\s+", " ", str(value).strip())


def _fund_collect_schedule_dataset_signature(firm_acl: dict) -> dict:
    specs = [
        {
            "key": "daily",
            "table": "HID_Fund_Daily_Position",
            "columns": [
                "EntryDate", "FirmName", "BankName", "AccountType", "AccountLast4",
                "CreditLimit", "OpeningBalance", "Receipts", "PaymentsUsed", "ClosingBalance", "Remarks",
            ],
        },
        {
            "key": "wc",
            "table": "HID_Fund_WC_Loan_Position",
            "columns": [
                "EntryDate", "FirmName", "BankName", "FacilityType", "SanctionLimit",
                "DrawingPower", "Utilised", "AvailableLimit", "ROIPct", "DueDate", "Remarks",
            ],
        },
        {
            "key": "fdr",
            "table": "HID_Fund_FDR_Tracker",
            "columns": [
                "EntryDate", "FirmName", "BankName", "FdrNo", "FdrAmount",
                "StartDate", "MaturityDate", "ROIPct", "LienFlag", "LinkedLoan", "Remarks",
            ],
        },
    ]

    hasher = hashlib.sha256()
    total_rows = 0
    min_entry_date = None
    max_entry_date = None
    counts = {"daily": 0, "wc": 0, "fdr": 0}

    with _get_login_db_connection() as conn:
        _ensure_fund_tracker_tables(conn)
        cursor = conn.cursor()
        for spec in specs:
            columns = spec["columns"]
            params = []
            sql = f"SELECT {', '.join(columns)} FROM dbo.{spec['table']} WHERE 1 = 1"
            if not firm_acl.get("all"):
                firms = firm_acl.get("firms") or []
                if not firms:
                    continue
                placeholders = ",".join("?" * len(firms))
                sql += f" AND UPPER(LTRIM(RTRIM(FirmName))) IN ({placeholders})"
                params.extend(firms)
            sql += " ORDER BY " + ", ".join(columns)
            try:
                cursor.execute(sql, params)
            except Exception:
                continue
            rows = cursor.fetchall()
            cols = [c[0] for c in cursor.description]
            for row in rows:
                rec = {cols[i]: row[i] for i in range(len(cols))}
                entry_dt = _fund_parse_date_value(rec.get("EntryDate"), None)
                if entry_dt:
                    min_entry_date = entry_dt if min_entry_date is None else min(min_entry_date, entry_dt)
                    max_entry_date = entry_dt if max_entry_date is None else max(max_entry_date, entry_dt)
                payload = [spec["key"]] + [_fund_signature_value(rec.get(col)) for col in cols]
                hasher.update(("|".join(payload) + "\n").encode("utf-8", "ignore"))
                total_rows += 1
                counts[spec["key"]] = counts.get(spec["key"], 0) + 1

    return {
        "signature": hasher.hexdigest() if total_rows else "EMPTY_DATASET",
        "total_rows": total_rows,
        "from_date": min_entry_date,
        "to_date": max_entry_date,
        "counts": counts,
    }


def _fund_collect_scheduled_recipients() -> tuple[list[str], list[str]]:
    configured_rows = _fetch_fund_position_recipients(firms=None, only_active=True)
    recipients = []
    invalid = []
    seen = set()
    for row in configured_rows:
        email = str((row or {}).get("Email") or "").strip().lower()
        if not email:
            continue
        if not _fund_is_valid_email(email):
            invalid.append(email)
            continue
        if email in seen:
            continue
        seen.add(email)
        recipients.append(email)
    return recipients, invalid


def _build_fund_history_scheduled_email_body(
    *,
    from_iso: str,
    to_iso: str,
    cutoff_time_text: str,
    latest_snapshot_iso: str,
    generated_at_text: str,
    recipient_count: int,
    history_changes: int,
    snapshot_days: int,
) -> str:
    from html import escape
    return f"""
    <html>
    <head>
      <style>
        body {{
          font-family: Arial, sans-serif;
          color: #1f2937;
          background: #f8fafc;
          padding: 16px;
        }}
        .box {{
          max-width: 780px;
          border: 1px solid #e2e8f0;
          border-radius: 12px;
          background: #ffffff;
          padding: 18px 20px;
        }}
        .title {{
          margin: 0 0 8px 0;
          font-size: 18px;
          color: #1e3a8a;
          font-weight: 700;
        }}
        table {{
          width: 100%;
          border-collapse: collapse;
          margin-top: 10px;
        }}
        td {{
          border-bottom: 1px solid #f1f5f9;
          padding: 7px 6px;
          font-size: 13px;
          vertical-align: top;
        }}
        .k {{
          width: 260px;
          font-weight: 700;
          color: #334155;
          white-space: nowrap;
        }}
        .footer {{
          margin-top: 14px;
          font-size: 12px;
          color: #64748b;
        }}
      </style>
    </head>
    <body>
      <div class="box">
        <p class="title">Fund Position Scheduled History Report</p>
        <p>Please find the scheduled fund history PDF attached.</p>
        <table>
          <tr><td class="k">Date Range Included</td><td>{escape(from_iso)} to {escape(to_iso)}</td></tr>
          <tr><td class="k">Cutoff Time</td><td>{escape(cutoff_time_text)}</td></tr>
          <tr><td class="k">Latest Snapshot Date Included</td><td>{escape(latest_snapshot_iso)}</td></tr>
          <tr><td class="k">Generated At</td><td>{escape(generated_at_text)}</td></tr>
          <tr><td class="k">Recipients</td><td>{recipient_count}</td></tr>
          <tr><td class="k">Snapshot Days</td><td>{snapshot_days}</td></tr>
          <tr><td class="k">History Changes</td><td>{history_changes}</td></tr>
        </table>
        <div class="footer">This is an automated scheduled email from the Fund Position Tracker.</div>
      </div>
    </body>
    </html>
    """


def _run_fund_position_scheduled_mail(target_dt: datetime, reason: str = "daemon") -> dict:
    target_local = target_dt.astimezone(LOCAL_TZ) if target_dt.tzinfo else target_dt.replace(tzinfo=LOCAL_TZ)
    run_now = datetime.now(tz=LOCAL_TZ)
    target_naive = _fund_schedule_as_local_naive(target_local)

    state = _fund_position_schedule_state_get()
    last_run_target = _fund_schedule_as_local_naive(state.get("LastRunTarget"))
    if last_run_target and target_naive and last_run_target == target_naive:
        return {"status": "skipped", "message": "already processed for this schedule target"}

    firm_acl = {"all": True, "firms": []}
    try:
        dataset = _fund_collect_schedule_dataset_signature(firm_acl)
    except Exception as e:
        msg = f"Failed to build fund dataset signature: {e}"
        _fund_position_schedule_state_save(
            run_target=target_local,
            run_status="error",
            run_message=msg,
            run_at=run_now,
            persist_sent=False,
        )
        return {"status": "error", "message": msg}

    if int(dataset.get("total_rows") or 0) <= 0:
        msg = "No fund position data available for scheduled mail."
        _fund_position_schedule_state_save(
            run_target=target_local,
            run_status="skipped",
            run_message=msg,
            run_at=run_now,
            persist_sent=False,
        )
        return {"status": "skipped", "message": msg}

    current_signature = str(dataset.get("signature") or "").strip()
    last_sent_signature = str(state.get("LastSentSignature") or "").strip()
    if current_signature and last_sent_signature and current_signature == last_sent_signature:
        msg = "No data change since last scheduled mail."
        _fund_position_schedule_state_save(
            run_target=target_local,
            run_status="skipped",
            run_message=msg,
            run_at=run_now,
            persist_sent=False,
        )
        return {"status": "skipped", "message": msg}

    from_date = dataset.get("from_date")
    to_date = dataset.get("to_date")
    if not isinstance(from_date, date) or not isinstance(to_date, date):
        msg = "No valid snapshot range found for scheduled mail."
        _fund_position_schedule_state_save(
            run_target=target_local,
            run_status="skipped",
            run_message=msg,
            run_at=run_now,
            persist_sent=False,
        )
        return {"status": "skipped", "message": msg}

    recipients, invalid_configured = _fund_collect_scheduled_recipients()
    if not recipients:
        msg = "No active configured fund recipients found."
        _fund_position_schedule_state_save(
            run_target=target_local,
            run_status="skipped",
            run_message=msg,
            run_at=run_now,
            persist_sent=False,
        )
        return {"status": "skipped", "message": msg}

    exported_by = "SYSTEM (Scheduled)"
    try:
        export_payload = _fund_build_history_export_payload(from_date, to_date, firm_acl, exported_by)
    except Exception as e:
        msg = f"Failed to build scheduled fund history PDF: {e}"
        _fund_position_schedule_state_save(
            run_target=target_local,
            run_status="error",
            run_message=msg,
            run_at=run_now,
            persist_sent=False,
        )
        return {"status": "error", "message": msg}

    cutoff_text = target_local.astimezone(LOCAL_TZ).strftime("%d-%b-%Y %I:%M %p IST")
    generated_at = datetime.now(tz=LOCAL_TZ)
    generated_text = generated_at.strftime("%d-%b-%Y %I:%M:%S %p IST")
    from_iso = from_date.isoformat()
    to_iso = to_date.isoformat()
    latest_snapshot_iso = to_iso
    filename = f"Fund_Position_History_Scheduled_{from_iso}_to_{to_iso}.pdf"
    subject = (
        "Fund Position Scheduled History"
        f" | Cutoff time: {cutoff_text}"
        f" | Latest snapshot date included: {latest_snapshot_iso}"
        f" | Generated at: {generated_text}"
    )
    body_html = _build_fund_history_scheduled_email_body(
        from_iso=from_iso,
        to_iso=to_iso,
        cutoff_time_text=cutoff_text,
        latest_snapshot_iso=latest_snapshot_iso,
        generated_at_text=generated_text,
        recipient_count=len(recipients),
        history_changes=len(export_payload.get("history_rows") or []),
        snapshot_days=int(export_payload.get("snapshot_days") or 0),
    )
    mail_result = _send_graph_mail_with_attachment(
        subject=subject,
        body_html=body_html,
        to_recipients=recipients,
        filename=filename,
        content_bytes=export_payload.get("pdf_bytes") or b"",
    )
    mail_state = str(mail_result.get("status") or "").strip().lower()
    if mail_state != "success":
        msg = mail_result.get("message") or "Scheduled mail send failed"
        _fund_position_schedule_state_save(
            run_target=target_local,
            run_status="error",
            run_message=msg,
            run_at=run_now,
            persist_sent=False,
        )
        return {
            "status": "error",
            "message": msg,
            "mail_status": mail_result,
            "invalid_configured_recipients": invalid_configured,
        }

    msg = f"Scheduled report emailed to {len(recipients)} recipient(s)."
    _fund_position_schedule_state_save(
        run_target=target_local,
        run_status="success",
        run_message=msg,
        run_at=run_now,
        sent_at=run_now,
        sent_signature=current_signature,
        sent_cutoff=target_local,
        sent_latest_snapshot_date=to_date,
        generated_at=generated_at,
        persist_sent=True,
    )
    return {
        "status": "success",
        "message": msg,
        "mail_status": mail_result,
        "recipients_count": len(recipients),
        "invalid_configured_recipients": invalid_configured,
        "range_from": from_iso,
        "range_to": to_iso,
        "reason": reason,
    }


def _run_fund_position_schedule_catchup_if_needed(reason: str = "daemon") -> bool:
    if not FUND_POSITION_SCHEDULE_ENABLED:
        return False
    now = datetime.now(tz=LOCAL_TZ)
    target = _last_fund_position_schedule_target(now)
    if (now - target) > timedelta(hours=FUND_POSITION_SCHEDULE_CATCHUP_MAX_HOURS):
        return False
    result = _run_fund_position_scheduled_mail(target, reason=f"{reason}:catchup")
    return str(result.get("status") or "").strip().lower() != "skipped" or "already processed" not in str(result.get("message") or "").lower()


def _fund_position_scheduled_mail_daemon():
    if not FUND_POSITION_SCHEDULE_ENABLED:
        print("Fund position scheduled mail daemon disabled by config.")
        return
    while True:
        try:
            catchup_ran = _run_fund_position_schedule_catchup_if_needed(reason="daemon")
            if catchup_ran:
                print("Fund position scheduled mail catch-up run completed.")
            now = datetime.now(tz=LOCAL_TZ)
            target = _next_fund_position_schedule_target(now)
            secs = max(1, int((target - now).total_seconds()))
            print(f"Fund position scheduled mail in {secs//3600}h {(secs%3600)//60}m")
            time.sleep(secs)
            result = _run_fund_position_scheduled_mail(target, reason="daemon")
            print(f"Fund position scheduled mail run: {result.get('status')} - {result.get('message')}")
            time.sleep(2)
        except Exception as e:
            print(f"Fund position scheduled mail daemon error: {e}")
            time.sleep(60)


@app.route('/api/fund_position/export_pdf', methods=['GET'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_fund_position_export_pdf():
    from_date = _fund_parse_date_value(request.args.get("from"), None)
    to_date = _fund_parse_date_value(request.args.get("to"), None)
    single_date = _fund_parse_date_value(request.args.get("date"), datetime.now(tz=LOCAL_TZ).date())

    if not from_date and not to_date:
        from_date = single_date
        to_date = single_date
    elif from_date and not to_date:
        to_date = from_date
    elif to_date and not from_date:
        from_date = to_date

    if not from_date or not to_date:
        _audit_log_event(
            "fund_position",
            "export_pdf",
            status="error",
            entity_type="fund_history_export",
            summary="Invalid date range",
        )
        return jsonify({"status": "error", "message": "Invalid date range"}), 400

    if from_date > to_date:
        _audit_log_event(
            "fund_position",
            "export_pdf",
            status="error",
            entity_type="fund_history_export",
            summary="From date cannot be greater than To date",
            details={"from": from_date.isoformat(), "to": to_date.isoformat()},
        )
        return jsonify({"status": "error", "message": "From date cannot be greater than To date"}), 400

    range_days = (to_date - from_date).days + 1
    max_days = 120
    if range_days > max_days:
        return jsonify({
            "status": "error",
            "message": f"Date range too large. Please select up to {max_days} days.",
        }), 400

    firm_acl = _allowed_fund_firms_for_session()
    if not firm_acl.get("all") and not (firm_acl.get("firms") or []):
        _audit_log_event(
            "fund_position",
            "export_pdf",
            status="error",
            entity_type="fund_history_export",
            summary="No firm access assigned",
            details={"from": from_date.isoformat(), "to": to_date.isoformat()},
        )
        return jsonify({"status": "error", "message": "No firm access assigned"}), 403

    exported_by = (session.get("username") or session.get("name") or "").strip() or "Unknown"
    try:
        export_payload = _fund_build_history_export_payload(from_date, to_date, firm_acl, exported_by)
    except Exception as export_err:
        _audit_log_event(
            "fund_position",
            "export_pdf",
            status="error",
            entity_type="fund_history_export",
            summary="Failed to export fund history PDF",
            details={
                "from": from_date.isoformat(),
                "to": to_date.isoformat(),
                "error": str(export_err),
            },
        )
        return jsonify({"status": "error", "message": f"Failed to export PDF: {export_err}"}), 500

    timeline = export_payload.get("timeline") or []
    history_rows = export_payload.get("history_rows") or []
    pdf_bytes = export_payload.get("pdf_bytes") or b""
    snapshot_days = int(export_payload.get("snapshot_days") or 0)
    _audit_log_event(
        "fund_position",
        "export_pdf",
        status="success",
        entity_type="fund_history_export",
        entity_id=f"{from_date.isoformat()}_{to_date.isoformat()}",
        summary="Fund history PDF exported",
        details={
            "from": from_date.isoformat(),
            "to": to_date.isoformat(),
            "range_days": range_days,
            "snapshot_days": snapshot_days,
            "history_changes": len(history_rows),
            "daily_rows": int(export_payload.get("daily_rows") or 0),
            "wc_rows": int(export_payload.get("wc_rows") or 0),
            "fdr_rows": int(export_payload.get("fdr_rows") or 0),
        },
    )

    filename = f"Fund_Position_History_{from_date.isoformat()}_to_{to_date.isoformat()}.pdf"
    return send_file(
        io.BytesIO(pdf_bytes),
        mimetype="application/pdf",
        as_attachment=True,
        download_name=filename,
    )

@app.route('/api/fund_position/email_pdf', methods=['POST'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_fund_position_email_pdf():
    body = request.get_json(silent=True) or {}
    from_date = _fund_parse_date_value(body.get("from"), None)
    to_date = _fund_parse_date_value(body.get("to"), None)
    if not from_date or not to_date:
        return jsonify({"status": "error", "message": "Invalid date range"}), 400
    if from_date > to_date:
        return jsonify({"status": "error", "message": "From date cannot be greater than To date"}), 400

    range_days = (to_date - from_date).days + 1
    max_days = 120
    if range_days > max_days:
        return jsonify({
            "status": "error",
            "message": f"Date range too large. Please select up to {max_days} days.",
        }), 400

    use_configured_recipients = False
    raw_use_configured = body.get("use_configured_recipients")
    if isinstance(raw_use_configured, bool):
        use_configured_recipients = raw_use_configured
    else:
        use_configured_recipients = str(raw_use_configured or "").strip().lower() in {"1", "true", "yes", "on"}

    raw_recipients = body.get("to_emails") if body.get("to_emails") is not None else body.get("to")
    manual_recipients = _fund_parse_email_recipients(raw_recipients)
    invalid_manual = [email for email in manual_recipients if not _fund_is_valid_email(email)]
    if invalid_manual:
        return jsonify({"status": "error", "message": "Invalid email address(es)", "invalid_recipients": invalid_manual}), 400

    firm_acl = _allowed_fund_firms_for_session()
    if not firm_acl.get("all") and not (firm_acl.get("firms") or []):
        return jsonify({"status": "error", "message": "No firm access assigned"}), 403

    configured_recipients = []
    invalid_configured = []
    if use_configured_recipients:
        configured_rows = _fetch_fund_position_recipients(
            firms=None if firm_acl.get("all") else (firm_acl.get("firms") or []),
            only_active=True,
        )
        for row in configured_rows:
            email = str((row or {}).get("Email") or "").strip().lower()
            if not email:
                continue
            if _fund_is_valid_email(email):
                configured_recipients.append(email)
            else:
                invalid_configured.append(email)

    recipients = []
    seen = set()
    for email in manual_recipients + configured_recipients:
        key = str(email or "").strip().lower()
        if not key or key in seen:
            continue
        seen.add(key)
        recipients.append(key)

    if not recipients:
        return jsonify({
            "status": "error",
            "message": "No valid recipients found. Add manual email(s) or enable configured recipients.",
        }), 400
    if len(recipients) > 50:
        return jsonify({"status": "error", "message": "Maximum 50 recipients allowed per request"}), 400

    exported_by = (session.get("username") or session.get("name") or "").strip() or "Unknown"
    try:
        export_payload = _fund_build_history_export_payload(from_date, to_date, firm_acl, exported_by)
    except Exception as export_err:
        _audit_log_event(
            "fund_position",
            "email_pdf",
            status="error",
            entity_type="fund_history_export",
            summary="Failed to prepare fund history PDF mail",
            details={
                "from": from_date.isoformat(),
                "to": to_date.isoformat(),
                "error": str(export_err),
            },
        )
        return jsonify({"status": "error", "message": f"Failed to prepare report: {export_err}"}), 500

    from_iso = from_date.isoformat()
    to_iso = to_date.isoformat()
    filename = f"Fund_Position_History_{from_iso}_to_{to_iso}.pdf"
    subject = f"Fund Position History Report | {from_iso} to {to_iso}"
    body_html = _build_fund_history_report_email_body(
        from_iso=from_iso,
        to_iso=to_iso,
        exported_by=exported_by,
        recipient_count=len(recipients),
        history_changes=len(export_payload.get("history_rows") or []),
        snapshot_days=int(export_payload.get("snapshot_days") or 0),
    )
    mail_result = _send_graph_mail_with_attachment(
        subject=subject,
        body_html=body_html,
        to_recipients=recipients,
        filename=filename,
        content_bytes=export_payload.get("pdf_bytes") or b"",
    )
    mail_state = str(mail_result.get("status") or "").strip().lower()
    _audit_log_event(
        "fund_position",
        "email_pdf",
        status="success" if mail_state == "success" else "error",
        entity_type="fund_history_export",
        entity_id=f"{from_iso}_{to_iso}",
        summary="Fund history PDF mailed",
        details={
            "from": from_iso,
            "to": to_iso,
            "manual_recipients_count": len(manual_recipients),
            "configured_recipients_count": len(configured_recipients),
            "use_configured_recipients": use_configured_recipients,
            "recipients_count": len(recipients),
            "recipients": recipients,
            "invalid_configured_recipients": invalid_configured,
            "range_days": range_days,
            "history_changes": len(export_payload.get("history_rows") or []),
            "mail_result": mail_result,
        },
    )
    if mail_state != "success":
        return jsonify({
            "status": "error",
            "message": mail_result.get("message") or "Failed to send email",
            "mail_status": mail_result,
        }), 500

    return jsonify({
        "status": "success",
        "message": f"Report emailed to {len(recipients)} recipient(s)",
        "recipients": recipients,
        "manual_recipients_count": len(manual_recipients),
        "configured_recipients_count": len(configured_recipients),
        "invalid_configured_recipients": invalid_configured,
        "mail_status": mail_result,
    })

@app.route('/api/fund_position/save', methods=['POST'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_fund_position_save():
    body = request.get_json(silent=True) or {}
    entry_date = _fund_parse_date_value(body.get("date"), datetime.now(tz=LOCAL_TZ).date())
    if not entry_date:
        _audit_log_event(
            "fund_position",
            "save_snapshot",
            status="error",
            entity_type="fund_snapshot",
            summary="Invalid date",
        )
        return jsonify({"status": "error", "message": "Invalid date"}), 400

    daily_payload = body.get("daily_rows") or []
    wc_payload = body.get("wc_rows") or []
    fdr_payload = body.get("fdr_rows") or []

    firm_acl = _allowed_fund_firms_for_session()
    if not firm_acl.get("all") and not (firm_acl.get("firms") or []):
        _audit_log_event(
            "fund_position",
            "save_snapshot",
            status="error",
            entity_type="fund_snapshot",
            entity_id=entry_date.isoformat(),
            summary="No firm access assigned",
        )
        return jsonify({"status": "error", "message": "No firm access assigned"}), 403

    lock_state = _fund_snapshot_edit_state(entry_date)
    if lock_state.get("is_edit_locked"):
        _audit_log_event(
            "fund_position",
            "save_snapshot",
            status="error",
            entity_type="fund_snapshot",
            entity_id=entry_date.isoformat(),
            summary="Edit lock active",
            details=lock_state,
        )
        return jsonify({
            "status": "error",
            "message": lock_state.get("edit_lock_message") or "This snapshot is locked for edits.",
            **lock_state,
        }), 403

    allowed_set = {f.upper() for f in (firm_acl.get("firms") or [])}
    denied = set()
    user_name = (session.get("username") or "").strip()

    def _optional_decimal(raw):
        if raw is None:
            return None
        txt = str(raw).strip()
        if not txt:
            return None
        return _fund_parse_decimal(raw)

    def _check_firm_access(raw_firm: str):
        firm = _normalize_firm_name(raw_firm)
        if not firm:
            return ""
        if firm_acl.get("all"):
            return firm
        if firm.upper() in allowed_set:
            return firm
        denied.add(firm)
        return ""

    daily_rows = []
    for row in (daily_payload if isinstance(daily_payload, list) else []):
        if not _fund_has_business_value(row, ["firm_name", "bank_name", "account_type", "account_last4", "credit_limit", "opening_balance", "receipts", "payments_used", "remarks"]):
            continue
        firm = _check_firm_access(row.get("firm_name"))
        if not firm:
            continue
        opening = _fund_parse_decimal(row.get("opening_balance"))
        receipts = _fund_parse_decimal(row.get("receipts"))
        payments = _fund_parse_decimal(row.get("payments_used"))
        closing_raw = row.get("closing_balance")
        closing = _fund_parse_decimal(closing_raw, opening + receipts - payments) if closing_raw not in (None, "") else (opening + receipts - payments)
        daily_rows.append((
            entry_date,
            firm,
            _fund_text(row.get("bank_name"), 120),
            _fund_text(row.get("account_type"), 40),
            _fund_text(row.get("account_last4"), 20),
            _optional_decimal(row.get("credit_limit")),
            opening,
            receipts,
            payments,
            closing,
            _fund_text(row.get("remarks"), 500),
            user_name,
        ))

    wc_rows = []
    for row in (wc_payload if isinstance(wc_payload, list) else []):
        if not _fund_has_business_value(row, ["firm_name", "bank_name", "facility_type", "sanction_limit", "drawing_power", "utilised", "available_limit", "roi_pct", "due_date", "remarks"]):
            continue
        firm = _check_firm_access(row.get("firm_name"))
        if not firm:
            continue
        sanction = _fund_parse_decimal(row.get("sanction_limit"))
        utilised = _fund_parse_decimal(row.get("utilised"))
        available_raw = row.get("available_limit")
        available = _fund_parse_decimal(available_raw, sanction - utilised) if available_raw not in (None, "") else (sanction - utilised)
        wc_rows.append((
            entry_date,
            firm,
            _fund_text(row.get("bank_name"), 120),
            _fund_text(row.get("facility_type"), 80),
            _optional_decimal(row.get("sanction_limit")),
            _optional_decimal(row.get("drawing_power")),
            _optional_decimal(row.get("utilised")),
            available,
            _optional_decimal(row.get("roi_pct")),
            _fund_parse_date_value(row.get("due_date")),
            _fund_text(row.get("remarks"), 500),
            user_name,
        ))

    fdr_rows = []
    for row in (fdr_payload if isinstance(fdr_payload, list) else []):
        if not _fund_has_business_value(row, ["firm_name", "bank_name", "fdr_no", "fdr_amount", "start_date", "maturity_date", "roi_pct", "lien_flag", "linked_loan", "remarks"]):
            continue
        firm = _check_firm_access(row.get("firm_name"))
        if not firm:
            continue
        fdr_rows.append((
            entry_date,
            firm,
            _fund_text(row.get("bank_name"), 120),
            _fund_text(row.get("fdr_no"), 200),
            _optional_decimal(row.get("fdr_amount")),
            _fund_parse_date_value(row.get("start_date")),
            _fund_parse_date_value(row.get("maturity_date")),
            _optional_decimal(row.get("roi_pct")),
            _fund_text(row.get("lien_flag"), 10),
            _fund_text(row.get("linked_loan"), 200),
            _fund_text(row.get("remarks"), 500),
            user_name,
        ))

    if denied:
        _audit_log_event(
            "fund_position",
            "save_snapshot",
            status="error",
            entity_type="fund_snapshot",
            entity_id=entry_date.isoformat(),
            summary="Attempt to update denied firms",
            details={"denied_firms": sorted(denied)},
        )
        return jsonify({"status": "error", "message": "You cannot update firms outside your scope", "denied_firms": sorted(denied)}), 403

    before_payload = None
    try:
        before_payload = _fund_snapshot_payload(entry_date, firm_acl)
    except Exception:
        before_payload = None

    try:
        with _get_login_db_connection() as conn:
            _ensure_fund_tracker_tables(conn)
            cursor = conn.cursor()
            _fund_delete_rows_for_date(cursor, "HID_Fund_Daily_Position", entry_date, firm_acl)
            _fund_delete_rows_for_date(cursor, "HID_Fund_WC_Loan_Position", entry_date, firm_acl)
            _fund_delete_rows_for_date(cursor, "HID_Fund_FDR_Tracker", entry_date, firm_acl)

            if daily_rows:
                cursor.executemany("""
                    INSERT INTO dbo.HID_Fund_Daily_Position
                    (EntryDate, FirmName, BankName, AccountType, AccountLast4, CreditLimit, OpeningBalance, Receipts, PaymentsUsed, ClosingBalance, Remarks, UpdatedBy, UpdatedAt)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, SYSDATETIME())
                """, daily_rows)
            if wc_rows:
                cursor.executemany("""
                    INSERT INTO dbo.HID_Fund_WC_Loan_Position
                    (EntryDate, FirmName, BankName, FacilityType, SanctionLimit, DrawingPower, Utilised, AvailableLimit, ROIPct, DueDate, Remarks, UpdatedBy, UpdatedAt)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, SYSDATETIME())
                """, wc_rows)
            if fdr_rows:
                cursor.executemany("""
                    INSERT INTO dbo.HID_Fund_FDR_Tracker
                    (EntryDate, FirmName, BankName, FdrNo, FdrAmount, StartDate, MaturityDate, ROIPct, LienFlag, LinkedLoan, Remarks, UpdatedBy, UpdatedAt)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, SYSDATETIME())
                """, fdr_rows)
            conn.commit()
    except Exception as save_err:
        _audit_log_event(
            "fund_position",
            "save_snapshot",
            status="error",
            entity_type="fund_snapshot",
            entity_id=entry_date.isoformat(),
            summary="Failed to save fund snapshot",
            details={"error": str(save_err)},
        )
        return jsonify({"status": "error", "message": f"Failed to save fund snapshot: {save_err}"}), 500

    payload = _fund_snapshot_payload(entry_date, firm_acl)
    save_diff = _fund_build_save_diff(before_payload, payload)
    changed_firms = save_diff.get("firms") or sorted({
        _normalize_firm_name(row.get("firm_name")) for row in (payload.get("daily_rows") or [])
        if _normalize_firm_name(row.get("firm_name"))
    })
    totals = payload.get("totals") or {}
    summary_text = f"Snapshot saved on {entry_date.isoformat()}"

    _audit_log_event(
        "fund_position",
        "save_snapshot",
        status="success",
        entity_type="fund_snapshot",
        entity_id=entry_date.isoformat(),
        summary=summary_text,
        details={
            "saved_counts": {
                "daily": len(daily_rows),
                "wc_loan": len(wc_rows),
                "fdr": len(fdr_rows),
            },
            "diff": save_diff,
            "totals": totals,
            "firms": changed_firms,
        },
    )

    # Save no longer triggers automatic email; users can send manually via Email Report.
    mail_result = {"status": "skipped", "message": "auto-mail disabled for save"}
    mail_state = str(mail_result.get("status") or "").strip().lower()
    _audit_log_event(
        "fund_position",
        "save_mail",
        status="success" if mail_state in {"success", "skipped"} else "error",
        entity_type="fund_snapshot",
        entity_id=entry_date.isoformat(),
        summary="Fund snapshot auto-mail skipped",
        details=mail_result,
    )

    return jsonify({
        "status": "success",
        "message": "Fund tracker saved successfully",
        "saved_counts": {
            "daily": len(daily_rows),
            "wc_loan": len(wc_rows),
            "fdr": len(fdr_rows),
        },
        "mail_status": mail_result,
        **payload,
    })


@app.route('/api/fund_position/edit_event', methods=['POST'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_fund_position_edit_event():
    body = request.get_json(silent=True) or {}
    entry_date = _fund_parse_date_value(body.get("date"), datetime.now(tz=LOCAL_TZ).date())
    if not entry_date:
        _audit_log_event(
            "fund_position",
            "edit_field",
            status="error",
            entity_type="fund_snapshot",
            summary="Invalid date in edit event",
        )
        return jsonify({"status": "error", "message": "Invalid date"}), 400

    lock_state = _fund_snapshot_edit_state(entry_date)
    if lock_state.get("is_edit_locked"):
        _audit_log_event(
            "fund_position",
            "edit_field",
            status="error",
            entity_type="fund_snapshot",
            entity_id=entry_date.isoformat(),
            summary="Edit event blocked by lock",
            details=lock_state,
        )
        return jsonify({
            "status": "error",
            "message": lock_state.get("edit_lock_message") or "This snapshot is locked for edits.",
            **lock_state,
        }), 403

    tab = str(body.get("tab") or "").strip().lower()
    field = str(body.get("field") or "").strip()
    row_index = _safe_int(body.get("row_index"), 0)
    old_value = body.get("old_value")
    new_value = body.get("new_value")
    row_data = body.get("row_data") if isinstance(body.get("row_data"), dict) else {}
    firm_name = _normalize_firm_name(row_data.get("firm_name") or body.get("firm_name") or "")
    if not tab or not field:
        _audit_log_event(
            "fund_position",
            "edit_field",
            status="error",
            entity_type="fund_snapshot",
            entity_id=entry_date.isoformat(),
            summary="Invalid edit event payload",
            details={"tab": tab, "field": field},
        )
        return jsonify({"status": "error", "message": "Invalid edit event payload"}), 400

    if old_value == new_value:
        return jsonify({"status": "success", "message": "No change captured"})

    firm_acl = _allowed_fund_firms_for_session()
    if not firm_acl.get("all"):
        allowed = {f.upper() for f in (firm_acl.get("firms") or [])}
        if firm_name and firm_name.upper() not in allowed:
            _audit_log_event(
                "fund_position",
                "edit_field",
                status="error",
                entity_type="fund_snapshot",
                entity_id=entry_date.isoformat(),
                summary="Firm access denied for edit event",
                details={"firm_name": firm_name},
            )
            return jsonify({"status": "error", "message": "You cannot update firms outside your scope"}), 403

    payload = _fund_snapshot_payload(entry_date, firm_acl)
    totals = payload.get("totals") or {}
    row_label = " | ".join(
        [str(row_data.get("firm_name") or "").strip(), str(row_data.get("bank_name") or "").strip(), str(row_data.get("account_last4") or "").strip()]
    ).strip(" |")
    summary = f"Edited {tab}.{field} on row {row_index or 1}"
    details = {
        "tab": tab,
        "field": field,
        "row_index": row_index,
        "row_label": row_label,
        "old_value": old_value,
        "new_value": new_value,
        "row_data": row_data,
        "totals": totals,
    }
    _audit_log_event(
        "fund_position",
        "edit_field",
        status="success",
        entity_type="fund_snapshot",
        entity_id=entry_date.isoformat(),
        summary=summary,
        details=details,
    )

    mail_result = {
        "status": "skipped",
        "message": "auto-mail disabled for edit event; scheduled digest runs at 12:10 AM IST",
    }
    mail_state = str(mail_result.get("status") or "").strip().lower()
    _audit_log_event(
        "fund_position",
        "edit_mail",
        status="success" if mail_state in {"success", "skipped"} else "error",
        entity_type="fund_snapshot",
        entity_id=entry_date.isoformat(),
        summary="Fund field-edit auto-mail skipped",
        details=mail_result,
    )

    return jsonify({"status": "success", "mail_status": mail_result})

