@app.route('/api/fund_position/master_account_upsert', methods=['POST'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_fund_master_account_upsert():
    if not _can_manage_fund_master():
        _audit_log_event(
            "fund_position",
            "master_account_upsert",
            status="error",
            entity_type="fund_master_account",
            summary="Access denied for master account upsert",
        )
        return jsonify({"status": "error", "message": "Access denied for this section."}), 403

    body = request.get_json(silent=True) or {}
    rec_id = _safe_int(body.get("id"), 0)
    firm_name = _normalize_firm_name(body.get("firm_name"))
    bank_name = _fund_text(body.get("bank_name"), 120)
    account_type = _fund_text(body.get("account_type"), 40)
    account_last4 = _fund_text(body.get("account_last4"), 20)
    credit_limit = _fund_parse_decimal(body.get("credit_limit"), 0.0)
    is_active = 1 if str(body.get("is_active", "1")).strip().lower() in ("1", "true", "yes", "on") else 0

    if not firm_name or not bank_name:
        _audit_log_event(
            "fund_position",
            "master_account_upsert",
            status="error",
            entity_type="fund_master_account",
            summary="Firm and bank are required",
        )
        return jsonify({"status": "error", "message": "Firm and bank are required"}), 400

    firm_acl = _allowed_fund_firms_for_session()
    if not firm_acl.get("all"):
        allowed = {f.upper() for f in (firm_acl.get("firms") or [])}
        if firm_name.upper() not in allowed:
            _audit_log_event(
                "fund_position",
                "master_account_upsert",
                status="error",
                entity_type="fund_master_account",
                summary="Firm access denied for master account upsert",
                details={"firm_name": firm_name},
            )
            return jsonify({"status": "error", "message": "You cannot manage this firm"}), 403

    username = (session.get("username") or "").strip()
    with _get_login_db_connection() as conn:
        _ensure_fund_tracker_tables(conn)
        cursor = conn.cursor()
        if rec_id > 0:
            cursor.execute("""
                UPDATE dbo.HID_Fund_Master_Accounts
                SET FirmName = ?, BankName = ?, AccountType = ?, AccountLast4 = ?, CreditLimit = ?, IsActive = ?, UpdatedBy = ?, UpdatedAt = SYSDATETIME()
                WHERE Id = ?
            """, (firm_name, bank_name, account_type, account_last4, credit_limit, is_active, username, rec_id))
        else:
            cursor.execute("""
                INSERT INTO dbo.HID_Fund_Master_Accounts
                    (FirmName, BankName, AccountType, AccountLast4, CreditLimit, IsActive, CreatedBy, UpdatedBy, UpdatedAt)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, SYSDATETIME())
            """, (firm_name, bank_name, account_type, account_last4, credit_limit, is_active, username, username))
        conn.commit()
        rows = _fund_fetch_master_accounts(cursor, firm_acl, only_active=False)
    _audit_log_event(
        "fund_position",
        "master_account_upsert",
        status="success",
        entity_type="fund_master_account",
        entity_id=str(rec_id) if rec_id > 0 else None,
        summary="Fund master account saved",
        details={
            "id": rec_id if rec_id > 0 else None,
            "firm_name": firm_name,
            "bank_name": bank_name,
            "account_type": account_type,
            "account_last4": account_last4,
            "credit_limit": credit_limit,
            "is_active": bool(is_active),
        },
    )
    return jsonify({"status": "success", "rows": rows})

@app.route('/api/fund_position/master_account_toggle', methods=['POST'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_fund_master_account_toggle():
    if not _can_manage_fund_master():
        _audit_log_event(
            "fund_position",
            "master_account_toggle",
            status="error",
            entity_type="fund_master_account",
            summary="Access denied for master account toggle",
        )
        return jsonify({"status": "error", "message": "Access denied for this section."}), 403
    body = request.get_json(silent=True) or {}
    rec_id = _safe_int(body.get("id"), 0)
    if rec_id <= 0:
        _audit_log_event(
            "fund_position",
            "master_account_toggle",
            status="error",
            entity_type="fund_master_account",
            summary="Invalid master account id",
        )
        return jsonify({"status": "error", "message": "Invalid id"}), 400
    is_active = 1 if str(body.get("is_active", "1")).strip().lower() in ("1", "true", "yes", "on") else 0
    username = (session.get("username") or "").strip()
    firm_acl = _allowed_fund_firms_for_session()

    with _get_login_db_connection() as conn:
        _ensure_fund_tracker_tables(conn)
        cursor = conn.cursor()
        cursor.execute("SELECT FirmName FROM dbo.HID_Fund_Master_Accounts WHERE Id = ?", (rec_id,))
        row = cursor.fetchone()
        if not row:
            _audit_log_event(
                "fund_position",
                "master_account_toggle",
                status="error",
                entity_type="fund_master_account",
                entity_id=str(rec_id),
                summary="Master account not found",
            )
            return jsonify({"status": "error", "message": "Record not found"}), 404
        firm_name = _normalize_firm_name(row[0] if row else "")
        if not firm_acl.get("all"):
            allowed = {f.upper() for f in (firm_acl.get("firms") or [])}
            if firm_name.upper() not in allowed:
                _audit_log_event(
                    "fund_position",
                    "master_account_toggle",
                    status="error",
                    entity_type="fund_master_account",
                    entity_id=str(rec_id),
                    summary="Firm access denied for master account toggle",
                    details={"firm_name": firm_name},
                )
                return jsonify({"status": "error", "message": "You cannot manage this firm"}), 403

        cursor.execute("""
            UPDATE dbo.HID_Fund_Master_Accounts
            SET IsActive = ?, UpdatedBy = ?, UpdatedAt = SYSDATETIME()
            WHERE Id = ?
        """, (is_active, username, rec_id))
        conn.commit()
        rows = _fund_fetch_master_accounts(cursor, firm_acl, only_active=False)
    _audit_log_event(
        "fund_position",
        "master_account_toggle",
        status="success",
        entity_type="fund_master_account",
        entity_id=str(rec_id),
        summary="Fund master account status updated",
        details={"is_active": bool(is_active), "firm_name": firm_name},
    )
    return jsonify({"status": "success", "rows": rows})

