def _mod_summary_normalize_date(value) -> str | None:
    if value is None:
        return None
    if isinstance(value, datetime):
        return value.date().strftime("%Y-%m-%d")
    if isinstance(value, date):
        return value.strftime("%Y-%m-%d")
    raw = str(value).strip()
    if len(raw) >= 10 and raw[4] == "-" and raw[7] == "-":
        return raw[:10]
    try:
        return datetime.fromisoformat(raw).date().strftime("%Y-%m-%d")
    except Exception:
        return None


def _mod_summary_pick_lookback_days(duration: str) -> int:
    if duration == "yearly":
        return 3650
    if duration == "monthly":
        return 730
    return 120


def _mod_summary_default_limit(duration: str) -> int:
    if duration == "yearly":
        return 8
    if duration == "monthly":
        return 18
    return 45


def _mod_summary_row_status(coverage_pct: float, occupancy_pct: float | None) -> str:
    if coverage_pct >= 90 and (occupancy_pct is None or occupancy_pct >= 70):
        return "healthy"
    if coverage_pct >= 70:
        return "watch"
    return "critical"


def _fetch_mod_summary_daily_rows(units_to_use: list[str], from_date: str, to_date: str, segment: str = "total") -> list[dict]:
    if not units_to_use:
        return []

    segment_norm = str(segment or "total").strip().lower()
    split_mode = segment_norm in {"asarfi", "cardiac"}
    expected_units = max(1, len(units_to_use))
    placeholders = ",".join("?" * len(units_to_use))
    params = [from_date, to_date, *units_to_use]
    records: dict[tuple[str, str], dict] = {}

    def _upsert(snapshot_date: str, unit: str) -> dict:
        key = (snapshot_date, unit)
        if key not in records:
            records[key] = {
                "snapshot_date": snapshot_date,
                "unit": unit,
                "morning_saved": False,
                "night_saved": False,
                "morning_snapshot_time": None,
                "night_snapshot_time": None,
                "occupancy_used_morning": 0,
                "occupancy_beds_morning": 0,
                "occupancy_used_night": 0,
                "occupancy_beds_night": 0,
                "opd_total": 0,
                "ipd_total": 0,
                "night_admissions": 0,
                "night_discharges": 0,
                "night_0000_0800_admissions": 0,
                "morning_prev_admissions": 0,
                "morning_prev_discharges": 0,
                "investigation_total": 0,
                "procedure_total": 0,
            }
        return records[key]

    with _get_login_db_connection() as conn:
        _ensure_morning_report_tables(conn)
        _ensure_night_report_detail_table(conn)
        _ensure_night_report_ward_table(conn)
        cur = conn.cursor()

        morning_sql = f"""
            WITH base AS (
                SELECT SnapshotDate, Unit, MAX(SnapshotTime) AS SnapshotTime
                FROM dbo.HID_Morning_Report_Header WITH (NOLOCK)
                WHERE SnapshotDate BETWEEN ? AND ? AND Unit IN ({placeholders})
                GROUP BY SnapshotDate, Unit
            ),
            occ AS (
                SELECT SnapshotDate, Unit,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(WardName, '')))) IN ('TOTAL', 'TOTALS')
                                THEN 0
                                ELSE ISNULL(OccupiedCount, 0) + ISNULL(ClinicallyDischargedCount, 0) END) AS OccupancyUsed,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(WardName, '')))) IN ('TOTAL', 'TOTALS')
                                THEN 0
                                ELSE ISNULL(BedCount, 0) END) AS Beds
                FROM dbo.HID_Morning_Report_Occupancy WITH (NOLOCK)
                WHERE SnapshotDate BETWEEN ? AND ? AND Unit IN ({placeholders})
                GROUP BY SnapshotDate, Unit
            ),
            doc AS (
                SELECT SnapshotDate, Unit,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Department, '')))) = 'TOTAL'
                                THEN 0 ELSE ISNULL(OPDCount, 0) END) AS OPDTotal,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Department, '')))) = 'TOTAL'
                                THEN 0 ELSE ISNULL(IPDCount, 0) END) AS IPDTotal
                FROM dbo.HID_Morning_Report_Doctorwise WITH (NOLOCK)
                WHERE SnapshotDate BETWEEN ? AND ? AND Unit IN ({placeholders})
                GROUP BY SnapshotDate, Unit
            ),
            sumry AS (
                SELECT SnapshotDate, Unit,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'OCCUPANCY @%'
                                THEN ISNULL(AsarfiCount, 0) ELSE 0 END) AS OccAsarfi,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'OCCUPANCY @%'
                                THEN ISNULL(CardiacCount, 0) ELSE 0 END) AS OccCardiac,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'OCCUPANCY @%'
                                THEN ISNULL(TotalCount, 0) ELSE 0 END) AS OccTotal,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'OPD COUNT%'
                                THEN ISNULL(AsarfiCount, 0) ELSE 0 END) AS OpdAsarfi,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'OPD COUNT%'
                                THEN ISNULL(CardiacCount, 0) ELSE 0 END) AS OpdCardiac,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'OPD COUNT%'
                                THEN ISNULL(TotalCount, 0) ELSE 0 END) AS OpdTotal,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'ADMISSION PREVIOUS DAY%'
                                 AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE '%00:00%'
                                THEN ISNULL(AsarfiCount, 0) ELSE 0 END) AS PrevAdmAsarfi,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'ADMISSION PREVIOUS DAY%'
                                 AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE '%00:00%'
                                THEN ISNULL(CardiacCount, 0) ELSE 0 END) AS PrevAdmCardiac,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'ADMISSION PREVIOUS DAY%'
                                 AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE '%00:00%'
                                THEN ISNULL(TotalCount, 0) ELSE 0 END) AS PrevAdmTotal,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'DISCHARGE PREVIOUS DAY%'
                                THEN ISNULL(AsarfiCount, 0) ELSE 0 END) AS PrevDisAsarfi,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'DISCHARGE PREVIOUS DAY%'
                                THEN ISNULL(CardiacCount, 0) ELSE 0 END) AS PrevDisCardiac,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'DISCHARGE PREVIOUS DAY%'
                                THEN ISNULL(TotalCount, 0) ELSE 0 END) AS PrevDisTotal,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'NIGHT ADMISSION%'
                                 AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE '%08%'
                                THEN ISNULL(AsarfiCount, 0) ELSE 0 END) AS Night0800Asarfi,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'NIGHT ADMISSION%'
                                 AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE '%08%'
                                THEN ISNULL(CardiacCount, 0) ELSE 0 END) AS Night0800Cardiac,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'NIGHT ADMISSION%'
                                 AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE '%08%'
                                THEN ISNULL(TotalCount, 0) ELSE 0 END) AS Night0800Total
                FROM dbo.HID_Morning_Report_Summary WITH (NOLOCK)
                WHERE SnapshotDate BETWEEN ? AND ? AND Unit IN ({placeholders})
                GROUP BY SnapshotDate, Unit
            ),
            invseg AS (
                SELECT SnapshotDate, Unit,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) = 'TOTAL'
                                THEN 0 ELSE ISNULL(AsarfiCount, 0) END) AS InvAsarfi,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) = 'TOTAL'
                                THEN 0 ELSE ISNULL(CardiacCount, 0) END) AS InvCardiac,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) = 'TOTAL'
                                THEN 0 ELSE ISNULL(TotalCount, 0) END) AS InvestigationTotal
                FROM dbo.HID_Morning_Report_Investigation WITH (NOLOCK)
                WHERE SnapshotDate BETWEEN ? AND ? AND Unit IN ({placeholders})
                GROUP BY SnapshotDate, Unit
            ),
            procedure_cte AS (
                SELECT SnapshotDate, Unit,
                       SUM(ISNULL(ProcCount, 0)) AS ProcedureTotal
                FROM dbo.HID_Morning_Report_Procedure WITH (NOLOCK)
                WHERE SnapshotDate BETWEEN ? AND ? AND Unit IN ({placeholders})
                GROUP BY SnapshotDate, Unit
            )
            SELECT
                base.SnapshotDate,
                base.Unit,
                base.SnapshotTime,
                ISNULL(occ.OccupancyUsed, 0) AS OccupancyUsed,
                ISNULL(occ.Beds, 0) AS Beds,
                ISNULL(doc.OPDTotal, 0) AS OPDTotal,
                ISNULL(doc.IPDTotal, 0) AS IPDTotal,
                ISNULL(invseg.InvestigationTotal, 0) AS InvestigationTotal,
                ISNULL(procedure_cte.ProcedureTotal, 0) AS ProcedureTotal,
                ISNULL(sumry.OccAsarfi, 0) AS OccAsarfi,
                ISNULL(sumry.OccCardiac, 0) AS OccCardiac,
                ISNULL(sumry.OccTotal, 0) AS OccTotal,
                ISNULL(sumry.OpdAsarfi, 0) AS OpdAsarfi,
                ISNULL(sumry.OpdCardiac, 0) AS OpdCardiac,
                ISNULL(sumry.OpdTotal, 0) AS OpdTotal,
                ISNULL(sumry.PrevAdmAsarfi, 0) AS PrevAdmAsarfi,
                ISNULL(sumry.PrevAdmCardiac, 0) AS PrevAdmCardiac,
                ISNULL(sumry.PrevAdmTotal, 0) AS PrevAdmTotal,
                ISNULL(sumry.PrevDisAsarfi, 0) AS PrevDisAsarfi,
                ISNULL(sumry.PrevDisCardiac, 0) AS PrevDisCardiac,
                ISNULL(sumry.PrevDisTotal, 0) AS PrevDisTotal,
                ISNULL(sumry.Night0800Asarfi, 0) AS Night0800Asarfi,
                ISNULL(sumry.Night0800Cardiac, 0) AS Night0800Cardiac,
                ISNULL(sumry.Night0800Total, 0) AS Night0800Total,
                ISNULL(invseg.InvAsarfi, 0) AS InvAsarfi,
                ISNULL(invseg.InvCardiac, 0) AS InvCardiac
            FROM base
            LEFT JOIN occ  ON occ.SnapshotDate  = base.SnapshotDate AND occ.Unit  = base.Unit
            LEFT JOIN doc  ON doc.SnapshotDate  = base.SnapshotDate AND doc.Unit  = base.Unit
            LEFT JOIN sumry ON sumry.SnapshotDate = base.SnapshotDate AND sumry.Unit = base.Unit
            LEFT JOIN invseg ON invseg.SnapshotDate = base.SnapshotDate AND invseg.Unit = base.Unit
            LEFT JOIN procedure_cte ON procedure_cte.SnapshotDate = base.SnapshotDate AND procedure_cte.Unit = base.Unit
            ORDER BY base.SnapshotDate DESC, base.Unit ASC
        """
        cur.execute(
            morning_sql,
            [
                *params,
                *params,
                *params,
                *params,
                *params,
                *params,
            ],
        )
        for (
            snap_date, unit, snap_time,
            occ_used, beds, opd, ipd, inv_total, proc_total,
            occ_asarfi, occ_cardiac, occ_total,
            opd_asarfi, opd_cardiac, opd_total,
            prev_adm_asarfi, prev_adm_cardiac, prev_adm_total,
            prev_dis_asarfi, prev_dis_cardiac, prev_dis_total,
            night_0800_asarfi, night_0800_cardiac, night_0800_total,
            inv_asarfi, inv_cardiac
        ) in cur.fetchall():
            date_key = _mod_summary_normalize_date(snap_date)
            unit_key = str(unit or "").strip().upper()
            if not date_key or not unit_key:
                continue
            item = _upsert(date_key, unit_key)
            item["morning_saved"] = True
            item["morning_snapshot_time"] = snap_time
            is_ahl_split = split_mode and unit_key == "AHL"
            if is_ahl_split:
                seg_occ = int(occ_asarfi or 0) if segment_norm == "asarfi" else int(occ_cardiac or 0)
                seg_opd = int(opd_asarfi or 0) if segment_norm == "asarfi" else int(opd_cardiac or 0)
                seg_inv = int(inv_asarfi or 0) if segment_norm == "asarfi" else int(inv_cardiac or 0)
                seg_night_0800 = int(night_0800_asarfi or 0) if segment_norm == "asarfi" else int(night_0800_cardiac or 0)
                seg_prev_adm = int(prev_adm_asarfi or 0) if segment_norm == "asarfi" else int(prev_adm_cardiac or 0)
                seg_prev_dis = int(prev_dis_asarfi or 0) if segment_norm == "asarfi" else int(prev_dis_cardiac or 0)
                occ_total_ref = int(occ_total or 0) or int(occ_used or 0)
                seg_proc = 0
                if occ_total_ref > 0:
                    seg_proc = int(round((int(proc_total or 0) * seg_occ) / float(occ_total_ref)))
                item["occupancy_used_morning"] = seg_occ
                item["occupancy_beds_morning"] = int(beds or 0)
                item["opd_total"] = seg_opd
                # segmented IPD is not persisted separately; use 08:00 occupancy count as IPD proxy
                item["ipd_total"] = seg_occ
                item["night_0000_0800_admissions"] = seg_night_0800
                item["morning_prev_admissions"] = seg_prev_adm
                item["morning_prev_discharges"] = seg_prev_dis
                item["investigation_total"] = seg_inv
                item["procedure_total"] = seg_proc
            else:
                item["occupancy_used_morning"] = int(occ_used or 0)
                item["occupancy_beds_morning"] = int(beds or 0)
                item["opd_total"] = int(opd_total or opd or 0)
                item["ipd_total"] = int(ipd or 0)
                item["night_0000_0800_admissions"] = int(night_0800_total or 0)
                item["morning_prev_admissions"] = int(prev_adm_total or 0)
                item["morning_prev_discharges"] = int(prev_dis_total or 0)
                item["investigation_total"] = int(inv_total or 0)
                item["procedure_total"] = int(proc_total or 0)

        night_sql = f"""
            WITH ward AS (
                SELECT SnapshotDate, Unit,
                       MAX(SnapshotTime) AS SnapshotTime,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(WardName, '')))) IN ('TOTAL', 'TOTALS')
                                THEN 0
                                ELSE ISNULL(OccupiedCount, 0) + ISNULL(ClinicallyDischargedCount, 0) END) AS OccupancyUsed,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(WardName, '')))) IN ('TOTAL', 'TOTALS')
                                THEN 0
                                ELSE ISNULL(BedCount, 0) END) AS Beds
                FROM dbo.HID_Night_Report_Ward WITH (NOLOCK)
                WHERE SnapshotDate BETWEEN ? AND ? AND Unit IN ({placeholders})
                GROUP BY SnapshotDate, Unit
            ),
            detail AS (
                SELECT SnapshotDate, Unit,
                       MAX(SnapshotTime) AS SnapshotTime,
                       MAX(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Section, '')))) = 'PARTICULARS'
                                  AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) = 'TOTAL'
                                THEN 1 ELSE 0 END) AS HasParticularTotal,
                       MAX(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Section, '')))) = 'PARTICULARS'
                                  AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) = 'TOTAL'
                                THEN ISNULL(Admission, 0) ELSE 0 END) AS TotalAdmissions,
                       MAX(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Section, '')))) = 'PARTICULARS'
                                  AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) = 'TOTAL'
                                THEN ISNULL(Discharge, 0) ELSE 0 END) AS TotalDischarges,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Section, '')))) = 'PARTICULARS'
                                  AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) <> 'TOTAL'
                                THEN ISNULL(Admission, 0) ELSE 0 END) AS SumAdmissions,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Section, '')))) = 'PARTICULARS'
                                  AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) <> 'TOTAL'
                                THEN ISNULL(Discharge, 0) ELSE 0 END) AS SumDischarges,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Section, '')))) = 'PARTICULARS'
                                  AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) IN ('ASARFI UNIT', 'ASARFI')
                                THEN ISNULL(Admission, 0) ELSE 0 END) AS AsarfiAdmissions,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Section, '')))) = 'PARTICULARS'
                                  AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) IN ('ASARFI UNIT', 'ASARFI')
                                THEN ISNULL(Discharge, 0) ELSE 0 END) AS AsarfiDischarges,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Section, '')))) = 'PARTICULARS'
                                  AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) IN ('CARDIAC UNIT', 'CARDIAC')
                                THEN ISNULL(Admission, 0) ELSE 0 END) AS CardiacAdmissions,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Section, '')))) = 'PARTICULARS'
                                  AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) IN ('CARDIAC UNIT', 'CARDIAC')
                                THEN ISNULL(Discharge, 0) ELSE 0 END) AS CardiacDischarges
                FROM dbo.HID_Night_Report_Detail WITH (NOLOCK)
                WHERE SnapshotDate BETWEEN ? AND ? AND Unit IN ({placeholders})
                GROUP BY SnapshotDate, Unit
            )
            SELECT
                COALESCE(ward.SnapshotDate, detail.SnapshotDate) AS SnapshotDate,
                COALESCE(ward.Unit, detail.Unit) AS Unit,
                ward.SnapshotTime AS WardSnapshotTime,
                detail.SnapshotTime AS DetailSnapshotTime,
                ISNULL(ward.OccupancyUsed, 0) AS OccupancyUsed,
                ISNULL(ward.Beds, 0) AS Beds,
                CASE WHEN ISNULL(detail.HasParticularTotal, 0) = 1
                     THEN ISNULL(detail.TotalAdmissions, 0)
                     ELSE ISNULL(detail.SumAdmissions, 0) END AS NightAdmissions,
                CASE WHEN ISNULL(detail.HasParticularTotal, 0) = 1
                     THEN ISNULL(detail.TotalDischarges, 0)
                     ELSE ISNULL(detail.SumDischarges, 0) END AS NightDischarges,
                ISNULL(detail.AsarfiAdmissions, 0) AS AsarfiAdmissions,
                ISNULL(detail.AsarfiDischarges, 0) AS AsarfiDischarges,
                ISNULL(detail.CardiacAdmissions, 0) AS CardiacAdmissions,
                ISNULL(detail.CardiacDischarges, 0) AS CardiacDischarges
            FROM ward
            FULL OUTER JOIN detail
              ON detail.SnapshotDate = ward.SnapshotDate AND detail.Unit = ward.Unit
            ORDER BY COALESCE(ward.SnapshotDate, detail.SnapshotDate) DESC,
                     COALESCE(ward.Unit, detail.Unit) ASC
        """
        cur.execute(night_sql, [*params, *params])
        for (
            snap_date, unit, ward_snap_time, detail_snap_time, occ_used, beds, night_adm, night_dis,
            asarfi_adm, asarfi_dis, cardiac_adm, cardiac_dis
        ) in cur.fetchall():
            date_key = _mod_summary_normalize_date(snap_date)
            unit_key = str(unit or "").strip().upper()
            if not date_key or not unit_key:
                continue
            item = _upsert(date_key, unit_key)
            item["night_saved"] = True
            item["night_snapshot_time"] = detail_snap_time or ward_snap_time
            item["occupancy_used_night"] = int(occ_used or 0)
            item["occupancy_beds_night"] = int(beds or 0)
            is_ahl_split = split_mode and unit_key == "AHL"
            if is_ahl_split:
                seg_adm = int(asarfi_adm or 0) if segment_norm == "asarfi" else int(cardiac_adm or 0)
                seg_dis = int(asarfi_dis or 0) if segment_norm == "asarfi" else int(cardiac_dis or 0)
                item["night_admissions"] = seg_adm
                item["night_discharges"] = seg_dis
            else:
                item["night_admissions"] = int(night_adm or 0)
                item["night_discharges"] = int(night_dis or 0)

    daily_by_date: dict[str, dict] = {}
    for row in records.values():
        date_key = row["snapshot_date"]
        day = daily_by_date.setdefault(
            date_key,
            {
                "period_key": date_key,
                "period_label": date_key,
                "days": 1,
                "units": set(),
                "reports_saved": 0,
                "expected_reports": expected_units * 2,
                "morning_reports": 0,
                "night_reports": 0,
                "occupancy_used": 0,
                "occupancy_beds": 0,
                "opd_total": 0,
                "ipd_total": 0,
                "night_admissions": 0,
                "night_discharges": 0,
                "night_0000_0800_admissions": 0,
                "investigation_total": 0,
                "procedure_total": 0,
                "_updated_dt": None,
            },
        )
        day["units"].add(row["unit"])
        if row.get("morning_saved"):
            day["morning_reports"] += 1
            day["reports_saved"] += 1
        if row.get("night_saved"):
            day["night_reports"] += 1
            day["reports_saved"] += 1

        occ_used = int(row.get("occupancy_used_morning") or 0)
        occ_beds = int(row.get("occupancy_beds_morning") or 0)
        if occ_beds <= 0:
            occ_used = int(row.get("occupancy_used_night") or 0)
            occ_beds = int(row.get("occupancy_beds_night") or 0)
        day["occupancy_used"] += max(0, occ_used)
        day["occupancy_beds"] += max(0, occ_beds)

        day["opd_total"] += int(row.get("opd_total") or 0)
        day["ipd_total"] += int(row.get("ipd_total") or 0)
        row_night_adm = int(row.get("night_admissions") or 0)
        row_night_dis = int(row.get("night_discharges") or 0)
        row_prev_adm = int(row.get("morning_prev_admissions") or 0)
        row_prev_dis = int(row.get("morning_prev_discharges") or 0)
        if row_night_adm <= 0 and row_prev_adm > 0:
            row_night_adm = row_prev_adm
        if row_night_dis <= 0 and row_prev_dis > 0:
            row_night_dis = row_prev_dis
        day["night_admissions"] += row_night_adm
        day["night_discharges"] += row_night_dis
        day["night_0000_0800_admissions"] += int(row.get("night_0000_0800_admissions") or 0)
        day["investigation_total"] += int(row.get("investigation_total") or 0)
        day["procedure_total"] += int(row.get("procedure_total") or 0)

        updated_dt = _coerce_local_dt(row.get("morning_snapshot_time"))
        night_dt = _coerce_local_dt(row.get("night_snapshot_time"))
        if night_dt and (not updated_dt or night_dt > updated_dt):
            updated_dt = night_dt
        if updated_dt and (day["_updated_dt"] is None or updated_dt > day["_updated_dt"]):
            day["_updated_dt"] = updated_dt

    daily_rows = []
    for date_key, row in daily_by_date.items():
        beds = int(row.get("occupancy_beds") or 0)
        used = int(row.get("occupancy_used") or 0)
        occupancy_pct = round((used / beds) * 100.0, 2) if beds else None
        expected_reports = max(1, int(row.get("expected_reports") or (expected_units * 2)))
        coverage_pct = round((float(row.get("reports_saved") or 0) / expected_reports) * 100.0, 1)
        updated_at = row["_updated_dt"].strftime("%Y-%m-%d %H:%M:%S") if row.get("_updated_dt") else ""
        daily_rows.append(
            {
                "period_key": date_key,
                "period_label": date_key,
                "days": 1,
                "units_covered": len(row.get("units") or []),
                "reports_saved": int(row.get("reports_saved") or 0),
                "expected_reports": expected_reports,
                "morning_reports": int(row.get("morning_reports") or 0),
                "night_reports": int(row.get("night_reports") or 0),
                "occupancy_used": used,
                "occupancy_beds": beds,
                "avg_occupancy_pct": occupancy_pct,
                "avg_opd": round(float(row.get("opd_total") or 0), 2),
                "avg_ipd": round(float(row.get("ipd_total") or 0), 2),
                "avg_night_admissions": round(float(row.get("night_admissions") or 0), 2),
                "avg_night_discharges": round(float(row.get("night_discharges") or 0), 2),
                "avg_night_0000_0800_admissions": round(float(row.get("night_0000_0800_admissions") or 0), 2),
                "avg_investigations": round(float(row.get("investigation_total") or 0), 2),
                "avg_procedures": round(float(row.get("procedure_total") or 0), 2),
                "total_opd": int(row.get("opd_total") or 0),
                "total_ipd": int(row.get("ipd_total") or 0),
                "total_night_admissions": int(row.get("night_admissions") or 0),
                "total_night_discharges": int(row.get("night_discharges") or 0),
                "total_night_0000_0800_admissions": int(row.get("night_0000_0800_admissions") or 0),
                "total_investigations": int(row.get("investigation_total") or 0),
                "total_procedures": int(row.get("procedure_total") or 0),
                "coverage_pct": coverage_pct,
                "status": _mod_summary_row_status(coverage_pct, occupancy_pct),
                "updated_at": updated_at,
                "_updated_dt": row.get("_updated_dt"),
            }
        )

    daily_rows.sort(key=lambda r: r.get("period_key") or "", reverse=True)
    return daily_rows


def _aggregate_mod_summary_rows(daily_rows: list[dict], duration: str) -> list[dict]:
    if duration == "daily":
        return daily_rows

    buckets: dict[str, dict] = {}
    for row in daily_rows:
        period_key = row.get("period_key") or ""
        try:
            dt_val = datetime.strptime(period_key, "%Y-%m-%d").date()
        except Exception:
            continue

        if duration == "yearly":
            key = dt_val.strftime("%Y")
            label = key
        else:
            key = dt_val.strftime("%Y-%m")
            label = dt_val.strftime("%b %Y")

        bucket = buckets.setdefault(
            key,
            {
                "period_key": key,
                "period_label": label,
                "days": 0,
                "reports_saved": 0,
                "expected_reports": 0,
                "morning_reports": 0,
                "night_reports": 0,
                "units_covered": 0,
                "occupancy_used": 0,
                "occupancy_beds": 0,
                "opd_total": 0.0,
                "ipd_total": 0.0,
                "night_admissions_total": 0.0,
                "night_discharges_total": 0.0,
                "night_0000_0800_admissions_total": 0.0,
                "investigations_total": 0.0,
                "procedures_total": 0.0,
                "_updated_dt": None,
                "updated_at": "",
            },
        )

        bucket["days"] += 1
        bucket["reports_saved"] += int(row.get("reports_saved") or 0)
        bucket["expected_reports"] += int(row.get("expected_reports") or 0)
        bucket["morning_reports"] += int(row.get("morning_reports") or 0)
        bucket["night_reports"] += int(row.get("night_reports") or 0)
        bucket["units_covered"] = max(bucket["units_covered"], int(row.get("units_covered") or 0))
        bucket["occupancy_used"] += int(row.get("occupancy_used") or 0)
        bucket["occupancy_beds"] += int(row.get("occupancy_beds") or 0)
        bucket["opd_total"] += float(row.get("avg_opd") or 0.0)
        bucket["ipd_total"] += float(row.get("avg_ipd") or 0.0)
        bucket["night_admissions_total"] += float(row.get("avg_night_admissions") or 0.0)
        bucket["night_discharges_total"] += float(row.get("avg_night_discharges") or 0.0)
        bucket["night_0000_0800_admissions_total"] += float(row.get("avg_night_0000_0800_admissions") or 0.0)
        bucket["investigations_total"] += float(row.get("avg_investigations") or 0.0)
        bucket["procedures_total"] += float(row.get("avg_procedures") or 0.0)

        updated_dt = row.get("_updated_dt")
        if updated_dt and (bucket["_updated_dt"] is None or updated_dt > bucket["_updated_dt"]):
            bucket["_updated_dt"] = updated_dt

    out = []
    for key, item in buckets.items():
        days = max(1, int(item.get("days") or 1))
        occ_beds = int(item.get("occupancy_beds") or 0)
        occ_used = int(item.get("occupancy_used") or 0)
        occupancy_pct = round((occ_used / occ_beds) * 100.0, 2) if occ_beds else None
        expected_reports = max(1, int(item.get("expected_reports") or 0))
        coverage_pct = round((float(item.get("reports_saved") or 0) / expected_reports) * 100.0, 1)
        updated_dt = item.get("_updated_dt")
        item["updated_at"] = updated_dt.strftime("%Y-%m-%d %H:%M:%S") if updated_dt else ""
        out.append(
            {
                "period_key": key,
                "period_label": item.get("period_label") or key,
                "days": days,
                "units_covered": int(item.get("units_covered") or 0),
                "reports_saved": int(item.get("reports_saved") or 0),
                "expected_reports": expected_reports,
                "morning_reports": int(item.get("morning_reports") or 0),
                "night_reports": int(item.get("night_reports") or 0),
                "occupancy_used": occ_used,
                "occupancy_beds": occ_beds,
                "avg_occupancy_pct": occupancy_pct,
                "avg_opd": round(float(item.get("opd_total") or 0.0) / days, 2),
                "avg_ipd": round(float(item.get("ipd_total") or 0.0) / days, 2),
                "avg_night_admissions": round(float(item.get("night_admissions_total") or 0.0) / days, 2),
                "avg_night_discharges": round(float(item.get("night_discharges_total") or 0.0) / days, 2),
                "avg_night_0000_0800_admissions": round(float(item.get("night_0000_0800_admissions_total") or 0.0) / days, 2),
                "avg_investigations": round(float(item.get("investigations_total") or 0.0) / days, 2),
                "avg_procedures": round(float(item.get("procedures_total") or 0.0) / days, 2),
                "total_opd": int(round(float(item.get("opd_total") or 0.0))),
                "total_ipd": int(round(float(item.get("ipd_total") or 0.0))),
                "total_night_admissions": int(round(float(item.get("night_admissions_total") or 0.0))),
                "total_night_discharges": int(round(float(item.get("night_discharges_total") or 0.0))),
                "total_night_0000_0800_admissions": int(round(float(item.get("night_0000_0800_admissions_total") or 0.0))),
                "total_investigations": int(round(float(item.get("investigations_total") or 0.0))),
                "total_procedures": int(round(float(item.get("procedures_total") or 0.0))),
                "coverage_pct": coverage_pct,
                "status": _mod_summary_row_status(coverage_pct, occupancy_pct),
                "updated_at": item.get("updated_at") or "",
                "_updated_dt": updated_dt,
            }
        )

    out.sort(key=lambda r: r.get("period_key") or "", reverse=True)
    return out


def _fetch_mod_summary_department_insights(
    units_to_use: list[str], from_date: str, to_date: str, duration: str
) -> dict:
    if not units_to_use:
        return {
            "opd": {"potential": [], "needs_attention": [], "steady": [], "stagnating": []},
            "ipd": {"potential": [], "needs_attention": [], "steady": [], "stagnating": []},
            "total_departments": 0,
        }

    placeholders = ",".join("?" * len(units_to_use))
    params = [from_date, to_date, *units_to_use]
    dept_daily: dict[str, dict[str, dict[str, float]]] = {}

    with _get_login_db_connection() as conn:
        _ensure_morning_report_tables(conn)
        cur = conn.cursor()
        cur.execute(
            f"""
            SELECT SnapshotDate, Department,
                   SUM(ISNULL(OPDCount, 0)) AS OPDTotal,
                   SUM(ISNULL(IPDCount, 0)) AS IPDTotal
            FROM dbo.HID_Morning_Report_Doctorwise WITH (NOLOCK)
            WHERE SnapshotDate BETWEEN ? AND ?
              AND Unit IN ({placeholders})
              AND UPPER(LTRIM(RTRIM(ISNULL(Department, '')))) <> 'TOTAL'
            GROUP BY SnapshotDate, Department
            ORDER BY SnapshotDate ASC
            """,
            params,
        )
        rows = cur.fetchall()

    for snap_date, department, opd_total, ipd_total in rows:
        date_key = _mod_summary_normalize_date(snap_date)
        dept_key = str(department or "").strip()
        if not date_key or not dept_key:
            continue
        per_dept = dept_daily.setdefault(dept_key, {})
        item = per_dept.setdefault(date_key, {"opd": 0.0, "ipd": 0.0})
        item["opd"] += float(opd_total or 0.0)
        item["ipd"] += float(ipd_total or 0.0)

    def _trend_window(length: int) -> int:
        if duration == "yearly":
            return min(2, max(1, length // 2))
        if duration == "monthly":
            return min(3, max(1, length // 2))
        return min(7, max(1, length // 2))

    def _build_stream(metric_key: str) -> dict:
        stats = []
        for dept, per_day in dept_daily.items():
            date_keys = sorted(per_day.keys())
            if not date_keys:
                continue
            vals = [float(per_day[d].get(metric_key) or 0.0) for d in date_keys]
            active_days = len(vals)
            avg_metric = (sum(vals) / active_days) if active_days else 0.0

            win = _trend_window(active_days)
            recent = sum(vals[-win:]) if vals else 0.0
            prev = sum(vals[-(2 * win):-win]) if active_days > win else 0.0
            delta = recent - prev
            delta_pct = round((delta / prev) * 100.0, 2) if prev > 0 else None

            stats.append(
                {
                    "department": dept,
                    "active_days": active_days,
                    "avg_metric": round(avg_metric, 2),
                    "recent_total": round(recent, 2),
                    "previous_total": round(prev, 2),
                    "trend_delta": round(delta, 2),
                    "trend_pct": delta_pct,
                }
            )

        if not stats:
            return {"potential": [], "needs_attention": [], "steady": [], "stagnating": []}

        avg_values = sorted([float(s.get("avg_metric") or 0.0) for s in stats if float(s.get("avg_metric") or 0.0) > 0])
        if avg_values:
            mid = len(avg_values) // 2
            median_avg = avg_values[mid] if len(avg_values) % 2 == 1 else (avg_values[mid - 1] + avg_values[mid]) / 2.0
        else:
            median_avg = 0.0
        stagnation_cutoff = max(2.0, median_avg * 0.5)
        steady_pct_band = 8.0

        def _is_growth(s: dict) -> bool:
            avg_metric = float(s.get("avg_metric") or 0.0)
            if avg_metric <= 0:
                return False
            delta = float(s.get("trend_delta") or 0.0)
            pct = s.get("trend_pct")
            if delta <= 0:
                return False
            if pct is None:
                return delta >= 2.0
            return float(pct) > 8.0 or delta >= 2.0

        def _is_drop(s: dict) -> bool:
            avg_metric = float(s.get("avg_metric") or 0.0)
            if avg_metric <= 0:
                return False
            delta = float(s.get("trend_delta") or 0.0)
            pct = s.get("trend_pct")
            if delta >= 0:
                return False
            if pct is None:
                return delta <= -2.0
            return float(pct) < -8.0 or delta <= -2.0

        potential = [s for s in stats if _is_growth(s)]
        potential.sort(
            key=lambda s: (
                float(s.get("trend_pct") if s.get("trend_pct") is not None else -9999),
                float(s.get("avg_metric") or 0.0),
            ),
            reverse=True,
        )

        needs_attention = [s for s in stats if _is_drop(s)]
        needs_attention.sort(
            key=lambda s: (
                float(s.get("trend_delta") or 0.0),
                -float(s.get("avg_metric") or 0.0),
            )
        )

        steady = []
        stagnating = []
        for s in stats:
            avg_metric = float(s.get("avg_metric") or 0.0)
            if avg_metric <= 0:
                continue
            trend_pct = s.get("trend_pct")
            trend_delta = float(s.get("trend_delta") or 0.0)
            is_stable_band = (
                (trend_pct is not None and abs(float(trend_pct)) <= steady_pct_band)
                or (trend_pct is None and abs(trend_delta) <= 1.0)
            )
            if not is_stable_band:
                continue
            if avg_metric <= stagnation_cutoff:
                stagnating.append(s)
            else:
                steady.append(s)

        steady.sort(
            key=lambda s: (
                abs(float(s.get("trend_pct") or 0.0)),
                -float(s.get("avg_metric") or 0.0),
            )
        )
        stagnating.sort(
            key=lambda s: (
                float(s.get("avg_metric") or 0.0),
                abs(float(s.get("trend_pct") or 0.0)),
            )
        )

        return {
            "potential": potential[:5],
            "needs_attention": needs_attention[:5],
            "steady": steady[:5],
            "stagnating": stagnating[:5],
        }

    return {
        "opd": _build_stream("opd"),
        "ipd": _build_stream("ipd"),
        "total_departments": len(dept_daily),
    }


def _parse_mod_export_date(value: str | None) -> date | None:
    raw = str(value or "").strip()
    if not raw:
        return None
    try:
        return datetime.strptime(raw, "%Y-%m-%d").date()
    except Exception:
        return None


def _resolve_mod_export_date_range(duration: str | None, from_raw: str | None, to_raw: str | None) -> tuple[str, date | None, date | None]:
    duration_norm = str(duration or "custom").strip().lower()
    if duration_norm not in {"day", "month", "year", "custom"}:
        duration_norm = "custom"

    today = datetime.now(tz=LOCAL_TZ).date()
    closed_to = today - timedelta(days=1)
    from_dt = _parse_mod_export_date(from_raw)
    to_dt = _parse_mod_export_date(to_raw)
    if str(from_raw or "").strip() and not from_dt:
        return duration_norm, None, None
    if str(to_raw or "").strip() and not to_dt:
        return duration_norm, None, None

    if from_dt and not to_dt:
        to_dt = from_dt
    elif to_dt and not from_dt:
        from_dt = to_dt

    if not from_dt and not to_dt:
        to_dt = closed_to
        if duration_norm == "year":
            from_dt = date(to_dt.year, 1, 1)
        elif duration_norm == "month":
            from_dt = date(to_dt.year, to_dt.month, 1)
        else:
            from_dt = to_dt

    return duration_norm, from_dt, to_dt


def _mod_seq_export_key(label: str) -> str:
    return re.sub(r"[^a-z0-9]+", "_", str(label or "").lower()).strip("_")


def _fetch_ahl_sequence_export_extras(from_date: str, to_date: str) -> dict[str, dict]:
    out: dict[str, dict] = {}
    ward_map: dict[str, list[tuple[str, int]]] = {}
    manual_by_date: dict[str, bool] = {}

    inv_labels = [str(label).strip() for label, _ in MORNING_REPORT_INVESTIGATION_MAP if str(label).strip()]
    proc_labels = [str(label).strip() for label in MORNING_REPORT_KEY_PROCEDURES if str(label).strip()]

    inv_alias_map: dict[str, str] = {}
    for label, aliases in MORNING_REPORT_INVESTIGATION_MAP:
        canonical = str(label or "").strip()
        if not canonical:
            continue
        for token in [canonical, *(aliases or [])]:
            key = _mod_seq_export_key(token)
            if key:
                inv_alias_map[key] = canonical

    proc_alias_map: dict[str, str] = {}
    for label in proc_labels:
        key = _mod_seq_export_key(label)
        if key:
            proc_alias_map[key] = label

    def _ensure(date_key: str) -> dict:
        item = out.get(date_key)
        if item is None:
            item = {
                "night_cash_occupancy": 0,
                "night_cashless_occupancy": 0,
                "night_asarfi_admissions": 0,
                "night_asarfi_discharges": 0,
                "night_cardiac_admissions": 0,
                "night_cardiac_discharges": 0,
                "night_0000_0800_asarfi_admissions": 0,
                "night_0000_0800_cardiac_admissions": 0,
                "night_0000_0800_total_admissions": 0,
                "ward_wise_patient_count": "",
                "morning_key_procedures": 0,
            }
            for inv_label in inv_labels:
                inv_key = _mod_seq_export_key(inv_label)
                item[f"inv_{inv_key}_asarfi"] = 0
                item[f"inv_{inv_key}_cardiac"] = 0
                item[f"inv_{inv_key}_total"] = 0
            for proc_label in proc_labels:
                proc_key = _mod_seq_export_key(proc_label)
                item[f"proc_{proc_key}"] = 0
            out[date_key] = item
        return item

    try:
        with _get_login_db_connection() as conn:
            _ensure_night_report_detail_table(conn)
            _ensure_night_report_ward_table(conn)
            _ensure_morning_report_tables(conn)
            cur = conn.cursor()

            cur.execute(
                """
                SELECT
                    SnapshotDate,
                    SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Section, '')))) = 'OCCUPANCY'
                              AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) = 'CASH'
                             THEN ISNULL([Count], 0) ELSE 0 END) AS CashOcc,
                    SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Section, '')))) = 'OCCUPANCY'
                              AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) = 'CASHLESS'
                             THEN ISNULL([Count], 0) ELSE 0 END) AS CashlessOcc,
                    SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Section, '')))) = 'PARTICULARS'
                              AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) IN ('ASARFI UNIT', 'ASARFI')
                             THEN ISNULL(Admission, 0) ELSE 0 END) AS AsarfiAdm,
                    SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Section, '')))) = 'PARTICULARS'
                              AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) IN ('ASARFI UNIT', 'ASARFI')
                             THEN ISNULL(Discharge, 0) ELSE 0 END) AS AsarfiDis,
                    SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Section, '')))) = 'PARTICULARS'
                              AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) IN ('CARDIAC UNIT', 'CARDIAC')
                             THEN ISNULL(Admission, 0) ELSE 0 END) AS CardiacAdm,
                    SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Section, '')))) = 'PARTICULARS'
                              AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) IN ('CARDIAC UNIT', 'CARDIAC')
                             THEN ISNULL(Discharge, 0) ELSE 0 END) AS CardiacDis
                FROM dbo.HID_Night_Report_Detail WITH (NOLOCK)
                WHERE Unit = 'AHL' AND SnapshotDate BETWEEN ? AND ?
                GROUP BY SnapshotDate
                """,
                (from_date, to_date),
            )
            for snap_date, cash, cashless, asarfi_adm, asarfi_dis, cardiac_adm, cardiac_dis in cur.fetchall():
                date_key = _mod_summary_normalize_date(snap_date)
                if not date_key:
                    continue
                item = _ensure(date_key)
                item["night_cash_occupancy"] = int(cash or 0)
                item["night_cashless_occupancy"] = int(cashless or 0)
                item["night_asarfi_admissions"] = int(asarfi_adm or 0)
                item["night_asarfi_discharges"] = int(asarfi_dis or 0)
                item["night_cardiac_admissions"] = int(cardiac_adm or 0)
                item["night_cardiac_discharges"] = int(cardiac_dis or 0)

            cur.execute(
                """
                SELECT SnapshotDate,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'NIGHT ADMISSION%'
                                 AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE '%08%'
                                THEN ISNULL(AsarfiCount, 0) ELSE 0 END) AS AsarfiNight0800,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'NIGHT ADMISSION%'
                                 AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE '%08%'
                                THEN ISNULL(CardiacCount, 0) ELSE 0 END) AS CardiacNight0800,
                       SUM(CASE WHEN UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE 'NIGHT ADMISSION%'
                                 AND UPPER(LTRIM(RTRIM(ISNULL(Label, '')))) LIKE '%08%'
                                THEN ISNULL(TotalCount, 0) ELSE 0 END) AS TotalNight0800
                FROM dbo.HID_Morning_Report_Summary WITH (NOLOCK)
                WHERE Unit = 'AHL' AND SnapshotDate BETWEEN ? AND ?
                GROUP BY SnapshotDate
                """,
                (from_date, to_date),
            )
            for snap_date, asarfi_0800, cardiac_0800, total_0800 in cur.fetchall():
                date_key = _mod_summary_normalize_date(snap_date)
                if not date_key:
                    continue
                item = _ensure(date_key)
                item["night_0000_0800_asarfi_admissions"] = int(asarfi_0800 or 0)
                item["night_0000_0800_cardiac_admissions"] = int(cardiac_0800 or 0)
                item["night_0000_0800_total_admissions"] = int(total_0800 or 0)

            cur.execute(
                """
                SELECT SnapshotDate, WardName, PatientCount
                FROM dbo.HID_Night_Report_Ward WITH (NOLOCK)
                WHERE Unit = 'AHL' AND SnapshotDate BETWEEN ? AND ?
                ORDER BY SnapshotDate ASC, WardName ASC
                """,
                (from_date, to_date),
            )
            for snap_date, ward_name, patient_count in cur.fetchall():
                date_key = _mod_summary_normalize_date(snap_date)
                ward = str(ward_name or "").strip()
                if not date_key or not ward:
                    continue
                ward_norm = ward.upper()
                if ward_norm in {"TOTAL", "TOTALS"}:
                    continue
                ward_map.setdefault(date_key, []).append((ward, int(patient_count or 0)))
                _ensure(date_key)

            cur.execute(
                """
                SELECT SnapshotDate, Label, AsarfiCount, CardiacCount, TotalCount
                FROM dbo.HID_Morning_Report_Investigation WITH (NOLOCK)
                WHERE Unit = 'AHL' AND SnapshotDate BETWEEN ? AND ?
                """,
                (from_date, to_date),
            )
            for snap_date, label, asarfi, cardiac, total in cur.fetchall():
                date_key = _mod_summary_normalize_date(snap_date)
                if not date_key:
                    continue
                label_key = _mod_seq_export_key(label)
                canonical = inv_alias_map.get(label_key)
                if not canonical:
                    continue
                inv_key = _mod_seq_export_key(canonical)
                item = _ensure(date_key)
                item[f"inv_{inv_key}_asarfi"] += int(asarfi or 0)
                item[f"inv_{inv_key}_cardiac"] += int(cardiac or 0)
                item[f"inv_{inv_key}_total"] += int(total or 0)

            cur.execute(
                """
                SELECT SnapshotDate,
                       MAX(CASE WHEN ISNULL(ManualFlag, 0) = 1 THEN 1 ELSE 0 END) AS HasManualSave
                FROM dbo.HID_Morning_Report_Summary WITH (NOLOCK)
                WHERE Unit = 'AHL' AND SnapshotDate BETWEEN ? AND ?
                GROUP BY SnapshotDate
                """,
                (from_date, to_date),
            )
            for snap_date, has_manual in cur.fetchall():
                date_key = _mod_summary_normalize_date(snap_date)
                if not date_key:
                    continue
                manual_by_date[date_key] = int(has_manual or 0) == 1
                _ensure(date_key)

            cur.execute(
                """
                SELECT SnapshotDate, Label, ProcCount
                FROM dbo.HID_Morning_Report_Procedure WITH (NOLOCK)
                WHERE Unit = 'AHL' AND SnapshotDate BETWEEN ? AND ?
                """,
                (from_date, to_date),
            )
            for snap_date, label, proc_count in cur.fetchall():
                date_key = _mod_summary_normalize_date(snap_date)
                if not date_key:
                    continue
                label_key = _mod_seq_export_key(label)
                canonical = proc_alias_map.get(label_key)
                if not canonical:
                    continue
                proc_key = _mod_seq_export_key(canonical)
                item = _ensure(date_key)
                item[f"proc_{proc_key}"] += int(proc_count or 0)
    except Exception:
        return out

    for date_key, ward_rows in ward_map.items():
        ward_rows_sorted = sorted(ward_rows, key=lambda x: str(x[0] or "").upper())
        text = " | ".join(f"{ward}:{count}" for ward, count in ward_rows_sorted) if ward_rows_sorted else ""
        item = _ensure(date_key)
        item["ward_wise_patient_count"] = text

    for date_key, item in out.items():
        has_manual = bool(manual_by_date.get(date_key, False))
        proc_total = 0
        for proc_label in proc_labels:
            proc_key = _mod_seq_export_key(proc_label)
            key = f"proc_{proc_key}"
            val = int(item.get(key) or 0)
            if not has_manual:
                item[key] = 0
                continue
            proc_total += val
        item["morning_key_procedures"] = proc_total if has_manual else 0

    return out


def _build_mod_sequence_audit_excel(
    rows: list[dict],
    *,
    from_date: str,
    to_date: str,
    unit_label: str,
    duration: str,
    segment: str,
    locked_only: bool,
    exported_by: str,
    include_ahl_details: bool = False,
) -> bytes:
    wb = Workbook()
    ws_night = wb.active
    ws_night.title = "Night Report"
    ws_morning = wb.create_sheet("Morning Report")
    ws_combined = wb.create_sheet("Combined")
    ws_details = wb.create_sheet("Sequence Details")

    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    title_font = Font(size=14, bold=True, color="1e3a8a")
    subtitle_font = Font(size=11, bold=True, color="1e3a8a")
    header_font = Font(bold=True, color="FFFFFF")
    thin = Side(border_style="thin", color="d1d5db")
    border = Border(top=thin, bottom=thin, left=thin, right=thin)
    header_fill = PatternFill(start_color="1e3a8a", end_color="1e3a8a", fill_type="solid")
    meta_fill = PatternFill(start_color="eff6ff", end_color="eff6ff", fill_type="solid")

    total_rows = len(rows)

    def _num(value, digits: int = 2):
        if value is None:
            return None
        try:
            return round(float(value), digits)
        except Exception:
            return None

    def _avg(field: str, digits: int = 2):
        vals = []
        for row in rows:
            val = row.get(field)
            try:
                if val is not None:
                    vals.append(float(val))
            except Exception:
                continue
        if not vals:
            return None
        return round(sum(vals) / len(vals), digits)

    def _latest_snapshot() -> str:
        best_text = ""
        best_dt = None
        fmts = ("%Y-%m-%d %H:%M:%S", "%Y-%m-%d %H:%M:%S.%f")
        for row in rows:
            raw = str(row.get("updated_at") or "").strip()
            if not raw:
                continue
            parsed = None
            for fmt in fmts:
                try:
                    parsed = datetime.strptime(raw, fmt)
                    break
                except Exception:
                    continue
            if parsed is not None:
                if best_dt is None or parsed > best_dt:
                    best_dt = parsed
                    best_text = raw
            elif not best_text or raw > best_text:
                best_text = raw
        return best_text or "-"

    latest_snapshot = _latest_snapshot()
    segment_title = str(segment or "total").strip().lower()
    if segment_title == "asarfi":
        segment_title = "Asarfi"
    elif segment_title == "cardiac":
        segment_title = "Cardiac"
    else:
        segment_title = "Combined"

    summary_line = (
        f"Locked Sequences Exported: {total_rows} | "
        "Includes summary averages and sequence-level raw detail rows."
    )

    key_procedures_avg = _avg("ahl_morning_key_procedures") if include_ahl_details else _avg("avg_procedures")

    night_metrics: list[tuple[str, object]] = [
        ("Locked Sequences", total_rows),
        ("Admissions (Prev Day upto 00:00)", _avg("avg_night_admissions")),
        ("Discharges (Prev Day)", _avg("avg_night_discharges")),
        ("Occupancy Used @08:00", _avg("occupancy_used")),
        ("Occupancy Beds @08:00", _avg("occupancy_beds")),
        ("Occupancy % @08:00", _avg("avg_occupancy_pct")),
        ("Latest Snapshot", latest_snapshot),
    ]
    morning_metrics: list[tuple[str, object]] = [
        ("Locked Sequences", total_rows),
        ("OPD (Prev Day upto 00:00)", _avg("avg_opd")),
        ("IPD (Prev Day upto 00:00)", _avg("avg_ipd")),
        ("Investigations Total (Prev Day)", _avg("avg_investigations")),
        ("Key Procedures Total (Prev Day)", key_procedures_avg),
        ("Occupancy Used @08:00", _avg("occupancy_used")),
        ("Occupancy Beds @08:00", _avg("occupancy_beds")),
        ("Occupancy % @08:00", _avg("avg_occupancy_pct")),
        ("Latest Snapshot", latest_snapshot),
    ]
    combined_metrics: list[tuple[str, str, object]] = [
        ("Night Report", "Admissions (Prev Day upto 00:00)", _avg("avg_night_admissions")),
        ("Night Report", "Discharges (Prev Day)", _avg("avg_night_discharges")),
        ("Night Report", "Occupancy Used @08:00", _avg("occupancy_used")),
        ("Night Report", "Occupancy Beds @08:00", _avg("occupancy_beds")),
        ("Night Report", "Occupancy % @08:00", _avg("avg_occupancy_pct")),
        ("Morning Report", "OPD (Prev Day upto 00:00)", _avg("avg_opd")),
        ("Morning Report", "IPD (Prev Day upto 00:00)", _avg("avg_ipd")),
        ("Morning Report", "Investigations Total (Prev Day)", _avg("avg_investigations")),
        ("Morning Report", "Key Procedures Total (Prev Day)", key_procedures_avg),
        ("Morning Report", "Occupancy Used @08:00", _avg("occupancy_used")),
        ("Morning Report", "Occupancy Beds @08:00", _avg("occupancy_beds")),
        ("Morning Report", "Occupancy % @08:00", _avg("avg_occupancy_pct")),
        ("Combined", "Locked Sequences", total_rows),
        ("Combined", "Latest Snapshot", latest_snapshot),
    ]
    ahl_inv_labels = [str(label).strip() for label, _ in MORNING_REPORT_INVESTIGATION_MAP if str(label).strip()]
    ahl_proc_labels = [str(label).strip() for label in MORNING_REPORT_KEY_PROCEDURES if str(label).strip()]

    details_rows: list[dict] = []
    for row in rows:
        status_label = str(row.get("status_label") or "").strip().upper() or "LOCKED"
        detail = {
            "Sequence Date": row.get("period_label") or row.get("period_key"),
            "Latest Snapshot": row.get("updated_at") or "-",
            "Admissions (Prev Day upto 00:00)": _num(row.get("avg_night_admissions"), 0),
            "Discharges (Prev Day)": _num(row.get("avg_night_discharges"), 0),
            "OPD (Prev Day upto 00:00)": _num(row.get("avg_opd"), 0),
            "IPD (Prev Day upto 00:00)": _num(row.get("avg_ipd"), 0),
            "Investigations Total (Prev Day)": _num(row.get("avg_investigations"), 0),
            "Key Procedures Total (Prev Day)": (
                _num(row.get("ahl_morning_key_procedures"), 0)
                if include_ahl_details
                else _num(row.get("avg_procedures"), 0)
            ),
            "Occupancy Used @08:00": _num(row.get("occupancy_used"), 0),
            "Occupancy Beds @08:00": _num(row.get("occupancy_beds"), 0),
            "Occupancy % @08:00": _num(row.get("avg_occupancy_pct")),
            "Sequence Status": status_label,
        }
        if include_ahl_details:
            detail["Cash Occupancy @00:00"] = _num(row.get("ahl_night_cash_occupancy"), 0)
            detail["Cashless Occupancy @00:00"] = _num(row.get("ahl_night_cashless_occupancy"), 0)
            detail["Asarfi Admission (Prev Day upto 00:00)"] = _num(row.get("ahl_night_asarfi_admissions"), 0)
            detail["Asarfi Discharge (Prev Day)"] = _num(row.get("ahl_night_asarfi_discharges"), 0)
            detail["Cardiac Admission (Prev Day upto 00:00)"] = _num(row.get("ahl_night_cardiac_admissions"), 0)
            detail["Cardiac Discharge (Prev Day)"] = _num(row.get("ahl_night_cardiac_discharges"), 0)
            detail["Asarfi Admission (00:00 to 08:00 Today)"] = _num(row.get("ahl_night_0000_0800_asarfi_admissions"), 0)
            detail["Cardiac Admission (00:00 to 08:00 Today)"] = _num(row.get("ahl_night_0000_0800_cardiac_admissions"), 0)
            detail["Admission (00:00 to 08:00 Today Total)"] = _num(row.get("ahl_night_0000_0800_total_admissions"), 0)
            detail["Ward-wise Patient Count"] = row.get("ahl_night_ward_wise_patient_count") or "-"
            for label in ahl_inv_labels:
                key = _mod_seq_export_key(label)
                detail[f"Investigation {label} Asarfi"] = _num(row.get(f"ahl_inv_{key}_asarfi"), 0)
                detail[f"Investigation {label} Cardiac"] = _num(row.get(f"ahl_inv_{key}_cardiac"), 0)
                detail[f"Investigation {label} Total"] = _num(row.get(f"ahl_inv_{key}_total"), 0)
            for label in ahl_proc_labels:
                key = _mod_seq_export_key(label)
                detail[f"Key Procedure {label}"] = _num(row.get(f"ahl_proc_{key}"), 0)
        details_rows.append(detail)

    def _write_sheet_meta(ws, title: str, total_cols: int) -> None:
        total_cols = max(1, int(total_cols or 1))
        ws.append([title])
        ws.merge_cells(start_row=1, start_column=1, end_row=1, end_column=total_cols)
        ws["A1"].font = title_font
        ws["A1"].alignment = Alignment(horizontal="center", vertical="center")

        ws.append([f"Unit: {unit_label} | Date Range: {from_date} to {to_date} | Range: {duration.title()} | Segment: {segment_title}"])
        ws.merge_cells(start_row=2, start_column=1, end_row=2, end_column=total_cols)
        ws["A2"].font = subtitle_font
        ws["A2"].alignment = Alignment(horizontal="center", vertical="center")
        ws["A2"].fill = meta_fill

        ws.append([f"Exported By: {exported_by} | Exported At: {exported_at} | Locked Only: {'Yes' if locked_only else 'No'}"])
        ws.merge_cells(start_row=3, start_column=1, end_row=3, end_column=total_cols)
        ws["A3"].alignment = Alignment(horizontal="center", vertical="center")
        ws["A3"].fill = meta_fill

        ws.append([summary_line])
        ws.merge_cells(start_row=4, start_column=1, end_row=4, end_column=total_cols)
        ws["A4"].alignment = Alignment(horizontal="center", vertical="center")
        ws["A4"].fill = meta_fill

    def _autosize(ws) -> None:
        for col_idx in range(1, ws.max_column + 1):
            col_letter = get_column_letter(col_idx)
            max_len = 0
            for row_idx in range(1, ws.max_row + 1):
                value = ws.cell(row=row_idx, column=col_idx).value
                if value is None:
                    continue
                max_len = max(max_len, len(str(value)))
            ws.column_dimensions[col_letter].width = min(max_len + 2, 42)

    def _write_metric_sheet(ws, title: str, metrics: list[tuple[str, object]]) -> None:
        headers = ["Metric", "Average"]
        _write_sheet_meta(ws, title, len(headers))
        ws.append([])
        ws.append(headers)
        header_row = ws.max_row
        for cell in ws[header_row]:
            cell.font = header_font
            cell.fill = header_fill
            cell.alignment = Alignment(horizontal="center", vertical="center")
            cell.border = border

        if not metrics:
            ws.append(["No locked MOD sequence rows found for this selection."])
            ws.merge_cells(start_row=header_row + 1, start_column=1, end_row=header_row + 1, end_column=len(headers))
            ws["A" + str(header_row + 1)].alignment = Alignment(horizontal="center", vertical="center")
            ws["A" + str(header_row + 1)].border = border
            _autosize(ws)
            return

        for label, value in metrics:
            out_value = value if value is not None else "-"
            ws.append([label, out_value])
            excel_row = ws.max_row
            label_cell = ws.cell(row=excel_row, column=1)
            value_cell = ws.cell(row=excel_row, column=2)
            label_cell.border = border
            value_cell.border = border
            label_cell.alignment = Alignment(horizontal="left", vertical="center")
            if isinstance(out_value, (int, float)):
                if str(label).strip().endswith("%"):
                    value_cell.number_format = '0.00"%"'
                elif str(label).strip().lower() == "locked sequences":
                    value_cell.number_format = "#,##0"
                else:
                    value_cell.number_format = "#,##0.00"
                value_cell.alignment = Alignment(horizontal="right", vertical="center")
            else:
                value_cell.alignment = Alignment(horizontal="left", vertical="center")

        ws.freeze_panes = f"A{header_row + 1}"
        _autosize(ws)

    def _write_combined_sheet(ws) -> None:
        headers = ["Section", "Metric", "Average"]
        _write_sheet_meta(ws, "Combined Night + Morning MOD Audit", len(headers))
        ws.append([])
        ws.append(headers)
        header_row = ws.max_row
        for cell in ws[header_row]:
            cell.font = header_font
            cell.fill = header_fill
            cell.alignment = Alignment(horizontal="center", vertical="center")
            cell.border = border

        if not combined_metrics:
            ws.append(["No locked MOD sequence rows found for this selection."])
            ws.merge_cells(start_row=header_row + 1, start_column=1, end_row=header_row + 1, end_column=len(headers))
            ws["A" + str(header_row + 1)].alignment = Alignment(horizontal="center", vertical="center")
            ws["A" + str(header_row + 1)].border = border
            _autosize(ws)
            return

        for section, metric, value in combined_metrics:
            out_value = value if value is not None else "-"
            ws.append([section, metric, out_value])
            excel_row = ws.max_row
            section_cell = ws.cell(row=excel_row, column=1)
            metric_cell = ws.cell(row=excel_row, column=2)
            value_cell = ws.cell(row=excel_row, column=3)
            section_cell.border = border
            metric_cell.border = border
            value_cell.border = border
            section_cell.alignment = Alignment(horizontal="left", vertical="center")
            metric_cell.alignment = Alignment(horizontal="left", vertical="center")
            if isinstance(out_value, (int, float)):
                if str(metric).strip().endswith("%"):
                    value_cell.number_format = '0.00"%"'
                elif str(metric).strip().lower() == "locked sequences":
                    value_cell.number_format = "#,##0"
                else:
                    value_cell.number_format = "#,##0.00"
                value_cell.alignment = Alignment(horizontal="right", vertical="center")
            else:
                value_cell.alignment = Alignment(horizontal="left", vertical="center")

        ws.freeze_panes = f"A{header_row + 1}"
        _autosize(ws)

    def _write_details_sheet(ws) -> None:
        headers = ["Sequence Date"]
        if include_ahl_details:
            headers.extend(
                [
                    "Cash Occupancy @00:00",
                    "Cashless Occupancy @00:00",
                    "Asarfi Admission (Prev Day upto 00:00)",
                    "Asarfi Discharge (Prev Day)",
                    "Cardiac Admission (Prev Day upto 00:00)",
                    "Cardiac Discharge (Prev Day)",
                    "Asarfi Admission (00:00 to 08:00 Today)",
                    "Cardiac Admission (00:00 to 08:00 Today)",
                    "Admission (00:00 to 08:00 Today Total)",
                    "Ward-wise Patient Count",
                ]
            )
            for label in ahl_inv_labels:
                headers.extend(
                    [
                        f"Investigation {label} Asarfi",
                        f"Investigation {label} Cardiac",
                        f"Investigation {label} Total",
                    ]
                )
            for label in ahl_proc_labels:
                headers.append(f"Key Procedure {label}")
        headers.extend(
            [
                "Latest Snapshot",
                "Admissions (Prev Day upto 00:00)",
                "Discharges (Prev Day)",
                "OPD (Prev Day upto 00:00)",
                "IPD (Prev Day upto 00:00)",
                "Investigations Total (Prev Day)",
                "Key Procedures Total (Prev Day)",
                "Occupancy Used @08:00",
                "Occupancy Beds @08:00",
                "Occupancy % @08:00",
                "Sequence Status",
            ]
        )
        _write_sheet_meta(ws, "Sequence Details (Raw Parameters)", len(headers))
        ws.append([])
        ws.append(headers)
        header_row = ws.max_row
        for cell in ws[header_row]:
            cell.font = header_font
            cell.fill = header_fill
            cell.alignment = Alignment(horizontal="center", vertical="center")
            cell.border = border

        if not details_rows:
            ws.append(["No locked MOD sequence rows found for this selection."])
            ws.merge_cells(start_row=header_row + 1, start_column=1, end_row=header_row + 1, end_column=len(headers))
            ws["A" + str(header_row + 1)].alignment = Alignment(horizontal="center", vertical="center")
            ws["A" + str(header_row + 1)].border = border
            _autosize(ws)
            return

        int_cols = {
            "Admissions (Prev Day upto 00:00)",
            "Discharges (Prev Day)",
            "OPD (Prev Day upto 00:00)",
            "IPD (Prev Day upto 00:00)",
            "Investigations Total (Prev Day)",
            "Key Procedures Total (Prev Day)",
            "Occupancy Used @08:00",
            "Occupancy Beds @08:00",
        }
        float_cols = {
            "Occupancy % @08:00",
        }
        if include_ahl_details:
            int_cols.update(
                {
                    "Cash Occupancy @00:00",
                    "Cashless Occupancy @00:00",
                    "Asarfi Admission (Prev Day upto 00:00)",
                    "Asarfi Discharge (Prev Day)",
                    "Cardiac Admission (Prev Day upto 00:00)",
                    "Cardiac Discharge (Prev Day)",
                    "Asarfi Admission (00:00 to 08:00 Today)",
                    "Cardiac Admission (00:00 to 08:00 Today)",
                    "Admission (00:00 to 08:00 Today Total)",
                }
            )
            for label in ahl_inv_labels:
                int_cols.update(
                    {
                        f"Investigation {label} Asarfi",
                        f"Investigation {label} Cardiac",
                        f"Investigation {label} Total",
                    }
                )
            for label in ahl_proc_labels:
                int_cols.add(f"Key Procedure {label}")

        for row in details_rows:
            ws.append([row.get(h) for h in headers])
            excel_row = ws.max_row
            status_val = str(row.get("Sequence Status") or "").upper()

            for idx, header in enumerate(headers, start=1):
                cell = ws.cell(row=excel_row, column=idx)
                cell.border = border
                if header in int_cols:
                    cell.number_format = "#,##0"
                    cell.alignment = Alignment(horizontal="right", vertical="center")
                elif header in float_cols:
                    if header == "Occupancy % @08:00":
                        cell.number_format = '0.00"%"'
                    else:
                        cell.number_format = "#,##0.00"
                    cell.alignment = Alignment(horizontal="right", vertical="center")
                elif header in {"Sequence Date", "Latest Snapshot", "Ward-wise Patient Count"}:
                    cell.alignment = Alignment(horizontal="left", vertical="center")
                else:
                    cell.alignment = Alignment(horizontal="center", vertical="center")

            status_cell = ws.cell(row=excel_row, column=headers.index("Sequence Status") + 1)
            if status_val == "LOCKED":
                status_cell.fill = PatternFill(start_color="dcfce7", end_color="dcfce7", fill_type="solid")
            elif status_val == "PARTIAL":
                status_cell.fill = PatternFill(start_color="fef3c7", end_color="fef3c7", fill_type="solid")
            elif status_val == "MISSING":
                status_cell.fill = PatternFill(start_color="fee2e2", end_color="fee2e2", fill_type="solid")

        ws.freeze_panes = f"A{header_row + 1}"
        _autosize(ws)

    _write_metric_sheet(
        ws_night,
        "Night MOD Locked Sequence Audit",
        night_metrics,
    )

    _write_metric_sheet(
        ws_morning,
        "Morning MOD Locked Sequence Audit",
        morning_metrics,
    )

    _write_combined_sheet(ws_combined)
    _write_details_sheet(ws_details)

    buffer = io.BytesIO()
    wb.save(buffer)
    buffer.seek(0)
    return buffer.getvalue()


@app.route('/api/mod_reports/summary')
@login_required(allowed_roles={"IT", "Management", "Departmental Head", "Executive"})
def api_mod_reports_summary():
    duration = (request.args.get("duration") or "daily").strip().lower()
    if duration not in {"daily", "monthly", "yearly"}:
        duration = "daily"
    requested_segment = (request.args.get("segment") or "total").strip().lower()
    if requested_segment not in {"total", "asarfi", "cardiac"}:
        requested_segment = "total"

    try:
        limit = int(request.args.get("limit") or _mod_summary_default_limit(duration))
    except Exception:
        limit = _mod_summary_default_limit(duration)
    limit = max(3, min(limit, 120))

    try:
        lookback_days = int(request.args.get("lookback_days") or _mod_summary_pick_lookback_days(duration))
    except Exception:
        lookback_days = _mod_summary_pick_lookback_days(duration)
    lookback_days = max(30, min(lookback_days, 3650))

    requested_unit = (request.args.get("unit") or "").strip().upper()
    allowed_units = _analytics_allowed_units_for_session() or _allowed_units_for_session()
    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access"}), 403

    if requested_unit and requested_unit != "ALL" and requested_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403
    if not requested_unit:
        requested_unit = allowed_units[0] if len(allowed_units) == 1 else "ALL"
    if requested_unit != "AHL":
        requested_segment = "total"

    units_to_use = allowed_units if requested_unit == "ALL" else [requested_unit]
    today = datetime.now(tz=LOCAL_TZ).date()
    include_today = _is_truthy(request.args.get("include_today"))
    closed_to = today if include_today else (today - timedelta(days=1))
    from_dt = today - timedelta(days=lookback_days)
    if closed_to < from_dt:
        from_dt = closed_to
    from_date = from_dt.strftime("%Y-%m-%d")
    to_date = closed_to.strftime("%Y-%m-%d")

    try:
        daily_rows = _fetch_mod_summary_daily_rows(units_to_use, from_date, to_date, segment=requested_segment)
        rows = _aggregate_mod_summary_rows(daily_rows, duration)
        dept_insights = _fetch_mod_summary_department_insights(units_to_use, from_date, to_date, duration)
    except Exception as e:
        return jsonify({"status": "error", "message": f"Failed to build MOD summary: {e}"}), 500

    rows = rows[:limit]

    def _avg(field: str) -> float:
        vals = [float(r[field]) for r in rows if r.get(field) is not None]
        if not vals:
            return 0.0
        return round(sum(vals) / len(vals), 2)

    def _trend(field: str) -> float | None:
        if len(rows) < 2:
            return None
        a = rows[0].get(field)
        b = rows[1].get(field)
        if a is None or b is None:
            return None
        return round(float(a) - float(b), 2)

    kpis = {
        "avg_occupancy_pct": _avg("avg_occupancy_pct"),
        "avg_opd": _avg("avg_opd"),
        "avg_ipd": _avg("avg_ipd"),
        "avg_night_admissions": _avg("avg_night_admissions"),
        "avg_night_discharges": _avg("avg_night_discharges"),
        "avg_investigations": _avg("avg_investigations"),
        "avg_procedures": _avg("avg_procedures"),
        "avg_coverage_pct": _avg("coverage_pct"),
        "total_reports_saved": int(sum(int(r.get("reports_saved") or 0) for r in rows)),
        "periods": len(rows),
    }
    trends = {
        "occupancy_pct": _trend("avg_occupancy_pct"),
        "opd": _trend("avg_opd"),
        "ipd": _trend("avg_ipd"),
        "night_admissions": _trend("avg_night_admissions"),
        "night_discharges": _trend("avg_night_discharges"),
        "coverage_pct": _trend("coverage_pct"),
    }

    for row in rows:
        row.pop("_updated_dt", None)

    segment_limited = bool(requested_unit == "AHL" and requested_segment in {"asarfi", "cardiac"})
    if segment_limited:
        dept_insights["note"] = "Department insights use combined AHL doctorwise snapshots; split-wise department data is not persisted."

    return jsonify(
        {
            "status": "success",
            "duration": duration,
            "unit": requested_unit,
            "segment": requested_segment,
            "units": units_to_use,
            "from": from_date,
            "to": to_date,
            "closed_only": not include_today,
            "rows": rows,
            "kpis": kpis,
            "trends": trends,
            "dept_insights": dept_insights,
            "available_units": allowed_units,
            "updated_at": datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S"),
        }
    )


@app.route('/api/mod_reports/sequence_audit/export_excel')
@login_required(allowed_roles={"IT", "Management", "Departmental Head", "Executive"})
def api_mod_reports_sequence_audit_export_excel():
    duration_raw = request.args.get("range") or request.args.get("duration") or "custom"
    from_raw = request.args.get("from") or request.args.get("from_date")
    to_raw = request.args.get("to") or request.args.get("to_date")
    duration, from_dt, to_dt = _resolve_mod_export_date_range(duration_raw, from_raw, to_raw)

    if not from_dt or not to_dt:
        return jsonify({"status": "error", "message": "Valid from/to date is required (YYYY-MM-DD)."}), 400
    if to_dt < from_dt:
        return jsonify({"status": "error", "message": "To date cannot be earlier than from date."}), 400
    if (to_dt - from_dt).days > 3660:
        return jsonify({"status": "error", "message": "Date range too large. Keep it within 10 years."}), 400

    now_local = datetime.now(tz=LOCAL_TZ)
    today = now_local.date()
    if to_dt > today:
        return jsonify({"status": "error", "message": "Future dates are not allowed."}), 400

    allowed_units = _analytics_allowed_units_for_session() or _allowed_units_for_session()
    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access"}), 403

    requested_unit = (request.args.get("unit") or "").strip().upper()
    if requested_unit and requested_unit != "ALL" and requested_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403
    if not requested_unit:
        requested_unit = allowed_units[0] if len(allowed_units) == 1 else "ALL"
    units_to_use = allowed_units if requested_unit == "ALL" else [requested_unit]

    requested_segment = (request.args.get("segment") or "total").strip().lower()
    if requested_segment not in {"total", "asarfi", "cardiac"}:
        requested_segment = "total"
    if requested_unit != "AHL":
        requested_segment = "total"

    from_date = from_dt.strftime("%Y-%m-%d")
    to_date = to_dt.strftime("%Y-%m-%d")

    try:
        daily_rows = _fetch_mod_summary_daily_rows(units_to_use, from_date, to_date, segment=requested_segment)
    except Exception as e:
        return jsonify({"status": "error", "message": f"Failed to build MOD audit export data: {e}"}), 500

    rows_for_export = []
    for row in (daily_rows or []):
        period_key = str(row.get("period_key") or "").strip()
        try:
            period_dt = datetime.strptime(period_key, "%Y-%m-%d").date()
        except Exception:
            continue
        # Sequence lock happens 6 hours after 08:00 snapshot => 14:00 local time.
        lock_ready_at = datetime.combine(period_dt, datetime.min.time(), tzinfo=LOCAL_TZ) + timedelta(hours=14)
        if now_local < lock_ready_at:
            continue
        expected_reports = max(1, int(row.get("expected_reports") or 0))
        reports_saved = int(row.get("reports_saved") or 0)
        out = dict(row)
        if reports_saved >= expected_reports:
            out["status_label"] = "LOCKED"
        elif reports_saved > 0:
            out["status_label"] = "PARTIAL"
        else:
            out["status_label"] = "MISSING"
        rows_for_export.append(out)

    locked_only = _is_truthy(request.args.get("locked_only", "1"))
    if locked_only:
        rows_for_export = [
            r for r in rows_for_export
            if int(r.get("reports_saved") or 0) >= int(r.get("expected_reports") or 0)
        ]

    rows_for_export.sort(key=lambda r: str(r.get("period_key") or ""), reverse=True)
    if not rows_for_export:
        return jsonify(
            {
                "status": "error",
                "message": "No locked MOD sequence rows found for this range/unit.",
                "from": from_date,
                "to": to_date,
            }
        ), 404

    include_ahl_details = requested_unit == "AHL"
    if include_ahl_details:
        extras_map = _fetch_ahl_sequence_export_extras(from_date, to_date)
        ahl_inv_labels = [str(label).strip() for label, _ in MORNING_REPORT_INVESTIGATION_MAP if str(label).strip()]
        ahl_proc_labels = [str(label).strip() for label in MORNING_REPORT_KEY_PROCEDURES if str(label).strip()]
        for row in rows_for_export:
            date_key = str(row.get("period_key") or row.get("period_label") or "").strip()
            ext = extras_map.get(date_key) or {}
            row["ahl_night_cash_occupancy"] = int(ext.get("night_cash_occupancy") or 0)
            row["ahl_night_cashless_occupancy"] = int(ext.get("night_cashless_occupancy") or 0)
            row["ahl_night_asarfi_admissions"] = int(ext.get("night_asarfi_admissions") or 0)
            row["ahl_night_asarfi_discharges"] = int(ext.get("night_asarfi_discharges") or 0)
            row["ahl_night_cardiac_admissions"] = int(ext.get("night_cardiac_admissions") or 0)
            row["ahl_night_cardiac_discharges"] = int(ext.get("night_cardiac_discharges") or 0)
            row["ahl_night_0000_0800_asarfi_admissions"] = int(ext.get("night_0000_0800_asarfi_admissions") or 0)
            row["ahl_night_0000_0800_cardiac_admissions"] = int(ext.get("night_0000_0800_cardiac_admissions") or 0)
            row["ahl_night_0000_0800_total_admissions"] = int(ext.get("night_0000_0800_total_admissions") or 0)
            row["ahl_night_ward_wise_patient_count"] = str(ext.get("ward_wise_patient_count") or "-")
            row["ahl_morning_key_procedures"] = int(ext.get("morning_key_procedures") or 0)
            for label in ahl_inv_labels:
                key = _mod_seq_export_key(label)
                row[f"ahl_inv_{key}_asarfi"] = int(ext.get(f"inv_{key}_asarfi") or 0)
                row[f"ahl_inv_{key}_cardiac"] = int(ext.get(f"inv_{key}_cardiac") or 0)
                row[f"ahl_inv_{key}_total"] = int(ext.get(f"inv_{key}_total") or 0)
            for label in ahl_proc_labels:
                key = _mod_seq_export_key(label)
                row[f"ahl_proc_{key}"] = int(ext.get(f"proc_{key}") or 0)

    exported_by = session.get("username") or session.get("user") or "Unknown"
    unit_label = requested_unit if requested_unit != "ALL" else "ALL Units"
    if requested_unit == "AHL" and requested_segment in {"asarfi", "cardiac"}:
        unit_label = f"AHL ({requested_segment.title()})"

    data = _build_mod_sequence_audit_excel(
        rows_for_export,
        from_date=from_date,
        to_date=to_date,
        unit_label=unit_label,
        duration=duration,
        segment=requested_segment,
        locked_only=locked_only,
        exported_by=exported_by,
        include_ahl_details=include_ahl_details,
    )

    unit_token = re.sub(r"[^A-Za-z0-9_]+", "_", unit_label.replace(" ", "_")).strip("_") or "ALL"
    filename = f"MOD_Sequence_Audit_{unit_token}_{from_date}_to_{to_date}.xlsx"
    return send_file(
        io.BytesIO(data),
        as_attachment=True,
        download_name=filename,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )


