def _fetch_night_snapshot_audit_rows(limit: int = 120) -> list[dict]:
    limit = max(20, min(int(limit or 120), 500))
    rows_out = []
    try:
        with _get_login_db_connection() as conn:
            _ensure_night_report_snapshot_audit_table(conn)
            cur = conn.cursor()
            cur.execute(
                f"""
                SELECT TOP {limit}
                    TargetTime, RunTime, SnapshotDate, Unit, Status, Message,
                    ParticularRows, ParticularValueRows, DoctorVolumeRows, DoctorVolumeValueRows,
                    WardRows, DetailsSaved, WardsSaved
                FROM dbo.HID_Night_Report_Snapshot_Audit WITH (NOLOCK)
                ORDER BY RunTime DESC, Id DESC
                """
            )
            rows = cur.fetchall()
    except Exception:
        return rows_out

    for row in rows:
        target_time, run_time, snapshot_date, unit, status, message, part_rows, part_val_rows, doc_rows, doc_val_rows, ward_rows, details_saved, wards_saved = row
        rows_out.append({
            "target_time": str(target_time) if target_time is not None else "",
            "run_time": str(run_time) if run_time is not None else "",
            "snapshot_date": str(snapshot_date)[:10] if snapshot_date is not None else "",
            "unit": str(unit or "").strip().upper(),
            "status": str(status or "").strip().upper(),
            "message": str(message or "").strip(),
            "particular_rows": int(part_rows or 0),
            "particular_value_rows": int(part_val_rows or 0),
            "doctor_volume_rows": int(doc_rows or 0),
            "doctor_volume_value_rows": int(doc_val_rows or 0),
            "ward_rows": int(ward_rows or 0),
            "details_saved": int(details_saved or 0),
            "wards_saved": int(wards_saved or 0),
        })
    return rows_out


