# ============================================================
# Purchase Module APIs
# ============================================================
OTP_CENTER_UNIT = "AHL"
OTP_PO_REQUEST_TYPE = "PO_APPROVAL"
OTP_BILL_EDIT_REQUEST_TYPE = "BILL_EDIT"
OTP_VISIT_EDIT_REQUEST_TYPE = "VISIT_EDIT"
PO_VALUATION_START_DATE = "2026-01-06"
ITEM_MASTER_DESCRIPTIVE_NAME_MAX = 100

def _get_purchase_unit():
    unit = (request.args.get("unit") or request.form.get("unit") or "").strip().upper()
    if request.is_json:
        data = request.get_json(silent=True) or {}
        unit = unit or str(data.get("unit") or "").strip().upper()
    allowed_units = _allowed_purchase_units_for_session()
    if not allowed_units:
        return None, (jsonify({"status": "error", "message": "No unit access assigned"}), 403)
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return None, (jsonify({"status": "error", "message": "Please select a unit"}), 400)
    if unit not in allowed_units:
        return None, (jsonify({"status": "error", "message": f"Unit {unit} not permitted"}), 403)
    return unit, None


def _purchase_normalize_email(raw_value) -> str:
    return str(raw_value or "").strip().lower()


def _purchase_is_valid_email(email: str) -> bool:
    if not email:
        return False
    return bool(re.match(r"^[A-Z0-9._%+\-]+@[A-Z0-9.\-]+\.[A-Z]{2,}$", email, flags=re.IGNORECASE))


def _build_purchase_department_payload(unit: str):
    purchasing_depts = _fetch_purchasing_departments(include_inactive=False)
    incharge_map = _fetch_purchase_incharge_recipients_by_department(unit)
    payload = []
    for row in (purchasing_depts or []):
        dept_id = _safe_int(row.get("Id"))
        dept_name = str(row.get("PurchasingDeptName") or "").strip()
        if dept_id <= 0 or not dept_name:
            continue
        payload.append(
            {
                "id": dept_id,
                "name": dept_name,
                "is_active": 1,
                "recipients": incharge_map.get(dept_id, []),
            }
        )
    default_id = _safe_int((payload or [{}])[0].get("id")) if payload else 0
    preferred_name = UNIT_DEFAULT_PURCHASING_DEPT.get(str(unit or "").strip().upper())
    if preferred_name and payload:
        preferred_norm = _normalize_purchasing_dept_name(preferred_name)
        for dept in payload:
            if _normalize_purchasing_dept_name(dept.get("name")) == preferred_norm:
                default_id = _safe_int(dept.get("id"))
                break
    return payload, default_id


def _build_purchase_department_master_rows():
    rows = []
    for row in (_fetch_purchasing_departments(include_inactive=True) or []):
        dept_id = _safe_int(row.get("Id"))
        dept_name = str(row.get("PurchasingDeptName") or "").strip()
        if dept_id <= 0 or not dept_name:
            continue
        rows.append(
            {
                "id": dept_id,
                "name": dept_name,
                "is_active": 1 if _safe_int(row.get("IsActive"), 1) != 0 else 0,
            }
        )
    return rows


def _is_unit_master_active_row(row: dict) -> bool:
    raw_val = row.get("deactive")
    if raw_val is None:
        raw_val = row.get("is_active")
    text = str(raw_val or "").strip().lower()
    if text in {"", "0", "false", "no", "n"}:
        return True
    if text in {"1", "true", "yes", "y"}:
        return False
    try:
        return int(raw_val or 0) == 0
    except Exception:
        return True


def _normalize_purchase_unit_text(value: str) -> str:
    return re.sub(r"\s+", " ", str(value or "").strip())


def _guess_purchase_unit_code(unit_text: str) -> str:
    normalized = _normalize_purchase_unit_text(unit_text).upper()
    if not normalized:
        return ""
    if re.fullmatch(r"[A-Z0-9]{1,20}", normalized):
        return normalized
    compact = re.sub(r"[^A-Z0-9]", "", normalized)
    if compact and len(compact) <= 20:
        return compact
    return ""


def _build_purchase_unit_master_rows(unit: str):
    df = data_fetch.fetch_purchase_unit_master(unit, include_inactive=True)
    if df is None or df.empty:
        return []
    df = _clean_df_columns(df)
    cols = {str(c).strip().lower(): c for c in df.columns}
    id_col = cols.get("id")
    name_col = cols.get("name")
    code_col = cols.get("code")
    deactive_col = cols.get("deactive")
    rows = []
    if not id_col:
        return rows
    for _, row in df.iterrows():
        unit_id = _safe_int(row.get(id_col))
        if unit_id <= 0:
            continue
        name = _normalize_purchase_unit_text(row.get(name_col) if name_col else "")
        code = _normalize_purchase_unit_text(row.get(code_col) if code_col else "")
        if not name and not code:
            continue
        if not name:
            name = code
        rows.append(
            {
                "id": unit_id,
                "code": code,
                "name": name,
                "unit": unit,
                "deactive": row.get(deactive_col) if deactive_col else 0,
                "is_active": 1 if _is_unit_master_active_row({"deactive": row.get(deactive_col) if deactive_col else 0}) else 0,
            }
        )
    rows.sort(key=lambda r: (str(r.get("name") or "").upper(), str(r.get("code") or "").upper(), _safe_int(r.get("id"), 0)))
    return rows


def _build_purchase_unit_payload(unit: str):
    rows = _build_purchase_unit_master_rows(unit)
    active_rows = [row for row in rows if _safe_int(row.get("is_active"), 1) == 1]
    return active_rows


def _purchase_unit_master_permissions(role_name: str):
    role_base = _role_base(role_name or "")
    return {
        "can_deactivate": role_base in {"IT", "Management", "Departmental Head"},
    }


def _purchase_dept_master_permissions(role_name: str):
    role_base = _role_base(role_name or "")
    return {
        "can_deactivate": role_base in {"IT", "Management", "Departmental Head"},
        "can_delete": role_base == "IT",
    }


def _create_purchase_otp_request(
    unit: str,
    po_no: str,
    po_id: int,
    amount,
    supplier_name: str,
    reason: str,
    requested_by: str,
    purchasing_dept_id: int | None = None,
):
    from modules.db_connection import get_sql_connection
    try:
        amount_val = Decimal(str(amount or 0))
    except Exception:
        amount_val = Decimal("0")
    try:
        conn = get_sql_connection(OTP_CENTER_UNIT)
        if not conn:
            return {"error": "Unable to connect to OTP database"}
        try:
            conn.autocommit = True
        except Exception:
            pass
        cursor = conn.cursor()
        request_type = OTP_PO_REQUEST_TYPE
        bill_no = str(po_no or "")
        receipt_no = str(po_id or "")
        reason_val = (reason or "").strip()
        supplier_val = (supplier_name or "").strip()
        requested_by_val = (requested_by or "").strip()

        try:
            cursor.execute("""
                DECLARE @id INT, @otp VARCHAR(10);
                EXEC dbo.usp_CreateDiscountApprovalRequest
                    @Unit=?, @BillNo=?, @ReceiptNo=?, @RequestType=?, @RequestedAmount=?,
                    @Reason=?, @RequestedByUserName=?, @UHIDNo=?, @PatientName=?,
                    @RequestId=@id OUTPUT, @OtpPlainOut=@otp OUTPUT;
                SELECT @id, @otp;
            """, (unit, bill_no, receipt_no, request_type, amount_val,
                  reason_val, requested_by_val, "", supplier_val))
        except Exception as e:
            if "8144" in str(e) or "too many arguments" in str(e).lower():
                cursor.execute("""
                    DECLARE @id INT, @otp VARCHAR(10);
                    EXEC dbo.usp_CreateDiscountApprovalRequest
                        @BillNo=?, @ReceiptNo=?, @RequestType=?, @RequestedAmount=?,
                        @Reason=?, @RequestedByUserName=?, @UHIDNo=?, @PatientName=?,
                        @RequestId=@id OUTPUT, @OtpPlainOut=@otp OUTPUT;
                    SELECT @id, @otp;
                """, (bill_no, receipt_no, request_type, amount_val,
                      reason_val, requested_by_val, "", supplier_val))
            else:
                raise

        row = cursor.fetchone()
        if not row or not row[0]:
            return {"error": "OTP request not created"}
        request_id = int(row[0])
        otp_plain = str(row[1] or "").strip() if len(row) > 1 else ""

        try:
            cursor.execute("""
                UPDATE DiscountApprovalRequest
                SET Unit = ?, EmailSent = 1, EmailSentAt = GETDATE()
                WHERE Id = ?;
            """, (unit, request_id))
            conn.commit()
        except Exception:
            pass
        email_kwargs = {
            "unit": unit,
            "po_no": bill_no,
            "po_id": receipt_no,
            "otp_plain": otp_plain,
            "amount": amount_val,
            "supplier_name": supplier_val,
            "reason": reason_val,
            "requested_by": requested_by_val,
            "purchasing_dept_id": purchasing_dept_id,
        }
        use_async_mail = bool(getattr(config, "PURCHASE_OTP_EMAIL_ASYNC", True))
        if use_async_mail:
            try:
                def _send_po_otp_mail_job():
                    try:
                        _send_purchase_otp_email(**email_kwargs)
                    except Exception as mail_err:
                        print(f"PO OTP email send failed: {mail_err}")

                mail_thread = Thread(
                    target=_send_po_otp_mail_job,
                    daemon=True,
                    name=f"po-otp-mail-{request_id}",
                )
                mail_thread.start()
            except Exception as e:
                print(f"PO OTP async dispatch failed: {e}")
        else:
            try:
                _send_purchase_otp_email(**email_kwargs)
            except Exception as e:
                print(f"PO OTP email send failed: {e}")
        conn.close()
        return {"request_id": request_id, "otp": otp_plain}
    except Exception as e:
        return {"error": str(e)}


