    def _format_indian_currency(val):
        try:
            num = float(val)
            if not math.isfinite(num):
                return "0.00"
        except Exception:
            return "0.00"
        sign = "-" if num < 0 else ""
        num = abs(num)
        s = f"{num:.2f}"
        if "." not in s:
            return "0.00"
        int_part, dec_part = s.split(".", 1)
        if len(int_part) <= 3:
            grouped = int_part
        else:
            last3 = int_part[-3:]
            rest = int_part[:-3]
            groups = []
            while rest:
                groups.append(rest[-2:])
                rest = rest[:-2]
            grouped = ",".join(reversed(groups)) + "," + last3
        return f"{sign}{grouped}.{dec_part}"

    def fmt_money(val):
        return _format_indian_currency(val)

    def fmt_date(val):
        if val is None or val == "":
            return "-"
        if isinstance(val, (datetime, date)):
            return val.strftime("%d-%b-%Y")
        return str(val)[:10]

    def fmt_datetime(val):
        if val is None or val == "":
            return "-"
        if isinstance(val, datetime):
            return val.strftime("%d-%b-%Y %I:%M %p")
        if isinstance(val, date):
            return datetime.combine(val, datetime.min.time()).strftime("%d-%b-%Y %I:%M %p")
        return str(val)

    def split_terms(text):
        if not text:
            return []
        parts = re.split(r"(?:\r?\n|;)+", str(text))
        cleaned = []
        for part in parts:
            item = part.strip()
            if item:
                cleaned.append(item)
        return cleaned

    def _escape_with_line_breaks(text):
        raw = str(text or "")
        if not raw:
            return ""
        normalized = raw.replace("\r\n", "\n").replace("\r", "\n")
        return escape(normalized).replace("\n", "<br/>")

    def _two_digits_words(num: int) -> str:
        ones = ["", "One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine"]
        teens = ["Ten", "Eleven", "Twelve", "Thirteen", "Fourteen", "Fifteen", "Sixteen", "Seventeen", "Eighteen", "Nineteen"]
        tens = ["", "", "Twenty", "Thirty", "Forty", "Fifty", "Sixty", "Seventy", "Eighty", "Ninety"]
        if num < 10:
            return ones[num]
        if num < 20:
            return teens[num - 10]
        ten = tens[num // 10]
        one = ones[num % 10]
        return f"{ten} {one}".strip()

    def _three_digits_words(num: int) -> str:
        if num >= 100:
            head = f"{_two_digits_words(num // 100)} Hundred"
            tail = _two_digits_words(num % 100)
            return f"{head} {tail}".strip()
        return _two_digits_words(num)

    def indian_number_to_words(num: int) -> str:
        if num == 0:
            return "Zero"
        words = []
        crore = num // 10000000
        if crore:
            words.append(f"{_three_digits_words(crore)} Crore")
        num %= 10000000
        lakh = num // 100000
        if lakh:
            words.append(f"{_two_digits_words(lakh)} Lakh")
        num %= 100000
        thousand = num // 1000
        if thousand:
            words.append(f"{_two_digits_words(thousand)} Thousand")
        num %= 1000
        if num:
            words.append(_three_digits_words(num))
        return " ".join([w for w in words if w]).strip()

    def amount_in_words(amount_val) -> str:
        try:
            amt = Decimal(str(amount_val)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
        except Exception:
            amt = Decimal("0.00")
        rupees = int(amt)
        paise = int((amt - Decimal(rupees)) * 100)
        if paise == 100:
            rupees += 1
            paise = 0
        rupees_words = indian_number_to_words(rupees)
        if paise:
            paise_words = indian_number_to_words(paise)
            return f"Rupees {rupees_words} and Paise {paise_words} Only"
        return f"Rupees {rupees_words} Only"

