def _fetch_audit_logs_payload(force_module: str | None = None, max_limit: int = 1000):
    def _parse_date(val: str | None, default: date):
        if not val:
            return default
        try:
            return datetime.fromisoformat(val).date()
        except Exception:
            return default

    today = datetime.now(tz=LOCAL_TZ).date()
    from_date = _parse_date(request.args.get("from"), today - timedelta(days=7))
    to_date = _parse_date(request.args.get("to"), today)

    module = force_module or (request.args.get("module") or "").strip()
    action = (request.args.get("action") or "").strip()
    status = (request.args.get("status") or "").strip()
    entity_type = (request.args.get("entity_type") or "").strip()
    entity_id = (request.args.get("entity_id") or "").strip()
    unit = (request.args.get("unit") or "").strip().upper()
    username = (request.args.get("username") or "").strip()
    query_text = (request.args.get("q") or "").strip()

    try:
        limit = int(request.args.get("limit") or 200)
    except Exception:
        limit = 200
    try:
        offset = int(request.args.get("offset") or 0)
    except Exception:
        offset = 0
    max_limit = max(1, int(max_limit or 1000))
    limit = max(1, min(limit, max_limit))
    offset = max(0, offset)

    allowed_units = _allowed_units_for_session()
    role_base = _role_base(session.get("role") or "")
    if allowed_units and role_base not in {"IT", "Management"}:
        if unit and unit not in allowed_units:
            return {"status": "error", "message": "Unit not allowed"}, 403

    from_dt = datetime.combine(from_date, datetime.min.time()).strftime("%Y-%m-%d %H:%M:%S")
    to_dt = datetime.combine(to_date, datetime.max.time()).strftime("%Y-%m-%d %H:%M:%S")

    where = ["EventTime >= ?", "EventTime <= ?"]
    params = [from_dt, to_dt]

    if module:
        where.append("Module = ?")
        params.append(module)
    if action:
        where.append("Action = ?")
        params.append(action)
    if status:
        where.append("Status = ?")
        params.append(status)
    if entity_type:
        where.append("EntityType = ?")
        params.append(entity_type)
    if entity_id:
        where.append("EntityId = ?")
        params.append(entity_id)
    if username:
        where.append("Username = ?")
        params.append(username)

    if unit:
        where.append("Unit = ?")
        params.append(unit)
    elif allowed_units and role_base not in {"IT", "Management"}:
        placeholders = ",".join(["?"] * len(allowed_units))
        where.append(f"Unit IN ({placeholders})")
        params.extend(allowed_units)

    if query_text:
        where.append("(Summary LIKE ? OR Details LIKE ? OR EntityId LIKE ? OR Username LIKE ?)")
        like_val = f"%{query_text}%"
        params.extend([like_val, like_val, like_val, like_val])

    where_sql = " AND ".join(where) if where else "1=1"

    try:
        with _get_login_db_connection() as conn:
            _ensure_audit_log_table(conn)
            cursor = conn.cursor()
            cursor.execute(
                f"""
                SELECT LogId, EventTime, Module, Action, Status, EntityType, EntityId, Unit,
                       Username, RoleName, AccountId, Summary, Details, RequestId, IpAddress, UserAgent
                FROM dbo.HID_Audit_Log WITH (NOLOCK)
                WHERE {where_sql}
                ORDER BY EventTime DESC
                OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
                """,
                (*params, offset, limit),
            )
            rows = cursor.fetchall()
            cols = [c[0] for c in cursor.description]
            records = [{cols[i]: row[i] for i in range(len(cols))} for row in rows]
    except Exception as e:
        return {"status": "error", "message": f"Failed to fetch logs: {e}"}, 500

    records = _sanitize_json_payload(records)
    return {
        "status": "success",
        "from": from_date.isoformat(),
        "to": to_date.isoformat(),
        "offset": offset,
        "limit": limit,
        "count": len(records),
        "rows": records,
    }, 200


