def _build_audit_log_excel(records: list[dict], title: str | None = None) -> io.BytesIO:
    wb = Workbook()
    ws = wb.active
    ws.title = "Audit Logs" if not title else str(title)[:31]

    headers = [
        "EventTime", "Module", "Action", "Status", "EntityType", "EntityId",
        "Unit", "Username", "RoleName", "Summary", "Details", "RequestId",
        "IpAddress", "UserAgent"
    ]
    ws.append(headers)

    for row in records:
        ws.append([
            row.get("EventTime"),
            row.get("Module"),
            row.get("Action"),
            row.get("Status"),
            row.get("EntityType"),
            row.get("EntityId"),
            row.get("Unit"),
            row.get("Username"),
            row.get("RoleName"),
            row.get("Summary"),
            row.get("Details"),
            row.get("RequestId"),
            row.get("IpAddress"),
            row.get("UserAgent"),
        ])

    header_fill = PatternFill(start_color="E2E8F0", end_color="E2E8F0", fill_type="solid")
    header_font = Font(bold=True)
    for cell in ws[1]:
        cell.fill = header_fill
        cell.font = header_font

    for col in ws.columns:
        max_len = 0
        col_letter = col[0].column_letter
        for cell in col[:200]:
            val = cell.value
            if val is None:
                continue
            try:
                max_len = max(max_len, len(str(val)))
            except Exception:
                pass
        ws.column_dimensions[col_letter].width = min(60, max(10, max_len + 2))

    buf = io.BytesIO()
    wb.save(buf)
    buf.seek(0)
    return buf


@app.route('/api/audit/logs/export')
@login_required(allowed_roles={"IT"})
def api_audit_logs_export():
    payload, status = _fetch_audit_logs_payload(max_limit=5000)
    if status != 200:
        return jsonify(payload), status

    records = payload.get("rows") or []
    module = (request.args.get("module") or "").strip() or "all"
    from_date = payload.get("from")
    to_date = payload.get("to")
    filename = f"Audit_Logs_{module}_{from_date}_to_{to_date}.xlsx"

    data = _build_audit_log_excel(records, title="Audit Logs")
    return send_file(
        data,
        as_attachment=True,
        download_name=filename,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )


def _gst_pay_seg(pat_type: str) -> str:
    val = (pat_type or "").upper()
    if "PSU & CORPORATES" in val and "CASHLESS" in val:
        return "Cashless"
    if "GSS" in val and "CASHLESS" in val:
        return "Cashless"
    if "EASTERN CENTRAL RAILWAY" in val:
        return "Cashless"
    if "CMPF" in val:
        return "Cashless"
    if "TPA" in val:
        return "TPA"
    if "ONGC" in val:
        return "ONGC"
    return "Cash"


def _gst_visit_bucket(v: str) -> str:
    vv = (v or "").strip().upper()
    if vv.startswith("DPV"):
        return "DPV"
    if "TEMP" in vv:
        return "Temp-Patient"
    return "OPD"


def _gst_norm_filters(raw_filters: list[str] | None, total: int = 12) -> list[str]:
    if not raw_filters:
        return [""] * total
    filters = [str(x or "").strip().lower() for x in raw_filters]
    if len(filters) < total:
        filters.extend([""] * (total - len(filters)))
    return filters[:total]


def _gst_tax_pct_display(value) -> str:
    try:
        pct = float(value or 0)
    except Exception:
        pct = 0.0
    if abs(pct - round(pct)) < 1e-6:
        return f"{int(round(pct))}%"
    text = f"{pct:.4f}".rstrip("0").rstrip(".")
    return f"{text}%"


def _gst_row_matches_filters(values: list, filters: list[str]) -> bool:
    for idx, f in enumerate(filters):
        if not f:
            continue
        val = ""
        if idx < len(values):
            val = str(values[idx] or "").lower()
        if f not in val:
            return False
    return True


def _gst_sales_filter_values(row: dict) -> list[str]:
    amt = _safe_float(_row_value(row, ["TotalAmt", "TotalAmount", "Amount"]))
    tax_pct = _safe_float(_row_value(row, ["Taxid", "TaxId", "TaxID"]))
    tax_component = amt * tax_pct / (100 + tax_pct) if tax_pct else 0.0
    cgst = tax_component / 2
    sgst = tax_component / 2
    taxable = amt - tax_component
    return [
        _row_value(row, ["SaleDate"]) or "",
        _row_value(row, ["BillDate"]) or "",
        _row_value(row, ["patient", "Patient"]) or "",
        _row_value(row, ["regno", "RegNo", "RegNo."]) or "",
        _row_value(row, ["TypeOfVisit", "VisitType"]) or "",
        _gst_pay_seg(_row_value(row, ["PatTypeNew", "PatType"])),
        _row_value(row, ["name", "Name", "Item"]) or "",
        _gst_tax_pct_display(tax_pct),
        f"{cgst:.2f}",
        f"{sgst:.2f}",
        f"{taxable:.2f}",
        f"{amt:.2f}",
    ]


def _gst_return_filter_values(row: dict) -> list[str]:
    amt = _safe_float(_row_value(row, ["ReturnAmt", "ReturnAmount", "Amount"]))
    tax_pct = _safe_float(_row_value(row, ["Taxid", "TaxId", "TaxID"]))
    tax_component = amt * tax_pct / (100 + tax_pct) if tax_pct else 0.0
    cgst = tax_component / 2
    sgst = tax_component / 2
    taxable = amt - tax_component
    paytype = _row_value(row, ["PatTypeNew", "payType", "PayType"])
    return [
        _row_value(row, ["ReturnDate"]) or "",
        _row_value(row, ["VisitNo", "visitno", "Visit_No"]) or "",
        _row_value(row, ["Patient", "patient"]) or "",
        _row_value(row, ["Regno", "RegNo", "RegNo."]) or "",
        _row_value(row, ["TypeOfVisit", "VisitType"]) or "",
        _gst_pay_seg(paytype),
        _row_value(row, ["Name", "name", "Item"]) or "",
        _gst_tax_pct_display(tax_pct),
        f"{cgst:.2f}",
        f"{sgst:.2f}",
        f"{taxable:.2f}",
        f"{amt:.2f}",
    ]


def _build_gst_export_bytes(
    target_unit: str,
    start_date: str,
    end_date: str,
    username: str,
    fresh: bool = False,
    sale_filters: list[str] | None = None,
    return_filters: list[str] | None = None,
) -> io.BytesIO:
    cache_key = (target_unit, start_date, end_date)
    cached = _gst_cache_get(cache_key) if not fresh else None
    sales_records = cached.get("sales") if cached else None
    returns_records = cached.get("returns") if cached else None

    df_sales = pd.DataFrame(sales_records) if sales_records is not None else None
    df_returns = pd.DataFrame(returns_records) if returns_records is not None else None

    if df_sales is None:
        df_sales = data_fetch.fetch_gst_drug_sales(target_unit, start_date, end_date)
    if df_returns is None:
        df_returns = data_fetch.fetch_gst_drug_returns(target_unit, start_date, end_date)

    if df_sales is None:
        df_sales = pd.DataFrame()
    if df_returns is None:
        df_returns = pd.DataFrame()

    _gst_cache_put(
        cache_key,
        {
            "sales": df_sales.to_dict(orient="records") if not df_sales.empty else [],
            "returns": df_returns.to_dict(orient="records") if not df_returns.empty else [],
        },
    )

    sale_filters_norm = _gst_norm_filters(sale_filters)
    return_filters_norm = _gst_norm_filters(return_filters)
    include_details = any(sale_filters_norm) or any(return_filters_norm)

    for col in ["SaleDate", "BillDate"]:
        if col in df_sales.columns and pd.api.types.is_datetime64_any_dtype(df_sales[col]):
            df_sales[col] = pd.to_datetime(df_sales[col], errors="coerce").dt.strftime("%Y-%m-%d %H:%M:%S")
    for col in ["ReturnDate"]:
        if col in df_returns.columns and pd.api.types.is_datetime64_any_dtype(df_returns[col]):
            df_returns[col] = pd.to_datetime(df_returns[col], errors="coerce").dt.strftime("%Y-%m-%d %H:%M:%S")

    df_sales = df_sales.replace({np.nan: None, np.inf: None, -np.inf: None})
    df_returns = df_returns.replace({np.nan: None, np.inf: None, -np.inf: None})

    sales_records = df_sales.to_dict(orient="records") if not df_sales.empty else []
    returns_records = df_returns.to_dict(orient="records") if not df_returns.empty else []

    if any(sale_filters_norm):
        sales_records = [
            r for r in sales_records
            if _gst_row_matches_filters(_gst_sales_filter_values(r), sale_filters_norm)
        ]
    if any(return_filters_norm):
        returns_records = [
            r for r in returns_records
            if _gst_row_matches_filters(_gst_return_filter_values(r), return_filters_norm)
        ]

    details = []
    sales_details = []
    returns_details = []

    for r in sales_records:
        tax_pct = _safe_float(_row_value(r, ["Taxid", "TaxId", "TaxID"]))
        amt = _safe_float(_row_value(r, ["TotalAmt", "TotalAmount", "Amount"]))
        tax_component = amt * tax_pct / (100 + tax_pct) if tax_pct else 0.0
        cgst = tax_component / 2
        sgst = tax_component / 2
        taxable = amt - tax_component
        pay_seg = _gst_pay_seg(_row_value(r, ["PatTypeNew", "PatType"]))
        details.append({
            "Source": "Sale",
            "Kind": "D",
            "TranDate": _row_value(r, ["SaleDate"]) or "",
            "VisitNo": _row_value(r, ["visitno", "VisitNo"]) or "",
            "Patient": _row_value(r, ["patient", "Patient"]) or "",
            "RegNo": _row_value(r, ["regno", "RegNo", "Regno"]) or "",
            "VisitType": _row_value(r, ["TypeOfVisit", "VisitType"]) or "",
            "VisitBucket": _gst_visit_bucket(_row_value(r, ["TypeOfVisit", "VisitType"])),
            "PaySeg": pay_seg,
            "Item": _row_value(r, ["name", "Name", "Item"]) or "",
            "TaxPct": tax_pct,
            "CGST": cgst,
            "SGST": sgst,
            "Taxable": taxable,
            "Amount": amt,
            "AmountSign": amt
        })
        if include_details:
            sales_details.append({
                "Sale Date": _row_value(r, ["SaleDate"]) or "",
                "Bill Date": _row_value(r, ["BillDate"]) or "",
                "Patient": _row_value(r, ["patient", "Patient"]) or "",
                "Reg No": _row_value(r, ["regno", "RegNo", "Regno"]) or "",
                "Visit Type": _row_value(r, ["TypeOfVisit", "VisitType"]) or "",
                "Pay Seg": pay_seg,
                "Item": _row_value(r, ["name", "Name", "Item"]) or "",
                "Tax %": tax_pct,
                "CGST": cgst,
                "SGST": sgst,
                "Taxable": taxable,
                "Amount": amt,
            })

    for r in returns_records:
        tax_pct = _safe_float(_row_value(r, ["Taxid", "TaxId", "TaxID"]))
        amt = _safe_float(_row_value(r, ["ReturnAmt", "ReturnAmount", "Amount"]))
        tax_component = amt * tax_pct / (100 + tax_pct) if tax_pct else 0.0
        cgst = tax_component / 2
        sgst = tax_component / 2
        taxable = amt - tax_component
        paytype_col = _row_value(r, ["PatTypeNew", "payType", "PayType"])
        pay_seg = _gst_pay_seg(paytype_col)
        details.append({
            "Source": "Return",
            "Kind": "R",
            "TranDate": _row_value(r, ["ReturnDate"]) or "",
            "VisitNo": _row_value(r, ["VisitNo", "visitno"]) or "",
            "Patient": _row_value(r, ["Patient", "patient"]) or "",
            "RegNo": _row_value(r, ["Regno", "RegNo"]) or "",
            "VisitType": _row_value(r, ["TypeOfVisit", "VisitType"]) or "",
            "VisitBucket": _gst_visit_bucket(_row_value(r, ["TypeOfVisit", "VisitType"])),
            "PaySeg": pay_seg,
            "Item": _row_value(r, ["Name", "name", "Item"]) or "",
            "TaxPct": tax_pct,
            "CGST": cgst,
            "SGST": sgst,
            "Taxable": taxable,
            "Amount": amt,
            "AmountSign": -amt
        })
        if include_details:
            returns_details.append({
                "Return Date": _row_value(r, ["ReturnDate"]) or "",
                "Visit No": _row_value(r, ["VisitNo", "visitno"]) or "",
                "Patient": _row_value(r, ["Patient", "patient"]) or "",
                "Reg No": _row_value(r, ["Regno", "RegNo"]) or "",
                "Visit Type": _row_value(r, ["TypeOfVisit", "VisitType"]) or "",
                "Pay Seg": pay_seg,
                "Item": _row_value(r, ["Name", "name", "Item"]) or "",
                "Tax %": tax_pct,
                "CGST": cgst,
                "SGST": sgst,
                "Taxable": taxable,
                "Amount": amt,
            })

    details_df = pd.DataFrame(details)
    if details_df.empty:
        raise ValueError("No data to export for this range")
    sales_detail_df = pd.DataFrame(sales_details) if include_details else pd.DataFrame()
    returns_detail_df = pd.DataFrame(returns_details) if include_details else pd.DataFrame()

    def build_section(df, label):
        if df.empty:
            return pd.DataFrame(columns=["Section", "PaySeg", "TaxPct", "DPV", "OPD", "Temp-Patient", "CGST", "SGST", "Taxable", "Amount"])
        df = df.copy()
        df["AmtDisp"] = df["AmountSign"].abs() if label == "Returns" else df["AmountSign"]
        bucket = df.pivot_table(index=["PaySeg", "TaxPct"], columns="VisitBucket", values="AmtDisp", aggfunc="sum", fill_value=0).reset_index()
        agg = df.groupby(["PaySeg", "TaxPct"], as_index=False).agg({"CGST": "sum", "SGST": "sum", "Taxable": "sum", "AmtDisp": "sum"})
        merged = agg.merge(bucket, on=["PaySeg", "TaxPct"], how="left")
        for col in ["DPV", "OPD", "Temp-Patient"]:
            if col not in merged.columns:
                merged[col] = 0
        merged["Section"] = label
        merged.rename(columns={"AmtDisp": "Amount", "TaxPct": "Tax %"}, inplace=True)
        return merged[["Section", "PaySeg", "Tax %", "DPV", "OPD", "Temp-Patient", "CGST", "SGST", "Taxable", "Amount"]]

    sales_df = details_df[details_df["Kind"] == "D"].copy()
    returns_df = details_df[details_df["Kind"] == "R"].copy()
    summary_sales = build_section(sales_df, "Sales")
    summary_returns = build_section(returns_df, "Returns")
    wb = Workbook()
    wb.remove(wb.active)
    thin = Side(border_style="thin", color="d9d9d9")
    header_fill = PatternFill(start_color="e2e8f0", end_color="e2e8f0", fill_type="solid")
    payseg_fills = {
        "cash": PatternFill(start_color="fff7c2", end_color="fff7c2", fill_type="solid"),
        "cashless": PatternFill(start_color="e3f2fd", end_color="e3f2fd", fill_type="solid"),
        "tpa": PatternFill(start_color="f3e5f5", end_color="f3e5f5", fill_type="solid"),
    }
    title_font = Font(size=14, bold=True)
    hdr_font = Font(bold=True)
    money_cols = {"CGST", "SGST", "Taxable", "Amount"}
    pct_cols = {"Tax %"}

    def write_sheet(name, title, df, include_headers=True):
        ws = wb.create_sheet(name)
        ws.append([title])
        ws["A1"].font = title_font
        ws.append(["Unit", target_unit, "From", start_date, "To", end_date, "Exported By", username or ""])
        ws.append([])
        if df is None or df.empty:
            ws.append(["No data"])
            return
        col_formats = {}
        if include_headers:
            ws.append(list(df.columns))
            for cell in ws[ws.max_row]:
                cell.font = hdr_font
                cell.fill = header_fill
                cell.alignment = Alignment(horizontal="center", vertical="center")
                cell.border = Border(top=thin, bottom=thin, left=thin, right=thin)
            for idx, name in enumerate(df.columns, start=1):
                if name in money_cols:
                    col_formats[idx] = ("#,##,##0.00", "right")
                elif name in pct_cols:
                    col_formats[idx] = ("0.##", "right")
        for _, row in df.iterrows():
            ws.append(list(row.values))
            for idx, cell in enumerate(ws[ws.max_row], start=1):
                cell.border = Border(top=thin, bottom=thin, left=thin, right=thin)
                fmt = col_formats.get(idx)
                if fmt:
                    cell.number_format = fmt[0]
                    cell.alignment = Alignment(horizontal=fmt[1], vertical="center")
        for col_idx in range(1, ws.max_column + 1):
            max_len = 0
            col_letter = get_column_letter(col_idx)
            for row in range(1, ws.max_row + 1):
                cell = ws.cell(row=row, column=col_idx)
                if cell.value is not None:
                    max_len = max(max_len, len(str(cell.value)))
            ws.column_dimensions[col_letter].width = min(max_len + 2, 40)
        ws.freeze_panes = "A4"

    ws_sum = wb.create_sheet("Summary")
    ws_sum.append(["GST Sales/Returns Summary"])
    ws_sum["A1"].font = title_font
    ws_sum.merge_cells(start_row=1, start_column=1, end_row=1, end_column=10)
    ws_sum.append(["Unit", target_unit, "From", start_date, "To", end_date, "Exported By", username or ""])
    ws_sum.append([])

    def write_section(sheet, title, df_section):
        sheet.append([title])
        sheet[sheet.cell(row=sheet.max_row, column=1).coordinate].font = hdr_font
        sheet.append(["PaySeg", "Tax %", "Section", "DPV", "OPD", "Temp-Patient", "CGST", "SGST", "Taxable", "Amount"])
        header_fill_blue = PatternFill(start_color="1f4e78", end_color="1f4e78", fill_type="solid")
        header_font_white = Font(bold=True, color="FFFFFF")
        for cell in sheet[sheet.max_row]:
            cell.font = header_font_white
            cell.fill = header_fill_blue
            cell.alignment = Alignment(horizontal="center", vertical="center")
            cell.border = Border(top=thin, bottom=thin, left=thin, right=thin)
        if df_section.empty:
            sheet.append(["No data"])
            return
        for _, r in df_section.iterrows():
            sheet.append([
                r.get("PaySeg", ""),
                r.get("Tax %", ""),
                r.get("Section", ""),
                float(r.get("DPV", 0)),
                float(r.get("OPD", 0)),
                float(r.get("Temp-Patient", 0)),
                float(r.get("CGST", 0)),
                float(r.get("SGST", 0)),
                float(r.get("Taxable", 0)),
                float(r.get("Amount", 0)),
            ])
            for cell in sheet[sheet.max_row]:
                cell.border = Border(top=thin, bottom=thin, left=thin, right=thin)
            payseg_key = str(r.get("PaySeg") or "").strip().lower()
            fill = payseg_fills.get(payseg_key)
            if fill:
                for cell in sheet[sheet.max_row]:
                    cell.fill = fill
        sheet.append([])

    write_section(ws_sum, "Sales Summary", summary_sales)
    write_section(ws_sum, "Returns Summary", summary_returns)

    for col_idx in range(1, ws_sum.max_column + 1):
        max_len = 0
        col_letter = get_column_letter(col_idx)
        for row in range(1, ws_sum.max_row + 1):
            cell = ws_sum.cell(row=row, column=col_idx)
            if cell.value is not None:
                max_len = max(max_len, len(str(cell.value)))
        ws_sum.column_dimensions[col_letter].width = min(max_len + 2, 40)

    if include_details:
        write_sheet("Sales Details", "GST Sales (Filtered)", sales_detail_df)
        write_sheet("Return Details", "GST Returns (Filtered)", returns_detail_df)

    buf = io.BytesIO()
    wb.save(buf)
    buf.seek(0)
    return buf


@app.route('/api/audit/gst_export')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_gst_export():
    unit = (request.args.get("unit") or "").strip() or None
    start_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    end_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    fresh = _is_truthy(request.args.get("fresh"))
    sale_filters = [(request.args.get(f"sale_filter{i}") or "") for i in range(12)]
    return_filters = [(request.args.get(f"return_filter{i}") or "") for i in range(12)]
    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return jsonify({"status": "error", "message": "No unit available"}), 400
    if allowed_units and target_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403
    username = session.get("username") or session.get("user") or ""
    try:
        buf = _build_gst_export_bytes(
            target_unit,
            start_date,
            end_date,
            username,
            fresh=fresh,
            sale_filters=sale_filters,
            return_filters=return_filters,
        )
    except ValueError as exc:
        return jsonify({"status": "error", "message": str(exc)}), 400
    filename = f"gst_{target_unit}_{start_date}_to_{end_date}.xlsx"
    return send_file(
        buf,
        as_attachment=True,
        download_name=filename,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )

def _discount_flags_for_bills(bill_nos: list[str]):
    """
    Return a mapping of BillNo -> Status from the central OTP DB (AHL).
    Used to mark rows where a discount/cancellation request was applied.
    """
    if not bill_nos:
        return {}
    try:
        from modules.db_connection import get_sql_connection
        conn = get_sql_connection("AHL")
        if not conn:
            return {}
        cursor = conn.cursor()
        placeholders = ",".join("?" for _ in bill_nos)
        cursor.execute(
            f"SELECT BillNo, Status FROM DiscountApprovalRequest WHERE BillNo IN ({placeholders})",
            bill_nos
        )
        rows = cursor.fetchall()
        return {str(r.BillNo).strip(): str(getattr(r, "Status", "")).strip().upper() for r in rows}
    except Exception:
        return {}
    finally:
        try:
            conn.close()
        except Exception:
            pass

@app.route('/api/discount/bills')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_discount_bills():
    unit = (request.args.get("unit") or "").strip() or None
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return jsonify({"status": "error", "message": "No unit available"}), 400
    if allowed_units and target_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403

    df = data_fetch.fetch_bill_register_comprehensive(target_unit, from_date, to_date)
    if df is None:
        return jsonify({"status": "error", "message": "Database error"}), 500
    if df.empty:
        return jsonify({"status": "success", "data": [], "unit": target_unit, "count": 0}), 200

    # Convert datetimes to ISO strings for JSON safety
    for col in df.columns:
        if pd.api.types.is_datetime64_any_dtype(df[col]):
            df[col] = pd.to_datetime(df[col], errors="coerce").dt.strftime("%Y-%m-%d %H:%M:%S")
    records = df.where(pd.notna(df), None).to_dict(orient="records")

    # Annotate discount applied flags using central OTP DB
    bill_nos = [str(r.get("BillNo") or r.get("billno") or "").strip() for r in records if (r.get("BillNo") or r.get("billno"))]
    flags = _discount_flags_for_bills(bill_nos)
    for r in records:
        bno = str(r.get("BillNo") or r.get("billno") or "").strip()
        status = flags.get(bno, "")
        r["_app_discount_applied"] = status in {"USED", "APPROVED"}

    return jsonify({"status": "success", "data": records, "unit": target_unit, "count": len(records)})

