def _excel_header_token(value) -> str:
    if value is None:
        return ""
    return re.sub(r"[^a-z0-9]+", "", str(value).strip().lower())


def _parse_excel_amount(value):
    if value is None or isinstance(value, bool):
        return None
    if isinstance(value, Decimal):
        return value
    if isinstance(value, (int, float)):
        if isinstance(value, float) and (math.isnan(value) or math.isinf(value)):
            return None
        return Decimal(str(value))
    raw = str(value).strip()
    if not raw or raw.startswith("="):
        return None
    cleaned = (
        raw.replace(",", "")
        .replace("â‚¹", "")
        .replace("INR", "")
        .replace("Rs.", "")
        .replace("Rs", "")
        .strip()
    )
    if not cleaned:
        return None
    try:
        return Decimal(cleaned)
    except Exception:
        return None


def _resolve_revenue_rebalance_layout(ws):
    component_token_to_name = {}
    for canonical, aliases in _REVENUE_REBALANCE_COMPONENT_CANDIDATES.items():
        for alias in aliases:
            token = _excel_header_token(alias)
            if token:
                component_token_to_name[token] = canonical
    net_tokens = {_excel_header_token(alias) for alias in _REVENUE_REBALANCE_NET_CANDIDATES if _excel_header_token(alias)}

    best = None
    scan_rows = min(int(ws.max_row or 0), 25)
    for row_idx in range(1, scan_rows + 1):
        component_cols = {}
        net_col = None
        for col_idx in range(1, int(ws.max_column or 0) + 1):
            token = _excel_header_token(ws.cell(row=row_idx, column=col_idx).value)
            if not token:
                continue
            mapped = component_token_to_name.get(token)
            if mapped and mapped not in component_cols:
                component_cols[mapped] = col_idx
            if net_col is None and token in net_tokens:
                net_col = col_idx
        if net_col and len(component_cols) >= 2:
            score = (len(component_cols) * 10) - row_idx
            if not best or score > best["score"]:
                best = {
                    "header_row": row_idx,
                    "net_col": net_col,
                    "component_cols": component_cols,
                    "score": score,
                }
    if not best:
        return None
    best.pop("score", None)
    return best


def _select_revenue_rebalance_sheets(workbook, sheet_name: str | None, process_all: bool):
    sheets = list(workbook.worksheets or [])
    if process_all:
        return sheets, None
    requested = str(sheet_name or "").strip()
    if not requested:
        return sheets, None
    requested_cf = requested.casefold()
    exact = [ws for ws in sheets if str(ws.title or "").strip().casefold() == requested_cf]
    if exact:
        return exact, None
    contains = [ws for ws in sheets if requested_cf in str(ws.title or "").strip().casefold()]
    if contains:
        return contains, None
    available = [ws.title for ws in sheets]
    return [], f"Sheet '{requested}' not found. Available sheets: {', '.join(available)}"


def _money_to_float(value: Decimal) -> float:
    if value is None:
        return 0.0
    try:
        return float(value.quantize(_REVENUE_REBALANCE_TOLERANCE, rounding=ROUND_HALF_UP))
    except Exception:
        try:
            return float(value)
        except Exception:
            return 0.0


def _rebalance_revenue_sheet(
    ws,
    layout: dict,
    reduce_only: bool = True,
    target_net_basis: str = "original",
    target_net_percent: Decimal | None = None,
    target_net_value: Decimal | None = None,
):
    net_col = int(layout.get("net_col") or 0)
    component_cols = layout.get("component_cols") or {}
    header_row = int(layout.get("header_row") or 1)
    if not net_col or not component_cols:
        return None

    tolerance = _REVENUE_REBALANCE_TOLERANCE
    component_pairs = sorted(component_cols.items(), key=lambda item: item[1])

    stats = {
        "sheet": ws.title,
        "rows_seen": 0,
        "rows_adjusted": 0,
        "rows_scaled_down": 0,
        "rows_scaled_up": 0,
        "rows_already_matching": 0,
        "rows_skipped_reduce_only": 0,
        "rows_skipped_non_numeric": 0,
        "rows_skipped_non_positive": 0,
        "rows_skipped_formula": 0,
        "component_total_before": Decimal("0"),
        "component_total_after": Decimal("0"),
        "original_net_total": Decimal("0"),
        "target_net_total": Decimal("0"),
    }

    for row_idx in range(header_row + 1, int(ws.max_row or 0) + 1):
        net_cell = ws.cell(row=row_idx, column=net_col)
        component_cells = [(name, ws.cell(row=row_idx, column=col_idx)) for name, col_idx in component_pairs]

        if net_cell.data_type == "f" or any(cell.data_type == "f" for _, cell in component_cells):
            stats["rows_skipped_formula"] += 1
            continue

        net_value = _parse_excel_amount(net_cell.value)
        raw_component_values = [_parse_excel_amount(cell.value) for _, cell in component_cells]
        if net_value is None and all(value is None for value in raw_component_values):
            continue
        if net_value is None:
            stats["rows_skipped_non_numeric"] += 1
            continue

        component_values = [value if value is not None else Decimal("0") for value in raw_component_values]
        component_sum_before = sum(component_values, Decimal("0"))

        row_target_net = net_value
        if target_net_basis == "percentage" and target_net_percent is not None:
            row_target_net = net_value * (Decimal("1") + (target_net_percent / Decimal("100")))
        elif target_net_basis == "absolute" and target_net_value is not None:
            row_target_net = target_net_value

        diff_before = component_sum_before - row_target_net

        stats["rows_seen"] += 1
        stats["component_total_before"] += component_sum_before
        stats["original_net_total"] += net_value
        stats["target_net_total"] += row_target_net

        if abs(diff_before) <= tolerance:
            stats["rows_already_matching"] += 1
            stats["component_total_after"] += component_sum_before
            continue
        if component_sum_before <= 0:
            stats["rows_skipped_non_positive"] += 1
            stats["component_total_after"] += component_sum_before
            continue
        change_direction = "down" if diff_before > tolerance else "up"
        if reduce_only and change_direction == "up":
            stats["rows_skipped_reduce_only"] += 1
            stats["component_total_after"] += component_sum_before
            continue

        ratio = row_target_net / component_sum_before if component_sum_before else Decimal("0")
        scaled_values = [
            (value * ratio).quantize(tolerance, rounding=ROUND_HALF_UP)
            for value in component_values
        ]
        target_net_q = row_target_net.quantize(tolerance, rounding=ROUND_HALF_UP)
        remainder = target_net_q - sum(scaled_values, Decimal("0"))
        if remainder != 0:
            target_idx = max(range(len(component_values)), key=lambda idx: abs(component_values[idx]))
            scaled_values[target_idx] = scaled_values[target_idx] + remainder

        row_changed = False
        for idx, (_, cell) in enumerate(component_cells):
            prior = component_values[idx].quantize(tolerance, rounding=ROUND_HALF_UP)
            if prior != scaled_values[idx]:
                row_changed = True
            cell.value = float(scaled_values[idx])
        if row_changed:
            stats["rows_adjusted"] += 1
            if change_direction == "down":
                stats["rows_scaled_down"] += 1
            else:
                stats["rows_scaled_up"] += 1

        stats["component_total_after"] += sum(scaled_values, Decimal("0"))

    stats["delta_before"] = stats["component_total_before"] - stats["target_net_total"]
    stats["delta_after"] = stats["component_total_after"] - stats["target_net_total"]
    # Backward-compatible alias (points to target basis net total).
    stats["net_total"] = stats["target_net_total"]
    return stats


@app.route('/api/modifications/revenue_component_rebalance', methods=['POST'])
@app.route('/api/modifications/revenue_component_rebalance/', methods=['POST'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_modifications_revenue_component_rebalance():
    uploaded = request.files.get("file")
    if not uploaded or not str(uploaded.filename or "").strip():
        return jsonify({"status": "error", "message": "Please upload an Excel file (.xlsx or .xlsm)."}), 400

    original_name = os.path.basename(str(uploaded.filename or "").strip())
    _, ext = os.path.splitext(original_name)
    ext = ext.lower()
    if ext not in {".xlsx", ".xlsm"}:
        return jsonify({"status": "error", "message": "Unsupported file type. Upload .xlsx or .xlsm."}), 400

    reduce_only_raw = request.form.get("reduce_only")
    allow_increase_raw = request.form.get("allow_increase")
    if allow_increase_raw is not None and str(allow_increase_raw).strip() != "":
        allow_increase = _is_truthy(allow_increase_raw)
        reduce_only = not allow_increase
    else:
        reduce_only = _is_truthy(reduce_only_raw if reduce_only_raw is not None else "1")
        allow_increase = not reduce_only
    target_net_basis = str(request.form.get("target_net_basis") or "original").strip().lower()
    if target_net_basis not in {"original", "percentage", "absolute"}:
        return jsonify({"status": "error", "message": "Invalid target net basis. Use original, percentage, or absolute."}), 400

    target_net_percent = None
    target_net_value = None
    if target_net_basis == "percentage":
        target_net_percent = _parse_excel_amount(request.form.get("target_net_percent"))
        if target_net_percent is None:
            return jsonify({"status": "error", "message": "Enter a valid net percentage."}), 400
        if target_net_percent < Decimal("-100"):
            return jsonify({"status": "error", "message": "Net percentage cannot be below -100%."}), 400
    elif target_net_basis == "absolute":
        target_net_value = _parse_excel_amount(request.form.get("target_net_value"))
        if target_net_value is None:
            return jsonify({"status": "error", "message": "Enter a valid fixed net value."}), 400
        if target_net_value < 0:
            return jsonify({"status": "error", "message": "Fixed net value cannot be negative."}), 400

    process_all = _is_truthy(request.form.get("process_all"))
    requested_sheet = (request.form.get("sheet_name") or "").strip()

    try:
        uploaded.stream.seek(0)
    except Exception:
        pass

    try:
        workbook = load_workbook(uploaded, data_only=False, keep_vba=(ext == ".xlsm"))
    except Exception as exc:
        return jsonify({"status": "error", "message": f"Failed to read workbook: {exc}"}), 400

    target_sheets, select_error = _select_revenue_rebalance_sheets(workbook, requested_sheet, process_all)
    if select_error:
        return jsonify({"status": "error", "message": select_error}), 400

    sheet_stats = []
    for ws in target_sheets:
        layout = _resolve_revenue_rebalance_layout(ws)
        if not layout:
            continue
        stats = _rebalance_revenue_sheet(
            ws,
            layout,
            reduce_only=reduce_only,
            target_net_basis=target_net_basis,
            target_net_percent=target_net_percent,
            target_net_value=target_net_value,
        )
        if stats:
            sheet_stats.append(stats)

    if not sheet_stats:
        return jsonify({
            "status": "error",
            "message": "No compatible sheet found. Expected NetAmount and at least two component columns.",
        }), 400

    total_rows_seen = int(sum(item["rows_seen"] for item in sheet_stats))
    total_rows_adjusted = int(sum(item["rows_adjusted"] for item in sheet_stats))
    total_rows_scaled_down = int(sum(item["rows_scaled_down"] for item in sheet_stats))
    total_rows_scaled_up = int(sum(item["rows_scaled_up"] for item in sheet_stats))
    total_rows_matching = int(sum(item["rows_already_matching"] for item in sheet_stats))
    total_rows_skipped_reduce_only = int(sum(item["rows_skipped_reduce_only"] for item in sheet_stats))
    total_rows_skipped_non_numeric = int(sum(item["rows_skipped_non_numeric"] for item in sheet_stats))
    total_rows_skipped_non_positive = int(sum(item["rows_skipped_non_positive"] for item in sheet_stats))
    total_rows_skipped_formula = int(sum(item["rows_skipped_formula"] for item in sheet_stats))

    total_component_before = sum((item["component_total_before"] for item in sheet_stats), Decimal("0"))
    total_component_after = sum((item["component_total_after"] for item in sheet_stats), Decimal("0"))
    total_original_net = sum((item.get("original_net_total") or Decimal("0") for item in sheet_stats), Decimal("0"))
    total_target_net = sum((item.get("target_net_total") or Decimal("0") for item in sheet_stats), Decimal("0"))

    compact_sheets = []
    for item in sheet_stats:
        compact_sheets.append({
            "sheet": item["sheet"],
            "rows_seen": int(item["rows_seen"]),
            "rows_adjusted": int(item["rows_adjusted"]),
            "rows_scaled_down": int(item["rows_scaled_down"]),
            "rows_scaled_up": int(item["rows_scaled_up"]),
            "rows_already_matching": int(item["rows_already_matching"]),
            "rows_skipped_reduce_only": int(item["rows_skipped_reduce_only"]),
            "original_net_total": _money_to_float(item.get("original_net_total") or Decimal("0")),
            "target_net_total": _money_to_float(item.get("target_net_total") or Decimal("0")),
            "delta_before": _money_to_float(item["delta_before"]),
            "delta_after": _money_to_float(item["delta_after"]),
        })

    target_net_basis_label = {
        "original": "Original NetAmount",
        "percentage": "Percentage of NetAmount",
        "absolute": "Fixed Net value",
    }.get(target_net_basis, "Original NetAmount")

    summary = {
        "sheet_mode": "all" if process_all else "selected",
        "requested_sheet": requested_sheet or "",
        "reduce_only": bool(reduce_only),
        "allow_increase": bool(allow_increase),
        "adjustment_mode": "reduce_only" if reduce_only else "rebalance_up_down",
        "target_net_basis": target_net_basis,
        "target_net_basis_label": target_net_basis_label,
        "target_net_percent": _money_to_float(target_net_percent) if target_net_percent is not None else None,
        "target_net_value": _money_to_float(target_net_value) if target_net_value is not None else None,
        "processed_sheets": len(sheet_stats),
        "rows_seen": total_rows_seen,
        "rows_adjusted": total_rows_adjusted,
        "rows_scaled_down": total_rows_scaled_down,
        "rows_scaled_up": total_rows_scaled_up,
        "rows_already_matching": total_rows_matching,
        "rows_skipped_reduce_only": total_rows_skipped_reduce_only,
        "rows_skipped_non_numeric": total_rows_skipped_non_numeric,
        "rows_skipped_non_positive": total_rows_skipped_non_positive,
        "rows_skipped_formula": total_rows_skipped_formula,
        "component_total_before": _money_to_float(total_component_before),
        "component_total_after": _money_to_float(total_component_after),
        "original_net_total": _money_to_float(total_original_net),
        "target_net_total": _money_to_float(total_target_net),
        "net_total": _money_to_float(total_target_net),
        "delta_before": _money_to_float(total_component_before - total_target_net),
        "delta_after": _money_to_float(total_component_after - total_target_net),
        "sheets": compact_sheets,
    }

    stem, _ = os.path.splitext(original_name or "Revenue_Summary")
    safe_stem = re.sub(r"[^A-Za-z0-9._-]+", "_", stem).strip("._") or "Revenue_Summary"
    download_name = f"{safe_stem}_rebalanced{ext if ext in {'.xlsx', '.xlsm'} else '.xlsx'}"

    output = io.BytesIO()
    try:
        workbook.save(output)
    except Exception as exc:
        return jsonify({"status": "error", "message": f"Failed to save workbook: {exc}"}), 500
    output.seek(0)

    summary_json = json.dumps(summary, separators=(",", ":"))
    summary_b64 = base64.b64encode(summary_json.encode("utf-8")).decode("ascii")
    mime = (
        "application/vnd.ms-excel.sheet.macroEnabled.12"
        if ext == ".xlsm"
        else "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    )
    response = send_file(
        output,
        mimetype=mime,
        as_attachment=True,
        download_name=download_name,
    )
    response.headers["X-Rebalance-Summary-B64"] = summary_b64
    response.headers["X-Rebalance-Status"] = "success"
    return response


@app.route('/api/modifications/locked_bills')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_locked_bills():
    unit = (request.args.get("unit") or "").strip() or None
    bill_type = (request.args.get("bill_type") or "").strip() or None
    days_raw = request.args.get("days")
    try:
        days = int(days_raw) if days_raw is not None else 7
    except Exception:
        days = 7
    days = max(1, min(days, 14))

    allowed_units = _modification_units(_allowed_units_for_session())
    target_unit = (unit or (allowed_units[0] if allowed_units else None))
    if not target_unit:
        return jsonify({"status": "error", "message": "No unit available"}), 400
    target_unit = target_unit.strip().upper()
    if allowed_units and target_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403

    now = datetime.now(tz=LOCAL_TZ)
    start_date = (now - timedelta(days=days - 1)).strftime("%Y-%m-%d")
    end_date = now.strftime("%Y-%m-%d")

    df = data_fetch.fetch_locked_bills_recent(target_unit, start_date, end_date, bill_type=bill_type)
    if df is None:
        return jsonify({"status": "error", "message": "Database error"}), 500
    if df.empty:
        return jsonify({"status": "success", "data": [], "unit": target_unit, "count": 0}), 200

    for col in df.columns:
        if pd.api.types.is_datetime64_any_dtype(df[col]):
            df[col] = pd.to_datetime(df[col], errors="coerce").dt.strftime("%Y-%m-%d %H:%M:%S")
    df = df.replace({np.nan: None, np.inf: None, -np.inf: None})
    records = df.to_dict(orient="records")
    return jsonify({"status": "success", "data": records, "unit": target_unit, "count": len(records)})


