@app.route('/api/modifications/visit_reference')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_modification_visit_reference():
    unit = (request.args.get("unit") or "").strip() or None
    allowed_units = _modification_units(_allowed_units_for_session())
    target_unit = (unit or (allowed_units[0] if allowed_units else None))
    if not target_unit:
        return jsonify({"status": "error", "message": "No unit available"}), 400
    target_unit = target_unit.strip().upper()
    if allowed_units and target_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403

    departments = data_fetch.fetch_departments(target_unit)
    wards = data_fetch.fetch_wards(target_unit)
    rooms = data_fetch.fetch_rooms(target_unit)
    beds = data_fetch.fetch_beds(target_unit)
    doctors = data_fetch.fetch_doctors(target_unit)
    users = data_fetch.fetch_users(target_unit)
    patient_types = data_fetch.fetch_patient_types(target_unit)
    patient_subtypes = data_fetch.fetch_patient_subtypes(target_unit)
    tariff_schemes = data_fetch.fetch_tariff_schemes(target_unit)
    health_checkups = data_fetch.fetch_health_checkups(target_unit)

    if (
        departments is None
        and wards is None
        and rooms is None
        and beds is None
        and doctors is None
        and users is None
        and patient_types is None
        and patient_subtypes is None
        and tariff_schemes is None
        and health_checkups is None
    ):
        return jsonify({"status": "error", "message": "Database error"}), 500

    def _records(df):
        if df is None or df.empty:
            return []
        df = df.replace({np.nan: None, np.inf: None, -np.inf: None})
        return df.to_dict(orient="records")

    payload = {
        "departments": _records(departments),
        "wards": _records(wards),
        "rooms": _records(rooms),
        "beds": _records(beds),
        "doctors": _records(doctors),
        "users": _records(users),
        "patient_types": _records(patient_types),
        "patient_subtypes": _records(patient_subtypes),
        "tariff_schemes": _records(tariff_schemes),
        "health_checkups": _records(health_checkups),
    }
    return jsonify({"status": "success", "data": payload, "unit": target_unit})


@app.route('/api/modifications/bed_status/check')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_modification_bed_status_check():
    unit = (request.args.get("unit") or "").strip().upper()
    bed_id = _coerce_int(request.args.get("bed_id"), allow_none=True)
    allowed_units = _modification_units(_allowed_units_for_session())
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return jsonify({"status": "error", "message": "Select a unit"}), 400
    if allowed_units and unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403
    if not bed_id:
        return jsonify({"status": "error", "message": "Missing bed id"}), 400

    from modules.db_connection import get_sql_connection
    conn = get_sql_connection(unit)
    if not conn:
        return jsonify({"status": "error", "message": f"Unable to connect to unit {unit}"}), 500
    try:
        cursor = conn.cursor()
        bed_status = _fetch_bed_status(cursor, int(bed_id))
        active_visit = _fetch_active_bed_visit(cursor, int(bed_id))
        return jsonify({
            "status": "success",
            "bed_status": bed_status,
            "occupied": bool(active_visit),
            "active_visit": active_visit,
        })
    except Exception as e:
        return jsonify({"status": "error", "message": str(e)}), 500
    finally:
        try:
            conn.close()
        except Exception:
            pass


@app.route('/api/modifications/bed_status/update', methods=['POST'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_modification_bed_status_update():
    data = request.get_json(silent=True) or {}
    unit = (data.get("unit") or "").strip().upper()
    bed_id = _coerce_int(data.get("bed_id"), allow_none=True)
    status = _coerce_int(data.get("status"), allow_none=True)
    allowed_units = _modification_units(_allowed_units_for_session())
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return jsonify({"status": "error", "message": "Select a unit"}), 400
    if allowed_units and unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403
    if not bed_id:
        return jsonify({"status": "error", "message": "Missing bed id"}), 400
    if status not in (1, 2):
        return jsonify({"status": "error", "message": "Invalid bed status"}), 400

    from modules.db_connection import get_sql_connection
    conn = get_sql_connection(unit)
    if not conn:
        return jsonify({"status": "error", "message": f"Unable to connect to unit {unit}"}), 500
    try:
        cursor = conn.cursor()
        if status == 1:
            active_visit = _fetch_active_bed_visit(cursor, int(bed_id))
            if active_visit:
                return jsonify({"status": "error", "message": "Bed is occupied by an undischarged patient."}), 400
        cursor.execute(
            "UPDATE Bed_mst SET Bed_Status_ID = ? WHERE Bed_ID = ?",
            (int(status), int(bed_id)),
        )
        conn.commit()
        return jsonify({"status": "success"})
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return jsonify({"status": "error", "message": str(e)}), 500
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _coerce_int(val, allow_none: bool = True):
    if val is None:
        return None if allow_none else 0
    raw = str(val).strip()
    if not raw:
        return None if allow_none else 0
    try:
        return int(raw)
    except Exception:
        return None if allow_none else 0


def _coerce_nullable_flag(val):
    if val is None:
        return None
    raw = str(val).strip()
    if not raw or raw == "0":
        return None
    try:
        return int(raw)
    except Exception:
        return None


def _apply_bill_edit_updates(
    unit: str,
    bill_no: str,
    bill_id: str,
    reg_no: str,
    bill_date: str,
    changes: dict,
    username: str,
    dry_run: bool = False,
):
    from modules.db_connection import get_sql_connection
    conn = get_sql_connection(unit)
    if not conn:
        return {"error": f"Unable to connect to unit {unit}"}
    try:
        conn.autocommit = False
        cursor = conn.cursor()

        bill_no_val = str(bill_no or "").strip()
        bill_id_val = _coerce_int(bill_id, allow_none=True)
        reg_no_val = str(reg_no or "").strip()
        bill_date_val = _parse_datetime_input(bill_date)
        if not bill_date_val:
            bill_date_val = None

        if bill_id_val:
            cursor.execute("""
                SELECT TOP 1
                    bm.Bill_ID, bm.BillNo, bm.Registration_No, bm.BillDate,
                    bm.DiscountAmount, bm.NetAmount, bm.DueAmount, bm.submitted,
                    bm.BillType, bm.CancelStatus,
                    v.Visit_ID, v.TypeOfVisit, v.DischargeType, v.DischargeDate, v.billSubmitStatus,
                    v.IPPhNoc, v.IPPhNocBy, v.IPPhNocDate,
                    v.OPPhNoc, v.OPPhNocBy, v.OPPhNocDate
                FROM Billing_Mst bm WITH (ROWLOCK, UPDLOCK)
                LEFT JOIN Visit v WITH (NOLOCK) ON v.Visit_ID = bm.Visit_ID
                WHERE bm.Bill_ID = ?
                ORDER BY bm.BillDate DESC
            """, (bill_id_val,))
        elif bill_no_val:
            cursor.execute("""
                SELECT TOP 1
                    bm.Bill_ID, bm.BillNo, bm.Registration_No, bm.BillDate,
                    bm.DiscountAmount, bm.NetAmount, bm.DueAmount, bm.submitted,
                    bm.BillType, bm.CancelStatus,
                    v.Visit_ID, v.TypeOfVisit, v.DischargeType, v.DischargeDate, v.billSubmitStatus,
                    v.IPPhNoc, v.IPPhNocBy, v.IPPhNocDate,
                    v.OPPhNoc, v.OPPhNocBy, v.OPPhNocDate
                FROM Billing_Mst bm WITH (ROWLOCK, UPDLOCK)
                LEFT JOIN Visit v WITH (NOLOCK) ON v.Visit_ID = bm.Visit_ID
                WHERE bm.BillNo = ?
                ORDER BY bm.BillDate DESC
            """, (bill_no_val,))
        elif reg_no_val and bill_date_val:
            cursor.execute("""
                SELECT TOP 1
                    bm.Bill_ID, bm.BillNo, bm.Registration_No, bm.BillDate,
                    bm.DiscountAmount, bm.NetAmount, bm.DueAmount, bm.submitted,
                    bm.BillType, bm.CancelStatus,
                    v.Visit_ID, v.TypeOfVisit, v.DischargeType, v.DischargeDate, v.billSubmitStatus,
                    v.IPPhNoc, v.IPPhNocBy, v.IPPhNocDate,
                    v.OPPhNoc, v.OPPhNocBy, v.OPPhNocDate
                FROM Billing_Mst bm WITH (ROWLOCK, UPDLOCK)
                LEFT JOIN Visit v WITH (NOLOCK) ON v.Visit_ID = bm.Visit_ID
                WHERE bm.Registration_No = ?
                  AND bm.BillDate >= ?
                  AND bm.BillDate < DATEADD(day, 1, ?)
                ORDER BY bm.BillDate DESC
            """, (reg_no_val, bill_date_val, bill_date_val))
        else:
            return {"error": "Missing bill identifier"}

        row = cursor.fetchone()
        if not row:
            conn.rollback()
            return {"error": "Bill not found"}

        visit_type = str(getattr(row, "TypeOfVisit", "") or "").upper()
        is_ipd = "IPD" in visit_type
        visit_id = getattr(row, "Visit_ID", None)
        cancel_status = getattr(row, "CancelStatus", None)
        bill_type = str(getattr(row, "BillType", "") or "").strip().upper()
        receipt_type = "PH" if bill_type == "PH" else "P"
        account_id = _resolve_account_id(username) or 0

        cancel_bill = _is_truthy(changes.get("cancel_bill"))
        cancel_receipt_no = str(changes.get("cancel_receipt_no") or "").strip()
        receipt_payment_raw = changes.get("receipt_payment_mode") or {}
        receipt_payment_no = ""
        payment_mode_id = None
        if isinstance(receipt_payment_raw, dict):
            receipt_payment_no = str(receipt_payment_raw.get("receipt_no") or "").strip()
            payment_mode_id = _coerce_int(receipt_payment_raw.get("payment_mode_id"), allow_none=True)

        action_count = (1 if cancel_bill else 0) + (1 if cancel_receipt_no else 0) + (1 if receipt_payment_no else 0)
        if action_count > 1:
            conn.rollback()
            return {"error": "Only one bill/receipt action can be applied at a time."}
        if action_count == 1:
            extra_keys = set(changes.keys()) - {"cancel_bill", "cancel_receipt_no", "receipt_payment_mode"}
            if extra_keys:
                conn.rollback()
                return {"error": "Bill/receipt actions cannot be combined with other edits."}
            if not visit_id:
                conn.rollback()
                return {"error": "Visit record not found for bill."}

            if cancel_bill:
                if cancel_status in (1, True, "1"):
                    conn.rollback()
                    return {"error": "Bill is already cancelled."}
                if dry_run:
                    conn.rollback()
                    return {"success": True}
                if bill_type == "PH":
                    cursor.execute(
                        """
                        UPDATE Billing_Mst
                        SET CancelStatus = 1,
                            CancelReasonID = 1,
                            CanceledBy = ?,
                            CanceledOn = GETDATE(),
                            PHReturnAmount = ISNULL(NetAmount, 0),
                            NetAmount = 0,
                            DueAmount = 0,
                            UpdatedOn = GETDATE()
                        WHERE Bill_ID = ?
                        """,
                        (account_id, getattr(row, "Bill_ID")),
                    )
                else:
                    cursor.execute(
                        """
                        UPDATE Billing_Mst
                        SET CancelStatus = 1,
                            CancelReasonID = 1,
                            CanceledBy = ?,
                            CanceledOn = GETDATE(),
                            DueAmount = 0,
                            UpdatedOn = GETDATE()
                        WHERE Bill_ID = ?
                        """,
                        (account_id, getattr(row, "Bill_ID")),
                    )
                cursor.execute(
                    """
                    UPDATE Receipt_mst
                    SET CancelStatus = 1,
                        CancelReasonid = 1,
                        CancelDate = GETDATE(),
                        CanceledBy = ?
                    WHERE Visit_ID = ? AND ReceiptType = ? AND ISNULL(CancelStatus, 0) = 0
                    """,
                    (account_id, visit_id, receipt_type),
                )
                conn.commit()
                return {"success": True}

            if cancel_receipt_no:
                cursor.execute(
                    """
                    SELECT TOP 1 Receipt_ID, Receipt_No, Amount, CancelStatus, ReceiptType
                    FROM Receipt_mst WITH (ROWLOCK, UPDLOCK)
                    WHERE Receipt_No = ? AND Visit_ID = ? AND ReceiptType = ?
                    """,
                    (cancel_receipt_no, visit_id, receipt_type),
                )
                rec = cursor.fetchone()
                if not rec:
                    conn.rollback()
                    return {"error": "Receipt not found for this bill."}
                if getattr(rec, "CancelStatus", None) in (1, True, "1"):
                    conn.rollback()
                    return {"error": "Receipt is already cancelled."}
                receipt_type = str(getattr(rec, "ReceiptType", "") or "").strip().upper()
                if receipt_type not in ("P", "PH"):
                    conn.rollback()
                    return {"error": "Only P/PH receipts can be cancelled here."}
                receipt_amt = Decimal(str(getattr(rec, "Amount", 0) or 0))
                curr_due = Decimal(str(getattr(row, "DueAmount", 0) or 0))
                curr_net = Decimal(str(getattr(row, "NetAmount", 0) or 0))
                new_due = curr_due + receipt_amt
                if curr_net > 0 and new_due > curr_net:
                    new_due = curr_net

                if dry_run:
                    conn.rollback()
                    return {"success": True}
                cursor.execute(
                    """
                    UPDATE Receipt_mst
                    SET CancelStatus = 1,
                        CancelReasonid = 1,
                        CancelDate = GETDATE(),
                        CanceledBy = ?
                    WHERE Receipt_No = ? AND Visit_ID = ? AND ReceiptType = ?
                    """,
                    (account_id, cancel_receipt_no, visit_id, receipt_type),
                )
                cursor.execute(
                    """
                    UPDATE Billing_Mst
                    SET DueAmount = ?,
                        UpdatedOn = GETDATE()
                    WHERE Bill_ID = ?
                    """,
                    (float(new_due), getattr(row, "Bill_ID")),
                )
                conn.commit()
                return {"success": True}

            if receipt_payment_no:
                if payment_mode_id is None:
                    conn.rollback()
                    return {"error": "Select a payment mode to update the receipt."}
                cursor.execute(
                    """
                    SELECT TOP 1 Receipt_ID, Receipt_No, CancelStatus, ReceiptType
                    FROM Receipt_mst WITH (ROWLOCK, UPDLOCK)
                    WHERE Receipt_No = ? AND Visit_ID = ? AND ReceiptType = ?
                    """,
                    (receipt_payment_no, visit_id, receipt_type),
                )
                rec = cursor.fetchone()
                if not rec:
                    conn.rollback()
                    return {"error": "Receipt not found for this bill."}
                if getattr(rec, "CancelStatus", None) in (1, True, "1"):
                    conn.rollback()
                    return {"error": "Cannot update payment mode for a cancelled receipt."}
                receipt_type = str(getattr(rec, "ReceiptType", "") or "").strip().upper()
                if receipt_type not in ("P", "PH"):
                    conn.rollback()
                    return {"error": "Only P/PH receipts can be updated here."}
                if dry_run:
                    conn.rollback()
                    return {"success": True}
                cursor.execute(
                    """
                    UPDATE Receipt_mst
                    SET PaymentMode = ?,
                        UpdatedOn = GETDATE(),
                        UpdatedBy = ?
                    WHERE Receipt_No = ? AND Visit_ID = ?
                    """,
                    (payment_mode_id, account_id, receipt_payment_no, visit_id),
                )
                conn.commit()
                return {"success": True}

        updates_bm = []
        params_bm = []
        updates_visit = []
        params_visit = []

        if "bill_date" in changes:
            new_bill_date_raw = str(changes.get("bill_date") or "").strip()
            if not new_bill_date_raw:
                conn.rollback()
                return {"error": "Bill date is required."}
            new_bill_date = _parse_datetime_input(new_bill_date_raw)
            if not new_bill_date:
                conn.rollback()
                return {"error": "Invalid bill date format."}
            updates_bm.append("BillDate = ?")
            params_bm.append(new_bill_date)

        if "discount_amount" in changes:
            curr_due = Decimal(str(getattr(row, "DueAmount", 0) or 0))
            curr_disc = Decimal(str(getattr(row, "DiscountAmount", 0) or 0))
            curr_net = Decimal(str(getattr(row, "NetAmount", 0) or 0))
            new_disc = Decimal(str(changes.get("discount_amount") or 0))
            if new_disc < 0:
                conn.rollback()
                return {"error": "Discount amount cannot be negative."}
            delta = new_disc - curr_disc
            if delta > 0 and curr_due <= 0:
                conn.rollback()
                if not is_ipd:
                    return {"error": "Due amount is 0. Please cancel the receipt before applying a discount."}
                return {"error": "Discount edit allowed only when due amount is greater than 0."}
            new_due = curr_due - delta
            if new_due < 0:
                conn.rollback()
                return {"error": "Discount cannot make due amount negative."}
            new_net = curr_net - delta
            if new_net < 0:
                new_net = Decimal("0")
            updates_bm.extend(["DiscountAmount = ?", "NetAmount = ?", "DueAmount = ?"])
            params_bm.extend([float(new_disc), float(new_net), float(new_due)])

        ipd_keys = {"discharge_type", "clear_discharge_date", "submitted", "ip_ph_noc", "ip_user", "ip_noc_date", "op_ph_noc", "op_user", "op_noc_date"}
        if (set(changes.keys()) & ipd_keys) and not is_ipd:
            conn.rollback()
            return {"error": "IPD-only fields can only be edited for In-Patient bills."}

        if is_ipd:
            def _normalize_datetime(val):
                if val is None or val == "":
                    return None
                if isinstance(val, datetime):
                    return val
                if isinstance(val, date):
                    return datetime.combine(val, datetime.min.time())
                if isinstance(val, str):
                    return _parse_datetime_input(val)
                return None

            def _submitted_values(submitted_raw):
                submitted_text = str(submitted_raw or "").strip()
                if submitted_text == "1":
                    return 1, 1
                if submitted_text == "0":
                    return 0, None
                if submitted_text == "":
                    return None, None
                coerced = _coerce_int(submitted_text, allow_none=True)
                return coerced, coerced

            discharge_dt = _normalize_datetime(getattr(row, "DischargeDate", None))
            discharge_locked = False
            if discharge_dt:
                now_dt = datetime.now(tz=LOCAL_TZ)
                if discharge_dt.tzinfo is None:
                    discharge_dt = discharge_dt.replace(tzinfo=LOCAL_TZ)
                hours_since = (now_dt - discharge_dt).total_seconds() / 3600
                discharge_locked = hours_since >= 12
            if discharge_locked and (set(changes.keys()) & ipd_keys):
                conn.rollback()
                return {
                    "error": "It has been 12 hours since the patient was sent for clinical discharge. Please contact IT to remove the discharge time limit before proceeding."
                }

            orig_discharge = _coerce_int(getattr(row, "DischargeType", None), allow_none=True)
            discharge_val = orig_discharge
            discharge_changed = False
            if "discharge_type" in changes:
                discharge_val = _coerce_int(changes.get("discharge_type"), allow_none=True)
                discharge_changed = discharge_val != orig_discharge
                updates_visit.append("DischargeType = ?")
                params_visit.append(discharge_val)
            clear_discharge_date = _is_truthy(changes.get("clear_discharge_date"))
            if clear_discharge_date:
                if discharge_val != 0:
                    conn.rollback()
                    return {"error": "Discharge date can only be cleared when discharge type is Not Discharged."}
                updates_visit.append("DischargeDate = NULL")

            force_not_discharged = discharge_changed and discharge_val == 0
            submitted_raw = None
            if force_not_discharged:
                submitted_raw = "0"
            elif "submitted" in changes:
                submitted_raw = str(changes.get("submitted") or "").strip()

            submitted_open = submitted_raw is not None and str(submitted_raw) == "0"
            force_clear_noc = force_not_discharged or submitted_open

            if submitted_raw is not None:
                bm_submitted, visit_submitted = _submitted_values(submitted_raw)
                updates_bm.append("submitted = ?")
                params_bm.append(bm_submitted)
                updates_visit.append("billSubmitStatus = ?")
                params_visit.append(visit_submitted)

            if force_clear_noc:
                updates_visit.extend([
                    "IPPhNoc = NULL",
                    "IPPhNocBy = NULL",
                    "IPPhNocDate = NULL",
                    "OPPhNoc = NULL",
                    "OPPhNocBy = NULL",
                    "OPPhNocDate = NULL",
                ])
            else:
                ip_noc_change = "ip_ph_noc" in changes
                ip_noc_val = _coerce_nullable_flag(changes.get("ip_ph_noc")) if ip_noc_change else None
                if ip_noc_change:
                    updates_visit.append("IPPhNoc = ?")
                    params_visit.append(ip_noc_val)

                ip_noc_active = ip_noc_val if ip_noc_change else _coerce_int(getattr(row, "IPPhNoc", None), allow_none=True)
                if ip_noc_active:
                    if "ip_user" in changes:
                        ip_user_id = _resolve_account_id(changes.get("ip_user"))
                        if ip_user_id is None and str(changes.get("ip_user") or "").strip():
                            conn.rollback()
                            return {"error": "Unknown IP user. Use username or account id."}
                        updates_visit.append("IPPhNocBy = ?")
                        params_visit.append(ip_user_id)
                    if "ip_noc_date" in changes:
                        ip_date = _parse_datetime_input(changes.get("ip_noc_date"))
                        updates_visit.append("IPPhNocDate = ?")
                        params_visit.append(ip_date)
                elif ip_noc_change:
                    updates_visit.append("IPPhNocBy = NULL")
                    updates_visit.append("IPPhNocDate = NULL")

                op_noc_change = "op_ph_noc" in changes
                op_noc_val = _coerce_nullable_flag(changes.get("op_ph_noc")) if op_noc_change else None
                if op_noc_change:
                    updates_visit.append("OPPhNoc = ?")
                    params_visit.append(op_noc_val)

                op_noc_active = op_noc_val if op_noc_change else _coerce_int(getattr(row, "OPPhNoc", None), allow_none=True)
                if op_noc_active:
                    if "op_user" in changes:
                        op_user_id = _resolve_account_id(changes.get("op_user"))
                        if op_user_id is None and str(changes.get("op_user") or "").strip():
                            conn.rollback()
                            return {"error": "Unknown OP user. Use username or account id."}
                        updates_visit.append("OPPhNocBy = ?")
                        params_visit.append(op_user_id)
                    if "op_noc_date" in changes:
                        op_date = _parse_datetime_input(changes.get("op_noc_date"))
                        updates_visit.append("OPPhNocDate = ?")
                        params_visit.append(op_date)
                elif op_noc_change:
                    updates_visit.append("OPPhNocBy = NULL")
                    updates_visit.append("OPPhNocDate = NULL")

        if not updates_bm and not updates_visit:
            conn.rollback()
            return {"error": "No valid updates to apply."}

        visit_id = None
        if updates_visit:
            visit_id = getattr(row, "Visit_ID", None)
            if not visit_id:
                conn.rollback()
                return {"error": "Visit record not found for bill."}

        if dry_run:
            conn.rollback()
            return {"success": True}

        if updates_bm:
            updates_bm.append("UpdatedOn = GETDATE()")
            cursor.execute(
                f"UPDATE Billing_Mst SET {', '.join(updates_bm)} WHERE Bill_ID = ?",
                (*params_bm, getattr(row, "Bill_ID")),
            )

        if updates_visit:
            cursor.execute(
                f"UPDATE Visit SET {', '.join(updates_visit)} WHERE Visit_ID = ?",
                (*params_visit, visit_id),
            )

        conn.commit()
        return {"success": True}
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"error": str(e)}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _resolve_table_ref_ci(
    conn,
    table_candidates: list[str],
    preferred_schema: str = "dbo",
) -> str | None:
    cur = conn.cursor()
    for cand in (table_candidates or []):
        raw = str(cand or "").strip()
        if not raw:
            continue
        parts = [p.strip().strip("[]") for p in raw.split(".") if p and p.strip()]
        if not parts:
            continue
        schema_hint = None
        table_name = parts[-1]
        if len(parts) >= 2:
            schema_hint = parts[-2]
        # Fast path: OBJECT_ID resolution first (works even when sys.* metadata is restricted)
        direct_refs = []
        if schema_hint:
            direct_refs.append(f"{schema_hint}.{table_name}")
            direct_refs.append(f"[{schema_hint}].[{table_name}]")
        direct_refs.append(table_name)
        if preferred_schema:
            direct_refs.append(f"{preferred_schema}.{table_name}")
            direct_refs.append(f"[{preferred_schema}].[{table_name}]")
        seen = set()
        for ref in direct_refs:
            norm = ref.lower()
            if norm in seen:
                continue
            seen.add(norm)
            try:
                cur.execute("SELECT OBJECT_ID(?)", (ref,))
                row = cur.fetchone()
                if row and row[0]:
                    if "." in ref and not ref.startswith("["):
                        return ref
                    if schema_hint:
                        return f"{schema_hint}.{table_name}"
                    return f"{preferred_schema}.{table_name}" if preferred_schema else table_name
            except Exception:
                pass
        try:
            if schema_hint:
                cur.execute(
                    """
                    SELECT TOP 1 s.name AS SchemaName, t.name AS TableName
                    FROM sys.tables t
                    JOIN sys.schemas s ON s.schema_id = t.schema_id
                    WHERE LOWER(t.name) = LOWER(?)
                      AND LOWER(s.name) = LOWER(?)
                    """,
                    (table_name, schema_hint),
                )
            else:
                cur.execute(
                    """
                    SELECT TOP 1 s.name AS SchemaName, t.name AS TableName
                    FROM sys.tables t
                    JOIN sys.schemas s ON s.schema_id = t.schema_id
                    WHERE LOWER(t.name) = LOWER(?)
                    ORDER BY CASE WHEN LOWER(s.name) = LOWER(?) THEN 0 ELSE 1 END, s.name
                    """,
                    (table_name, preferred_schema),
                )
            row = cur.fetchone()
            if row and row[0] and row[1]:
                return f"{row[0]}.{row[1]}"
        except Exception:
            continue
    return None


def _get_columns_map_by_table_ref(conn, table_ref: str) -> dict[str, str]:
    cur = conn.cursor()
    cols = {}
    refs = [table_ref]
    bare = str(table_ref or "").split(".")[-1].strip()
    if bare and bare not in refs:
        refs.append(bare)
    for ref in refs:
        if not ref:
            continue
        try:
            cur.execute(
                "SELECT c.name FROM sys.columns c WHERE c.object_id = OBJECT_ID(?)",
                (ref,),
            )
            rows = cur.fetchall()
            if rows:
                for row in rows:
                    if row and row[0]:
                        cols[str(row[0]).strip().lower()] = str(row[0]).strip()
                if cols:
                    return cols
        except Exception:
            continue
    # Fallback via INFORMATION_SCHEMA
    try:
        raw = str(table_ref or "").strip()
        parts = [p.strip().strip("[]") for p in raw.split(".") if p and p.strip()]
        schema_name = "dbo"
        table_name = parts[-1] if parts else bare
        if len(parts) >= 2:
            schema_name = parts[-2]
        if table_name:
            cur.execute(
                """
                SELECT COLUMN_NAME
                FROM INFORMATION_SCHEMA.COLUMNS
                WHERE LOWER(TABLE_NAME) = LOWER(?)
                  AND LOWER(TABLE_SCHEMA) = LOWER(?)
                """,
                (table_name, schema_name),
            )
            rows = cur.fetchall()
            if rows:
                for row in rows:
                    if row and row[0]:
                        cols[str(row[0]).strip().lower()] = str(row[0]).strip()
                if cols:
                    return cols
    except Exception:
        pass
    return cols


def _resolve_referral_grade_type_id(
    conn,
    cursor,
    preferred_id: int,
    preferred_name: str | None = None,
    preferred_name_like: str | None = None,
):
    table_ref = _resolve_table_ref_ci(
        conn,
        ["dbo.GradofAgency", "dbo.GradeofAgency", "dbo.GradeOfAgency", "GradofAgency", "GradeofAgency", "GradeOfAgency"],
    )
    if not table_ref:
        return preferred_id
    col_map = _get_columns_map_by_table_ref(conn, table_ref)
    if not col_map:
        return preferred_id

    id_col = _resolve_column(col_map, ["Id", "ID", "id"])
    name_col = _resolve_column(col_map, ["gradname", "GradName", "GradeName", "Name"])
    deactive_col = _resolve_column(col_map, ["deactive", "Deactive", "Inactive", "inactive"])
    if not id_col:
        return preferred_id
    active_clause = f" AND ISNULL({deactive_col}, 0) = 0" if deactive_col else ""

    try:
        cursor.execute(
            f"SELECT TOP 1 {id_col} FROM {table_ref} WITH (NOLOCK) WHERE {id_col} = ?{active_clause}",
            (preferred_id,),
        )
        row = cursor.fetchone()
        if row and row[0] is not None:
            return int(row[0])
    except Exception:
        pass

    if name_col and preferred_name:
        try:
            cursor.execute(
                f"""
                SELECT TOP 1 {id_col}
                FROM {table_ref} WITH (NOLOCK)
                WHERE LTRIM(RTRIM(CAST({name_col} AS NVARCHAR(255)))) = ?{active_clause}
                """,
                (preferred_name,),
            )
            row = cursor.fetchone()
            if row and row[0] is not None:
                return int(row[0])
        except Exception:
            pass

    if name_col and preferred_name_like:
        try:
            cursor.execute(
                f"""
                SELECT TOP 1 {id_col}
                FROM {table_ref} WITH (NOLOCK)
                WHERE LOWER(LTRIM(RTRIM(CAST({name_col} AS NVARCHAR(255))))) LIKE ?{active_clause}
                """,
                (f"%{preferred_name_like.lower()}%",),
            )
            row = cursor.fetchone()
            if row and row[0] is not None:
                return int(row[0])
        except Exception:
            pass

    return preferred_id


def _insert_referred_mst_entry(
    conn,
    cursor,
    visit_id: int,
    entry: dict,
    account_id: int,
    dry_run: bool = False,
):
    table_ref = _resolve_table_ref_ci(
        conn,
        ["dbo.referred_mst", "dbo.Referred_Mst", "Referred_Mst", "Referred_mst", "referred_mst"],
    )
    if not table_ref:
        table_ref = "dbo.referred_mst"
    col_map = _get_columns_map_by_table_ref(conn, table_ref)

    visit_col = _resolve_column(col_map, ["visitId", "VisitId", "VisitID", "Visit_ID"]) or "visitId"
    ref_type_col = _resolve_column(col_map, ["refTypeId", "RefTypeId", "RefTypeID", "RefType_ID"]) or "refTypeId"
    ref_name_col = _resolve_column(col_map, ["refName", "RefName", "ReferralName"]) or "refName"
    ref_district_col = _resolve_column(col_map, ["refDistrict", "RefDistrict", "District"]) or "refDistrict"
    ref_mobile_col = _resolve_column(col_map, ["refMobileNo", "RefMobileNo", "RefMobile", "MobileNo", "Mobile"]) or "refMobileNo"
    inserted_on_col = _resolve_column(col_map, ["insertedOn", "InsertedOn", "InsertedON", "Inserted_On"]) or "insertedOn"
    inserted_by_col = _resolve_column(col_map, ["insertedBy", "InsertedBy", "InsertedByUserID"]) or "insertedBy"

    mode = str((entry or {}).get("mode") or "").strip().lower()
    ref_name = ""
    ref_district = None
    ref_mobile = None
    ref_type_id = None

    if mode == "selected":
        doctor_id = _coerce_int((entry or {}).get("doctor_id"), allow_none=True)
        if not doctor_id:
            return {"error": "Invalid Ref Doc selection."}
        try:
            cursor.execute(
                """
                SELECT TOP 1 empid
                FROM employee_mst WITH (NOLOCK)
                WHERE empid = ?
                  AND emptype = 'Doc'
                  AND ISNULL(deactive, 0) = 0
                """,
                (doctor_id,),
            )
            if not cursor.fetchone():
                return {"error": "Selected Ref Doc is invalid."}
        except Exception as e:
            return {"error": f"Unable to validate Ref Doc: {e}"}
        try:
            cursor.execute("SELECT dbo.fn_doctorfirstname(?) AS RefName", (doctor_id,))
            row = cursor.fetchone()
            ref_name = str((getattr(row, "RefName", None) if row else None) or "").strip()
        except Exception:
            ref_name = ""
        if not ref_name:
            ref_name = str(doctor_id)
        ref_type_id = _resolve_referral_grade_type_id(
            conn=conn,
            cursor=cursor,
            preferred_id=2,
            preferred_name="AHL",
        )
        ref_district = "Dhanbad"
        ref_mobile = None
    elif mode == "manual":
        ref_name = str((entry or {}).get("manual_name") or "").strip()
        if not ref_name:
            return {"error": "Manual Ref Doc name is required."}
        ref_type_id = _resolve_referral_grade_type_id(
            conn=conn,
            cursor=cursor,
            preferred_id=4,
            preferred_name_like="doctor",
        )
        ref_district = None
        ref_mobile = None
    else:
        return {"error": "Invalid ref_doc_entry mode."}

    insert_cols = [visit_col, ref_type_col, ref_name_col]
    insert_vals = ["?", "?", "?"]
    params = [visit_id, int(ref_type_id or 0), ref_name]

    insert_cols.append(ref_district_col)
    insert_vals.append("?")
    params.append(ref_district)
    insert_cols.append(ref_mobile_col)
    insert_vals.append("?")
    params.append(ref_mobile)
    insert_cols.append(inserted_on_col)
    insert_vals.append("GETDATE()")
    insert_cols.append(inserted_by_col)
    insert_vals.append("?")
    params.append(int(account_id or 0))

    if dry_run:
        return {"success": True}
    try:
        cursor.execute(
            f"""
            INSERT INTO {table_ref} ({", ".join(insert_cols)})
            VALUES ({", ".join(insert_vals)})
            """,
            tuple(params),
        )
    except Exception as e:
        return {"error": f"Failed to insert Referred_Mst entry: {e}"}
    return {"success": True}


def _apply_visit_edit_updates(
    unit: str,
    visit_id: int,
    changes: dict,
    username: str,
    dry_run: bool = False,
):
    from modules.db_connection import get_sql_connection
    unit_norm = (unit or "").strip().upper()
    if not visit_id:
        return {"error": "Missing visit id"}
    conn = get_sql_connection(unit_norm)
    if not conn:
        return {"error": f"Unable to connect to unit {unit_norm}"}
    try:
        conn.autocommit = False
        cursor = conn.cursor()
        cursor.execute(
            "SELECT TOP 1 Visit_ID, BedID, VisitDate, DischargeDate FROM Visit WITH (ROWLOCK, UPDLOCK) WHERE Visit_ID = ?",
            (visit_id,),
        )
        row = cursor.fetchone()
        if not row:
            conn.rollback()
            return {"error": "Visit not found"}
        current_bed_id = row[1]
        current_visit_date = row[2] if len(row) > 2 else None
        current_discharge_date = row[3] if len(row) > 3 else None

        def _norm_raw(val):
            if val is None:
                return None
            if isinstance(val, str):
                raw = val.strip()
                if not raw or raw.lower() in {"null", "none"}:
                    return None
                return raw
            return val

        def _parse_int(val, field: str):
            raw = _norm_raw(val)
            if raw is None:
                return None
            coerced = _coerce_int(raw, allow_none=True)
            if coerced is None:
                raise ValueError(f"Invalid {field}")
            return coerced

        def _parse_flag(val, field: str):
            raw = _norm_raw(val)
            if raw is None:
                return None
            raw_str = str(raw).strip().lower()
            if raw_str in {"true", "yes", "y"}:
                return 1
            if raw_str in {"false", "no", "n"}:
                return None
            coerced = _coerce_nullable_flag(raw_str)
            if coerced is None and raw_str not in {"", "0"}:
                raise ValueError(f"Invalid {field}")
            return coerced

        def _parse_datetime(val, field: str):
            raw = _norm_raw(val)
            if raw is None:
                return None
            parsed = _parse_datetime_input(str(raw))
            if parsed is None:
                raise ValueError(f"Invalid {field}")
            return parsed

        def _parse_text(val):
            raw = _norm_raw(val)
            if raw is None:
                return None
            return str(raw)

        def _coerce_datetime(val):
            if val is None or val == "":
                return None
            if isinstance(val, datetime):
                return val
            if isinstance(val, date):
                return datetime.combine(val, datetime.min.time())
            if isinstance(val, str):
                return _parse_datetime_input(val)
            return None

        changes = dict(changes or {})
        ref_doc_entry = changes.get("ref_doc_entry")
        referred_insert_payload = None
        if "ref_doc_entry" in changes:
            if not isinstance(ref_doc_entry, dict):
                conn.rollback()
                return {"error": "Invalid ref_doc_entry payload."}
            ref_mode = str(ref_doc_entry.get("mode") or "").strip().lower()
            if ref_mode not in {"selected", "manual", "empty"}:
                conn.rollback()
                return {"error": "Invalid ref_doc_entry mode."}
            if ref_mode == "selected":
                try:
                    ref_doc_selected_id = _parse_int(ref_doc_entry.get("doctor_id"), "Ref Doc")
                except ValueError as ve:
                    conn.rollback()
                    return {"error": str(ve)}
                if ref_doc_selected_id is None:
                    conn.rollback()
                    return {"error": "Ref Doc is required."}
                try:
                    cursor.execute(
                        """
                        SELECT TOP 1 empid
                        FROM employee_mst WITH (NOLOCK)
                        WHERE empid = ?
                          AND emptype = 'Doc'
                          AND ISNULL(deactive, 0) = 0
                        """,
                        (ref_doc_selected_id,),
                    )
                    if not cursor.fetchone():
                        conn.rollback()
                        return {"error": "Selected Ref Doc is invalid."}
                except Exception as e:
                    conn.rollback()
                    return {"error": f"Unable to validate Ref Doc: {e}"}
                if "ref_doc_id" not in changes:
                    changes["ref_doc_id"] = ref_doc_selected_id
                referred_insert_payload = {"mode": "selected", "doctor_id": ref_doc_selected_id}
            elif ref_mode == "manual":
                manual_name = str(_parse_text(ref_doc_entry.get("manual_name")) or "").strip()
                if not manual_name:
                    conn.rollback()
                    return {"error": "Manual Ref Doc name is required."}
                if "ref_doc_id" not in changes:
                    changes["ref_doc_id"] = None
                referred_insert_payload = {"mode": "manual", "manual_name": manual_name}
            else:
                if "ref_doc_id" not in changes:
                    changes["ref_doc_id"] = None

        discharge_type_val = None
        if "discharge_type" in changes:
            try:
                discharge_type_val = _parse_int(changes.get("discharge_type"), "DischargeType")
            except ValueError as ve:
                conn.rollback()
                return {"error": str(ve)}
            if discharge_type_val == 0:
                changes["discharge_date"] = None

        bill_submit_open = False
        bill_submit_closed = False
        if "bill_submit_status" in changes:
            try:
                bill_submit_val = _parse_int(changes.get("bill_submit_status"), "billSubmitStatus")
            except ValueError as ve:
                conn.rollback()
                return {"error": str(ve)}
            bill_submit_open = bill_submit_val == 0
            bill_submit_closed = bill_submit_val == 1

        visit_dt = _coerce_datetime(current_visit_date)
        discharge_dt = _coerce_datetime(current_discharge_date)
        if "visit_date" in changes:
            try:
                visit_dt = _parse_datetime(changes.get("visit_date"), "VisitDate")
            except ValueError as ve:
                conn.rollback()
                return {"error": str(ve)}
        if "discharge_date" in changes:
            try:
                discharge_dt = _parse_datetime(changes.get("discharge_date"), "DischargeDate")
            except ValueError as ve:
                conn.rollback()
                return {"error": str(ve)}
        if visit_dt and discharge_dt and visit_dt > discharge_dt:
            conn.rollback()
            return {"error": "Visit Date cannot be after Discharge Date."}

        field_specs = [
            ("ward_id", "WardID", "int"),
            ("room_id", "RoomID", "int"),
            ("bed_id", "BedID", "int"),
            ("department_id", "DepartmentID", "int"),
            ("doc_in_charge", "DocInCharge", "int"),
            ("ref_doc_id", "RefDocID", "int"),
            ("discharge_type", "DischargeType", "int"),
            ("discharge_date", "DischargeDate", "datetime"),
            ("visit_date", "VisitDate", "datetime"),
            ("patient_type_id", "PatientType_ID", "int"),
            ("tariff_scheme_id", "TariffScheme_ID", "int"),
            ("patient_sub_type_id", "PatientSubType_ID", "int"),
            ("health_checkup_id", "HealthCheckUpID", "int"),
            ("outside_ref_doctor", "OutsideRefDoctor", "int"),
            ("sub_doc_id", "subdocid", "int"),
            ("pay_type", "payType", "int"),
            ("ip_ph_noc", "IPPhNoc", "flag"),
            ("ip_ph_noc_date", "IPPhNocDate", "datetime"),
            ("op_ph_noc", "OPPhNoc", "flag"),
            ("op_ph_noc_date", "OPPhNocDate", "datetime"),
            ("op_ph_noc_by", "OPPhNocBy", "int"),
            ("ip_ph_noc_by", "IPPhNocBy", "int"),
            ("bill_submit_status", "billSubmitStatus", "int"),
            ("tag", "tag", "text"),
            ("open_by", "openBy", "int"),
            ("open_datetime", "openDatetime", "datetime"),
        ]

        updates = []
        params = []
        bed_change = "bed_id" in changes
        new_bed_id = current_bed_id
        if bed_change:
            try:
                new_bed_id = _parse_int(changes.get("bed_id"), "BedID")
            except ValueError as ve:
                conn.rollback()
                return {"error": str(ve)}
            if new_bed_id != current_bed_id and new_bed_id is not None:
                active_visit = _fetch_active_bed_visit(cursor, int(new_bed_id), exclude_visit_id=visit_id)
                if active_visit:
                    conn.rollback()
                    return {"error": "Bed is occupied by another patient."}
                bed_status = _fetch_bed_status(cursor, int(new_bed_id))
                if bed_status == 2:
                    conn.rollback()
                    return {"error": "Bed is marked occupied. Update bed status to empty first."}
        for key, column, kind in field_specs:
            if key not in changes:
                continue
            try:
                if kind == "int":
                    value = _parse_int(changes.get(key), column)
                elif kind == "flag":
                    value = _parse_flag(changes.get(key), column)
                elif kind == "datetime":
                    value = _parse_datetime(changes.get(key), column)
                elif kind == "text":
                    value = _parse_text(changes.get(key))
                else:
                    continue
            except ValueError as ve:
                conn.rollback()
                return {"error": str(ve)}
            updates.append(f"{column} = ?")
            params.append(value)

        if not updates and not referred_insert_payload:
            conn.rollback()
            return {"error": "No valid updates to apply."}

        account_id = _resolve_account_id(username) or 0
        if updates:
            updates.append("UpdatedBy = ?")
            params.append(account_id)
            updates.append("UpdatedOn = GETDATE()")

        if dry_run:
            if referred_insert_payload:
                referred_result = _insert_referred_mst_entry(
                    conn=conn,
                    cursor=cursor,
                    visit_id=visit_id,
                    entry=referred_insert_payload,
                    account_id=account_id,
                    dry_run=True,
                )
                if referred_result.get("error"):
                    conn.rollback()
                    return {"error": referred_result.get("error")}
            conn.rollback()
            return {"success": True}

        if bed_change and new_bed_id != current_bed_id:
            if current_bed_id:
                active_old = _fetch_active_bed_visit(cursor, int(current_bed_id), exclude_visit_id=visit_id)
                if not active_old:
                    cursor.execute(
                        "UPDATE Bed_mst SET Bed_Status_ID = 1 WHERE Bed_ID = ?",
                        (int(current_bed_id),),
                    )
            if new_bed_id:
                cursor.execute(
                    "UPDATE Bed_mst SET Bed_Status_ID = 2 WHERE Bed_ID = ?",
                    (int(new_bed_id),),
                )

        if updates:
            cursor.execute(
                f"UPDATE Visit SET {', '.join(updates)} WHERE Visit_ID = ?",
                (*params, visit_id),
            )
        if bill_submit_open:
            cursor.execute(
                """
                UPDATE Billing_Mst
                SET submitted = NULL,
                    UpdatedOn = GETDATE()
                WHERE Visit_ID = ? AND BillType = ?
                """,
                (visit_id, "P"),
            )
        elif bill_submit_closed:
            cursor.execute(
                """
                UPDATE Billing_Mst
                SET submitted = 1,
                    UpdatedOn = GETDATE()
                WHERE Visit_ID = ? AND BillType = ?
                """,
                (visit_id, "P"),
            )
        if referred_insert_payload:
            referred_result = _insert_referred_mst_entry(
                conn=conn,
                cursor=cursor,
                visit_id=visit_id,
                entry=referred_insert_payload,
                account_id=account_id,
            )
            if referred_result.get("error"):
                conn.rollback()
                return {"error": referred_result.get("error")}
        conn.commit()
        return {"success": True}
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"error": str(e)}
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _create_virtual_visit_duplicate(
    unit: str,
    patient_id,
    visit_date,
    discharge_date,
    patient_sub_type_id,
    visit_type_id,
    doc_id,
    discharge_type_id,
    username: str,
    visit_status=None,
    dry_run: bool = False,
):
    from modules.db_connection import get_sql_connection

    unit_norm = (unit or "").strip().upper()
    patient_id_val = _coerce_int(patient_id, allow_none=True)
    patient_sub_type_raw = str(patient_sub_type_id or "").strip()
    patient_sub_type_id_val = _coerce_int(patient_sub_type_id, allow_none=True)
    visit_type_id_val = _coerce_int(visit_type_id, allow_none=True)
    doc_id_val = _coerce_int(doc_id, allow_none=True)
    discharge_type_id_val = _coerce_int(discharge_type_id, allow_none=True)
    visit_status_val = _coerce_int(visit_status, allow_none=True)
    visit_dt = _parse_datetime_input(visit_date)
    discharge_dt = _parse_datetime_input(discharge_date)

    if not unit_norm:
        return {"error": "Select a unit"}
    if not patient_id_val:
        return {"error": "Patient ID is required"}
    if not patient_sub_type_raw and not patient_sub_type_id_val:
        return {"error": "Patient SubType is required"}
    if visit_type_id_val not in (1, 2, 3):
        return {"error": "Visit Type must be 1 (IPD), 2 (OPD), or 3 (DPV)"}
    if not visit_dt:
        return {"error": "Visit Date is required"}
    is_ipd_visit = visit_type_id_val == 1
    if is_ipd_visit:
        if not discharge_dt:
            return {"error": "Discharge Date is required for IPD."}
        if visit_dt > discharge_dt:
            return {"error": "Visit Date cannot be after Discharge Date."}
    else:
        if not discharge_dt:
            discharge_dt = visit_dt
    if doc_id_val is None:
        doc_id_val = 0
    if is_ipd_visit:
        if discharge_type_id_val is None:
            discharge_type_id_val = 2
    else:
        discharge_type_id_val = 0

    conn = get_sql_connection(unit_norm)
    if not conn:
        return {"error": f"Unable to connect to unit {unit_norm}"}
    try:
        conn.autocommit = False
        cursor = conn.cursor()

        cursor.execute(
            """
            SELECT TOP 1
                PatientId,
                Registration_No,
                PatientType_ID,
                PatientSubType_ID,
                Title,
                First_Name,
                Middle_Name,
                Last_Name
            FROM Patient WITH (NOLOCK)
            WHERE PatientId = ?
              AND ISNULL(Deactive, 0) = 0
            """,
            (patient_id_val,),
        )
        patient_row = cursor.fetchone()
        if not patient_row:
            conn.rollback()
            return {"error": "Patient not found for this unit."}

        subtype_col_map = _get_table_columns_map(conn, "patientsubtype_mst")
        subtype_id_col = _resolve_column(
            subtype_col_map,
            ["PatientSubTypeID", "PatientSubTypeId", "PatientSubType_ID", "SubTypeID", "SubTypeId", "Id"],
        )
        subtype_deactive_col = _resolve_column(
            subtype_col_map,
            ["Deactive", "deactive", "Inactive", "inactive"],
        )
        subtype_type_col = _resolve_column(
            subtype_col_map,
            ["PatientTypeID", "PatientTypeId", "PatientType_ID", "TypeID", "TypeId", "PatientType"],
        )
        if not subtype_id_col:
            conn.rollback()
            return {"error": "PatientSubType master is missing ID column."}

        if patient_sub_type_id_val is None and patient_sub_type_raw:
            subtype_name_cols = []
            for cand in ["PatientSubTypeDesc", "PatientSubType_Desc", "PatientSubTypeName", "PatientSubType", "SubTypeName", "Name"]:
                resolved = _resolve_column(subtype_col_map, [cand])
                if resolved and resolved not in subtype_name_cols:
                    subtype_name_cols.append(resolved)
            if subtype_name_cols:
                where_name = " OR ".join([f"LTRIM(RTRIM(CAST({c} AS NVARCHAR(255)))) = ?" for c in subtype_name_cols])
                deactive_clause = f" AND ISNULL({subtype_deactive_col}, 0) = 0" if subtype_deactive_col else ""
                cursor.execute(
                    f"""
                    SELECT TOP 1 {subtype_id_col} AS PatientSubTypeID
                    FROM patientsubtype_mst WITH (NOLOCK)
                    WHERE ({where_name}){deactive_clause}
                    ORDER BY {subtype_id_col}
                    """,
                    tuple([patient_sub_type_raw] * len(subtype_name_cols)),
                )
                subtype_lookup_row = cursor.fetchone()
                if subtype_lookup_row:
                    patient_sub_type_id_val = _coerce_int(getattr(subtype_lookup_row, "PatientSubTypeID", None), allow_none=True)

        if not patient_sub_type_id_val:
            conn.rollback()
            return {"error": "Invalid Patient SubType."}

        subtype_select_cols = [f"{subtype_id_col} AS PatientSubTypeID"]
        if subtype_type_col:
            subtype_select_cols.append(f"{subtype_type_col} AS PatientTypeID")
        deactive_clause = f" AND ISNULL({subtype_deactive_col}, 0) = 0" if subtype_deactive_col else ""
        cursor.execute(
            f"""
            SELECT TOP 1 {", ".join(subtype_select_cols)}
            FROM patientsubtype_mst WITH (NOLOCK)
            WHERE {subtype_id_col} = ?{deactive_clause}
            """,
            (patient_sub_type_id_val,),
        )
        subtype_row = cursor.fetchone()
        if not subtype_row:
            conn.rollback()
            return {"error": "Invalid Patient SubType ID."}

        if doc_id_val not in (0, None):
            cursor.execute(
                """
                SELECT TOP 1 empid
                FROM employee_mst WITH (NOLOCK)
                WHERE empid = ?
                  AND emptype = 'Doc'
                  AND ISNULL(deactive, 0) = 0
                  AND ISNULL(docunit_id, 0) IN (1, 2, 3)
                """,
                (doc_id_val,),
            )
            doc_row = cursor.fetchone()
            if not doc_row:
                conn.rollback()
                return {"error": "Invalid Doctor ID."}

        vd_col_map = {}
        try:
            cursor.execute(
                "SELECT c.name FROM sys.columns c WHERE c.object_id = OBJECT_ID(?)",
                ("dbo.Visit_Duplicate",),
            )
            for row in cursor.fetchall():
                if row and row[0]:
                    vd_col_map[str(row[0]).strip().lower()] = str(row[0]).strip()
        except Exception:
            vd_col_map = _get_table_columns_map(conn, "Visit_Duplicate")
        vd_visit_id_col = _resolve_column(vd_col_map, ["visitId", "VisitId", "VisitID", "Visit_ID"])
        vd_patient_id_col = _resolve_column(vd_col_map, ["patientId", "PatientId", "PatientID", "Patient_ID"])
        vd_visit_date_col = _resolve_column(vd_col_map, ["visitDate", "VisitDate", "Visit_Date"])
        vd_discharge_date_col = _resolve_column(vd_col_map, ["dischargeDate", "DischargeDate", "Discharge_Date"])
        vd_patient_subtype_col = _resolve_column(vd_col_map, ["patientSubTypeId", "PatientSubTypeId", "PatientSubTypeID", "PatientSubType_ID"])
        vd_doc_col = _resolve_column(vd_col_map, ["docId", "DocId", "DocID", "DoctorId", "DoctorID"])
        vd_discharge_type_col = _resolve_column(vd_col_map, ["dischargeTypeId", "DischargeTypeId", "DischargeTypeID", "DischargeType_ID"])
        vd_visit_type_col = _resolve_column(vd_col_map, ["visitTypeId", "VisitTypeId", "VisitTypeID", "VisitType_ID"])
        vd_visit_status_col = _resolve_column(vd_col_map, ["visitStatus", "VisitStatus"])
        vd_inserted_by_col = _resolve_column(vd_col_map, ["insertedBy", "InsertedBy", "InsertedByUserID"])
        vd_inserted_on_col = _resolve_column(vd_col_map, ["insertedOn", "InsertedOn", "InsertedON", "Inserted_On"])
        vd_cbill_col = _resolve_column(vd_col_map, ["CBillId", "CBillID", "CBill_Id"])

        required_missing = [
            name for name, col in [
                ("visitId", vd_visit_id_col),
                ("patientId", vd_patient_id_col),
                ("visitDate", vd_visit_date_col),
                ("dischargeDate", vd_discharge_date_col),
                ("patientSubTypeId", vd_patient_subtype_col),
                ("docId", vd_doc_col),
                ("dischargeTypeId", vd_discharge_type_col),
                ("visitTypeId", vd_visit_type_col),
            ] if not col
        ]
        if required_missing:
            conn.rollback()
            return {"error": f"Visit_Duplicate is missing required columns: {', '.join(required_missing)}"}

        vd_visit_id_is_identity = False
        if vd_visit_id_col:
            try:
                cursor.execute(
                    "SELECT c.is_identity FROM sys.columns c WHERE c.object_id = OBJECT_ID(?) AND c.name = ?",
                    ("dbo.Visit_Duplicate", vd_visit_id_col),
                )
                identity_row = cursor.fetchone()
                vd_visit_id_is_identity = bool(identity_row and int(identity_row[0]) == 1)
            except Exception:
                vd_visit_id_is_identity = False

        cursor.execute(
            f"SELECT ISNULL(MAX({vd_visit_id_col}), 0) + 1 AS NextVisitId FROM dbo.Visit_Duplicate WITH (UPDLOCK, HOLDLOCK)"
        )
        next_row = cursor.fetchone()
        next_visit_id = _coerce_int(getattr(next_row, "NextVisitId", None), allow_none=True) if next_row else None
        if not next_visit_id:
            next_visit_id = 1

        inserted_by = _resolve_account_id(username) or 0

        if dry_run:
            conn.rollback()
            return {"success": True, "visit_id": next_visit_id}

        insert_cols = [
            vd_visit_id_col,
            vd_patient_id_col,
            vd_visit_date_col,
            vd_discharge_date_col,
            vd_patient_subtype_col,
            vd_doc_col,
            vd_discharge_type_col,
            vd_visit_type_col,
        ]
        insert_vals_sql = ["?", "?", "?", "?", "?", "?", "?", "?"]
        insert_params = [
            next_visit_id,
            patient_id_val,
            visit_dt,
            discharge_dt,
            patient_sub_type_id_val,
            int(doc_id_val or 0),
            discharge_type_id_val,
            visit_type_id_val,
        ]
        if vd_visit_status_col:
            insert_cols.append(vd_visit_status_col)
            insert_vals_sql.append("?")
            insert_params.append(visit_status_val)
        if vd_inserted_by_col:
            insert_cols.append(vd_inserted_by_col)
            insert_vals_sql.append("?")
            insert_params.append(inserted_by)
        if vd_inserted_on_col:
            insert_cols.append(vd_inserted_on_col)
            insert_vals_sql.append("GETDATE()")
        if vd_cbill_col:
            insert_cols.append(vd_cbill_col)
            insert_vals_sql.append("NULL")

        identity_insert_enabled = False
        try:
            if vd_visit_id_is_identity:
                cursor.execute("SET IDENTITY_INSERT dbo.Visit_Duplicate ON")
                identity_insert_enabled = True
            cursor.execute(
                f"""
                INSERT INTO dbo.Visit_Duplicate ({", ".join(insert_cols)})
                VALUES ({", ".join(insert_vals_sql)})
                """,
                tuple(insert_params),
            )
        finally:
            if identity_insert_enabled:
                try:
                    cursor.execute("SET IDENTITY_INSERT dbo.Visit_Duplicate OFF")
                except Exception:
                    pass

        created_visit_id = next_visit_id
        if vd_visit_id_is_identity:
            try:
                cursor.execute(
                    f"""
                    SELECT TOP 1 {vd_visit_id_col} AS NewVisitId
                    FROM dbo.Visit_Duplicate WITH (NOLOCK)
                    WHERE {vd_visit_id_col} = ?
                    """,
                    (next_visit_id,),
                )
                id_row = cursor.fetchone()
                created_visit_id = _coerce_int(getattr(id_row, "NewVisitId", None), allow_none=True) if id_row else None
            except Exception:
                created_visit_id = None
            if not created_visit_id:
                try:
                    cursor.execute(f"SELECT MAX({vd_visit_id_col}) AS NewVisitId FROM dbo.Visit_Duplicate WITH (NOLOCK)")
                    id_row = cursor.fetchone()
                    created_visit_id = _coerce_int(getattr(id_row, "NewVisitId", None), allow_none=True) if id_row else None
                except Exception:
                    created_visit_id = None
        conn.commit()

        parts = [
            str(getattr(patient_row, "Title", "") or "").strip(),
            str(getattr(patient_row, "First_Name", "") or "").strip(),
            str(getattr(patient_row, "Middle_Name", "") or "").strip(),
            str(getattr(patient_row, "Last_Name", "") or "").strip(),
        ]
        patient_name = " ".join([p for p in parts if p]).strip()
        return {
            "success": True,
            "visit_id": created_visit_id or next_visit_id,
            "patient_id": patient_id_val,
            "reg_no": str(getattr(patient_row, "Registration_No", "") or "").strip(),
            "patient_name": patient_name,
        }
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return {"error": str(e)}
    finally:
        try:
            conn.close()
        except Exception:
            pass


