# ============================================================
# MIS: Doctor Medicine Sale & Issue
# ============================================================
DOC_MED_DETAIL_COLUMNS = [
    "Source",
    "Registration_No",
    "PatientName",
    "ItemName",
    "Quantity",
    "Rate",
    "MRP",
    "Tax",
    "Amount",
    "Group_Name",
    "Sub_Grp",
    "DoctorName",
]


def _build_doct_medicine_details_df(sale_df: pd.DataFrame, issue_df: pd.DataFrame) -> pd.DataFrame:
    def _pick(cols_map, candidates):
        for cand in candidates:
            key = cand.lower()
            if key in cols_map:
                return cols_map[key]
        return None

    def _build_from(df: pd.DataFrame, source: str, qty_keys):
        if df is None or df.empty:
            return pd.DataFrame(columns=DOC_MED_DETAIL_COLUMNS)

        df = _clean_df_columns(df)
        cols_map = {str(c).strip().lower(): c for c in df.columns}

        reg_col = _pick(cols_map, ["Registration_No", "RegistrationNo", "RegNo", "Reg_No"])
        patient_col = _pick(cols_map, ["PatientName", "Patient", "Patient_Name"])
        item_col = _pick(cols_map, ["ItemName", "Item_Name", "Item"])
        qty_col = _pick(cols_map, qty_keys)
        rate_col = _pick(cols_map, ["Rate"])
        mrp_col = _pick(cols_map, ["MRP", "Mrp"])
        tax_col = _pick(cols_map, ["Tax", "TaxRate"])
        group_col = _pick(cols_map, ["Group_Name", "Group", "GroupName"])
        sub_col = _pick(cols_map, ["Sub_Grp", "SubGroup", "SubGroupName"])
        doc_col = _pick(cols_map, ["DoctorIncharge", "DoctorInCharge", "DoctorName", "Doctor"])

        out = pd.DataFrame(index=df.index)
        out["Source"] = source
        out["Registration_No"] = df[reg_col] if reg_col else ""
        out["PatientName"] = df[patient_col] if patient_col else ""
        out["ItemName"] = df[item_col] if item_col else ""
        out["Quantity"] = df[qty_col] if qty_col else 0
        out["Rate"] = df[rate_col] if rate_col else 0
        out["MRP"] = df[mrp_col] if mrp_col else 0
        out["Tax"] = df[tax_col] if tax_col else 0
        out["Group_Name"] = df[group_col] if group_col else ""
        out["Sub_Grp"] = df[sub_col] if sub_col else ""
        out["DoctorName"] = df[doc_col] if doc_col else ""

        for col in ["Quantity", "Rate", "MRP", "Tax"]:
            out[col] = pd.to_numeric(out[col], errors="coerce").fillna(0.0).astype(float)

        out["Amount"] = (out["Quantity"] * out["MRP"]).fillna(0.0).astype(float)

        for col in ["Registration_No", "PatientName", "ItemName", "Group_Name", "Sub_Grp", "DoctorName", "Source"]:
            out[col] = out[col].astype(str).replace({"nan": "", "None": ""}).str.strip()

        return out[DOC_MED_DETAIL_COLUMNS]

    sale_details = _build_from(sale_df, "Sale", ["SlQty", "Qty", "Quantity", "SaleQty", "Sale_Qty"])
    issue_details = _build_from(issue_df, "Issue", ["Issueqty", "IssueQty", "Qty", "Quantity"])
    combined = pd.concat([sale_details, issue_details], ignore_index=True)
    return combined[DOC_MED_DETAIL_COLUMNS]


def _build_doct_medicine_summary_frames(details_df: pd.DataFrame):
    if details_df is None or details_df.empty:
        empty_summary = pd.DataFrame(columns=["Group_Name", "Quantity", "Revenue", "Records"])
        empty_totals = {"sale_qty": 0.0, "sale_revenue": 0.0, "issue_qty": 0.0, "issue_revenue": 0.0}
        return empty_summary, 0.0, 0.0, 0, empty_totals

    work = details_df.copy()
    work["Group_Name"] = work["Group_Name"].replace("", "Unknown").fillna("Unknown")

    total_quantity = float(work["Quantity"].sum())
    total_revenue = float(work["Amount"].sum())
    total_records = int(len(work))
    source_key = work["Source"].astype(str).str.strip().str.lower()
    sale_mask = source_key == "sale"
    issue_mask = source_key == "issue"
    totals = {
        "sale_qty": float(work.loc[sale_mask, "Quantity"].sum()),
        "sale_revenue": float(work.loc[sale_mask, "Amount"].sum()),
        "issue_qty": float(work.loc[issue_mask, "Quantity"].sum()),
        "issue_revenue": float(work.loc[issue_mask, "Amount"].sum()),
    }

    summary = (
        work.groupby("Group_Name", dropna=False)
        .agg(Quantity=("Quantity", "sum"), Revenue=("Amount", "sum"), Records=("Group_Name", "size"))
        .reset_index()
        .sort_values("Revenue", ascending=False)
    )

    return summary, total_quantity, total_revenue, total_records, totals


def _doct_medicine_doctor_label(details_df: pd.DataFrame) -> str:
    if details_df is None or details_df.empty or "DoctorName" not in details_df.columns:
        return ""
    names = details_df["DoctorName"].astype(str).str.strip()
    names = [n for n in names.unique() if n]
    if not names:
        return ""
    if len(names) == 1:
        return names[0]
    return "Multiple"


@app.route('/api/mis/doctor_medicine')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_doctor_medicine():
    unit = (request.args.get("unit") or "").strip().upper()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    doc_id_raw = (
        request.args.get("doc_id")
        or request.args.get("docid")
        or request.args.get("doctor_id")
        or request.args.get("doc")
    )

    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return jsonify({"status": "error", "message": "No unit available"}), 400
    if allowed_units and target_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403
    if not doc_id_raw:
        return jsonify({"status": "error", "message": "Doctor ID is required"}), 400
    try:
        doc_id = int(str(doc_id_raw).strip())
    except Exception:
        return jsonify({"status": "error", "message": "Invalid doctor ID"}), 400

    sale_df, issue_df = data_fetch.fetch_doct_medicine_sale_issue(target_unit, from_date, to_date, doc_id)
    if sale_df is None and issue_df is None:
        return jsonify({"status": "error", "message": "Database error"}), 500

    details_df = _build_doct_medicine_details_df(sale_df, issue_df)
    summary_df, total_quantity, total_revenue, total_records, totals = _build_doct_medicine_summary_frames(details_df)

    details_records = details_df.where(pd.notna(details_df), None).to_dict(orient="records")
    summary_records = summary_df.to_dict(orient="records")
    doctor_label = _doct_medicine_doctor_label(details_df)

    return jsonify({
        "status": "success",
        "unit": target_unit,
        "from_date": from_date,
        "to_date": to_date,
        "doc_id": doc_id,
        "doctor_name": doctor_label,
        "total_quantity": total_quantity,
        "total_revenue": total_revenue,
        "total_records": total_records,
        "sale_total_quantity": totals.get("sale_qty", 0.0),
        "sale_total_revenue": totals.get("sale_revenue", 0.0),
        "issue_total_quantity": totals.get("issue_qty", 0.0),
        "issue_total_revenue": totals.get("issue_revenue", 0.0),
        "group_summary": summary_records,
        "details": details_records,
    })


def _build_doct_medicine_excel(unit: str, from_date: str, to_date: str, doc_id: int, exported_by: str):
    sale_df, issue_df = data_fetch.fetch_doct_medicine_sale_issue(unit, from_date, to_date, doc_id)
    if sale_df is None and issue_df is None:
        return None, None, "No data available to export"

    details_df = _build_doct_medicine_details_df(sale_df, issue_df)
    if details_df.empty:
        return None, None, "No data available to export"

    summary_df, total_quantity, total_revenue, total_records, totals = _build_doct_medicine_summary_frames(details_df)
    doctor_label = _doct_medicine_doctor_label(details_df) or "Unknown"

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
        workbook = writer.book

        title_fmt = workbook.add_format({
            "bold": True,
            "font_size": 14,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#1e3a8a",
            "font_color": "white",
        })
        subtitle_fmt = workbook.add_format({
            "bold": True,
            "font_size": 10,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#e2e8f0",
        })
        meta_fmt = workbook.add_format({
            "font_size": 9,
            "align": "center",
            "valign": "vcenter",
            "font_color": "#475569",
        })
        section_fmt = workbook.add_format({
            "bold": True,
            "font_size": 10,
            "align": "left",
            "valign": "vcenter",
            "bg_color": "#f1f5f9",
        })
        header_fmt = workbook.add_format({
            "bold": True,
            "font_size": 9,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#1e3a8a",
            "font_color": "white",
            "border": 1,
        })
        text_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "left"})
        int_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "#,##,##0"})
        qty_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "#,##,##0.00"})
        money_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "#,##,##0.00"})
        pct_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "0.00%"})
        text_col_fmt = workbook.add_format({"font_size": 9, "align": "left"})
        qty_col_fmt = workbook.add_format({"font_size": 9, "align": "right", "num_format": "#,##,##0.00"})
        money_col_fmt = workbook.add_format({"font_size": 9, "align": "right", "num_format": "#,##,##0.00"})
        border_only_fmt = workbook.add_format({"border": 1})

        exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
        unit_header = _lab_unit_header_text(unit)

        summary_ws = workbook.add_worksheet("Summary")
        writer.sheets["Summary"] = summary_ws

        summary_last_col = 3
        summary_ws.merge_range(0, 0, 0, summary_last_col, "Doctor Medicine Sale & Issue - Summary", title_fmt)
        summary_ws.merge_range(1, 0, 1, summary_last_col, f"Unit: {unit_header}", subtitle_fmt)
        summary_ws.merge_range(2, 0, 2, summary_last_col, f"Doctor: {doctor_label} | Doc ID: {doc_id}", subtitle_fmt)
        summary_ws.merge_range(3, 0, 3, summary_last_col, f"Date Range: {from_date} to {to_date}", subtitle_fmt)
        summary_ws.merge_range(4, 0, 4, summary_last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)

        summary_ws.write(6, 0, "Total Records", section_fmt)
        summary_ws.write(6, 1, total_records, int_fmt)
        summary_ws.write(7, 0, "Total Quantity", section_fmt)
        summary_ws.write(7, 1, total_quantity, qty_fmt)
        summary_ws.write(8, 0, "Total Revenue (INR)", section_fmt)
        summary_ws.write(8, 1, total_revenue, money_fmt)
        summary_ws.write(9, 0, "Total Sale Qty", section_fmt)
        summary_ws.write(9, 1, totals.get("sale_qty", 0.0), qty_fmt)
        summary_ws.write(10, 0, "Total Sale Revenue (INR)", section_fmt)
        summary_ws.write(10, 1, totals.get("sale_revenue", 0.0), money_fmt)
        summary_ws.write(11, 0, "Total Issue Qty", section_fmt)
        summary_ws.write(11, 1, totals.get("issue_qty", 0.0), qty_fmt)
        summary_ws.write(12, 0, "Total Issue Revenue (INR)", section_fmt)
        summary_ws.write(12, 1, totals.get("issue_revenue", 0.0), money_fmt)

        row_ptr = 14
        summary_ws.merge_range(row_ptr, 0, row_ptr, summary_last_col, "Group-wise Summary", section_fmt)
        row_ptr += 1
        summary_ws.write_row(row_ptr, 0, ["Group", "Quantity", "Revenue (INR)", "Share %"], header_fmt)
        row_ptr += 1
        for _, row in summary_df.iterrows():
            share = (float(row["Revenue"]) / total_revenue) if total_revenue else 0.0
            summary_ws.write(row_ptr, 0, row["Group_Name"], text_fmt)
            summary_ws.write(row_ptr, 1, float(row["Quantity"]), qty_fmt)
            summary_ws.write(row_ptr, 2, float(row["Revenue"]), money_fmt)
            summary_ws.write(row_ptr, 3, share, pct_fmt)
            row_ptr += 1

        summary_ws.merge_range(row_ptr + 1, 0, row_ptr + 1, summary_last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)
        summary_ws.set_column(0, 0, 34)
        summary_ws.set_column(1, 1, 14)
        summary_ws.set_column(2, 2, 18)
        summary_ws.set_column(3, 3, 12)
        summary_ws.freeze_panes(6, 0)

        details_df.to_excel(writer, sheet_name="Details", index=False, startrow=5)
        details_ws = writer.sheets["Details"]
        details_last_col = len(details_df.columns) - 1
        details_ws.merge_range(0, 0, 0, details_last_col, "Doctor Medicine Sale & Issue - Detail Report", title_fmt)
        details_ws.merge_range(1, 0, 1, details_last_col, f"Unit: {unit_header} | Doctor: {doctor_label} | Doc ID: {doc_id}", subtitle_fmt)
        details_ws.merge_range(2, 0, 2, details_last_col, f"Date Range: {from_date} to {to_date}", subtitle_fmt)
        details_ws.merge_range(3, 0, 3, details_last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)

        for col_num, col_name in enumerate(details_df.columns):
            details_ws.write(5, col_num, col_name, header_fmt)
            width = 16
            fmt = text_col_fmt
            if col_name in {"Quantity"}:
                width = 10
                fmt = qty_col_fmt
            elif col_name in {"Rate", "MRP", "Tax", "Amount"}:
                width = 14
                fmt = money_col_fmt
            elif col_name in {"PatientName", "ItemName"}:
                width = 26
            elif col_name in {"Group_Name", "Sub_Grp"}:
                width = 20
            details_ws.set_column(col_num, col_num, width, fmt)

        data_start_row = 6
        data_end_row = 5 + len(details_df)
        if len(details_df) > 0:
            from xlsxwriter.utility import xl_col_to_name
            top_row = data_start_row + 1
            last_col_letter = xl_col_to_name(details_last_col)
            criteria = f"=COUNTA($A{top_row}:${last_col_letter}{top_row})>0"
            details_ws.conditional_format(
                data_start_row, 0, data_end_row, details_last_col,
                {"type": "formula", "criteria": criteria, "format": border_only_fmt}
            )

        footer_row = 6 + len(details_df)
        details_ws.merge_range(footer_row, 0, footer_row, details_last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)
        details_ws.freeze_panes(6, 0)

    output.seek(0)
    filename = f"Doctor_Medicine_{unit}_{from_date}_to_{to_date}.xlsx"
    return output.getvalue(), filename, None


def _run_doct_medicine_excel_job(job_id: str, unit: str, from_date: str, to_date: str, doc_id: int, exported_by: str):
    _excel_job_update(job_id, state="running")
    try:
        data, filename, err = _build_doct_medicine_excel(unit, from_date, to_date, doc_id, exported_by)
        if not data:
            _excel_job_update(job_id, state="error", error=err or "No data available to export")
            return
        _export_cache_put_bytes("doctor_medicine_xlsx_job", data, job_id)
        _excel_job_update(job_id, state="done", filename=filename)
    except Exception as exc:
        _excel_job_update(job_id, state="error", error=str(exc))


