def _build_dpv_pdf_buffer(unit: str, from_date: str, to_date: str, doc_id: int, exported_by: str):
    from reportlab.lib.pagesizes import A4, landscape
    from reportlab.lib import colors
    from reportlab.lib.units import mm
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer, PageBreak, Image
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_RIGHT
    from xml.sax.saxutils import escape

    df_raw = data_fetch.fetch_doctorwise_dpv_procedures(unit, from_date, to_date, doc_id)
    if df_raw is None or df_raw.empty:
        return None

    doctor_label = _resolve_doctor_name(unit, doc_id) or "Unknown"
    details_df = _build_dpv_details_df(df_raw, doctor_label)
    summary_df, total_quantity, total_revenue, total_records = _build_dpv_summary_frames(details_df)

    def _format_inr(number) -> str:
        try:
            n = float(number)
        except Exception:
            return "0.00"
        sign = "-" if n < 0 else ""
        n = abs(n)
        s = f"{n:.2f}"
        whole, frac = s.split(".")
        if len(whole) <= 3:
            grouped = whole
        else:
            last = whole[-3:]
            rest = whole[:-3]
            parts = []
            while rest:
                parts.append(rest[-2:])
                rest = rest[:-2]
            grouped = ",".join(reversed(parts)) + "," + last
        return f"{sign}{grouped}.{frac}"

    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=landscape(A4),
        topMargin=14 * mm,
        bottomMargin=14 * mm,
        leftMargin=12 * mm,
        rightMargin=12 * mm,
    )

    styles = getSampleStyleSheet()
    style_title = ParagraphStyle("RptTitle", parent=styles["Heading2"], fontSize=12, alignment=TA_CENTER, textColor=colors.HexColor("#1e3a8a"))
    style_sub = ParagraphStyle("RptSub", parent=styles["Normal"], fontSize=9, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_meta = ParagraphStyle("RptMeta", parent=styles["Normal"], fontSize=8, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_th = ParagraphStyle("RptTh", parent=styles["Normal"], fontSize=8, textColor=colors.white, alignment=TA_CENTER)
    style_td = ParagraphStyle("RptTd", parent=styles["Normal"], fontSize=6.5, textColor=colors.black, leading=8)
    style_td_wrap = ParagraphStyle(
        "RptTdWrap",
        parent=styles["Normal"],
        fontSize=6.5,
        textColor=colors.black,
        leading=8,
        wordWrap="CJK",
    )
    style_td_right = ParagraphStyle("RptTdRight", parent=styles["Normal"], fontSize=6.5, textColor=colors.black, alignment=TA_RIGHT, leading=8)

    elements = []
    logo_path = os.path.join(app.root_path, "static", "logo", "asarfi.png")
    if os.path.exists(logo_path):
        logo = Image(logo_path, width=18 * mm, height=18 * mm, mask="auto")
        logo.hAlign = "CENTER"
        elements.append(logo)

    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    unit_header = _lab_unit_header_text(unit)
    elements.append(Spacer(1, 6))
    elements.append(Paragraph("Doctorwise DPV Procedures - Summary", style_title))
    elements.append(Paragraph(f"Unit: {unit_header}", style_sub))
    elements.append(Paragraph(f"Doctor: {doctor_label} | Doc ID: {doc_id}", style_sub))
    elements.append(Paragraph(f"Date Range: {from_date} to {to_date}", style_sub))
    elements.append(Paragraph(f"Exported By: {exported_by} | Exported At: {exported_at}", style_meta))
    elements.append(Spacer(1, 8))

    summary_rows = [
        [Paragraph("Metric", style_th), Paragraph("Value", style_th)],
        [Paragraph("Total Records", style_td), Paragraph(f"{total_records:,}", style_td_right)],
        [Paragraph("Total Quantity", style_td), Paragraph(f"{total_quantity:,.2f}", style_td_right)],
        [Paragraph("Total Revenue (INR)", style_td), Paragraph(_format_inr(total_revenue), style_td_right)],
    ]
    summary_table = Table(summary_rows, colWidths=[70 * mm, 40 * mm])
    summary_table.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("GRID", (0, 0), (-1, -1), 0.4, colors.HexColor("#1f2937")),
        ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
    ]))
    elements.append(summary_table)
    elements.append(Spacer(1, 10))

    service_rows = [[Paragraph("Service", style_th), Paragraph("Quantity", style_th), Paragraph("Revenue (INR)", style_th)]]
    for _, row in summary_df.iterrows():
        service_rows.append([
            Paragraph(escape(str(row["Service_Name"] or "")), style_td_wrap),
            Paragraph(f"{float(row['Quantity']):,.2f}", style_td_right),
            Paragraph(_format_inr(row["Revenue"]), style_td_right),
        ])
    service_table = Table(service_rows, colWidths=[90 * mm, 25 * mm, 35 * mm], repeatRows=1)
    service_table.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("GRID", (0, 0), (-1, -1), 0.4, colors.HexColor("#1f2937")),
        ("VALIGN", (0, 0), (-1, -1), "TOP"),
    ]))
    elements.append(service_table)
    elements.append(PageBreak())

    detail_headers = [
        Paragraph("Reg No", style_th),
        Paragraph("Patient", style_th),
        Paragraph("Patient Type", style_th),
        Paragraph("Visit Date", style_th),
        Paragraph("Service", style_th),
        Paragraph("Qty", style_th),
        Paragraph("Rate", style_th),
        Paragraph("Amount", style_th),
        Paragraph("Discount", style_th),
        Paragraph("Bill No", style_th),
        Paragraph("Doctor", style_th),
    ]
    detail_rows = [detail_headers]
    for _, row in details_df.iterrows():
        detail_rows.append([
            Paragraph(escape(str(row.get("Registration_No") or "")), style_td),
            Paragraph(escape(str(row.get("Patient") or "")), style_td_wrap),
            Paragraph(escape(str(row.get("PatientType") or "")), style_td_wrap),
            Paragraph(escape(str(row.get("VisitDate") or "")), style_td),
            Paragraph(escape(str(row.get("Service_Name") or "")), style_td_wrap),
            Paragraph(f"{float(row.get('Quantity') or 0):,.2f}", style_td_right),
            Paragraph(_format_inr(row.get("Rate") or 0), style_td_right),
            Paragraph(_format_inr(row.get("Amount") or 0), style_td_right),
            Paragraph(_format_inr(row.get("DiscountAmount") or 0), style_td_right),
            Paragraph(escape(str(row.get("BillNo") or "")), style_td),
            Paragraph(escape(str(row.get("DoctorName") or "")), style_td_wrap),
        ])

    detail_tbl = Table(
        detail_rows,
        colWidths=[18 * mm, 28 * mm, 26 * mm, 16 * mm, 40 * mm, 12 * mm, 16 * mm, 18 * mm, 18 * mm, 18 * mm, 24 * mm],
        repeatRows=1,
    )
    detail_tbl.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("FONTSIZE", (0, 0), (-1, -1), 6.5),
        ("GRID", (0, 0), (-1, -1), 0.4, colors.HexColor("#1f2937")),
        ("VALIGN", (0, 0), (-1, -1), "TOP"),
        ("ALIGN", (-6, 1), (-1, -1), "RIGHT"),
    ]))
    elements.append(detail_tbl)

    def _draw_page_number(canvas, doc_obj):
        canvas.saveState()
        width, _ = doc.pagesize
        canvas.setFont("Helvetica", 8)
        canvas.setFillColor(colors.HexColor("#64748b"))
        canvas.drawRightString(width - 12 * mm, 10 * mm, f"Page {doc_obj.page}")
        canvas.drawString(12 * mm, 10 * mm, "Copyright (c) ASARFI HOSPITAL")
        canvas.restoreState()

    doc.build(elements, onFirstPage=_draw_page_number, onLaterPages=_draw_page_number)
    buffer.seek(0)
    return buffer


