# ============================================================
# MIS: Blood Bank Service-wise Billing
# ============================================================
BLOODBANK_BILLING_DETAIL_COLUMNS = [
    "RecordSource",
    "OrderStatus",
    "PendingToBilling",
    "IsOrderCancelled",
    "BillDate",
    "OrderDateTime",
    "ShiftedToBillingDate",
    "VisitDate",
    "DischargeDate",
    "RegNo",
    "Patient",
    "Service_Name",
    "Rate",
    "Quantity",
    "Amount",
    "Sub_Dept",
    "Category_Id",
    "TypeOfVisit",
    "OrderNo",
    "OrderId",
    "OrderDetailId",
    "ServBilled",
    "ServBillId",
    "OrderCreatedBy",
    "OrderCancelledBy",
    "OrderCancelledAt",
    "ShiftHistory",
]


def _build_bloodbank_billing_details_df(df_raw: pd.DataFrame) -> pd.DataFrame:
    if df_raw is None or df_raw.empty:
        return pd.DataFrame(columns=BLOODBANK_BILLING_DETAIL_COLUMNS)

    df_raw = _clean_df_columns(df_raw)
    cols_map = {str(c).strip().lower(): c for c in df_raw.columns}

    def _pick(candidates):
        for cand in candidates:
            key = cand.lower()
            if key in cols_map:
                return cols_map[key]
        return None

    col_map = {
        "RecordSource": _pick(["RecordSource", "Source"]),
        "OrderStatus": _pick(["OrderStatus", "Status"]),
        "PendingToBilling": _pick(["PendingToBillingFlag", "PendingToBilling", "PendingFlag"]),
        "IsOrderCancelled": _pick(["IsOrderCancelled", "OrderCancelled", "Cancelled"]),
        "BillDate": _pick(["BillDate", "Bill_Date", "Billdate", "Date"]),
        "OrderDateTime": _pick(["OrderDateTime", "OrderDate", "OrdDateTime"]),
        "ShiftedToBillingDate": _pick(["ShiftedToBillingDate", "ShiftedDate", "BillingShiftDate"]),
        "VisitDate": _pick(["VisitDate", "Visit_Date", "Visitdate"]),
        "DischargeDate": _pick(["DischargeDate", "Discharge_Date", "Dischargedate"]),
        "RegNo": _pick(["RegNo", "Registration_No", "RegistrationNo", "Reg_No", "UHID"]),
        "Patient": _pick(["Patient", "PatientName", "Patient_Name"]),
        "Service_Name": _pick(["Service_Name", "ServiceName", "Service", "Service Name"]),
        "Rate": _pick(["Rate", "ServiceAmount"]),
        "Quantity": _pick(["Quantity", "Qty", "QTY", "OrdQty"]),
        "Amount": _pick(["Amount", "NetAmount", "TotalAmount"]),
        "Sub_Dept": _pick(["Sub_Dept", "SubDept", "Sub_Department"]),
        "Category_Id": _pick(["Category_Id", "CategoryId", "Category"]),
        "TypeOfVisit": _pick(["TypeOfVisit", "Type Of Visit", "VisitType", "Visit Type"]),
        "OrderNo": _pick(["OrderNo", "OrdNo"]),
        "OrderId": _pick(["OrderId", "OrdId"]),
        "OrderDetailId": _pick(["OrderDetailId", "OrdDtlID", "OrderDtlId"]),
        "ServBilled": _pick(["ServBilled"]),
        "ServBillId": _pick(["ServBillId", "ServiceBillId"]),
        "OrderCreatedBy": _pick(["OrderCreatedBy", "CreatedBy", "InsertedBy"]),
        "OrderCancelledBy": _pick(["OrderCancelledBy", "CancelledBy"]),
        "OrderCancelledAt": _pick(["OrderCancelledAt", "CancelDateTime", "CancelledAt"]),
        "ShiftHistory": _pick(["ShiftHistory", "History", "ShiftTrail"]),
    }

    details = pd.DataFrame()
    for col in BLOODBANK_BILLING_DETAIL_COLUMNS:
        source = col_map.get(col)
        if source and source in df_raw.columns:
            details[col] = df_raw[source]
        else:
            details[col] = pd.Series([None] * len(df_raw))

    for date_col in ["BillDate", "OrderDateTime", "ShiftedToBillingDate", "VisitDate", "DischargeDate", "OrderCancelledAt"]:
        date_series = pd.to_datetime(details[date_col], errors="coerce")
        fmt = "%Y-%m-%d %H:%M" if date_col in {"OrderDateTime", "ShiftedToBillingDate", "OrderCancelledAt"} else "%Y-%m-%d"
        details[date_col] = date_series.dt.strftime(fmt).fillna("")

    details["Rate"] = pd.to_numeric(details["Rate"], errors="coerce").fillna(0.0).astype(float)
    details["Quantity"] = pd.to_numeric(details["Quantity"], errors="coerce").fillna(0.0).astype(float)
    amt_num = pd.to_numeric(details["Amount"], errors="coerce")
    calc_amount = (details["Rate"] * details["Quantity"]).astype(float)
    details["Amount"] = amt_num.fillna(calc_amount).astype(float)

    # Keep Amount consistent with displayed Qty and Rate in this reconciliation view.
    mismatch_mask = (
        details["Quantity"].gt(0)
        & details["Rate"].gt(0)
        & details["Amount"].sub(calc_amount).abs().gt(0.01)
    )
    details.loc[mismatch_mask, "Amount"] = calc_amount[mismatch_mask]

    details["OrderId"] = pd.to_numeric(details["OrderId"], errors="coerce").fillna(0).astype(int)
    details["OrderDetailId"] = pd.to_numeric(details["OrderDetailId"], errors="coerce").fillna(0).astype(int)
    details["ServBilled"] = pd.to_numeric(details["ServBilled"], errors="coerce").fillna(0).astype(int)
    details["ServBillId"] = pd.to_numeric(details["ServBillId"], errors="coerce").fillna(0).astype(int)
    details["PendingToBilling"] = pd.to_numeric(details["PendingToBilling"], errors="coerce").fillna(0).astype(int)
    details["IsOrderCancelled"] = pd.to_numeric(details["IsOrderCancelled"], errors="coerce").fillna(0).astype(int)

    # Backfill pending/cancel flags if source did not provide explicit flags.
    status_series = details["OrderStatus"].astype(str).str.lower()
    missing_pending = details["PendingToBilling"].isna() | details["PendingToBilling"].eq(0)
    details.loc[
        missing_pending
        & details["RecordSource"].astype(str).str.upper().eq("ORDER")
        & details["ServBilled"].eq(0)
        & details["ServBillId"].eq(0)
        & ~status_series.str.contains("cancel"),
        "PendingToBilling",
    ] = 1
    details.loc[
        details["RecordSource"].astype(str).str.upper().eq("ORDER")
        & status_series.str.contains("cancel"),
        "IsOrderCancelled",
    ] = 1

    for col in ["Category_Id"]:
        details[col] = pd.to_numeric(details[col], errors="coerce").fillna(0).astype(int)

    for col in [
        "RecordSource",
        "OrderStatus",
        "RegNo",
        "Patient",
        "Service_Name",
        "Sub_Dept",
        "TypeOfVisit",
        "OrderNo",
        "OrderCreatedBy",
        "OrderCancelledBy",
        "ShiftHistory",
    ]:
        details[col] = details[col].astype(str).replace({"nan": "", "None": ""}).str.strip()

    details.loc[details["RecordSource"] == "", "RecordSource"] = "BILLING"
    details["RecordSource"] = details["RecordSource"].str.upper()

    details.loc[
        details["OrderStatus"] == "",
        "OrderStatus",
    ] = np.where(
        details["IsOrderCancelled"].eq(1),
        "Cancelled",
        np.where(
            details["PendingToBilling"].eq(1),
            "Pending Billing",
            np.where(details["RecordSource"].eq("ORDER"), "Shifted to Billing", "Billed"),
        ),
    )

    # Normalize status flags so color/status KPIs stay consistent even with upstream inconsistencies.
    status_norm = details["OrderStatus"].astype(str).str.lower()
    cancel_mask = status_norm.str.contains("cancel")
    pending_mask = status_norm.str.contains("pending")
    shift_mask = status_norm.str.contains("shift")
    shifted_evidence_mask = details["RecordSource"].eq("ORDER") & (
        details["ServBilled"].eq(1)
        | details["ServBillId"].gt(0)
        | details["ShiftedToBillingDate"].astype(str).str.strip().ne("")
    )

    details.loc[cancel_mask, "IsOrderCancelled"] = 1
    details.loc[cancel_mask, "PendingToBilling"] = 0
    details.loc[pending_mask & ~cancel_mask, "PendingToBilling"] = 1
    details.loc[shift_mask | shifted_evidence_mask, "PendingToBilling"] = 0
    details.loc[
        shifted_evidence_mask & ~cancel_mask & pending_mask,
        "OrderStatus",
    ] = "Shifted to Billing"

    # Keep textual "not available" clean for billing-only rows.
    details.loc[details["OrderStatus"].eq("Billed"), "PendingToBilling"] = 0

    # Add default shift history where not supplied.
    empty_hist = details["ShiftHistory"].eq("")
    details.loc[
        empty_hist & details["IsOrderCancelled"].eq(1),
        "ShiftHistory",
    ] = "Order was cancelled."
    details.loc[
        empty_hist & details["PendingToBilling"].eq(1),
        "ShiftHistory",
    ] = "Pending to shift into billing."
    details.loc[
        empty_hist
        & details["RecordSource"].eq("ORDER")
        & details["PendingToBilling"].eq(0)
        & details["ShiftedToBillingDate"].ne(""),
        "ShiftHistory",
    ] = details["ShiftedToBillingDate"].map(lambda v: f"Shifted to billing on {v}" if v else "")

    return details[BLOODBANK_BILLING_DETAIL_COLUMNS]


def _build_bloodbank_billing_summary_frames(details_df: pd.DataFrame):
    if details_df is None or details_df.empty:
        empty_summary = pd.DataFrame(columns=["Service_Name", "Quantity", "Revenue", "Records"])
        return empty_summary, 0.0, 0.0, 0

    work = details_df.copy()
    work["Service_Name"] = work["Service_Name"].replace("", "Unknown").fillna("Unknown")
    work["Amount"] = pd.to_numeric(work["Amount"], errors="coerce").fillna(0.0)

    status = work["OrderStatus"].astype(str).str.lower()
    cancelled_mask = (
        pd.to_numeric(work["IsOrderCancelled"], errors="coerce").fillna(0).astype(int).eq(1)
        | status.str.contains("cancel")
    )
    rev_work = work.loc[~cancelled_mask].copy()

    total_quantity = float(work["Quantity"].sum())
    total_revenue = float(rev_work["Amount"].sum())
    total_records = int(len(work))

    summary_qty = (
        work.groupby("Service_Name", dropna=False)
        .agg(Quantity=("Quantity", "sum"), Records=("Service_Name", "size"))
        .reset_index()
    )
    summary_rev = (
        rev_work.groupby("Service_Name", dropna=False)
        .agg(Revenue=("Amount", "sum"))
        .reset_index()
    )
    summary = (
        summary_qty.merge(summary_rev, on="Service_Name", how="left")
        .fillna({"Revenue": 0.0})
        .sort_values("Revenue", ascending=False)
    )

    return summary, total_quantity, total_revenue, total_records


def _build_bloodbank_billing_status_totals(details_df: pd.DataFrame) -> dict:
    if details_df is None or details_df.empty:
        return {
            "pending_count": 0,
            "shifted_count": 0,
            "cancelled_count": 0,
            "billing_only_count": 0,
            "order_count": 0,
            "pending_amount": 0.0,
            "shifted_amount": 0.0,
            "cancelled_amount": 0.0,
        }

    work = details_df.copy()
    source = work["RecordSource"].astype(str).str.upper()
    status = work["OrderStatus"].astype(str).str.lower()
    pending_mask = pd.to_numeric(work["PendingToBilling"], errors="coerce").fillna(0).astype(int).eq(1)
    cancelled_mask = (
        pd.to_numeric(work["IsOrderCancelled"], errors="coerce").fillna(0).astype(int).eq(1)
        | status.str.contains("cancel")
    )
    shifted_mask = (
        source.eq("ORDER")
        & ~pending_mask
        & ~cancelled_mask
    )
    billing_only_mask = source.eq("BILLING")

    amount = pd.to_numeric(work.get("Amount"), errors="coerce").fillna(0.0)
    return {
        "pending_count": int(pending_mask.sum()),
        "shifted_count": int(shifted_mask.sum()),
        "cancelled_count": int(cancelled_mask.sum()),
        "billing_only_count": int(billing_only_mask.sum()),
        "order_count": int(source.eq("ORDER").sum()),
        "pending_amount": float(amount[pending_mask].sum()),
        "shifted_amount": float(amount[shifted_mask].sum()),
        "cancelled_amount": float(amount[cancelled_mask].sum()),
    }


def _apply_bloodbank_details_filter(details_df: pd.DataFrame, search_text: str = "", open_only: bool = False) -> pd.DataFrame:
    if details_df is None or details_df.empty:
        return details_df

    work = details_df.copy()
    status = work["OrderStatus"].astype(str).str.lower()
    pending_mask = (
        pd.to_numeric(work["PendingToBilling"], errors="coerce").fillna(0).astype(int).eq(1)
        | status.str.contains("pending")
    )
    cancelled_mask = (
        pd.to_numeric(work["IsOrderCancelled"], errors="coerce").fillna(0).astype(int).eq(1)
        | status.str.contains("cancel")
    )

    if open_only:
        work = work.loc[pending_mask | cancelled_mask].copy()
        if work.empty:
            return work

    q = (search_text or "").strip().lower()
    if not q:
        return work.reset_index(drop=True)

    search_cols = [
        "RecordSource",
        "OrderStatus",
        "PendingToBilling",
        "IsOrderCancelled",
        "BillDate",
        "OrderDateTime",
        "ShiftedToBillingDate",
        "RegNo",
        "Patient",
        "Service_Name",
        "Sub_Dept",
        "Category_Id",
        "Rate",
        "Quantity",
        "Amount",
        "TypeOfVisit",
        "VisitDate",
        "DischargeDate",
        "OrderNo",
        "OrderId",
        "OrderDetailId",
        "ServBilled",
        "ServBillId",
        "OrderCreatedBy",
        "OrderCancelledBy",
        "OrderCancelledAt",
        "ShiftHistory",
        "TrackingPendingSince",
        "TrackingShiftedAt",
        "TrackingStatus",
    ]
    existing_cols = [c for c in search_cols if c in work.columns]
    if not existing_cols:
        return work.iloc[0:0].copy()

    search_blob = (
        work[existing_cols]
        .fillna("")
        .astype(str)
        .agg(" ".join, axis=1)
        .str.lower()
    )
    matched = search_blob.str.contains(re.escape(q), regex=True, na=False)
    return work.loc[matched].reset_index(drop=True)


def _ensure_bloodbank_order_tracking_table():
    _ensure_local_store()

    def _setup(conn):
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS bloodbank_order_tracking (
                unit TEXT NOT NULL,
                order_detail_id INTEGER NOT NULL,
                order_id INTEGER NULL,
                order_no TEXT NULL,
                first_seen_order_at TEXT NULL,
                first_seen_pending_at TEXT NULL,
                last_seen_pending_at TEXT NULL,
                shifted_at TEXT NULL,
                shifted_bill_id TEXT NULL,
                last_status TEXT NULL,
                updated_at TEXT NOT NULL,
                PRIMARY KEY (unit, order_detail_id)
            )
            """
        )
        conn.execute(
            "CREATE INDEX IF NOT EXISTS idx_bb_track_unit_status ON bloodbank_order_tracking(unit, last_status)"
        )

    _with_local_db(_setup)


def _sync_bloodbank_order_tracking(unit: str, details_df: pd.DataFrame):
    if details_df is None or details_df.empty:
        return details_df, {"tracked_rows": 0, "upserts": 0}

    _ensure_bloodbank_order_tracking_table()
    unit_norm = (unit or "").strip().upper()
    now_ts = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")

    work = details_df.copy()
    if "TrackingPendingSince" not in work.columns:
        work["TrackingPendingSince"] = ""
    if "TrackingShiftedAt" not in work.columns:
        work["TrackingShiftedAt"] = ""
    if "TrackingStatus" not in work.columns:
        work["TrackingStatus"] = ""

    if "OrderDetailId" not in work.columns:
        return work, {"tracked_rows": 0, "upserts": 0}

    order_ids = pd.to_numeric(work["OrderDetailId"], errors="coerce").fillna(0).astype(int)
    is_order_row = work["RecordSource"].astype(str).str.upper().eq("ORDER")
    tracked_idx = work.index[is_order_row & order_ids.gt(0)].tolist()
    if not tracked_idx:
        return work, {"tracked_rows": 0, "upserts": 0}

    upserts = 0
    with sqlite3.connect(_abs_local_db_path()) as conn:
        for idx in tracked_idx:
            row = work.loc[idx]
            order_detail_id = int(pd.to_numeric(row.get("OrderDetailId"), errors="coerce") or 0)
            if order_detail_id <= 0:
                continue
            order_id = int(pd.to_numeric(row.get("OrderId"), errors="coerce") or 0)
            order_no = str(row.get("OrderNo") or "").strip()
            order_dt = str(row.get("OrderDateTime") or "").strip()
            pending_flag = int(pd.to_numeric(row.get("PendingToBilling"), errors="coerce") or 0)
            shifted_at = str(row.get("ShiftedToBillingDate") or "").strip()
            shifted_bill_num = int(pd.to_numeric(row.get("ServBillId"), errors="coerce") or 0)
            shifted_bill_id = str(shifted_bill_num) if shifted_bill_num > 0 else ""
            status = str(row.get("OrderStatus") or "").strip()

            existing = conn.execute(
                """
                SELECT first_seen_order_at, first_seen_pending_at, last_seen_pending_at, shifted_at, shifted_bill_id
                FROM bloodbank_order_tracking
                WHERE unit = ? AND order_detail_id = ?
                """,
                (unit_norm, order_detail_id),
            ).fetchone()

            if not existing:
                conn.execute(
                    """
                    INSERT INTO bloodbank_order_tracking
                    (unit, order_detail_id, order_id, order_no, first_seen_order_at, first_seen_pending_at,
                     last_seen_pending_at, shifted_at, shifted_bill_id, last_status, updated_at)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                    """,
                    (
                        unit_norm,
                        order_detail_id,
                        order_id if order_id > 0 else None,
                        order_no or None,
                        order_dt or now_ts,
                        now_ts if pending_flag == 1 else None,
                        now_ts if pending_flag == 1 else None,
                        shifted_at or None,
                        shifted_bill_id or None,
                        status or None,
                        now_ts,
                    ),
                )
                upserts += 1
                continue

            ex_first_order, ex_first_pending, ex_last_pending, ex_shifted_at, ex_shifted_bill = existing
            first_order = ex_first_order or (order_dt or now_ts)
            first_pending = ex_first_pending or (now_ts if pending_flag == 1 else None)
            last_pending = now_ts if pending_flag == 1 else ex_last_pending
            final_shifted = ex_shifted_at or (shifted_at or None)
            final_shift_bill = ex_shifted_bill or (shifted_bill_id or None)

            conn.execute(
                """
                UPDATE bloodbank_order_tracking
                SET order_id = COALESCE(?, order_id),
                    order_no = COALESCE(NULLIF(?, ''), order_no),
                    first_seen_order_at = COALESCE(?, first_seen_order_at),
                    first_seen_pending_at = COALESCE(?, first_seen_pending_at),
                    last_seen_pending_at = COALESCE(?, last_seen_pending_at),
                    shifted_at = COALESCE(?, shifted_at),
                    shifted_bill_id = COALESCE(NULLIF(?, ''), shifted_bill_id),
                    last_status = COALESCE(NULLIF(?, ''), last_status),
                    updated_at = ?
                WHERE unit = ? AND order_detail_id = ?
                """,
                (
                    order_id if order_id > 0 else None,
                    order_no,
                    first_order,
                    first_pending,
                    last_pending,
                    final_shifted,
                    final_shift_bill,
                    status,
                    now_ts,
                    unit_norm,
                    order_detail_id,
                ),
            )
            upserts += 1

        conn.commit()

        track_df = pd.read_sql(
            """
            SELECT order_detail_id, first_seen_pending_at, shifted_at, last_status
            FROM bloodbank_order_tracking
            WHERE unit = ?
            """,
            conn,
            params=[unit_norm],
        )

    track_map = {}
    if track_df is not None and not track_df.empty:
        for _, trow in track_df.iterrows():
            try:
                key = int(pd.to_numeric(trow.get("order_detail_id"), errors="coerce") or 0)
            except Exception:
                key = 0
            if key <= 0:
                continue
            track_map[key] = {
                "pending_since": str(trow.get("first_seen_pending_at") or "").strip(),
                "shifted_at": str(trow.get("shifted_at") or "").strip(),
                "last_status": str(trow.get("last_status") or "").strip(),
            }

    for idx in tracked_idx:
        oid = int(pd.to_numeric(work.at[idx, "OrderDetailId"], errors="coerce") or 0)
        tr = track_map.get(oid)
        if not tr:
            continue
        work.at[idx, "TrackingPendingSince"] = tr.get("pending_since") or ""
        work.at[idx, "TrackingShiftedAt"] = tr.get("shifted_at") or ""
        work.at[idx, "TrackingStatus"] = tr.get("last_status") or ""

        trail_parts = []
        if tr.get("pending_since"):
            trail_parts.append(f"Tracked pending since {tr['pending_since']}")
        if tr.get("shifted_at"):
            trail_parts.append(f"Tracked shifted on {tr['shifted_at']}")
        trail_text = " | ".join(trail_parts)
        if trail_text:
            curr_hist = str(work.at[idx, "ShiftHistory"] or "").strip()
            if curr_hist:
                if trail_text not in curr_hist:
                    work.at[idx, "ShiftHistory"] = f"{curr_hist} | {trail_text}"
            else:
                work.at[idx, "ShiftHistory"] = trail_text

    return work, {"tracked_rows": len(tracked_idx), "upserts": upserts}


@app.route('/api/mis/bloodbank_service_billing')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_bloodbank_service_billing():
    unit = (request.args.get("unit") or "").strip().upper()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return jsonify({"status": "error", "message": "No unit available"}), 400
    if allowed_units and target_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403

    df_raw = data_fetch.fetch_bloodbank_service_billing(target_unit, from_date, to_date)
    if df_raw is None:
        return jsonify({"status": "error", "message": "Database error"}), 500

    details_df = _build_bloodbank_billing_details_df(df_raw)
    details_df, tracker_stats = _sync_bloodbank_order_tracking(target_unit, details_df)
    summary_df, total_quantity, total_revenue, total_records = _build_bloodbank_billing_summary_frames(details_df)
    status_totals = _build_bloodbank_billing_status_totals(details_df)

    details_records = details_df.where(pd.notna(details_df), None).to_dict(orient="records")
    summary_records = summary_df.to_dict(orient="records")

    return jsonify({
        "status": "success",
        "unit": target_unit,
        "from_date": from_date,
        "to_date": to_date,
        "total_quantity": total_quantity,
        "total_revenue": total_revenue,
        "total_records": total_records,
        "service_summary": summary_records,
        "status_totals": status_totals,
        "tracker_stats": tracker_stats,
        "details": details_records,
    })


def _build_bloodbank_billing_excel(
    unit: str,
    from_date: str,
    to_date: str,
    exported_by: str,
    search_text: str = "",
    open_only: bool = False,
):
    df_raw = data_fetch.fetch_bloodbank_service_billing(unit, from_date, to_date)
    if df_raw is None or df_raw.empty:
        return None, None, "No data available to export"

    details_df = _build_bloodbank_billing_details_df(df_raw)
    details_df, _ = _sync_bloodbank_order_tracking(unit, details_df)
    details_df = _apply_bloodbank_details_filter(details_df, search_text=search_text, open_only=open_only)
    if details_df is None or details_df.empty:
        return None, None, "No data available for selected export filter"
    summary_df, total_quantity, total_revenue, total_records = _build_bloodbank_billing_summary_frames(details_df)

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
        workbook = writer.book

        title_fmt = workbook.add_format({
            "bold": True,
            "font_size": 14,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#1e3a8a",
            "font_color": "white",
        })
        subtitle_fmt = workbook.add_format({
            "bold": True,
            "font_size": 10,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#e2e8f0",
        })
        meta_fmt = workbook.add_format({
            "font_size": 9,
            "align": "center",
            "valign": "vcenter",
            "font_color": "#475569",
        })
        section_fmt = workbook.add_format({
            "bold": True,
            "font_size": 10,
            "align": "left",
            "valign": "vcenter",
            "bg_color": "#f1f5f9",
        })
        header_fmt = workbook.add_format({
            "bold": True,
            "font_size": 9,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#1e3a8a",
            "font_color": "white",
            "border": 1,
        })
        text_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "left"})
        int_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "#,##,##0"})
        qty_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "#,##,##0.00"})
        money_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "#,##,##0.00"})
        pct_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "0.00%"})
        text_col_fmt = workbook.add_format({"font_size": 9, "align": "left"})
        qty_col_fmt = workbook.add_format({"font_size": 9, "align": "right", "num_format": "#,##,##0.00"})
        money_col_fmt = workbook.add_format({"font_size": 9, "align": "right", "num_format": "#,##,##0.00"})
        border_only_fmt = workbook.add_format({"border": 1})

        exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
        unit_header = _lab_unit_header_text(unit)

        summary_ws = workbook.add_worksheet("Summary")
        writer.sheets["Summary"] = summary_ws

        summary_last_col = 3
        summary_ws.merge_range(0, 0, 0, summary_last_col, "Blood Bank Billing & Orders - Summary", title_fmt)
        summary_ws.merge_range(1, 0, 1, summary_last_col, f"Unit: {unit_header}", subtitle_fmt)
        filter_label = f"Filter: search='{search_text.strip()}'" if search_text.strip() else "Filter: none"
        if open_only:
            filter_label = f"{filter_label} | open discrepancies only"

        summary_ws.merge_range(2, 0, 2, summary_last_col, f"Date Range: {from_date} to {to_date}", subtitle_fmt)
        summary_ws.merge_range(3, 0, 3, summary_last_col, filter_label, meta_fmt)
        summary_ws.merge_range(4, 0, 4, summary_last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)

        summary_ws.write(6, 0, "Total Records", section_fmt)
        summary_ws.write(6, 1, total_records, int_fmt)
        summary_ws.write(7, 0, "Total Quantity", section_fmt)
        summary_ws.write(7, 1, total_quantity, qty_fmt)
        summary_ws.write(8, 0, "Total Revenue (INR)", section_fmt)
        summary_ws.write(8, 1, total_revenue, money_fmt)

        row_ptr = 10
        summary_ws.merge_range(row_ptr, 0, row_ptr, summary_last_col, "Service-wise Summary", section_fmt)
        row_ptr += 1
        summary_ws.write_row(row_ptr, 0, ["Service", "Quantity", "Revenue (INR)", "Share %"], header_fmt)
        row_ptr += 1
        for _, row in summary_df.iterrows():
            share = (float(row["Revenue"]) / total_revenue) if total_revenue else 0.0
            summary_ws.write(row_ptr, 0, row["Service_Name"], text_fmt)
            summary_ws.write(row_ptr, 1, float(row["Quantity"]), qty_fmt)
            summary_ws.write(row_ptr, 2, float(row["Revenue"]), money_fmt)
            summary_ws.write(row_ptr, 3, share, pct_fmt)
            row_ptr += 1

        summary_ws.merge_range(row_ptr + 1, 0, row_ptr + 1, summary_last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)
        summary_ws.set_column(0, 0, 36)
        summary_ws.set_column(1, 1, 14)
        summary_ws.set_column(2, 2, 18)
        summary_ws.set_column(3, 3, 12)
        summary_ws.freeze_panes(6, 0)

        details_df.to_excel(writer, sheet_name="Details", index=False, startrow=5)
        details_ws = writer.sheets["Details"]
        details_last_col = len(details_df.columns) - 1
        details_ws.merge_range(0, 0, 0, details_last_col, "Blood Bank Billing & Orders - Detail Report", title_fmt)
        details_ws.merge_range(1, 0, 1, details_last_col, f"Unit: {unit_header}", subtitle_fmt)
        details_ws.merge_range(2, 0, 2, details_last_col, f"Date Range: {from_date} to {to_date}", subtitle_fmt)
        details_ws.merge_range(3, 0, 3, details_last_col, filter_label, meta_fmt)
        details_ws.merge_range(4, 0, 4, details_last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)

        for col_num, col_name in enumerate(details_df.columns):
            details_ws.write(5, col_num, col_name, header_fmt)
            width = 14
            fmt = text_col_fmt
            if col_name in {"BillDate", "VisitDate", "DischargeDate"}:
                width = 12
            elif col_name in {"OrderDateTime", "ShiftedToBillingDate", "OrderCancelledAt"}:
                width = 18
            elif col_name in {"Quantity"}:
                width = 10
                fmt = qty_col_fmt
            elif col_name in {"Rate", "Amount"}:
                width = 14
                fmt = money_col_fmt
            elif col_name in {"Patient", "Service_Name"}:
                width = 26
            elif col_name in {"ShiftHistory"}:
                width = 40
            elif col_name in {"Sub_Dept"}:
                width = 20
            elif col_name in {"RecordSource", "OrderStatus", "OrderNo", "OrderCreatedBy", "OrderCancelledBy"}:
                width = 16
            details_ws.set_column(col_num, col_num, width, fmt)

        data_start_row = 6
        data_end_row = 5 + len(details_df)
        if len(details_df) > 0:
            from xlsxwriter.utility import xl_col_to_name
            top_row = data_start_row + 1
            last_col_letter = xl_col_to_name(details_last_col)
            criteria = f"=COUNTA($A{top_row}:${last_col_letter}{top_row})>0"
            details_ws.conditional_format(
                data_start_row, 0, data_end_row, details_last_col,
                {"type": "formula", "criteria": criteria, "format": border_only_fmt}
            )

        footer_row = 6 + len(details_df)
        details_ws.merge_range(footer_row, 0, footer_row, details_last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)
        details_ws.freeze_panes(6, 0)

    output.seek(0)
    filename_suffix = "_filtered" if (search_text.strip() or open_only) else ""
    filename = f"BloodBank_Servicewise_{unit}_{from_date}_to_{to_date}{filename_suffix}.xlsx"
    return output.getvalue(), filename, None


def _run_bloodbank_billing_excel_job(
    job_id: str,
    unit: str,
    from_date: str,
    to_date: str,
    exported_by: str,
    search_text: str = "",
    open_only: bool = False,
):
    _excel_job_update(job_id, state="running")
    try:
        data, filename, err = _build_bloodbank_billing_excel(
            unit,
            from_date,
            to_date,
            exported_by,
            search_text=search_text,
            open_only=open_only,
        )
        if not data:
            _excel_job_update(job_id, state="error", error=err or "No data available to export")
            return
        _export_cache_put_bytes("bloodbank_billing_xlsx_job", data, job_id)
        _excel_job_update(job_id, state="done", filename=filename)
    except Exception as exc:
        _excel_job_update(job_id, state="error", error=str(exc))


