# ============================================================
# MIS: Billwise Doctor Share
# ============================================================
BILLWISE_DOCSHARE_DETAIL_COLUMNS = [
    "BillDate",
    "BillNo",
    "Registration_No",
    "PatientName",
    "PatientType",
    "TypeOfVisit",
    "DoctorName",
    "SecondaryDoc",
    "Service_Name",
    "BillQty",
    "Rate",
    "Amount",
    "VisitDate",
    "DischargeDate",
]


def _visit_type_label(vtype: int) -> str:
    mapping = {
        0: "All",
        1: "IPD",
        2: "OPD",
        3: "DPV",
        6: "HCV",
    }
    return mapping.get(vtype, f"Type {vtype}")


def _build_billwise_doctorshare_details_df(df_raw: pd.DataFrame) -> pd.DataFrame:
    if df_raw is None or df_raw.empty:
        return pd.DataFrame(columns=BILLWISE_DOCSHARE_DETAIL_COLUMNS)

    df_raw = _clean_df_columns(df_raw)
    cols_map = {str(c).strip().lower(): c for c in df_raw.columns}

    def _pick(candidates):
        for cand in candidates:
            key = cand.lower()
            if key in cols_map:
                return cols_map[key]
        return None

    col_map = {
        "BillDate": _pick(["BillDate", "Bill_Date", "Billdate", "Date"]),
        "BillNo": _pick(["BillNo", "Bill_No", "Billno"]),
        "Registration_No": _pick(["Registration_No", "RegistrationNo", "RegNo", "Reg_No", "UHID"]),
        "PatientName": _pick(["PatientName", "Patient", "Patientname", "Patient_Name"]),
        "PatientType": _pick(["PatientType", "Patienttype", "Patient_Type", "PatType"]),
        "TypeOfVisit": _pick(["TypeOfVisit", "VisitType", "Visit Type", "Type Of Visit"]),
        "DoctorName": _pick(["DoctorName", "Doctor", "Doctorname", "DocInCharge", "DocIncharge"]),
        "SecondaryDoc": _pick(["SecondaryDoc", "Secondary", "SecondaryDoctor"]),
        "Service_Name": _pick(["Service_Name", "ServiceName", "Service", "Service Name"]),
        "BillQty": _pick(["BillQty", "Quantity", "Qty", "QTY"]),
        "Rate": _pick(["Rate"]),
        "Amount": _pick(["Amount", "NetAmount", "Net_Amt", "TotalAmount", "Total_Amt"]),
        "VisitDate": _pick(["VisitDate", "Visit_Date", "Visitdate"]),
        "DischargeDate": _pick(["DischargeDate", "Discharge_Date", "Dischargedate"]),
    }

    details = pd.DataFrame()
    for col in BILLWISE_DOCSHARE_DETAIL_COLUMNS:
        source = col_map.get(col)
        if source and source in df_raw.columns:
            details[col] = df_raw[source]
        else:
            details[col] = pd.Series([None] * len(df_raw))

    for date_col in ["BillDate", "VisitDate", "DischargeDate"]:
        date_series = pd.to_datetime(details[date_col], errors="coerce")
        details[date_col] = date_series.dt.strftime("%Y-%m-%d").fillna("")

    for col in ["BillQty", "Rate", "Amount"]:
        details[col] = pd.to_numeric(details[col], errors="coerce").fillna(0.0).astype(float)

    for col in ["Registration_No", "BillNo", "PatientName", "PatientType", "TypeOfVisit", "DoctorName", "SecondaryDoc", "Service_Name"]:
        details[col] = details[col].astype(str).replace({"nan": "", "None": ""}).str.strip()

    return details[BILLWISE_DOCSHARE_DETAIL_COLUMNS]


def _build_billwise_doctorshare_summary_frames(details_df: pd.DataFrame):
    if details_df is None or details_df.empty:
        empty_summary = pd.DataFrame(columns=["Service_Name", "Quantity", "Revenue", "Records"])
        return empty_summary, 0.0, 0.0, 0

    work = details_df.copy()
    work["Service_Name"] = work["Service_Name"].replace("", "Unknown").fillna("Unknown")

    total_quantity = float(work["BillQty"].sum())
    total_revenue = float(work["Amount"].sum())
    total_records = int(len(work))

    summary = (
        work.groupby("Service_Name", dropna=False)
        .agg(Quantity=("BillQty", "sum"), Revenue=("Amount", "sum"), Records=("Service_Name", "size"))
        .reset_index()
        .sort_values("Revenue", ascending=False)
    )

    return summary, total_quantity, total_revenue, total_records


@app.route('/api/mis/billwise_doctorshare')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_billwise_doctorshare():
    unit = (request.args.get("unit") or "").strip().upper()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    doc_id_raw = (
        request.args.get("doc_id")
        or request.args.get("docid")
        or request.args.get("doctor_id")
        or request.args.get("doc")
    )
    vtype_raw = request.args.get("vtype")

    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return jsonify({"status": "error", "message": "No unit available"}), 400
    if allowed_units and target_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403
    if doc_id_raw is None or str(doc_id_raw).strip() == "":
        return jsonify({"status": "error", "message": "Doctor ID is required"}), 400
    try:
        doc_id = int(str(doc_id_raw).strip())
    except Exception:
        return jsonify({"status": "error", "message": "Invalid doctor ID"}), 400
    try:
        vtype = int(str(vtype_raw or 0).strip())
    except Exception:
        return jsonify({"status": "error", "message": "Invalid visit type"}), 400

    df_raw = data_fetch.fetch_billwise_doctorshare(target_unit, from_date, to_date, doc_id, vtype)
    if df_raw is None:
        return jsonify({"status": "error", "message": "Database error"}), 500

    details_df = _build_billwise_doctorshare_details_df(df_raw)
    summary_df, total_quantity, total_revenue, total_records = _build_billwise_doctorshare_summary_frames(details_df)

    details_records = details_df.where(pd.notna(details_df), None).to_dict(orient="records")
    summary_records = summary_df.to_dict(orient="records")

    doctor_label = "All Doctors" if doc_id == 0 else (_resolve_doctor_name(target_unit, doc_id) or "Unknown")
    visit_label = _visit_type_label(vtype)

    return jsonify({
        "status": "success",
        "unit": target_unit,
        "from_date": from_date,
        "to_date": to_date,
        "doc_id": doc_id,
        "doctor_name": doctor_label,
        "visit_type": vtype,
        "visit_label": visit_label,
        "total_quantity": total_quantity,
        "total_revenue": total_revenue,
        "total_records": total_records,
        "service_summary": summary_records,
        "details": details_records,
    })


def _build_billwise_doctorshare_excel(unit: str, from_date: str, to_date: str, doc_id: int, vtype: int, exported_by: str):
    df_raw = data_fetch.fetch_billwise_doctorshare(unit, from_date, to_date, doc_id, vtype)
    if df_raw is None or df_raw.empty:
        return None, None, "No data available to export"

    details_df = _build_billwise_doctorshare_details_df(df_raw)
    summary_df, total_quantity, total_revenue, total_records = _build_billwise_doctorshare_summary_frames(details_df)
    doctor_label = "All Doctors" if doc_id == 0 else (_resolve_doctor_name(unit, doc_id) or "Unknown")
    visit_label = _visit_type_label(vtype)

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
        workbook = writer.book

        title_fmt = workbook.add_format({
            "bold": True,
            "font_size": 14,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#1e3a8a",
            "font_color": "white",
        })
        subtitle_fmt = workbook.add_format({
            "bold": True,
            "font_size": 10,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#e2e8f0",
        })
        meta_fmt = workbook.add_format({
            "font_size": 9,
            "align": "center",
            "valign": "vcenter",
            "font_color": "#475569",
        })
        section_fmt = workbook.add_format({
            "bold": True,
            "font_size": 10,
            "align": "left",
            "valign": "vcenter",
            "bg_color": "#f1f5f9",
        })
        header_fmt = workbook.add_format({
            "bold": True,
            "font_size": 9,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#1e3a8a",
            "font_color": "white",
            "border": 1,
        })
        text_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "left"})
        int_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "#,##,##0"})
        qty_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "#,##,##0.00"})
        money_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "#,##,##0.00"})
        pct_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "0.00%"})
        text_col_fmt = workbook.add_format({"font_size": 9, "align": "left"})
        qty_col_fmt = workbook.add_format({"font_size": 9, "align": "right", "num_format": "#,##,##0.00"})
        money_col_fmt = workbook.add_format({"font_size": 9, "align": "right", "num_format": "#,##,##0.00"})
        border_only_fmt = workbook.add_format({"border": 1})

        exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
        unit_header = _lab_unit_header_text(unit)

        summary_ws = workbook.add_worksheet("Summary")
        writer.sheets["Summary"] = summary_ws

        summary_last_col = 3
        summary_ws.merge_range(0, 0, 0, summary_last_col, "Billwise Doctor Share - Summary", title_fmt)
        summary_ws.merge_range(1, 0, 1, summary_last_col, f"Unit: {unit_header}", subtitle_fmt)
        summary_ws.merge_range(2, 0, 2, summary_last_col, f"Doctor: {doctor_label} | Doc ID: {doc_id}", subtitle_fmt)
        summary_ws.merge_range(3, 0, 3, summary_last_col, f"Visit Type: {visit_label} | Code: {vtype}", subtitle_fmt)
        summary_ws.merge_range(4, 0, 4, summary_last_col, f"Date Range: {from_date} to {to_date}", subtitle_fmt)
        summary_ws.merge_range(5, 0, 5, summary_last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)

        summary_ws.write(7, 0, "Total Records", section_fmt)
        summary_ws.write(7, 1, total_records, int_fmt)
        summary_ws.write(8, 0, "Total Quantity", section_fmt)
        summary_ws.write(8, 1, total_quantity, qty_fmt)
        summary_ws.write(9, 0, "Total Revenue (INR)", section_fmt)
        summary_ws.write(9, 1, total_revenue, money_fmt)

        row_ptr = 11
        summary_ws.merge_range(row_ptr, 0, row_ptr, summary_last_col, "Service-wise Summary", section_fmt)
        row_ptr += 1
        summary_ws.write_row(row_ptr, 0, ["Service", "Quantity", "Revenue (INR)", "Share %"], header_fmt)
        row_ptr += 1
        for _, row in summary_df.iterrows():
            share = (float(row["Revenue"]) / total_revenue) if total_revenue else 0.0
            summary_ws.write(row_ptr, 0, row["Service_Name"], text_fmt)
            summary_ws.write(row_ptr, 1, float(row["Quantity"]), qty_fmt)
            summary_ws.write(row_ptr, 2, float(row["Revenue"]), money_fmt)
            summary_ws.write(row_ptr, 3, share, pct_fmt)
            row_ptr += 1

        summary_ws.merge_range(row_ptr + 1, 0, row_ptr + 1, summary_last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)
        summary_ws.set_column(0, 0, 36)
        summary_ws.set_column(1, 1, 14)
        summary_ws.set_column(2, 2, 18)
        summary_ws.set_column(3, 3, 12)
        summary_ws.freeze_panes(7, 0)

        details_df.to_excel(writer, sheet_name="Details", index=False, startrow=5)
        details_ws = writer.sheets["Details"]
        details_last_col = len(details_df.columns) - 1
        details_ws.merge_range(0, 0, 0, details_last_col, "Billwise Doctor Share - Detail Report", title_fmt)
        details_ws.merge_range(1, 0, 1, details_last_col, f"Unit: {unit_header}", subtitle_fmt)
        details_ws.merge_range(2, 0, 2, details_last_col, f"Doctor: {doctor_label} | Doc ID: {doc_id}", subtitle_fmt)
        details_ws.merge_range(3, 0, 3, details_last_col, f"Visit Type: {visit_label} | Code: {vtype}", subtitle_fmt)
        details_ws.merge_range(4, 0, 4, details_last_col, f"Date Range: {from_date} to {to_date} | Exported By: {exported_by}", meta_fmt)

        for col_num, col_name in enumerate(details_df.columns):
            details_ws.write(5, col_num, col_name, header_fmt)
            width = 14
            fmt = text_col_fmt
            if col_name in {"BillDate", "VisitDate", "DischargeDate"}:
                width = 12
            elif col_name in {"BillQty"}:
                width = 10
                fmt = qty_col_fmt
            elif col_name in {"Rate", "Amount"}:
                width = 14
                fmt = money_col_fmt
            elif col_name in {"PatientName", "Service_Name"}:
                width = 26
            elif col_name in {"DoctorName", "SecondaryDoc"}:
                width = 20
            details_ws.set_column(col_num, col_num, width, fmt)

        data_start_row = 6
        data_end_row = 5 + len(details_df)
        if len(details_df) > 0:
            from xlsxwriter.utility import xl_col_to_name
            top_row = data_start_row + 1
            last_col_letter = xl_col_to_name(details_last_col)
            criteria = f"=COUNTA($A{top_row}:${last_col_letter}{top_row})>0"
            details_ws.conditional_format(
                data_start_row, 0, data_end_row, details_last_col,
                {"type": "formula", "criteria": criteria, "format": border_only_fmt}
            )

        footer_row = 6 + len(details_df)
        details_ws.merge_range(footer_row, 0, footer_row, details_last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)
        details_ws.freeze_panes(6, 0)

    output.seek(0)
    filename = f"Billwise_DoctorShare_{unit}_{from_date}_to_{to_date}.xlsx"
    return output.getvalue(), filename, None


def _run_billwise_doctorshare_excel_job(job_id: str, unit: str, from_date: str, to_date: str, doc_id: int, vtype: int, exported_by: str):
    _excel_job_update(job_id, state="running")
    try:
        data, filename, err = _build_billwise_doctorshare_excel(unit, from_date, to_date, doc_id, vtype, exported_by)
        if not data:
            _excel_job_update(job_id, state="error", error=err or "No data available to export")
            return
        _export_cache_put_bytes("billwise_doctorshare_xlsx_job", data, job_id)
        _excel_job_update(job_id, state="done", filename=filename)
    except Exception as exc:
        _excel_job_update(job_id, state="error", error=str(exc))


@app.route('/api/mis/billwise_doctorshare/export_excel')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_billwise_doctorshare_export_excel():
    unit = (request.args.get("unit") or "").strip().upper()
    from_date = (request.args.get("from") or "").strip()
    to_date = (request.args.get("to") or "").strip()
    doc_id_raw = (
        request.args.get("doc_id")
        or request.args.get("docid")
        or request.args.get("doctor_id")
        or request.args.get("doc")
    )
    vtype_raw = request.args.get("vtype")
    allowed_units = _allowed_units_for_session()

    if not allowed_units:
        return "No unit access assigned", 403
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return "Please select a unit", 400
    if unit not in allowed_units:
        return f"Unit {unit} not permitted", 403
    if not from_date or not to_date:
        return "Please select a valid date range", 400
    if doc_id_raw is None or str(doc_id_raw).strip() == "":
        return "Doctor ID is required", 400
    try:
        doc_id = int(str(doc_id_raw).strip())
    except Exception:
        return "Invalid doctor ID", 400
    try:
        vtype = int(str(vtype_raw or 0).strip())
    except Exception:
        return "Invalid visit type", 400

    exported_by = session.get("username") or session.get("user") or "Unknown"
    data, filename, err = _build_billwise_doctorshare_excel(unit, from_date, to_date, doc_id, vtype, exported_by)
    if not data:
        return err or "No data available to export", 404
    return send_file(
        io.BytesIO(data),
        as_attachment=True,
        download_name=filename,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )


@app.route('/api/mis/billwise_doctorshare/export_excel_job', methods=["POST"])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_billwise_doctorshare_export_excel_job():
    payload = request.get_json(silent=True) or {}
    unit = (payload.get("unit") or request.args.get("unit") or "").strip().upper()
    from_date = (payload.get("from") or payload.get("from_date") or request.args.get("from") or "").strip()
    to_date = (payload.get("to") or payload.get("to_date") or request.args.get("to") or "").strip()
    doc_id_raw = (
        payload.get("doc_id")
        or payload.get("docid")
        or payload.get("doctor_id")
        or request.args.get("doc_id")
        or request.args.get("docid")
        or request.args.get("doctor_id")
        or request.args.get("doc")
    )
    vtype_raw = payload.get("vtype") or request.args.get("vtype")
    allowed_units = _allowed_units_for_session()

    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return jsonify({"status": "error", "message": "Please select a unit"}), 400
    if unit not in allowed_units:
        return jsonify({"status": "error", "message": f"Unit {unit} not permitted"}), 403
    if not from_date or not to_date:
        return jsonify({"status": "error", "message": "Please select a valid date range"}), 400
    if doc_id_raw is None or str(doc_id_raw).strip() == "":
        return jsonify({"status": "error", "message": "Doctor ID is required"}), 400
    try:
        doc_id = int(str(doc_id_raw).strip())
    except Exception:
        return jsonify({"status": "error", "message": "Invalid doctor ID"}), 400
    try:
        vtype = int(str(vtype_raw or 0).strip())
    except Exception:
        return jsonify({"status": "error", "message": "Invalid visit type"}), 400

    exported_by = session.get("username") or session.get("user") or "Unknown"
    job_id = token_hex(16)
    _excel_job_update(job_id, state="queued", filename=None)
    EXPORT_EXECUTOR.submit(_run_billwise_doctorshare_excel_job, job_id, unit, from_date, to_date, doc_id, vtype, exported_by)
    return jsonify({"status": "queued", "job_id": job_id})


@app.route('/api/mis/billwise_doctorshare/export_excel_job_status')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_billwise_doctorshare_export_excel_job_status():
    job_id = (request.args.get("job_id") or "").strip()
    if not job_id:
        return jsonify({"status": "error", "message": "Missing job id"}), 400
    entry = _excel_job_get(job_id)
    if not entry:
        return jsonify({"status": "error", "message": "Job not found"}), 404
    return jsonify({
        "status": "success",
        "state": entry.get("state"),
        "error": entry.get("error"),
        "filename": entry.get("filename"),
    })


@app.route('/api/mis/billwise_doctorshare/export_excel_job_result')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_billwise_doctorshare_export_excel_job_result():
    job_id = (request.args.get("job_id") or "").strip()
    if not job_id:
        return "Missing job id", 400
    entry = _excel_job_get(job_id)
    if not entry:
        return "Job not found", 404
    if entry.get("state") != "done":
        return "Job not ready", 409
    data = _export_cache_get_bytes("billwise_doctorshare_xlsx_job", job_id)
    if not data:
        return "Export expired", 404
    filename = entry.get("filename") or "Billwise_DoctorShare.xlsx"
    return send_file(
        io.BytesIO(data),
        as_attachment=True,
        download_name=filename,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )


def _build_billwise_doctorshare_pdf_buffer(unit: str, from_date: str, to_date: str, doc_id: int, vtype: int, exported_by: str):
    from reportlab.lib.pagesizes import A4, landscape
    from reportlab.lib import colors
    from reportlab.lib.units import mm
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer, PageBreak, Image
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_RIGHT
    from xml.sax.saxutils import escape

    df_raw = data_fetch.fetch_billwise_doctorshare(unit, from_date, to_date, doc_id, vtype)
    if df_raw is None or df_raw.empty:
        return None

    details_df = _build_billwise_doctorshare_details_df(df_raw)
    summary_df, total_quantity, total_revenue, total_records = _build_billwise_doctorshare_summary_frames(details_df)
    doctor_label = "All Doctors" if doc_id == 0 else (_resolve_doctor_name(unit, doc_id) or "Unknown")
    visit_label = _visit_type_label(vtype)

    def _format_inr(number) -> str:
        try:
            n = float(number)
        except Exception:
            return "0.00"
        sign = "-" if n < 0 else ""
        n = abs(n)
        s = f"{n:.2f}"
        whole, frac = s.split(".")
        if len(whole) <= 3:
            grouped = whole
        else:
            last = whole[-3:]
            rest = whole[:-3]
            parts = []
            while rest:
                parts.append(rest[-2:])
                rest = rest[:-2]
            grouped = ",".join(reversed(parts)) + "," + last
        return f"{sign}{grouped}.{frac}"

    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=landscape(A4),
        topMargin=14 * mm,
        bottomMargin=14 * mm,
        leftMargin=12 * mm,
        rightMargin=12 * mm,
    )

    styles = getSampleStyleSheet()
    style_title = ParagraphStyle("RptTitle", parent=styles["Heading2"], fontSize=12, alignment=TA_CENTER, textColor=colors.HexColor("#1e3a8a"))
    style_sub = ParagraphStyle("RptSub", parent=styles["Normal"], fontSize=9, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_meta = ParagraphStyle("RptMeta", parent=styles["Normal"], fontSize=8, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_th = ParagraphStyle("RptTh", parent=styles["Normal"], fontSize=8, textColor=colors.white, alignment=TA_CENTER)
    style_td = ParagraphStyle("RptTd", parent=styles["Normal"], fontSize=6.5, textColor=colors.black, leading=8)
    style_td_wrap = ParagraphStyle(
        "RptTdWrap",
        parent=styles["Normal"],
        fontSize=6.5,
        textColor=colors.black,
        leading=8,
        wordWrap="CJK",
    )
    style_td_right = ParagraphStyle("RptTdRight", parent=styles["Normal"], fontSize=6.5, textColor=colors.black, alignment=TA_RIGHT, leading=8)

    elements = []
    logo_path = os.path.join(app.root_path, "static", "logo", "asarfi.png")
    if os.path.exists(logo_path):
        logo = Image(logo_path, width=18 * mm, height=18 * mm, mask="auto")
        logo.hAlign = "CENTER"
        elements.append(logo)

    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    unit_header = _lab_unit_header_text(unit)
    elements.append(Spacer(1, 6))
    elements.append(Paragraph("Billwise Doctor Share - Summary", style_title))
    elements.append(Paragraph(f"Unit: {unit_header}", style_sub))
    elements.append(Paragraph(f"Doctor: {doctor_label} | Doc ID: {doc_id}", style_sub))
    elements.append(Paragraph(f"Visit Type: {visit_label} | Code: {vtype}", style_sub))
    elements.append(Paragraph(f"Date Range: {from_date} to {to_date}", style_sub))
    elements.append(Paragraph(f"Exported By: {exported_by} | Exported At: {exported_at}", style_meta))
    elements.append(Spacer(1, 8))

    summary_rows = [
        [Paragraph("Metric", style_th), Paragraph("Value", style_th)],
        [Paragraph("Total Records", style_td), Paragraph(f"{total_records:,}", style_td_right)],
        [Paragraph("Total Quantity", style_td), Paragraph(f"{total_quantity:,.2f}", style_td_right)],
        [Paragraph("Total Revenue (INR)", style_td), Paragraph(_format_inr(total_revenue), style_td_right)],
    ]
    summary_table = Table(summary_rows, colWidths=[70 * mm, 40 * mm])
    summary_table.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("GRID", (0, 0), (-1, -1), 0.4, colors.HexColor("#1f2937")),
        ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
    ]))
    elements.append(summary_table)
    elements.append(Spacer(1, 10))

    service_rows = [[Paragraph("Service", style_th), Paragraph("Quantity", style_th), Paragraph("Revenue (INR)", style_th)]]
    for _, row in summary_df.iterrows():
        service_rows.append([
            Paragraph(escape(str(row["Service_Name"] or "")), style_td_wrap),
            Paragraph(f"{float(row['Quantity']):,.2f}", style_td_right),
            Paragraph(_format_inr(row["Revenue"]), style_td_right),
        ])
    service_table = Table(service_rows, colWidths=[90 * mm, 25 * mm, 35 * mm], repeatRows=1)
    service_table.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("GRID", (0, 0), (-1, -1), 0.4, colors.HexColor("#1f2937")),
        ("VALIGN", (0, 0), (-1, -1), "TOP"),
    ]))
    elements.append(service_table)
    elements.append(PageBreak())

    detail_headers = [
        Paragraph("Bill Date", style_th),
        Paragraph("Bill No", style_th),
        Paragraph("Reg No", style_th),
        Paragraph("Patient", style_th),
        Paragraph("Patient Type", style_th),
        Paragraph("Visit Type", style_th),
        Paragraph("Doctor", style_th),
        Paragraph("Secondary Doc", style_th),
        Paragraph("Service", style_th),
        Paragraph("Qty", style_th),
        Paragraph("Rate", style_th),
        Paragraph("Amount", style_th),
        Paragraph("Visit Date", style_th),
        Paragraph("Discharge Date", style_th),
    ]
    detail_rows = [detail_headers]
    for _, row in details_df.iterrows():
        detail_rows.append([
            Paragraph(escape(str(row.get("BillDate") or "")), style_td),
            Paragraph(escape(str(row.get("BillNo") or "")), style_td),
            Paragraph(escape(str(row.get("Registration_No") or "")), style_td),
            Paragraph(escape(str(row.get("PatientName") or "")), style_td_wrap),
            Paragraph(escape(str(row.get("PatientType") or "")), style_td_wrap),
            Paragraph(escape(str(row.get("TypeOfVisit") or "")), style_td),
            Paragraph(escape(str(row.get("DoctorName") or "")), style_td_wrap),
            Paragraph(escape(str(row.get("SecondaryDoc") or "")), style_td_wrap),
            Paragraph(escape(str(row.get("Service_Name") or "")), style_td_wrap),
            Paragraph(f"{float(row.get('BillQty') or 0):,.2f}", style_td_right),
            Paragraph(_format_inr(row.get("Rate") or 0), style_td_right),
            Paragraph(_format_inr(row.get("Amount") or 0), style_td_right),
            Paragraph(escape(str(row.get("VisitDate") or "")), style_td),
            Paragraph(escape(str(row.get("DischargeDate") or "")), style_td),
        ])

    detail_tbl = Table(
        detail_rows,
        colWidths=[16 * mm, 16 * mm, 18 * mm, 28 * mm, 22 * mm, 16 * mm, 24 * mm, 24 * mm, 36 * mm, 12 * mm, 16 * mm, 16 * mm, 16 * mm, 18 * mm],
        repeatRows=1,
    )
    detail_tbl.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("FONTSIZE", (0, 0), (-1, -1), 6.5),
        ("GRID", (0, 0), (-1, -1), 0.4, colors.HexColor("#1f2937")),
        ("VALIGN", (0, 0), (-1, -1), "TOP"),
        ("ALIGN", (9, 1), (11, -1), "RIGHT"),
    ]))
    elements.append(detail_tbl)

    def _draw_page_number(canvas, doc_obj):
        canvas.saveState()
        width, _ = doc.pagesize
        canvas.setFont("Helvetica", 8)
        canvas.setFillColor(colors.HexColor("#64748b"))
        canvas.drawRightString(width - 12 * mm, 10 * mm, f"Page {doc_obj.page}")
        canvas.drawString(12 * mm, 10 * mm, "Copyright (c) ASARFI HOSPITAL")
        canvas.restoreState()

    doc.build(elements, onFirstPage=_draw_page_number, onLaterPages=_draw_page_number)
    buffer.seek(0)
    return buffer


@app.route('/api/mis/billwise_doctorshare/export_pdf')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_billwise_doctorshare_export_pdf():
    unit = (request.args.get("unit") or "").strip().upper()
    from_date = (request.args.get("from") or "").strip()
    to_date = (request.args.get("to") or "").strip()
    doc_id_raw = (
        request.args.get("doc_id")
        or request.args.get("docid")
        or request.args.get("doctor_id")
        or request.args.get("doc")
    )
    vtype_raw = request.args.get("vtype")
    allowed_units = _allowed_units_for_session()

    if not allowed_units:
        return "No unit access assigned", 403
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return "Please select a unit", 400
    if unit not in allowed_units:
        return f"Unit {unit} not permitted", 403
    if not from_date or not to_date:
        return "Please select a valid date range", 400
    if doc_id_raw is None or str(doc_id_raw).strip() == "":
        return "Doctor ID is required", 400
    try:
        doc_id = int(str(doc_id_raw).strip())
    except Exception:
        return "Invalid doctor ID", 400
    try:
        vtype = int(str(vtype_raw or 0).strip())
    except Exception:
        return "Invalid visit type", 400

    exported_by = session.get("username") or session.get("user") or "Unknown"
    buffer = _build_billwise_doctorshare_pdf_buffer(unit, from_date, to_date, doc_id, vtype, exported_by)
    if buffer is None:
        return "No data available to export", 404
    filename = f"Billwise_DoctorShare_{unit}_{from_date}_to_{to_date}.pdf"
    return send_file(buffer, mimetype="application/pdf", as_attachment=True, download_name=filename)

@app.route('/api/mis/ip_billed_consumables')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_ip_billed_consumables():
    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _analytics_allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return jsonify({"status": "error", "message": "No unit available"}), 400
    if allowed_units and target_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403

    df = data_fetch.fetch_ipd_cardiac_consumables(target_unit, from_date, to_date)
    if df is None:
        return jsonify({"status": "error", "message": "Database error"}), 500
    if df.empty:
        return jsonify({"status": "success", "data": [], "unit": target_unit, "count": 0}), 200

    df = _clean_df_columns(df)
    for col in df.columns:
        if pd.api.types.is_datetime64_any_dtype(df[col]):
            df[col] = pd.to_datetime(df[col], errors="coerce").dt.strftime("%Y-%m-%d %H:%M:%S")

    df = df.replace({pd.NaT: None, np.nan: None})
    df = df.where(pd.notna(df), None)

    records = df.to_dict(orient="records")
    return jsonify({"status": "success", "data": records, "unit": target_unit, "count": len(records)})


@app.route('/api/mis/ip_billed_consumables/export_excel')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_ip_billed_consumables_export_excel():
    import io
    import pandas as pd

    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _analytics_allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return "No unit available", 400
    if allowed_units and target_unit not in allowed_units:
        return "Unit not allowed", 403

    df = data_fetch.fetch_ipd_cardiac_consumables(target_unit, from_date, to_date)
    if df is None or df.empty:
        return "No data available to export", 404

    df = _clean_df_columns(df.copy())
    export_cols = [
        ("BillDetailID", "Bill Detail ID"),
        ("Bill_ID", "Bill ID"),
        ("Visit_ID", "Visit ID"),
        ("Registration_No", "Reg No"),
        ("Patient", "Patient"),
        ("Doctor", "Doctor"),
        ("BillDate", "Bill Date"),
        ("AdmissionDate", "Admission Date"),
        ("DischargeDate", "Discharge Date"),
        ("PatType", "Patient Type"),
        ("ItemName", "Item Name"),
        ("BatchName", "Batch Name"),
        ("Rate", "Rate"),
        ("Quantity", "Qty"),
        ("Amount", "Amount"),
        ("PurchasePrice", "Purchase Price"),
        ("SalePrice", "Sale Price"),
        ("OrderDtlId", "Order Detail ID"),
        ("DrugId", "Drug ID"),
    ]

    col_map = {src: label for src, label in export_cols if src in df.columns}
    selected_cols = [c for c, _ in export_cols if c in df.columns]
    if not selected_cols:
        return "No data available to export", 404
    df = df[selected_cols].rename(columns=col_map)

    money_cols = {"Rate", "Amount", "Purchase Price", "Sale Price"}
    qty_cols = {"Qty"}
    id_cols = {"Bill Detail ID", "Bill ID", "Visit ID", "Order Detail ID", "Drug ID"}
    date_cols = {"Bill Date", "Admission Date", "Discharge Date"}

    for col in df.columns:
        if col in money_cols or col in qty_cols or col in id_cols:
            df[col] = pd.to_numeric(df[col], errors="coerce")
        if col in date_cols:
            df[col] = pd.to_datetime(df[col], errors="coerce")

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
        wb = writer.book
        ws_name = "IP Consumables"
        df.to_excel(writer, sheet_name=ws_name, index=False, startrow=5)
        ws = writer.sheets[ws_name]

        title_fmt = wb.add_format({
            "bold": True, "font_size": 14, "font_color": "#1E3A8A",
            "align": "center", "valign": "vcenter"
        })
        subtitle_fmt = wb.add_format({
            "bold": True, "font_size": 11, "align": "center", "valign": "vcenter"
        })
        meta_fmt = wb.add_format({"font_size": 9, "align": "center", "valign": "vcenter"})
        header_fmt = wb.add_format({
            "bold": True, "bg_color": "#1E3A8A", "font_color": "white",
            "border": 1, "align": "center", "valign": "vcenter"
        })
        date_fmt = wb.add_format({"num_format": "yyyy-mm-dd", "align": "center", "valign": "vcenter"})
        qty_fmt = wb.add_format({"num_format": "#,##,##0.00", "align": "right", "valign": "vcenter"})
        money_fmt = wb.add_format({"num_format": "#,##,##0.00", "align": "right", "valign": "vcenter"})
        int_fmt = wb.add_format({"num_format": "#,##,##0", "align": "right", "valign": "vcenter"})
        text_fmt = wb.add_format({"align": "left", "valign": "vcenter"})

        last_col = len(df.columns) - 1
        date_label = from_date if from_date == to_date else f"{from_date} to {to_date}"
        ws.merge_range(0, 0, 0, last_col, "IP Billed Consumables (Cardiac)", title_fmt)
        ws.merge_range(1, 0, 1, last_col, f"Unit: {target_unit} | Date Range: {date_label}", subtitle_fmt)

        exported_by = session.get("username") or session.get("user") or "Unknown"
        exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
        ws.merge_range(2, 0, 2, last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)

        for col_num, col_name in enumerate(df.columns):
            ws.write(5, col_num, col_name, header_fmt)
            width = 16
            fmt = text_fmt
            if col_name in date_cols:
                width = 14
                fmt = date_fmt
            elif col_name in money_cols:
                width = 16
                fmt = money_fmt
            elif col_name in qty_cols:
                width = 10
                fmt = qty_fmt
            elif col_name in id_cols:
                width = 12
                fmt = int_fmt
            elif col_name in {"Patient", "Doctor", "Item Name", "Batch Name"}:
                width = 24
            elif col_name in {"Reg No", "Patient Type"}:
                width = 18
            ws.set_column(col_num, col_num, width, fmt)

        footer_row = 6 + len(df)
        ws.merge_range(footer_row, 0, footer_row, last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)
        ws.freeze_panes(6, 0)

    output.seek(0)
    filename = f"IP_Billed_Consumables_{target_unit}_{from_date}_to_{to_date}.xlsx"
    return send_file(
        output,
        as_attachment=True,
        download_name=filename,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    )


REFUND_TRACKER_MASTER_COLUMNS = [
    "RefundId",
    "RefundInitializeDate",
    "RegNo",
    "PatientName",
    "PatientType",
    "CorpType",
    "VisitNo",
    "VisitDate",
    "DischargeDate",
    "RefundStatus",
    "AdminStatus",
    "CorpStatus",
    "AccountStatus",
    "TotalReceiveAmt",
    "RefundAmt",
    "RefundDeductionAmt",
    "AccountDeductionAmt",
    "CorpDeductionAmt",
    "TotalDeductionAmt",
    "PatientBankName",
    "PatientAccountNo",
    "PatientBankIFSC",
    "PatientAccHolderName",
    "PatientRelationName",
    "UTRNo",
    "RefundRemark",
    "AccountRemark",
    "CorpRemarks",
    "AttachedReceiptCount",
    "AttachedReceiptAmount",
]

REFUND_TRACKER_DETAIL_COLUMNS = [
    "RecId",
    "RefundId",
    "OldReceiptId",
    "ReceiptNo",
    "RefRecAmount",
    "ReceiptAmount",
    "RecDate",
    "OldRecDate",
    "PaymentMode",
    "ReceiptType",
    "CancelStatus",
    "LinkedUserName",
    "InsertedDate",
]


def _refund_tracker_norm_text(value, fallback: str = "") -> str:
    txt = str(value or "").strip()
    if not txt:
        return fallback
    if txt.lower() in {"nan", "none", "null"}:
        return fallback
    return txt


def _refund_tracker_status_label(value) -> str:
    # Business rule: 1/1.0 => True; 0/null/blank => False
    token = str(value if value is not None else "").strip()
    if not token or token.lower() in {"nan", "none", "null"}:
        return "False"
    try:
        num = float(token)
        return "True" if abs(num - 1.0) < 1e-9 else "False"
    except Exception:
        low = token.lower()
        if low in {"true", "t", "y", "yes"}:
            return "True"
        if low in {"false", "f", "n", "no"}:
            return "False"
        return token


def _refund_tracker_fmt_dt(value) -> str:
    dt_val = pd.to_datetime(value, errors="coerce")
    if pd.isna(dt_val):
        return ""
    return dt_val.strftime("%Y-%m-%d %H:%M:%S")


def _build_refund_tracker_frames(df_raw: pd.DataFrame):
    if df_raw is None or df_raw.empty:
        return (
            pd.DataFrame(columns=REFUND_TRACKER_MASTER_COLUMNS),
            pd.DataFrame(columns=REFUND_TRACKER_DETAIL_COLUMNS),
        )

    df = _clean_df_columns(df_raw.copy())

    expected_cols = {
        "RefundId", "RefundInitializeDate", "RegNo", "PatientName", "PatientType", "CorpType",
        "VisitNo", "VisitDate", "DischargeDate", "RefundStatus", "AdminStatus", "CorpStatus",
        "AccountStatus", "TotalReceiveAmt", "RefundAmt", "RefundDeductionAmt", "AccountDeductionAmt",
        "CorpDeductionAmt", "PatientBankName", "PatientAccountNo", "PatientBankIFSC",
        "PatientAccHolderName", "PatientRelationName", "UTRNo", "RefundRemark", "AccountRemark",
        "CorpRemarks", "RecId", "OldReceiptId", "ReceiptNo", "RefRecAmount", "ReceiptAmount", "RecDate",
        "OldRecDate", "PaymentMode", "ReceiptType",
        "CancelStatus", "LinkedUserName",
        "InsertedDate",
    }
    for col in expected_cols:
        if col not in df.columns:
            df[col] = None

    numeric_cols = [
        "RefundId", "TotalReceiveAmt", "RefundAmt", "RefundDeductionAmt",
        "AccountDeductionAmt", "CorpDeductionAmt", "RecId", "OldReceiptId",
        "RefRecAmount", "ReceiptAmount",
    ]
    for col in numeric_cols:
        if col in df.columns:
            df[col] = pd.to_numeric(df[col], errors="coerce")

    df["_RefundInitializeDateSort"] = pd.to_datetime(df["RefundInitializeDate"], errors="coerce")
    df["_RecDateSort"] = pd.to_datetime(df["RecDate"], errors="coerce")
    df["_InsertedDateSort"] = pd.to_datetime(df["InsertedDate"], errors="coerce")

    for col in [
        "RefundInitializeDate", "VisitDate", "DischargeDate",
        "RecDate", "OldRecDate", "InsertedDate",
    ]:
        if col in df.columns:
            df[col] = df[col].apply(_refund_tracker_fmt_dt)

    for col in [
        "RegNo", "PatientName", "PatientType", "CorpType", "VisitNo",
        "RefundStatus", "AdminStatus", "CorpStatus", "AccountStatus",
        "PatientBankName", "PatientAccountNo", "PatientBankIFSC",
        "PatientAccHolderName", "PatientRelationName", "UTRNo", "RefundRemark",
        "AccountRemark", "CorpRemarks", "ReceiptNo", "PaymentMode", "ReceiptType",
        "CancelStatus", "LinkedUserName",
    ]:
        if col in df.columns:
            df[col] = df[col].apply(_refund_tracker_norm_text)

    for col in ["RefundStatus", "AdminStatus", "CorpStatus", "AccountStatus"]:
        if col in df.columns:
            df[col] = df[col].apply(_refund_tracker_status_label)

    for col in ["PatientType", "CorpType"]:
        if col in df.columns:
            df[col] = df[col].apply(lambda v: _refund_tracker_norm_text(v, "Unknown"))

    details_df = df[df["RecId"].notna()].copy()
    if details_df.empty:
        details_df = pd.DataFrame(columns=REFUND_TRACKER_DETAIL_COLUMNS)
    else:
        details_df = details_df.sort_values(
            ["RefundId", "_RecDateSort", "_InsertedDateSort", "RecId"],
            ascending=[False, False, False, False],
            na_position="last",
            kind="stable",
        )
        details_df["RecId"] = pd.to_numeric(details_df["RecId"], errors="coerce").fillna(0).astype(int)
        details_df["RefundId"] = pd.to_numeric(details_df["RefundId"], errors="coerce").fillna(0).astype(int)
        details_df["RefRecAmount"] = pd.to_numeric(details_df["RefRecAmount"], errors="coerce").fillna(0.0)
        details_df["ReceiptAmount"] = pd.to_numeric(details_df["ReceiptAmount"], errors="coerce").fillna(0.0)
        details_df["OldReceiptId"] = pd.to_numeric(details_df["OldReceiptId"], errors="coerce")
        details_df = details_df[REFUND_TRACKER_DETAIL_COLUMNS]

    masters_df = df.sort_values(
        ["_RefundInitializeDateSort", "RefundId"],
        ascending=[False, False],
        na_position="last",
        kind="stable",
    ).drop_duplicates(subset=["RefundId"], keep="first")

    if details_df.empty:
        masters_df["AttachedReceiptCount"] = 0
        masters_df["AttachedReceiptAmount"] = 0.0
    else:
        detail_agg = (
            details_df.groupby("RefundId", dropna=False)
            .agg(
                AttachedReceiptCount=("RecId", "count"),
                AttachedReceiptAmount=("RefRecAmount", "sum"),
            )
            .reset_index()
        )
        masters_df = masters_df.merge(detail_agg, on="RefundId", how="left")
        masters_df["AttachedReceiptCount"] = (
            pd.to_numeric(masters_df["AttachedReceiptCount"], errors="coerce").fillna(0).astype(int)
        )
        masters_df["AttachedReceiptAmount"] = (
            pd.to_numeric(masters_df["AttachedReceiptAmount"], errors="coerce").fillna(0.0).astype(float)
        )

    for col in [
        "TotalReceiveAmt", "RefundAmt", "RefundDeductionAmt",
        "AccountDeductionAmt", "CorpDeductionAmt",
    ]:
        masters_df[col] = pd.to_numeric(masters_df[col], errors="coerce").fillna(0.0).astype(float)

    masters_df["TotalDeductionAmt"] = (
        masters_df["RefundDeductionAmt"]
        + masters_df["AccountDeductionAmt"]
        + masters_df["CorpDeductionAmt"]
    )

    for col in REFUND_TRACKER_MASTER_COLUMNS:
        if col not in masters_df.columns:
            masters_df[col] = None
    masters_df = masters_df[REFUND_TRACKER_MASTER_COLUMNS].copy()
    masters_df["RefundId"] = pd.to_numeric(masters_df["RefundId"], errors="coerce").fillna(0).astype(int)
    masters_df["AttachedReceiptCount"] = (
        pd.to_numeric(masters_df["AttachedReceiptCount"], errors="coerce").fillna(0).astype(int)
    )
    masters_df["AttachedReceiptAmount"] = (
        pd.to_numeric(masters_df["AttachedReceiptAmount"], errors="coerce").fillna(0.0).astype(float)
    )

    return masters_df.reset_index(drop=True), details_df.reset_index(drop=True)


def _compute_refund_tracker_kpis(masters_df: pd.DataFrame) -> dict:
    empty_payload = {
        "summary": {
            "total_refunds": 0,
            "total_received": 0.0,
            "total_refund_amount": 0.0,
            "total_deductions": 0.0,
            "avg_refund": 0.0,
        },
        "patient_type_segments": [],
        "corp_type_segments": [],
        "status_summary": {
            "refund_status": [],
            "admin_status": [],
            "corp_status": [],
            "account_status": [],
        },
    }
    if masters_df is None or masters_df.empty:
        return empty_payload

    work = masters_df.copy()
    for col in ["TotalReceiveAmt", "RefundAmt", "TotalDeductionAmt"]:
        work[col] = pd.to_numeric(work[col], errors="coerce").fillna(0.0)

    total_refunds = int(len(work))
    total_received = float(work["TotalReceiveAmt"].sum())
    total_refund_amount = float(work["RefundAmt"].sum())
    total_deductions = float(work["TotalDeductionAmt"].sum())
    avg_refund = float(total_refund_amount / total_refunds) if total_refunds else 0.0

    def _segment(col_name: str):
        grp = (
            work.groupby(col_name, dropna=False)
            .agg(
                count=("RefundId", "count"),
                refund_amount=("RefundAmt", "sum"),
                received_amount=("TotalReceiveAmt", "sum"),
            )
            .reset_index()
            .rename(columns={col_name: "name"})
            .sort_values(["refund_amount", "count"], ascending=[False, False], kind="stable")
        )
        out = []
        for _, row in grp.iterrows():
            out.append({
                "name": _refund_tracker_norm_text(row.get("name"), "Unknown"),
                "count": int(row.get("count") or 0),
                "refund_amount": float(row.get("refund_amount") or 0.0),
                "received_amount": float(row.get("received_amount") or 0.0),
            })
        return out

    def _status_breakup(col_name: str):
        grp = (
            work.groupby(col_name, dropna=False)
            .size()
            .reset_index(name="count")
            .sort_values(["count", col_name], ascending=[False, True], kind="stable")
        )
        out = []
        for _, row in grp.iterrows():
            out.append({
                "name": _refund_tracker_status_label(row.get(col_name)),
                "count": int(row.get("count") or 0),
            })
        return out

    return {
        "summary": {
            "total_refunds": total_refunds,
            "total_received": total_received,
            "total_refund_amount": total_refund_amount,
            "total_deductions": total_deductions,
            "avg_refund": avg_refund,
        },
        "patient_type_segments": _segment("PatientType"),
        "corp_type_segments": _segment("CorpType"),
        "status_summary": {
            "refund_status": _status_breakup("RefundStatus"),
            "admin_status": _status_breakup("AdminStatus"),
            "corp_status": _status_breakup("CorpStatus"),
            "account_status": _status_breakup("AccountStatus"),
        },
    }


def _refund_tracker_filter_options(masters_df: pd.DataFrame) -> dict:
    if masters_df is None or masters_df.empty:
        return {
            "refund_status": [],
            "admin_status": [],
            "corp_status": [],
            "account_status": [],
            "patient_type": [],
            "corp_type": [],
        }

    def _vals(col_name: str):
        series = masters_df.get(col_name, pd.Series(dtype=object))
        values = {_refund_tracker_norm_text(v) for v in series.tolist() if _refund_tracker_norm_text(v)}
        return sorted(values, key=lambda x: x.lower())

    return {
        "refund_status": _vals("RefundStatus"),
        "admin_status": _vals("AdminStatus"),
        "corp_status": _vals("CorpStatus"),
        "account_status": _vals("AccountStatus"),
        "patient_type": _vals("PatientType"),
        "corp_type": _vals("CorpType"),
    }


def _refund_tracker_normalize_filter_value(value) -> str:
    token = str(value or "").strip()
    if not token:
        return "all"
    if token.lower() in {"all", "*"}:
        return "all"
    return token


def _apply_refund_tracker_filters(masters_df: pd.DataFrame, details_df: pd.DataFrame, filters: dict):
    masters = masters_df.copy() if masters_df is not None else pd.DataFrame(columns=REFUND_TRACKER_MASTER_COLUMNS)
    details = details_df.copy() if details_df is not None else pd.DataFrame(columns=REFUND_TRACKER_DETAIL_COLUMNS)
    filters = filters or {}

    filter_map = [
        ("refund_status", "RefundStatus"),
        ("admin_status", "AdminStatus"),
        ("corp_status", "CorpStatus"),
        ("account_status", "AccountStatus"),
        ("patient_type", "PatientType"),
        ("corp_type", "CorpType"),
    ]
    for filter_key, col_name in filter_map:
        selected = _refund_tracker_normalize_filter_value(filters.get(filter_key))
        if selected == "all":
            continue
        masters = masters[
            masters[col_name].astype(str).str.strip().str.lower() == selected.lower()
        ]

    if masters.empty:
        return masters.reset_index(drop=True), details.iloc[0:0].copy()

    selected_ids = set(
        pd.to_numeric(masters["RefundId"], errors="coerce").dropna().astype(int).tolist()
    )
    detail_scope = details[
        pd.to_numeric(details["RefundId"], errors="coerce").fillna(-1).astype(int).isin(selected_ids)
    ].copy()

    query = str(filters.get("search") or "").strip().lower()
    if query:
        def _row_has_query(row):
            for val in row.values:
                if val is None:
                    continue
                if query in str(val).lower():
                    return True
            return False

        master_mask = masters.apply(_row_has_query, axis=1) if not masters.empty else pd.Series(dtype=bool)
        matched_ids = set(
            pd.to_numeric(masters.loc[master_mask, "RefundId"], errors="coerce").dropna().astype(int).tolist()
        )
        if not detail_scope.empty:
            detail_mask = detail_scope.apply(_row_has_query, axis=1)
            matched_ids.update(
                pd.to_numeric(detail_scope.loc[detail_mask, "RefundId"], errors="coerce").dropna().astype(int).tolist()
            )
        if matched_ids:
            masters = masters[
                pd.to_numeric(masters["RefundId"], errors="coerce").fillna(-1).astype(int).isin(matched_ids)
            ]
        else:
            masters = masters.iloc[0:0].copy()

    final_ids = set(
        pd.to_numeric(masters["RefundId"], errors="coerce").dropna().astype(int).tolist()
    )
    details = detail_scope[
        pd.to_numeric(detail_scope["RefundId"], errors="coerce").fillna(-1).astype(int).isin(final_ids)
    ].copy()

    return masters.reset_index(drop=True), details.reset_index(drop=True)


def _build_refund_tracker_excel(
    unit: str,
    from_date: str,
    to_date: str,
    filters: dict,
    exported_by: str,
):
    df_raw = data_fetch.fetch_refund_tracker_raw(unit, from_date, to_date)
    if df_raw is None:
        return None, None, "Database error"

    masters_df, details_df = _build_refund_tracker_frames(df_raw)
    masters_df, details_df = _apply_refund_tracker_filters(masters_df, details_df, filters or {})
    if masters_df.empty:
        return None, None, "No data available to export"

    kpis = _compute_refund_tracker_kpis(masters_df)
    status_summary = kpis.get("status_summary") or {}
    output = io.BytesIO()
    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")

    def _filter_label(value):
        token = _refund_tracker_normalize_filter_value(value)
        return "All" if token == "all" else token

    filter_line = (
        "Search: {search} | Refund Status: {refund_status} | Admin Status: {admin_status} | "
        "Corp Status: {corp_status} | Account Status: {account_status} | "
        "Patient Type: {patient_type} | Corp Type: {corp_type}"
    ).format(
        search=_refund_tracker_norm_text((filters or {}).get("search"), "All"),
        refund_status=_filter_label((filters or {}).get("refund_status")),
        admin_status=_filter_label((filters or {}).get("admin_status")),
        corp_status=_filter_label((filters or {}).get("corp_status")),
        account_status=_filter_label((filters or {}).get("account_status")),
        patient_type=_filter_label((filters or {}).get("patient_type")),
        corp_type=_filter_label((filters or {}).get("corp_type")),
    )

    with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
        wb = writer.book
        title_fmt = wb.add_format({
            "bold": True,
            "font_size": 14,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#1E3A8A",
            "font_color": "white",
        })
        subtitle_fmt = wb.add_format({"bold": True, "font_size": 10, "align": "center", "valign": "vcenter"})
        meta_fmt = wb.add_format({"font_size": 9, "align": "left", "valign": "vcenter"})
        section_fmt = wb.add_format({"bold": True, "font_size": 10, "bg_color": "#F1F5F9"})
        header_fmt = wb.add_format({
            "bold": True,
            "bg_color": "#1E3A8A",
            "font_color": "white",
            "border": 1,
            "align": "center",
            "valign": "vcenter",
        })
        text_fmt = wb.add_format({"border": 1, "align": "left", "valign": "vcenter"})
        int_fmt = wb.add_format({"border": 1, "align": "right", "valign": "vcenter", "num_format": "#,##0"})
        id_plain_fmt = wb.add_format({"border": 1, "align": "right", "valign": "vcenter", "num_format": "0"})
        money_fmt = wb.add_format({"border": 1, "align": "right", "valign": "vcenter", "num_format": "#,##,##0.00"})
        pct_fmt = wb.add_format({"border": 1, "align": "right", "valign": "vcenter", "num_format": "0.00%"})
        date_fmt = wb.add_format({"border": 1, "align": "center", "valign": "vcenter", "num_format": "yyyy-mm-dd hh:mm:ss"})

        ws_sum = wb.add_worksheet("Summary")
        writer.sheets["Summary"] = ws_sum
        ws_sum.merge_range(0, 0, 0, 5, "Refund Tracker MIS - Summary", title_fmt)
        ws_sum.merge_range(1, 0, 1, 5, f"Unit: {unit} | Date Range: {from_date} to {to_date}", subtitle_fmt)
        ws_sum.merge_range(2, 0, 2, 5, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)
        ws_sum.merge_range(3, 0, 3, 5, f"Applied Filters: {filter_line}", meta_fmt)

        summary = kpis.get("summary") or {}
        metrics = [
            ("Total Refunds", int(summary.get("total_refunds") or 0), int_fmt),
            ("Total Received", float(summary.get("total_received") or 0.0), money_fmt),
            ("Total Refund Amount", float(summary.get("total_refund_amount") or 0.0), money_fmt),
            ("Total Deductions", float(summary.get("total_deductions") or 0.0), money_fmt),
            ("Average Refund", float(summary.get("avg_refund") or 0.0), money_fmt),
        ]
        row_ptr = 5
        ws_sum.write(row_ptr, 0, "Metric", header_fmt)
        ws_sum.write(row_ptr, 1, "Value", header_fmt)
        row_ptr += 1
        for label, value, value_fmt in metrics:
            ws_sum.write(row_ptr, 0, label, text_fmt)
            ws_sum.write(row_ptr, 1, value, value_fmt)
            row_ptr += 1

        total_refunds = int(summary.get("total_refunds") or 0)
        total_received = float(summary.get("total_received") or 0.0)
        total_deductions = float(summary.get("total_deductions") or 0.0)
        deduction_specs = [
            ("Refund Stage", "RefundDeductionAmt"),
            ("Account Stage", "AccountDeductionAmt"),
            ("Corp Stage", "CorpDeductionAmt"),
        ]
        deduction_analysis_rows = []
        for stage_name, col_name in deduction_specs:
            amount = float(pd.to_numeric(masters_df.get(col_name, 0.0), errors="coerce").fillna(0.0).sum())
            with_deduction = int(
                (pd.to_numeric(masters_df.get(col_name, 0.0), errors="coerce").fillna(0.0) > 0).sum()
            )
            pct_of_total_ded = (amount / total_deductions) if total_deductions else 0.0
            pct_of_total_recv = (amount / total_received) if total_received else 0.0
            coverage_pct = (with_deduction / total_refunds) if total_refunds else 0.0
            deduction_analysis_rows.append({
                "stage": stage_name,
                "amount": amount,
                "pct_total_ded": pct_of_total_ded,
                "pct_total_recv": pct_of_total_recv,
                "with_deduction": with_deduction,
                "coverage_pct": coverage_pct,
            })

        row_ptr += 1
        ws_sum.merge_range(row_ptr, 0, row_ptr, 5, "Deduction Analysis By Stage", section_fmt)
        row_ptr += 1
        ws_sum.write_row(
            row_ptr,
            0,
            [
                "Stage",
                "Deduction Amount",
                "% of Total Deductions",
                "% of Total Received",
                "Refunds With Deduction",
                "Coverage %",
            ],
            header_fmt,
        )
        row_ptr += 1
        for drow in deduction_analysis_rows:
            ws_sum.write(row_ptr, 0, drow["stage"], text_fmt)
            ws_sum.write(row_ptr, 1, drow["amount"], money_fmt)
            ws_sum.write(row_ptr, 2, drow["pct_total_ded"], pct_fmt)
            ws_sum.write(row_ptr, 3, drow["pct_total_recv"], pct_fmt)
            ws_sum.write(row_ptr, 4, drow["with_deduction"], int_fmt)
            ws_sum.write(row_ptr, 5, drow["coverage_pct"], pct_fmt)
            row_ptr += 1

        ws_sum.write(row_ptr, 0, "Total", header_fmt)
        ws_sum.write(row_ptr, 1, total_deductions, money_fmt)
        ws_sum.write(row_ptr, 2, 1.0 if total_deductions else 0.0, pct_fmt)
        ws_sum.write(row_ptr, 3, (total_deductions / total_received) if total_received else 0.0, pct_fmt)
        ws_sum.write(row_ptr, 4, total_refunds, int_fmt)
        ws_sum.write(row_ptr, 5, 1.0 if total_refunds else 0.0, pct_fmt)

        row_ptr += 1
        ws_sum.merge_range(row_ptr, 0, row_ptr, 3, "Patient Type Segments", section_fmt)
        row_ptr += 1
        ws_sum.write_row(row_ptr, 0, ["Patient Type", "Count", "Refund Amount", "Received Amount"], header_fmt)
        row_ptr += 1
        for seg in (kpis.get("patient_type_segments") or []):
            ws_sum.write(row_ptr, 0, seg.get("name"), text_fmt)
            ws_sum.write(row_ptr, 1, int(seg.get("count") or 0), int_fmt)
            ws_sum.write(row_ptr, 2, float(seg.get("refund_amount") or 0.0), money_fmt)
            ws_sum.write(row_ptr, 3, float(seg.get("received_amount") or 0.0), money_fmt)
            row_ptr += 1

        row_ptr += 1
        ws_sum.merge_range(row_ptr, 0, row_ptr, 3, "Corp Type Segments", section_fmt)
        row_ptr += 1
        ws_sum.write_row(row_ptr, 0, ["Corp Type", "Count", "Refund Amount", "Received Amount"], header_fmt)
        row_ptr += 1
        for seg in (kpis.get("corp_type_segments") or []):
            ws_sum.write(row_ptr, 0, seg.get("name"), text_fmt)
            ws_sum.write(row_ptr, 1, int(seg.get("count") or 0), int_fmt)
            ws_sum.write(row_ptr, 2, float(seg.get("refund_amount") or 0.0), money_fmt)
            ws_sum.write(row_ptr, 3, float(seg.get("received_amount") or 0.0), money_fmt)
            row_ptr += 1

        row_ptr += 1
        ws_sum.merge_range(row_ptr, 0, row_ptr, 4, "Status Summary", section_fmt)
        row_ptr += 1
        ws_sum.write_row(row_ptr, 0, ["Status Type", "Status", "Count"], header_fmt)
        row_ptr += 1
        status_labels = [
            ("refund_status", "Refund Status"),
            ("admin_status", "Admin Status"),
            ("corp_status", "Corp Status"),
            ("account_status", "Account Status"),
        ]
        for status_key, status_label in status_labels:
            rows = status_summary.get(status_key) or []
            if not rows:
                ws_sum.write(row_ptr, 0, status_label, text_fmt)
                ws_sum.write(row_ptr, 1, "No Data", text_fmt)
                ws_sum.write(row_ptr, 2, 0, int_fmt)
                row_ptr += 1
                continue
            for idx, status_row in enumerate(rows):
                ws_sum.write(row_ptr, 0, status_label, text_fmt)
                ws_sum.write(row_ptr, 1, status_row.get("name"), text_fmt)
                ws_sum.write(row_ptr, 2, int(status_row.get("count") or 0), int_fmt)
                row_ptr += 1

        ws_sum.set_column(0, 0, 26)
        ws_sum.set_column(1, 1, 22)
        ws_sum.set_column(2, 3, 18)
        ws_sum.set_column(4, 5, 14)
        ws_sum.freeze_panes(6, 0)
        ws_sum.set_footer("&LASARFI HOSPITAL&RPage &P of &N")

        masters_export_df = masters_df[REFUND_TRACKER_MASTER_COLUMNS].copy()
        details_export_df = details_df[REFUND_TRACKER_DETAIL_COLUMNS].copy()

        def _write_data_sheet(sheet_name: str, title: str, frame: pd.DataFrame):
            frame = frame.copy()
            frame.to_excel(writer, sheet_name=sheet_name, index=False, startrow=6)
            ws = writer.sheets[sheet_name]
            last_col = max(0, len(frame.columns) - 1)
            ws.merge_range(0, 0, 0, last_col, title, title_fmt)
            ws.merge_range(1, 0, 1, last_col, f"Unit: {unit} | Date Range: {from_date} to {to_date}", subtitle_fmt)
            ws.merge_range(2, 0, 2, last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)
            ws.merge_range(3, 0, 3, last_col, filter_line, meta_fmt)
            ws.merge_range(4, 0, 4, last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)
            id_no_comma_keys = {"refundid", "recid", "oldreceiptid"}
            count_keys = {"attachedreceiptcount"}
            money_keys = {
                "totalreceiveamt", "refundamt", "refunddeductionamt", "accountdeductionamt",
                "corpdeductionamt", "totaldeductionamt", "attachedreceiptamount",
                "refrecamount", "receiptamount",
            }
            col_cfg = {}
            for col_idx, col_name in enumerate(frame.columns):
                ws.write(6, col_idx, col_name, header_fmt)
                key = str(col_name).lower()
                width = 16
                fmt = text_fmt
                if "date" in key or "time" in key:
                    width = 19
                    fmt = date_fmt
                elif key in id_no_comma_keys:
                    width = 14
                    fmt = id_plain_fmt
                elif key in count_keys:
                    width = 14
                    fmt = int_fmt
                elif key in money_keys:
                    width = 18
                    fmt = money_fmt
                elif key in {"patientname", "refundremark", "accountremark", "corpremarks", "patientbankname"}:
                    width = 24
                elif key in {"patientaccountno", "patientbankifsc", "patientaccholdername", "patientrelationname"}:
                    width = 20
                ws.set_column(col_idx, col_idx, width)
                col_cfg[col_idx] = (key, fmt)

            # Apply bordered cell formats only to actual data rows to avoid border bleed.
            if not frame.empty:
                for row_idx, row_vals in enumerate(frame.itertuples(index=False, name=None), start=7):
                    for col_idx, raw_val in enumerate(row_vals):
                        key, fmt = col_cfg.get(col_idx, ("", text_fmt))
                        if pd.isna(raw_val):
                            ws.write_blank(row_idx, col_idx, None, fmt)
                            continue

                        if "date" in key or "time" in key:
                            dt_val = pd.to_datetime(raw_val, errors="coerce")
                            if pd.notna(dt_val):
                                ws.write_datetime(row_idx, col_idx, dt_val.to_pydatetime(), fmt)
                            else:
                                ws.write(row_idx, col_idx, str(raw_val), text_fmt)
                            continue

                        if key in id_no_comma_keys:
                            num = pd.to_numeric(raw_val, errors="coerce")
                            if pd.notna(num):
                                ws.write_number(row_idx, col_idx, float(num), id_plain_fmt)
                            else:
                                ws.write(row_idx, col_idx, str(raw_val), text_fmt)
                            continue

                        if key in count_keys:
                            num = pd.to_numeric(raw_val, errors="coerce")
                            if pd.notna(num):
                                ws.write_number(row_idx, col_idx, float(num), int_fmt)
                            else:
                                ws.write(row_idx, col_idx, str(raw_val), text_fmt)
                            continue

                        if key in money_keys:
                            num = pd.to_numeric(raw_val, errors="coerce")
                            if pd.notna(num):
                                ws.write_number(row_idx, col_idx, float(num), money_fmt)
                            else:
                                ws.write(row_idx, col_idx, str(raw_val), text_fmt)
                            continue

                        ws.write(row_idx, col_idx, raw_val, fmt)
            ws.freeze_panes(7, 0)
            ws.set_footer("&LASARFI HOSPITAL&RPage &P of &N")

        _write_data_sheet("Refund Masters", "Refund Tracker - Master Records", masters_export_df)
        _write_data_sheet("Receipt Details", "Refund Tracker - Linked Receipt Details", details_export_df)

    output.seek(0)
    filename = f"Refund_Tracker_{unit}_{from_date}_to_{to_date}.xlsx"
    return output.getvalue(), filename, None


def _run_refund_tracker_excel_job(
    job_id: str,
    unit: str,
    from_date: str,
    to_date: str,
    filters: dict,
    exported_by: str,
):
    _excel_job_update(job_id, state="running")
    try:
        data, filename, err = _build_refund_tracker_excel(unit, from_date, to_date, filters, exported_by)
        if not data:
            _excel_job_update(job_id, state="error", error=err or "No data available to export")
            return
        _export_cache_put_bytes("refund_tracker_xlsx_job", data, job_id)
        _excel_job_update(job_id, state="done", filename=filename)
    except Exception as exc:
        _excel_job_update(job_id, state="error", error=str(exc))


@app.route('/api/mis/refund_tracker')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_refund_tracker():
    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return jsonify({"status": "error", "message": "No unit available"}), 400
    if allowed_units and target_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403

    df_raw = data_fetch.fetch_refund_tracker_raw(target_unit, from_date, to_date)
    if df_raw is None:
        return jsonify({"status": "error", "message": "Database error"}), 500

    masters_df, details_df = _build_refund_tracker_frames(df_raw)
    kpis = _compute_refund_tracker_kpis(masters_df)
    filter_options = _refund_tracker_filter_options(masters_df)

    if masters_df.empty:
        return jsonify({
            "status": "success",
            "unit": target_unit,
            "count": 0,
            "masters": [],
            "details": {},
            "kpis": kpis,
            "filters": filter_options,
        }), 200

    masters_payload_df = masters_df.replace({pd.NaT: None, np.nan: None, np.inf: None, -np.inf: None})
    masters_payload_df = masters_payload_df.where(pd.notna(masters_payload_df), None)
    masters_records = _sanitize_json_payload(masters_payload_df.to_dict(orient="records"))

    details_payload_df = details_df.replace({pd.NaT: None, np.nan: None, np.inf: None, -np.inf: None})
    details_payload_df = details_payload_df.where(pd.notna(details_payload_df), None)
    details_records = details_payload_df.to_dict(orient="records")
    details_map = {}
    for row in details_records:
        rid_val = row.get("RefundId")
        if rid_val is None:
            continue
        try:
            rid_key = str(int(float(rid_val)))
        except Exception:
            rid_key = str(rid_val)
        details_map.setdefault(rid_key, []).append(row)

    return jsonify({
        "status": "success",
        "unit": target_unit,
        "count": int(len(masters_records)),
        "masters": masters_records,
        "details": _sanitize_json_payload(details_map),
        "kpis": _sanitize_json_payload(kpis),
        "filters": _sanitize_json_payload(filter_options),
    })


@app.route('/api/mis/refund_tracker/export_excel_job', methods=["POST"])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_refund_tracker_export_excel_job():
    payload = request.get_json(silent=True) or {}
    unit = (payload.get("unit") or request.args.get("unit") or "").strip()
    from_date = (payload.get("from") or payload.get("from_date") or request.args.get("from") or "").strip()
    to_date = (payload.get("to") or payload.get("to_date") or request.args.get("to") or "").strip()
    if not from_date:
        from_date = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    if not to_date:
        to_date = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _allowed_units_for_session()
    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return jsonify({"status": "error", "message": "Please select a unit"}), 400
    if unit not in allowed_units:
        return jsonify({"status": "error", "message": f"Unit {unit} not permitted"}), 403

    filters = {
        "search": payload.get("search") or "",
        "refund_status": payload.get("refund_status") or payload.get("refundStatus") or "all",
        "admin_status": payload.get("admin_status") or payload.get("adminStatus") or "all",
        "corp_status": payload.get("corp_status") or payload.get("corpStatus") or "all",
        "account_status": payload.get("account_status") or payload.get("accountStatus") or "all",
        "patient_type": payload.get("patient_type") or payload.get("patientType") or "all",
        "corp_type": payload.get("corp_type") or payload.get("corpType") or "all",
    }

    exported_by = session.get("username") or session.get("user") or "Unknown"
    job_id = token_hex(16)
    _excel_job_update(job_id, state="queued", filename=None)
    EXPORT_EXECUTOR.submit(
        _run_refund_tracker_excel_job,
        job_id,
        unit,
        from_date,
        to_date,
        filters,
        exported_by,
    )
    return jsonify({"status": "queued", "job_id": job_id})


@app.route('/api/mis/refund_tracker/export_excel_job_status')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_refund_tracker_export_excel_job_status():
    job_id = (request.args.get("job_id") or "").strip()
    if not job_id:
        return jsonify({"status": "error", "message": "Missing job id"}), 400
    entry = _excel_job_get(job_id)
    if not entry:
        return jsonify({"status": "error", "message": "Job not found"}), 404
    return jsonify({
        "status": "success",
        "state": entry.get("state"),
        "error": entry.get("error"),
        "filename": entry.get("filename"),
    })


@app.route('/api/mis/refund_tracker/export_excel_job_result')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_refund_tracker_export_excel_job_result():
    job_id = (request.args.get("job_id") or "").strip()
    if not job_id:
        return "Missing job id", 400
    entry = _excel_job_get(job_id)
    if not entry:
        return "Job not found", 404
    if entry.get("state") != "done":
        return "Job not ready", 409
    data = _export_cache_get_bytes("refund_tracker_xlsx_job", job_id)
    if not data:
        return "Export expired", 404
    filename = entry.get("filename") or "Refund_Tracker.xlsx"
    return send_file(
        io.BytesIO(data),
        as_attachment=True,
        download_name=filename,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )


@app.route('/api/mis/collections')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_collections():
    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return jsonify({"status": "error", "message": "No unit available"}), 400
    if allowed_units and target_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403

    df = data_fetch.fetch_receipt_summary(target_unit, from_date, to_date)
    if df is None:
        return jsonify({"status": "error", "message": "Database error"}), 500
    if df.empty:
        return jsonify({"status": "success", "data": [], "unit": target_unit, "count": 0}), 200

    # Clean up NaT/NaN and convert datetimes to strings for JSON safety
    for col in df.columns:
        if pd.api.types.is_datetime64_any_dtype(df[col]):
            df[col] = pd.to_datetime(df[col], errors="coerce").dt.strftime("%Y-%m-%d %H:%M:%S")
    # Clean NaN/NaT so JSON doesn't emit bare NaN tokens
    df = df.replace({pd.NaT: None, np.nan: None})
    df = df.where(pd.notna(df), None)

    records = df.to_dict(orient="records")
    return jsonify({"status": "success", "data": records, "unit": target_unit, "count": len(records)})


def _normalize_payment_mode_approval(value) -> str:
    token = str(value or "").strip().lower()
    if token in {"1", "y", "yes", "approved", "approve", "a", "true"}:
        return "Approved"
    if token in {"2", "n", "no", "reject", "rejected", "r", "false"}:
        return "Rejected"
    return "Pending"


def _load_payment_mode_updates_df(target_unit: str, from_date: str, to_date: str):
    df = data_fetch.fetch_payment_mode_change_updates(target_unit, from_date, to_date)
    if df is None:
        return None
    if df.empty:
        return df

    df = _clean_df_columns(df.copy())
    for col in [
        "Id", "VisitId", "ReceiptId", "PaymentModeId", "UpdatedBy", "ApprovedBy",
    ]:
        if col in df.columns:
            df[col] = pd.to_numeric(df[col], errors="coerce")

    for col in ["UpdatedOn", "ApprovedDate"]:
        if col in df.columns:
            df[col] = pd.to_datetime(df[col], errors="coerce")

    if "PaymentMode" not in df.columns:
        df["PaymentMode"] = ""
    if "OriginalPaymentModeId" not in df.columns:
        df["OriginalPaymentModeId"] = None
    if "OriginalPaymentMode" not in df.columns:
        df["OriginalPaymentMode"] = ""
    if "UpdatedByName" not in df.columns:
        df["UpdatedByName"] = ""
    if "ApprovedByName" not in df.columns:
        df["ApprovedByName"] = ""
    if "Approval" not in df.columns:
        df["Approval"] = ""
    if "Tag" not in df.columns:
        df["Tag"] = "U"

    df["PaymentMode"] = df["PaymentMode"].astype(str).str.strip()
    df["OriginalPaymentMode"] = df["OriginalPaymentMode"].astype(str).str.strip()
    if "OriginalPaymentModeId" in df.columns:
        df["OriginalPaymentModeId"] = pd.to_numeric(df["OriginalPaymentModeId"], errors="coerce")
    if "OriginalPaymentMode" in df.columns and "PaymentMode" in df.columns:
        df["OriginalPaymentMode"] = df["OriginalPaymentMode"].replace({"nan": "", "None": ""})
        fallback_mask = df["OriginalPaymentMode"].astype(str).str.strip() == ""
        df.loc[fallback_mask, "OriginalPaymentMode"] = df.loc[fallback_mask, "PaymentMode"]
    df["UpdatedByName"] = df["UpdatedByName"].astype(str).str.strip()
    df["ApprovedByName"] = df["ApprovedByName"].astype(str).str.strip()
    df["Tag"] = df["Tag"].astype(str).str.strip()
    df["ApprovalStatus"] = df["Approval"].apply(_normalize_payment_mode_approval)
    return df


@app.route('/api/mis/payment_mode_updates')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_payment_mode_updates():
    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return jsonify({"status": "error", "message": "No unit available"}), 400
    if allowed_units and target_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403

    df = _load_payment_mode_updates_df(target_unit, from_date, to_date)
    if df is None:
        return jsonify({"status": "error", "message": "Database error"}), 500
    if df.empty:
        return jsonify({"status": "success", "data": [], "unit": target_unit, "count": 0}), 200

    payload_df = df.copy()
    for col in ["UpdatedOn", "ApprovedDate"]:
        if col in payload_df.columns:
            payload_df[col] = pd.to_datetime(payload_df[col], errors="coerce").dt.strftime("%Y-%m-%d %H:%M:%S")

    payload_df = payload_df.replace({pd.NaT: None, np.nan: None, np.inf: None, -np.inf: None})
    payload_df = payload_df.where(pd.notna(payload_df), None)
    records = _sanitize_json_payload(payload_df.to_dict(orient="records"))
    return jsonify({"status": "success", "data": records, "unit": target_unit, "count": len(records)})


@app.route('/api/mis/payment_mode_updates/export_excel')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_payment_mode_updates_export_excel():
    import io
    from xlsxwriter.utility import xl_col_to_name

    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return jsonify({"status": "error", "message": "No unit available"}), 400
    if allowed_units and target_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403

    df = _load_payment_mode_updates_df(target_unit, from_date, to_date)
    if df is None:
        return jsonify({"status": "error", "message": "Database error"}), 500
    if df.empty:
        return jsonify({"status": "error", "message": "No data available to export"}), 400

    display_cols = [
        "Id", "ReceiptId", "VisitId", "PatientId", "Patient", "RegNo",
        "OriginalPaymentModeId", "OriginalPaymentMode",
        "PaymentModeId", "PaymentMode",
        "UpdatedBy", "UpdatedByName", "UpdatedOn",
        "Approval", "ApprovalStatus", "ApprovedBy", "ApprovedByName", "ApprovedDate", "Tag",
    ]
    export_df = df[[c for c in display_cols if c in df.columns]].copy()

    total_rows = int(len(export_df))
    approved_count = int((export_df.get("ApprovalStatus", pd.Series(dtype=str)) == "Approved").sum())
    rejected_count = int((export_df.get("ApprovalStatus", pd.Series(dtype=str)) == "Rejected").sum())
    pending_count = int((export_df.get("ApprovalStatus", pd.Series(dtype=str)) == "Pending").sum())
    updater_series = export_df.get("UpdatedByName", pd.Series(dtype=str)).astype(str).str.strip().replace({"nan": "", "None": ""})
    unique_updaters = int(updater_series[updater_series != ""].nunique())
    unique_modes = int(export_df.get("PaymentMode", pd.Series(dtype=str)).astype(str).str.strip().replace({"nan": ""}).nunique())

    mode_summary = (
        export_df.groupby("PaymentMode", dropna=False)
        .agg(
            Updates=("Id", "count"),
            Approved=("ApprovalStatus", lambda s: int((s == "Approved").sum())),
            Rejected=("ApprovalStatus", lambda s: int((s == "Rejected").sum())),
            Pending=("ApprovalStatus", lambda s: int((s == "Pending").sum())),
        )
        .reset_index()
        .sort_values(["Updates", "PaymentMode"], ascending=[False, True], kind="stable")
    )

    output = io.BytesIO()
    exported_by = session.get("username") or session.get("user") or "Unknown"
    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")

    with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
        wb = writer.book
        title_fmt = wb.add_format({"bold": True, "font_size": 14, "font_color": "#1E3A8A", "align": "center"})
        subtitle_fmt = wb.add_format({"bold": True, "font_size": 10, "align": "center"})
        meta_fmt = wb.add_format({"font_size": 9, "align": "left", "valign": "vcenter"})
        header_fmt = wb.add_format({
            "bold": True, "bg_color": "#1E3A8A", "font_color": "white",
            "border": 1, "align": "center", "valign": "vcenter"
        })
        text_fmt = wb.add_format({"align": "left", "valign": "vcenter"})
        int_fmt = wb.add_format({"align": "right", "valign": "vcenter", "num_format": "#,##0"})
        id_fmt = wb.add_format({"align": "right", "valign": "vcenter", "num_format": "0"})
        date_fmt = wb.add_format({"align": "center", "valign": "vcenter", "num_format": "yyyy-mm-dd hh:mm"})
        approved_fmt = wb.add_format({"bg_color": "#ECFDF3"})
        rejected_fmt = wb.add_format({"bg_color": "#FEF2F2"})
        pending_fmt = wb.add_format({"bg_color": "#FFFBEB"})

        ws_sum = wb.add_worksheet("Summary")
        writer.sheets["Summary"] = ws_sum
        ws_sum.merge_range(0, 0, 0, 5, "Payment Mode Change Updates", title_fmt)
        ws_sum.merge_range(1, 0, 1, 5, f"Unit: {target_unit} | Date Range: {from_date} to {to_date}", subtitle_fmt)
        ws_sum.merge_range(2, 0, 2, 5, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)
        ws_sum.merge_range(3, 0, 3, 5, "Source: PaymentModeChageUpdate (Tag = 'U')", meta_fmt)

        metrics = [
            ("Total Updated Receipts", total_rows),
            ("Approved", approved_count),
            ("Pending", pending_count),
            ("Rejected", rejected_count),
            ("Unique Updaters", unique_updaters),
            ("Unique Payment Modes", unique_modes),
        ]
        ws_sum.write(5, 0, "Metric", header_fmt)
        ws_sum.write(5, 1, "Value", header_fmt)
        row_cursor = 6
        for label, value in metrics:
            ws_sum.write(row_cursor, 0, label, text_fmt)
            ws_sum.write(row_cursor, 1, value, int_fmt)
            row_cursor += 1

        mode_start = row_cursor + 2
        ws_sum.write(mode_start, 0, "Payment Mode", header_fmt)
        ws_sum.write(mode_start, 1, "Updates", header_fmt)
        ws_sum.write(mode_start, 2, "Approved", header_fmt)
        ws_sum.write(mode_start, 3, "Pending", header_fmt)
        ws_sum.write(mode_start, 4, "Rejected", header_fmt)
        for idx, (_, mr) in enumerate(mode_summary.iterrows(), start=1):
            r = mode_start + idx
            ws_sum.write(r, 0, str(mr.get("PaymentMode") or "Unknown"), text_fmt)
            ws_sum.write(r, 1, int(mr.get("Updates") or 0), int_fmt)
            ws_sum.write(r, 2, int(mr.get("Approved") or 0), int_fmt)
            ws_sum.write(r, 3, int(mr.get("Pending") or 0), int_fmt)
            ws_sum.write(r, 4, int(mr.get("Rejected") or 0), int_fmt)

        ws_sum.set_column(0, 0, 30)
        ws_sum.set_column(1, 4, 14)

        for id_col_name in ["Id", "ReceiptId", "VisitId", "PatientId", "OriginalPaymentModeId", "PaymentModeId", "UpdatedBy", "ApprovedBy"]:
            if id_col_name in export_df.columns:
                export_df[id_col_name] = pd.to_numeric(export_df[id_col_name], errors="coerce")

        export_df.to_excel(writer, sheet_name="Details", index=False, startrow=4)
        ws = writer.sheets["Details"]
        last_col = len(export_df.columns) - 1
        ws.merge_range(0, 0, 0, last_col, "Payment Mode Change Updates - Details", title_fmt)
        ws.merge_range(1, 0, 1, last_col, f"Unit: {target_unit} | Date Range: {from_date} to {to_date}", subtitle_fmt)
        ws.merge_range(2, 0, 2, last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)
        ws.merge_range(3, 0, 3, last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)
        for col_idx, col_name in enumerate(export_df.columns):
            ws.write(4, col_idx, col_name, header_fmt)
            col_key = str(col_name).lower()
            width = 16
            fmt = text_fmt
            if col_key in {"id", "receiptid", "visitid", "patientid", "originalpaymentmodeid", "paymentmodeid", "updatedby", "approvedby"}:
                width = 12
                fmt = id_fmt
            elif "date" in col_key or "updatedon" in col_key:
                width = 18
                fmt = date_fmt
            elif "name" in col_key or "paymentmode" in col_key or col_key in {"approvalstatus", "patient", "regno"}:
                width = 22
            elif col_key in {"approval", "tag"}:
                width = 12
            ws.set_column(col_idx, col_idx, width, fmt)

        if "ApprovalStatus" in export_df.columns and len(export_df) > 0:
            status_idx = list(export_df.columns).index("ApprovalStatus")
            status_letter = xl_col_to_name(status_idx)
            data_start = 5
            data_end = 4 + len(export_df)
            ws.conditional_format(
                data_start, 0, data_end, last_col,
                {"type": "formula", "criteria": f'=${status_letter}{data_start + 1}=\"Approved\"', "format": approved_fmt},
            )
            ws.conditional_format(
                data_start, 0, data_end, last_col,
                {"type": "formula", "criteria": f'=${status_letter}{data_start + 1}=\"Rejected\"', "format": rejected_fmt},
            )
            ws.conditional_format(
                data_start, 0, data_end, last_col,
                {"type": "formula", "criteria": f'=${status_letter}{data_start + 1}=\"Pending\"', "format": pending_fmt},
            )
        ws.freeze_panes(5, 0)

    output.seek(0)
    filename = f"Payment_Mode_Updates_{target_unit}_{from_date}_to_{to_date}.xlsx"
    return send_file(
        output,
        as_attachment=True,
        download_name=filename,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )


def _build_payment_mode_updates_pdf_buffer(target_unit: str, from_date: str, to_date: str, exported_by: str):
    import io
    from reportlab.lib.pagesizes import A4, landscape
    from reportlab.lib import colors
    from reportlab.lib.units import mm
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer, PageBreak
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_RIGHT
    from xml.sax.saxutils import escape

    df = _load_payment_mode_updates_df(target_unit, from_date, to_date)
    if df is None or df.empty:
        return None

    def _fmt_dt(value):
        try:
            dt_val = pd.to_datetime(value, errors="coerce")
            if pd.isna(dt_val):
                return ""
            return dt_val.strftime("%Y-%m-%d %H:%M")
        except Exception:
            return ""

    total_rows = int(len(df))
    approved_count = int((df["ApprovalStatus"] == "Approved").sum()) if "ApprovalStatus" in df.columns else 0
    rejected_count = int((df["ApprovalStatus"] == "Rejected").sum()) if "ApprovalStatus" in df.columns else 0
    pending_count = int((df["ApprovalStatus"] == "Pending").sum()) if "ApprovalStatus" in df.columns else 0

    mode_summary = (
        df.groupby("PaymentMode", dropna=False)
        .agg(
            Updates=("Id", "count"),
            Approved=("ApprovalStatus", lambda s: int((s == "Approved").sum())),
            Rejected=("ApprovalStatus", lambda s: int((s == "Rejected").sum())),
            Pending=("ApprovalStatus", lambda s: int((s == "Pending").sum())),
        )
        .reset_index()
        .sort_values(["Updates", "PaymentMode"], ascending=[False, True], kind="stable")
    )

    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=landscape(A4),
        topMargin=14 * mm,
        bottomMargin=14 * mm,
        leftMargin=10 * mm,
        rightMargin=10 * mm,
    )
    styles = getSampleStyleSheet()
    style_title = ParagraphStyle("PMUTitle", parent=styles["Heading2"], fontSize=14, alignment=TA_CENTER, textColor=colors.HexColor("#1E3A8A"))
    style_sub = ParagraphStyle("PMUSub", parent=styles["Normal"], fontSize=9, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_meta = ParagraphStyle("PMUMeta", parent=styles["Normal"], fontSize=8, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_td = ParagraphStyle("PMUTd", parent=styles["Normal"], fontSize=8, textColor=colors.black)
    style_td_right = ParagraphStyle("PMUTdRight", parent=styles["Normal"], fontSize=8, textColor=colors.black, alignment=TA_RIGHT)

    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")

    def on_page(canvas, doc_obj):
        canvas.saveState()
        canvas.setFont("Helvetica-Bold", 9)
        canvas.setFillColor(colors.HexColor("#1E3A8A"))
        canvas.drawString(10 * mm, 201 * mm, "ASARFI HOSPITAL - Billing MIS")
        canvas.setFont("Helvetica", 8)
        canvas.setFillColor(colors.black)
        canvas.drawString(10 * mm, 9 * mm, f"Exported By: {exported_by} | Exported At: {exported_at}")
        canvas.drawRightString(287 * mm, 9 * mm, f"Page {doc_obj.page}")
        canvas.restoreState()

    elements = []
    elements.append(Paragraph("Payment Mode Change Updates Report", style_title))
    elements.append(Paragraph(f"Unit: {target_unit} | Date Range: {from_date} to {to_date}", style_sub))
    elements.append(Paragraph("Source Table: PaymentModeChageUpdate (Tag = 'U')", style_meta))
    elements.append(Spacer(1, 6))

    metrics_table = Table(
        [
            ["Metric", "Value"],
            ["Total Updated Receipts", f"{total_rows:,}"],
            ["Approved", f"{approved_count:,}"],
            ["Pending", f"{pending_count:,}"],
            ["Rejected", f"{rejected_count:,}"],
        ],
        colWidths=[70 * mm, 40 * mm],
        hAlign="LEFT",
    )
    metrics_table.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1E3A8A")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("GRID", (0, 0), (-1, -1), 0.25, colors.HexColor("#CBD5E1")),
        ("ALIGN", (1, 1), (1, -1), "RIGHT"),
        ("BACKGROUND", (0, 2), (-1, 2), colors.HexColor("#ECFDF3")),
        ("BACKGROUND", (0, 3), (-1, 3), colors.HexColor("#FFFBEB")),
        ("BACKGROUND", (0, 4), (-1, 4), colors.HexColor("#FEF2F2")),
    ]))
    elements.append(metrics_table)
    elements.append(Spacer(1, 8))

    mode_rows = [[
        Paragraph("Payment Mode", style_td),
        Paragraph("Updates", style_td_right),
        Paragraph("Approved", style_td_right),
        Paragraph("Pending", style_td_right),
        Paragraph("Rejected", style_td_right),
    ]]
    for _, row in mode_summary.iterrows():
        mode_rows.append([
            Paragraph(escape(str(row.get("PaymentMode") or "Unknown")), style_td),
            Paragraph(f"{int(row.get('Updates') or 0):,}", style_td_right),
            Paragraph(f"{int(row.get('Approved') or 0):,}", style_td_right),
            Paragraph(f"{int(row.get('Pending') or 0):,}", style_td_right),
            Paragraph(f"{int(row.get('Rejected') or 0):,}", style_td_right),
        ])
    mode_table = Table(mode_rows, colWidths=[90 * mm, 28 * mm, 28 * mm, 28 * mm, 28 * mm], hAlign="LEFT")
    mode_table.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1E3A8A")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("GRID", (0, 0), (-1, -1), 0.25, colors.HexColor("#CBD5E1")),
    ]))
    elements.append(mode_table)

    elements.append(PageBreak())
    elements.append(Paragraph("Details", style_title))
    elements.append(Spacer(1, 4))

    details_cols = [
        "Id", "ReceiptId", "VisitId", "Patient", "RegNo",
        "OriginalPaymentMode", "PaymentMode", "UpdatedByName", "UpdatedOn",
        "ApprovalStatus", "ApprovedByName", "ApprovedDate",
    ]
    details_cols = [c for c in details_cols if c in df.columns]
    detail_header = [Paragraph(escape(str(c)), style_td) for c in details_cols]
    detail_rows = [detail_header]
    row_statuses = []

    for _, row in df.iterrows():
        row_vals = []
        for col in details_cols:
            val = row.get(col)
            if col in {"UpdatedOn", "ApprovedDate"}:
                text_val = _fmt_dt(val)
            elif col in {"Id", "ReceiptId", "VisitId", "PatientId"}:
                text_val = "" if pd.isna(val) else str(int(float(val)))
            else:
                text_val = "" if val is None or (isinstance(val, float) and np.isnan(val)) else str(val)
            is_num = col in {"Id", "ReceiptId", "VisitId", "PatientId"}
            row_vals.append(Paragraph(escape(text_val), style_td_right if is_num else style_td))
        detail_rows.append(row_vals)
        row_statuses.append(str(row.get("ApprovalStatus") or "Pending"))

    col_widths = [14 * mm, 17 * mm, 17 * mm, 34 * mm, 22 * mm, 30 * mm, 30 * mm, 28 * mm, 27 * mm, 24 * mm, 28 * mm, 27 * mm]
    col_widths = col_widths[:len(details_cols)]
    details_table = Table(detail_rows, colWidths=col_widths, repeatRows=1)
    style_cmds = [
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1E3A8A")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("GRID", (0, 0), (-1, -1), 0.25, colors.HexColor("#CBD5E1")),
        ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
    ]
    for idx, status in enumerate(row_statuses, start=1):
        if status == "Approved":
            style_cmds.append(("BACKGROUND", (0, idx), (-1, idx), colors.HexColor("#ECFDF3")))
        elif status == "Rejected":
            style_cmds.append(("BACKGROUND", (0, idx), (-1, idx), colors.HexColor("#FEF2F2")))
        else:
            style_cmds.append(("BACKGROUND", (0, idx), (-1, idx), colors.HexColor("#FFFBEB")))
    details_table.setStyle(TableStyle(style_cmds))
    elements.append(details_table)

    doc.build(elements, onFirstPage=on_page, onLaterPages=on_page)
    buffer.seek(0)
    return buffer


@app.route('/api/mis/payment_mode_updates/export_pdf')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_payment_mode_updates_export_pdf():
    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return "No unit available", 400
    if allowed_units and target_unit not in allowed_units:
        return "Unit not allowed", 403

    exported_by = session.get("username") or session.get("user") or "Unknown"
    buffer = _build_payment_mode_updates_pdf_buffer(target_unit, from_date, to_date, exported_by)
    if buffer is None:
        return "No data available to export", 404

    return send_file(
        buffer,
        mimetype="application/pdf",
        as_attachment=True,
        download_name=f"Payment_Mode_Updates_{target_unit}_{from_date}_to_{to_date}.pdf",
    )


@app.route('/api/mis/compliance')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_compliance():
    """
    Billing-Collection compliance:
    - Loads receipts (Usp_ReceiptSummary) and revenue (Usp_CorpsubmitBillSummaryupdate)
    - Matches receipts to revenue by:
        * Hospital (default): Visit_ID
        * OP Pharmacy (PH) or IP Pharmacy (PI): Bill_ID / BillNo
    - Receipts drive; unmatched diff is Suspense.
    """
    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _analytics_allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return jsonify({"status": "error", "message": "No unit available"}), 400
    if allowed_units and target_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403

    rec_df = data_fetch.fetch_receipt_summary(target_unit, from_date, to_date)
    rev_df = _fetch_revenue_limited(target_unit, from_date, to_date)
    if rec_df is None:
        return jsonify({"status": "error", "message": "Unable to load receipts"}), 500
    if rec_df.empty:
        return jsonify({"status": "success", "data": [], "unit": target_unit, "count": 0}), 200

    if rev_df is None or rev_df.empty:
        rev_df = pd.DataFrame()

    rec_df = _clean_df_columns(rec_df)
    rev_df = _clean_df_columns(rev_df)

    # Backdated highlight now based on bill date < receipt date within current range
    prior_receipt_keys = set()
    prior_df = pd.DataFrame()

    def col_in(df, candidates):
        cols = {c.lower(): c for c in df.columns}
        for cand in candidates:
            if cand.lower() in cols:
                return cols[cand.lower()]
        return None

    def norm_key(val):
        if val is None:
            return ""
        s = str(val).strip()
        # If numeric-looking with trailing .0, strip it
        try:
            f = float(s)
            if f.is_integer():
                return str(int(f))
            return str(f)
        except Exception:
            pass
        if "." in s and s.endswith("0"):
            s = s.rstrip("0").rstrip(".")
        return s

    # Revenue maps
    rev_visit_col = col_in(rev_df, ["Visit_ID", "VisitID", "VisitId", "Visit_No", "VisitNo"])
    rev_bill_col = col_in(rev_df, ["Bill_ID", "BillID", "BillId"])
    rev_billno_col = col_in(rev_df, ["BillNo", "Bill_No"])
    rev_billdate_col = col_in(rev_df, ["BillDate", "Bill_Date", "InvoiceDate", "Invoice_Date"])
    rev_amt_col = col_in(rev_df, ["NetAmount", "NETAMOUNT", "Amount", "TotalAmount"])

    rev_visit_map = {}
    rev_visit_map_digits = {}
    rev_visit_map_last = {}
    rev_bill_map = {}
    rev_bill_map_no = {}
    rev_billdate_map = {}
    if rev_amt_col:
        if rev_visit_col:
            rev_df["_norm_visit"] = rev_df[rev_visit_col].apply(norm_key)
            rev_df["_norm_visit_digits"] = rev_df["_norm_visit"].apply(lambda x: "".join(ch for ch in x if ch.isdigit()))
            rev_df["_norm_visit_last"] = rev_df["_norm_visit"].apply(lambda x: x.split("/")[-1] if "/" in x else x)
            rev_visit_map = rev_df.groupby("_norm_visit")[rev_amt_col].sum().to_dict()
            rev_visit_map_digits = rev_df.groupby("_norm_visit_digits")[rev_amt_col].sum().to_dict()
            rev_visit_map_last = rev_df.groupby("_norm_visit_last")[rev_amt_col].sum().to_dict()
        if rev_bill_col:
            rev_df["_norm_bill_id"] = rev_df[rev_bill_col].apply(norm_key)
            rev_bill_map = rev_df.groupby("_norm_bill_id")[rev_amt_col].sum().to_dict()
        if rev_billno_col:
            rev_df["_norm_bill_no"] = rev_df[rev_billno_col].apply(norm_key)
            rev_bill_map_no = rev_df.groupby("_norm_bill_no")[rev_amt_col].sum().to_dict()
        if rev_billdate_col:
            # Prefer Bill_ID map; fall back to BillNo map for dates
            if rev_bill_col:
                rev_billdate_map = rev_df.set_index("_norm_bill_id")[rev_billdate_col].to_dict()
            elif rev_billno_col:
                rev_billdate_map = rev_df.set_index("_norm_bill_no")[rev_billdate_col].to_dict()

    # Receipt columns (explicit preference: VisitNo for hospital, Bill_ID for pharmacy)
    rec_visit_col = col_in(rec_df, ["VisitNo", "Visit_No", "Visit_ID", "VisitID", "VisitId"])
    rec_bill_col = col_in(rec_df, ["Bill_ID", "BillID", "BillId"])
    rec_billno_col = col_in(rec_df, ["BillNo", "Bill_No"])
    rec_amt_col = col_in(rec_df, ["Amount", "NetAmount", "TotalAmount"])
    rec_type_col = col_in(rec_df, ["ReceiptType", "Type"])
    rec_mode_col = col_in(rec_df, ["PModeName", "PaymentMode", "Mode"])
    rec_date_col = col_in(rec_df, ["Receipt_Date", "ReceiptDate", "Date"])
    rec_patient_col = col_in(rec_df, ["Patient", "PatientName", "Patientname", "Patient_Name"])
    rec_reg_col = col_in(rec_df, ["RegNo", "Regno", "PatientID", "PatientId", "Patient_ID", "UHID", "MRNo", "Registration_No", "RegistrationNo"])
    rec_billdate_col = col_in(rec_df, ["BillDate", "Bill_Date", "Bill Dt", "BillDt"])

    # Helper to extract key from any receipt row (used for current and prior)
    def extract_key(row, receipt_type):
        if receipt_type in ("PH", "PI"):
            key_id = norm_key(row.get(rec_bill_col)) if rec_bill_col else ""
            key_no = norm_key(row.get(rec_billno_col)) if rec_billno_col else ""
            key = key_id or key_no
            key_type = "Bill"
        else:
            key = str(row.get(rec_visit_col) or "").strip() if rec_visit_col else ""
            key_type = "Visit"
        return key_type, key

    # Build prior receipt key set
    if not prior_df.empty:
        p_type_col = col_in(prior_df, ["ReceiptType", "Type"])
        for _, pr in prior_df.iterrows():
            pr_type = str(pr.get(p_type_col) or "").strip().upper() if p_type_col else ""
            _, pk = extract_key(pr, pr_type)
            prior_receipt_keys.add(norm_key(pk))

    out_rows = []
    seen_revenue_keys = set()
    seen_suspense_keys = set()
    receipt_totals = {}
    revenue_for_key = {}
    if rec_amt_col:
        # Precompute total receipts per key for suspense calc
        if rec_amt_col:
            for _, row in rec_df.iterrows():
                r_type_raw = str(row.get(rec_type_col) or "").strip().upper()
                if r_type_raw in ("PH", "PI"):
                    key_id = norm_key(row.get(rec_bill_col)) if rec_bill_col else ""
                    key_no = norm_key(row.get(rec_billno_col)) if rec_billno_col else ""
                    k = key_id or key_no
                else:
                    k = norm_key(row.get(rec_visit_col)) if rec_visit_col else ""
                if k:
                    receipt_totals[k] = receipt_totals.get(k, 0.0) + float(row.get(rec_amt_col) or 0)

        # Precompute revenue per key (first available match, visit or bill)
        for k in receipt_totals.keys():
            rev_amt = 0.0
            # Try visit maps
            rev_amt = float(rev_visit_map.get(k, 0) or rev_visit_map_digits.get(k, 0) or rev_visit_map_last.get(k, 0))
            if rev_amt == 0.0:
                digits = "".join(ch for ch in k if ch.isdigit())
                if digits:
                    rev_amt = float(rev_visit_map.get(digits, 0) or rev_visit_map_digits.get(digits, 0) or rev_visit_map_last.get(digits, 0))
            if rev_amt == 0.0 and "/" in k:
                last_seg = k.split("/")[-1]
                rev_amt = float(rev_visit_map.get(last_seg, 0) or rev_visit_map_digits.get(last_seg, 0) or rev_visit_map_last.get(last_seg, 0))
            # Try bill maps if still zero
            if rev_amt == 0.0:
                rev_amt = float(rev_bill_map.get(k, 0) or rev_bill_map_no.get(k, 0))
                if rev_amt == 0.0 and "/" in k:
                    last_seg = k.split("/")[-1]
                    rev_amt = float(rev_bill_map.get(last_seg, 0) or rev_bill_map_no.get(last_seg, 0))
                if rev_amt == 0.0:
                    digits = "".join(ch for ch in k if ch.isdigit())
                    if digits:
                        rev_amt = float(rev_bill_map.get(digits, 0) or rev_bill_map_no.get(digits, 0))
            revenue_for_key[k] = rev_amt

        for _, row in rec_df.iterrows():
            r_type_raw = str(row.get(rec_type_col) or "").strip().upper()
            pay_mode = str(row.get(rec_mode_col) or "").strip()
            receipt_amt = float(row.get(rec_amt_col) or 0)
            receipt_date = row.get(rec_date_col) if rec_date_col else ""
            bill_date_raw = row.get(rec_billdate_col) if rec_billdate_col else None
            bill_dt = pd.to_datetime(bill_date_raw, errors="coerce") if bill_date_raw is not None else None
            receipt_dt = pd.to_datetime(receipt_date, errors="coerce") if receipt_date else None
            today_dt = datetime.now(tz=LOCAL_TZ).date()
            key = None
            key_type = None
            # Receipt type: PH or PI -> match by Bill_ID; Hospital/others -> match by VisitNo
            if r_type_raw in ("PH", "PI"):
                key_id = norm_key(row.get(rec_bill_col)) if rec_bill_col else ""
                key_no = norm_key(row.get(rec_billno_col)) if rec_billno_col else ""
                key = key_id or key_no
                key_type = "Bill"
                revenue_amt = 0.0
                if key_id and rev_bill_map:
                    revenue_amt = float(rev_bill_map.get(key_id, 0))
                elif key_no and rev_bill_map_no:
                    revenue_amt = float(rev_bill_map_no.get(key_no, 0))
                # If no bill date from receipts, try revenue map
                if (bill_dt is None or pd.isna(bill_dt)) and rev_billdate_map:
                    if key_id and key_id in rev_billdate_map:
                        bill_dt = pd.to_datetime(rev_billdate_map.get(key_id), errors="coerce")
                    elif key_no and key_no in rev_billdate_map:
                        bill_dt = pd.to_datetime(rev_billdate_map.get(key_no), errors="coerce")
            else:
                key = norm_key(row.get(rec_visit_col)) if rec_visit_col else ""
                key_type = "Visit"
                revenue_amt = revenue_for_key.get(key, 0.0)
            if not key:
                key = "UNKNOWN"
                revenue_amt = 0.0

            norm_lookup = norm_key(key)
            if norm_lookup in seen_revenue_keys:
                revenue_amt = 0.0
            else:
                seen_revenue_keys.add(norm_lookup)

            # Cache first matched revenue per key for suspense calc
            # Cache highest revenue seen per key (in case early rows had zero)
            if norm_lookup not in revenue_for_key:
                revenue_for_key[norm_lookup] = revenue_amt
            else:
                revenue_for_key[norm_lookup] = max(revenue_for_key[norm_lookup], revenue_amt)

            # Suspense is receipts only if unmatched; apply once per key based on total receipts
            total_receipts_for_key = receipt_totals.get(norm_lookup, receipt_amt)
            if norm_lookup in seen_suspense_keys:
                suspense = 0.0
            else:
                suspense = total_receipts_for_key if revenue_for_key.get(norm_lookup, 0) <= 0 else max(0.0, total_receipts_for_key - revenue_for_key.get(norm_lookup, 0))
                seen_suspense_keys.add(norm_lookup)
            patient_val = str(row.get(rec_patient_col) or "").strip() if rec_patient_col else ""
            reg_val = norm_key(row.get(rec_reg_col)) if rec_reg_col else ""
            visit_val = norm_key(row.get(rec_visit_col)) if rec_visit_col else ""
            # Highlight only when receipt is today and bill date is earlier (pharmacy refill/backdated)
            backdated_match = 0
            if receipt_dt is not None and not pd.isna(receipt_dt):
                receipt_date_only = receipt_dt.date()
                if receipt_date_only == today_dt and bill_dt is not None and not pd.isna(bill_dt):
                    try:
                        bill_date_only = bill_dt.date()
                        if bill_date_only < receipt_date_only:
                            backdated_match = 1
                    except Exception:
                        pass
            out_rows.append({
                "key_type": key_type,
                "key": key,
                "receipt_type": r_type_raw,
                "pay_mode": pay_mode,
                "receipt_date": receipt_date,
                "receipt_amount": receipt_amt,
                "revenue_amount": revenue_amt,
                "suspense_amount": suspense,
                "patient": patient_val,
                "reg_no": reg_val,
                "visit_no": visit_val,
                "backdated_match": backdated_match
            })

    return jsonify({"status": "success", "data": out_rows, "unit": target_unit, "count": len(out_rows)})


@app.route('/api/mis/collections/export_excel')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_collections_export_excel():
    """
    Export collections/receipts to Excel with:
      - Summary Sheet:
        1. Header matching screenshot.
        2. User Matrix (User vs Mode).
        3. **NEW: Visit/Type Matrix (IPD/OPD/Pharmacy vs Mode)**.
        4. Payment Mode Summary (Crystal Logic).
        5. Patient Type Summary.
      - Raw Data Sheets.
    """
    import io
    import pandas as pd
    import re
    from xlsxwriter.utility import xl_col_to_name

    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    
    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    
    if not target_unit:
        return jsonify({"status": "error", "message": "No unit available"}), 400
    if allowed_units and target_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403

    # Fetch Data
    df = data_fetch.fetch_receipt_summary(target_unit, from_date, to_date)
    if df is None:
        return jsonify({"status": "error", "message": "Database error"}), 500
    if df.empty:
        return jsonify({"status": "error", "message": "No data available to export"}), 400

    # --- 1. Clean Data ---
    df = _clean_df_columns(df.copy())
    cols_map = {c.lower(): c for c in df.columns}
    
    def get_col(candidates):
        return next((cols_map[c.lower()] for c in candidates if c.lower() in cols_map), None)

    amt_col = get_col(["Amount", "NetAmount", "TotalAmount"])
    user_col = get_col(["UserName", "User"])
    mode_col = get_col(["PModeName", "PaymentMode", "Mode"])
    cat_col = get_col(["ReceiptCategory", "Category"])
    pat_cat_col = get_col(["PatientCategory", "Patient_Category", "PayTypeRaw", "PayType"])
    pat_type_col = get_col(["PatientTypes", "PatientType", "Patient_Types"])
    visit_col = get_col(["TypeOfVisit", "VisitType", "Visit_Type"])
    type_col = get_col(["ReceiptType", "Type"]) # Needed for PH/PI/P logic

    # Ensure numeric amount
    if amt_col:
        df[amt_col] = pd.to_numeric(df[amt_col], errors='coerce').fillna(0.0)
    else:
        df["Amount"] = 0.0
        amt_col = "Amount"

    # Fill NaNs for strings
    for col in [user_col, mode_col, cat_col, pat_cat_col, pat_type_col, visit_col, type_col]:
        if col: df[col] = df[col].fillna("").astype(str).str.strip()

    # --- Logic 1: Crystal Categories ---
    def calc_category(row):
        val = row.get(pat_cat_col, "")
        if not val or val.lower() == "nan" or val == "": return "Temporary Patients"
        val_lower = val.lower()
        if "cashless" in val_lower: return "Cashless Category"
        elif "cash" in val_lower: return "Cash Category"
        else: return "Category Undefined"

    if pat_cat_col: df["CalculatedCategory"] = df.apply(calc_category, axis=1)
    else: df["CalculatedCategory"] = "Category Undefined"

    # --- Logic 2: Unregistered Patient ---
    if pat_type_col and visit_col:
        mask_unreg = (((df[pat_type_col] == "") | (df[pat_type_col].str.lower() == "unknown")) & 
                      (df[visit_col].str.lower() == "unregistered patient sale"))
        df.loc[mask_unreg, pat_type_col] = "Unregistered Patient Sale"
        df.loc[df[pat_type_col] == "", pat_type_col] = "Unknown"

    # --- Logic 3: Visit Breakdown (Screenshot 2 Logic) ---
    def calc_report_group(row):
        # Get raw values
        r_type = str(row.get(type_col, "")).strip().upper()
        v_type = str(row.get(visit_col, "")).strip().upper()
        
        # 1. Pharmacy Checks (ReceiptType overrides Visit)
        if r_type == "PH":
            return f"{target_unit} Pharmacy OPD" # e.g. ASARFI MEDICAL OPD
        if r_type == "PI":
            return f"{target_unit} Pharmacy IPD" # e.g. ASARFI MEDICAL IPD
            
        # 2. IPD Check (Visit contains IPD)
        if "IPD" in v_type:
            return f"{target_unit} IPD" # e.g. AHL IPD
            
        # 3. OPD Check (OPD/DPV/HCV AND Type 'P')
        if any(x in v_type for x in ["OPD", "DPV", "HCV"]):
            if r_type == "P":
                return f"{target_unit} OPD" # e.g. AHL OPD
        
        return "Other"

    if visit_col and type_col:
        df["_ReportGroup"] = df.apply(calc_report_group, axis=1)
    else:
        df["_ReportGroup"] = "Other"

    # --- Excel Writer ---
    output = io.BytesIO()
    with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
        wb = writer.book

        # --- Styles ---
        style_h1 = wb.add_format({"bold": True, "font_size": 14, "font_color": "#1E3A8A", "align": "left"}) 
        style_h2 = wb.add_format({"bold": True, "font_size": 12, "font_color": "#000000", "align": "left"})
        style_h3 = wb.add_format({"font_size": 10, "font_color": "#000000", "align": "left"})

        # Matrix Styles
        fmt_header = wb.add_format({"bold": True, "border": 1, "align": "center", "bg_color": "#F1F5F9", "valign": "vcenter", "text_wrap": True})
        
        # Cyan Header for the 2nd Matrix (Screenshot style)
        fmt_header_cyan = wb.add_format({"bold": True, "border": 1, "align": "center", "bg_color": "#B7DEE8", "valign": "vcenter", "text_wrap": True})

        fmt_text = wb.add_format({"border": 1, "align": "left", "valign": "vcenter"})
        fmt_text_bold = wb.add_format({"border": 1, "align": "left", "bold": True, "bg_color": "#F8FAFC", "valign": "vcenter"})
        inr_num_format = "[$\u20B9-4009] #,##,##0.00"
        fmt_curr = wb.add_format({"border": 1, "align": "right", "num_format": inr_num_format, "valign": "vcenter"})
        fmt_curr_bold = wb.add_format({"border": 1, "align": "right", "bold": True, "num_format": inr_num_format, "bg_color": "#F8FAFC", "valign": "vcenter"})
        
        fmt_sec_title = wb.add_format({"bold": True, "font_size": 11, "underline": True, "font_color": "#000000"})

        # ==========================================
        # SHEET 1: SUMMARY
        # ==========================================
        ws_sum = wb.add_worksheet("Summary")
        ws_sum.hide_gridlines(2) 
        
        session_user = session.get('username') or 'System'
        ws_sum.write(0, 0, "ASARFI HOSPITAL", style_h1)
        ws_sum.write(1, 0, "RECEIPTS EXPORT (DAILY CASH DETAILS)", style_h2)
        ws_sum.write(2, 0, f"Unit: {target_unit} | Date: {from_date} to {to_date} | User: {session_user}", style_h3)
        
        row_cur = 4

        # ---------------------------------------------------------
        # 1. USER MATRIX
        # ---------------------------------------------------------
        if user_col and mode_col:
            pivot = df.pivot_table(index=user_col, columns=mode_col, values=amt_col, aggfunc='sum', fill_value=0)
            pivot["Total Collection"] = pivot.sum(axis=1)
            grand_totals = pivot.sum(axis=0)
            grand_totals.name = "Total"
            pivot = pd.concat([pivot, pd.DataFrame(grand_totals).T])

            # Headers
            ws_sum.write(row_cur, 0, "USER", fmt_header)
            ws_sum.set_column(0, 0, 25)
            col_idx = 1
            for mode_name in pivot.columns:
                ws_sum.write(row_cur, col_idx, mode_name.upper(), fmt_header)
                ws_sum.set_column(col_idx, col_idx, 15)
                col_idx += 1
            ws_sum.write(row_cur, col_idx, "Remarks", fmt_header)
            ws_sum.set_column(col_idx, col_idx, 25)
            remarks_idx = col_idx
            row_cur += 1

            for row_user, row_data in pivot.iterrows():
                is_total = (row_user == "Total")
                f_txt = fmt_text_bold if is_total else fmt_text
                f_num = fmt_curr_bold if is_total else fmt_curr
                
                ws_sum.write(row_cur, 0, row_user, f_txt)
                c_idx = 1
                for val in row_data:
                    val_num = float(val)
                    if val_num == 0 and not is_total:
                        ws_sum.write(row_cur, c_idx, "-", wb.add_format({"border": 1, "align": "center"}))
                    else:
                        ws_sum.write(row_cur, c_idx, val_num, f_num)
                    c_idx += 1
                ws_sum.write(row_cur, remarks_idx, "", f_txt)
                row_cur += 1
            
            row_cur += 3

        # ---------------------------------------------------------
        # 2. VISIT / TYPE MATRIX 
        # ---------------------------------------------------------
        # Rows: _ReportGroup, Cols: Mode
        if "_ReportGroup" in df.columns and mode_col:
            # Pivot
            piv2 = df.pivot_table(index="_ReportGroup", columns=mode_col, values=amt_col, aggfunc='sum', fill_value=0)
            # Remove "Other" if 0 or keep it, usually 'Other' might contain Advance receipts if logic is strict
            # Sort rows to match screenshot preference: OPD, IPD, Pharmacy OPD, Pharmacy IPD
            desired_order = [
                f"{target_unit} OPD",
                f"{target_unit} IPD",
                f"{target_unit} Pharmacy OPD",
                f"{target_unit} Pharmacy IPD"
            ]
            # Add any existing rows that aren't in desired list (like Other) to the end
            existing_rows = piv2.index.tolist()
            sorted_rows = [r for r in desired_order if r in existing_rows] + [r for r in existing_rows if r not in desired_order]
            piv2 = piv2.reindex(sorted_rows)

            # Calculate Totals
            piv2["TOTAL"] = piv2.sum(axis=1)
            
            # Grand Total Row (Empty name in screenshot, just bold numbers)
            grand_totals_2 = piv2.sum(axis=0)
            grand_totals_2.name = "" # Blank name for total row as per screenshot visual usually
            piv2 = pd.concat([piv2, pd.DataFrame(grand_totals_2).T])

            # Render Header (Cyan)
            ws_sum.write(row_cur, 0, "NAME", fmt_header)
            
            col_idx = 1
            for mode_name in piv2.columns:
                ws_sum.write(row_cur, col_idx, mode_name, fmt_header)
                col_idx += 1
            row_cur += 1

            # Render Body
            for r_name, r_data in piv2.iterrows():
                is_total = (r_name == "")
                f_txt = fmt_text_bold if is_total else fmt_text
                f_num = fmt_curr_bold if is_total else fmt_curr
                
                ws_sum.write(row_cur, 0, r_name, f_txt)
                
                c_idx = 1
                for val in r_data:
                    val_num = float(val)
                    if val_num == 0 and not is_total:
                        # Screenshot shows blank or 0? Screenshot shows empty for 0.
                        ws_sum.write(row_cur, c_idx, "", wb.add_format({"border": 1}))
                    else:
                        ws_sum.write(row_cur, c_idx, val_num, f_num)
                    c_idx += 1
                row_cur += 1
            
            row_cur += 3

        # ---------------------------------------------------------
        # 3. PAYMENT MODE SUMMARY
        # ---------------------------------------------------------
        ws_sum.write(row_cur, 0, "Payment Mode Summary", fmt_sec_title)
        row_cur += 1
        
        ws_sum.write(row_cur, 0, "Payment Mode / Details", fmt_header)
        ws_sum.write(row_cur, 1, "Amount", fmt_header)
        ws_sum.set_column(1, 1, 20)
        row_cur += 1

        if mode_col:
            total_all_modes = 0
            for mode_name, mode_df in df.groupby(mode_col):
                mode_total = mode_df[amt_col].sum()
                total_all_modes += mode_total
                
                ws_sum.write(row_cur, 0, f"Payment Mode: {mode_name}", fmt_text_bold)
                ws_sum.write(row_cur, 1, mode_total, fmt_curr_bold)
                row_cur += 1
                
                sub_grps = mode_df.groupby("CalculatedCategory")[amt_col].sum()
                for cat_name, cat_val in sub_grps.items():
                    ws_sum.write(row_cur, 0, f"    {cat_name}", fmt_text)
                    ws_sum.write(row_cur, 1, cat_val, fmt_curr)
                    row_cur += 1
            
            ws_sum.write(row_cur, 0, "Grand Total Collection", fmt_text_bold)
            ws_sum.write(row_cur, 1, total_all_modes, fmt_curr_bold)
            row_cur += 3

        # ---------------------------------------------------------
        # 4. CATEGORY SUMMARY
        # ---------------------------------------------------------
        if cat_col:
            ws_sum.write(row_cur, 0, "Category Summary", fmt_sec_title)
            row_cur += 1
            cat_grps = df.groupby(cat_col)[amt_col].sum()
            
            ws_sum.write(row_cur, 0, "Category", fmt_header)
            ws_sum.write(row_cur, 1, "Total Collection", fmt_header)
            row_cur += 1
            
            for c_name, c_val in cat_grps.items():
                ws_sum.write(row_cur, 0, c_name, fmt_text)
                ws_sum.write(row_cur, 1, c_val, fmt_curr)
                row_cur += 1
            
            ws_sum.write(row_cur, 0, "Total", fmt_text_bold)
            ws_sum.write(row_cur, 1, cat_grps.sum(), fmt_curr_bold)
            row_cur += 3

        # ---------------------------------------------------------
        # 5. PATIENT TYPES SUMMARY
        # ---------------------------------------------------------
        if pat_type_col:
            ws_sum.write(row_cur, 0, "Patient Types Summary", fmt_sec_title)
            row_cur += 1
            pt_grps = df.groupby(pat_type_col)[amt_col].sum()
            
            ws_sum.write(row_cur, 0, "Patient Type", fmt_header)
            ws_sum.write(row_cur, 1, "Total Collection", fmt_header)
            row_cur += 1
            
            for pt_name, pt_val in pt_grps.items():
                ws_sum.write(row_cur, 0, pt_name, fmt_text)
                ws_sum.write(row_cur, 1, pt_val, fmt_curr)
                row_cur += 1
                
            ws_sum.write(row_cur, 0, "Total", fmt_text_bold)
            ws_sum.write(row_cur, 1, pt_grps.sum(), fmt_curr_bold)
            row_cur += 3

        # ==========================================
        # SHEET 2+: RAW DATA
        # ==========================================
        export_df = pd.DataFrame()
        def pick_series(candidates, default=""):
            for c in candidates:
                if c.lower() in cols_map: return df[cols_map[c.lower()]]
            return pd.Series([default] * len(df))
        
        def fmt_date(s):
            try: return pd.to_datetime(s, errors='coerce').dt.strftime('%d-%m-%Y').fillna('')
            except: return s.astype(str)

        export_df["Sl."] = range(1, len(df) + 1)
        export_df["Receipt No"] = pick_series(["Receipt_No", "ReceiptNo", "RcptNo"])
        export_df["Date"] = fmt_date(pick_series(["Receipt_Date", "Date"]))
        export_df["Time"] = pick_series(["Receipt_Time", "Time"])
        export_df["Category"] = pick_series(["ReceiptCategory", "Category"])
        export_df["Type"] = pick_series(["ReceiptType", "Type"])
        export_df["Payment Mode"] = pick_series(["PModeName", "PaymentMode", "Mode"])
        export_df["PayType"] = pick_series(["PayType", "paytype"])
        export_df["Amount"] = df[amt_col]
        export_df["Bill No"] = pick_series(["BillNo", "Bill_No", "InvoiceNo"])
        export_df["Bill Date"] = fmt_date(pick_series(["BillDate", "Bill_Date"]))
        export_df["Patient"] = pick_series(["Patient", "PatientName", "Patientname"])
        export_df["Reg No"] = pick_series(["RegNo", "Regno", "PatientID"])
        export_df["Visit ID"] = pick_series(["Visit_ID", "VisitId", "VisitID", "VisitIdNo"])
        export_df["Visit No"] = pick_series(["VisitNo", "Visit_No", "Visit_No.", "VisitNumber", "IPDNo", "OPDNo"])
        export_df["Patient Type"] = pick_series(["PatientTypes", "PatientType"])
        export_df["Visit"] = pick_series(["TypeOfVisit", "VisitType"])
        export_df["User"] = pick_series(["UserName", "User"])
        export_df["Report Category"] = df["CalculatedCategory"]
        export_df["Report Group"] = df["_ReportGroup"]

        # Cashless Flag
        export_df["CashlessFlag"] = (
            (
                export_df["PayType"].astype(str).str.lower().str.contains("cashless")
                | export_df["Payment Mode"].astype(str).str.lower().str.contains("cashless")
            )
            & (~export_df["Payment Mode"].astype(str).str.lower().str.contains("debit voucher"))
        ).astype(int)

        header_raw_fmt = wb.add_format({"bold": True, "font_color": "white", "bg_color": "#1E3A8A", "align": "center", "valign": "vcenter", "border": 1})
        cashless_row_fmt = wb.add_format({"bg_color": "#FDE2E4"})
        curr_raw_fmt = wb.add_format({"num_format": "#,##0.00"})

        def write_sheet(sheet_name, data):
            if data is None or data.empty: return
            local_df = data.copy()
            for col in local_df.columns:
                if col != "CashlessFlag": local_df[col] = local_df[col].fillna("")
            
            local_df.to_excel(writer, sheet_name=sheet_name, index=False, startrow=3)
            ws = writer.sheets[sheet_name]

            ws.write(0, 0, "ASARFI HOSPITAL", wb.add_format({"bold": True, "font_size": 14, "color": "#1E3A8A"}))
            ws.write(1, 0, f"RECEIPTS EXPORT ({sheet_name.upper()})", wb.add_format({"bold": True, "font_size": 11}))
            ws.write(2, 0, f"Unit: {target_unit} | Date: {from_date} to {to_date} | User: {session_user}")

            for col_idx, col_name in enumerate(local_df.columns):
                ws.write(3, col_idx, col_name, header_raw_fmt)

            last_row = 3 + len(local_df)
            ws.autofilter(3, 0, last_row, len(local_df.columns)-1)
            ws.freeze_panes(4, 0)

            for idx, col_name in enumerate(local_df.columns):
                width = 14
                if col_name in ["Patient", "Payment Mode", "Report Group"]: width = 20
                if col_name == "Sl.": width = 5
                ws.set_column(idx, idx, width, curr_raw_fmt if col_name == "Amount" else None, {"hidden": col_name == "CashlessFlag"})

            try:
                flag_idx = list(local_df.columns).index("CashlessFlag")
                flag_let = xl_col_to_name(flag_idx)
                ws.conditional_format(4, 0, last_row, len(local_df.columns)-1, {
                    "type": "formula", "criteria": f"=${flag_let}5=1", "format": cashless_row_fmt
                })
            except: pass

        write_sheet("All Receipts", export_df)
        if "Payment Mode" in export_df.columns:
            for mode_val, grp in export_df.groupby("Payment Mode", dropna=False):
                write_sheet(re.sub(r"[\\/*?:\\[\\]]", "_", f"Mode-{mode_val}")[:31], grp)
        if "Category" in export_df.columns:
            cat_s = export_df["Category"].astype(str).str.lower()
            write_sheet("Advance Receipts", export_df[cat_s.str.contains("advance", na=False)])
            write_sheet("Against Bill", export_df[cat_s.str.contains("receipt against bill", na=False)])

    output.seek(0)
    return send_file(output, as_attachment=True, download_name=f"Collections_{target_unit}_{from_date}.xlsx", mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")


