@app.route('/api/mis/phc_ledger')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_phc_ledger():
    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)

    if not target_unit or (allowed_units and target_unit not in allowed_units):
        return jsonify({"status": "error", "message": "Unauthorized Unit Access"}), 403

    df = data_fetch.fetch_phc_ledger(target_unit, from_date, to_date)
    if df is None:
        return jsonify({"status": "error", "message": "Database error"}), 500
    if df.empty:
        return jsonify({"status": "success", "data": [], "unit": target_unit, "count": 0}), 200

    for col in df.columns:
        if pd.api.types.is_datetime64_any_dtype(df[col]):
            df[col] = pd.to_datetime(df[col], errors="coerce").dt.strftime("%Y-%m-%d %H:%M:%S")

    df = df.replace({pd.NaT: None, np.nan: None})
    df = df.where(pd.notna(df), None)

    records = df.to_dict(orient="records")
    return jsonify({"status": "success", "data": records, "unit": target_unit, "count": len(records)})


@app.route('/api/mis/phc_ledger/export_excel')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_phc_ledger_export_excel():
    import io
    import pandas as pd
    import re
    from xlsxwriter.utility import xl_col_to_name

    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)

    if not target_unit or (allowed_units and target_unit not in allowed_units):
        return "Unauthorized", 403

    df = data_fetch.fetch_phc_ledger(target_unit, from_date, to_date)
    if df is None or df.empty:
        return "No data found for export", 404

    df = _clean_df_columns(df)

    def _norm_key(val: str) -> str:
        return re.sub(r"[\s_]+", "", str(val or "")).lower()

    def _find_col(candidates):
        for col in df.columns:
            if _norm_key(col) in candidates:
                return col
        return None

    def _num_series(col_name):
        if col_name and col_name in df.columns:
            series = df[col_name].astype(str)
            series = series.str.replace(",", "", regex=False)
            series = series.str.replace(r"[^0-9.\-]", "", regex=True)
            return pd.to_numeric(series, errors="coerce").fillna(0)
        return pd.Series([0] * len(df))

    visit_col = _find_col({"typeofvisit", "visittype"})
    pkg_col = _find_col({"packagename"})
    pkg_cost_col = _find_col({"packagecost", "netpackagecost"})
    net_amt_col = _find_col({"netamount"})
    bill_disc_col = _find_col({"billdiscount"})

    visit_series = df[visit_col].astype(str).str.strip().str.upper() if visit_col else pd.Series([""] * len(df))
    hcv_mask = visit_series == "HCV"
    pkg_cost = _num_series(pkg_cost_col)
    net_amt = _num_series(net_amt_col)
    bill_disc = _num_series(bill_disc_col)
    hcv_total = float(pkg_cost[hcv_mask].sum())
    non_hcv_total = float(net_amt[~hcv_mask].sum())
    net_total = hcv_total + non_hcv_total
    bill_discount_total = float(bill_disc.sum())

    diag_total = float((net_amt + bill_disc.abs()).where(~hcv_mask, 0).sum())
    diag_discount = float(bill_disc.where(~hcv_mask, 0).sum())

    pkg_stats = {}
    if pkg_col and pkg_col in df.columns:
        for name, amt in zip(df[pkg_col].fillna("Unknown Package"), pkg_cost.where(pkg_cost != 0, net_amt)):
            key = str(name)
            if key not in pkg_stats:
                pkg_stats[key] = {"qty": 0, "amount": 0.0}
            pkg_stats[key]["qty"] += 1
            pkg_stats[key]["amount"] += float(amt)

    package_rows = sorted(
        ((name, stats["qty"], stats["amount"]) for name, stats in pkg_stats.items()),
        key=lambda x: x[2],
        reverse=True
    )

    preferred_order = [
        "PatientCategory", "PatientType", "TypeOfVisit", "CorpType", "Doctor", "Dept",
        "Registration_No", "PatientName", "PackageName", "VisitNo", "VisitDate",
        "billdate", "billno", "LabAmount", "RadioAmount", "HospAmount", "PackageDiscount",
        "NetPackageCost", "BillDiscount", "NetAmount", "CancelStatus",
    ]
    cols_map = {_norm_key(c): c for c in df.columns}
    ordered_cols = [cols_map[_norm_key(c)] for c in preferred_order if _norm_key(c) in cols_map]
    final_cols = ordered_cols + [c for c in df.columns if c not in ordered_cols]
    df = df[final_cols]

    numeric_cols = [
        col for col in df.columns
        if any(x in str(col).lower() for x in ["amount", "net", "discount", "cost", "price", "rate"])
    ]
    for col in numeric_cols:
        df[col] = _num_series(col)

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
        wb = writer.book

        title_fmt = wb.add_format({
            "bold": True, "font_size": 14, "font_color": "#1E3A8A",
            "align": "center", "valign": "vcenter"
        })
        subtitle_fmt = wb.add_format({
            "bold": True, "font_size": 11, "align": "center", "valign": "vcenter"
        })
        meta_fmt = wb.add_format({"font_size": 9, "align": "left", "valign": "vcenter"})
        header_fmt = wb.add_format({
            "bold": True, "bg_color": "#1E3A8A", "font_color": "white",
            "border": 1, "align": "center", "valign": "vcenter"
        })
        highlight_cell_fmt = wb.add_format({
            "bold": True, "bg_color": "#FEF9C3", "border": 1,
            "align": "left", "valign": "vcenter"
        })
        highlight_money_fmt = wb.add_format({
            "bold": True, "bg_color": "#FEF9C3", "border": 1,
            "align": "right", "valign": "vcenter", "num_format": "#,##,##0.00"
        })
        text_fmt = wb.add_format({"align": "left", "valign": "vcenter"})
        date_fmt = wb.add_format({"num_format": "yyyy-mm-dd", "align": "center", "valign": "vcenter"})
        money_fmt = wb.add_format({"num_format": "#,##,##0.00", "align": "right", "valign": "vcenter"})
        highlight_fmt = wb.add_format({"bg_color": "#FEF9C3"})

        exported_by = session.get("username") or session.get("user") or "Unknown"
        exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")

        # --- Summary Sheet ---
        ws_sum = wb.add_worksheet("Summary")
        ws_sum.merge_range(0, 0, 0, 4, "ASARFI HOSPITAL", title_fmt)
        ws_sum.merge_range(1, 0, 1, 4, "Health-Checkup Ledger Summary", subtitle_fmt)
        ws_sum.write(2, 0, f"Unit: {target_unit} | Date Range: {from_date} to {to_date}", meta_fmt)
        ws_sum.write(3, 0, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)
        ws_sum.write(4, 0, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)

        metrics = [
            ("Net Amount Total", net_total),
            ("HCV Package Total", hcv_total),
            ("Non-HCV Net Total", non_hcv_total),
            ("Bill Discount Total", bill_discount_total),
            ("Diagnostic Tests Total", diag_total),
            ("Diagnostic Bill Discount", diag_discount),
        ]

        row = 6
        ws_sum.write(row, 0, "Metric", header_fmt)
        ws_sum.write(row, 1, "Value", header_fmt)
        row += 1
        for label, value in metrics:
            if label in {"HCV Package Total", "Non-HCV Net Total"}:
                ws_sum.write(row, 0, label, highlight_cell_fmt)
                ws_sum.write(row, 1, value, highlight_money_fmt)
            else:
                ws_sum.write(row, 0, label, text_fmt)
                ws_sum.write(row, 1, value, money_fmt)
            row += 1

        ws_sum.write(row, 0, "Package Name", header_fmt)
        ws_sum.write(row, 1, "Quantity", header_fmt)
        ws_sum.write(row, 2, "Amount", header_fmt)
        row += 1
        if package_rows:
            for name, qty, amt in package_rows:
                ws_sum.write(row, 0, name, text_fmt)
                ws_sum.write(row, 1, qty, text_fmt)
                ws_sum.write(row, 2, amt, money_fmt)
                row += 1
        else:
            ws_sum.write(row, 0, "No packages found", text_fmt)

        ws_sum.set_column(0, 0, 38)
        ws_sum.set_column(1, 1, 12)
        ws_sum.set_column(2, 2, 22)

        # --- Details Sheet ---
        df.to_excel(writer, sheet_name="Details", index=False, startrow=4)
        ws = writer.sheets["Details"]

        last_col = len(df.columns) - 1
        ws.merge_range(0, 0, 0, last_col, "Health-Checkup Ledger Details", title_fmt)
        ws.merge_range(1, 0, 1, last_col, f"Unit: {target_unit} | Date Range: {from_date} to {to_date}", subtitle_fmt)
        ws.merge_range(2, 0, 2, last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)
        ws.merge_range(3, 0, 3, last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)

        for col_idx, col_name in enumerate(df.columns):
            ws.write(4, col_idx, col_name, header_fmt)
            col_lower = str(col_name).lower()
            width = 16
            fmt = text_fmt
            if "date" in col_lower or "time" in col_lower:
                width = 18
                fmt = date_fmt
            elif any(x in col_lower for x in ["amount", "net", "discount", "cost", "price", "rate"]):
                width = 18
                fmt = money_fmt
            elif any(x in col_lower for x in ["patient", "package", "doctor"]):
                width = 24
            ws.set_column(col_idx, col_idx, width, fmt)

        data_start = 5
        data_end = 4 + len(df)
        if visit_col and visit_col in df.columns:
            visit_idx = list(df.columns).index(visit_col)
            visit_letter = xl_col_to_name(visit_idx)
            ws.conditional_format(data_start, 0, data_end, last_col, {
                "type": "formula",
                "criteria": f'=${visit_letter}{data_start + 1}<>"HCV"',
                "format": highlight_fmt
            })

        ws.freeze_panes(5, 0)

    output.seek(0)
    fname = f"PHC_Ledger_{target_unit}_{from_date}.xlsx"
    return send_file(
        output,
        as_attachment=True,
        download_name=fname,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    )



