@app.route('/api/mis/service_ledger/export_excel')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_service_ledger_export_excel():
    import io
    import pandas as pd
    import re

    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from")
    to_date = request.args.get("to")
    service_name = (request.args.get("service_name") or "").strip()
    service_id_raw = (request.args.get("service_id") or "").strip()
    service_id = None
    if service_id_raw:
        try:
            service_id = int(service_id_raw)
        except ValueError:
            service_id = None
    
    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)

    if not target_unit or (allowed_units and target_unit not in allowed_units):
        return "Unauthorized", 403

    # 1. Fetch Data
    df = data_fetch.fetch_service_consumptions(target_unit, from_date, to_date, service_name, service_id=service_id)
    
    if df is None or df.empty:
        return "No data found for export", 404

    # 2. Clean Data (Currency strings to numbers)
    for col in ['Rate', 'Total_Amt']:
        if col in df.columns:
            df[col] = df[col].astype(str).str.replace(',', '').replace('nan', '0')
            df[col] = df[col].astype(str).str.replace(r'[^0-9.\-]', '', regex=True).replace('', '0').replace('nan', '0')
            df[col] = pd.to_numeric(df[col], errors='coerce').fillna(0.0)
            
    if 'DocIncharge' not in df.columns:
        df['DocIncharge'] = 'Unknown'
    
    # Fill missing doctors
    df['DocIncharge'] = df['DocIncharge'].fillna("Unknown")

    # 3. Prepare Excel
    output = io.BytesIO()
    with pd.ExcelWriter(output, engine='xlsxwriter') as writer:
        wb = writer.book
        
        # --- Formats ---
        header_fmt = wb.add_format({
            'bold': True, 'bg_color': '#1e3a8a', 'font_color': 'white', 
            'border': 1, 'align': 'center', 'valign': 'vcenter'
        })
        curr_fmt = wb.add_format({'num_format': '[$\u20B9-4009] #,##,##0.00', 'align': 'right'})
        text_fmt = wb.add_format({'align': 'left'})
        center_fmt = wb.add_format({'align': 'center'})
        border_fmt = wb.add_format({'border': 1}) # For conditional formatting
        title_fmt = wb.add_format({'bold': True, 'font_size': 14, 'font_color': '#1E3A8A'})

        # --- Helper to Format Worksheet ---
        def format_worksheet(ws, dataframe, title_text):
            # Write Title
            ws.write(0, 0, title_text, title_fmt)
            ws.write(1, 0, f"Unit: {target_unit} | Date: {from_date} to {to_date}")
            
            # Headers
            for col_num, value in enumerate(dataframe.columns.values):
                ws.write(3, col_num, value, header_fmt)

            # Column Widths (No borders in set_column to prevent spill)
            money_cols = ['Rate', 'Total_Amt', 'Total Amount']
            center_cols = ['Quantity', 'Qty', 'RegNo']
            
            for i, col in enumerate(dataframe.columns):
                width = 15
                base_fmt = text_fmt
                if col in money_cols:
                    width = 18
                    base_fmt = curr_fmt
                elif col in center_cols:
                    width = 12
                    base_fmt = center_fmt
                elif col in ['Service_Name', 'Patient', 'Sub_Dept', 'DocIncharge']:
                    width = 35
                elif col in ['Bill_Date']:
                    width = 20
                ws.set_column(i, i, width, base_fmt)

            # Conditional Borders (Only on data rows)
            if len(dataframe) > 0:
                last_row = 3 + len(dataframe)
                last_col = len(dataframe.columns) - 1
                ws.conditional_format(3, 0, last_row, last_col, {
                    'type': 'no_errors',
                    'format': border_fmt
                })
            
            ws.freeze_panes(4, 0)

        # --- SHEET 1: EXECUTIVE SUMMARY ---
        summary_df = df.groupby('DocIncharge')[['Total_Amt']].sum().reset_index()
        summary_df = summary_df.sort_values('Total_Amt', ascending=False) # Sort by Highest Value
        summary_df.columns = ['Doctor Name', 'Total Amount']
        
        summary_df.to_excel(writer, sheet_name="Executive Summary", index=False, startrow=3)
        format_worksheet(writer.sheets["Executive Summary"], summary_df, "DOCTOR-WISE SUMMARY")

        # --- SHEET 2: ALL DATA (MASTER LEDGER) ---  <-- NEW ADDITION
        df.to_excel(writer, sheet_name="All Data", index=False, startrow=3)
        format_worksheet(writer.sheets["All Data"], df, "MASTER SERVICE LEDGER (ALL DATA)")

        # --- SHEET 3+: INDIVIDUAL SHEETS (Sorted by Revenue) ---
        sorted_doctors = summary_df['Doctor Name'].tolist()
        
        used_sheet_names = set(["executive summary", "all data"])

        for doc in sorted_doctors:
            # Filter
            doc_df = df[df['DocIncharge'] == doc].copy()
            if doc_df.empty: continue

            # Sanitize Name
            safe_doc_name = re.sub(r'[\[\]:*?/\\]', '', str(doc))
            
            # Fallback if empty
            if not safe_doc_name: safe_doc_name = "Unknown"

            sheet_name = safe_doc_name[:31]
            
            # Handle Duplicates
            counter = 1
            base_name = sheet_name
            while sheet_name.lower() in used_sheet_names:
                suffix = f"_{counter}"
                trim_len = 31 - len(suffix)
                sheet_name = f"{base_name[:trim_len]}{suffix}"
                counter += 1
            used_sheet_names.add(sheet_name.lower())
            
            # Write Sheet
            doc_df.to_excel(writer, sheet_name=sheet_name, index=False, startrow=3)
            format_worksheet(writer.sheets[sheet_name], doc_df, f"LEDGER: {doc}")

    output.seek(0)
    filename = f"ServiceLedger_ByDoctor_{target_unit}_{from_date}.xlsx"
    return send_file(output, as_attachment=True, download_name=filename, mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")


def _build_service_ledger_pdf_buffer(target_unit: str, from_date: str, to_date: str, service_name: str, exported_by: str, service_id: int | None = None):
    import io
    import re
    from reportlab.lib.pagesizes import A4, landscape
    from reportlab.lib import colors
    from reportlab.lib.units import mm
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer, Image
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_RIGHT
    from xml.sax.saxutils import escape

    df = data_fetch.fetch_service_consumptions(target_unit, from_date, to_date, service_name, service_id=service_id)
    if df is None or df.empty:
        return None

    df = _clean_df_columns(df)

    def _norm_key(val: str) -> str:
        return re.sub(r"[\s_]+", "", str(val or "")).lower()

    cols_map = {_norm_key(c): c for c in df.columns}

    def _pick(candidates):
        for cand in candidates:
            if cand in df.columns:
                return cand
            key = _norm_key(cand)
            if key in cols_map:
                return cols_map[key]
        return None

    date_col = _pick(["Bill_Date", "Bill Date", "BillDate", "Billdate", "Date"])
    reg_col = _pick(["RegNo", "Reg No", "Registration_No", "Registration No", "RegistrationNo"])
    patient_col = _pick(["Patient", "PatientName", "Patient Name", "Patient_Name"])
    service_col = _pick(["Service_Name", "Service Name", "ServiceName"])
    subdept_col = _pick(["Sub_Dept", "Sub Dept", "SubDept", "Department", "Dept"])
    rate_col = _pick(["Rate", "Unit Rate", "Service Rate", "RateAmount", "Rate Amount"])
    qty_col = _pick(["Quantity", "Qty", "QTY"])
    total_col = _pick(["Total_Amt", "Total Amount", "TotalAmount", "Total Amt", "Total_Amount"])
    proc_col = _pick(["ProcedureDoctor", "Procedure Doctor", "ProcDoctor", "Proc Doctor", "Doctor"])
    doc_incharge_col = _pick(["DocIncharge", "Doc Incharge", "DocInCharge", "DoctorInCharge", "Doctor Incharge", "Doctor In Charge"])
    if doc_incharge_col == proc_col:
        doc_incharge_col = None

    col_defs = []
    for label, col in [
        ("Bill Date", date_col),
        ("Reg No", reg_col),
        ("Patient", patient_col),
        ("Service Name", service_col),
        ("Sub Dept", subdept_col),
        ("Rate", rate_col),
        ("Qty", qty_col),
        ("Total", total_col),
        ("Procedure Doctor", proc_col),
        ("Doc Incharge", doc_incharge_col),
    ]:
        if col:
            col_defs.append((label, col))

    if not col_defs:
        return None

    def _format_inr(number) -> str:
        n = _safe_float(number)
        sign = "-" if n < 0 else ""
        n = abs(n)
        s = f"{n:.2f}"
        whole, frac = s.split(".")
        if len(whole) <= 3:
            grouped = whole
        else:
            last = whole[-3:]
            rest = whole[:-3]
            parts = []
            while rest:
                parts.append(rest[-2:])
                rest = rest[:-2]
            grouped = ",".join(reversed(parts)) + "," + last
        return f"{sign}{grouped}.{frac}"

    def _fmt_date(val) -> str:
        try:
            return pd.to_datetime(val).strftime("%d-%m-%Y")
        except Exception:
            return str(val or "")

    def _fmt_qty(val) -> str:
        qty = _safe_float(val)
        if abs(qty - round(qty)) < 0.000001:
            return f"{qty:,.0f}"
        return f"{qty:,.2f}"

    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=landscape(A4),
        topMargin=14 * mm,
        bottomMargin=14 * mm,
        leftMargin=12 * mm,
        rightMargin=12 * mm,
    )

    styles = getSampleStyleSheet()
    style_title = ParagraphStyle("RptTitle", parent=styles["Heading2"], fontSize=12, alignment=TA_CENTER, textColor=colors.HexColor("#1e3a8a"))
    style_sub = ParagraphStyle("RptSub", parent=styles["Normal"], fontSize=9, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_meta = ParagraphStyle("RptMeta", parent=styles["Normal"], fontSize=8, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_td = ParagraphStyle("RptTd", parent=styles["Normal"], fontSize=7, textColor=colors.black)
    style_td_right = ParagraphStyle("RptTdRight", parent=styles["Normal"], fontSize=7, textColor=colors.black, alignment=TA_RIGHT)

    elements = []

    logo_path = os.path.join(app.root_path, "static", "logo", "asarfi.png")
    if os.path.exists(logo_path):
        logo = Image(logo_path, width=18 * mm, height=18 * mm, mask='auto')
        logo.hAlign = "CENTER"
        elements.append(logo)

    elements.append(Spacer(1, 6))
    elements.append(Paragraph("Service Ledger Report", style_title))
    service_label = service_name.strip() if service_name else ""
    service_text = service_label if service_label else "All"
    elements.append(Paragraph(f"{from_date} to {to_date}", style_sub))
    elements.append(Paragraph(f"Unit: {target_unit} | Service: {service_text}", style_sub))
    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    elements.append(Paragraph(f"Exported By: {exported_by} | Exported At: {exported_at}", style_meta))
    elements.append(Spacer(1, 8))

    header_row = [label for label, _ in col_defs]
    table_data = [header_row]
    money_cols = {c for c in [rate_col, total_col] if c}
    numeric_cols = {c for c in [rate_col, total_col, qty_col] if c}

    for _, row in df.iterrows():
        row_cells = []
        for label, col in col_defs:
            raw_val = row.get(col)
            if col == date_col:
                cell_val = _fmt_date(raw_val)
            elif col == qty_col:
                cell_val = _fmt_qty(raw_val)
            elif col in money_cols:
                cell_val = _format_inr(raw_val)
            else:
                cell_val = "" if raw_val is None else str(raw_val)
            style = style_td_right if col in numeric_cols else style_td
            row_cells.append(Paragraph(escape(cell_val), style))
        table_data.append(row_cells)

    def _col_width(label: str) -> float:
        if label == "Bill Date":
            return 22 * mm
        if label == "Reg No":
            return 26 * mm
        if label == "Patient":
            return 42 * mm
        if label == "Service Name":
            return 60 * mm
        if label == "Sub Dept":
            return 26 * mm
        if label == "Rate":
            return 18 * mm
        if label == "Qty":
            return 12 * mm
        if label == "Total":
            return 20 * mm
        if "Doctor" in label:
            return 40 * mm
        if "Incharge" in label:
            return 36 * mm
        return 24 * mm

    col_widths = [_col_width(label) for label, _ in col_defs]
    tbl = Table(table_data, colWidths=col_widths, repeatRows=1)
    tbl_style = TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("FONTSIZE", (0, 0), (-1, -1), 7),
        ("GRID", (0, 0), (-1, -1), 0.4, colors.HexColor("#1f2937")),
        ("VALIGN", (0, 0), (-1, -1), "TOP"),
    ])

    for idx, (_, col) in enumerate(col_defs):
        if col in numeric_cols:
            tbl_style.add("ALIGN", (idx, 1), (idx, -1), "RIGHT")

    tbl.setStyle(tbl_style)
    elements.append(tbl)
    elements.append(Spacer(1, 8))

    summary_rows = [["Summary", "Value"], ["Total Rows", f"{len(df):,}"]]
    if qty_col:
        total_qty = sum(_safe_float(v) for v in df[qty_col].tolist())
        summary_rows.append(["Total Quantity", _fmt_qty(total_qty)])
    if total_col:
        total_amt = sum(_safe_float(v) for v in df[total_col].tolist())
        summary_rows.append(["Total Amount", _format_inr(total_amt)])

    summary_table = Table(summary_rows, colWidths=[45 * mm, 35 * mm])
    summary_table.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#e2e8f0")),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("ALIGN", (1, 1), (-1, -1), "RIGHT"),
        ("GRID", (0, 0), (-1, -1), 0.4, colors.HexColor("#1f2937")),
        ("FONTSIZE", (0, 0), (-1, -1), 8),
    ]))
    elements.append(summary_table)
    elements.append(Paragraph("Copyright: (c) ASARFI HOSPITAL", style_meta))

    def _draw_page_number(canvas, doc_obj):
        canvas.saveState()
        canvas.setFont("Helvetica", 8)
        width, _ = doc.pagesize
        canvas.drawRightString(width - 12 * mm, 10 * mm, f"Page {doc_obj.page}")
        canvas.restoreState()

    doc.build(elements, onFirstPage=_draw_page_number, onLaterPages=_draw_page_number)
    buffer.seek(0)
    return buffer


@app.route('/api/mis/service_ledger/export_pdf')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_service_ledger_export_pdf():
    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    service_name = (request.args.get("service_name") or "").strip()
    service_id_raw = (request.args.get("service_id") or "").strip()
    service_id = None
    if service_id_raw:
        try:
            service_id = int(service_id_raw)
        except ValueError:
            service_id = None

    allowed_units = _analytics_allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)

    if not target_unit or (allowed_units and target_unit not in allowed_units):
        return "Unauthorized", 403

    exported_by = session.get("username") or session.get("user") or "Unknown"
    buffer = _build_service_ledger_pdf_buffer(target_unit, from_date, to_date, service_name, exported_by, service_id=service_id)
    if buffer is None:
        return "No data found for export", 404

    filename = f"Service_Ledger_{target_unit}_{from_date}_to_{to_date}.pdf"
    return send_file(buffer, mimetype="application/pdf", as_attachment=True, download_name=filename)


# ============================================================
# MIS: Diagnostics & Laboratory Summary
# ============================================================
LAB_DETAIL_COLUMNS = [
    "BillDate",
    "Registration_No",
    "Patient",
    "PatientType",
    "TypeOfVisit",
    "Doctor",
    "SubDepartment_Name",
    "Service_Name",
    "Quantity",
    "Amount",
]

def _lab_unit_header_text(unit: str) -> str:
    unit_key = str(unit or "").strip().upper()
    if unit_key == "ACI":
        return "Asarfi Cancer Institute"
    if unit_key == "BALLIA":
        return "Asarfi Hospital, Ballia (A unit of ASAP Impact Ltd.)"
    if unit_key == "AHL":
        return "Asarfi Hospital"
    return "ASARFI HOSPITAL"


def _build_laboratory_details_df(df_raw: pd.DataFrame) -> pd.DataFrame:
    if df_raw is None or df_raw.empty:
        return pd.DataFrame(columns=LAB_DETAIL_COLUMNS)

    df_raw = _clean_df_columns(df_raw)
    cols_map = {str(c).strip().lower(): c for c in df_raw.columns}

    def _pick(candidates):
        for cand in candidates:
            key = cand.lower()
            if key in cols_map:
                return cols_map[key]
        return None

    col_map = {
        "PatientType": _pick(["PatientType", "Patient_Type", "PatType"]),
        "Patient": _pick(["Patient", "PatientName", "Patient_Name"]),
        "Registration_No": _pick(["Registration_No", "RegistrationNo", "RegNo", "Reg_No", "UHID"]),
        "Amount": _pick(["Amount", "NetAmount", "Net_Amt", "TotalAmount", "Total_Amt"]),
        "Quantity": _pick(["Quantity", "Qty", "QTY"]),
        "TypeOfVisit": _pick(["TypeOfVisit", "VisitType", "Visit Type"]),
        "BillDate": _pick(["BillDate", "Bill_Date", "Billdate", "Date"]),
        "Doctor": _pick(["Doctor", "DoctorName", "DocInCharge", "DocIncharge", "DoctorInCharge"]),
        "SubDepartment_Name": _pick(["SubDepartment_Name", "SubDept", "Sub_Department", "SubDepartment"]),
        "Service_Name": _pick(["Service_Name", "ServiceName", "Service", "Service Name"]),
    }

    details = pd.DataFrame()
    for col in LAB_DETAIL_COLUMNS:
        source = col_map.get(col)
        if source and source in df_raw.columns:
            details[col] = df_raw[source]
        else:
            details[col] = pd.Series([None] * len(df_raw))

    bill_series = pd.to_datetime(details["BillDate"], errors="coerce")
    details["BillDate"] = bill_series.dt.strftime("%Y-%m-%d").fillna("")

    details["Amount"] = (
        pd.to_numeric(details["Amount"], errors="coerce")
        .fillna(0.0)
        .astype(float)
    )
    details["Quantity"] = (
        pd.to_numeric(details["Quantity"], errors="coerce")
        .fillna(0.0)
        .astype(float)
    )

    for col in [
        "PatientType",
        "Patient",
        "Registration_No",
        "TypeOfVisit",
        "Doctor",
        "SubDepartment_Name",
        "Service_Name",
    ]:
        details[col] = details[col].astype(str).replace({"nan": "", "None": ""}).str.strip()

    return details[LAB_DETAIL_COLUMNS]


def _build_laboratory_summary_frames(details_df: pd.DataFrame):
    if details_df is None or details_df.empty:
        empty_summary = pd.DataFrame(columns=["Name", "Records", "Revenue"])
        return empty_summary, empty_summary, 0.0, 0, 0.0

    work = details_df.copy()
    work["Doctor"] = work["Doctor"].replace("", "Unknown").fillna("Unknown")
    work["PatientType"] = work["PatientType"].replace("", "Unknown").fillna("Unknown")

    total_revenue = float(work["Amount"].sum())
    total_records = int(len(work))
    total_quantity = float(work["Quantity"].sum())

    doctor_summary = (
        work.groupby("Doctor", dropna=False)
        .agg(Records=("Doctor", "size"), Revenue=("Amount", "sum"))
        .reset_index()
        .rename(columns={"Doctor": "Name"})
        .sort_values("Revenue", ascending=False)
    )

    patient_summary = (
        work.groupby("PatientType", dropna=False)
        .agg(Records=("PatientType", "size"), Revenue=("Amount", "sum"))
        .reset_index()
        .rename(columns={"PatientType": "Name"})
        .sort_values("Revenue", ascending=False)
    )

    return doctor_summary, patient_summary, total_revenue, total_records, total_quantity


@app.route('/api/mis/laboratory_summary')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_laboratory_summary():
    unit = (request.args.get("unit") or "").strip().upper()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _analytics_allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)

    if not target_unit or (allowed_units and target_unit not in allowed_units):
        return jsonify({"status": "error", "message": "Unauthorized Unit Access"}), 403

    df_raw = data_fetch.fetch_laboratory_summary(target_unit, from_date, to_date)
    if df_raw is None:
        return jsonify({"status": "error", "message": "Database error"}), 500

    details_df = _build_laboratory_details_df(df_raw)
    doctor_summary, patient_summary, total_revenue, total_records, total_quantity = _build_laboratory_summary_frames(details_df)

    details_records = details_df.where(pd.notna(details_df), None).to_dict(orient="records")
    doctor_records = doctor_summary.to_dict(orient="records")
    patient_records = patient_summary.to_dict(orient="records")

    return jsonify({
        "status": "success",
        "unit": target_unit,
        "from_date": from_date,
        "to_date": to_date,
        "total_revenue": total_revenue,
        "total_records": total_records,
        "total_quantity": total_quantity,
        "doctor_summary": doctor_records,
        "patienttype_summary": patient_records,
        "details": details_records,
    })


def _build_laboratory_summary_excel(unit: str, from_date: str, to_date: str, exported_by: str):
    df_raw = data_fetch.fetch_laboratory_summary(unit, from_date, to_date)
    if df_raw is None or df_raw.empty:
        return None, None, "No data available to export"

    details_df = _build_laboratory_details_df(df_raw)
    doctor_summary, patient_summary, total_revenue, total_records, total_quantity = _build_laboratory_summary_frames(details_df)

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
        workbook = writer.book

        title_fmt = workbook.add_format({
            "bold": True,
            "font_size": 14,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#1e3a8a",
            "font_color": "white",
        })
        subtitle_fmt = workbook.add_format({
            "bold": True,
            "font_size": 10,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#e2e8f0",
        })
        meta_fmt = workbook.add_format({
            "font_size": 9,
            "align": "center",
            "valign": "vcenter",
            "font_color": "#475569",
        })
        section_fmt = workbook.add_format({
            "bold": True,
            "font_size": 10,
            "align": "left",
            "valign": "vcenter",
            "bg_color": "#f1f5f9",
        })
        header_fmt = workbook.add_format({
            "bold": True,
            "font_size": 9,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#1e3a8a",
            "font_color": "white",
            "border": 1,
        })
        text_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "left"})
        int_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "#,##,##0"})
        pct_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "0.00%"})
        money_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "#,##,##0.00"})
        text_col_fmt = workbook.add_format({"font_size": 9, "align": "left"})
        int_col_fmt = workbook.add_format({"font_size": 9, "align": "right", "num_format": "#,##,##0"})
        money_col_fmt = workbook.add_format({"font_size": 9, "align": "right", "num_format": "#,##,##0.00"})
        border_only_fmt = workbook.add_format({"border": 1})

        exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
        unit_header = _lab_unit_header_text(unit)

        # Summary Sheet
        summary_ws = workbook.add_worksheet("Summary")
        writer.sheets["Summary"] = summary_ws

        summary_last_col = 3
        summary_ws.merge_range(0, 0, 0, summary_last_col, "Diagnostics & Laboratory MIS - Revenue Summary", title_fmt)
        summary_ws.merge_range(1, 0, 1, summary_last_col, f"Unit: {unit_header}", subtitle_fmt)
        summary_ws.merge_range(2, 0, 2, summary_last_col, f"Date Range: {from_date} to {to_date}", subtitle_fmt)
        summary_ws.merge_range(3, 0, 3, summary_last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)

        summary_ws.write(5, 0, "Total Revenue (INR)", section_fmt)
        summary_ws.write(5, 1, total_revenue, money_fmt)
        summary_ws.write(6, 0, "Total Records", section_fmt)
        summary_ws.write(6, 1, total_records, int_fmt)
        summary_ws.write(7, 0, "Total Quantity", section_fmt)
        summary_ws.write(7, 1, total_quantity, int_fmt)

        row_ptr = 9
        summary_ws.merge_range(row_ptr, 0, row_ptr, summary_last_col, "Doctor-wise Revenue Summary", section_fmt)
        row_ptr += 1
        summary_ws.write_row(row_ptr, 0, ["Doctor", "Records", "Revenue (INR)", "Share %"], header_fmt)
        row_ptr += 1
        for _, row in doctor_summary.iterrows():
            share = (float(row["Revenue"]) / total_revenue) if total_revenue else 0.0
            summary_ws.write(row_ptr, 0, row["Name"], text_fmt)
            summary_ws.write(row_ptr, 1, int(row["Records"]), int_fmt)
            summary_ws.write(row_ptr, 2, float(row["Revenue"]), money_fmt)
            summary_ws.write(row_ptr, 3, share, pct_fmt)
            row_ptr += 1

        row_ptr += 2
        summary_ws.merge_range(row_ptr, 0, row_ptr, summary_last_col, "Patient Type-wise Revenue Summary", section_fmt)
        row_ptr += 1
        summary_ws.write_row(row_ptr, 0, ["Patient Type", "Records", "Revenue (INR)", "Share %"], header_fmt)
        row_ptr += 1
        for _, row in patient_summary.iterrows():
            share = (float(row["Revenue"]) / total_revenue) if total_revenue else 0.0
            summary_ws.write(row_ptr, 0, row["Name"], text_fmt)
            summary_ws.write(row_ptr, 1, int(row["Records"]), int_fmt)
            summary_ws.write(row_ptr, 2, float(row["Revenue"]), money_fmt)
            summary_ws.write(row_ptr, 3, share, pct_fmt)
            row_ptr += 1

        summary_ws.merge_range(row_ptr + 1, 0, row_ptr + 1, summary_last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)
        summary_ws.set_column(0, 0, 34)
        summary_ws.set_column(1, 1, 14)
        summary_ws.set_column(2, 2, 18)
        summary_ws.set_column(3, 3, 12)
        summary_ws.freeze_panes(5, 0)

        # Details Sheet
        details_df.to_excel(writer, sheet_name="Details", index=False, startrow=5)
        details_ws = writer.sheets["Details"]
        details_last_col = len(details_df.columns) - 1
        details_ws.merge_range(0, 0, 0, details_last_col, "Diagnostics & Laboratory MIS - Detail Report", title_fmt)
        details_ws.merge_range(1, 0, 1, details_last_col, f"Unit: {unit_header} | Date Range: {from_date} to {to_date}", subtitle_fmt)
        details_ws.merge_range(2, 0, 2, details_last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)

        for col_num, col_name in enumerate(details_df.columns):
            details_ws.write(5, col_num, col_name, header_fmt)
            if col_name == "Amount":
                details_ws.set_column(col_num, col_num, 16, money_col_fmt)
            elif col_name == "Quantity":
                details_ws.set_column(col_num, col_num, 10, int_col_fmt)
            elif col_name == "BillDate":
                details_ws.set_column(col_num, col_num, 14, text_col_fmt)
            elif col_name in {"Patient", "Service_Name"}:
                details_ws.set_column(col_num, col_num, 28, text_col_fmt)
            else:
                details_ws.set_column(col_num, col_num, 20, text_col_fmt)

        data_start_row = 6
        data_end_row = 5 + len(details_df)
        if len(details_df) > 0:
            details_ws.conditional_format(
                data_start_row, 0, data_end_row, details_last_col,
                {"type": "formula", "criteria": "=TRUE", "format": border_only_fmt}
            )

        footer_row = 6 + len(details_df)
        details_ws.merge_range(footer_row, 0, footer_row, details_last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)
        details_ws.freeze_panes(6, 0)

    output.seek(0)
    filename = f"Laboratory_Summary_{unit}_{from_date}_to_{to_date}.xlsx"
    return output.getvalue(), filename, None


def _run_laboratory_summary_excel_job(job_id: str, unit: str, from_date: str, to_date: str, exported_by: str):
    _excel_job_update(job_id, state="running")
    try:
        data, filename, err = _build_laboratory_summary_excel(unit, from_date, to_date, exported_by)
        if not data:
            _excel_job_update(job_id, state="error", error=err or "No data available to export")
            return
        _export_cache_put_bytes("lab_summary_xlsx_job", data, job_id)
        _excel_job_update(job_id, state="done", filename=filename)
    except Exception as exc:
        _excel_job_update(job_id, state="error", error=str(exc))


