# ============================================================
# NEW: Collections PDF Export
# ============================================================

def _build_collections_pdf_buffer(target_unit: str, from_date: str, to_date: str, username: str):
    import io
    from reportlab.lib.pagesizes import A4, landscape
    from reportlab.lib import colors
    from reportlab.lib.units import inch, mm
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer, PageBreak
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_RIGHT, TA_LEFT
    from datetime import datetime

    # --- 1. Helpers ---
    def format_inr(number):
        """Formats a number into Indian Currency format (e.g., 1,23,456.00)"""
        try:
            n = float(number)
        except (ValueError, TypeError):
            return "0.00"

        s, *d = str("{:.2f}".format(n)).partition(".")
        # Logic: Group last 3, then every 2
        r = ",".join([s[x-2:x] for x in range(-3, -len(s), -2)][::-1] + [s[-3:]])
        val = "".join([r] + d)
        return val

    def get_crystal_category(row):
        """
        Crystal Logic:
        IF ISNULL({PatientType}) THEN "Temporary Patients"
        ELSE IF {PatientType} LIKE "*Cashless*" THEN "Cashless Category"
        ELSE IF {PatientType} LIKE "*Cash*" THEN "Cash Category"
        ELSE "Category Undefined"
        """
        # Fetch PatientType safely (handling potential column name variations)
        pt = str(row.get("PatientTypes") or row.get("PatientType") or "").strip()

        if not pt or pt.lower() in ('nan', 'none', 'null'):
            return "Temporary Patients"

        pt_lower = pt.lower()
        if "cashless" in pt_lower:
            return "Cashless Category"
        elif "cash" in pt_lower:
            return "Cash Category"
        else:
            return "Category Undefined"

    df = data_fetch.fetch_receipt_summary(target_unit, from_date, to_date)
    if df is None or df.empty:
        return None

    df = _clean_df_columns(df)

    # Pre-calc columns
    def txt(val): return str(val).strip() if pd.notna(val) else ""
    def num(val): return float(val) if pd.notna(val) else 0.0
    def fmt_date(val):
        try: return pd.to_datetime(val).strftime("%d-%m-%Y")
        except: return ""

    # Split Data
    sections = {
        "IPD": [],
        "PH": [],
        "OPD": []
    }

    for _, r in df.iterrows():
        # Clean row data for usage
        clean_row = r.to_dict()
        clean_row['CrystalCat'] = get_crystal_category(clean_row)

        r_type = txt(r.get("ReceiptType") or r.get("Type")).upper()
        visit = txt(r.get("TypeOfVisit") or r.get("VisitType")).upper()

        if r_type == 'P' and 'IPD' in visit:
            sections["IPD"].append(clean_row)
        elif r_type in ('PH', 'PI'):
            sections["PH"].append(clean_row)
        elif r_type == 'P': # Fallback for OPD/Other
            sections["OPD"].append(clean_row)

    # --- 3. PDF Setup ---
    buffer = io.BytesIO()
    doc = SimpleDocTemplate(buffer, pagesize=landscape(A4),
                            topMargin=10*mm, bottomMargin=15*mm,
                            leftMargin=10*mm, rightMargin=10*mm)
    elements = []
    styles = getSampleStyleSheet()

    # Styles
    style_title = ParagraphStyle('RptTitle', parent=styles['Heading1'], fontSize=16, textColor=colors.HexColor('#1e3a8a'), alignment=TA_CENTER, spaceAfter=2)
    style_subtitle = ParagraphStyle('RptSub', parent=styles['Normal'], fontSize=10, textColor=colors.HexColor('#475569'), alignment=TA_CENTER, spaceAfter=12)
    style_section = ParagraphStyle('SecHead', parent=styles['Heading2'], fontSize=14, textColor=colors.black, backColor=colors.HexColor('#f1f5f9'), borderPadding=6, spaceBefore=12, spaceAfter=8)

    style_th = ParagraphStyle('TH', parent=styles['Normal'], fontSize=8, fontName='Helvetica-Bold', textColor=colors.white, alignment=TA_CENTER)
    style_td = ParagraphStyle('TD', parent=styles['Normal'], fontSize=8, fontName='Helvetica', textColor=colors.black)
    style_td_right = ParagraphStyle('TDRight', parent=styles['Normal'], fontSize=8, fontName='Helvetica', textColor=colors.black, alignment=TA_RIGHT)

    # Summary Styles
    style_sum_mode = ParagraphStyle('SumMode', parent=styles['Normal'], fontSize=10, fontName='Helvetica-Bold', textColor=colors.red, alignment=TA_RIGHT)
    style_sum_label = ParagraphStyle('SumLabel', parent=styles['Normal'], fontSize=9, fontName='Helvetica-Bold', textColor=colors.black)
    style_sum_val = ParagraphStyle('SumVal', parent=styles['Normal'], fontSize=9, fontName='Helvetica-Bold', textColor=colors.black, alignment=TA_RIGHT)
    style_sum_total_label = ParagraphStyle('SumTotLabel', parent=styles['Normal'], fontSize=9, fontName='Helvetica-Bold', textColor=colors.black, alignment=TA_RIGHT)

    user_name = username or 'System'
    gen_time = datetime.now(tz=LOCAL_TZ).strftime("%d-%b-%Y %I:%M %p")

    def header_footer(canvas, doc):
        canvas.saveState()

        # Determine Header Text based on Unit
        unit_key = str(target_unit).upper().strip()
        if unit_key == 'ACI':
            header_text = "Asarfi Cancer Institute"
        elif unit_key == 'BALLIA':
            header_text = "Asarfi Hospital, Ballia (A unit of ASAP Impact Ltd.)"
        elif unit_key == 'AHL':
            header_text = "Asarfi Hospital"
        else:
            header_text = "ASARFI HOSPITAL"

        # Header
        canvas.setFont('Helvetica-Bold', 10)
        canvas.setFillColor(colors.HexColor('#1e3a8a'))
        canvas.drawString(10*mm, 200*mm, header_text)

        # Footer Line
        canvas.setStrokeColor(colors.gray)
        canvas.setLineWidth(0.5)
        canvas.line(10*mm, 12*mm, 287*mm, 12*mm)

        # Footer Text
        canvas.setFont('Helvetica', 8)
        canvas.setFillColor(colors.black)

        # Left Side
        canvas.drawString(10*mm, 8*mm, f"Generated by: {user_name} | {gen_time}")
        canvas.setFont('Helvetica-Oblique', 8)
        canvas.setFillColor(colors.HexColor('#64748b'))

        # Confidential Text
        canvas.drawString(10*mm, 4*mm, "Confidential Financial Document")

        # Right Side (Page Number)
        canvas.setFont('Helvetica', 8)
        canvas.setFillColor(colors.black)
        canvas.drawRightString(287*mm, 8*mm, f"Page {doc.page}")

        canvas.restoreState()

    # --- 4. Content Generators ---

    def add_detail_list(rows):
        if not rows:
            elements.append(Paragraph("No Records Found", styles['Normal']))
            return

        # 1. Sort rows by User to ensure grouping works
        rows.sort(key=lambda x: txt(x.get("UserName") or "Unknown User").lower())

        # 2. Define Columns (Removed 'User', adjusted widths)
        # Sl, RecNo, Date, Patient, RegNo, RefNo, Mode, Amount
        col_widths = [10*mm, 35*mm, 20*mm, 70*mm, 30*mm, 35*mm, 45*mm, 30*mm]

        # 3. Initialize Table Data with Header
        table_data = [[
            Paragraph("Sl.", style_th),
            Paragraph("Receipt No", style_th),
            Paragraph("Date", style_th),
            Paragraph("Patient Name", style_th),
            Paragraph("Reg. No", style_th),
            Paragraph("Bill/Visit No", style_th),
            Paragraph("Payment Mode", style_th),
            Paragraph("Amount", style_th)
        ]]

        # 4. Base Table Styles
        tbl_style_cmds = [
            ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#1e3a8a')),
            ('TEXTCOLOR', (0, 0), (-1, 0), colors.white),
            ('ALIGN', (0, 0), (-1, -1), 'LEFT'),
            ('ALIGN', (-1, 0), (-1, -1), 'RIGHT'), # Amount Column Right Align
            ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
            ('FONTSIZE', (0, 0), (-1, -1), 8),
            ('GRID', (0, 0), (-1, -1), 0.25, colors.HexColor('#e2e8f0')),
            ('BOTTOMPADDING', (0, 0), (-1, -1), 4),
            ('TOPPADDING', (0, 0), (-1, -1), 4),
        ]

        current_user = None
        user_total = 0
        grand_total = 0
        sl_no = 1
        row_idx = 1 # Start at 1 because 0 is header

        # --- Loop through rows ---
        for r in rows:
            this_user = txt(r.get("UserName") or "Unknown User")
            amt = num(r.get("Amount") or r.get("NetAmount"))

            # Check for User Change
            if this_user != current_user:
                # If not the first user, print previous user's subtotal
                if current_user is not None:
                    table_data.append([
                        "", "", "", "", "", "",
                        Paragraph(f"<b>Total for {current_user}:</b>", style_td_right),
                        Paragraph(f"<b>{format_inr(user_total)}</b>", style_td_right)
                    ])
                    # Style for Subtotal Row
                    tbl_style_cmds.append(('BACKGROUND', (0, row_idx), (-1, row_idx), colors.HexColor('#f1f5f9')))
                    tbl_style_cmds.append(('LINEABOVE', (-2, row_idx), (-1, row_idx), 1, colors.black))
                    tbl_style_cmds.append(('SPAN', (0, row_idx), (5, row_idx)))
                    row_idx += 1

                # Print New User Header
                table_data.append([
                    Paragraph(f"<b>User: {this_user}</b>", style_td),
                    "", "", "", "", "", "", ""
                ])
                # Style for User Header Row
                tbl_style_cmds.append(('BACKGROUND', (0, row_idx), (-1, row_idx), colors.HexColor('#dbeafe')))
                tbl_style_cmds.append(('TEXTCOLOR', (0, row_idx), (-1, row_idx), colors.HexColor('#1e3a8a')))
                tbl_style_cmds.append(('SPAN', (0, row_idx), (-1, row_idx)))

                current_user = this_user
                user_total = 0
                row_idx += 1

            # Add Detail Row
            ref_no = txt(r.get("BillNo")) if txt(r.get("ReceiptType")).upper() in ('PH', 'PI') else txt(r.get("VisitNo"))

            row_content = [
                str(sl_no),
                txt(r.get("Receipt_No")),
                fmt_date(r.get("Receipt_Date")),
                Paragraph(txt(r.get("Patientname") or r.get("Patient")), style_td),
                txt(r.get("RegNo")),
                ref_no,
                txt(r.get("PModeName")),
                Paragraph(format_inr(amt), style_td_right)
            ]
            table_data.append(row_content)

            user_total += amt
            grand_total += amt
            sl_no += 1
            row_idx += 1

        # --- After Loop: Print Last User Subtotal ---
        if current_user is not None:
            table_data.append([
                "", "", "", "", "", "",
                Paragraph(f"<b>Total for {current_user}:</b>", style_td_right),
                Paragraph(f"<b>{format_inr(user_total)}</b>", style_td_right)
            ])
            tbl_style_cmds.append(('BACKGROUND', (0, row_idx), (-1, row_idx), colors.HexColor('#f1f5f9')))
            tbl_style_cmds.append(('LINEABOVE', (-2, row_idx), (-1, row_idx), 1, colors.black))
            tbl_style_cmds.append(('SPAN', (0, row_idx), (5, row_idx)))
            row_idx += 1

        # --- Print Grand Total ---
        table_data.append([
            "", "", "", "", "", "",
            Paragraph("<b><font color='white'>GRAND TOTAL:</font></b>", style_td_right),
            Paragraph(f"<b><font color='white'>{format_inr(grand_total)}</font></b>", style_td_right)
        ])
        tbl_style_cmds.append(('BACKGROUND', (0, row_idx), (-1, row_idx), colors.HexColor('#1e3a8a')))
        tbl_style_cmds.append(('TEXTCOLOR', (0, row_idx), (-1, row_idx), colors.white))
        tbl_style_cmds.append(('SPAN', (0, row_idx), (5, row_idx)))

        # Build Table
        t = Table(table_data, colWidths=col_widths, repeatRows=1)
        t.setStyle(TableStyle(tbl_style_cmds))

        elements.append(t)
        elements.append(Spacer(1, 8*mm))

    def add_summaries(rows):
        if not rows:
            return

        style_th_left = ParagraphStyle('THLeft', parent=styles['Normal'], fontSize=9, fontName='Helvetica-Bold', textColor=colors.white, alignment=TA_LEFT)
        style_th_right = ParagraphStyle('THRight', parent=styles['Normal'], fontSize=9, fontName='Helvetica-Bold', textColor=colors.white, alignment=TA_RIGHT)
        style_td = ParagraphStyle('TD', parent=styles['Normal'], fontSize=8, fontName='Helvetica', textColor=colors.black)
        style_td_right = ParagraphStyle('TDRight', parent=styles['Normal'], fontSize=8, fontName='Helvetica', textColor=colors.black, alignment=TA_RIGHT)
        style_sum_total_label = ParagraphStyle('SumTotLbl', parent=styles['Normal'], fontSize=8, fontName='Helvetica-Bold', textColor=colors.black, alignment=TA_RIGHT)
        style_sum_val = ParagraphStyle('SumVal', parent=styles['Normal'], fontSize=8, fontName='Helvetica-Bold', textColor=colors.black, alignment=TA_RIGHT)

        mode_groups = {}
        for r in rows:
            m = txt(r.get("PModeName"))
            cat = r['CrystalCat']
            amt = num(r.get("Amount"))
            if m not in mode_groups:
                mode_groups[m] = {}
            mode_groups[m][cat] = mode_groups[m].get(cat, 0) + amt

        pt_groups = {}
        for r in rows:
            val = txt(r.get("PatientTypes") or r.get("PatientType"))
            if not val or val.lower() == "unknown":
                pt_raw = "Temporary Patients"
            else:
                pt_raw = val
            m = txt(r.get("PModeName"))
            amt = num(r.get("Amount"))
            if pt_raw not in pt_groups:
                pt_groups[pt_raw] = {}
            pt_groups[pt_raw][m] = pt_groups[pt_raw].get(m, 0) + amt

        grand_total = sum(num(r.get("Amount")) for r in rows)
        col_widths = [80*mm, 35*mm]

        t1_data = []
        t1_data.append([Paragraph("Summary 1: Payment Mode Breakdown", style_th_left), ""])

        sorted_modes = sorted(mode_groups.keys())
        for mode in sorted_modes:
            cats = mode_groups[mode]
            mode_total = sum(cats.values())

            t1_data.append([Paragraph(f"<b>{mode}</b>", style_td), ""])

            for cat in sorted(cats.keys()):
                t1_data.append([
                    Paragraph(f"&nbsp;&nbsp;&nbsp;&nbsp;{cat}", style_td),
                    Paragraph(format_inr(cats[cat]), style_td_right)
                ])

            t1_data.append([
                Paragraph(f"Total {mode}:", style_sum_total_label),
                Paragraph(format_inr(mode_total), style_sum_val)
            ])

        t1_data.append([
            Paragraph("Grand Total:", style_th_left),
            Paragraph(f"<b>{format_inr(grand_total)}</b>", style_th_right)
        ])

        t2_data = []
        t2_data.append([Paragraph("Summary 2: Category Details", style_th_left), ""])

        sorted_pts = sorted(pt_groups.keys())
        for pt in sorted_pts:
            modes = pt_groups[pt]

            t2_data.append([Paragraph(f"<b>{pt}</b>", style_td), ""])

            for m in sorted(modes.keys()):
                t2_data.append([
                    Paragraph(f"&nbsp;&nbsp;&nbsp;&nbsp;{m}", style_td),
                    Paragraph(format_inr(modes[m]), style_td_right)
                ])

        t2_data.append([
            Paragraph("Grand Total:", style_th_left),
            Paragraph(f"<b>{format_inr(grand_total)}</b>", style_th_right)
        ])

        def create_summary_table(data):
            t = Table(data, colWidths=col_widths, hAlign='LEFT')

            tbl_style = [
                ('GRID', (0, 0), (-1, -1), 0.25, colors.HexColor('#cbd5e1')),
                ('VALIGN', (0, 0), (-1, -1), 'MIDDLE'),
                ('BOTTOMPADDING', (0, 0), (-1, -1), 4),
                ('TOPPADDING', (0, 0), (-1, -1), 4),
                ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#1e3a8a')),
                ('TEXTCOLOR', (0, 0), (-1, 0), colors.white),
                ('SPAN', (0, 0), (1, 0)),
                ('BACKGROUND', (0, -1), (-1, -1), colors.HexColor('#1e3a8a')),
                ('TEXTCOLOR', (0, -1), (-1, -1), colors.white),
            ]

            for i, row in enumerate(data):
                if i > 0 and i < len(data)-1:
                    if row[1] == "":
                        tbl_style.append(('BACKGROUND', (0, i), (-1, i), colors.HexColor('#f1f5f9')))
                        tbl_style.append(('SPAN', (0, i), (1, i)))
                        tbl_style.append(('FONTNAME', (0, i), (-1, i), 'Helvetica-Bold'))

                    if hasattr(row[0], 'text') and 'Total' in row[0].text:
                        tbl_style.append(('LINEABOVE', (0, i), (-1, i), 0.5, colors.black))
                        tbl_style.append(('FONTNAME', (0, i), (-1, i), 'Helvetica-Bold'))
                        tbl_style.append(('BACKGROUND', (0, i), (-1, i), colors.HexColor('#e2e8f0')))

            t.setStyle(TableStyle(tbl_style))
            return t

        t1 = create_summary_table(t1_data)
        t2 = create_summary_table(t2_data)

        elements.append(Spacer(1, 5*mm))

        max_rows = max(len(t1_data), len(t2_data))
        if max_rows > 20:
            elements.append(t1)
            elements.append(Spacer(1, 5*mm))
            elements.append(t2)
        else:
            container_data = [[t1, "", t2]]
            container_table = Table(container_data, colWidths=[115*mm, 10*mm, 115*mm], hAlign='LEFT')
            container_table.setStyle(TableStyle([
                ('VALIGN', (0, 0), (-1, -1), 'TOP'),
            ]))
            elements.append(container_table)

        elements.append(Spacer(1, 5*mm))

    # --- 5. Orchestration (Sequence) ---
    elements.append(Paragraph("Daily Collection Report", style_title))
    elements.append(Paragraph(f"Unit: {target_unit} | Date Range: {from_date} to {to_date}", style_subtitle))
    elements.append(Spacer(1, 5*mm))

    if sections["IPD"]:
        elements.append(Paragraph("1. IPD Patient Collection List", style_section))
        add_detail_list(sections["IPD"])
        elements.append(PageBreak())
        add_summaries(sections["IPD"])
        elements.append(PageBreak())

    if sections["PH"]:
        elements.append(Paragraph("2. PH Sale Collection List", style_section))
        add_detail_list(sections["PH"])
        elements.append(PageBreak())
        add_summaries(sections["PH"])
        elements.append(PageBreak())

    if sections["OPD"]:
        elements.append(Paragraph("3. OPD Patient Collection List", style_section))
        add_detail_list(sections["OPD"])
        elements.append(PageBreak())
        add_summaries(sections["OPD"])

    doc.build(elements, onFirstPage=header_footer, onLaterPages=header_footer)
    buffer.seek(0)
    return buffer

@app.route('/api/mis/collections/export_pdf')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_collections_export_pdf():
    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit or (allowed_units and target_unit not in allowed_units):
        return "Unauthorized Unit Access", 403

    username = session.get("username") or session.get("user") or "System"
    buffer = _build_collections_pdf_buffer(target_unit, from_date, to_date, username)
    if buffer is None:
        return "No data available to export", 404

    return send_file(
        buffer,
        as_attachment=True,
        download_name=f"Collection_Report_{target_unit}_{from_date}.pdf",
        mimetype='application/pdf'
    )

@app.route('/api/mis/admin/balances')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_admin_balances():
    unit = (request.args.get("unit") or "").strip().upper()
    from_date = request.args.get("from")
    to_date = request.args.get("to")

    if not from_date or not to_date:
        return jsonify({"status": "error", "message": "Date range required"}), 400

    allowed_units = _allowed_units_for_session()
    if not unit or (allowed_units and unit not in allowed_units):
        # Default to first allowed if valid, else error
        if allowed_units:
            unit = allowed_units[0]
        else:
             return jsonify({"status": "error", "message": "Access denied"}), 403

    df = data_fetch.fetch_ipd_bill_tracking(unit, from_date, to_date)
    
    if df is None:
        return jsonify({"status": "error", "message": "Database error"}), 500
    
    # Convert NaN to None for valid JSON
    records = df.where(pd.notna(df), None).to_dict(orient="records")
    
    return jsonify({
        "status": "success", 
        "data": records, 
        "unit": unit,
        "count": len(records)
    })


@app.route('/api/mis/admin/balances/export_excel')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_admin_balances_export_excel():
    import io
    import pandas as pd

    unit = (request.args.get("unit") or "").strip().upper()
    from_date = request.args.get("from")
    to_date = request.args.get("to")

    if not from_date or not to_date:
        return "Date range required", 400

    allowed_units = _allowed_units_for_session()
    if not unit or (allowed_units and unit not in allowed_units):
        if allowed_units:
            unit = allowed_units[0]
        else:
            return "Unauthorized", 403

    df = data_fetch.fetch_ipd_bill_tracking(unit, from_date, to_date)
    if df is None or df.empty:
        return "No data found for export", 404

    df = _clean_df_columns(df)

    fixed_order = [
        "Registration_No",
        "PatientName",
        "DoctorInCharge",
        "AdminssionDt",
        "DischargeDate",
        "BillDate",
        "PatientCategory",
        "PatientType",
        "VisitNo",
        "LabAmount",
        "RadioAmount",
        "GDMO",
        "Oxygen",
        "Other Consultants",
        "Anaesthesia",
        "Fooding",
        "DiscountAmount",
        "FinalAmount",
        "GrossAmount",
    ]

    cols_map = {str(c).strip(): c for c in df.columns}
    ordered_cols = [cols_map[c] for c in fixed_order if c in cols_map]
    final_cols = ordered_cols + [c for c in df.columns if c not in ordered_cols]
    df = df[final_cols]

    def _num_series(series):
        cleaned = series.astype(str).str.replace(",", "", regex=False)
        cleaned = cleaned.str.replace(r"[^0-9.\-]", "", regex=True)
        return pd.to_numeric(cleaned, errors="coerce").fillna(0)

    amount_keywords = ["amount", "gdmo", "oxygen", "consultants", "anaesthesia", "fooding"]
    for col in df.columns:
        if any(k in str(col).lower() for k in amount_keywords):
            df[col] = _num_series(df[col])

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
        wb = writer.book

        title_fmt = wb.add_format({
            "bold": True, "font_size": 14, "font_color": "#1E3A8A",
            "align": "center", "valign": "vcenter"
        })
        subtitle_fmt = wb.add_format({
            "bold": True, "font_size": 11, "align": "center", "valign": "vcenter"
        })
        meta_fmt = wb.add_format({"font_size": 9, "align": "left", "valign": "vcenter"})
        header_fmt = wb.add_format({
            "bold": True, "bg_color": "#1E3A8A", "font_color": "white",
            "border": 1, "align": "center", "valign": "vcenter"
        })
        text_fmt = wb.add_format({"align": "left", "valign": "vcenter"})
        date_fmt = wb.add_format({"num_format": "yyyy-mm-dd", "align": "center", "valign": "vcenter"})
        money_fmt = wb.add_format({"num_format": "#,##,##0.00", "align": "right", "valign": "vcenter"})

        exported_by = session.get("username") or session.get("user") or "Unknown"
        exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")

        sheet_name = "Balances & Ledgers"
        df.to_excel(writer, sheet_name=sheet_name, index=False, startrow=5, header=False)
        ws = writer.sheets[sheet_name]

        last_col = len(df.columns) - 1
        ws.merge_range(0, 0, 0, last_col, "Balances & Ledgers", title_fmt)
        ws.merge_range(1, 0, 1, last_col, f"Unit: {unit} | Date Range: {from_date} to {to_date}", subtitle_fmt)
        ws.merge_range(2, 0, 2, last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)
        ws.merge_range(3, 0, 3, last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)

        for col_idx, col_name in enumerate(df.columns):
            ws.write(4, col_idx, col_name, header_fmt)
            col_lower = str(col_name).lower()
            width = 16
            fmt = text_fmt
            if "date" in col_lower or "time" in col_lower:
                width = 18
                fmt = date_fmt
            elif any(k in col_lower for k in amount_keywords):
                width = 16
                fmt = money_fmt
            elif any(x in col_lower for x in ["patient", "doctor"]):
                width = 24
            ws.set_column(col_idx, col_idx, width, fmt)

        ws.freeze_panes(5, 0)

    output.seek(0)
    fname = f"Balances_Ledgers_{unit}_{from_date}.xlsx"
    return send_file(
        output,
        as_attachment=True,
        download_name=fname,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    )


@app.route('/api/mis/ip_ledger_summary')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_ip_ledger_summary():
    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _allowed_units_for_session()
