def _build_ip_package_ledger_pdf_buffer(unit: str, from_date: str, to_date: str, exported_by: str):
    from reportlab.lib.pagesizes import A4, landscape
    from reportlab.lib import colors
    from reportlab.lib.units import mm
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer, PageBreak, Image
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_RIGHT
    from xml.sax.saxutils import escape

    def _format_inr(number) -> str:
        try:
            n = float(number or 0)
        except Exception:
            return "0.00"
        sign = "-" if n < 0 else ""
        n = abs(n)
        s = f"{n:.2f}"
        whole, frac = s.split(".")
        if len(whole) <= 3:
            grouped = whole
        else:
            last = whole[-3:]
            rest = whole[:-3]
            parts = []
            while rest:
                parts.append(rest[-2:])
                rest = rest[:-2]
            grouped = ",".join(reversed(parts)) + "," + last
        return f"{sign}{grouped}.{frac}"

    def _fmt_pct(value) -> str:
        try:
            return f"{float(value):.2f}%"
        except Exception:
            return "0.00%"

    df_raw = data_fetch.fetch_ip_package_ledger(unit, from_date, to_date)
    if df_raw is None or df_raw.empty:
        return None

    df = _clean_df_columns(df_raw).copy()

    for col in ("Rate", "Quantity", "Amount"):
        if col not in df.columns:
            df[col] = 0
        df[col] = pd.to_numeric(df[col], errors="coerce").fillna(0)

    if "BillDate" in df.columns:
        bill_dt = pd.to_datetime(df["BillDate"], errors="coerce")
        df["BillDateFmt"] = bill_dt.dt.strftime("%Y-%m-%d %H:%M").fillna("")
    else:
        df["BillDateFmt"] = ""

    for col in ("PackageName", "PackageCode", "PackageServiceName", "BillNo", "RegNo", "PatientName", "DoctorInCharge", "Ward"):
        if col not in df.columns:
            df[col] = ""
        df[col] = df[col].fillna("").astype(str).str.strip()

    df["PackageDisplay"] = np.where(df["PackageName"] != "", df["PackageName"], np.where(df["PackageCode"] != "", df["PackageCode"], "Unknown"))

    total_rows = int(len(df))
    total_qty = float(df["Quantity"].sum())
    total_amount = float(df["Amount"].sum())
    unique_bills = int(df["Bill_ID"].fillna(df["BillNo"]).astype(str).str.strip().replace({"": np.nan}).dropna().nunique()) if "Bill_ID" in df.columns else int(df["BillNo"].astype(str).str.strip().replace({"": np.nan}).dropna().nunique())
    unique_patients = int(df["RegNo"].astype(str).str.strip().replace({"": np.nan}).dropna().nunique())
    unique_packages = int(df["PackageDisplay"].astype(str).str.strip().replace({"": np.nan}).dropna().nunique())
    avg_amount_per_bill = (total_amount / unique_bills) if unique_bills else 0
    avg_qty_per_bill = (total_qty / unique_bills) if unique_bills else 0

    package_summary = (
        df.groupby("PackageDisplay", dropna=False, as_index=False)
        .agg(Quantity=("Quantity", "sum"), Amount=("Amount", "sum"))
        .sort_values("Amount", ascending=False)
    )
    package_summary["SharePct"] = np.where(total_amount > 0, (package_summary["Amount"] / total_amount) * 100.0, 0.0)

    top5 = package_summary.head(5).copy()
    top1_share = float(top5.iloc[0]["SharePct"]) if not top5.empty else 0.0
    top5_share = float(top5["SharePct"].sum()) if not top5.empty else 0.0

    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=landscape(A4),
        topMargin=14 * mm,
        bottomMargin=14 * mm,
        leftMargin=12 * mm,
        rightMargin=12 * mm,
    )

    styles = getSampleStyleSheet()
    style_title = ParagraphStyle("IpPkgTitle", parent=styles["Heading2"], fontSize=13, alignment=TA_CENTER, textColor=colors.HexColor("#1e3a8a"))
    style_sub = ParagraphStyle("IpPkgSub", parent=styles["Normal"], fontSize=9, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_meta = ParagraphStyle("IpPkgMeta", parent=styles["Normal"], fontSize=8, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_section = ParagraphStyle("IpPkgSection", parent=styles["Heading4"], fontSize=10, textColor=colors.HexColor("#1e3a8a"), spaceBefore=6, spaceAfter=4)
    style_th = ParagraphStyle("IpPkgTh", parent=styles["Normal"], fontSize=8, textColor=colors.white, alignment=TA_CENTER)
    style_td = ParagraphStyle("IpPkgTd", parent=styles["Normal"], fontSize=7, textColor=colors.black, leading=8)
    style_td_wrap = ParagraphStyle("IpPkgTdWrap", parent=style_td, wordWrap="CJK")
    style_td_right = ParagraphStyle("IpPkgTdRight", parent=style_td, alignment=TA_RIGHT)

    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    unit_header = _lab_unit_header_text(unit)

    elements = []
    logo_path = os.path.join(app.root_path, "static", "logo", "asarfi.png")
    if os.path.exists(logo_path):
        logo = Image(logo_path, width=18 * mm, height=18 * mm, mask="auto")
        logo.hAlign = "CENTER"
        elements.append(logo)

    elements.append(Spacer(1, 4))
    elements.append(Paragraph("IP Package Ledger Report", style_title))
    elements.append(Paragraph(f"Unit: {unit_header}", style_sub))
    elements.append(Paragraph(f"Date Range: {from_date} to {to_date}", style_sub))
    elements.append(Paragraph(f"Exported By: {exported_by} | Exported At: {exported_at}", style_meta))
    elements.append(Spacer(1, 8))

    elements.append(Paragraph("1. KPI Snapshot", style_section))
    kpi_rows = [
        [Paragraph("Metric", style_th), Paragraph("Value", style_th), Paragraph("Metric", style_th), Paragraph("Value", style_th)],
        [Paragraph("Total Rows", style_td), Paragraph(f"{total_rows:,}", style_td_right), Paragraph("Unique Bills", style_td), Paragraph(f"{unique_bills:,}", style_td_right)],
        [Paragraph("Unique Patients", style_td), Paragraph(f"{unique_patients:,}", style_td_right), Paragraph("Unique Packages", style_td), Paragraph(f"{unique_packages:,}", style_td_right)],
        [Paragraph("Total Quantity", style_td), Paragraph(f"{total_qty:,.2f}", style_td_right), Paragraph("Total Amount (INR)", style_td), Paragraph(_format_inr(total_amount), style_td_right)],
        [Paragraph("Avg Amount / Bill (INR)", style_td), Paragraph(_format_inr(avg_amount_per_bill), style_td_right), Paragraph("Avg Quantity / Bill", style_td), Paragraph(f"{avg_qty_per_bill:,.2f}", style_td_right)],
        [Paragraph("Top 1 Package Share", style_td), Paragraph(_fmt_pct(top1_share), style_td_right), Paragraph("Top 5 Package Share", style_td), Paragraph(_fmt_pct(top5_share), style_td_right)],
    ]
    kpi_table = Table(kpi_rows, colWidths=[55 * mm, 30 * mm, 55 * mm, 30 * mm])
    kpi_table.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("GRID", (0, 0), (-1, -1), 0.35, colors.HexColor("#334155")),
        ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
        ("BACKGROUND", (0, 1), (-1, -1), colors.HexColor("#f8fafc")),
    ]))
    elements.append(kpi_table)
    elements.append(Spacer(1, 8))

    elements.append(Paragraph("2. Top Package Mix (By Amount)", style_section))
    top_mix_rows = [[
        Paragraph("Package Name", style_th),
        Paragraph("Quantity", style_th),
        Paragraph("Amount (INR)", style_th),
        Paragraph("Share %", style_th),
    ]]
    if top5.empty:
        top_mix_rows.append([
            Paragraph("No records", style_td_wrap),
            Paragraph("0", style_td_right),
            Paragraph("0.00", style_td_right),
            Paragraph("0.00%", style_td_right),
        ])
    else:
        for _, row in top5.iterrows():
            top_mix_rows.append([
                Paragraph(escape(str(row.get("PackageDisplay") or "")), style_td_wrap),
                Paragraph(f"{float(row.get('Quantity') or 0):,.2f}", style_td_right),
                Paragraph(_format_inr(row.get("Amount") or 0), style_td_right),
                Paragraph(_fmt_pct(row.get("SharePct") or 0), style_td_right),
            ])
        top_mix_rows.append([
            Paragraph("<b>Total (Top 5)</b>", style_td),
            Paragraph(f"<b>{float(top5['Quantity'].sum()):,.2f}</b>", style_td_right),
            Paragraph(f"<b>{_format_inr(top5['Amount'].sum())}</b>", style_td_right),
            Paragraph(f"<b>{_fmt_pct(top5_share)}</b>", style_td_right),
        ])

    top_mix_table = Table(top_mix_rows, colWidths=[105 * mm, 30 * mm, 35 * mm, 25 * mm], repeatRows=1)
    top_mix_style = [
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("GRID", (0, 0), (-1, -1), 0.35, colors.HexColor("#334155")),
        ("VALIGN", (0, 0), (-1, -1), "TOP"),
    ]
    if len(top_mix_rows) > 2:
        top_mix_style.append(("BACKGROUND", (0, -1), (-1, -1), colors.HexColor("#e2e8f0")))
        top_mix_style.append(("FONTNAME", (0, -1), (-1, -1), "Helvetica-Bold"))
    top_mix_table.setStyle(TableStyle(top_mix_style))
    elements.append(top_mix_table)
    elements.append(PageBreak())

    elements.append(Paragraph("3. Detailed Package Ledger", style_section))
    detail_rows = [[
        Paragraph("Bill Date", style_th),
        Paragraph("Bill No", style_th),
        Paragraph("Reg No", style_th),
        Paragraph("Patient", style_th),
        Paragraph("Doctor", style_th),
        Paragraph("Ward", style_th),
        Paragraph("Package Name", style_th),
        Paragraph("Service", style_th),
        Paragraph("Qty", style_th),
        Paragraph("Rate", style_th),
        Paragraph("Amount", style_th),
    ]]

    detail_df = df.sort_values(by=["BillDate"], ascending=False) if "BillDate" in df.columns else df
    for _, row in detail_df.iterrows():
        detail_rows.append([
            Paragraph(escape(str(row.get("BillDateFmt") or "")), style_td),
            Paragraph(escape(str(row.get("BillNo") or "")), style_td),
            Paragraph(escape(str(row.get("RegNo") or "")), style_td),
            Paragraph(escape(str(row.get("PatientName") or "")), style_td_wrap),
            Paragraph(escape(str(row.get("DoctorInCharge") or "")), style_td_wrap),
            Paragraph(escape(str(row.get("Ward") or "")), style_td_wrap),
            Paragraph(escape(str(row.get("PackageDisplay") or "")), style_td_wrap),
            Paragraph(escape(str(row.get("PackageServiceName") or "")), style_td_wrap),
            Paragraph(f"{float(row.get('Quantity') or 0):,.2f}", style_td_right),
            Paragraph(_format_inr(row.get("Rate") or 0), style_td_right),
            Paragraph(_format_inr(row.get("Amount") or 0), style_td_right),
        ])

    detail_table = Table(
        detail_rows,
        colWidths=[18 * mm, 15 * mm, 20 * mm, 32 * mm, 30 * mm, 24 * mm, 30 * mm, 38 * mm, 10 * mm, 16 * mm, 20 * mm],
        repeatRows=1,
    )
    detail_table.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("FONTSIZE", (0, 0), (-1, -1), 6.5),
        ("GRID", (0, 0), (-1, -1), 0.3, colors.HexColor("#475569")),
        ("VALIGN", (0, 0), (-1, -1), "TOP"),
        ("ALIGN", (-3, 1), (-1, -1), "RIGHT"),
    ]))
    elements.append(detail_table)

    footer_text = f"Exported By: {exported_by} | Exported At: {exported_at} | Unit: {unit} | Date Range: {from_date} to {to_date}"

    def _draw_footer(canvas, doc_obj):
        canvas.saveState()
        width, _ = doc.pagesize
        canvas.setFont("Helvetica", 8)
        canvas.setFillColor(colors.HexColor("#64748b"))
        canvas.drawString(doc_obj.leftMargin, 8 * mm, footer_text)
        canvas.drawRightString(width - doc_obj.rightMargin, 8 * mm, f"Page {doc_obj.page}")
        canvas.restoreState()

    doc.build(elements, onFirstPage=_draw_footer, onLaterPages=_draw_footer)
    buffer.seek(0)
    return buffer


@app.route('/api/mis/ip_package_ledger/export_pdf')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_ip_package_ledger_export_pdf():
    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return "No unit available", 400
    if allowed_units and target_unit not in allowed_units:
        return "Unit not allowed", 403

    exported_by = session.get("username") or session.get("user") or "Unknown"
    buffer = _build_ip_package_ledger_pdf_buffer(target_unit, from_date, to_date, exported_by)
    if buffer is None:
        return "No data available to export", 404

    filename = f"IP_Package_Ledger_{target_unit}_{from_date}_to_{to_date}.pdf"
    return send_file(buffer, mimetype="application/pdf", as_attachment=True, download_name=filename)


@app.route('/api/mis/ip_ledger_summary/export_excel')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_ip_ledger_summary_export_excel():
    import io
    import pandas as pd

    unit = (request.args.get("unit") or "").strip()
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")

    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return "No unit available", 400
    if allowed_units and target_unit not in allowed_units:
        return "Unit not allowed", 403

    df = data_fetch.fetch_visit_billing_receipt_summary(target_unit, from_date, to_date)
    if df is None or df.empty:
        return "No data found for export", 404

    df = _clean_df_columns(df)

    preferred = [
        "Visit_ID",
        "VisitNo",
        "VisitDate",
        "Regno",
        "PatientName",
        "TypeOfVisit",
        "DoctorIncharge",
        "DischargeDate",
        "Dept_Name",
        "Pat_Type",
        "Bill_PH",
        "Bill_PI",
        "Bill_P",
        "Bill_Total",
        "Receipt_PH",
        "Receipt_PI",
        "Receipt_P",
        "Receipt_Total",
    ]
    cols_map = {str(c).strip(): c for c in df.columns}
    ordered_cols = [cols_map[c] for c in preferred if c in cols_map]
    final_cols = ordered_cols + [c for c in df.columns if c not in ordered_cols]
    df = df[final_cols]

    def _num_series(series):
        cleaned = series.astype(str).str.replace(",", "", regex=False)
        cleaned = cleaned.str.replace(r"[^0-9.\-]", "", regex=True)
        return pd.to_numeric(cleaned, errors="coerce").fillna(0)

    def _is_amount_col(col_name: str) -> bool:
        low = str(col_name).lower()
        if "bill_" in low or "receipt_" in low:
            return True
        if "bill" in low and "billdate" not in low:
            return True
        if "receipt" in low:
            return True
        return False

    for col in df.columns:
        if _is_amount_col(col):
            df[col] = _num_series(df[col])

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
        wb = writer.book

        title_fmt = wb.add_format({
            "bold": True, "font_size": 14, "font_color": "#1E3A8A",
            "align": "center", "valign": "vcenter"
        })
        subtitle_fmt = wb.add_format({
            "bold": True, "font_size": 11, "align": "center", "valign": "vcenter"
        })
        meta_fmt = wb.add_format({"font_size": 9, "align": "left", "valign": "vcenter"})
        header_fmt = wb.add_format({
            "bold": True, "bg_color": "#1E3A8A", "font_color": "white",
            "border": 1, "align": "center", "valign": "vcenter"
        })
        text_fmt = wb.add_format({"align": "left", "valign": "vcenter"})
        date_fmt = wb.add_format({"num_format": "yyyy-mm-dd", "align": "center", "valign": "vcenter"})
        money_fmt = wb.add_format({"num_format": "#,##,##0.00", "align": "right", "valign": "vcenter"})
        highlight_money_fmt = wb.add_format({"num_format": "#,##,##0.00", "align": "right", "valign": "vcenter", "bg_color": "#FEF9C3"})

        exported_by = session.get("username") or session.get("user") or "Unknown"
        exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")

        sheet_name = "Summarized IP Ledger"
        df.to_excel(writer, sheet_name=sheet_name, index=False, startrow=5, header=False)
        ws = writer.sheets[sheet_name]

        last_col = len(df.columns) - 1
        ws.merge_range(0, 0, 0, last_col, "Summarized IP Ledger", title_fmt)
        ws.merge_range(1, 0, 1, last_col, f"Unit: {target_unit} | Date Range: {from_date} to {to_date}", subtitle_fmt)
        ws.merge_range(2, 0, 2, last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)
        ws.merge_range(3, 0, 3, last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)

        highlight_cols = []
        for col_idx, col_name in enumerate(df.columns):
            ws.write(4, col_idx, col_name, header_fmt)
            col_lower = str(col_name).lower()
            width = 16
            fmt = text_fmt
            if "date" in col_lower or "time" in col_lower:
                width = 18
                fmt = date_fmt
            elif _is_amount_col(col_name):
                width = 16
                fmt = money_fmt
            elif any(x in col_lower for x in ["patient", "doctor", "dept"]):
                width = 24
            ws.set_column(col_idx, col_idx, width, fmt)

            norm = col_lower.replace("_", "")
            if norm in {"billtotal", "receipttotal"}:
                highlight_cols.append(col_idx)

        data_start = 5
        data_end = 4 + len(df)
        for col_idx in highlight_cols:
            ws.conditional_format(data_start, col_idx, data_end, col_idx, {
                "type": "no_errors",
                "format": highlight_money_fmt
            })

        ws.freeze_panes(5, 0)

    output.seek(0)
    fname = f"Summarized_IP_Ledger_{target_unit}_{from_date}.xlsx"
    return send_file(
        output,
        as_attachment=True,
        download_name=fname,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    )


@app.route('/api/mis/discount_due_track')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_discount_due_track():
    unit = (request.args.get("unit") or "").strip() or None
    from_date = request.args.get("from") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    to_date = request.args.get("to") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    allowed_units = _allowed_units_for_session()
    target_unit = unit or (allowed_units[0] if allowed_units else None)
    if not target_unit:
        return jsonify({"status": "error", "message": "No unit available"}), 400

    if allowed_units and target_unit not in allowed_units:
        return jsonify({"status": "error", "message": "Unit not allowed"}), 403

    df = data_fetch.fetch_discount_due_track(target_unit, from_date, to_date)
    if df is None or df.empty:
        return jsonify({"status": "success", "data": [], "unit": target_unit}), 200
    records = df.to_dict(orient="records")
    return jsonify({"status": "success", "data": records, "unit": target_unit})

# ============================================================
# User Management
# ============================================================
def _default_sections_for_creator():
    raw = session.get("section_rights") or []
    if isinstance(raw, str):
        raw = [s.strip() for s in raw.split(",")]
    return [str(x).strip().lower() for x in raw if str(x).strip()]


def _user_management_wants_json() -> bool:
    if request.is_json:
        return True
    requested_with = (request.headers.get("X-Requested-With") or "").strip().lower()
    if requested_with == "xmlhttprequest":
        return True
    accept = (request.headers.get("Accept") or "").lower()
    return "application/json" in accept


def _user_management_success(message: str, status_code: int = 200, **extra):
    if _user_management_wants_json():
        payload = {"ok": True, "message": str(message)}
        if extra:
            payload.update(extra)
        return jsonify(payload), status_code
    return redirect(url_for('user_management'))


def _user_management_error(message: str, status_code: int = 400, **extra):
    if _user_management_wants_json():
        payload = {"ok": False, "message": str(message)}
        if extra:
            payload.update(extra)
        return jsonify(payload), status_code
    return (str(message), status_code)


