@app.route('/user_management/')
@app.route('/user_management')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def user_management():
    role = (session.get("role") or "").strip()
    role_base = _role_base(role)
    username = (session.get("username") or "").strip()
    requests = _fetch_user_requests(role, username)
    allowed_units = _allowed_units_for_session()
    fund_acl = _allowed_fund_firms_for_session()
    firm_choices = _fund_tracker_known_firms() if fund_acl.get("all") else (fund_acl.get("firms") or [])
    can_assign_all_firms = (role_base == "IT") or bool(fund_acl.get("all"))
    grouped_requests = {}
    for req in requests:
        uname = (req.get("NewUserName") or "").strip()
        if not uname:
            continue
        grouped_requests.setdefault(uname, []).append(req)
    notifications = _pending_notifications_for_it() if role == "IT" else []
    existing_users = _fetch_hid_users() if role in {"IT", "Management", "Departmental Head"} else []
    hist_cutoff = fiscal_year_start(datetime.now(tz=LOCAL_TZ)).date()
    hist_requests = [r for r in requests if (r.get("ActionType") or "").strip().lower() == "historicalaccess"]
    hist_requests_view = hist_requests if role == "IT" else [r for r in hist_requests if (r.get("RequestedBy") or "").strip().lower() == username.lower()]
    hist_grant_active = (role == "IT") or has_historical_grant(username, session.get("sid"))
    purchasing_departments = _fetch_purchasing_departments() if role == "IT" else []
    purchase_incharges = _fetch_purchase_incharges() if role == "IT" else []
    purchase_approval_recipients = _fetch_purchase_approval_recipients() if role == "IT" else []
    bill_edit_directors = _fetch_bill_edit_directors() if role == "IT" else []
    fund_position_recipients = _fetch_fund_position_recipients() if role == "IT" else []
    it_direct_users = _fetch_hid_users_for_it_admin() if role == "IT" else []
    return render_template(
        'user_management.html',
        requests=requests,
        grouped_requests=grouped_requests,
        notifications=notifications,
        role=role,
        creator_sections=",".join(_default_sections_for_creator()),
        unit_scope=(session.get("unit_scope") or ""),
        firm_scope=(session.get("firm_scope") or ("*" if role_base == "IT" else "")),
        can_assign_all_firms=can_assign_all_firms,
        section_choices=_all_section_keys(),
        existing_users=existing_users,
        hist_requests=hist_requests_view,
        historical_allowed=hist_grant_active,
        historical_cutoff=hist_cutoff,
        purchasing_departments=purchasing_departments,
        purchase_incharges=purchase_incharges,
        purchase_approval_recipients=purchase_approval_recipients,
        bill_edit_directors=bill_edit_directors,
        fund_position_recipients=fund_position_recipients,
        it_direct_users=it_direct_users,
        allowed_units=allowed_units,
        allowed_firms=firm_choices,
    )

@app.route('/user_management/request/', methods=['POST'])
@app.route('/user_management/request', methods=['POST'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def user_management_request():
    new_username = (request.form.get("new_username") or "").strip()
    passwordw = request.form.get("password") or ""
    role = (request.form.get("role") or "").strip()
    unit = _normalize_unit_scope_text(request.form.get("unit_scope") or "")
    purchase_unit_scope = _normalize_unit_scope_text(request.form.get("purchase_unit_scope") or "")
    firms = _normalize_firm_scope_text(request.form.get("firm_scope") or "")
    sections_raw = request.form.get("sections") or ""
    note = request.form.get("note") or ""
    requester_role = (session.get("role") or "").strip()
    requester = (session.get("username") or "").strip()

    if not new_username or not passwordw or not role:
        return _user_management_error("Missing required fields", 400)

    # Hierarchy checks
    requester_role_clean = requester_role.split(":")[0].strip()
    if requester_role_clean != "IT":
        if role == "IT":
            return _user_management_error("You are not allowed to create IT users", 403)
        if requester_role_clean == "Departmental Head" and role == "Management":
            return _user_management_error("Departmental Heads cannot create Management users", 403)

    if requester_role.startswith("Departmental Head") and not unit:
        unit = _normalize_unit_scope_text(session.get("unit_scope") or "")
    if requester_role.startswith("Departmental Head") and not firms:
        firms = _normalize_firm_scope_text(session.get("firm_scope") or "")

    if not sections_raw:
        sections_raw = ",".join(_default_sections_for_creator())

    acl = _allowed_fund_firms_for_session()
    if requester_role_clean != "IT":
        if acl.get("all"):
            if not firms:
                firms = "*"
        else:
            requested_firms = _normalize_firm_scope(firms)
            if not requested_firms:
                requested_firms = acl.get("firms") or []
            allowed_set = {f.upper() for f in (acl.get("firms") or [])}
            invalid = [f for f in requested_firms if f.upper() not in allowed_set]
            if invalid:
                return _user_management_error("You cannot assign firms outside your own scope", 403)
            firms = _normalize_firm_scope_text(requested_firms)

    acctid = ROLE_ACCOUNTID.get(role) or None

    _insert_user_request({
        "requested_by": requester,
        "new_username": new_username,
        "passwordw": passwordw,
        "role": role,
        "accountid": acctid,
        "unit_scope": unit,
        "purchase_unit_scope": purchase_unit_scope,
        "firm_scope": firms,
        "sections": sections_raw,
        "note": note,
        "action_type": "Create",
    })
    return _user_management_success("User request submitted.")

@app.route('/user_management/decision/', methods=['POST'])
@app.route('/user_management/decision', methods=['POST'])
@login_required(allowed_roles={"IT"})
def user_management_decision():
    req_id = request.form.get("request_id")
    action = (request.form.get("action") or "").strip().lower()
    if not req_id or action not in ("approve", "hold"):
        return _user_management_error("Invalid request", 400)
    req_id = int(req_id)

    with _get_login_db_connection() as conn:
        _ensure_user_request_table(conn)
        cursor = conn.cursor()
        cursor.execute("SELECT RequestId, RequestedBy, NewUserName, RequestedPassword, RequestedRole, RequestedAccountId, RequestedUnit, RequestedPurchaseUnits, RequestedFirms, RequestedSections, ActionType, RequestedIsActive, RequestedSessionId FROM dbo.HID_User_Requests WHERE RequestId = ?", (req_id,))
        row = cursor.fetchone()
        if not row:
            return _user_management_error("Request not found", 404)
        cols = [c[0] for c in cursor.description]
        rec = {cols[i]: row[i] for i in range(len(cols))}
    action_type = (rec.get("ActionType") or "").strip().lower()

    if action_type == "historicalaccess":
        target_user = (rec.get("NewUserName") or "").strip()
        target_sid = rec.get("RequestedSessionId") or _session_store_get(target_user)
        if action == "approve":
            if target_user:
                grant_historical(target_user, target_sid, HIST_GRANT_TTL_SECONDS)
            _update_user_request_status(req_id, "Approved", session.get("username"))
            _push_user_notification(
                target_user,
                "Historical access approved",
                "Your request for historical data access has been approved for this session.",
                link="/dashboard",
                ref=req_id
            )
        else:
            remind_at = datetime.now() + timedelta(days=2)
            _update_user_request_status(req_id, "Hold", session.get("username"), remind_at=remind_at)
        if action == "approve":
            return _user_management_success("Historical access approved.")
        return _user_management_success("Historical access request moved to hold.")

    if action == "approve":
        _upsert_hid_user(rec)
        _update_user_request_status(req_id, "Approved", session.get("username"))
    else:
        remind_at = datetime.now() + timedelta(days=2)
        _update_user_request_status(req_id, "Hold", session.get("username"), remind_at=remind_at)

    if action == "approve":
        return _user_management_success("Request approved and user access updated.")
    return _user_management_success("Request moved to hold.")

@app.route('/user_management/update_user/', methods=['POST'])
@app.route('/user_management/update_user', methods=['POST'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def user_management_update_user():
    target_username = (request.form.get("target_username") or "").strip()
    role = (request.form.get("role") or "").strip()
    unit = _normalize_unit_scope_text(request.form.get("unit_scope") or "")
    purchase_unit_scope = _normalize_unit_scope_text(request.form.get("purchase_unit_scope") or "")
    firms = _normalize_firm_scope_text(request.form.get("firm_scope") or "")
    sections_raw = request.form.get("sections") or ""
    active = request.form.get("is_active")
    requester_role = (session.get("role") or "").strip()

    if not target_username:
        return _user_management_error("Missing target user", 400)

    # Fetch current target role for hierarchy checks
    with _get_login_db_connection() as conn:
        cursor = conn.cursor()
        cursor.execute("SELECT RoleName, AccountId FROM dbo.HID_User_Mst WHERE UserName = ?", (target_username,))
        row = cursor.fetchone()
        if not row:
            return _user_management_error("User not found", 404)
        target_role_db = (row.RoleName or ACCOUNTID_ROLE.get(row.AccountId) or "").strip()

    req_clean = requester_role.split(":")[0].strip()
    if req_clean != "IT":
        if role == "IT":
            return _user_management_error("You are not allowed to set role IT", 403)
        if req_clean == "Departmental Head" and role == "Management":
            return _user_management_error("Departmental Heads cannot set role Management", 403)
        # cannot edit users above your rank, and cannot set role above your rank
        if _role_rank(req_clean) < _role_rank(target_role_db):
            return _user_management_error("You cannot edit users above your role", 403)
        if _role_rank(req_clean) < _role_rank(role):
            return _user_management_error("You cannot set a role above your own", 403)

    acl = _allowed_fund_firms_for_session()
    if req_clean != "IT":
        if acl.get("all"):
            if not firms:
                firms = "*"
        else:
            requested_firms = _normalize_firm_scope(firms)
            if not requested_firms:
                requested_firms = acl.get("firms") or []
            allowed_set = {f.upper() for f in (acl.get("firms") or [])}
            invalid = [f for f in requested_firms if f.upper() not in allowed_set]
            if invalid:
                return _user_management_error("You cannot assign firms outside your own scope", 403)
            firms = _normalize_firm_scope_text(requested_firms)

    acctid = ROLE_ACCOUNTID.get(role) or None
    is_active_bit = 1 if str(active).lower() in ("1", "true", "yes", "on") else 0

    if req_clean != "IT":
        # non-IT -> create an update request for IT approval
        _insert_user_request({
            "requested_by": (session.get("username") or "").strip(),
            "new_username": target_username,
            "passwordw": "",  # unchanged
            "role": role,
            "accountid": acctid,
            "unit_scope": unit,
            "purchase_unit_scope": purchase_unit_scope,
            "firm_scope": firms,
            "sections": sections_raw,
            "note": "Update request (sections/role/unit/purchase/status)",
            "action_type": "Update",
            "requested_is_active": is_active_bit,
        })
        return _user_management_success("Update request sent for IT approval.")

    with _get_login_db_connection() as conn:
        _ensure_hid_user_scope_columns(conn)
        cursor = conn.cursor()
        cursor.execute("SELECT 1 FROM dbo.HID_User_Mst WHERE UserName = ?", (target_username,))
        exists = cursor.fetchone() is not None
        if not exists:
            return _user_management_error("User not found", 404)
        try:
            cursor.execute("""
                UPDATE dbo.HID_User_Mst
                SET AccountId = ?, RoleName = ?, UnitScope = ?, PurchaseUnitScope = ?, FirmScope = ?, SectionRights = ?, IsActive = ?, UpdatedAt = SYSDATETIME()
                WHERE UserName = ?
            """, (acctid, role, unit, purchase_unit_scope, firms, sections_raw, is_active_bit, target_username))
        except Exception:
            cursor.execute("""
                UPDATE dbo.HID_User_Mst
                SET AccountId = ?, RoleName = ?, UnitScope = ?, SectionRights = ?, IsActive = ?, UpdatedAt = SYSDATETIME()
                WHERE UserName = ?
            """, (acctid, role, unit, sections_raw, is_active_bit, target_username))
        conn.commit()

    return _user_management_success("User updated successfully.")


