# ============================================================
# MIS: Preventive Health Checkup Journey (HCV -> IPD)
# ============================================================
@app.route('/api/mis/hcv_journey')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_hcv_journey():
    global _HCV_CACHE
    unit = (request.args.get("unit") or "").strip().upper()
    allowed_units = _allowed_units_for_session()
    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403

    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return jsonify({"status": "error", "message": "Please select a unit"}), 400

    if unit not in allowed_units:
        return jsonify({"status": "error", "message": f"Unit {unit} not permitted for your role"}), 403

    # --- cache results per unit (skip caching if data contains "today") ---
    now_dt = datetime.now(tz=LOCAL_TZ).date()
    ttl_secs = 60 * 60  # 1 hour cache for historical data
    try:
        _HCV_CACHE
    except NameError:
        _HCV_CACHE = {}

    def _cache_hit():
        ent = _HCV_CACHE.get(unit)
        if not ent:
            return None
        if (time.time() - ent.get("ts", 0)) > ttl_secs:
            return None
        return ent

    cache_entry = _cache_hit()
    if cache_entry:
        pair_df = cache_entry.get("pairs")
        history_df = cache_entry.get("history")
    else:
        pair_df, history_df = data_fetch.fetch_hcv_journey(unit)

        # Determine if data contains today's date; only cache if not
        def _contains_today(df: pd.DataFrame) -> bool:
            if df is None or df.empty:
                return False
            for col in df.columns:
                if "date" in str(col).lower():
                    try:
                        dts = pd.to_datetime(df[col], errors="coerce").dt.date
                        if (dts == now_dt).any():
                            return True
                    except Exception:
                        continue
            return False

        has_today = _contains_today(pair_df) or _contains_today(history_df)
        if pair_df is not None or history_df is not None:
            _HCV_CACHE[unit] = {
                "pairs": pair_df,
                "history": history_df,
                "ts": time.time(),
                "has_today": has_today
            }
    if pair_df is None and history_df is None:
        return jsonify({"status": "error", "message": "Failed to fetch HCV journey data"}), 500

    def _records(df):
        if df is None:
            return []
        df_copy = df.copy()
        # Normalize datetimes to strings and replace NaN/NaT with None for JSON safety
        for col in df_copy.columns:
            if pd.api.types.is_datetime64_any_dtype(df_copy[col]):
                df_copy[col] = pd.to_datetime(df_copy[col], errors="coerce").dt.strftime("%Y-%m-%d %H:%M:%S")
        df_copy = df_copy.replace({pd.NA: None, np.nan: None})
        df_copy = df_copy.where(pd.notna(df_copy), None)
        return df_copy.to_dict(orient="records")

    return jsonify({
        "status": "success",
        "unit": unit,
        "pairs": _records(pair_df),
        "history": _records(history_df)
    })

