# MIS: Admission & Discharge Summary (Dept Wise)
# ============================================================
def _get_admission_discharge_summary_df(unit: str, from_date: str, to_date: str):
    df = data_fetch.fetch_admission_discharge_summary(unit, from_date, to_date)
    if df is None:
        return None
    if df.empty:
        return df

    df = _clean_df_columns(df)

    cols_map = {str(c).strip().lower(): c for c in df.columns}
    def _pick_col(candidates, default=None):
        for c in candidates:
            key = str(c).strip().lower()
            if key in cols_map:
                return cols_map[key]
        return default

    dept_col = _pick_col(["Departmentname", "DepartmentName", "Department_Name", "DeptName", "Department", "Dept"], "Departmentname")
    pt_col = _pick_col(["pattype", "PatType", "PatientType", "Patient_Type", "PatientSubType", "PatientSubType_Desc"], "pattype")
    adm_col = _pick_col(["TotAdmission", "TotalAdmission", "Admission", "Admissions", "TotAdmissions"], "TotAdmission")
    dis_col = _pick_col(["TotDischarges", "TotalDischarges", "Discharge", "Discharges", "TotDischarge"], "TotDischarges")

    if dept_col not in df.columns:
        df[dept_col] = ""
    if pt_col not in df.columns:
        df[pt_col] = ""
    if adm_col not in df.columns:
        df[adm_col] = 0
    if dis_col not in df.columns:
        df[dis_col] = 0

    out = pd.DataFrame({
        "PatientType": df[pt_col].fillna("").astype(str).str.strip(),
        "DepartmentName": df[dept_col].fillna("").astype(str).str.strip(),
        "Admission": pd.to_numeric(df[adm_col], errors="coerce").fillna(0),
        "Discharge": pd.to_numeric(df[dis_col], errors="coerce").fillna(0),
    })

    grouped = (out.groupby(["PatientType", "DepartmentName"], dropna=False, as_index=False)
               .agg({"Admission": "sum", "Discharge": "sum"}))
    grouped["PatientType"] = grouped["PatientType"].replace({"nan": ""})
    grouped["DepartmentName"] = grouped["DepartmentName"].replace({"nan": ""})
    grouped = grouped.sort_values(["PatientType", "DepartmentName"], kind="mergesort").reset_index(drop=True)
    return grouped


def _shape_pharmacy_stock_df(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()

    df = _clean_df_columns(df)
    cols_map = {str(c).strip().lower(): c for c in df.columns}

    def _pick_col(candidates, default=None):
        for c in candidates:
            key = str(c).strip().lower()
            if key in cols_map:
                return cols_map[key]
        return default

    item_id_col = _pick_col(["ID", "ItemID", "Item_Id"], "ID")
    item_name_col = _pick_col(["Name", "ItemName", "Item_Name"], "Name")
    batch_id_col = _pick_col(["BatchID", "Batch_Id", "BatchId"], "BatchID")
    batch_name_col = _pick_col(["batchname", "BatchName", "Batch_Name"], "batchname")
    expiry_col = _pick_col(["ExpiryDate", "Expiry_Date", "Expiry"], "ExpiryDate")
    store_name_col = _pick_col(["storename", "StoreName", "Store_Name"], "storename")
    rate_col = _pick_col(["Rate", "rate"], "Rate")
    mrp_col = _pick_col(["mrp", "MRP"], "mrp")
    qty_col = _pick_col(["Qty", "Quantity", "QTY"], "Qty")
    purchase_col = _pick_col(["PurchaseValue", "Purchase_Value", "PurchaseValue"], "PurchaseValue")
    sale_col = _pick_col(["Salevalue", "SaleValue", "Sale_Value"], "Salevalue")
    generic_col = _pick_col(["GenericName", "Generic_Name"], "GenericName")
    manufacturer_col = _pick_col(["Manufacturer_name", "ManufacturerName", "Manufacturer_Name"], "Manufacturer_name")
    group_col = _pick_col(["GroupName", "Group_Name"], "GroupName")
    subgroup_col = _pick_col(["SubGroupName", "Sub_GroupName", "SubGroup_Name"], "SubGroupName")

    def _num(series):
        return pd.to_numeric(series, errors="coerce").fillna(0)

    out = pd.DataFrame({
        "ItemID": df[item_id_col] if item_id_col in df.columns else None,
        "ItemName": df[item_name_col] if item_name_col in df.columns else "",
        "BatchID": df[batch_id_col] if batch_id_col in df.columns else None,
        "BatchName": df[batch_name_col] if batch_name_col in df.columns else "",
        "ExpiryDate": df[expiry_col] if expiry_col in df.columns else None,
        "StoreName": df[store_name_col] if store_name_col in df.columns else "",
        "Rate": _num(df[rate_col]) if rate_col in df.columns else 0,
        "MRP": _num(df[mrp_col]) if mrp_col in df.columns else 0,
        "Qty": _num(df[qty_col]) if qty_col in df.columns else 0,
        "PurchaseValue": _num(df[purchase_col]) if purchase_col in df.columns else 0,
        "SaleValue": _num(df[sale_col]) if sale_col in df.columns else 0,
        "GenericName": df[generic_col] if generic_col in df.columns else "",
        "ManufacturerName": df[manufacturer_col] if manufacturer_col in df.columns else "",
        "GroupName": df[group_col] if group_col in df.columns else "",
        "SubGroupName": df[subgroup_col] if subgroup_col in df.columns else "",
    })

    out["ExpiryDate"] = pd.to_datetime(out["ExpiryDate"], errors="coerce").dt.strftime("%Y-%m-%d")
    for c in ["ItemName", "BatchName", "StoreName", "GenericName", "ManufacturerName", "GroupName", "SubGroupName"]:
        out[c] = out[c].fillna("").astype(str).str.strip()

    return out


def _lookup_store_name(unit: str, store_id: int) -> str:
    try:
        store_df = data_fetch.fetch_pharmacy_stores(unit)
        if store_df is None or store_df.empty:
            return ""
        store_df = _clean_df_columns(store_df)
        cols_map = {str(c).strip().lower(): c for c in store_df.columns}
        id_col = cols_map.get("id") or cols_map.get("storeid") or cols_map.get("store_id")
        name_col = cols_map.get("name") or cols_map.get("storename") or cols_map.get("store_name")
        if not id_col or not name_col:
            return ""
        match = store_df[store_df[id_col].astype(str) == str(store_id)]
        if match.empty:
            return ""
        return str(match.iloc[0][name_col] or "").strip()
    except Exception:
        return ""


def _get_pharmacy_stock_df(unit: str, store_id: int, snapshot_date: str | None = None):
    if snapshot_date:
        _ensure_pharmacy_stock_snapshot_table()
        query = """
            SELECT item_id, item_name, batch_id, batch_name, expiry_date,
                   store_name, rate, mrp, qty, purchase_value, sale_value,
                   generic_name, manufacturer_name, group_name, subgroup_name,
                   snapshot_time
            FROM pharmacy_stock_snapshot
            WHERE snapshot_date = ? AND unit = ? AND store_id = ?
            ORDER BY item_name, batch_name
        """
        with _connect_local_db() as conn:
            rows = conn.execute(query, (snapshot_date, unit, store_id)).fetchall()
        if not rows:
            return pd.DataFrame(), "snapshot", None, None
        df = pd.DataFrame(rows, columns=[
            "ItemID", "ItemName", "BatchID", "BatchName", "ExpiryDate",
            "StoreName", "Rate", "MRP", "Qty", "PurchaseValue", "SaleValue",
            "GenericName", "ManufacturerName", "GroupName", "SubGroupName", "SnapshotTime"
        ])
        snapshot_time = str(df["SnapshotTime"].iloc[0]) if "SnapshotTime" in df.columns else None
        if "SnapshotTime" in df.columns:
            df = df.drop(columns=["SnapshotTime"])
        return df, "snapshot", snapshot_time, str(df["StoreName"].iloc[0]) if "StoreName" in df.columns else None

    live_df = data_fetch.fetch_current_pharmacy_stock(unit, store_id)
    if live_df is None:
        return None, "live", None, None
    if live_df.empty:
        return pd.DataFrame(), "live", None, None
    live_df = _shape_pharmacy_stock_df(live_df)
    store_name = str(live_df["StoreName"].iloc[0]) if "StoreName" in live_df.columns and not live_df.empty else None
    return live_df, "live", None, store_name


def _save_pharmacy_stock_snapshot():
    """Capture current pharmacy stock for all stores per unit into local snapshot."""
    _ensure_pharmacy_stock_snapshot_table()
    snapshot_date = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    snapshot_time = datetime.now(tz=LOCAL_TZ).strftime("%H:%M:%S")

    units = _all_units_upper()
    if not units:
        return

    def _write_rows(rows):
        if not rows:
            return
        def _insert(conn):
            conn.executemany("""
                INSERT OR REPLACE INTO pharmacy_stock_snapshot
                (snapshot_date, snapshot_time, unit, store_id, store_name,
                 item_id, item_name, batch_id, batch_name, expiry_date,
                 rate, mrp, qty, purchase_value, sale_value,
                 generic_name, manufacturer_name, group_name, subgroup_name)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """, rows)
        _with_local_db(_insert)

    for unit in units:
        store_df = data_fetch.fetch_pharmacy_stores(unit)
        if store_df is None or store_df.empty:
            continue
        store_df = _clean_df_columns(store_df)
        cols_map = {str(c).strip().lower(): c for c in store_df.columns}
        id_col = cols_map.get("id") or cols_map.get("storeid") or cols_map.get("store_id")
        name_col = cols_map.get("name") or cols_map.get("storename") or cols_map.get("store_name")
        if not id_col:
            continue
        rows_to_insert = []
        for _, store_row in store_df.iterrows():
            store_id = store_row.get(id_col)
            if store_id is None:
                continue
            try:
                store_id_int = int(store_id)
            except Exception:
                continue
            store_name = str(store_row.get(name_col) or "").strip() if name_col else ""
            stock_df = data_fetch.fetch_current_pharmacy_stock(unit, store_id_int)
            if stock_df is None or stock_df.empty:
                continue
            stock_df = _shape_pharmacy_stock_df(stock_df)
            if stock_df.empty:
                continue
            for _, row in stock_df.iterrows():
                rows_to_insert.append((
                    snapshot_date,
                    snapshot_time,
                    unit,
                    store_id_int,
                    store_name or row.get("StoreName"),
                    int(row.get("ItemID")) if pd.notna(row.get("ItemID")) else None,
                    row.get("ItemName"),
                    int(row.get("BatchID")) if pd.notna(row.get("BatchID")) else None,
                    row.get("BatchName"),
                    row.get("ExpiryDate"),
                    float(row.get("Rate") or 0),
                    float(row.get("MRP") or 0),
                    float(row.get("Qty") or 0),
                    float(row.get("PurchaseValue") or 0),
                    float(row.get("SaleValue") or 0),
                    row.get("GenericName"),
                    row.get("ManufacturerName"),
                    row.get("GroupName"),
                    row.get("SubGroupName"),
                ))
        _write_rows(rows_to_insert)

    _prune_pharmacy_stock_snapshot(90)


def _prune_pharmacy_stock_snapshot(retention_days: int = 90):
    """Delete pharmacy stock snapshots older than retention_days."""
    cutoff_date = (datetime.now(tz=LOCAL_TZ) - timedelta(days=retention_days)).strftime("%Y-%m-%d")
    def _delete(conn):
        conn.execute(
            "DELETE FROM pharmacy_stock_snapshot WHERE snapshot_date < ?",
            (cutoff_date,)
        )
    _with_local_db(_delete)


