def _ph_stmt_parse_iso_date(value: str | None) -> date | None:
    raw = str(value or "").strip()
    if not raw:
        return None
    try:
        return datetime.strptime(raw, "%Y-%m-%d").date()
    except Exception:
        return None


def _ph_stmt_norm_text(value) -> str:
    if value is None:
        return ""
    try:
        if pd.isna(value):
            return ""
    except Exception:
        pass
    text = str(value).strip()
    if text.lower() in {"nan", "nat", "none", "null", "undefined"}:
        return ""
    return text


def _ph_stmt_norm_key(value) -> str:
    return re.sub(r"\s+", " ", _ph_stmt_norm_text(value)).strip().lower()


def _ph_stmt_num_series(series) -> pd.Series:
    return pd.to_numeric(series, errors="coerce").fillna(0.0)


def _ph_stmt_first_text(series: pd.Series) -> str:
    for val in series:
        text = _ph_stmt_norm_text(val)
        if text:
            return text
    return ""


def _ph_stmt_item_key(item_id, item_name: str) -> str:
    try:
        if item_id is not None and not pd.isna(item_id):
            return f"id:{int(float(item_id))}"
    except Exception:
        pass
    return f"name:{_ph_stmt_norm_key(item_name)}"


def _ph_stmt_filter_consumption_for_store(df: pd.DataFrame, store_id: int, store_name: str | None) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()
    out = df.copy()
    if "DocType" not in out.columns:
        out["DocType"] = ""
    if "StoreName" not in out.columns:
        out["StoreName"] = ""
    doc = out["DocType"].astype(str).str.strip().str.upper()
    store_txt = out["StoreName"].astype(str).str.strip().str.lower()
    store_name_norm = (store_name or "").strip().lower()

    if int(store_id) == 2:
        mask = doc.isin({"ROT", "DRT"}) | store_txt.str.contains("opd", na=False)
        if store_name_norm:
            mask = mask | (store_txt == store_name_norm)
        return out[mask]
    if int(store_id) == 3:
        unknown_store = store_txt.isin({"", "none", "nan", "null", "undefined"})
        mask = doc.isin({"PIS", "RFD"}) | (doc.eq("ISD") & unknown_store) | store_txt.str.contains("ipd", na=False)
        if store_name_norm:
            mask = mask | (store_txt == store_name_norm)
        return out[mask]
    if int(store_id) == 15:
        mask = store_txt.str.contains("cathlab", na=False)
        if store_name_norm:
            mask = mask | (store_txt == store_name_norm)
        return out[mask]
    return out


def _build_pharmacy_current_stock_statement_df(unit: str, store_id: int, from_date: str, to_date: str):
    unit_norm = (unit or "").strip().upper()
    try:
        store_id_int = int(store_id)
    except Exception:
        return None, {"error": "Invalid store id"}

    cache_key = (unit_norm, store_id_int, str(from_date or ""), str(to_date or ""))
    cached = _ph_stmt_cache_get(cache_key)
    if cached and isinstance(cached.get("df"), pd.DataFrame):
        return cached["df"].copy(), copy.deepcopy(cached.get("meta") or {})

    warnings_list = []
    closing_df, _, _, store_name = _get_pharmacy_stock_df(unit_norm, store_id_int, None)
    if closing_df is None:
        return None, {"error": "Failed to fetch current stock"}

    store_name = store_name or _lookup_store_name(unit_norm, store_id_int) or f"Store {store_id_int}"

    if closing_df.empty:
        empty_df = pd.DataFrame(columns=PH_STMT_COLUMNS)
        meta = {
            "unit": unit_norm,
            "store_id": store_id_int,
            "store_name": store_name,
            "from_date": from_date,
            "to_date": to_date,
            "warnings": [],
            "unmatched_purchase_rows": 0,
            "reconciled": True,
            "closing_total_current": 0.0,
            "closing_total_statement": 0.0,
            "closing_difference": 0.0,
            "row_count": 0,
        }
        _ph_stmt_cache_put(cache_key, empty_df, meta)
        return empty_df, meta

    close = _clean_df_columns(closing_df).copy()
    for col, default in [("ItemID", None), ("ItemName", ""), ("GroupName", ""), ("SubGroupName", ""), ("Qty", 0), ("Rate", 0), ("MRP", 0)]:
        if col not in close.columns:
            close[col] = default

    close["ClosingQty"] = _ph_stmt_num_series(close["Qty"])
    close["RateNum"] = _ph_stmt_num_series(close["Rate"])
    close["MRPNum"] = _ph_stmt_num_series(close["MRP"])
    close["RateWeighted"] = close["RateNum"] * close["ClosingQty"].abs()
    close["MRPWeighted"] = close["MRPNum"] * close["ClosingQty"].abs()
    close["__name_key"] = close["ItemName"].apply(_ph_stmt_norm_key)
    close["__item_key"] = close.apply(lambda r: _ph_stmt_item_key(r.get("ItemID"), r.get("ItemName")), axis=1)

    base = (
        close.groupby("__item_key", dropna=False, as_index=False)
        .agg(
            ItemName=("ItemName", _ph_stmt_first_text),
            GroupName=("GroupName", _ph_stmt_first_text),
            SubGroupName=("SubGroupName", _ph_stmt_first_text),
            ClosingQty=("ClosingQty", "sum"),
            RateWeighted=("RateWeighted", "sum"),
            MRPWeighted=("MRPWeighted", "sum"),
            RateMean=("RateNum", "mean"),
            MRPMean=("MRPNum", "mean"),
            __name_key=("__name_key", _ph_stmt_first_text),
        )
    )

    qty_denom = _ph_stmt_num_series(base["ClosingQty"]).abs()
    base["Rate"] = np.where(qty_denom > 0, _ph_stmt_num_series(base["RateWeighted"]) / qty_denom, _ph_stmt_num_series(base["RateMean"]))
    base["MRP"] = np.where(qty_denom > 0, _ph_stmt_num_series(base["MRPWeighted"]) / qty_denom, _ph_stmt_num_series(base["MRPMean"]))
    base["Rate"] = _ph_stmt_num_series(base["Rate"])
    base["MRP"] = _ph_stmt_num_series(base["MRP"])
    for helper_col in ["RateWeighted", "MRPWeighted", "RateMean", "MRPMean"]:
        if helper_col in base.columns:
            base.drop(columns=[helper_col], inplace=True)

    for col in ["OpeningQty", "PurchaseQty", "PurchaseReturnQty", "SaleQty", "IssuedQty", "SaleReturnQty", "IssueReturnQty"]:
        base[col] = 0.0

    item_keys = set(base["__item_key"].astype(str))
    base_name_keys = base["__name_key"].astype(str)
    name_counts = base_name_keys.value_counts().to_dict()
    name_to_key = {}
    for _, row in base.iterrows():
        nk = str(row.get("__name_key") or "")
        if nk and name_counts.get(nk, 0) == 1:
            name_to_key[nk] = str(row.get("__item_key") or "")

    def _resolve_current_key(item_id, item_name):
        key = _ph_stmt_item_key(item_id, item_name)
        if key in item_keys:
            return key
        return name_to_key.get(_ph_stmt_norm_key(item_name))

    cons_df = data_fetch.fetch_pharmacy_itemwise_consumption(unit_norm, from_date, to_date, None, None)
    if cons_df is None:
        warnings_list.append("Itemwise consumption dataset unavailable. Sale/issue/return quantities set to 0.")
    elif not cons_df.empty:
        cons = _clean_df_columns(cons_df).copy()
        for col, default in [("ItemID", None), ("ItemName", ""), ("DocType", ""), ("Consumption_Type", ""), ("TotalQty", 0), ("StoreName", "")]:
            if col not in cons.columns:
                cons[col] = default
        cons = _ph_stmt_filter_consumption_for_store(cons, store_id_int, store_name)
        if not cons.empty:
            cons["QtyNum"] = _ph_stmt_num_series(cons["TotalQty"]).abs()
            cons["DocTypeNorm"] = cons["DocType"].astype(str).str.strip().str.upper()
            cons["TypeNorm"] = cons["Consumption_Type"].astype(str).str.strip().str.lower()
            cons["__item_key"] = cons.apply(lambda r: _resolve_current_key(r.get("ItemID"), r.get("ItemName")), axis=1)
            cons = cons[cons["__item_key"].notna() & (cons["__item_key"].astype(str) != "")]
            if not cons.empty:
                cons["SaleQty"] = np.where(
                    (cons["TypeNorm"] == "sale") | (cons["DocTypeNorm"] == "ROT"),
                    cons["QtyNum"],
                    0.0,
                )
                cons["IssuedQty"] = np.where(
                    cons["TypeNorm"].isin({"issue", "departmental issue"}) | cons["DocTypeNorm"].isin({"PIS", "ISD"}),
                    cons["QtyNum"],
                    0.0,
                )
                cons["SaleReturnQty"] = np.where(
                    (cons["TypeNorm"] == "opd return") | (cons["DocTypeNorm"] == "DRT"),
                    cons["QtyNum"],
                    0.0,
                )
                cons["IssueReturnQty"] = np.where(
                    (cons["TypeNorm"] == "ipd return") | (cons["DocTypeNorm"] == "RFD"),
                    cons["QtyNum"],
                    0.0,
                )
                cons_agg = (
                    cons.groupby("__item_key", dropna=False, as_index=False)
                    .agg(
                        SaleQty=("SaleQty", "sum"),
                        IssuedQty=("IssuedQty", "sum"),
                        SaleReturnQty=("SaleReturnQty", "sum"),
                        IssueReturnQty=("IssueReturnQty", "sum"),
                    )
                )
                base = base.merge(cons_agg, on="__item_key", how="left", suffixes=("", "_mov"))
                for col in ["SaleQty", "IssuedQty", "SaleReturnQty", "IssueReturnQty"]:
                    mov_col = f"{col}_mov"
                    if mov_col in base.columns:
                        base[col] = _ph_stmt_num_series(base[mov_col])
                        base.drop(columns=[mov_col], inplace=True)

    unmatched_purchase_rows = 0
    purchase_df = data_fetch.fetch_pharmacy_storewise_purchase(unit_norm, from_date, to_date, store_id_int)
    if purchase_df is None:
        warnings_list.append("Store-wise purchase dataset unavailable. Purchase quantities set to 0.")
    elif not purchase_df.empty:
        pur = _clean_df_columns(purchase_df).copy()
        for col, default in [("itemname", ""), ("Qty", 0), ("DocType", "")]:
            if col not in pur.columns:
                pur[col] = default
        pur["DocTypeNorm"] = pur["DocType"].astype(str).str.strip().str.upper()
        pur = pur[pur["DocTypeNorm"].eq("GRN")]
        if not pur.empty:
            pur["QtyNum"] = _ph_stmt_num_series(pur["Qty"]).abs()
            pur["__item_key"] = pur["itemname"].apply(lambda x: name_to_key.get(_ph_stmt_norm_key(x)))
            unmatched_mask = ((pur["__item_key"].isna()) | (pur["__item_key"].astype(str) == "")) & (pur["QtyNum"] != 0)
            unmatched_purchase_rows = int(unmatched_mask.sum())
            pur = pur[pur["__item_key"].notna() & (pur["__item_key"].astype(str) != "")]
            if not pur.empty:
                pur_agg = pur.groupby("__item_key", dropna=False, as_index=False)["QtyNum"].sum().rename(columns={"QtyNum": "PurchaseQty"})
                base = base.merge(pur_agg, on="__item_key", how="left", suffixes=("", "_pur"))
                if "PurchaseQty_pur" in base.columns:
                    base["PurchaseQty"] = _ph_stmt_num_series(base["PurchaseQty_pur"])
                    base.drop(columns=["PurchaseQty_pur"], inplace=True)

    pur_ret_df = data_fetch.fetch_pharmacy_purchase_return_itemwise(unit_norm, from_date, to_date, store_id_int)
    if pur_ret_df is None:
        warnings_list.append("Purchase return dataset unavailable. Purchase return quantities set to 0.")
    elif not pur_ret_df.empty:
        pr = _clean_df_columns(pur_ret_df).copy()
        for col, default in [("ItemID", None), ("Itemname", ""), ("Qty", 0)]:
            if col not in pr.columns:
                pr[col] = default
        pr["QtyNum"] = _ph_stmt_num_series(pr["Qty"]).abs()
        pr["__item_key"] = pr.apply(lambda r: _resolve_current_key(r.get("ItemID"), r.get("Itemname")), axis=1)
        pr = pr[pr["__item_key"].notna() & (pr["__item_key"].astype(str) != "")]
        if not pr.empty:
            pr_agg = pr.groupby("__item_key", dropna=False, as_index=False)["QtyNum"].sum().rename(columns={"QtyNum": "PurchaseReturnQty"})
            base = base.merge(pr_agg, on="__item_key", how="left", suffixes=("", "_pret"))
            if "PurchaseReturnQty_pret" in base.columns:
                base["PurchaseReturnQty"] = _ph_stmt_num_series(base["PurchaseReturnQty_pret"])
                base.drop(columns=["PurchaseReturnQty_pret"], inplace=True)

    for col in ["Rate", "MRP", "PurchaseQty", "PurchaseReturnQty", "SaleQty", "IssuedQty", "SaleReturnQty", "IssueReturnQty", "ClosingQty"]:
        base[col] = _ph_stmt_num_series(base[col])

    base["OpeningQty"] = (
        base["ClosingQty"]
        - base["PurchaseQty"]
        + base["PurchaseReturnQty"]
        + base["SaleQty"]
        + base["IssuedQty"]
        - base["SaleReturnQty"]
        - base["IssueReturnQty"]
    )

    if unmatched_purchase_rows > 0:
        warnings_list.append(f"{unmatched_purchase_rows} purchase row(s) could not be matched to current-stock item names.")
    if store_id_int == 15:
        warnings_list.append("CATHLAB movement mapping can be partial; review movement columns before final decisions.")

    out_df = base[PH_STMT_COLUMNS].copy()
    for col in [c for c in PH_STMT_COLUMNS if c.endswith("Qty")]:
        out_df[col] = _ph_stmt_num_series(out_df[col]).round(3)
    for col in ["Rate", "MRP"]:
        if col in out_df.columns:
            out_df[col] = _ph_stmt_num_series(out_df[col]).round(2)
    out_df["ItemName"] = out_df["ItemName"].astype(str).str.strip()
    out_df["GroupName"] = out_df["GroupName"].astype(str).str.strip()
    out_df["SubGroupName"] = out_df["SubGroupName"].astype(str).str.strip()
    out_df = out_df.sort_values(["ItemName", "GroupName", "SubGroupName"], kind="mergesort").reset_index(drop=True)

    closing_total_current = float(_ph_stmt_num_series(close["ClosingQty"]).sum())
    closing_total_statement = float(_ph_stmt_num_series(out_df["ClosingQty"]).sum())
    closing_diff = float(closing_total_statement - closing_total_current)
    reconciled = abs(closing_diff) < 0.0005
    if not reconciled:
        warnings_list.append("Closing totals differ from current stock output. Please verify source data and filters.")

    meta = {
        "unit": unit_norm,
        "store_id": store_id_int,
        "store_name": store_name,
        "from_date": from_date,
        "to_date": to_date,
        "warnings": warnings_list,
        "unmatched_purchase_rows": int(unmatched_purchase_rows),
        "reconciled": bool(reconciled),
        "closing_total_current": round(closing_total_current, 3),
        "closing_total_statement": round(closing_total_statement, 3),
        "closing_difference": round(closing_diff, 6),
        "row_count": int(len(out_df)),
    }

    _ph_stmt_cache_put(cache_key, out_df, meta)
    return out_df, meta

@app.route('/api/mis/admission_discharge_summary')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_admission_discharge_summary():
    unit = (request.args.get("unit") or "").strip().upper()
    from_date = (request.args.get("from") or "").strip()
    to_date = (request.args.get("to") or "").strip()
    allowed_units = _allowed_units_for_session()

    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return jsonify({"status": "error", "message": "Please select a unit"}), 400
    if unit not in allowed_units:
        return jsonify({"status": "error", "message": f"Unit {unit} not permitted for your role"}), 403
    if not from_date or not to_date:
        return jsonify({"status": "error", "message": "Please select a valid date range"}), 400

    df = _get_admission_discharge_summary_df(unit, from_date, to_date)
    if df is None:
        return jsonify({"status": "error", "message": "Failed to fetch admission/discharge summary"}), 500
    if df.empty:
        return jsonify({"status": "success", "unit": unit, "rows": []})

    df = df.replace({pd.NA: None, np.nan: None})
    df = df.where(pd.notna(df), None)
    return jsonify({
        "status": "success",
        "unit": unit,
        "rows": df.to_dict(orient="records")
    })

def _build_admission_discharge_pdf_buffer(unit: str, from_date: str, to_date: str, exported_by: str | None):
    from reportlab.lib.pagesizes import A4
    from reportlab.lib import colors
    from reportlab.lib.units import mm
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer, Image
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER
    from xml.sax.saxutils import escape as xml_escape
    from xml.sax.saxutils import escape as xml_escape
    from xml.sax.saxutils import escape

    df = _get_admission_discharge_summary_df(unit, from_date, to_date)
    if df is None or df.empty:
        return None

    df = df.copy()
    df["PatientType"] = df["PatientType"].fillna("").replace("", "Unknown")
    df["DepartmentName"] = df["DepartmentName"].fillna("").replace("", "Unknown")

    def _fmt_date(val: str) -> str:
        try:
            return datetime.strptime(val, "%Y-%m-%d").strftime("%d-%b-%Y")
        except Exception:
            return val

    def _fmt_num(val) -> str:
        try:
            return f"{float(val):,.0f}"
        except Exception:
            return "0"

    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=A4,
        topMargin=14 * mm,
        bottomMargin=14 * mm,
        leftMargin=16 * mm,
        rightMargin=16 * mm,
    )

    styles = getSampleStyleSheet()
    style_title = ParagraphStyle("RptTitle", parent=styles["Heading2"], fontSize=12, alignment=TA_CENTER, textColor=colors.HexColor("#1e3a8a"))
    style_sub = ParagraphStyle("RptSub", parent=styles["Normal"], fontSize=9, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_meta = ParagraphStyle("RptMeta", parent=styles["Normal"], fontSize=8, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_cell = ParagraphStyle("RptCell", parent=styles["Normal"], fontSize=7, leading=8)
    style_cell = ParagraphStyle("RptCell", parent=styles["Normal"], fontSize=7, leading=8)
    style_cell = ParagraphStyle("RptCell", parent=styles["Normal"], fontSize=8, leading=10, wordWrap="CJK")

    elements = []

    logo_path = os.path.join(app.root_path, "static", "logo", "asarfi.png")
    if os.path.exists(logo_path):
        logo = Image(logo_path, width=22 * mm, height=22 * mm, mask='auto')
        logo.hAlign = "CENTER"
        elements.append(logo)

    elements.append(Spacer(1, 6))
    elements.append(Paragraph("Admission and Discharge Department wise", style_title))
    elements.append(Paragraph(f"{_fmt_date(from_date)} to {_fmt_date(to_date)}", style_sub))

    exported_by = exported_by or "Unknown"
    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%d-%b-%Y %I:%M %p")
    elements.append(Paragraph(f"Unit: {unit} | Exported by: {exported_by} | Exported at: {exported_at}", style_meta))
    elements.append(Spacer(1, 8))

    def _wrap_text(val) -> Paragraph:
        return Paragraph(escape(str(val or "")), style_cell)

    table_data = [["Patient Type", "SNo", "Department Name", "Admission", "Discharge"]]
    spans = []
    total_rows = []
    row_idx = 1
    sno = 1
    grand_adm = 0
    grand_dis = 0

    for pt, group in df.groupby("PatientType", sort=True):
        group = group.sort_values("DepartmentName")
        start_row = row_idx
        group_adm = 0
        group_dis = 0
        for _, row in group.iterrows():
            adm = float(row.get("Admission") or 0)
            dis = float(row.get("Discharge") or 0)
            group_adm += adm
            group_dis += dis
            grand_adm += adm
            grand_dis += dis
            table_data.append([
                _wrap_text(pt) if row_idx == start_row else "",
                str(sno),
                _wrap_text(row.get("DepartmentName") or ""),
                _fmt_num(adm),
                _fmt_num(dis),
            ])
            row_idx += 1
            sno += 1

        table_data.append(["", "", "Total :", _fmt_num(group_adm), _fmt_num(group_dis)])
        total_rows.append(row_idx)
        spans.append((0, start_row, 0, row_idx))
        row_idx += 1

    table_data.append(["", "", "Grand Total :", _fmt_num(grand_adm), _fmt_num(grand_dis)])
    grand_total_row = row_idx

    tbl = Table(table_data, colWidths=[45 * mm, 12 * mm, 70 * mm, 25 * mm, 25 * mm])
    tbl_style = TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("FONTSIZE", (0, 0), (-1, -1), 8),
        ("GRID", (0, 0), (-1, -1), 0.5, colors.HexColor("#1f2937")),
        ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
        ("ALIGN", (1, 1), (1, -1), "CENTER"),
        ("ALIGN", (3, 1), (4, -1), "RIGHT"),
        ("FONTNAME", (0, 1), (0, -1), "Helvetica-Bold"),
    ])

    for r in total_rows:
        tbl_style.add("BACKGROUND", (0, r), (-1, r), colors.HexColor("#f8fafc"))
        tbl_style.add("FONTNAME", (0, r), (-1, r), "Helvetica-Bold")

    tbl_style.add("BACKGROUND", (0, grand_total_row), (-1, grand_total_row), colors.HexColor("#e2e8f0"))
    tbl_style.add("FONTNAME", (0, grand_total_row), (-1, grand_total_row), "Helvetica-Bold")

    for c0, r0, c1, r1 in spans:
        tbl_style.add("SPAN", (c0, r0), (c1, r1))

    tbl.setStyle(tbl_style)
    elements.append(tbl)
    elements.append(Spacer(1, 8))

    elements.append(Paragraph("Copyright: (c) ASARFI HOSPITAL", style_meta))
    doc.build(elements)
    buffer.seek(0)
    return buffer

@app.route('/api/mis/admission_discharge_summary/export_pdf')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_admission_discharge_summary_export_pdf():
    unit = (request.args.get("unit") or "").strip().upper()
    from_date = (request.args.get("from") or "").strip()
    to_date = (request.args.get("to") or "").strip()
    allowed_units = _allowed_units_for_session()

    if not allowed_units:
        return "No unit access assigned", 403
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return "Please select a unit", 400
    if unit not in allowed_units:
        return f"Unit {unit} not permitted for your role", 403
    if not from_date or not to_date:
        return "Please select a valid date range", 400

    exported_by = session.get("username") or session.get("user") or "Unknown"
    buffer = _build_admission_discharge_pdf_buffer(unit, from_date, to_date, exported_by)
    if buffer is None:
        return "No data available to export", 404
    filename = f"Admission_Discharge_Summary_{unit}_{from_date}_to_{to_date}.pdf"
    return send_file(buffer, mimetype="application/pdf", as_attachment=True, download_name=filename)




# ============================================================
# MIS: Old vs New Patient Visits (Marketing)
# ============================================================
OLD_NEW_ALLOWED_VISIT_TYPES = {
    1: "IPD",
    2: "OPD",
    3: "DPV",
    6: "HCV",
}

OLD_NEW_PDF_DETAILS_CAP = 400
OLD_NEW_PDF_SOURCE_DEPT_CAP = 300
OLD_NEW_PDF_SOURCE_DOCTOR_CAP = 300


def _old_new_visit_type_label(visit_type_id: int) -> str:
    try:
        return OLD_NEW_ALLOWED_VISIT_TYPES.get(int(visit_type_id), f"VisitType-{visit_type_id}")
    except Exception:
        return "Unknown"


def _old_new_parse_iso_date(value: str) -> date | None:
    raw = str(value or "").strip()
    if not raw:
        return None
    try:
        return datetime.strptime(raw, "%Y-%m-%d").date()
    except Exception:
        return None


def _old_new_validate_request_params(unit_raw, from_raw, to_raw, visit_type_raw):
    allowed_units = _allowed_units_for_session()
    if not allowed_units:
        return None, "No unit access assigned", 403

    unit = str(unit_raw or "").strip().upper()
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return None, "Please select a unit", 400

    if unit not in allowed_units:
        return None, f"Unit {unit} not permitted for your role", 403

    from_date = str(from_raw or "").strip()
    to_date = str(to_raw or "").strip()
    if not from_date or not to_date:
        return None, "Please provide both from and to dates in YYYY-MM-DD format", 400

    from_dt = _old_new_parse_iso_date(from_date)
    to_dt = _old_new_parse_iso_date(to_date)
    if not from_dt or not to_dt:
        return None, "Invalid date format. Use YYYY-MM-DD for from/to", 400
    if from_dt > to_dt:
        return None, f"Invalid date range: from ({from_date}) must be <= to ({to_date})", 400

    visit_type_id = _coerce_int(visit_type_raw, allow_none=True)
    if visit_type_id not in OLD_NEW_ALLOWED_VISIT_TYPES:
        allowed = ", ".join(str(k) for k in sorted(OLD_NEW_ALLOWED_VISIT_TYPES.keys()))
        return None, f"Invalid visit_type_id. Allowed values: {allowed}", 400

    return {
        "unit": unit,
        "from_date": from_dt.strftime("%Y-%m-%d"),
        "to_date": to_dt.strftime("%Y-%m-%d"),
        "visit_type_id": int(visit_type_id),
        "visit_type_label": _old_new_visit_type_label(visit_type_id),
        "allowed_units": allowed_units,
    }, None, None


def _old_new_json_records(df: pd.DataFrame) -> list[dict]:
    if df is None or df.empty:
        return []
    out = df.copy()
    for col in out.columns:
        if pd.api.types.is_datetime64_any_dtype(out[col]):
            out[col] = pd.to_datetime(out[col], errors="coerce").dt.strftime("%Y-%m-%d")
    out = out.replace({pd.NA: None, np.nan: None})
    out = out.where(pd.notna(out), None)
    return out.to_dict(orient="records")


def _old_new_normalize_summary_df(df: pd.DataFrame) -> pd.DataFrame:
    cols = ["Dept", "TotalVisits", "NewPatientVisits", "OldPatientVisits", "NewPct", "OldPct"]
    if df is None or df.empty:
        return pd.DataFrame(columns=cols)

    df = _clean_df_columns(df.copy())
    cmap = {str(c).strip().lower(): c for c in df.columns}

    def _pick(candidates):
        for c in candidates:
            key = str(c).strip().lower()
            if key in cmap:
                return cmap[key]
        return None

    dept_col = _pick(["Dept", "Department", "DepartmentName", "DeptName"])
    total_col = _pick(["TotalVisits", "TotalVisit", "Total"])
    new_col = _pick(["NewPatientVisits", "NewVisits", "NewPatientVisit"])
    old_col = _pick(["OldPatientVisits", "OldVisits", "OldPatientVisit"])

    out = pd.DataFrame({
        "Dept": df[dept_col] if dept_col else "",
        "TotalVisits": pd.to_numeric(df[total_col], errors="coerce") if total_col else 0,
        "NewPatientVisits": pd.to_numeric(df[new_col], errors="coerce") if new_col else 0,
        "OldPatientVisits": pd.to_numeric(df[old_col], errors="coerce") if old_col else None,
    })
    out["Dept"] = out["Dept"].fillna("").astype(str).str.strip().replace("", "Unknown")
    out["TotalVisits"] = pd.to_numeric(out["TotalVisits"], errors="coerce").fillna(0).astype(int)
    out["NewPatientVisits"] = pd.to_numeric(out["NewPatientVisits"], errors="coerce").fillna(0).astype(int)
    out["OldPatientVisits"] = pd.to_numeric(out["OldPatientVisits"], errors="coerce")
    out["OldPatientVisits"] = out["OldPatientVisits"].fillna(out["TotalVisits"] - out["NewPatientVisits"])
    out["OldPatientVisits"] = pd.to_numeric(out["OldPatientVisits"], errors="coerce").fillna(0).astype(int)
    out["OldPatientVisits"] = out["OldPatientVisits"].clip(lower=0)
    out["TotalVisits"] = out["TotalVisits"].clip(lower=0)

    total_nonzero = out["TotalVisits"].replace(0, np.nan)
    out["NewPct"] = ((out["NewPatientVisits"] / total_nonzero) * 100.0).fillna(0.0).round(2)
    out["OldPct"] = ((out["OldPatientVisits"] / total_nonzero) * 100.0).fillna(0.0).round(2)
    out = out.sort_values(["Dept"], kind="mergesort").reset_index(drop=True)
    return out[cols]


def _old_new_normalize_detail_df(df: pd.DataFrame) -> pd.DataFrame:
    cols = [
        "Dept",
        "SubDept",
        "Doctor",
        "VisitDate",
        "Visit_ID",
        "PatientName",
        "RegNo",
        "PatientType",
    ]
    if df is None or df.empty:
        return pd.DataFrame(columns=cols)

    df = _clean_df_columns(df.copy())
    cmap = {str(c).strip().lower(): c for c in df.columns}

    def _pick(candidates):
        for c in candidates:
            key = str(c).strip().lower()
            if key in cmap:
                return cmap[key]
        return None

    dept_col = _pick(["Dept", "Department", "DepartmentName", "DeptName"])
    subdept_col = _pick(["SubDept", "SubDepartment", "SubDepartmentName"])
    doctor_col = _pick(["Doctor", "DoctorName"])
    visit_date_col = _pick(["VisitDate", "Visit_Date"])
    visit_id_col = _pick(["Visit_ID", "VisitId", "VisitID"])
    patient_col = _pick(["PatientName", "Patient", "Patient_Name"])
    reg_col = _pick(["RegNo", "Reg_No", "Registration_No", "RegistrationNo"])
    ptype_col = _pick(["PatientType", "PatType"])

    out = pd.DataFrame({
        "Dept": df[dept_col] if dept_col else "",
        "SubDept": df[subdept_col] if subdept_col else "",
        "Doctor": df[doctor_col] if doctor_col else "",
        "VisitDate": df[visit_date_col] if visit_date_col else None,
        "Visit_ID": pd.to_numeric(df[visit_id_col], errors="coerce") if visit_id_col else None,
        "PatientName": df[patient_col] if patient_col else "",
        "RegNo": df[reg_col] if reg_col else "",
        "PatientType": df[ptype_col] if ptype_col else "",
    })

    for col in ["Dept", "SubDept", "Doctor", "PatientName", "RegNo", "PatientType"]:
        out[col] = out[col].astype(str).replace({"nan": "", "None": ""}).str.strip()

    out["Dept"] = out["Dept"].replace("", "Unknown")
    out["SubDept"] = out["SubDept"].replace("", "Unknown")
    out["Doctor"] = out["Doctor"].replace("", "Unknown")
    out["VisitDate"] = pd.to_datetime(out["VisitDate"], errors="coerce").dt.strftime("%Y-%m-%d").fillna("")
    out["Visit_ID"] = pd.to_numeric(out["Visit_ID"], errors="coerce").fillna(0).astype(int)
    out["PatientType"] = out["PatientType"].str.title()
    out["PatientType"] = np.where(out["PatientType"] == "New", "New", "Old")
    out = out.sort_values(["Dept", "SubDept", "Doctor", "VisitDate", "Visit_ID"], kind="mergesort").reset_index(drop=True)
    return out[cols]


def _old_new_normalize_source_map_df(df: pd.DataFrame) -> pd.DataFrame:
    cols = ["Visit_ID", "SourceID", "SourceName"]
    if df is None or df.empty:
        return pd.DataFrame(columns=cols)

    df = _clean_df_columns(df.copy())
    cmap = {str(c).strip().lower(): c for c in df.columns}

    def _pick(candidates):
        for c in candidates:
            key = str(c).strip().lower()
            if key in cmap:
                return cmap[key]
        return None

    visit_col = _pick(["Visit_ID", "VisitId", "VisitID"])
    sid_col = _pick(["SourceID", "PatientSourceId", "Source_Id"])
    sname_col = _pick(["SourceName", "PatientSource", "Source"])

    out = pd.DataFrame({
        "Visit_ID": pd.to_numeric(df[visit_col], errors="coerce") if visit_col else None,
        "SourceID": pd.to_numeric(df[sid_col], errors="coerce") if sid_col else 0,
        "SourceName": df[sname_col] if sname_col else "Unknown",
    })
    out["Visit_ID"] = pd.to_numeric(out["Visit_ID"], errors="coerce").fillna(0).astype(int)
    out["SourceID"] = pd.to_numeric(out["SourceID"], errors="coerce").fillna(0).astype(int)
    out["SourceName"] = out["SourceName"].astype(str).replace({"nan": "", "None": ""}).str.strip()
    out["SourceName"] = out["SourceName"].replace("", "Unknown")
    out = out.drop_duplicates(subset=["Visit_ID"], keep="last")
    return out[cols]


def _old_new_source_comparison_frames(details_df: pd.DataFrame):
    src_summary_cols = [
        "SourceID",
        "SourceName",
        "TotalVisits",
        "NewVisits",
        "OldVisits",
        "VisitSharePct",
        "OldPct",
        "UniquePatients",
        "UniqueDoctors",
        "UniqueDepartments",
    ]
    src_dept_cols = [
        "SourceID",
        "SourceName",
        "Dept",
        "TotalVisits",
        "NewVisits",
        "OldVisits",
        "ShareWithinSourcePct",
        "OldPct",
    ]
    src_doc_cols = [
        "SourceID",
        "SourceName",
        "Dept",
        "SubDept",
        "Doctor",
        "TotalVisits",
        "NewVisits",
        "OldVisits",
        "ShareWithinSourcePct",
        "OldPct",
    ]

    if details_df is None or details_df.empty:
        return (
            pd.DataFrame(columns=src_summary_cols),
            pd.DataFrame(columns=src_dept_cols),
            pd.DataFrame(columns=src_doc_cols),
        )

    work = details_df.copy()
    for col in ["SourceName", "Dept", "SubDept", "Doctor", "RegNo", "PatientName"]:
        if col not in work.columns:
            work[col] = ""
        work[col] = work[col].astype(str).replace({"nan": "", "None": ""}).str.strip()
    if "SourceID" not in work.columns:
        work["SourceID"] = 0
    work["SourceID"] = pd.to_numeric(work["SourceID"], errors="coerce").fillna(0).astype(int)
    work["Visit_ID"] = pd.to_numeric(work.get("Visit_ID"), errors="coerce").fillna(0).astype(int)
    work["SourceName"] = work["SourceName"].replace("", "Unknown")
    work["Dept"] = work["Dept"].replace("", "Unknown")
    work["SubDept"] = work["SubDept"].replace("", "Unknown")
    work["Doctor"] = work["Doctor"].replace("", "Unknown")
    work["PatientType"] = np.where(work["PatientType"].astype(str).str.title() == "New", "New", "Old")

    patient_key = work["RegNo"].copy()
    patient_key = patient_key.where(patient_key.str.strip() != "", work["PatientName"])
    patient_key = patient_key.where(patient_key.str.strip() != "", "Visit-" + work["Visit_ID"].astype(str))
    work["PatientKey"] = patient_key

    total_visits = int(work["Visit_ID"].nunique())
    if total_visits <= 0:
        total_visits = int(len(work))

    src_summary = (
        work.groupby(["SourceID", "SourceName"], dropna=False)
        .agg(
            TotalVisits=("Visit_ID", "nunique"),
            NewVisits=("PatientType", lambda s: int((s == "New").sum())),
            OldVisits=("PatientType", lambda s: int((s == "Old").sum())),
            UniquePatients=("PatientKey", lambda s: int(s.dropna().astype(str).str.strip().replace("", np.nan).dropna().nunique())),
            UniqueDoctors=("Doctor", lambda s: int(s.dropna().astype(str).str.strip().replace("", np.nan).dropna().nunique())),
            UniqueDepartments=("Dept", lambda s: int(s.dropna().astype(str).str.strip().replace("", np.nan).dropna().nunique())),
        )
        .reset_index()
    )
    src_summary["VisitSharePct"] = np.where(total_visits > 0, (src_summary["TotalVisits"] / total_visits) * 100.0, 0.0)
    src_summary["OldPct"] = np.where(src_summary["TotalVisits"] > 0, (src_summary["OldVisits"] / src_summary["TotalVisits"]) * 100.0, 0.0)
    for col in ["VisitSharePct", "OldPct"]:
        src_summary[col] = src_summary[col].astype(float).round(2)
    src_summary = src_summary.sort_values(["TotalVisits", "OldVisits", "SourceName"], ascending=[False, False, True], kind="mergesort").reset_index(drop=True)
    src_summary = src_summary[src_summary_cols]

    src_dept = (
        work.groupby(["SourceID", "SourceName", "Dept"], dropna=False)
        .agg(
            TotalVisits=("Visit_ID", "nunique"),
            NewVisits=("PatientType", lambda s: int((s == "New").sum())),
            OldVisits=("PatientType", lambda s: int((s == "Old").sum())),
        )
        .reset_index()
    )
    if not src_dept.empty:
        src_totals = src_summary[["SourceID", "SourceName", "TotalVisits"]].rename(columns={"TotalVisits": "_SourceTotal"})
        src_dept = src_dept.merge(src_totals, on=["SourceID", "SourceName"], how="left")
        src_dept["_SourceTotal"] = pd.to_numeric(src_dept["_SourceTotal"], errors="coerce").fillna(0)
        src_dept["ShareWithinSourcePct"] = np.where(src_dept["_SourceTotal"] > 0, (src_dept["TotalVisits"] / src_dept["_SourceTotal"]) * 100.0, 0.0)
        src_dept["OldPct"] = np.where(src_dept["TotalVisits"] > 0, (src_dept["OldVisits"] / src_dept["TotalVisits"]) * 100.0, 0.0)
        src_dept["ShareWithinSourcePct"] = src_dept["ShareWithinSourcePct"].round(2)
        src_dept["OldPct"] = src_dept["OldPct"].round(2)
        src_dept = src_dept.drop(columns=["_SourceTotal"])
    src_dept = src_dept.sort_values(["TotalVisits", "SourceName", "Dept"], ascending=[False, True, True], kind="mergesort").reset_index(drop=True)
    src_dept = src_dept[src_dept_cols] if not src_dept.empty else pd.DataFrame(columns=src_dept_cols)

    src_doc = (
        work.groupby(["SourceID", "SourceName", "Dept", "SubDept", "Doctor"], dropna=False)
        .agg(
            TotalVisits=("Visit_ID", "nunique"),
            NewVisits=("PatientType", lambda s: int((s == "New").sum())),
            OldVisits=("PatientType", lambda s: int((s == "Old").sum())),
        )
        .reset_index()
    )
    if not src_doc.empty:
        src_totals = src_summary[["SourceID", "SourceName", "TotalVisits"]].rename(columns={"TotalVisits": "_SourceTotal"})
        src_doc = src_doc.merge(src_totals, on=["SourceID", "SourceName"], how="left")
        src_doc["_SourceTotal"] = pd.to_numeric(src_doc["_SourceTotal"], errors="coerce").fillna(0)
        src_doc["ShareWithinSourcePct"] = np.where(src_doc["_SourceTotal"] > 0, (src_doc["TotalVisits"] / src_doc["_SourceTotal"]) * 100.0, 0.0)
        src_doc["OldPct"] = np.where(src_doc["TotalVisits"] > 0, (src_doc["OldVisits"] / src_doc["TotalVisits"]) * 100.0, 0.0)
        src_doc["ShareWithinSourcePct"] = src_doc["ShareWithinSourcePct"].round(2)
        src_doc["OldPct"] = src_doc["OldPct"].round(2)
        src_doc = src_doc.drop(columns=["_SourceTotal"])
    src_doc = src_doc.sort_values(
        ["TotalVisits", "SourceName", "Dept", "SubDept", "Doctor"],
        ascending=[False, True, True, True, True],
        kind="mergesort",
    ).reset_index(drop=True)
    src_doc = src_doc[src_doc_cols] if not src_doc.empty else pd.DataFrame(columns=src_doc_cols)

    return src_summary, src_dept, src_doc


def _old_new_followup_configs(visit_type_id: int) -> list[dict]:
    try:
        visit_type_id = int(visit_type_id)
    except Exception:
        return []

    if visit_type_id == 2:
        return [
            {
                "flag_col": "HasDPV",
                "summary_key": "NewPatientsDidDPV",
                "summary_label": "New -> DPV",
                "kpi_key": "new_patients_did_dpv",
                "kpi_label": "New Patients Did DPV",
                "sheet_name": "New_OPD_DPV_Details",
                "title": "New OPD Patients Who Did DPV",
                "decision_note": "Follow-up logic for OPD: counts only new OPD rows where the same patient later had a DPV visit.",
            },
            {
                "flag_col": "HasIPD",
                "summary_key": "NewPatientsDidIPD",
                "summary_label": "New -> IPD",
                "kpi_key": "new_patients_did_ipd",
                "kpi_label": "New Patients Did IPD",
                "sheet_name": "New_OPD_IPD_Details",
                "title": "New OPD Patients Who Did IPD",
                "decision_note": "Follow-up logic for OPD: counts only new OPD rows where the same patient later had an IPD visit.",
            },
        ]

    if visit_type_id == 6:
        return [
            {
                "flag_col": "HasIPD",
                "summary_key": "NewPatientsDidIPD",
                "summary_label": "New -> IPD",
                "kpi_key": "new_patients_did_ipd",
                "kpi_label": "New Patients Did IPD",
                "sheet_name": "New_HCV_IPD_Details",
                "title": "New HCV Patients Who Did IPD",
                "decision_note": "Follow-up logic for HCV: counts only new HCV rows where the same patient later had an IPD visit.",
            },
        ]

    return []


def _build_old_new_patient_visits_payload(unit: str, visit_type_id: int, from_date: str, to_date: str):
    trace = []

    def _trace(step: str, status: str = "ok", **meta):
        row = {"step": step, "status": status}
        if meta:
            row.update(meta)
        trace.append(row)

    try:
        summary_raw, details_raw = data_fetch.fetch_old_new_patient_visits(unit, visit_type_id, from_date, to_date)
    except Exception as exc:
        return None, f"Failed to fetch old/new patient visit data: {exc}", 500

    summary_df = _old_new_normalize_summary_df(summary_raw)
    details_df = _old_new_normalize_detail_df(details_raw)
    _trace(
        "procedure_fetch",
        status="ok",
        summary_rows=int(len(summary_df)),
        detail_rows=int(len(details_df)),
    )

    if summary_df.empty and not details_df.empty:
        deriv = (
            details_df.groupby("Dept", dropna=False)
            .agg(
                TotalVisits=("Visit_ID", "nunique"),
                NewPatientVisits=("PatientType", lambda s: int((s == "New").sum())),
                OldPatientVisits=("PatientType", lambda s: int((s == "Old").sum())),
            )
            .reset_index()
        )
        deriv["NewPct"] = np.where(deriv["TotalVisits"] > 0, (deriv["NewPatientVisits"] / deriv["TotalVisits"]) * 100.0, 0.0)
        deriv["OldPct"] = np.where(deriv["TotalVisits"] > 0, (deriv["OldPatientVisits"] / deriv["TotalVisits"]) * 100.0, 0.0)
        deriv["NewPct"] = deriv["NewPct"].round(2)
        deriv["OldPct"] = deriv["OldPct"].round(2)
        summary_df = deriv[["Dept", "TotalVisits", "NewPatientVisits", "OldPatientVisits", "NewPct", "OldPct"]]
        summary_df = summary_df.sort_values(["Dept"], kind="mergesort").reset_index(drop=True)
        _trace("summary_fallback", status="warning", message="Procedure summary was empty; derived from detail rows")

    visit_ids = sorted({int(v) for v in details_df.get("Visit_ID", pd.Series(dtype=int)).tolist() if int(v) > 0})
    _trace("collect_visit_ids", status="ok", visit_ids_count=int(len(visit_ids)))

    source_map_raw = pd.DataFrame(columns=["Visit_ID", "SourceID", "SourceName"])
    if visit_ids:
        try:
            source_map_raw = data_fetch.fetch_patient_source_map_for_visits(unit, visit_ids)
        except Exception as exc:
            _trace("source_mapping_fetch", status="warning", message=f"Source mapping fetch failed: {exc}")
            source_map_raw = pd.DataFrame(columns=["Visit_ID", "SourceID", "SourceName"])
    source_map_df = _old_new_normalize_source_map_df(source_map_raw)
    _trace(
        "source_mapping_fetch",
        status="ok",
        mapped_rows=int(len(source_map_df)),
    )

    if details_df.empty:
        details_df["SourceID"] = pd.Series(dtype=int)
        details_df["SourceName"] = pd.Series(dtype=str)
    else:
        details_df = details_df.merge(source_map_df, on="Visit_ID", how="left")
        details_df["SourceID"] = pd.to_numeric(details_df.get("SourceID"), errors="coerce").fillna(0).astype(int)
        details_df["SourceName"] = details_df.get("SourceName", "").astype(str).replace({"nan": "", "None": ""}).str.strip()
        details_df["SourceName"] = details_df["SourceName"].replace("", "Unknown")

    details_df = details_df[
        ["Dept", "SubDept", "Doctor", "VisitDate", "Visit_ID", "PatientName", "RegNo", "PatientType", "SourceID", "SourceName"]
    ]
    detail_export_cols = list(details_df.columns)

    summary_extra_columns = []
    summary_extra_kpis = {}
    conversion_detail_sections = []
    followup_configs = _old_new_followup_configs(visit_type_id)
    if followup_configs:
        new_detail_df = details_df[details_df["PatientType"].astype(str).str.title() == "New"].copy() if not details_df.empty else pd.DataFrame(columns=detail_export_cols)
        base_followup_visit_ids = sorted({
            int(v) for v in new_detail_df.get("Visit_ID", pd.Series(dtype=int)).tolist()
            if pd.notna(v) and int(v) > 0
        })
        target_visit_types = []
        for cfg in followup_configs:
            if cfg.get("flag_col") == "HasDPV":
                target_visit_types.append(3)
            if cfg.get("flag_col") == "HasIPD":
                target_visit_types.append(1)
        target_visit_types = sorted(set(target_visit_types))

        followup_flags_df = pd.DataFrame(columns=["BaseVisit_ID", "HasIPD", "HasDPV"])
        if base_followup_visit_ids and target_visit_types:
            try:
                followup_flags_df = data_fetch.fetch_old_new_followup_flags(unit, base_followup_visit_ids, target_visit_types)
            except Exception as exc:
                _trace("followup_flags_fetch", status="warning", message=f"Follow-up fetch failed: {exc}")
                followup_flags_df = pd.DataFrame(columns=["BaseVisit_ID", "HasIPD", "HasDPV"])

        if "Visit_ID" not in new_detail_df.columns:
            new_detail_df["Visit_ID"] = pd.Series(dtype=int)
        if new_detail_df.empty:
            _trace(
                "followup_flags_fetch",
                status="ok",
                candidate_rows=0,
                target_visit_types=target_visit_types,
                flagged_rows=0,
            )
        else:
            if followup_flags_df.empty:
                new_detail_df["HasIPD"] = 0
                new_detail_df["HasDPV"] = 0
                _trace(
                    "followup_flags_fetch",
                    status="warning",
                    candidate_rows=int(len(new_detail_df)),
                    target_visit_types=target_visit_types,
                    flagged_rows=0,
                    message="No follow-up mapping rows returned for the candidate new visits.",
                )
            else:
                followup_flags_df = followup_flags_df.copy()
                followup_flags_df["BaseVisit_ID"] = pd.to_numeric(followup_flags_df.get("BaseVisit_ID"), errors="coerce").fillna(0).astype(int)
                for flag_col in ["HasIPD", "HasDPV"]:
                    followup_flags_df[flag_col] = pd.to_numeric(followup_flags_df.get(flag_col), errors="coerce").fillna(0).astype(int)
                new_detail_df = new_detail_df.merge(
                    followup_flags_df[["BaseVisit_ID", "HasIPD", "HasDPV"]],
                    left_on="Visit_ID",
                    right_on="BaseVisit_ID",
                    how="left",
                )
                for flag_col in ["HasIPD", "HasDPV"]:
                    new_detail_df[flag_col] = pd.to_numeric(new_detail_df.get(flag_col), errors="coerce").fillna(0).astype(int)
                if "BaseVisit_ID" in new_detail_df.columns:
                    new_detail_df = new_detail_df.drop(columns=["BaseVisit_ID"])
                flagged_rows_total = int(new_detail_df[["HasIPD", "HasDPV"]].max(axis=1).fillna(0).astype(int).gt(0).sum())
                _trace(
                    "followup_flags_fetch",
                    status="ok",
                    candidate_rows=int(len(new_detail_df)),
                    target_visit_types=target_visit_types,
                    flagged_rows=flagged_rows_total,
                )

        for cfg in followup_configs:
            flag_col = str(cfg.get("flag_col") or "").strip()
            summary_key = str(cfg.get("summary_key") or "").strip()
            kpi_key = str(cfg.get("kpi_key") or "").strip()
            if not flag_col or not summary_key or not kpi_key:
                continue

            summary_extra_columns.append({
                "key": summary_key,
                "label": cfg.get("summary_label") or summary_key,
                "kpi_key": kpi_key,
                "kpi_label": cfg.get("kpi_label") or cfg.get("summary_label") or summary_key,
            })

            flagged_mask = pd.to_numeric(new_detail_df.get(flag_col), errors="coerce").fillna(0).astype(int).gt(0) if not new_detail_df.empty else pd.Series(dtype=bool)
            flagged_rows_df = new_detail_df.loc[flagged_mask, detail_export_cols].copy() if not new_detail_df.empty else pd.DataFrame(columns=detail_export_cols)
            dept_counts = (
                flagged_rows_df.groupby("Dept", dropna=False)["Visit_ID"].nunique().astype(int).to_dict()
                if not flagged_rows_df.empty else
                {}
            )
            if summary_df.empty:
                summary_df[summary_key] = pd.Series(dtype=int)
            else:
                summary_df[summary_key] = summary_df["Dept"].map(dept_counts).fillna(0).astype(int)

            summary_extra_kpis[kpi_key] = int(flagged_rows_df["Visit_ID"].nunique()) if not flagged_rows_df.empty else 0
            conversion_detail_sections.append({
                "key": kpi_key,
                "sheet_name": cfg.get("sheet_name") or kpi_key[:31],
                "title": cfg.get("title") or cfg.get("kpi_label") or kpi_key,
                "rows": _old_new_json_records(flagged_rows_df),
            })

    for extra_col in summary_extra_columns:
        key = str(extra_col.get("key") or "").strip()
        if key and key not in summary_df.columns:
            summary_df[key] = pd.Series(dtype=int) if summary_df.empty else 0

    mapped_mask = (details_df.get("SourceID", 0) > 0) & (details_df.get("SourceName", "").astype(str).str.lower() != "unknown")
    mapped_count = int(details_df.loc[mapped_mask, "Visit_ID"].nunique()) if not details_df.empty else 0
    total_detail_visits = int(details_df["Visit_ID"].nunique()) if not details_df.empty else 0
    if total_detail_visits <= 0:
        total_detail_visits = int(len(details_df))
    unmapped_count = max(total_detail_visits - mapped_count, 0)
    mapped_pct = round((mapped_count / total_detail_visits) * 100.0, 2) if total_detail_visits else 0.0
    _trace(
        "source_mapping_apply",
        status="warning" if unmapped_count > 0 else "ok",
        total_visits=total_detail_visits,
        mapped_visits=mapped_count,
        unmapped_visits=unmapped_count,
        mapped_pct=mapped_pct,
    )

    src_summary_df, src_dept_df, src_doc_df = _old_new_source_comparison_frames(details_df)
    _trace(
        "source_comparison_build",
        status="ok",
        source_summary_rows=int(len(src_summary_df)),
        source_dept_rows=int(len(src_dept_df)),
        source_doctor_rows=int(len(src_doc_df)),
    )

    sum_total = int(pd.to_numeric(summary_df.get("TotalVisits"), errors="coerce").fillna(0).sum()) if not summary_df.empty else 0
    sum_new = int(pd.to_numeric(summary_df.get("NewPatientVisits"), errors="coerce").fillna(0).sum()) if not summary_df.empty else 0
    sum_old = int(pd.to_numeric(summary_df.get("OldPatientVisits"), errors="coerce").fillna(0).sum()) if not summary_df.empty else 0
    if sum_total <= 0 and total_detail_visits > 0:
        sum_total = total_detail_visits
        sum_new = int((details_df["PatientType"] == "New").sum())
        sum_old = int((details_df["PatientType"] == "Old").sum())

    new_pct = round((sum_new / sum_total) * 100.0, 2) if sum_total else 0.0
    old_pct = round((sum_old / sum_total) * 100.0, 2) if sum_total else 0.0

    details_rows = int(len(details_df))
    reg_series = details_df["RegNo"].astype(str).str.strip().replace("", np.nan) if "RegNo" in details_df.columns else pd.Series(dtype=object)
    unique_patients = int(reg_series.dropna().nunique()) if not details_df.empty else 0
    if unique_patients == 0 and not details_df.empty:
        unique_patients = int(details_df["PatientName"].astype(str).str.strip().replace("", np.nan).dropna().nunique())
    unique_doctors = int(details_df["Doctor"].astype(str).str.strip().replace("", np.nan).dropna().nunique()) if not details_df.empty else 0
    unique_depts = int(details_df["Dept"].astype(str).str.strip().replace("", np.nan).dropna().nunique()) if not details_df.empty else 0
    detail_old_pct = round((int((details_df["PatientType"] == "Old").sum()) / details_rows) * 100.0, 2) if details_rows else 0.0

    top_source_name = "N/A"
    top_source_old_pct = 0.0
    if src_summary_df is not None and not src_summary_df.empty:
        mapped_sources = src_summary_df[
            (pd.to_numeric(src_summary_df["SourceID"], errors="coerce").fillna(0) > 0)
            & (src_summary_df["SourceName"].astype(str).str.lower() != "unknown")
        ]
        top_src_df = mapped_sources if not mapped_sources.empty else src_summary_df
        top_row = top_src_df.iloc[0]
        top_source_name = str(top_row.get("SourceName") or "Unknown")
        top_source_old_pct = round(float(top_row.get("OldPct") or 0.0), 2)

    decision_notes = [
        "New patient logic: registration date equals visit date (as defined by dbo.usp_ComprehensiveOldNewPatientVisits).",
        "Old patient logic: old patient visits equal total visits minus new patient visits.",
        "Source mapping logic: Visit.PatientSourceId is mapped to Occupation_Mst.Occupation_Name; missing or invalid mappings are marked as Unknown.",
        "Source comparison is visit-level and aligned with the revenue source mapping method.",
    ]
    for cfg in followup_configs:
        note = str(cfg.get("decision_note") or "").strip()
        if note:
            decision_notes.append(note)

    payload = {
        "status": "success",
        "unit": unit,
        "from_date": from_date,
        "to_date": to_date,
        "visit_type_id": int(visit_type_id),
        "visit_type_label": _old_new_visit_type_label(visit_type_id),
        "kpis": {
            "summary": {
                "total_visits": sum_total,
                "new_visits": sum_new,
                "old_visits": sum_old,
                "new_pct": new_pct,
                "old_pct": old_pct,
                "department_count": int(summary_df["Dept"].nunique()) if not summary_df.empty else 0,
                **summary_extra_kpis,
            },
            "details": {
                "detail_rows": details_rows,
                "unique_patients": unique_patients,
                "unique_doctors": unique_doctors,
                "unique_departments": unique_depts,
                "old_pct_loyalty_index": detail_old_pct,
            },
            "source": {
                "mapped_pct": mapped_pct,
                "unmapped_count": unmapped_count,
                "top_source": top_source_name,
                "top_source_old_pct": top_source_old_pct,
            },
        },
        "summary_extra_columns": summary_extra_columns,
        "summary_rows": _old_new_json_records(summary_df),
        "detail_rows": _old_new_json_records(details_df),
        "conversion_detail_sections": conversion_detail_sections,
        "source_summary_rows": _old_new_json_records(src_summary_df),
        "source_dept_rows": _old_new_json_records(src_dept_df),
        "source_doctor_rows": _old_new_json_records(src_doc_df),
        "decision_notes": decision_notes,
        "trace": trace,
        "has_data": bool(len(summary_df) or len(details_df)),
    }
    return payload, None, None


@app.route('/api/mis/old_new_patient_visits')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_old_new_patient_visits():
    params, err, status_code = _old_new_validate_request_params(
        request.args.get("unit"),
        request.args.get("from"),
        request.args.get("to"),
        request.args.get("visit_type_id"),
    )
    if err:
        return jsonify({"status": "error", "message": err}), status_code

    payload, payload_err, payload_status = _build_old_new_patient_visits_payload(
        params["unit"],
        params["visit_type_id"],
        params["from_date"],
        params["to_date"],
    )
    if payload_err:
        return jsonify({"status": "error", "message": payload_err}), payload_status or 500
    return jsonify(payload)


def _old_new_payload_to_frames(payload: dict):
    summary_cols = ["Dept", "TotalVisits", "NewPatientVisits", "OldPatientVisits", "NewPct", "OldPct"]
    detail_cols = ["Dept", "SubDept", "Doctor", "VisitDate", "Visit_ID", "PatientName", "RegNo", "PatientType", "SourceID", "SourceName"]
    source_summary_cols = ["SourceID", "SourceName", "TotalVisits", "NewVisits", "OldVisits", "VisitSharePct", "OldPct", "UniquePatients", "UniqueDoctors", "UniqueDepartments"]
    source_dept_cols = ["SourceID", "SourceName", "Dept", "TotalVisits", "NewVisits", "OldVisits", "ShareWithinSourcePct", "OldPct"]
    source_doc_cols = ["SourceID", "SourceName", "Dept", "SubDept", "Doctor", "TotalVisits", "NewVisits", "OldVisits", "ShareWithinSourcePct", "OldPct"]
    extra_summary_cols = [
        str(item.get("key") or "").strip()
        for item in (payload.get("summary_extra_columns") or [])
        if str(item.get("key") or "").strip()
    ]
    summary_cols = summary_cols + [col for col in extra_summary_cols if col not in summary_cols]

    def _make(rows, cols, numeric_cols: set[str] | None = None):
        numeric_cols = set(numeric_cols or set())
        df = pd.DataFrame(rows or [])
        for col in cols:
            if col not in df.columns:
                df[col] = 0 if col.lower().endswith("id") or col in numeric_cols else ""
        return df[cols]

    conversion_sections = []
    for item in (payload.get("conversion_detail_sections") or []):
        conversion_sections.append({
            "key": str(item.get("key") or "").strip(),
            "sheet_name": str(item.get("sheet_name") or "Details").strip()[:31],
            "title": str(item.get("title") or "Visit Details").strip(),
            "df": _make(item.get("rows"), detail_cols, numeric_cols={"Visit_ID", "SourceID"}),
        })

    return (
        _make(
            payload.get("summary_rows"),
            summary_cols,
            numeric_cols={"TotalVisits", "NewPatientVisits", "OldPatientVisits", "NewPct", "OldPct", *extra_summary_cols},
        ),
        _make(payload.get("detail_rows"), detail_cols, numeric_cols={"Visit_ID", "SourceID"}),
        _make(
            payload.get("source_summary_rows"),
            source_summary_cols,
            numeric_cols={"SourceID", "TotalVisits", "NewVisits", "OldVisits", "VisitSharePct", "OldPct", "UniquePatients", "UniqueDoctors", "UniqueDepartments"},
        ),
        _make(
            payload.get("source_dept_rows"),
            source_dept_cols,
            numeric_cols={"SourceID", "TotalVisits", "NewVisits", "OldVisits", "ShareWithinSourcePct", "OldPct"},
        ),
        _make(
            payload.get("source_doctor_rows"),
            source_doc_cols,
            numeric_cols={"SourceID", "TotalVisits", "NewVisits", "OldVisits", "ShareWithinSourcePct", "OldPct"},
        ),
        conversion_sections,
    )


def _build_old_new_patient_visits_excel(
    unit: str,
    from_date: str,
    to_date: str,
    visit_type_id: int,
    exported_by: str,
):
    payload, err, status_code = _build_old_new_patient_visits_payload(unit, visit_type_id, from_date, to_date)
    if err:
        return None, None, err
    if not payload or not payload.get("has_data"):
        return None, None, "No data available to export"

    summary_df, detail_df, source_summary_df, source_dept_df, source_doc_df, conversion_sections = _old_new_payload_to_frames(payload)

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
        workbook = writer.book

        title_fmt = workbook.add_format({
            "bold": True,
            "font_size": 14,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#1e3a8a",
            "font_color": "white",
        })
        subtitle_fmt = workbook.add_format({
            "bold": True,
            "font_size": 10,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#e2e8f0",
        })
        meta_fmt = workbook.add_format({
            "font_size": 9,
            "align": "left",
            "valign": "vcenter",
            "font_color": "#334155",
        })
        section_fmt = workbook.add_format({
            "bold": True,
            "font_size": 10,
            "align": "left",
            "valign": "vcenter",
            "bg_color": "#f1f5f9",
            "font_color": "#0f172a",
        })
        header_fmt = workbook.add_format({
            "bold": True,
            "font_size": 9,
            "align": "center",
            "valign": "vcenter",
            "bg_color": "#1e3a8a",
            "font_color": "white",
            "border": 1,
        })
        text_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "left"})
        int_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "#,##,##0"})
        dec_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "right", "num_format": "#,##,##0.00"})
        date_fmt = workbook.add_format({"font_size": 9, "border": 1, "align": "center", "num_format": "yyyy-mm-dd"})
        trace_fmt = workbook.add_format({"font_size": 8, "border": 1, "align": "left", "valign": "top"})
        blank_fmt = workbook.add_format({"font_size": 9, "align": "left"})
        text_col_fmt = workbook.add_format({"font_size": 9, "align": "left"})
        int_col_fmt = workbook.add_format({"font_size": 9, "align": "right", "num_format": "#,##,##0"})
        visitid_col_fmt = workbook.add_format({"font_size": 9, "align": "right", "num_format": "0"})
        dec_col_fmt = workbook.add_format({"font_size": 9, "align": "right", "num_format": "#,##,##0.00"})
        date_col_fmt = workbook.add_format({"font_size": 9, "align": "center", "num_format": "yyyy-mm-dd"})
        row_border_fmt = workbook.add_format({"border": 1})

        exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
        unit_header = _lab_unit_header_text(unit)
        visit_label = payload.get("visit_type_label") or _old_new_visit_type_label(visit_type_id)

        meta_ws = workbook.add_worksheet("Meta_KPI")
        writer.sheets["Meta_KPI"] = meta_ws
        meta_last_col = 4
        meta_ws.merge_range(0, 0, 0, meta_last_col, "MIS Marketing - Old vs New Patient Visits", title_fmt)
        meta_ws.merge_range(1, 0, 1, meta_last_col, f"Unit: {unit_header} | Visit Type: {visit_label}", subtitle_fmt)
        meta_ws.merge_range(2, 0, 2, meta_last_col, f"Date Range: {from_date} to {to_date}", subtitle_fmt)
        meta_ws.merge_range(3, 0, 3, meta_last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)

        metadata_rows = [
            ("Unit", unit),
            ("Visit Type ID", int(visit_type_id)),
            ("Visit Type Label", visit_label),
            ("From Date", from_date),
            ("To Date", to_date),
            ("Generated At", exported_at),
        ]
        meta_ptr = 5
        meta_ws.write(meta_ptr, 0, "Metadata", section_fmt)
        meta_ptr += 1
        for key, val in metadata_rows:
            meta_ws.write(meta_ptr, 0, key, text_fmt)
            if isinstance(val, (int, float, np.integer, np.floating)):
                meta_ws.write(meta_ptr, 1, float(val), dec_fmt if isinstance(val, float) else int_fmt)
            else:
                meta_ws.write(meta_ptr, 1, str(val), text_fmt)
            meta_ptr += 1

        meta_ptr += 1
        meta_ws.write(meta_ptr, 0, "KPI Blocks", section_fmt)
        meta_ptr += 1
        meta_ws.write_row(meta_ptr, 0, ["Group", "Metric", "Value"], header_fmt)
        meta_ptr += 1

        kpis = payload.get("kpis") or {}
        summary_kpi = kpis.get("summary") or {}
        detail_kpi = kpis.get("details") or {}
        source_kpi = kpis.get("source") or {}
        summary_extra_defs = payload.get("summary_extra_columns") or []
        kpi_rows = [
            ("Summary", "Total Visits", summary_kpi.get("total_visits", 0)),
            ("Summary", "New Visits", summary_kpi.get("new_visits", 0)),
            ("Summary", "Old Visits", summary_kpi.get("old_visits", 0)),
            ("Summary", "New %", summary_kpi.get("new_pct", 0.0)),
            ("Summary", "Old %", summary_kpi.get("old_pct", 0.0)),
            ("Summary", "Department Count", summary_kpi.get("department_count", 0)),
        ]
        for item in summary_extra_defs:
            kpi_rows.append((
                "Summary",
                str(item.get("kpi_label") or item.get("label") or "Extra Summary Metric"),
                summary_kpi.get(str(item.get("kpi_key") or ""), 0),
            ))
        kpi_rows.extend([
            ("Details", "Detail Rows", detail_kpi.get("detail_rows", 0)),
            ("Details", "Unique Patients", detail_kpi.get("unique_patients", 0)),
            ("Details", "Unique Doctors", detail_kpi.get("unique_doctors", 0)),
            ("Details", "Unique Departments", detail_kpi.get("unique_departments", 0)),
            ("Details", "Old % Loyalty Index", detail_kpi.get("old_pct_loyalty_index", 0.0)),
            ("Source", "Mapped Source %", source_kpi.get("mapped_pct", 0.0)),
            ("Source", "Unmapped Count", source_kpi.get("unmapped_count", 0)),
            ("Source", "Top Source", source_kpi.get("top_source", "N/A")),
            ("Source", "Top Source Old %", source_kpi.get("top_source_old_pct", 0.0)),
        ])
        mapped_pct_row = None
        for grp, metric, val in kpi_rows:
            meta_ws.write(meta_ptr, 0, grp, text_fmt)
            meta_ws.write(meta_ptr, 1, metric, text_fmt)
            if isinstance(val, (int, float, np.integer, np.floating)):
                lower_metric = str(metric).lower()
                if "%" in metric or "pct" in lower_metric or "index" in lower_metric:
                    meta_ws.write(meta_ptr, 2, float(val), dec_fmt)
                else:
                    meta_ws.write(meta_ptr, 2, int(val) if float(val).is_integer() else float(val), int_fmt if float(val).is_integer() else dec_fmt)
            else:
                meta_ws.write(meta_ptr, 2, str(val), text_fmt)
            if metric == "Mapped Source %":
                mapped_pct_row = meta_ptr
            meta_ptr += 1

        meta_ptr += 1
        meta_ws.write(meta_ptr, 0, "Decision Notes", section_fmt)
        meta_ptr += 1
        notes = payload.get("decision_notes") or []
        if notes:
            for note in notes:
                meta_ws.write(meta_ptr, 0, str(note), trace_fmt)
                meta_ptr += 1
        else:
            meta_ws.write(meta_ptr, 0, "No decision notes available.", trace_fmt)
            meta_ptr += 1

        meta_ptr += 1
        meta_ws.write(meta_ptr, 0, "Backend Trace", section_fmt)
        meta_ptr += 1
        meta_ws.write_row(meta_ptr, 0, ["Step", "Status", "Details"], header_fmt)
        meta_ptr += 1
        for tr in (payload.get("trace") or []):
            step = str(tr.get("step") or "")
            status_val = str(tr.get("status") or "")
            detail_map = {k: v for k, v in tr.items() if k not in {"step", "status"}}
            detail_txt = json.dumps(detail_map, ensure_ascii=True)
            meta_ws.write(meta_ptr, 0, step, trace_fmt)
            meta_ws.write(meta_ptr, 1, status_val, trace_fmt)
            meta_ws.write(meta_ptr, 2, detail_txt, trace_fmt)
            meta_ptr += 1

        meta_ws.set_column(0, 0, 22, blank_fmt)
        meta_ws.set_column(1, 1, 26, blank_fmt)
        meta_ws.set_column(2, 2, 70, blank_fmt)
        meta_ws.set_column(3, 4, 18, blank_fmt)
        meta_ws.freeze_panes(6, 0)

        if mapped_pct_row is not None:
            meta_ws.conditional_format(
                mapped_pct_row,
                2,
                mapped_pct_row,
                2,
                {
                    "type": "3_color_scale",
                    "min_type": "num",
                    "min_value": 0,
                    "mid_type": "num",
                    "mid_value": 60,
                    "max_type": "num",
                    "max_value": 100,
                },
            )

        def _write_data_sheet(sheet_name: str, sheet_title: str, df: pd.DataFrame):
            local_df = df.copy() if df is not None else pd.DataFrame()
            if local_df is None:
                local_df = pd.DataFrame()
            if local_df.empty:
                ws = workbook.add_worksheet(sheet_name)
                writer.sheets[sheet_name] = ws
                ws.merge_range(0, 0, 0, 2, sheet_title, title_fmt)
                ws.merge_range(1, 0, 1, 2, f"Unit: {unit_header} | Visit Type: {visit_label}", subtitle_fmt)
                ws.merge_range(2, 0, 2, 2, f"Date Range: {from_date} to {to_date}", subtitle_fmt)
                ws.merge_range(3, 0, 3, 2, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)
                ws.write(5, 0, "No data available for selected filters.", section_fmt)
                ws.set_column(0, 2, 36)
                return

            local_df.to_excel(writer, sheet_name=sheet_name, index=False, startrow=5)
            ws = writer.sheets[sheet_name]
            last_col = len(local_df.columns) - 1
            ws.merge_range(0, 0, 0, last_col, sheet_title, title_fmt)
            ws.merge_range(1, 0, 1, last_col, f"Unit: {unit_header} | Visit Type: {visit_label}", subtitle_fmt)
            ws.merge_range(2, 0, 2, last_col, f"Date Range: {from_date} to {to_date}", subtitle_fmt)
            ws.merge_range(3, 0, 3, last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)

            for col_idx, col_name in enumerate(local_df.columns):
                ws.write(5, col_idx, col_name, header_fmt)
                col_series = local_df[col_name]
                col_width = max(
                    len(str(col_name)),
                    int(col_series.astype(str).replace({"nan": ""}).str.len().max() if len(col_series) else len(str(col_name))),
                ) + 2
                col_width = min(max(col_width, 10), 44)

                fmt = text_col_fmt
                if pd.api.types.is_numeric_dtype(col_series):
                    col_key = str(col_name).strip().lower()
                    if col_key in {"visit_id", "visitid"}:
                        fmt = visitid_col_fmt
                    elif str(col_name).lower().endswith("pct") or "%" in str(col_name).lower() or "share" in str(col_name).lower():
                        fmt = dec_col_fmt
                    else:
                        # Keep integral-looking numeric columns as integer.
                        as_num = pd.to_numeric(col_series, errors="coerce")
                        is_int_like = bool(((as_num.dropna() % 1) == 0).all()) if not as_num.dropna().empty else True
                        fmt = int_col_fmt if is_int_like else dec_col_fmt
                elif "date" in str(col_name).lower():
                    fmt = date_col_fmt
                    col_width = max(col_width, 12)
                ws.set_column(col_idx, col_idx, col_width, fmt)

            data_start = 6
            data_end = 5 + len(local_df)
            ws.autofilter(5, 0, data_end, last_col)
            ws.freeze_panes(6, 0)

            if len(local_df) > 0:
                from xlsxwriter.utility import xl_col_to_name

                top_row = data_start + 1
                last_col_letter = xl_col_to_name(last_col)
                criteria = f"=COUNTA($A{top_row}:${last_col_letter}{top_row})>0"
                ws.conditional_format(
                    data_start,
                    0,
                    data_end,
                    last_col,
                    {
                        "type": "formula",
                        "criteria": criteria,
                        "format": row_border_fmt,
                    },
                )

            pct_col_indices = [
                idx for idx, col in enumerate(local_df.columns)
                if str(col).lower().endswith("pct") or "%" in str(col).lower() or "share" in str(col).lower()
            ]
            for idx in pct_col_indices:
                ws.conditional_format(
                    data_start,
                    idx,
                    data_end,
                    idx,
                    {
                        "type": "3_color_scale",
                        "min_type": "num",
                        "min_value": 0,
                        "mid_type": "num",
                        "mid_value": 50,
                        "max_type": "num",
                        "max_value": 100,
                    },
                )

        _write_data_sheet("Summary_Dept", "Old vs New Visits - Department Summary", summary_df)
        _write_data_sheet("Details_Visits", "Old vs New Visits - Detail Rows", detail_df)
        for section in conversion_sections:
            _write_data_sheet(
                str(section.get("sheet_name") or "Details")[:31],
                str(section.get("title") or "Visit Details"),
                section.get("df"),
            )
        _write_data_sheet("Source_Comparison", "Patient Source Comparison", source_summary_df)
        _write_data_sheet("Source_x_Dept", "Patient Source x Department", source_dept_df)
        _write_data_sheet("Source_x_Doctor", "Patient Source x Doctor", source_doc_df)

    output.seek(0)
    filename = f"Old_New_Patient_Visits_{unit}_{from_date}_to_{to_date}_VT{visit_type_id}.xlsx"
    return output.getvalue(), filename, None


def _run_old_new_patient_visits_excel_job(
    job_id: str,
    unit: str,
    from_date: str,
    to_date: str,
    visit_type_id: int,
    exported_by: str,
):
    _excel_job_update(job_id, state="running")
    try:
        data, filename, err = _build_old_new_patient_visits_excel(
            unit=unit,
            from_date=from_date,
            to_date=to_date,
            visit_type_id=visit_type_id,
            exported_by=exported_by,
        )
        if not data:
            _excel_job_update(job_id, state="error", error=err or "No data available to export")
            return
        _export_cache_put_bytes("old_new_patient_visits_xlsx_job", data, job_id)
        _excel_job_update(job_id, state="done", filename=filename)
    except Exception as exc:
        _excel_job_update(job_id, state="error", error=str(exc))


@app.route('/api/mis/old_new_patient_visits/export_excel_job', methods=["POST"])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_old_new_patient_visits_export_excel_job():
    payload = request.get_json(silent=True) or {}
    unit_raw = payload.get("unit") or request.args.get("unit")
    from_raw = payload.get("from") or payload.get("from_date") or request.args.get("from")
    to_raw = payload.get("to") or payload.get("to_date") or request.args.get("to")
    visit_type_raw = payload.get("visit_type_id") or request.args.get("visit_type_id")

    params, err, status_code = _old_new_validate_request_params(unit_raw, from_raw, to_raw, visit_type_raw)
    if err:
        return jsonify({"status": "error", "message": err}), status_code

    exported_by = session.get("username") or session.get("user") or "Unknown"
    job_id = token_hex(16)
    _excel_job_update(job_id, state="queued", filename=None)
    EXPORT_EXECUTOR.submit(
        _run_old_new_patient_visits_excel_job,
        job_id,
        params["unit"],
        params["from_date"],
        params["to_date"],
        params["visit_type_id"],
        exported_by,
    )
    return jsonify({"status": "queued", "job_id": job_id})


@app.route('/api/mis/old_new_patient_visits/export_excel_job_status')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_old_new_patient_visits_export_excel_job_status():
    job_id = (request.args.get("job_id") or "").strip()
    if not job_id:
        return jsonify({"status": "error", "message": "Missing job id"}), 400
    entry = _excel_job_get(job_id)
    if not entry:
        return jsonify({"status": "error", "message": "Job not found"}), 404
    return jsonify({
        "status": "success",
        "state": entry.get("state"),
        "error": entry.get("error"),
        "filename": entry.get("filename"),
    })


@app.route('/api/mis/old_new_patient_visits/export_excel_job_result')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_old_new_patient_visits_export_excel_job_result():
    job_id = (request.args.get("job_id") or "").strip()
    if not job_id:
        return "Missing job id", 400
    entry = _excel_job_get(job_id)
    if not entry:
        return "Job not found", 404
    if entry.get("state") != "done":
        return "Job not ready", 409
    data = _export_cache_get_bytes("old_new_patient_visits_xlsx_job", job_id)
    if not data:
        return "Export expired", 404
    filename = entry.get("filename") or "Old_New_Patient_Visits.xlsx"
    return send_file(
        io.BytesIO(data),
        as_attachment=True,
        download_name=filename,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )


def _build_old_new_patient_visits_pdf_buffer(
    unit: str,
    from_date: str,
    to_date: str,
    visit_type_id: int,
    exported_by: str,
):
    from reportlab.lib.pagesizes import A4, landscape
    from reportlab.lib import colors
    from reportlab.lib.units import mm
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer, PageBreak, Image
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_RIGHT
    from xml.sax.saxutils import escape

    payload, err, status_code = _build_old_new_patient_visits_payload(unit, visit_type_id, from_date, to_date)
    if err or not payload or not payload.get("has_data"):
        return None

    summary_df, detail_df, source_summary_df, source_dept_df, source_doc_df, conversion_sections = _old_new_payload_to_frames(payload)
    visit_label = payload.get("visit_type_label") or _old_new_visit_type_label(visit_type_id)
    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    unit_header = _lab_unit_header_text(unit)

    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=landscape(A4),
        topMargin=10 * mm,
        bottomMargin=12 * mm,
        leftMargin=6 * mm,
        rightMargin=6 * mm,
    )

    styles = getSampleStyleSheet()
    style_title = ParagraphStyle(
        "OldNewTitle",
        parent=styles["Heading2"],
        alignment=TA_CENTER,
        textColor=colors.HexColor("#1e3a8a"),
        fontSize=13,
    )
    style_sub = ParagraphStyle(
        "OldNewSub",
        parent=styles["Normal"],
        alignment=TA_CENTER,
        textColor=colors.HexColor("#475569"),
        fontSize=9,
    )
    style_note = ParagraphStyle(
        "OldNewNote",
        parent=styles["Normal"],
        alignment=TA_LEFT,
        textColor=colors.HexColor("#334155"),
        fontSize=8,
        leading=10,
    )
    style_h = ParagraphStyle(
        "OldNewH",
        parent=styles["Heading4"],
        alignment=TA_LEFT,
        textColor=colors.HexColor("#0f172a"),
        fontSize=10,
    )
    style_th = ParagraphStyle("OldNewTH", parent=styles["Normal"], alignment=TA_CENTER, textColor=colors.white, fontSize=7.5)
    style_td = ParagraphStyle(
        "OldNewTD",
        parent=styles["Normal"],
        alignment=TA_LEFT,
        textColor=colors.black,
        fontSize=6.6,
        leading=7.4,
        splitLongWords=False,
    )
    style_td_right = ParagraphStyle(
        "OldNewTDR",
        parent=styles["Normal"],
        alignment=TA_RIGHT,
        textColor=colors.black,
        fontSize=6.6,
        leading=7.4,
        splitLongWords=False,
    )

    def _fmt_cell(col_name: str, value):
        if value is None or (isinstance(value, float) and np.isnan(value)):
            return ""
        col_key = str(col_name).strip().lower()
        if col_key in {"visit_id", "visitid"}:
            try:
                return str(int(float(value)))
            except Exception:
                return str(value)
        if isinstance(value, (np.integer, int)):
            return f"{int(value):,}"
        if isinstance(value, (np.floating, float)):
            if "pct" in col_key or "%" in col_key or "share" in col_key:
                return f"{float(value):,.2f}%"
            if float(value).is_integer():
                return f"{int(value):,}"
            return f"{float(value):,.2f}"
        return str(value)

    def _table_from_df(
        df: pd.DataFrame,
        columns: list[str],
        headers: list[str],
        col_widths_mm: list[float],
        numeric_cols: set[int] | None = None,
    ):
        numeric_cols = numeric_cols or set()
        rows = [[Paragraph(escape(h), style_th) for h in headers]]
        if df is None or df.empty:
            rows.append([Paragraph("No data", style_td)] + [Paragraph("", style_td) for _ in range(len(columns) - 1)])
        else:
            for _, row in df.iterrows():
                row_cells = []
                for idx, col in enumerate(columns):
                    txt = _fmt_cell(col, row.get(col))
                    cell_style = style_td_right if idx in numeric_cols else style_td
                    row_cells.append(Paragraph(escape(txt), cell_style))
                rows.append(row_cells)

        table = Table(rows, colWidths=[w * mm for w in col_widths_mm], repeatRows=1)
        style_cmds = [
            ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
            ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
            ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
            ("GRID", (0, 0), (-1, -1), 0.35, colors.HexColor("#1f2937")),
            ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
            ("ALIGN", (0, 0), (-1, 0), "CENTER"),
            ("ALIGN", (0, 1), (-1, -1), "LEFT"),
            ("ROWBACKGROUNDS", (0, 1), (-1, -1), [colors.white, colors.HexColor("#f8fafc")]),
        ]
        for idx in sorted(numeric_cols):
            style_cmds.append(("ALIGN", (idx, 1), (idx, -1), "RIGHT"))
        table.setStyle(TableStyle(style_cmds))
        return table

    story = []
    logo_path = os.path.join(app.root_path, "static", "logo", "asarfi.png")
    if os.path.exists(logo_path):
        logo = Image(logo_path, width=18 * mm, height=18 * mm, mask="auto")
        logo.hAlign = "CENTER"
        story.append(logo)

    story.append(Spacer(1, 4))
    story.append(Paragraph("MIS Marketing - Old vs New Patient Visits", style_title))
    story.append(Paragraph(f"Unit: {unit_header}", style_sub))
    story.append(Paragraph(f"Visit Type: {visit_label} (ID: {visit_type_id})", style_sub))
    story.append(Paragraph(f"Date Range: {from_date} to {to_date}", style_sub))
    story.append(Paragraph(f"Exported By: {exported_by} | Exported At: {exported_at}", style_sub))
    story.append(Spacer(1, 10))
    story.append(Paragraph("This report is section-wise paginated for print-friendly page references.", style_note))

    k = payload.get("kpis") or {}
    s = k.get("summary") or {}
    d = k.get("details") or {}
    src = k.get("source") or {}
    summary_extra_defs = payload.get("summary_extra_columns") or []

    story.append(Paragraph("KPI Summary", style_h))
    story.append(Spacer(1, 3))
    kpi_rows = [
        [Paragraph("KPI Group", style_th), Paragraph("Metric", style_th), Paragraph("Value", style_th)],
        [Paragraph("Summary", style_td), Paragraph("Total Visits", style_td), Paragraph(_fmt_cell("TotalVisits", s.get("total_visits", 0)), style_td_right)],
        [Paragraph("Summary", style_td), Paragraph("New Visits", style_td), Paragraph(_fmt_cell("NewVisits", s.get("new_visits", 0)), style_td_right)],
        [Paragraph("Summary", style_td), Paragraph("Old Visits", style_td), Paragraph(_fmt_cell("OldVisits", s.get("old_visits", 0)), style_td_right)],
        [Paragraph("Summary", style_td), Paragraph("New %", style_td), Paragraph(_fmt_cell("NewPct", s.get("new_pct", 0.0)), style_td_right)],
        [Paragraph("Summary", style_td), Paragraph("Old %", style_td), Paragraph(_fmt_cell("OldPct", s.get("old_pct", 0.0)), style_td_right)],
        [Paragraph("Summary", style_td), Paragraph("Department Count", style_td), Paragraph(_fmt_cell("DepartmentCount", s.get("department_count", 0)), style_td_right)],
    ]
    for item in summary_extra_defs:
        kpi_rows.append([
            Paragraph("Summary", style_td),
            Paragraph(escape(str(item.get("kpi_label") or item.get("label") or "Extra Summary Metric")), style_td),
            Paragraph(_fmt_cell(str(item.get("kpi_key") or ""), s.get(str(item.get("kpi_key") or ""), 0)), style_td_right),
        ])
    kpi_rows.extend([
        [Paragraph("Details", style_td), Paragraph("Detail Rows", style_td), Paragraph(_fmt_cell("Rows", d.get("detail_rows", 0)), style_td_right)],
        [Paragraph("Details", style_td), Paragraph("Unique Patients", style_td), Paragraph(_fmt_cell("UniquePatients", d.get("unique_patients", 0)), style_td_right)],
        [Paragraph("Details", style_td), Paragraph("Unique Doctors", style_td), Paragraph(_fmt_cell("UniqueDoctors", d.get("unique_doctors", 0)), style_td_right)],
        [Paragraph("Details", style_td), Paragraph("Old % Loyalty Index", style_td), Paragraph(_fmt_cell("OldPct", d.get("old_pct_loyalty_index", 0.0)), style_td_right)],
        [Paragraph("Source", style_td), Paragraph("Mapped Source %", style_td), Paragraph(_fmt_cell("MappedPct", src.get("mapped_pct", 0.0)), style_td_right)],
        [Paragraph("Source", style_td), Paragraph("Unmapped Count", style_td), Paragraph(_fmt_cell("Unmapped", src.get("unmapped_count", 0)), style_td_right)],
        [Paragraph("Source", style_td), Paragraph("Top Source", style_td), Paragraph(escape(str(src.get("top_source", "N/A"))), style_td)],
        [Paragraph("Source", style_td), Paragraph("Top Source Old %", style_td), Paragraph(_fmt_cell("TopOldPct", src.get("top_source_old_pct", 0.0)), style_td_right)],
    ])
    kpi_tbl = Table(kpi_rows, colWidths=[42 * mm, 135 * mm, 42 * mm], repeatRows=1)
    kpi_tbl.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("GRID", (0, 0), (-1, -1), 0.35, colors.HexColor("#1f2937")),
        ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
        ("ALIGN", (2, 1), (2, -1), "RIGHT"),
        ("ROWBACKGROUNDS", (0, 1), (-1, -1), [colors.white, colors.HexColor("#f8fafc")]),
    ]))
    story.append(kpi_tbl)
    story.append(PageBreak())

    story.append(Paragraph("Department Summary", style_h))
    story.append(Spacer(1, 3))
    summary_columns = ["Dept", "TotalVisits", "NewPatientVisits", "OldPatientVisits", "NewPct", "OldPct"]
    summary_headers = ["Department", "Total", "New", "Old", "New %", "Old %"]
    summary_widths = [88, 22, 22, 22, 24, 24]
    summary_numeric_cols = {1, 2, 3, 4, 5}
    for item in summary_extra_defs:
        summary_columns.append(str(item.get("key") or ""))
        summary_headers.append(str(item.get("label") or item.get("key") or "Extra"))
        summary_widths.append(26 if len(summary_extra_defs) <= 1 else 24)
        summary_numeric_cols.add(len(summary_columns) - 1)
    dept_table = _table_from_df(
        summary_df,
        columns=summary_columns,
        headers=summary_headers,
        col_widths_mm=summary_widths,
        numeric_cols=summary_numeric_cols,
    )
    story.append(dept_table)
    story.append(PageBreak())

    detail_cap_df = detail_df.head(OLD_NEW_PDF_DETAILS_CAP).copy()
    detail_capped = len(detail_df) > len(detail_cap_df)
    story.append(Paragraph("Visit Details", style_h))
    if detail_capped:
        story.append(Paragraph(
            f"Showing first {OLD_NEW_PDF_DETAILS_CAP:,} rows out of {len(detail_df):,}. Full rows are available in Excel export.",
            style_note,
        ))
    else:
        story.append(Paragraph(f"Total rows: {len(detail_df):,}", style_note))
    story.append(Spacer(1, 4))
    detail_table = _table_from_df(
        detail_cap_df,
        columns=["VisitDate", "Visit_ID", "RegNo", "PatientName", "Dept", "SubDept", "Doctor", "PatientType", "SourceName"],
        headers=["Visit Date", "Visit ID", "Reg No", "Patient", "Dept", "SubDept", "Doctor", "Type", "Source"],
        col_widths_mm=[24, 22, 24, 58, 34, 30, 38, 18, 34],
        numeric_cols={1},
    )
    story.append(detail_table)
    if conversion_sections:
        story.append(PageBreak())
        for section_idx, section in enumerate(conversion_sections):
            sec_df = (section.get("df") if isinstance(section, dict) else None)
            sec_df = sec_df.copy() if isinstance(sec_df, pd.DataFrame) else pd.DataFrame(columns=detail_df.columns)
            sec_cap_df = sec_df.head(OLD_NEW_PDF_DETAILS_CAP).copy()
            sec_capped = len(sec_df) > len(sec_cap_df)
            story.append(Paragraph(str(section.get("title") or "Visit Details"), style_h))
            if sec_capped:
                story.append(Paragraph(
                    f"Showing first {OLD_NEW_PDF_DETAILS_CAP:,} rows out of {len(sec_df):,}. Full rows are available in Excel export.",
                    style_note,
                ))
            else:
                story.append(Paragraph(f"Total rows: {len(sec_df):,}", style_note))
            story.append(Spacer(1, 4))
            story.append(_table_from_df(
                sec_cap_df,
                columns=["VisitDate", "Visit_ID", "RegNo", "PatientName", "Dept", "SubDept", "Doctor", "PatientType", "SourceName"],
                headers=["Visit Date", "Visit ID", "Reg No", "Patient", "Dept", "SubDept", "Doctor", "Type", "Source"],
                col_widths_mm=[24, 22, 24, 58, 34, 30, 38, 18, 34],
                numeric_cols={1},
            ))
            if section_idx < len(conversion_sections) - 1:
                story.append(PageBreak())
        story.append(PageBreak())
    else:
        story.append(PageBreak())

    story.append(Paragraph("Patient Source Comparison", style_h))
    story.append(Spacer(1, 3))
    source_summary_table = _table_from_df(
        source_summary_df,
        columns=["SourceID", "SourceName", "TotalVisits", "NewVisits", "OldVisits", "VisitSharePct", "OldPct", "UniquePatients", "UniqueDoctors", "UniqueDepartments"],
        headers=["Source ID", "Source", "Total", "New", "Old", "Share %", "Old %", "Patients", "Doctors", "Depts"],
        col_widths_mm=[20, 52, 20, 18, 18, 24, 22, 28, 28, 28],
        numeric_cols={0, 2, 3, 4, 5, 6, 7, 8, 9},
    )
    story.append(source_summary_table)
    story.append(PageBreak())

    source_dept_cap_df = source_dept_df.head(OLD_NEW_PDF_SOURCE_DEPT_CAP).copy()
    source_dept_capped = len(source_dept_df) > len(source_dept_cap_df)
    story.append(Paragraph("Patient Source x Department", style_h))
    if source_dept_capped:
        story.append(Paragraph(
            f"Showing first {OLD_NEW_PDF_SOURCE_DEPT_CAP:,} rows out of {len(source_dept_df):,}. Full rows are available in Excel export.",
            style_note,
        ))
    else:
        story.append(Paragraph(f"Total rows: {len(source_dept_df):,}", style_note))
    story.append(Spacer(1, 3))
    source_dept_table = _table_from_df(
        source_dept_cap_df,
        columns=["SourceID", "SourceName", "Dept", "TotalVisits", "NewVisits", "OldVisits", "ShareWithinSourcePct", "OldPct"],
        headers=["Source ID", "Source", "Dept", "Total", "New", "Old", "Share %", "Old %"],
        col_widths_mm=[20, 52, 74, 24, 20, 20, 30, 24],
        numeric_cols={0, 3, 4, 5, 6, 7},
    )
    story.append(source_dept_table)
    story.append(PageBreak())

    source_doc_cap_df = source_doc_df.head(OLD_NEW_PDF_SOURCE_DOCTOR_CAP).copy()
    source_doc_capped = len(source_doc_df) > len(source_doc_cap_df)
    story.append(Paragraph("Patient Source x Doctor", style_h))
    if source_doc_capped:
        story.append(Paragraph(
            f"Showing first {OLD_NEW_PDF_SOURCE_DOCTOR_CAP:,} rows out of {len(source_doc_df):,}. Full rows are available in Excel export.",
            style_note,
        ))
    else:
        story.append(Paragraph(f"Total rows: {len(source_doc_df):,}", style_note))
    story.append(Spacer(1, 3))
    source_doc_table = _table_from_df(
        source_doc_cap_df,
        columns=["SourceID", "SourceName", "Dept", "SubDept", "Doctor", "TotalVisits", "NewVisits", "OldVisits", "ShareWithinSourcePct", "OldPct"],
        headers=["Source ID", "Source", "Dept", "SubDept", "Doctor", "Total", "New", "Old", "Share %", "Old %"],
        col_widths_mm=[16, 34, 40, 32, 46, 20, 18, 18, 24, 20],
        numeric_cols={0, 5, 6, 7, 8, 9},
    )
    story.append(source_doc_table)

    footer_left = f"Date Range: {from_date} to {to_date} | Unit: {unit} | Visit Type: {visit_label}"
    footer_right_base = f"Exported By: {exported_by} | Exported At: {exported_at}"

    def _draw_footer(canvas, doc_obj):
        canvas.saveState()
        width, _ = doc.pagesize
        canvas.setFont("Helvetica", 7.5)
        canvas.setFillColor(colors.HexColor("#64748b"))
        canvas.drawString(6 * mm, 8 * mm, footer_left[:130])
        canvas.drawRightString(width - 6 * mm, 8 * mm, f"{footer_right_base} | Page {doc_obj.page}")
        canvas.restoreState()

    doc.build(story, onFirstPage=_draw_footer, onLaterPages=_draw_footer)
    buffer.seek(0)
    return buffer


@app.route('/api/mis/old_new_patient_visits/export_pdf')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_old_new_patient_visits_export_pdf():
    params, err, status_code = _old_new_validate_request_params(
        request.args.get("unit"),
        request.args.get("from"),
        request.args.get("to"),
        request.args.get("visit_type_id"),
    )
    if err:
        return err, status_code

    exported_by = session.get("username") or session.get("user") or "Unknown"
    buffer = _build_old_new_patient_visits_pdf_buffer(
        params["unit"],
        params["from_date"],
        params["to_date"],
        params["visit_type_id"],
        exported_by,
    )
    if buffer is None:
        return "No data available to export", 404
    filename = f"Old_New_Patient_Visits_{params['unit']}_{params['from_date']}_to_{params['to_date']}_VT{params['visit_type_id']}.pdf"
    return send_file(buffer, mimetype="application/pdf", as_attachment=True, download_name=filename)


# ============================================================
# MIS: Pharmacy Current Stock (Store-wise)
# ============================================================
@app.route('/api/mis/pharmacy/stores')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_pharmacy_stores():
    unit = (request.args.get("unit") or "").strip().upper()
    allowed_units = _allowed_units_for_session()
    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return jsonify({"status": "error", "message": "Please select a unit"}), 400
    if unit not in allowed_units:
        return jsonify({"status": "error", "message": f"Unit {unit} not permitted"}), 403

    df = data_fetch.fetch_pharmacy_stores(unit)
    if df is None:
        return jsonify({"status": "error", "message": "Failed to fetch stores"}), 500
    if df.empty:
        return jsonify({"status": "success", "unit": unit, "stores": []})

    df = _clean_df_columns(df)
    cols_map = {str(c).strip().lower(): c for c in df.columns}
    id_col = cols_map.get("id") or cols_map.get("storeid") or cols_map.get("store_id")
    name_col = cols_map.get("name") or cols_map.get("storename") or cols_map.get("store_name")
    if not id_col:
        return jsonify({"status": "error", "message": "Store id column missing"}), 500

    stores = []
    for _, row in df.iterrows():
        sid = row.get(id_col)
        if sid is None:
            continue
        try:
            sid = int(sid)
        except Exception:
            continue
        sname = str(row.get(name_col) or "").strip() if name_col else ""
        stores.append({"id": sid, "name": sname})

    stores = sorted(stores, key=lambda s: (s["name"] or "", s["id"]))
    return jsonify({"status": "success", "unit": unit, "stores": stores})


@app.route('/api/mis/pharmacy/stock_snapshot_dates')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_pharmacy_stock_snapshot_dates():
    unit = (request.args.get("unit") or "").strip().upper()
    store_id_raw = (request.args.get("store_id") or "").strip()
    allowed_units = _allowed_units_for_session()

    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return jsonify({"status": "error", "message": "Please select a unit"}), 400
    if unit not in allowed_units:
        return jsonify({"status": "error", "message": f"Unit {unit} not permitted"}), 403

    store_id = None
    if store_id_raw:
        try:
            store_id = int(store_id_raw)
        except Exception:
            return jsonify({"status": "error", "message": "Invalid store id"}), 400

    _ensure_pharmacy_stock_snapshot_table()
    try:
        with _connect_local_db() as conn:
            if store_id is not None:
                rows = conn.execute(
                    """
                    SELECT DISTINCT snapshot_date
                    FROM pharmacy_stock_snapshot
                    WHERE unit=? AND store_id=?
                    ORDER BY snapshot_date DESC
                    """,
                    (unit, store_id),
                ).fetchall()
            else:
                rows = conn.execute(
                    """
                    SELECT DISTINCT snapshot_date
                    FROM pharmacy_stock_snapshot
                    WHERE unit=?
                    ORDER BY snapshot_date DESC
                    """,
                    (unit,),
                ).fetchall()
        dates = [r[0] for r in rows if r and r[0]]
    except Exception as e:
        return jsonify({"status": "error", "message": f"Failed to load snapshot dates: {e}"}), 500

    payload = {"status": "success", "unit": unit, "dates": dates}
    if store_id is not None:
        payload["store_id"] = store_id
    return jsonify(payload)


