@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_pharmacy_non_moving():
    unit = (request.args.get("unit") or "").strip().upper()
    store_id_raw = (request.args.get("store_id") or request.args.get("store") or "").strip()
    allowed_units = _allowed_units_for_session()

    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return jsonify({"status": "error", "message": "Please select a unit"}), 400
    if unit not in allowed_units:
        return jsonify({"status": "error", "message": f"Unit {unit} not permitted"}), 403

    if not store_id_raw:
        return jsonify({"status": "error", "message": "Please select a store"}), 400
    try:
        store_id = int(store_id_raw)
    except Exception:
        return jsonify({"status": "error", "message": "Invalid store id"}), 400
    if store_id not in {2, 3}:
        return jsonify({"status": "error", "message": "Invalid store id"}), 400

    df = data_fetch.fetch_pharmacy_non_moving_items(unit, store_id)
    if df is None:
        return jsonify({"status": "error", "message": "Failed to fetch non-moving items"}), 500
    if df.empty:
        return jsonify({"status": "success", "unit": unit, "rows": [], "count": 0})

    df = _clean_df_columns(df)
    store_label = "OPD" if store_id == 2 else "IPD"
    if "StoreName" not in df.columns:
        df["StoreName"] = store_label
    else:
        df["StoreName"] = df["StoreName"].fillna(store_label)

    for col in ["NearestExpiryDate", "LastInwardDate"]:
        if col in df.columns:
            df[col] = pd.to_datetime(df[col], errors="coerce").dt.strftime("%Y-%m-%d")

    df = df.replace({np.nan: None, np.inf: None, -np.inf: None})
    rows = _sanitize_json_payload(df.to_dict(orient="records"))
    return jsonify({
        "status": "success",
        "unit": unit,
        "rows": rows,
        "count": len(rows),
    })


# ============================================================
# MIS: Pharmacy Product Margin
# ============================================================
def _margin_statement_store_id_for_source(source: str | None) -> int | None:
    source_key = (source or "").strip().lower()
    if source_key == "sale":
        return 2
    if source_key == "issue":
        return 3
    return None


def _build_margin_period_qty_lookup(
    unit: str,
    from_date: str,
    to_date: str,
    store_id: int,
    name_to_item_id: dict | None = None,
) -> tuple[dict[int, dict[str, float]], dict[str, dict[str, float]]]:
    by_item_id: dict[int, dict[str, float]] = {}
    by_name_key: dict[str, dict[str, float]] = {}
    if not store_id:
        return by_item_id, by_name_key
    try:
        stmt_df, _ = _build_pharmacy_current_stock_statement_df(unit, store_id, from_date, to_date)
    except Exception:
        return by_item_id, by_name_key
    if stmt_df is None or stmt_df.empty:
        return by_item_id, by_name_key

    work = _clean_df_columns(stmt_df).copy()
    if "ItemName" not in work.columns:
        return by_item_id, by_name_key
    if "PurchaseQty" not in work.columns:
        work["PurchaseQty"] = 0.0
    if "ClosingQty" not in work.columns:
        work["ClosingQty"] = 0.0

    work["__name_key"] = work["ItemName"].apply(_norm_key)
    work = work[work["__name_key"].notna() & (work["__name_key"].astype(str) != "")]
    if work.empty:
        return by_item_id, by_name_key

    work["PurchaseQty"] = pd.to_numeric(work["PurchaseQty"], errors="coerce").fillna(0.0)
    work["ClosingQty"] = pd.to_numeric(work["ClosingQty"], errors="coerce").fillna(0.0)
    work = (
        work.groupby("__name_key", dropna=False, as_index=False)
        .agg(
            PurchaseQty=("PurchaseQty", "sum"),
            ClosingQty=("ClosingQty", "sum"),
        )
    )

    if not isinstance(name_to_item_id, dict):
        name_to_item_id = _item_name_map_for_unit(unit)

    for _, row in work.iterrows():
        name_key = str(row.get("__name_key") or "")
        if not name_key:
            continue
        metrics = {
            "period_purchase_qty": float(row.get("PurchaseQty") or 0.0),
            "period_closing_qty": float(row.get("ClosingQty") or 0.0),
        }
        by_name_key[name_key] = metrics
        item_id = _safe_int((name_to_item_id or {}).get(name_key), 0)
        if item_id and item_id not in by_item_id:
            by_item_id[item_id] = metrics
    return by_item_id, by_name_key


def _enrich_product_margin_df_with_period_qty(
    unit: str,
    from_date: str,
    to_date: str,
    df: pd.DataFrame,
) -> pd.DataFrame:
    if df is None or df.empty or "_source" not in df.columns:
        return df

    cols = {str(c).strip().lower(): c for c in df.columns}
    id_col = cols.get("id") or cols.get("itemid") or cols.get("item_id")
    name_col = cols.get("name") or cols.get("itemname")

    out = df.copy()
    out["PeriodPurchaseQty"] = 0.0
    out["PeriodClosingQty"] = 0.0

    source_values = set(out["_source"].astype(str).str.strip().str.lower().tolist())
    source_keys = [src for src in ("sale", "issue") if src in source_values]
    if not source_keys:
        return out

    name_to_item_id = _item_name_map_for_unit(unit)
    source_lookups: dict[str, tuple[dict[int, dict[str, float]], dict[str, dict[str, float]]]] = {}
    for src in source_keys:
        store_id = _margin_statement_store_id_for_source(src)
        if not store_id:
            continue
        source_lookups[src] = _build_margin_period_qty_lookup(
            unit,
            from_date,
            to_date,
            store_id,
            name_to_item_id,
        )

    purchase_qty_vals = []
    closing_qty_vals = []
    for _, row in out.iterrows():
        src = str(row.get("_source") or "sale").strip().lower()
        by_item_id, by_name_key = source_lookups.get(src, ({}, {}))

        metrics = None
        item_id = _safe_int(row.get(id_col), 0) if id_col else 0
        if item_id:
            metrics = by_item_id.get(item_id)
        if metrics is None and name_col:
            name_key = _norm_key(row.get(name_col))
            if name_key:
                metrics = by_name_key.get(name_key)
        if metrics is None:
            purchase_qty_vals.append(0.0)
            closing_qty_vals.append(0.0)
            continue

        purchase_qty_vals.append(_safe_float(metrics.get("period_purchase_qty")))
        closing_qty_vals.append(_safe_float(metrics.get("period_closing_qty")))

    out["PeriodPurchaseQty"] = purchase_qty_vals
    out["PeriodClosingQty"] = closing_qty_vals
    return out


def _build_margin_rows_from_df(unit: str, df, source: str | None, need_manufacturer_id: bool = False):
    if df is None or df.empty:
        return []
    df = _clean_df_columns(df)
    manufacturer_map = None
    rows = []
    def _clean_text(value):
        if value is None:
            return ""
        try:
            if pd.isna(value):
                return ""
        except Exception:
            pass
        s = str(value).strip()
        if not s or s.lower() in {"nan", "none", "null"}:
            return ""
        return s
    for _, row in df.iterrows():
        row_data = row.to_dict()
        row_source = (source or _row_value(row_data, ["_source", "__source", "source"]) or "").strip().lower()
        if not row_source:
            row_source = "sale"
        item_name = _clean_text(_row_value(row_data, ["Name", "ItemName"]))
        if not item_name:
            continue
        manufacturer = _clean_text(_row_value(row_data, ["mn", "Manufacturer", "ManufacturerName"]))
        manufacturer_id = 0
        if need_manufacturer_id:
            manufacturer_id = _safe_int(_row_value(row_data, ["ManufacturerId", "ManufacturerID", "ManuId", "Manuid"]), 0)
            if not manufacturer_id and manufacturer:
                if manufacturer_map is None:
                    manufacturer_map = _manufacturer_name_map_for_unit(unit)
                manufacturer_id = _safe_int(manufacturer_map.get(_norm_key(manufacturer)), 0)
        med_type_id = _safe_int(_row_value(row_data, ["MedicineTypeId", "MedicineTypeID"]), 0)
        med_type_desc = _clean_text(_row_value(row_data, ["MedicineTypeDesc", "MedicineTypeDescription"]))
        rate = _safe_float(_row_value(row_data, ["Rate"]))
        mrp = _safe_float(_row_value(row_data, ["MRP"]))
        sale_qty = _safe_float(_row_value(row_data, ["itemsale", "ItemSale"]))
        purchase_value = _safe_float(_row_value(row_data, ["Expr1", "PurchaseValue", "qty", "Qty"]))
        mrp_value = _safe_float(_row_value(row_data, ["MRPvalue", "MRPValue"]))
        cur_qty = _safe_float(_row_value(row_data, ["Cur_Qty", "CurQty", "CurQty_IPD"]))
        period_purchase_qty = _safe_float(_row_value(row_data, ["PeriodPurchaseQty", "period_purchase_qty"]))
        period_closing_qty = _safe_float(_row_value(row_data, ["PeriodClosingQty", "period_closing_qty"]))
        if not cur_qty:
            cur_qty = purchase_value / rate if rate else 0.0

        if sale_qty and rate:
            purchase_value = sale_qty * rate
        elif sale_qty:
            purchase_value = 0.0
        if sale_qty and mrp:
            sale_value = sale_qty * mrp
        elif sale_qty:
            sale_value = 0.0
        else:
            sale_value = 0.0
            purchase_value = 0.0
        margin = sale_value - purchase_value
        margin_pct = (margin / purchase_value * 100.0) if purchase_value > 0 else 0.0

        item_id = _safe_int(_row_value(row_data, ["ID", "ItemId", "ItemID"]), 0)
        row_key = f"{row_source}|{item_id}" if item_id else f"{row_source}|{_norm_key(item_name)}|{med_type_id}|{_norm_key(manufacturer)}"

        rows.append({
            "row_key": row_key,
            "item_id": item_id,
            "item_name": item_name,
            "manufacturer": manufacturer,
            "manufacturer_id": manufacturer_id,
            "medicine_type_id": med_type_id,
            "medicine_type_desc": med_type_desc,
            "rate": rate,
            "mrp": mrp,
            "cur_qty": cur_qty,
            "purchase_qty_period": period_purchase_qty,
            "closing_qty_period": period_closing_qty,
            "sale_qty": sale_qty,
            "purchase_value": purchase_value,
            "sale_value": sale_value,
            "margin": margin,
            "margin_pct": margin_pct,
            "source": row_source,
        })
    return rows


def _get_product_margin_rows(
    unit: str,
    from_date: str,
    to_date: str,
    medicine_type_id: int,
    manufacturer_id: int,
    source: str,
):
    source_key = (source or "sale").strip().lower()
    if source_key not in {"sale", "issue", "both"}:
        source_key = "sale"

    rows = []
    had_error = False

    if source_key in {"sale", "both"}:
        cache_key = (unit, from_date, to_date, int(medicine_type_id or 0), "sale")
        df_sale = _margin_cache_get(cache_key)
        if df_sale is None:
            df_sale = data_fetch.fetch_pharmacy_product_margin(unit, from_date, to_date, int(medicine_type_id or 0))
            if df_sale is not None:
                _margin_cache_put(cache_key, df_sale)
        if df_sale is None:
            had_error = True
        else:
            rows.extend(_build_margin_rows_from_df(unit, df_sale, "sale", bool(manufacturer_id)))

    if source_key in {"issue", "both"}:
        cache_key = (unit, from_date, to_date, int(manufacturer_id or 0), "issue")
        df_issue = _margin_cache_get(cache_key)
        if df_issue is None:
            df_issue = data_fetch.fetch_pharmacy_issue_margin(unit, from_date, to_date, int(manufacturer_id or 0))
            if df_issue is not None:
                _margin_cache_put(cache_key, df_issue)
        if df_issue is None:
            had_error = True
        else:
            rows.extend(_build_margin_rows_from_df(unit, df_issue, "issue", bool(manufacturer_id)))

    if had_error and not rows:
        return None
    if manufacturer_id:
        rows = [
            r for r in rows
            if _safe_int(r.get("manufacturer_id")) == int(manufacturer_id)
        ]
    return rows


def _get_product_margin_df(
    unit: str,
    from_date: str,
    to_date: str,
    medicine_type_id: int,
    manufacturer_id: int,
    source: str,
):
    source_key = (source or "sale").strip().lower()
    if source_key not in {"sale", "issue", "both"}:
        source_key = "sale"

    def _margin_qty_agg(series: pd.Series) -> float:
        vals = pd.to_numeric(series, errors="coerce").dropna()
        if vals.empty:
            return 0.0
        # Some margin procedures return item qty already aggregated, repeated across many rows.
        # If qty is identical across the group, keep one value instead of multiplying it.
        if vals.nunique(dropna=True) == 1:
            return float(vals.iloc[0])
        return float(vals.sum())

    frames = []
    had_error = False

    if source_key in {"sale", "both"}:
        cache_key = (unit, from_date, to_date, int(medicine_type_id or 0), "sale")
        df_sale = _margin_cache_get(cache_key)
        if df_sale is None:
            df_sale = data_fetch.fetch_pharmacy_product_margin(unit, from_date, to_date, int(medicine_type_id or 0))
            if df_sale is not None:
                _margin_cache_put(cache_key, df_sale)
        if df_sale is None:
            had_error = True
        elif not df_sale.empty:
            df_sale = _clean_df_columns(df_sale).copy()
            df_sale["_source"] = "sale"
            frames.append(df_sale)

    if source_key in {"issue", "both"}:
        cache_key = (unit, from_date, to_date, int(manufacturer_id or 0), "issue")
        df_issue = _margin_cache_get(cache_key)
        if df_issue is None:
            df_issue = data_fetch.fetch_pharmacy_issue_margin(unit, from_date, to_date, int(manufacturer_id or 0))
            if df_issue is not None:
                _margin_cache_put(cache_key, df_issue)
        if df_issue is None:
            had_error = True
        elif not df_issue.empty:
            df_issue = _clean_df_columns(df_issue).copy()
            df_issue["_source"] = "issue"
            frames.append(df_issue)

    if had_error and not frames:
        return None
    if not frames:
        return pd.DataFrame()
    df = frames[0] if len(frames) == 1 else pd.concat(frames, ignore_index=True)

    if manufacturer_id and source_key in {"sale", "both"} and "_source" in df.columns:
        cols = {str(c).strip().lower(): c for c in df.columns}
        sale_mask = df["_source"] == "sale"
        match_mask = pd.Series(True, index=df.index)

        manuid_col = cols.get("manufacturerid") or cols.get("manuid")
        if manuid_col:
            series = pd.to_numeric(df.loc[sale_mask, manuid_col], errors="coerce").fillna(0).astype(int)
            match_mask.loc[sale_mask] = series == int(manufacturer_id)
        else:
            manuf_col = cols.get("mn") or cols.get("manufacturer") or cols.get("manufacturername")
            if manuf_col:
                manufacturer_map = _manufacturer_name_map_for_unit(unit)
                target_key = next((k for k, v in manufacturer_map.items() if int(v) == int(manufacturer_id)), None)
                if target_key:
                    series = df.loc[sale_mask, manuf_col].astype(str).str.strip().str.lower()
                    match_mask.loc[sale_mask] = series == target_key
                else:
                    match_mask.loc[sale_mask] = False
            else:
                match_mask.loc[sale_mask] = False
        df = df[match_mask]

    if source_key in {"sale", "issue", "both"} and "_source" in df.columns:
        cols = {str(c).strip().lower(): c for c in df.columns}
        if not df.empty:
            id_col = cols.get("id") or cols.get("itemid") or cols.get("item_id")
            name_col = cols.get("name") or cols.get("itemname")
            manuf_col = cols.get("mn") or cols.get("manufacturer") or cols.get("manufacturername")
            med_id_col = cols.get("medicinetypeid")
            med_desc_col = cols.get("medicinetypedesc") or cols.get("medicinetypedescription")
            rate_col = cols.get("rate")
            mrp_col = cols.get("mrp")
            itemsale_col = cols.get("itemsale")
            qty_col = cols.get("qty") or cols.get("issueqty") or cols.get("issue_qty")
            cur_qty_col = cols.get("cur_qty") or cols.get("curqty") or cols.get("curqty_ipd")

            group_cols = [c for c in ["_source", id_col, name_col, manuf_col, med_id_col, med_desc_col, rate_col, mrp_col] if c]
            agg = {}
            if itemsale_col:
                agg[itemsale_col] = _margin_qty_agg
            if qty_col:
                agg[qty_col] = _margin_qty_agg
            if cur_qty_col:
                agg[cur_qty_col] = "max"

            if group_cols and agg:
                df = df.groupby(group_cols, dropna=False, as_index=False).agg(agg)
                if not itemsale_col and qty_col:
                    df["itemsale"] = df[qty_col]

    return _enrich_product_margin_df_with_period_qty(unit, from_date, to_date, df)


@app.route('/api/mis/pharmacy/medicine_types')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_pharmacy_medicine_types():
    unit = (request.args.get("unit") or "").strip().upper()
    allowed_units = _allowed_units_for_session()
    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return jsonify({"status": "error", "message": "Please select a unit"}), 400
    if unit not in allowed_units:
        return jsonify({"status": "error", "message": f"Unit {unit} not permitted"}), 403

    df = data_fetch.fetch_medicine_types(unit)
    if df is None:
        return jsonify({"status": "error", "message": "Failed to fetch medicine types"}), 500
    if df.empty:
        return jsonify({"status": "success", "types": [], "unit": unit})

    df = _clean_df_columns(df)
    cols = {str(c).strip().lower(): c for c in df.columns}
    id_col = cols.get("medicinetypeid")
    name_col = cols.get("medicinetypedesc")
    if not id_col or not name_col:
        return jsonify({"status": "error", "message": "Medicine type columns missing"}), 500

    types = []
    for _, row in df.iterrows():
        types.append({
            "id": row.get(id_col),
            "name": str(row.get(name_col) or "").strip(),
        })
    return jsonify({"status": "success", "unit": unit, "types": _sanitize_json_payload(types)})


