@app.route('/api/mis/pharmacy/product_margin')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_pharmacy_product_margin():
    unit = (request.args.get("unit") or "").strip().upper()
    from_date = (request.args.get("from") or "").strip()
    to_date = (request.args.get("to") or "").strip()
    med_type_raw = (request.args.get("medicine_type_id") or request.args.get("manuid") or "0").strip()
    manufacturer_raw = (request.args.get("manufacturer_id") or request.args.get("manid") or "0").strip()
    source_raw = (request.args.get("source") or "sale").strip().lower()
    search = (request.args.get("q") or request.args.get("search") or "").strip()
    page_raw = (request.args.get("page") or "1").strip()
    page_size_raw = (request.args.get("page_size") or "20").strip()

    allowed_units = _allowed_units_for_session()
    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return jsonify({"status": "error", "message": "Please select a unit"}), 400
    if unit not in allowed_units:
        return jsonify({"status": "error", "message": f"Unit {unit} not permitted"}), 403
    if not from_date or not to_date:
        return jsonify({"status": "error", "message": "Please select a valid date range"}), 400

    try:
        medicine_type_id = int(med_type_raw or 0)
    except Exception:
        medicine_type_id = 0
    try:
        manufacturer_id = int(manufacturer_raw or 0)
    except Exception:
        manufacturer_id = 0
    try:
        page = max(1, int(page_raw))
    except Exception:
        page = 1
    try:
        page_size = int(page_size_raw)
    except Exception:
        page_size = 20
    page_size = min(max(page_size, 1), 200)

    df = _get_product_margin_df(unit, from_date, to_date, medicine_type_id, manufacturer_id, source_raw)
    if df is None:
        return jsonify({"status": "error", "message": "Failed to fetch product margin data"}), 500
    if df.empty:
        return jsonify({
            "status": "success",
            "unit": unit,
            "rows": [],
            "page": 1,
            "page_size": page_size,
            "total_pages": 1,
            "total_count": 0,
        })

    if search:
        q = _norm_key(search)
        cols = {str(c).strip().lower(): c for c in df.columns}
        name_col = cols.get("name") or cols.get("itemname")
        manuf_col = cols.get("mn") or cols.get("manufacturer") or cols.get("manufacturername")
        med_col = cols.get("medicinetypedesc") or cols.get("medicinetypedescription")
        source_col = cols.get("_source") or cols.get("__source") or cols.get("source")

        mask = pd.Series(False, index=df.index)
        if name_col:
            mask |= df[name_col].astype(str).str.strip().str.lower().str.contains(q, na=False)
        if manuf_col:
            mask |= df[manuf_col].astype(str).str.strip().str.lower().str.contains(q, na=False)
        if med_col:
            mask |= df[med_col].astype(str).str.strip().str.lower().str.contains(q, na=False)
        if source_col:
            mask |= df[source_col].astype(str).str.strip().str.lower().str.contains(q, na=False)
        df = df[mask]

    total_count = len(df)
    if total_count == 0:
        return jsonify({
            "status": "success",
            "unit": unit,
            "rows": [],
            "page": 1,
            "page_size": page_size,
            "total_pages": 1,
            "total_count": 0,
        })
    total_pages = max(1, math.ceil(total_count / page_size)) if page_size else 1
    page = min(page, total_pages)
    start = (page - 1) * page_size
    end = start + page_size
    page_df = df.iloc[start:end]
    page_rows = _build_margin_rows_from_df(unit, page_df, None, bool(manufacturer_id))

    if page_rows:
        missing_item_rows = [r for r in page_rows if not _safe_int(r.get("item_id")) and r.get("item_name")]
        if missing_item_rows:
            name_map = _item_name_map_for_unit(unit)
            for r in missing_item_rows:
                key = _norm_key(r.get("item_name"))
                if key and key in name_map:
                    r["item_id"] = name_map.get(key)

        try:
            start_date = datetime.strptime(from_date, "%Y-%m-%d").date()
            end_date = datetime.strptime(to_date, "%Y-%m-%d").date()
            range_days = (end_date - start_date).days + 1
            if range_days <= 0:
                range_days = 1
        except Exception:
            range_days = 1

        for r in page_rows:
            sale_qty = _safe_float(r.get("sale_qty"))
            cur_qty = _safe_float(r.get("cur_qty"))
            avg_daily_sale = sale_qty / range_days if range_days else 0.0
            avg_monthly_sale = avg_daily_sale * 30.0
            low_threshold = avg_monthly_sale * 0.30
            critical_threshold = avg_monthly_sale * 0.15
            has_avg = avg_monthly_sale > 0
            is_critical = bool(has_avg and cur_qty <= critical_threshold)
            is_low = bool(has_avg and cur_qty <= low_threshold)
            r["avg_monthly_sale"] = avg_monthly_sale
            r["low_stock_threshold"] = low_threshold
            r["critical_stock_threshold"] = critical_threshold
            r["low_stock"] = is_low
            r["critical_stock"] = is_critical

    return jsonify({
        "status": "success",
        "unit": unit,
        "rows": _sanitize_json_payload(page_rows),
        "page": page,
        "page_size": page_size,
        "total_pages": total_pages,
        "total_count": total_count,
    })


@app.route('/api/mis/pharmacy/product_margin/indent_draft', methods=['POST'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_pharmacy_product_margin_indent_draft():
    unit, error = _get_purchase_unit()
    if error:
        return error

    payload = request.get_json(silent=True) or {}
    items = payload.get("items") or []
    department_id = _safe_int(payload.get("department_id"))
    store_id = _safe_int(payload.get("store_id"))
    item_category_id = _safe_int(payload.get("item_category_id"))
    indent_date = payload.get("indent_date") or datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    from_date = payload.get("from_date") or ""
    to_date = payload.get("to_date") or ""

    if not department_id:
        return jsonify({"status": "error", "message": "Department is required"}), 400
    if not store_id:
        return jsonify({"status": "error", "message": "Store is required"}), 400
    if not item_category_id:
        return jsonify({"status": "error", "message": "Category type is required"}), 400
    if not items:
        return jsonify({"status": "error", "message": "At least one item is required"}), 400

    indent_id = _safe_int(payload.get("indent_id"))
    merge_mode = indent_id > 0
    existing_item_ids = set()
    indent_no = ""
    indent_date_for_detail = indent_date

    if merge_mode:
        mst_df = data_fetch.fetch_pm_indent_mst_other(unit, indent_id)
        if mst_df is None:
            return jsonify({"status": "error", "message": "Failed to fetch indent"}), 500
        if mst_df.empty:
            return jsonify({"status": "error", "message": "Indent not found"}), 404
        mst_df = _clean_df_columns(mst_df)
        mst_row = mst_df.iloc[0].to_dict()

        status_raw = str(_row_value(mst_row, ["Status"]) or "").strip().upper()
        if status_raw == "A":
            return jsonify({"status": "error", "message": "Authorized indents cannot be edited"}), 400
        if status_raw and status_raw not in ("D", "P"):
            return jsonify({"status": "error", "message": "Only draft indents can be merged"}), 400

        existing_department_id = _safe_int(_row_value(mst_row, ["DepartmentId", "DepartmentID"]))
        existing_store_id = _safe_int(_row_value(mst_row, ["StoreId", "StoreID"]))
        existing_category_id = _safe_int(_row_value(mst_row, ["ItemCategoryId", "ItemCategoryID", "CategoryId"]))
        if existing_department_id and department_id and existing_department_id != department_id:
            return jsonify({"status": "error", "message": "Selected department does not match the draft indent"}), 400
        if existing_store_id and store_id and existing_store_id != store_id:
            return jsonify({"status": "error", "message": "Selected store does not match the draft indent"}), 400
        if existing_category_id and item_category_id and existing_category_id != item_category_id:
            return jsonify({"status": "error", "message": "Selected category does not match the draft indent"}), 400

        indent_no = str(_row_value(mst_row, ["IndentNumber", "IndentNo", "Indent No"]) or "").strip()
        if not indent_no:
            indent_no = str(indent_id)

        indent_date_for_detail = _row_value(mst_row, ["DeliveryStartDate", "IndentDate"]) or indent_date

        existing_df = data_fetch.fetch_pm_indent_items_detail(unit, indent_id)
        if existing_df is not None and not existing_df.empty:
            existing_df = _clean_df_columns(existing_df)
            for _, row in existing_df.iterrows():
                row_dict = row.to_dict()
                existing_item_id = _safe_int(_row_value(row_dict, ["ItemID", "ItemId", "ItemID"]))
                if existing_item_id:
                    existing_item_ids.add(existing_item_id)
    else:
        now = datetime.now(tz=LOCAL_TZ)
        updated_by = _safe_int(session.get("user_id") or session.get("user") or session.get("username"), 1)
        remarks = payload.get("remarks") or f"Product Margin draft {from_date} to {to_date}".strip()

        indent_no = str(payload.get("indent_no") or "").strip()
        indent_params = {
            "pIndentid": _safe_int(payload.get("indent_id")),
            "pIndentnumber": indent_no,
            "pDepartmentid": department_id,
            "pBudgetid": _safe_int(payload.get("budget_id")),
            "pRemarks": remarks,
            "pPropindication": _safe_int(payload.get("prop_indication"), -1),
            "pIndentnature": payload.get("indent_nature") or "Normal",
            "pDeliverystartdate": indent_date,
            "pDeliveryenddate": payload.get("delivery_end") or indent_date,
            "pItemcategoryid": item_category_id,
            "pUpdatedon": now.strftime("%Y-%m-%d %H:%M:%S"),
            "pUpdatedby": updated_by,
            "pStatus": "D",
            "pAuthorisedremarks": "",
            "pAuthorisedby": 0,
            "pAuthorisedon": "1900-01-01",
            "pAuthorised": 0,
            "pProcurementId": _safe_int(payload.get("procurement_id")),
            "pStoreId": store_id,
            "pInsertedby": updated_by,
        }

        mst_result = data_fetch.add_pm_indent_mst_with_autonumber(unit, indent_params)
        if mst_result.get("error"):
            return jsonify({"status": "error", "message": mst_result["error"]}), 500

        indent_id = mst_result.get("indent_id")
        indent_no = mst_result.get("indent_no") or indent_no
        if not indent_id and indent_no:
            indent_id = data_fetch.fetch_indent_id_by_number(unit, indent_no)
        if not indent_id:
            return jsonify({"status": "error", "message": "Failed to create indent"}), 500

    detail_errors = []
    skipped_existing = []
    for item in items:
        try:
            item_id = _safe_int(item.get("item_id") or item.get("id"))
            qty = _safe_float(item.get("qty"))
            if not item_id or qty <= 0:
                continue
            if merge_mode and item_id in existing_item_ids:
                skipped_existing.append(item_id)
                continue

            rate = _safe_float(item.get("rate"))
            mrp = _safe_float(item.get("mrp"))
            tax_pct = _safe_float(item.get("tax_pct") or item.get("vat"))
            packsize_id = _safe_int(item.get("packsize_id"))

            if item_id and (packsize_id == 0 or rate == 0 or mrp == 0 or tax_pct == 0):
                detail_df = data_fetch.fetch_item_master_detail(unit, item_id)
                if detail_df is not None and not detail_df.empty:
                    detail_df = _clean_df_columns(detail_df)
                    detail_row = detail_df.iloc[0].to_dict()
                    packsize_id = packsize_id or _safe_int(_row_value(detail_row, ["PackSizeID", "PackSizeId"]))
                    rate = rate or _safe_float(_row_value(detail_row, ["StandardRate", "Standardrate"]))
                    mrp = mrp or _safe_float(_row_value(detail_row, ["SalesPrice", "Salesprice"]))
                    tax_pct = tax_pct or _safe_float(_row_value(detail_row, ["SalesTax", "Salestax"]))

            tax_amount = _safe_float(item.get("tax_amount"))
            if tax_amount == 0 and tax_pct:
                tax_amount = (rate * qty) * tax_pct / 100.0
            estimated_cost = _safe_float(item.get("estimated_cost"))
            if estimated_cost == 0:
                estimated_cost = (rate * qty) + tax_amount

            detail_params = {
                "pIndentdetailid": _safe_int(item.get("detail_id")),
                "pIndentid": int(indent_id),
                "pItemid": item_id,
                "pItemrate": rate,
                "pItemqty": qty,
                "pEstimatedcost": estimated_cost,
                "pSalestax": _safe_float(item.get("sales_tax")),
                "pExcisetax": _safe_float(item.get("excise_tax")),
                "pEscalated": _safe_int(item.get("escalated")),
                "pLandingrate": _safe_float(item.get("landing_rate")),
                "pDeliveryStartDate": indent_date_for_detail,
                "pDeliveryendDate": indent_date_for_detail,
                "pAuthoriseQty": _safe_float(item.get("authorise_qty")),
                "ppacksizeId": packsize_id,
                "pfreeqty": _safe_float(item.get("free_qty")),
                "pDiscount": _safe_float(item.get("discount")),
                "pTax": tax_pct,
                "pTaxAmount": tax_amount,
                "pVATOn": item.get("vat_on") or "M",
                "pVAT": item.get("vat_code") or "E",
                "pMRP": mrp,
                "pConsumeQty": _safe_float(item.get("consume_qty")),
                "pIssueQty": _safe_float(item.get("issue_qty")),
            }
            res = data_fetch.add_pm_indent_details(unit, detail_params)
            if res.get("error"):
                detail_errors.append(res["error"])
            elif merge_mode:
                existing_item_ids.add(item_id)
        except Exception as e:
            detail_errors.append(str(e))

    message_parts = []
    if merge_mode:
        message_parts.append(f"Indent {indent_no} updated.")
    else:
        message_parts.append(f"Indent draft created: {indent_no}.")
    if skipped_existing:
        message_parts.append(f"Skipped {len(skipped_existing)} existing items.")
    if detail_errors:
        message_parts.append("Some items failed.")
    message = " ".join(message_parts).strip()

    if detail_errors:
        return jsonify({
            "status": "partial",
            "indent_id": indent_id,
            "indent_no": indent_no,
            "message": message or "Indent created but some items failed",
            "errors": detail_errors,
            "skipped_existing": len(skipped_existing),
        }), 207

    return jsonify({
        "status": "success",
        "indent_id": indent_id,
        "indent_no": indent_no,
        "message": message,
        "skipped_existing": len(skipped_existing),
    })


@app.route('/api/mis/pharmacy/product_margin/export_excel')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_pharmacy_product_margin_export_excel():
    unit = (request.args.get("unit") or "").strip().upper()
    from_date = (request.args.get("from") or "").strip()
    to_date = (request.args.get("to") or "").strip()
    med_type_raw = (request.args.get("medicine_type_id") or request.args.get("manuid") or "0").strip()
    manufacturer_raw = (request.args.get("manufacturer_id") or request.args.get("manid") or "0").strip()
    source_raw = (request.args.get("source") or "sale").strip().lower()
    search = (request.args.get("q") or request.args.get("search") or "").strip()
    allowed_units = _allowed_units_for_session()

    if not allowed_units:
        return "No unit access assigned", 403
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return "Please select a unit", 400
    if unit not in allowed_units:
        return f"Unit {unit} not permitted", 403
    if not from_date or not to_date:
        return "Please select a valid date range", 400

    try:
        medicine_type_id = int(med_type_raw or 0)
    except Exception:
        medicine_type_id = 0
    try:
        manufacturer_id = int(manufacturer_raw or 0)
    except Exception:
        manufacturer_id = 0

    df = _get_product_margin_df(unit, from_date, to_date, medicine_type_id, manufacturer_id, source_raw)
    if df is None:
        return "Failed to load product margin data", 500
    rows = _build_margin_rows_from_df(unit, df, None, bool(manufacturer_id))
    if search:
        q = _norm_key(search)
        rows = [
            r for r in rows
            if q in _norm_key(r.get("item_name"))
            or q in _norm_key(r.get("manufacturer"))
            or q in _norm_key(r.get("medicine_type_desc"))
            or q in _norm_key(r.get("source"))
        ]
    if not rows:
        return "No data available to export", 404

    medicine_type_label = "All"
    if medicine_type_id:
        for r in rows:
            if r.get("medicine_type_desc"):
                medicine_type_label = r.get("medicine_type_desc")
                break
    manufacturer_label = "All"
    if manufacturer_id:
        for r in rows:
            if r.get("manufacturer"):
                manufacturer_label = r.get("manufacturer")
                break

    exported_by = session.get("username") or session.get("user") or "Unknown"
    try:
        data = _build_product_margin_excel_bytes(
            unit,
            from_date,
            to_date,
            medicine_type_label,
            manufacturer_label,
            source_raw,
            rows,
            exported_by,
            search,
        )
    except ValueError as exc:
        return str(exc), 400

    filename = f"Product_Margin_{unit}_{from_date}_to_{to_date}.xlsx"
    return send_file(
        io.BytesIO(data),
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        as_attachment=True,
        download_name=filename,
    )


