def _build_product_margin_pdf_buffer(
    unit: str,
    from_date: str,
    to_date: str,
    medicine_type_label: str,
    manufacturer_label: str,
    source_label: str,
    rows: list[dict],
    exported_by: str,
):
    from reportlab.lib.pagesizes import A4, landscape
    from reportlab.lib import colors
    from reportlab.lib.units import mm
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer, Image
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_RIGHT

    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=landscape(A4),
        topMargin=14 * mm,
        bottomMargin=14 * mm,
        leftMargin=12 * mm,
        rightMargin=12 * mm,
    )

    styles = getSampleStyleSheet()
    style_title = ParagraphStyle("RptTitle", parent=styles["Heading2"], fontSize=12, alignment=TA_CENTER, textColor=colors.HexColor("#1e3a8a"))
    style_sub = ParagraphStyle("RptSub", parent=styles["Normal"], fontSize=9, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_meta = ParagraphStyle("RptMeta", parent=styles["Normal"], fontSize=8, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_td = ParagraphStyle("RptTd", parent=styles["Normal"], fontSize=7, textColor=colors.black)
    style_td_right = ParagraphStyle("RptTdRight", parent=styles["Normal"], fontSize=7, textColor=colors.black, alignment=TA_RIGHT)

    elements = []

    logo_path = os.path.join(app.root_path, "static", "logo", "asarfi.png")
    if os.path.exists(logo_path):
        logo = Image(logo_path, width=18 * mm, height=18 * mm, mask='auto')
        logo.hAlign = "CENTER"
        elements.append(logo)

    elements.append(Spacer(1, 6))
    elements.append(Paragraph("Manufacturer Medicine Product Margin", style_title))
    elements.append(Paragraph(f"{from_date} to {to_date}", style_sub))
    source_title = (source_label or "sale").strip().title()
    elements.append(Paragraph(
        f"Unit: {unit} | Source: {source_title} | Medicine Type: {medicine_type_label} | Manufacturer: {manufacturer_label}",
        style_sub,
    ))
    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    elements.append(Paragraph(f"Exported By: {exported_by} | Exported At: {exported_at}", style_meta))
    elements.append(Spacer(1, 8))

    headers = [
        "Source",
        "Manufacturer",
        "Item Name",
        "Cur Qty",
        "Purchase Qty",
        "Closing Qty",
        "Sale Qty",
        "Rate",
        "MRP",
        "Purchase",
        "Sale",
        "Margin",
        "%",
    ]
    table_data = [headers]
    for r in rows:
        table_data.append([
            Paragraph(str(r.get("source") or "").title(), style_td),
            Paragraph(str(r.get("manufacturer") or ""), style_td),
            Paragraph(str(r.get("item_name") or ""), style_td),
            Paragraph(f"{_safe_float(r.get('cur_qty')):,.2f}", style_td_right),
            Paragraph(f"{_safe_float(r.get('purchase_qty_period')):,.2f}", style_td_right),
            Paragraph(f"{_safe_float(r.get('closing_qty_period')):,.2f}", style_td_right),
            Paragraph(f"{_safe_float(r.get('sale_qty')):,.2f}", style_td_right),
            Paragraph(f"{_safe_float(r.get('rate')):,.2f}", style_td_right),
            Paragraph(f"{_safe_float(r.get('mrp')):,.2f}", style_td_right),
            Paragraph(f"{_safe_float(r.get('purchase_value')):,.2f}", style_td_right),
            Paragraph(f"{_safe_float(r.get('sale_value')):,.2f}", style_td_right),
            Paragraph(f"{_safe_float(r.get('margin')):,.2f}", style_td_right),
            Paragraph(f"{_safe_float(r.get('margin_pct')):,.2f}", style_td_right),
        ])

    tbl = Table(table_data, repeatRows=1)
    tbl.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("FONTSIZE", (0, 0), (-1, -1), 7),
        ("GRID", (0, 0), (-1, -1), 0.5, colors.HexColor("#1f2937")),
        ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
        ("ALIGN", (3, 1), (-1, -1), "RIGHT"),
    ]))

    elements.append(tbl)
    elements.append(Spacer(1, 8))
    total_cur_qty = sum(_safe_float(r.get("cur_qty")) for r in rows)
    total_purchase_qty_period = sum(_safe_float(r.get("purchase_qty_period")) for r in rows)
    total_closing_qty_period = sum(_safe_float(r.get("closing_qty_period")) for r in rows)
    total_sale_qty = sum(_safe_float(r.get("sale_qty")) for r in rows)
    total_purchase = sum(_safe_float(r.get("purchase_value")) for r in rows)
    total_sale = sum(_safe_float(r.get("sale_value")) for r in rows)
    total_margin = total_sale - total_purchase
    margin_pct_total = (total_margin / total_purchase * 100.0) if total_purchase > 0 else 0.0

    summary_data = [
        ["Summary", ""],
        ["Total Cur Qty", _format_indian_currency(total_cur_qty)],
        ["Total Purchase Qty", _format_indian_currency(total_purchase_qty_period)],
        ["Total Closing Qty", _format_indian_currency(total_closing_qty_period)],
        ["Total Sale Qty", _format_indian_currency(total_sale_qty)],
        ["Total Purchase", _format_indian_currency(total_purchase)],
        ["Total Sale", _format_indian_currency(total_sale)],
        ["Total Margin", _format_indian_currency(total_margin)],
        ["Margin %", f"{margin_pct_total:,.2f}"],
    ]
    summary_table = Table(summary_data, colWidths=[50 * mm, 35 * mm])
    summary_table.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#e2e8f0")),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("ALIGN", (1, 1), (-1, -1), "RIGHT"),
        ("GRID", (0, 0), (-1, -1), 0.5, colors.HexColor("#1f2937")),
        ("FONTSIZE", (0, 0), (-1, -1), 8),
    ]))
    elements.append(summary_table)
    elements.append(Paragraph("Copyright: (c) ASARFI HOSPITAL", style_meta))

    def _draw_page_number(canvas, doc_obj):
        canvas.saveState()
        canvas.setFont("Helvetica", 8)
        page_label = f"Page {doc_obj.page}"
        width, height = doc.pagesize
        canvas.drawRightString(width - 12 * mm, 10 * mm, page_label)
        canvas.restoreState()

    doc.build(elements, onFirstPage=_draw_page_number, onLaterPages=_draw_page_number)
    buffer.seek(0)
    return buffer


def _build_product_margin_excel_bytes(
    unit: str,
    from_date: str,
    to_date: str,
    medicine_type_label: str,
    manufacturer_label: str,
    source_label: str,
    rows: list[dict],
    exported_by: str,
    search: str | None = None,
) -> bytes:
    if not rows:
        raise ValueError("No data available to export")

    exported_by = (exported_by or "Unknown").strip() or "Unknown"
    df = pd.DataFrame(rows)

    required_cols = {
        "source": "",
        "manufacturer": "",
        "item_name": "",
        "cur_qty": 0,
        "purchase_qty_period": 0,
        "closing_qty_period": 0,
        "sale_qty": 0,
        "rate": 0,
        "mrp": 0,
        "purchase_value": 0,
        "sale_value": 0,
        "margin": 0,
        "margin_pct": 0,
    }
    for col, default in required_cols.items():
        if col not in df.columns:
            df[col] = default

    for col in ["cur_qty", "purchase_qty_period", "closing_qty_period", "sale_qty", "rate", "mrp", "purchase_value", "sale_value", "margin", "margin_pct"]:
        df[col] = pd.to_numeric(df[col], errors="coerce").fillna(0.0)

    try:
        start_dt = datetime.strptime(from_date, "%Y-%m-%d").date()
        end_dt = datetime.strptime(to_date, "%Y-%m-%d").date()
        range_days = (end_dt - start_dt).days + 1
        if range_days <= 0:
            range_days = 1
    except Exception:
        range_days = 1

    avg_daily = df["sale_qty"] / range_days
    avg_monthly = avg_daily * 30.0
    low_threshold = avg_monthly * 0.30
    critical_threshold = avg_monthly * 0.15
    df["low_stock"] = (avg_monthly > 0) & (df["cur_qty"] <= low_threshold)
    df["critical_stock"] = (avg_monthly > 0) & (df["cur_qty"] <= critical_threshold)
    df["source"] = df["source"].fillna("").astype(str).str.upper()
    df["manufacturer"] = df["manufacturer"].fillna("").astype(str)
    df["item_name"] = df["item_name"].fillna("").astype(str)

    export_cols = [
        ("source", "Source"),
        ("manufacturer", "Manufacturer"),
        ("item_name", "Item Name"),
        ("cur_qty", "Cur Qty"),
        ("purchase_qty_period", "Purchase Qty (Range)"),
        ("closing_qty_period", "Closing Qty (Range)"),
        ("sale_qty", "Sale Qty"),
        ("rate", "Rate"),
        ("mrp", "MRP"),
        ("purchase_value", "Purchase"),
        ("sale_value", "Sale"),
        ("margin", "Margin"),
        ("margin_pct", "Margin %"),
    ]
    export_df = df[[c for c, _ in export_cols]].rename(columns={k: v for k, v in export_cols})

    wb = Workbook()
    ws = wb.active
    ws.title = "Product Margin"

    title_font = Font(size=14, bold=True, color="1e3a8a")
    header_font = Font(bold=True, color="FFFFFF")
    thin = Side(border_style="thin", color="d1d5db")
    border = Border(top=thin, bottom=thin, left=thin, right=thin)
    header_fill = PatternFill(start_color="1e3a8a", end_color="1e3a8a", fill_type="solid")
    critical_fill = PatternFill(start_color="fee2e2", end_color="fee2e2", fill_type="solid")
    low_fill = PatternFill(start_color="fef2f2", end_color="fef2f2", fill_type="solid")

    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    source_title = (source_label or "sale").strip().title()
    search_label = (search or "").strip() or "All"

    total_cols = max(1, len(export_df.columns))
    ws.append(["Manufacturer Medicine Product Margin"])
    ws["A1"].font = title_font
    ws.merge_cells(start_row=1, start_column=1, end_row=1, end_column=total_cols)
    ws["A1"].alignment = Alignment(horizontal="center", vertical="center")

    ws.append([f"Unit: {unit} | Date Range: {from_date} to {to_date} | Source: {source_title}"])
    ws.merge_cells(start_row=2, start_column=1, end_row=2, end_column=total_cols)
    ws["A2"].alignment = Alignment(horizontal="center", vertical="center")

    ws.append([f"Medicine Type: {medicine_type_label} | Manufacturer: {manufacturer_label} | Search: {search_label}"])
    ws.merge_cells(start_row=3, start_column=1, end_row=3, end_column=total_cols)
    ws["A3"].alignment = Alignment(horizontal="center", vertical="center")

    ws.append([f"Exported By: {exported_by} | Exported At: {exported_at}"])
    ws.merge_cells(start_row=4, start_column=1, end_row=4, end_column=total_cols)
    ws["A4"].alignment = Alignment(horizontal="center", vertical="center")

    ws.append(list(export_df.columns))
    for cell in ws[ws.max_row]:
        cell.font = header_font
        cell.fill = header_fill
        cell.alignment = Alignment(horizontal="center", vertical="center")
        cell.border = border

    num_cols = {"Cur Qty", "Purchase Qty (Range)", "Closing Qty (Range)", "Sale Qty", "Rate", "MRP", "Purchase", "Sale", "Margin", "Margin %"}
    num_fmt = "#,##,##0.00"
    pct_fmt = "0.00"

    for idx, row in export_df.iterrows():
        ws.append(list(row.values))
        fill = None
        if bool(df.loc[idx, "critical_stock"]):
            fill = critical_fill
        elif bool(df.loc[idx, "low_stock"]):
            fill = low_fill
        for col_idx, cell in enumerate(ws[ws.max_row], start=1):
            cell.border = border
            col_name = export_df.columns[col_idx - 1]
            if col_name in num_cols:
                cell.number_format = pct_fmt if col_name == "Margin %" else num_fmt
                cell.alignment = Alignment(horizontal="right", vertical="center")
            if fill:
                cell.fill = fill

    ws.freeze_panes = "A6"
    for col_idx in range(1, ws.max_column + 1):
        max_len = 0
        col_letter = get_column_letter(col_idx)
        for row_idx in range(1, ws.max_row + 1):
            cell = ws.cell(row=row_idx, column=col_idx)
            if cell.value is not None:
                max_len = max(max_len, len(str(cell.value)))
        ws.column_dimensions[col_letter].width = min(max_len + 2, 40)

    buf = io.BytesIO()
    wb.save(buf)
    buf.seek(0)
    return buf.getvalue()


def _build_gss_issue_register_excel(unit: str, from_date: str, to_date: str, exported_by: str):
    exported_by = (exported_by or "Unknown").strip() or "Unknown"
    df = data_fetch.fetch_pharmacy_gss_issue_register(unit, from_date, to_date)
    if df is None or df.empty:
        return None, None, "No data available to export"

    df = _clean_df_columns(df)
    df = df.copy()
    for col in ["Issueqty", "Rate", "Mrp", "Quantity", "ReturnRate", "ReturnMrp", "VisitDate", "DischargeDate",
                "Registration_No", "PatientName", "PatientSubType"]:
        if col not in df.columns:
            df[col] = 0 if col in ["Issueqty", "Rate", "Mrp", "Quantity", "ReturnRate", "ReturnMrp"] else ""

    issue_qty = pd.to_numeric(df["Issueqty"], errors="coerce").fillna(0)
    issue_rate = pd.to_numeric(df["Rate"], errors="coerce").fillna(0)
    issue_mrp = pd.to_numeric(df["Mrp"], errors="coerce").fillna(0)
    return_qty = pd.to_numeric(df["Quantity"], errors="coerce").fillna(0)
    return_rate = pd.to_numeric(df["ReturnRate"], errors="coerce").fillna(0)
    return_mrp = pd.to_numeric(df["ReturnMrp"], errors="coerce").fillna(0)

    df["IssueRateCalc"] = issue_rate
    df["IssueMrpCalc"] = issue_mrp
    df["ReturnRateCalc"] = return_rate
    df["ReturnMrpCalc"] = return_mrp
    df["IssueAmountRate"] = issue_qty * issue_rate
    df["IssueAmountMrp"] = issue_qty * issue_mrp
    df["ReturnAmountRate"] = return_qty * return_rate
    df["ReturnAmountMrp"] = return_qty * return_mrp

    summary_cols = [
        ("Registration_No", "Reg No"),
        ("PatientName", "Patient"),
        ("VisitDate", "Visit Date"),
        ("DischargeDate", "Discharge Date"),
        ("PatientSubType", "PatientSubType"),
        ("Issueqty", "Issue Qty"),
        ("Quantity", "Return Qty"),
        ("IssueAmountRate", "Issue Amount (Rate)"),
        ("IssueAmountMrp", "Issue Amount (MRP)"),
        ("ReturnAmountRate", "Return Amount (Rate)"),
        ("ReturnAmountMrp", "Return Amount (MRP)"),
    ]
    summary_df = df[[c for c, _ in summary_cols if c in df.columns]].rename(columns={k: v for k, v in summary_cols})
    for col in ["Issue Amount (Rate)", "Issue Amount (MRP)", "Return Amount (Rate)", "Return Amount (MRP)"]:
        summary_df[col] = pd.to_numeric(summary_df.get(col), errors="coerce").fillna(0)
    summary_df["Issue Qty"] = pd.to_numeric(summary_df.get("Issue Qty"), errors="coerce").fillna(0)
    summary_df["Return Qty"] = pd.to_numeric(summary_df.get("Return Qty"), errors="coerce").fillna(0)
    summary_df = summary_df.groupby(
        ["Reg No", "Patient", "Visit Date", "Discharge Date", "PatientSubType"],
        dropna=False,
        as_index=False
    )[["Issue Qty", "Return Qty", "Issue Amount (Rate)", "Issue Amount (MRP)", "Return Amount (Rate)", "Return Amount (MRP)"]].sum()
    summary_df["Issue Rate"] = summary_df["Issue Amount (Rate)"] / summary_df["Issue Qty"].replace(0, np.nan)
    summary_df["Issue MRP"] = summary_df["Issue Amount (MRP)"] / summary_df["Issue Qty"].replace(0, np.nan)
    summary_df["Return Rate"] = summary_df["Return Amount (Rate)"] / summary_df["Return Qty"].replace(0, np.nan)
    summary_df["Return MRP"] = summary_df["Return Amount (MRP)"] / summary_df["Return Qty"].replace(0, np.nan)
    summary_df = summary_df.fillna(0)
    summary_df = summary_df[[
        "Reg No", "Patient", "Visit Date", "Discharge Date", "PatientSubType",
        "Issue Qty", "Issue Rate", "Issue MRP", "Issue Amount (Rate)", "Issue Amount (MRP)",
        "Return Qty", "Return Rate", "Return MRP", "Return Amount (Rate)", "Return Amount (MRP)"
    ]]

    wb = Workbook()
    ws_summary = wb.active
    ws_summary.title = "Summary"

    title_font = Font(size=14, bold=True)
    header_font = Font(bold=True, color="FFFFFF")
    thin = Side(border_style="thin", color="d1d5db")
    border = Border(top=thin, bottom=thin, left=thin, right=thin)
    header_fill = PatternFill(start_color="1e3a8a", end_color="1e3a8a", fill_type="solid")
    issue_fill = PatternFill(start_color="dcfce7", end_color="dcfce7", fill_type="solid")
    return_fill = PatternFill(start_color="fee2e2", end_color="fee2e2", fill_type="solid")

    total_cols_summary = max(1, len(summary_df.columns))
    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")

    ws_summary.append(["GSS Issue/Return Register Summary"])
    ws_summary["A1"].font = title_font
    ws_summary.merge_cells(start_row=1, start_column=1, end_row=1, end_column=total_cols_summary)
    ws_summary["A1"].alignment = Alignment(horizontal="center", vertical="center")

    ws_summary.append([f"Exported By: {exported_by} | Exported At: {exported_at}"])
    ws_summary.merge_cells(start_row=2, start_column=1, end_row=2, end_column=total_cols_summary)
    ws_summary["A2"].alignment = Alignment(horizontal="center", vertical="center")

    ws_summary.append([f"Unit: {unit} | Date Range: {from_date} to {to_date}"])
    ws_summary.merge_cells(start_row=3, start_column=1, end_row=3, end_column=total_cols_summary)
    ws_summary["A3"].alignment = Alignment(horizontal="center", vertical="center")

    ws_summary.append(["Copyright: (c) ASARFI HOSPITAL"])
    ws_summary.merge_cells(start_row=4, start_column=1, end_row=4, end_column=total_cols_summary)
    ws_summary["A4"].alignment = Alignment(horizontal="center", vertical="center")

    ws_summary.append(list(summary_df.columns))
    for cell in ws_summary[ws_summary.max_row]:
        cell.font = header_font
        cell.fill = header_fill
        cell.alignment = Alignment(horizontal="center", vertical="center")
        cell.border = border

    sum_issue_idx = summary_df.columns.get_loc("Issue Amount (Rate)") + 1 if "Issue Amount (Rate)" in summary_df.columns else None
    sum_issue_mrp_idx = summary_df.columns.get_loc("Issue Amount (MRP)") + 1 if "Issue Amount (MRP)" in summary_df.columns else None
    sum_return_idx = summary_df.columns.get_loc("Return Amount (Rate)") + 1 if "Return Amount (Rate)" in summary_df.columns else None
    sum_return_mrp_idx = summary_df.columns.get_loc("Return Amount (MRP)") + 1 if "Return Amount (MRP)" in summary_df.columns else None
    for _, row in summary_df.iterrows():
        ws_summary.append(list(row.values))
        for idx, cell in enumerate(ws_summary[ws_summary.max_row], start=1):
            cell.border = border
            if sum_issue_idx and idx == sum_issue_idx:
                cell.fill = issue_fill
            if sum_issue_mrp_idx and idx == sum_issue_mrp_idx:
                cell.fill = issue_fill
            if sum_return_idx and idx == sum_return_idx:
                cell.fill = return_fill
            if sum_return_mrp_idx and idx == sum_return_mrp_idx:
                cell.fill = return_fill

    ws_summary.freeze_panes = "A6"
    for col_idx in range(1, ws_summary.max_column + 1):
        max_len = 0
        col_letter = get_column_letter(col_idx)
        for row in range(1, ws_summary.max_row + 1):
            cell = ws_summary.cell(row=row, column=col_idx)
            if cell.value is not None:
                max_len = max(max_len, len(str(cell.value)))
        ws_summary.column_dimensions[col_letter].width = min(max_len + 2, 40)

    buf = io.BytesIO()
    wb.save(buf)
    buf.seek(0)
    filename = f"GSS_Issue_Return_Register_{unit}_{from_date}_to_{to_date}.xlsx"
    return buf.getvalue(), filename, None


def _build_itemwise_consumption_excel(
    unit: str,
    from_date: str,
    to_date: str,
    doc_type: str | None,
    doc_id: int | None,
    exported_by: str,
):
    exported_by = (exported_by or "Unknown").strip() or "Unknown"
    df = data_fetch.fetch_pharmacy_itemwise_consumption(unit, from_date, to_date, doc_type, doc_id)
    if df is None or df.empty:
        return None, None, "No data available to export"

    df = _clean_df_columns(df)
    df = df.copy()
    required_cols = {
        "ItemID": 0,
        "ItemName": "",
        "DocType": "",
        "StoreName": "",
        "Consumption_Type": "",
        "PatientType": "",
        "AvgRate": 0,
        "AvgMRP": 0,
        "TotalQty": 0,
    }
    for col, default in required_cols.items():
        if col not in df.columns:
            df[col] = default

    df["AvgRate"] = pd.to_numeric(df["AvgRate"], errors="coerce").fillna(0)
    df["AvgMRP"] = pd.to_numeric(df["AvgMRP"], errors="coerce").fillna(0)
    df["TotalQty"] = pd.to_numeric(df["TotalQty"], errors="coerce").fillna(0)
    df["TotalValueRate"] = df["TotalQty"] * df["AvgRate"]
    df["TotalValueMRP"] = df["TotalQty"] * df["AvgMRP"]
    consumption_type = df["Consumption_Type"].astype(str).str.lower()
    doc_type_norm = df["DocType"].astype(str).str.upper()
    patient_type = df["PatientType"].astype(str).str.upper()
    is_departmental = (
        (doc_type_norm == "ISD")
        | consumption_type.str.contains("department", na=False)
        | patient_type.str.contains("department", na=False)
    )
    is_return = consumption_type.str.contains("return", na=False)
    dept_issue_mask = is_departmental & ~is_return
    if dept_issue_mask.any():
        df.loc[dept_issue_mask, "TotalValueMRP"] = (
            df.loc[dept_issue_mask, "TotalQty"] * df.loc[dept_issue_mask, "AvgRate"]
        )

    export_cols = [
        ("ItemID", "Item ID"),
        ("ItemName", "Item Name"),
        ("DocType", "Doc Type"),
        ("StoreName", "Store"),
        ("Consumption_Type", "Consumption Type"),
        ("PatientType", "Patient Type"),
        ("AvgRate", "Avg Rate"),
        ("AvgMRP", "Avg MRP"),
        ("TotalQty", "Total Qty"),
        ("TotalValueRate", "Total Value (Rate)"),
        ("TotalValueMRP", "Total Value (MRP)"),
    ]
    export_df = df[[c for c, _ in export_cols if c in df.columns]].rename(
        columns={src: label for src, label in export_cols}
    )

    wb = Workbook()
    ws = wb.active
    ws.title = "Itemwise Consumption"

    title_font = Font(size=14, bold=True)
    header_font = Font(bold=True, color="FFFFFF")
    thin = Side(border_style="thin", color="d1d5db")
    border = Border(top=thin, bottom=thin, left=thin, right=thin)
    header_fill = PatternFill(start_color="1e3a8a", end_color="1e3a8a", fill_type="solid")
    sale_fill = PatternFill(start_color="dcfce7", end_color="dcfce7", fill_type="solid")
    issue_fill = PatternFill(start_color="fef3c7", end_color="fef3c7", fill_type="solid")
    dept_fill = PatternFill(start_color="dbeafe", end_color="dbeafe", fill_type="solid")
    return_fill = PatternFill(start_color="fee2e2", end_color="fee2e2", fill_type="solid")

    total_cols = max(1, len(export_df.columns))
    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    doc_type_label = doc_type or "All"
    doc_id_label = str(doc_id) if doc_id is not None else "All"

    ws.append(["Itemwise Consumption Report"])
    ws["A1"].font = title_font
    ws.merge_cells(start_row=1, start_column=1, end_row=1, end_column=total_cols)
    ws["A1"].alignment = Alignment(horizontal="center", vertical="center")

    ws.append([f"Exported By: {exported_by} | Exported At: {exported_at}"])
    ws.merge_cells(start_row=2, start_column=1, end_row=2, end_column=total_cols)
    ws["A2"].alignment = Alignment(horizontal="center", vertical="center")

    ws.append([f"Unit: {unit} | Date Range: {from_date} to {to_date} | Doc Type: {doc_type_label} | Doc Id: {doc_id_label}"])
    ws.merge_cells(start_row=3, start_column=1, end_row=3, end_column=total_cols)
    ws["A3"].alignment = Alignment(horizontal="center", vertical="center")

    ws.append(["Copyright: (c) ASARFI HOSPITAL"])
    ws.merge_cells(start_row=4, start_column=1, end_row=4, end_column=total_cols)
    ws["A4"].alignment = Alignment(horizontal="center", vertical="center")

    ws.append(list(export_df.columns))
    for cell in ws[ws.max_row]:
        cell.font = header_font
        cell.fill = header_fill
        cell.alignment = Alignment(horizontal="center", vertical="center")
        cell.border = border

    consumption_idx = export_df.columns.get_loc("Consumption Type") + 1 if "Consumption Type" in export_df.columns else None
    qty_idx = export_df.columns.get_loc("Total Qty") + 1 if "Total Qty" in export_df.columns else None
    avg_rate_idx = export_df.columns.get_loc("Avg Rate") + 1 if "Avg Rate" in export_df.columns else None
    avg_mrp_idx = export_df.columns.get_loc("Avg MRP") + 1 if "Avg MRP" in export_df.columns else None
    total_rate_idx = export_df.columns.get_loc("Total Value (Rate)") + 1 if "Total Value (Rate)" in export_df.columns else None
    total_mrp_idx = export_df.columns.get_loc("Total Value (MRP)") + 1 if "Total Value (MRP)" in export_df.columns else None

    for _, row in export_df.iterrows():
        ws.append(list(row.values))
        for idx, cell in enumerate(ws[ws.max_row], start=1):
            cell.border = border
            if idx in {avg_rate_idx, avg_mrp_idx, total_rate_idx, total_mrp_idx}:
                cell.number_format = "#,##,##0.00"
                cell.alignment = Alignment(horizontal="right", vertical="center")
            elif idx == qty_idx:
                cell.number_format = "#,##,##0"
                cell.alignment = Alignment(horizontal="right", vertical="center")
            if consumption_idx and idx == consumption_idx:
                val = str(cell.value or "").strip().lower()
                if "return" in val:
                    cell.fill = return_fill
                elif "sale" in val:
                    cell.fill = sale_fill
                elif "issue" in val and "department" not in val:
                    cell.fill = issue_fill
                elif "department" in val:
                    cell.fill = dept_fill

    ws.freeze_panes = "A6"
    for col_idx in range(1, ws.max_column + 1):
        max_len = 0
        col_letter = get_column_letter(col_idx)
        for row_idx in range(1, ws.max_row + 1):
            cell = ws.cell(row=row_idx, column=col_idx)
            if cell.value is not None:
                max_len = max(max_len, len(str(cell.value)))
        ws.column_dimensions[col_letter].width = min(max_len + 2, 42)
    if "Item ID" in export_df.columns:
        item_idx = export_df.columns.get_loc("Item ID") + 1
        ws.column_dimensions[get_column_letter(item_idx)].width = 8
    if "Item ID" in export_df.columns:
        item_idx = export_df.columns.get_loc("Item ID") + 1
        item_letter = get_column_letter(item_idx)
        ws.column_dimensions[item_letter].width = 10

    buf = io.BytesIO()
    wb.save(buf)
    buf.seek(0)
    filename = f"Itemwise_Consumption_{unit}_{from_date}_to_{to_date}.xlsx"
    return buf.getvalue(), filename, None


def _build_pharmacy_expiry_excel(
    unit: str,
    from_date: str,
    to_date: str,
    store: str | None,
    exported_by: str,
):
    exported_by = (exported_by or "Unknown").strip() or "Unknown"
    df = data_fetch.fetch_pharmacy_expired_items(unit, from_date, to_date)
    if df is None or df.empty:
        return None, None, "No data available to export"

    df = _clean_df_columns(df).copy()
    required_cols = {
        "ItemName": "",
        "Qty": 0,
        "Rate": 0,
        "ExpiryDate": "",
        "GRNNo": "",
        "BatchName": "",
        "SupplierName": "",
        "StoreName": "",
    }
    for col, default in required_cols.items():
        if col not in df.columns:
            df[col] = default

    if store:
        store_norm = store.strip().upper()
        df = df[df["StoreName"].astype(str).str.upper() == store_norm]
        if df.empty:
            return None, None, "No data available for selected store"

    df["Qty"] = pd.to_numeric(df["Qty"], errors="coerce").fillna(0)
    df["Rate"] = pd.to_numeric(df["Rate"], errors="coerce").fillna(0)
    df["ExpiryDate"] = pd.to_datetime(df["ExpiryDate"], errors="coerce")

    today = datetime.now(tz=LOCAL_TZ).date()
    def _days_to_expiry(value):
        if value is None or pd.isna(value):
            return None
        try:
            return (value.date() - today).days
        except Exception:
            return None
    df["DaysToExpiry"] = df["ExpiryDate"].apply(_days_to_expiry)
    def _expiry_status(days):
        if days is None:
            return "Unknown"
        if days < 0:
            return "Expired"
        if days <= 7:
            return "Critical (<=7d)"
        if days <= 30:
            return "Warning (<=30d)"
        if days <= 90:
            return "Watch (<=90d)"
        return "OK (>90d)"
    df["ExpiryStatus"] = df["DaysToExpiry"].apply(_expiry_status)

    export_cols = [
        ("ItemName", "Item Name"),
        ("BatchName", "Batch"),
        ("ExpiryDate", "Expiry Date"),
        ("DaysToExpiry", "Days To Expiry"),
        ("ExpiryStatus", "Expiry Status"),
        ("Qty", "Qty"),
        ("Rate", "Rate"),
        ("GRNNo", "GRN No"),
        ("SupplierName", "Supplier"),
        ("StoreName", "Store"),
    ]
    export_df = df[[c for c, _ in export_cols if c in df.columns]].rename(
        columns={src: label for src, label in export_cols}
    )

    wb = Workbook()
    ws = wb.active
    ws.title = "Expiry Report"

    title_font = Font(size=14, bold=True, color="1e3a8a")
    header_font = Font(bold=True, color="FFFFFF")
    thin = Side(border_style="thin", color="d1d5db")
    border = Border(top=thin, bottom=thin, left=thin, right=thin)
    header_fill = PatternFill(start_color="1e3a8a", end_color="1e3a8a", fill_type="solid")
    expired_fill = PatternFill(start_color="fee2e2", end_color="fee2e2", fill_type="solid")
    critical_fill = PatternFill(start_color="fecaca", end_color="fecaca", fill_type="solid")
    warning_fill = PatternFill(start_color="fed7aa", end_color="fed7aa", fill_type="solid")
    watch_fill = PatternFill(start_color="fef3c7", end_color="fef3c7", fill_type="solid")
    ok_fill = PatternFill(start_color="dcfce7", end_color="dcfce7", fill_type="solid")

    total_cols = max(1, len(export_df.columns))
    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    store_label = store or "All"

    ws.append(["Pharmacy Expiry Report"])
    ws["A1"].font = title_font
    ws.merge_cells(start_row=1, start_column=1, end_row=1, end_column=total_cols)
    ws["A1"].alignment = Alignment(horizontal="center", vertical="center")

    ws.append([f"Unit: {unit} | Date Range: {from_date} to {to_date} | Store: {store_label}"])
    ws.merge_cells(start_row=2, start_column=1, end_row=2, end_column=total_cols)
    ws["A2"].alignment = Alignment(horizontal="center", vertical="center")

    ws.append([f"Exported By: {exported_by} | Exported At: {exported_at}"])
    ws.merge_cells(start_row=3, start_column=1, end_row=3, end_column=total_cols)
    ws["A3"].alignment = Alignment(horizontal="center", vertical="center")

    ws.append(list(export_df.columns))
    for cell in ws[ws.max_row]:
        cell.font = header_font
        cell.fill = header_fill
        cell.alignment = Alignment(horizontal="center", vertical="center")
        cell.border = border

    expiry_idx = export_df.columns.get_loc("Expiry Date") + 1 if "Expiry Date" in export_df.columns else None
    days_idx = export_df.columns.get_loc("Days To Expiry") + 1 if "Days To Expiry" in export_df.columns else None
    qty_idx = export_df.columns.get_loc("Qty") + 1 if "Qty" in export_df.columns else None
    rate_idx = export_df.columns.get_loc("Rate") + 1 if "Rate" in export_df.columns else None

    for _, row in export_df.iterrows():
        ws.append(list(row.values))
        days_val = row.get("Days To Expiry")
        fill = None
        try:
            if days_val is not None:
                days_val = int(days_val)
                if days_val < 0:
                    fill = expired_fill
                elif days_val <= 7:
                    fill = critical_fill
                elif days_val <= 30:
                    fill = warning_fill
                elif days_val <= 90:
                    fill = watch_fill
                else:
                    fill = ok_fill
        except Exception:
            fill = None
        for idx, cell in enumerate(ws[ws.max_row], start=1):
            cell.border = border
            if idx == expiry_idx:
                cell.number_format = "yyyy-mm-dd"
                cell.alignment = Alignment(horizontal="center", vertical="center")
            elif idx == days_idx:
                cell.alignment = Alignment(horizontal="right", vertical="center")
            elif idx == qty_idx:
                cell.number_format = "#,##,##0"
                cell.alignment = Alignment(horizontal="right", vertical="center")
            elif idx == rate_idx:
                cell.number_format = "#,##,##0.00"
                cell.alignment = Alignment(horizontal="right", vertical="center")
            if fill and idx in {expiry_idx, days_idx}:
                cell.fill = fill

    ws.freeze_panes = "A5"
    for col_idx in range(1, ws.max_column + 1):
        max_len = 0
        col_letter = get_column_letter(col_idx)
        for row_idx in range(1, ws.max_row + 1):
            cell = ws.cell(row=row_idx, column=col_idx)
            if cell.value is not None:
                max_len = max(max_len, len(str(cell.value)))
        ws.column_dimensions[col_letter].width = min(max_len + 2, 40)

    buf = io.BytesIO()
    wb.save(buf)
    buf.seek(0)
    filename = f"Pharmacy_Expiry_Report_{unit}_{from_date}_to_{to_date}.xlsx"
    return buf.getvalue(), filename, None


def _build_pharmacy_expiry_pdf_buffer(
    unit: str,
    from_date: str,
    to_date: str,
    store: str | None,
    exported_by: str | None,
):
    from reportlab.lib.pagesizes import A4, landscape
    from reportlab.lib import colors
    from reportlab.lib.units import mm
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer, Image
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER

    df = data_fetch.fetch_pharmacy_expired_items(unit, from_date, to_date)
    if df is None or df.empty:
        return None
    df = _clean_df_columns(df).copy()
    required_cols = {
        "ItemName": "",
        "Qty": 0,
        "Rate": 0,
        "ExpiryDate": None,
        "GRNNo": "",
        "BatchName": "",
        "SupplierName": "",
        "StoreName": "",
    }
    for col, default in required_cols.items():
        if col not in df.columns:
            df[col] = default

    if store:
        store_norm = store.strip().upper()
        if "StoreName" in df.columns:
            df = df[df["StoreName"].astype(str).str.upper() == store_norm]
    if df.empty:
        return None

    df["Qty"] = pd.to_numeric(df["Qty"], errors="coerce").fillna(0)
    df["Rate"] = pd.to_numeric(df["Rate"], errors="coerce").fillna(0)
    df["ExpiryDate"] = pd.to_datetime(df["ExpiryDate"], errors="coerce")

    today = datetime.now(tz=LOCAL_TZ).date()
    def _days_to_expiry(value):
        if value is None or pd.isna(value):
            return None
        try:
            return (value.date() - today).days
        except Exception:
            return None
    df["DaysToExpiry"] = df["ExpiryDate"].apply(_days_to_expiry)

    cols = [
        ("ItemName", "Item Name"),
        ("BatchName", "Batch"),
        ("ExpiryDate", "Expiry Date"),
        ("DaysToExpiry", "Days"),
        ("Qty", "Qty"),
        ("Rate", "Rate"),
        ("GRNNo", "GRN No"),
        ("SupplierName", "Supplier"),
        ("StoreName", "Store"),
    ]
    df = df[[c for c, _ in cols if c in df.columns]].rename(columns={k: v for k, v in cols})
    df["Expiry Date"] = df["Expiry Date"].dt.strftime("%Y-%m-%d")

    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=landscape(A4),
        topMargin=14 * mm,
        bottomMargin=14 * mm,
        leftMargin=12 * mm,
        rightMargin=12 * mm,
    )

    styles = getSampleStyleSheet()
    style_title = ParagraphStyle("RptTitle", parent=styles["Heading2"], fontSize=12, alignment=TA_CENTER, textColor=colors.HexColor("#1e3a8a"))
    style_sub = ParagraphStyle("RptSub", parent=styles["Normal"], fontSize=9, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_meta = ParagraphStyle("RptMeta", parent=styles["Normal"], fontSize=8, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))

    elements = []
    logo_path = os.path.join(app.root_path, "static", "logo", "asarfi.png")
    if os.path.exists(logo_path):
        logo = Image(logo_path, width=18 * mm, height=18 * mm, mask='auto')
        logo.hAlign = "CENTER"
        elements.append(logo)

    store_label = store or "All"
    exported_by = exported_by or "Unknown"
    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")

    elements.append(Spacer(1, 6))
    elements.append(Paragraph("Pharmacy Expiry Report", style_title))
    elements.append(Paragraph(f"Unit: {unit} | Date Range: {from_date} to {to_date} | Store: {store_label}", style_sub))
    elements.append(Paragraph(f"Exported By: {exported_by} | Exported At: {exported_at}", style_meta))
    elements.append(Spacer(1, 8))

    table_data = [list(df.columns)]
    for _, row in df.iterrows():
        table_data.append([
            str(row.get("Item Name") or ""),
            str(row.get("Batch") or ""),
            str(row.get("Expiry Date") or ""),
            str(row.get("Days") if row.get("Days") is not None else ""),
            f"{float(row.get('Qty') or 0):,.0f}",
            f"{float(row.get('Rate') or 0):,.2f}",
            str(row.get("GRN No") or ""),
            str(row.get("Supplier") or ""),
            str(row.get("Store") or ""),
        ])

    tbl = Table(table_data, repeatRows=1)
    tbl_style = TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("FONTSIZE", (0, 0), (-1, -1), 7),
        ("GRID", (0, 0), (-1, -1), 0.5, colors.HexColor("#1f2937")),
        ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
        ("ALIGN", (4, 1), (5, -1), "RIGHT"),
    ])

    for row_idx in range(1, len(table_data)):
        days_val = df.iloc[row_idx - 1].get("Days")
        fill = None
        try:
            if days_val is not None:
                days_val = int(days_val)
                if days_val < 0:
                    fill = colors.HexColor("#fee2e2")
                elif days_val <= 7:
                    fill = colors.HexColor("#fecaca")
                elif days_val <= 30:
                    fill = colors.HexColor("#fed7aa")
                elif days_val <= 90:
                    fill = colors.HexColor("#fef3c7")
                else:
                    fill = colors.HexColor("#dcfce7")
        except Exception:
            fill = None
        if fill:
            tbl_style.add("BACKGROUND", (2, row_idx), (2, row_idx), fill)
            tbl_style.add("BACKGROUND", (3, row_idx), (3, row_idx), fill)

    tbl.setStyle(tbl_style)
    elements.append(tbl)
    elements.append(Spacer(1, 8))
    elements.append(Paragraph("Copyright: (c) ASARFI HOSPITAL", style_meta))

    def _draw_page_number(canvas, doc_obj):
        canvas.saveState()
        canvas.setFont("Helvetica", 8)
        page_label = f"Page {doc_obj.page}"
        width, _ = doc.pagesize
        canvas.drawRightString(width - 12 * mm, 10 * mm, page_label)
        canvas.restoreState()

    doc.build(elements, onFirstPage=_draw_page_number, onLaterPages=_draw_page_number)
    buffer.seek(0)
    return buffer


def _build_pharmacy_non_moving_excel(
    unit: str,
    store_id: int,
    exported_by: str,
):
    exported_by = (exported_by or "Unknown").strip() or "Unknown"
    df = data_fetch.fetch_pharmacy_non_moving_items(unit, store_id)
    if df is None or df.empty:
        return None, None, "No data available to export"

    df = _clean_df_columns(df).copy()
    required_cols = {
        "ItemID": 0,
        "ItemName": "",
        "ItemType": "",
        "StQty": 0,
        "SaleQty": 0,
        "IssueQty": 0,
        "TotalMovedQty": 0,
        "Rate": 0,
        "NearestExpiryDate": None,
        "DaysLeftToExpire": None,
        "LastInwardDate": None,
    }
    for col, default in required_cols.items():
        if col not in df.columns:
            df[col] = default

    df["StQty"] = pd.to_numeric(df["StQty"], errors="coerce").fillna(0)
    df["SaleQty"] = pd.to_numeric(df["SaleQty"], errors="coerce").fillna(0)
    df["IssueQty"] = pd.to_numeric(df["IssueQty"], errors="coerce").fillna(0)
    df["TotalMovedQty"] = pd.to_numeric(df["TotalMovedQty"], errors="coerce").fillna(0)
    df["Rate"] = pd.to_numeric(df["Rate"], errors="coerce").fillna(0)
    df["NearestExpiryDate"] = pd.to_datetime(df["NearestExpiryDate"], errors="coerce")
    df["LastInwardDate"] = pd.to_datetime(df["LastInwardDate"], errors="coerce")

    today = datetime.now(tz=LOCAL_TZ).date()
    def _days_left(value):
        if value is None or pd.isna(value):
            return None
        try:
            return (value.date() - today).days
        except Exception:
            return None
    if "DaysLeftToExpire" not in df.columns:
        df["DaysLeftToExpire"] = df["NearestExpiryDate"].apply(_days_left)
    else:
        df["DaysLeftToExpire"] = pd.to_numeric(df["DaysLeftToExpire"], errors="coerce")

    store_label = "OPD" if store_id == 2 else "IPD"
    df["StoreName"] = store_label

    export_cols = [
        ("ItemID", "Item ID"),
        ("ItemName", "Item Name"),
        ("ItemType", "Item Type"),
        ("StQty", "Stock Qty"),
        ("SaleQty", "Sale Qty"),
        ("IssueQty", "Issue Qty"),
        ("TotalMovedQty", "Total Moved Qty"),
        ("Rate", "Rate"),
        ("NearestExpiryDate", "Nearest Expiry"),
        ("DaysLeftToExpire", "Days Left"),
        ("LastInwardDate", "Last Inward"),
        ("StoreName", "Store"),
    ]
    export_df = df[[c for c, _ in export_cols if c in df.columns]].rename(
        columns={src: label for src, label in export_cols}
    )

    wb = Workbook()
    ws = wb.active
    ws.title = "Non-Moving Items"

    title_font = Font(size=14, bold=True, color="1e3a8a")
    header_font = Font(bold=True, color="FFFFFF")
    thin = Side(border_style="thin", color="d1d5db")
    border = Border(top=thin, bottom=thin, left=thin, right=thin)
    header_fill = PatternFill(start_color="1e3a8a", end_color="1e3a8a", fill_type="solid")
    expired_fill = PatternFill(start_color="fee2e2", end_color="fee2e2", fill_type="solid")
    critical_fill = PatternFill(start_color="fecaca", end_color="fecaca", fill_type="solid")
    warning_fill = PatternFill(start_color="fed7aa", end_color="fed7aa", fill_type="solid")
    watch_fill = PatternFill(start_color="fef3c7", end_color="fef3c7", fill_type="solid")
    ok_fill = PatternFill(start_color="dcfce7", end_color="dcfce7", fill_type="solid")

    now_dt = datetime.now(tz=LOCAL_TZ)
    to_label = now_dt.strftime("%Y-%m-%d")
    from_label = (pd.Timestamp(now_dt) - pd.DateOffset(months=3)).date().strftime("%Y-%m-%d")
    exported_at = now_dt.strftime("%Y-%m-%d %H:%M:%S")

    total_cols = max(1, len(export_df.columns))
    ws.append(["Pharmacy Non-Moving Items Report"])
    ws["A1"].font = title_font
    ws.merge_cells(start_row=1, start_column=1, end_row=1, end_column=total_cols)
    ws["A1"].alignment = Alignment(horizontal="center", vertical="center")

    ws.append([f"Unit: {unit} | Store: {store_label} | Date Range: {from_label} to {to_label}"])
    ws.merge_cells(start_row=2, start_column=1, end_row=2, end_column=total_cols)
    ws["A2"].alignment = Alignment(horizontal="center", vertical="center")

    ws.append([f"Exported By: {exported_by} | Exported At: {exported_at}"])
    ws.merge_cells(start_row=3, start_column=1, end_row=3, end_column=total_cols)
    ws["A3"].alignment = Alignment(horizontal="center", vertical="center")

    ws.append(list(export_df.columns))
    for cell in ws[ws.max_row]:
        cell.font = header_font
        cell.fill = header_fill
        cell.alignment = Alignment(horizontal="center", vertical="center")
        cell.border = border

    expiry_idx = export_df.columns.get_loc("Nearest Expiry") + 1 if "Nearest Expiry" in export_df.columns else None
    days_idx = export_df.columns.get_loc("Days Left") + 1 if "Days Left" in export_df.columns else None
    rate_idx = export_df.columns.get_loc("Rate") + 1 if "Rate" in export_df.columns else None

    for _, row in export_df.iterrows():
        ws.append(list(row.values))
        days_val = row.get("Days Left")
        fill = None
        try:
            if days_val is not None and not pd.isna(days_val):
                days_val = int(days_val)
                if days_val < 0:
                    fill = expired_fill
                elif days_val <= 7:
                    fill = critical_fill
                elif days_val <= 30:
                    fill = warning_fill
                elif days_val <= 90:
                    fill = watch_fill
                else:
                    fill = ok_fill
        except Exception:
            fill = None
        for idx, cell in enumerate(ws[ws.max_row], start=1):
            cell.border = border
            if idx == expiry_idx:
                cell.number_format = "yyyy-mm-dd"
                cell.alignment = Alignment(horizontal="center", vertical="center")
                if fill:
                    cell.fill = fill
            elif idx == days_idx:
                cell.alignment = Alignment(horizontal="right", vertical="center")
            elif idx == rate_idx:
                cell.number_format = "#,##,##0.00"
                cell.alignment = Alignment(horizontal="right", vertical="center")

    ws.freeze_panes = "A5"
    for col_idx in range(1, ws.max_column + 1):
        max_len = 0
        col_letter = get_column_letter(col_idx)
        for row_idx in range(1, ws.max_row + 1):
            cell = ws.cell(row=row_idx, column=col_idx)
            if cell.value is not None:
                max_len = max(max_len, len(str(cell.value)))
        ws.column_dimensions[col_letter].width = min(max_len + 2, 42)

    buf = io.BytesIO()
    wb.save(buf)
    buf.seek(0)
    filename = f"Pharmacy_Non_Moving_{unit}_{store_label}_{from_label}_to_{to_label}.xlsx"
    return buf.getvalue(), filename, None


