def _build_pharmacy_current_stock_statement_excel(unit: str, store_id: int, from_date: str, to_date: str, exported_by: str | None):
    import io
    import pandas as pd

    df, meta = _build_pharmacy_current_stock_statement_df(unit, store_id, from_date, to_date)
    if df is None:
        return None, None, (meta or {}).get("error") or "Failed to build statement"

    meta = meta or {}
    store_name = meta.get("store_name") or _lookup_store_name(unit, store_id) or f"Store {store_id}"
    warnings_list = [str(w).strip() for w in (meta.get("warnings") or []) if str(w or "").strip()]
    warning_text = " | ".join(warnings_list) if warnings_list else "None"

    export_df = df.copy()
    col_map = {src: label for src, label in PH_STMT_EXPORT_COLS}
    export_df = export_df[[c for c, _ in PH_STMT_EXPORT_COLS if c in export_df.columns]].rename(columns=col_map)
    qty_cols = [label for _, label in PH_STMT_EXPORT_COLS if label.endswith("Qty")]
    for col in qty_cols:
        if col in export_df.columns:
            export_df[col] = pd.to_numeric(export_df[col], errors="coerce").fillna(0.0)

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
        wb = writer.book
        ws_name = "Stock Statement"
        start_row = 7
        export_df.to_excel(writer, sheet_name=ws_name, index=False, startrow=start_row)
        ws = writer.sheets[ws_name]

        title_fmt = wb.add_format({
            "bold": True, "font_size": 14, "font_color": "#1E3A8A",
            "align": "center", "valign": "vcenter"
        })
        subtitle_fmt = wb.add_format({
            "bold": True, "font_size": 11, "align": "center", "valign": "vcenter"
        })
        meta_fmt = wb.add_format({"font_size": 9, "align": "center", "valign": "vcenter"})
        warn_fmt = wb.add_format({"font_size": 8, "align": "left", "valign": "vcenter", "font_color": "#9a3412"})
        header_fmt = wb.add_format({
            "bold": True, "bg_color": "#1E3A8A", "font_color": "white",
            "border": 1, "align": "center", "valign": "vcenter"
        })
        data_text_fmt = wb.add_format({"border": 1, "align": "left", "valign": "vcenter"})
        data_rate_fmt = wb.add_format({"border": 1, "num_format": "#,##,##0.00", "align": "right", "valign": "vcenter"})
        data_qty_fmt = wb.add_format({"border": 1, "num_format": "#,##,##0.000", "align": "right", "valign": "vcenter"})
        # Subtle alternating highlight for item rows (readability without strong color blocks).
        data_text_alt_fmt = wb.add_format({
            "border": 1, "align": "left", "valign": "vcenter", "bg_color": "#f8fafc"
        })
        data_rate_alt_fmt = wb.add_format({
            "border": 1, "num_format": "#,##,##0.00", "align": "right", "valign": "vcenter", "bg_color": "#f8fafc"
        })
        data_qty_alt_fmt = wb.add_format({
            "border": 1, "num_format": "#,##,##0.000", "align": "right", "valign": "vcenter", "bg_color": "#f8fafc"
        })
        total_label_fmt = wb.add_format({
            "bold": True, "bg_color": "#d9d9d9", "border": 1,
            "align": "left", "valign": "vcenter"
        })
        total_qty_fmt = wb.add_format({
            "bold": True, "bg_color": "#d9d9d9", "border": 1,
            "num_format": "#,##,##0.000", "align": "right", "valign": "vcenter"
        })

        last_col = max(0, len(export_df.columns) - 1)
        ws.merge_range(0, 0, 0, last_col, "Current Stock Statement (Consolidated Per Item)", title_fmt)
        ws.merge_range(1, 0, 1, last_col, f"Unit: {unit} | Store: {store_name}", subtitle_fmt)
        ws.merge_range(2, 0, 2, last_col, f"Date Range: {from_date} to {to_date}", meta_fmt)
        ws.merge_range(3, 0, 3, last_col, f"Reconciled Closing: {'Yes' if meta.get('reconciled') else 'No'}", meta_fmt)
        ws.merge_range(4, 0, 4, last_col, f"Warnings: {warning_text}", warn_fmt)
        exported_by = exported_by or "Unknown"
        exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
        ws.merge_range(5, 0, 5, last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)

        for col_num, col_name in enumerate(export_df.columns):
            ws.write(start_row, col_num, col_name, header_fmt)
            if col_name == "Item Name":
                ws.set_column(col_num, col_num, 34)
            elif col_name in {"Item Group", "Item SubGroup"}:
                ws.set_column(col_num, col_num, 18)
            elif col_name in {"Rate", "MRP"}:
                ws.set_column(col_num, col_num, 12)
            else:
                ws.set_column(col_num, col_num, 13)

        data_start = start_row + 1
        total_row = data_start + len(export_df)
        if len(export_df) > 0:
            # Apply bordered formats only across the real data range, not full worksheet columns.
            for data_idx in range(len(export_df)):
                excel_row = data_start + data_idx
                text_fmt = data_text_alt_fmt if (data_idx % 2 == 1) else data_text_fmt
                rate_fmt = data_rate_alt_fmt if (data_idx % 2 == 1) else data_rate_fmt
                qty_fmt = data_qty_alt_fmt if (data_idx % 2 == 1) else data_qty_fmt
                for col_num, col_name in enumerate(export_df.columns):
                    cell_val = export_df.iloc[data_idx, col_num]
                    if col_name in {"Item Name", "Item Group", "Item SubGroup"}:
                        ws.write(excel_row, col_num, "" if pd.isna(cell_val) else str(cell_val), text_fmt)
                    elif col_name in {"Rate", "MRP"}:
                        try:
                            num_val = float(cell_val)
                        except Exception:
                            num_val = 0.0
                        ws.write_number(excel_row, col_num, num_val, rate_fmt)
                    else:
                        try:
                            num_val = float(cell_val)
                        except Exception:
                            num_val = 0.0
                        ws.write_number(excel_row, col_num, num_val, qty_fmt)

            ws.write(total_row, 0, "TOTAL", total_label_fmt)
            col_totals = {}
            for col_name in export_df.columns:
                if col_name.endswith("Qty"):
                    col_totals[col_name] = float(pd.to_numeric(export_df[col_name], errors="coerce").fillna(0.0).sum())
            for col_num, col_name in enumerate(export_df.columns):
                if col_num == 0:
                    continue
                if col_name.endswith("Qty"):
                    ws.write_number(total_row, col_num, float(col_totals.get(col_name, 0.0)), total_qty_fmt)
                else:
                    ws.write(total_row, col_num, "", total_label_fmt)
        else:
            ws.merge_range(data_start, 0, data_start, last_col, "No data for selected range", meta_fmt)
            total_row = data_start + 1

        ws.merge_range(total_row + 1, 0, total_row + 1, last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)
        ws.freeze_panes(data_start, 0)

    output.seek(0)
    filename = f"Pharmacy_Current_Stock_Statement_{unit}_Store{store_id}_{from_date}_to_{to_date}.xlsx"
    return output.getvalue(), filename, None


def _build_pharmacy_current_stock_statement_pdf_buffer(unit: str, store_id: int, from_date: str, to_date: str, exported_by: str | None):
    from reportlab.lib.pagesizes import A4, landscape
    from reportlab.lib import colors
    from reportlab.lib.units import mm
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer, Image
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_RIGHT
    from xml.sax.saxutils import escape as xml_escape

    df, meta = _build_pharmacy_current_stock_statement_df(unit, store_id, from_date, to_date)
    if df is None:
        return None, None, (meta or {}).get("error") or "Failed to build statement"

    meta = meta or {}
    store_name = meta.get("store_name") or _lookup_store_name(unit, store_id) or f"Store {store_id}"
    warnings_list = [str(w).strip() for w in (meta.get("warnings") or []) if str(w or "").strip()]

    export_df = df.copy()
    col_map = {src: label for src, label in PH_STMT_EXPORT_COLS}
    export_df = export_df[[c for c, _ in PH_STMT_EXPORT_COLS if c in export_df.columns]].rename(columns=col_map)

    qty_cols = [label for _, label in PH_STMT_EXPORT_COLS if label.endswith("Qty")]
    for col in qty_cols:
        if col in export_df.columns:
            export_df[col] = pd.to_numeric(export_df[col], errors="coerce").fillna(0.0)

    def _fmt_qty(val, decimals=3):
        try:
            num = float(val)
        except Exception:
            num = 0.0
        sign = "-" if num < 0 else ""
        num = abs(num)
        fmt = f"{num:.{decimals}f}"
        if decimals:
            int_part, dec_part = fmt.split(".")
        else:
            int_part, dec_part = fmt, ""
        if len(int_part) <= 3:
            grouped = int_part
        else:
            last3 = int_part[-3:]
            rest = int_part[:-3]
            groups = []
            while rest:
                groups.append(rest[-2:])
                rest = rest[:-2]
            grouped = ",".join(reversed(groups)) + "," + last3
        return f"{sign}{grouped}.{dec_part}" if decimals else f"{sign}{grouped}"

    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=landscape(A4),
        topMargin=14 * mm,
        bottomMargin=14 * mm,
        leftMargin=10 * mm,
        rightMargin=10 * mm,
    )

    styles = getSampleStyleSheet()
    style_title = ParagraphStyle("RptTitle", parent=styles["Heading2"], fontSize=12, alignment=TA_CENTER, textColor=colors.HexColor("#1e3a8a"))
    style_sub = ParagraphStyle("RptSub", parent=styles["Normal"], fontSize=9, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_meta = ParagraphStyle("RptMeta", parent=styles["Normal"], fontSize=8, alignment=TA_CENTER, textColor=colors.HexColor("#475569"))
    style_warn = ParagraphStyle("RptWarn", parent=styles["Normal"], fontSize=8, alignment=TA_LEFT, textColor=colors.HexColor("#9a3412"), leading=10)
    style_header = ParagraphStyle(
        "RptHeader",
        parent=styles["Normal"],
        fontName="Helvetica-Bold",
        fontSize=6.2,
        leading=7.0,
        alignment=TA_CENTER,
        textColor=colors.white,
        wordWrap="CJK",
    )
    style_cell_text = ParagraphStyle(
        "RptCellText",
        parent=styles["Normal"],
        fontSize=6.4,
        leading=7.2,
        alignment=TA_LEFT,
        textColor=colors.black,
        wordWrap="CJK",
    )
    style_cell_num = ParagraphStyle(
        "RptCellNum",
        parent=styles["Normal"],
        fontSize=6.2,
        leading=7.0,
        alignment=TA_RIGHT,
        textColor=colors.black,
        wordWrap="CJK",
    )
    style_total_label = ParagraphStyle("RptTotalLabel", parent=style_cell_text, fontName="Helvetica-Bold")
    style_total_num = ParagraphStyle("RptTotalNum", parent=style_cell_num, fontName="Helvetica-Bold")

    elements = []
    logo_path = os.path.join(app.root_path, "static", "logo", "asarfi.png")
    if os.path.exists(logo_path):
        logo = Image(logo_path, width=18 * mm, height=18 * mm, mask='auto')
        logo.hAlign = "CENTER"
        elements.append(logo)
    elements.append(Spacer(1, 6))
    elements.append(Paragraph("Current Stock Statement (Consolidated Per Item)", style_title))
    elements.append(Paragraph(f"Unit: {unit} | Store: {store_name}", style_sub))
    elements.append(Paragraph(f"Date Range: {from_date} to {to_date}", style_sub))
    elements.append(Paragraph(f"Reconciled Closing: {'Yes' if meta.get('reconciled') else 'No'}", style_meta))
    exported_by = exported_by or "Unknown"
    exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
    elements.append(Paragraph(f"Exported By: {exported_by} | Exported At: {exported_at}", style_meta))
    if warnings_list:
        elements.append(Spacer(1, 4))
        elements.append(Paragraph(f"Warnings: {xml_escape(' | '.join(warnings_list))}", style_warn))
    elements.append(Spacer(1, 8))

    def _pdf_safe_text(val) -> str:
        if val is None:
            return ""
        try:
            if pd.isna(val):
                return ""
        except Exception:
            pass
        text = str(val).replace("\r\n", "\n").replace("\r", "\n")
        # Default Helvetica in ReportLab cannot draw some unicode bullets/symbols.
        for bad in ("\u25a0", "\u25cf", "\u2022", "\uf0b7"):
            text = text.replace(bad, " ")
        cleaned = []
        for ch in text:
            code = ord(ch)
            if ch == "\n" or code >= 32:
                cleaned.append(ch)
        text = "".join(cleaned)
        text = text.encode("latin-1", "ignore").decode("latin-1")
        return " ".join(text.split())

    def _wrap_text(val, style=style_cell_text):
        return Paragraph(xml_escape(_pdf_safe_text(val)), style)

    def _wrap_num(val, decimals=3, total=False):
        style = style_total_num if total else style_cell_num
        return Paragraph(xml_escape(_fmt_qty(val, decimals)), style)

    table_data = [[_wrap_text(col, style_header) for col in export_df.columns]]
    if export_df.empty:
        table_data.append([_wrap_text("No data for selected range")] + [""] * (len(export_df.columns) - 1))
    else:
        for _, row in export_df.iterrows():
            table_data.append([
                _wrap_text(row.get("Item Name")),
                _wrap_text(row.get("Item Group")),
                _wrap_text(row.get("Item SubGroup")),
                _wrap_num(row.get("Rate"), 2),
                _wrap_num(row.get("MRP"), 2),
                _wrap_num(row.get("Opening Qty")),
                _wrap_num(row.get("Purchase Qty")),
                _wrap_num(row.get("Purchase Return Qty")),
                _wrap_num(row.get("Sale Qty")),
                _wrap_num(row.get("Issued Qty")),
                _wrap_num(row.get("Sale Return Qty")),
                _wrap_num(row.get("Issue Return Qty")),
                _wrap_num(row.get("Closing Qty")),
            ])

        totals = {col: float(pd.to_numeric(export_df[col], errors="coerce").fillna(0.0).sum()) for col in qty_cols if col in export_df.columns}
        table_data.append([
            _wrap_text("TOTAL", style_total_label), "", "", "", "",
            _wrap_num(totals.get("Opening Qty", 0.0), total=True),
            _wrap_num(totals.get("Purchase Qty", 0.0), total=True),
            _wrap_num(totals.get("Purchase Return Qty", 0.0), total=True),
            _wrap_num(totals.get("Sale Qty", 0.0), total=True),
            _wrap_num(totals.get("Issued Qty", 0.0), total=True),
            _wrap_num(totals.get("Sale Return Qty", 0.0), total=True),
            _wrap_num(totals.get("Issue Return Qty", 0.0), total=True),
            _wrap_num(totals.get("Closing Qty", 0.0), total=True),
        ])

    col_width_map_mm = {
        "Item Name": 58,
        "Item Group": 22,
        "Item SubGroup": 22,
        "Rate": 14,
        "MRP": 14,
        "Opening Qty": 17,
        "Purchase Qty": 17,
        "Purchase Return Qty": 17,
        "Sale Qty": 17,
        "Issued Qty": 17,
        "Sale Return Qty": 17,
        "Issue Return Qty": 17,
        "Closing Qty": 17,
    }
    col_widths = [col_width_map_mm.get(col, 17) * mm for col in export_df.columns]
    total_width = sum(col_widths)
    if total_width > doc.width and total_width > 0:
        scale = doc.width / total_width
        col_widths = [w * scale for w in col_widths]

    tbl = Table(table_data, colWidths=col_widths, repeatRows=1)
    tbl_style = TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#1e3a8a")),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("FONTSIZE", (0, 0), (-1, -1), 6.2),
        ("GRID", (0, 0), (-1, -1), 0.5, colors.HexColor("#1f2937")),
        ("VALIGN", (0, 0), (-1, -1), "TOP"),
        ("ALIGN", (3, 1), (-1, -1), "RIGHT"),
        ("LEFTPADDING", (0, 0), (-1, -1), 1.2),
        ("RIGHTPADDING", (0, 0), (-1, -1), 1.2),
        ("TOPPADDING", (0, 0), (-1, -1), 1.6),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 1.6),
        ("TOPPADDING", (0, 0), (-1, 0), 2.2),
        ("BOTTOMPADDING", (0, 0), (-1, 0), 2.2),
    ])
    if export_df.empty:
        tbl_style.add("ALIGN", (0, 1), (-1, 1), "CENTER")
        tbl_style.add("TEXTCOLOR", (0, 1), (-1, 1), colors.HexColor("#64748b"))
    else:
        total_row_idx = len(table_data) - 1
        tbl_style.add("BACKGROUND", (0, total_row_idx), (-1, total_row_idx), colors.HexColor("#d9d9d9"))
        tbl_style.add("FONTNAME", (0, total_row_idx), (-1, total_row_idx), "Helvetica-Bold")
    tbl.setStyle(tbl_style)
    elements.append(tbl)
    elements.append(Spacer(1, 8))

    footer_line_1 = (
        f"Date Range: {from_date} to {to_date} | Unit: {unit} | Store: {store_name} | "
        f"Reconciled Closing: {'Yes' if meta.get('reconciled') else 'No'}"
    )
    footer_line_2 = f"Exported By: {exported_by} | Exported At: {exported_at} | Copyright: (c) ASARFI HOSPITAL"

    def _draw_footer(canvas, doc_obj):
        canvas.saveState()
        width, _ = doc.pagesize
        canvas.setStrokeColor(colors.HexColor("#cbd5e1"))
        canvas.setLineWidth(0.35)
        canvas.line(doc_obj.leftMargin, 11.5 * mm, width - doc_obj.rightMargin, 11.5 * mm)
        canvas.setFillColor(colors.HexColor("#475569"))
        canvas.setFont("Helvetica", 7.2)
        canvas.drawString(doc_obj.leftMargin, 7 * mm, footer_line_1[:160])
        canvas.drawString(doc_obj.leftMargin, 4.2 * mm, footer_line_2[:160])
        canvas.drawRightString(width - doc_obj.rightMargin, 4.2 * mm, f"Page {doc_obj.page}")
        canvas.restoreState()

    doc.build(elements, onFirstPage=_draw_footer, onLaterPages=_draw_footer)
    buffer.seek(0)
    filename = f"Pharmacy_Current_Stock_Statement_{unit}_Store{store_id}_{from_date}_to_{to_date}.pdf"
    return buffer, filename, None


def _run_pharmacy_current_stock_statement_export_job(
    job_id: str,
    unit: str,
    store_id: int,
    from_date: str,
    to_date: str,
    export_format: str,
    exported_by: str,
):
    fmt = "pdf" if str(export_format or "").strip().lower() == "pdf" else "xlsx"
    _excel_job_update(job_id, state="running", format=fmt)
    try:
        if fmt == "pdf":
            buffer, filename, err = _build_pharmacy_current_stock_statement_pdf_buffer(
                unit, store_id, from_date, to_date, exported_by
            )
            data = buffer.getvalue() if buffer else None
        else:
            data, filename, err = _build_pharmacy_current_stock_statement_excel(
                unit, store_id, from_date, to_date, exported_by
            )
        if not data:
            _excel_job_update(job_id, state="error", error=err or "No data available to export", format=fmt)
            return
        _export_cache_put_bytes("pharmacy_current_stock_statement_job", data, job_id)
        _excel_job_update(job_id, state="done", filename=filename, format=fmt)
    except Exception as exc:
        _excel_job_update(job_id, state="error", error=str(exc), format=fmt)


@app.route('/api/mis/pharmacy/current_stock_statement/export_job', methods=["POST"])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_pharmacy_current_stock_statement_export_job():
    payload = request.get_json(silent=True) or {}
    unit = (payload.get("unit") or request.args.get("unit") or "").strip().upper()
    store_id_raw = (payload.get("store_id") or request.args.get("store_id") or "").strip()
    from_date = (payload.get("from") or payload.get("from_date") or request.args.get("from") or "").strip()
    to_date = (payload.get("to") or payload.get("to_date") or request.args.get("to") or "").strip()
    export_format = (payload.get("format") or request.args.get("format") or "xlsx").strip().lower()
    allowed_units = _allowed_units_for_session()

    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return jsonify({"status": "error", "message": "Please select a unit"}), 400
    if unit not in allowed_units:
        return jsonify({"status": "error", "message": f"Unit {unit} not permitted"}), 403
    if not store_id_raw:
        return jsonify({"status": "error", "message": "Please select a store"}), 400
    try:
        store_id = int(store_id_raw)
    except Exception:
        return jsonify({"status": "error", "message": "Invalid store id"}), 400
    if not from_date or not to_date:
        return jsonify({"status": "error", "message": "Please select a valid date range"}), 400
    from_dt = _ph_stmt_parse_iso_date(from_date)
    to_dt = _ph_stmt_parse_iso_date(to_date)
    if not from_dt or not to_dt:
        return jsonify({"status": "error", "message": "Invalid date format. Use YYYY-MM-DD"}), 400
    if from_dt > to_dt:
        return jsonify({"status": "error", "message": f"Invalid date range: from ({from_date}) must be <= to ({to_date})"}), 400
    if export_format not in {"xlsx", "pdf"}:
        return jsonify({"status": "error", "message": "Invalid export format. Use xlsx or pdf"}), 400

    exported_by = session.get("username") or session.get("user") or "Unknown"
    job_id = token_hex(16)
    _excel_job_update(job_id, state="queued", filename=None, format=export_format)
    EXPORT_EXECUTOR.submit(
        _run_pharmacy_current_stock_statement_export_job,
        job_id,
        unit,
        store_id,
        from_date,
        to_date,
        export_format,
        exported_by,
    )
    return jsonify({"status": "queued", "job_id": job_id, "format": export_format})


@app.route('/api/mis/pharmacy/current_stock_statement/export_job_status')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_pharmacy_current_stock_statement_export_job_status():
    job_id = (request.args.get("job_id") or "").strip()
    if not job_id:
        return jsonify({"status": "error", "message": "Missing job id"}), 400
    entry = _excel_job_get(job_id)
    if not entry:
        return jsonify({"status": "error", "message": "Job not found"}), 404
    return jsonify({
        "status": "success",
        "state": entry.get("state"),
        "error": entry.get("error"),
        "filename": entry.get("filename"),
        "format": entry.get("format") or "xlsx",
    })


@app.route('/api/mis/pharmacy/current_stock_statement/export_job_result')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_pharmacy_current_stock_statement_export_job_result():
    job_id = (request.args.get("job_id") or "").strip()
    if not job_id:
        return "Missing job id", 400
    entry = _excel_job_get(job_id)
    if not entry:
        return "Job not found", 404
    if entry.get("state") != "done":
        return "Job not ready", 409
    data = _export_cache_get_bytes("pharmacy_current_stock_statement_job", job_id)
    if not data:
        return "Export expired. Please queue a fresh export.", 404
    filename = str(entry.get("filename") or "Pharmacy_Current_Stock_Statement.xlsx")
    fmt = str(entry.get("format") or ("pdf" if filename.lower().endswith(".pdf") else "xlsx")).lower()
    mimetype = "application/pdf" if fmt == "pdf" else "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    return send_file(
        io.BytesIO(data),
        as_attachment=True,
        download_name=filename,
        mimetype=mimetype,
    )


@app.route('/api/mis/pharmacy/current_stock/export_excel')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_pharmacy_current_stock_export_excel():
    import io
    import pandas as pd

    unit = (request.args.get("unit") or "").strip().upper()
    store_id_raw = (request.args.get("store_id") or "").strip()
    snapshot_date = (request.args.get("snapshot_date") or "").strip()
    allowed_units = _allowed_units_for_session()

    if not allowed_units:
        return "No unit access assigned", 403
    if not unit:
        if len(allowed_units) == 1:
            unit = allowed_units[0]
        else:
            return "Please select a unit", 400
    if unit not in allowed_units:
        return f"Unit {unit} not permitted", 403
    if not store_id_raw:
        return "Please select a store", 400
    try:
        store_id = int(store_id_raw)
    except Exception:
        return "Invalid store id", 400

    df, source, snapshot_time, store_name = _get_pharmacy_stock_df(unit, store_id, snapshot_date or None)
    if df is None or df.empty:
        return "No data available to export", 404

    store_name = store_name or _lookup_store_name(unit, store_id) or f"Store {store_id}"
    source_label = "Snapshot" if source == "snapshot" else "Live"
    if snapshot_date:
        source_label = f"{source_label} ({snapshot_date})"

    df = df.copy()
    df["ExpiryDate"] = pd.to_datetime(df["ExpiryDate"], errors="coerce")

    export_cols = [
        ("ItemName", "Item Name"),
        ("BatchName", "Batch"),
        ("ExpiryDate", "Expiry"),
        ("Qty", "Qty"),
        ("Rate", "Rate"),
        ("MRP", "MRP"),
        ("PurchaseValue", "Purchase Value"),
        ("SaleValue", "Sale Value"),
        ("GroupName", "Group"),
        ("SubGroupName", "Sub Group"),
    ]
    col_map = {src: label for src, label in export_cols}
    df = df[[c for c, _ in export_cols if c in df.columns]].rename(columns=col_map)

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
        wb = writer.book
        ws_name = "Current Stock"
        df.to_excel(writer, sheet_name=ws_name, index=False, startrow=5)
        ws = writer.sheets[ws_name]

        title_fmt = wb.add_format({
            "bold": True, "font_size": 14, "font_color": "#1E3A8A",
            "align": "center", "valign": "vcenter"
        })
        subtitle_fmt = wb.add_format({
            "bold": True, "font_size": 11, "align": "center", "valign": "vcenter"
        })
        meta_fmt = wb.add_format({"font_size": 9, "align": "center", "valign": "vcenter"})
        header_fmt = wb.add_format({
            "bold": True, "bg_color": "#1E3A8A", "font_color": "white",
            "border": 1, "align": "center", "valign": "vcenter"
        })
        date_fmt = wb.add_format({"num_format": "yyyy-mm-dd", "align": "center", "valign": "vcenter"})
        qty_fmt = wb.add_format({"num_format": "#,##,##0", "align": "right", "valign": "vcenter"})
        money_fmt = wb.add_format({"num_format": "#,##,##0.00", "align": "right", "valign": "vcenter"})

        last_col = len(df.columns) - 1
        ws.merge_range(0, 0, 0, last_col, "Current Stock (Store Wise)", title_fmt)
        ws.merge_range(1, 0, 1, last_col, f"Unit: {unit} | Store: {store_name}", subtitle_fmt)
        ws.merge_range(2, 0, 2, last_col, f"Source: {source_label}", meta_fmt)

        exported_by = session.get("username") or session.get("user") or "Unknown"
        exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
        ws.merge_range(3, 0, 3, last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)

        for col_num, col_name in enumerate(df.columns):
            ws.write(5, col_num, col_name, header_fmt)
            if col_name == "Expiry":
                ws.set_column(col_num, col_num, 12, date_fmt)
            elif col_name == "Qty":
                ws.set_column(col_num, col_num, 10, qty_fmt)
            elif col_name in {"Rate", "MRP", "Purchase Value", "Sale Value"}:
                ws.set_column(col_num, col_num, 16, money_fmt)
            else:
                ws.set_column(col_num, col_num, 22)

        footer_row = 6 + len(df)
        ws.merge_range(footer_row, 0, footer_row, last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)
        ws.freeze_panes(6, 0)

    output.seek(0)
    filename = f"Pharmacy_Current_Stock_{unit}_Store{store_id}.xlsx"
    return send_file(
        output,
        as_attachment=True,
        download_name=filename,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    )


