def _build_supplier_params(
    supplier_id: int,
    supplier: dict,
    code: str,
    name: str,
    city_id: int,
    state_id: int,
    updated_by: int,
    now_str: str,
    existing: dict | None = None,
):
    def _existing(keys, default=""):
        return _row_value(existing, keys, default) if existing else default

    def _payload(key, default=""):
        if key in supplier:
            val = supplier.get(key)
            return "" if val is None else val
        return default

    def _payload_int(key, default=0, existing_keys=None):
        if key in supplier:
            return _safe_int(supplier.get(key), default)
        if existing_keys:
            return _safe_int(_existing(existing_keys, default), default)
        return default

    date_of_association = _payload(
        "date_of_association",
        _existing(["DateOfAssociation"], now_str) or now_str,
    )

    return {
        "pId": int(supplier_id or 0),
        "pCode": code,
        "pName": name,
        "pAddress": _payload("address", _existing(["Address"]) or ""),
        "pCity": _safe_int(city_id),
        "pState": _safe_int(state_id),
        "pPin": _payload("pin", _existing(["Pin"]) or ""),
        "pContactperson": _payload("contact_person", _existing(["ContactPerson"]) or ""),
        "pContactdesignation": _payload("contact_designation", _existing(["ContactDesignation"]) or ""),
        "pGroupid": _payload_int("group_id", 0, ["GroupID", "GroupId", "Groupid"]),
        "pCreditperiod": _payload_int("credit_period", 0, ["CreditPeriod"]),
        "pDateofassociation": date_of_association,
        "pFax": _payload("fax", _existing(["Fax"]) or ""),
        "pPhone1": _payload("phone1", _existing(["Phone1"]) or ""),
        "pPhone2": _payload("phone2", _existing(["Phone2"]) or ""),
        "pCellphone": _payload("cellphone", _existing(["CellPhone", "Cellphone"]) or ""),
        "pEmail": _payload("email", _existing(["Email"]) or ""),
        "pWeb": _payload("web", _existing(["Web"]) or ""),
        "pCst": _payload("cst", _existing(["CST"]) or ""),
        "pMst": _payload("mst", _existing(["MST"]) or ""),
        "pTds": _payload("tds", _existing(["TDS"]) or ""),
        "pExcisecode": _payload("excise_code", _existing(["ExciseCode"]) or ""),
        "pExportcode": _payload("export_code", _existing(["ExportCode"]) or ""),
        "pLedgerid": _payload_int("ledger_id", 0, ["LedgerID", "LedgerId"]),
        "pEligableforadv": _payload_int("eligible_for_adv", 0, ["EligableForAdv", "EligibleForAdv"]),
        "pBankname": _payload("bank_name", _existing(["BankName"]) or ""),
        "pBankbranch": _payload("bank_branch", _existing(["BankBranch"]) or ""),
        "pBankacno": _payload("bank_account", _existing(["BankAcNo", "BankAcNO"]) or ""),
        "pMcirno": _payload("mcir_no", _existing(["MCIRNo", "MCIRNO"]) or ""),
        "pNote": _payload("note", _existing(["Note"]) or ""),
        "pProposed": _payload("proposed", _existing(["Proposed"]) or ""),
        "pUpdatedby": updated_by,
        "pUpdatedon": now_str,
        "pSupptype": _payload("supplier_type", _existing(["SuppType"]) or ""),
        "pSociety": _payload("society", _existing(["Society"]) or ""),
        "pLandmark": _payload("landmark", _existing(["Landmark", "landmark"]) or ""),
        "pIncomeTaxNo": _payload("income_tax_no", _existing(["IncomeTaxNo"]) or "0"),
        "pVillage": _payload_int("village_id", 0, ["VillageID", "VillageId"]),
        "pPaytermsid": _payload_int("pay_terms_id", 0, ["Paytermsid", "PayTermsId", "PayTermsID"]),
    }


def _build_manufacturer_params(
    manufacturer_id: int,
    manufacturer: dict,
    code: str,
    name: str,
    city_id: int,
    state_id: int,
    updated_by: int,
    now_str: str,
    existing: dict | None = None,
):
    def _existing(keys, default=""):
        return _row_value(existing, keys, default) if existing else default

    def _payload(key, default=""):
        if key in manufacturer:
            val = manufacturer.get(key)
            return "" if val is None else val
        return default

    def _payload_int(key, default=0, existing_keys=None):
        if key in manufacturer:
            return _safe_int(manufacturer.get(key), default)
        if existing_keys:
            return _safe_int(_existing(existing_keys, default), default)
        return default

    def _payload_bool(key, default=1, existing_keys=None):
        if key in manufacturer:
            return 1 if manufacturer.get(key) else 0
        if existing_keys:
            existing_val = _existing(existing_keys, None)
            if existing_val is not None:
                return 1 if _safe_int(existing_val, default) else 0
        return 1 if default else 0

    entered_on = _payload("entered_on", _existing(["EnteredOn", "Enteredon"], now_str) or now_str)
    entered_by = _payload_int("entered_by", updated_by, ["EnteredBy", "Enteredby", "Entered_By"])
    active = _payload_bool("active", 1, ["Active"])

    return {
        "pId": int(manufacturer_id or 0),
        "pCode": code,
        "pName": name,
        "pAddress": _payload("address", _existing(["Address"]) or ""),
        "pCity": _safe_int(city_id),
        "pState": _safe_int(state_id),
        "pPin": _payload("pin", _existing(["Pin"]) or ""),
        "pContactperson": _payload("contact_person", _existing(["ContactPerson"]) or ""),
        "pContactdesignation": _payload("contact_designation", _existing(["ContactDesignation"]) or ""),
        "pPhone1": _payload("phone1", _existing(["Phone1"]) or ""),
        "pPhone2": _payload("phone2", _existing(["Phone2"]) or ""),
        "pCellphone": _payload("cellphone", _existing(["CellPhone", "Cellphone"]) or ""),
        "pWeb": _payload("web", _existing(["Web"]) or ""),
        "pEmail": _payload("email", _existing(["Email"]) or ""),
        "pBankname": _payload("bank_name", _existing(["BankName"]) or ""),
        "pBankacno": _payload("bank_account", _existing(["BankAcNo", "BankAcNO"]) or ""),
        "pBankbranch": _payload("bank_branch", _existing(["BankBranch"]) or ""),
        "pNote": _payload("note", _existing(["Note"]) or ""),
        "pActive": active,
        "pEnteredon": entered_on,
        "pEnteredby": entered_by,
        "pUpdatedon": now_str,
        "pUpdatedby": updated_by,
        "pSociety": _payload("society", _existing(["Society"]) or ""),
        "pLandmark": _payload("landmark", _existing(["Landmark", "landmark"]) or ""),
        "pVillage": _payload_int("village_id", 0, ["VillageID", "VillageId"]),
    }


def _ensure_item_masters_for_po(unit: str, items: list, now_str: str):
    if _role_base(session.get("role") or "") == "Executive":
        blocked = []
        seen = set()
        for item in items:
            item_id = _safe_int(item.get("item_id"))
            name = str(item.get("item_name") or "").strip()
            if item_id or not name:
                continue
            key = name.lower()
            if key in seen:
                continue
            seen.add(key)
            blocked.append(name)
        if blocked:
            preview = ", ".join(blocked[:3])
            more = f" (+{len(blocked) - 3} more)" if len(blocked) > 3 else ""
            return [], [f"Executive role cannot create item masters. Items: {preview}{more}."]
        return [], []

    pending_new_items = []
    for item in (items or []):
        item_id = _safe_int(item.get("item_id"))
        name = str(item.get("item_name") or "").strip()
        if item_id or not name:
            continue
        pending_new_items.append(item)
    if not pending_new_items:
        return [], []

    meta = _load_item_master_lists(unit)
    defaults = meta.get("defaults", {})
    lookups = meta.get("lookups", {})
    allow_zero_rate_mrp = _unit_allows_zero_rate_mrp(unit)
    default_store_name = _default_store_name_for_unit(unit)

    missing_errors = []
    for item in pending_new_items:
        item_id = _safe_int(item.get("item_id"))
        name = str(item.get("item_name") or "").strip()
        if item_id or not name:
            continue
        store_name = str(item.get("item_code") or item.get("store_name") or "").strip()
        if not store_name and default_store_name:
            store_name = default_store_name
            item["item_code"] = store_name
        unit_name = _normalize_purchase_unit_text(item.get("unit") or "")
        pack_size_id = _safe_int(item.get("pack_size_id"))
        rate = _safe_float(item.get("rate"))
        mrp = _safe_float(item.get("mrp"))
        gst_pct = _safe_float(item.get("gst_pct"))
        missing = []
        if not store_name and not item.get("location_id"):
            missing.append("store")
        if not pack_size_id:
            missing.append("pack size")
        if not unit_name and not _safe_int(item.get("unit_id")):
            missing.append("unit")
        if rate < 0 or (rate <= 0 and not allow_zero_rate_mrp):
            missing.append("rate")
        if mrp < 0 or (mrp <= 0 and not allow_zero_rate_mrp):
            missing.append("mrp")
        if gst_pct < 0:
            missing.append("gst")
        if missing:
            missing_errors.append(f"Item '{name}' missing {', '.join(missing)}.")
    if missing_errors:
        return [], missing_errors

    user_token = str(session.get("user_id") or session.get("user") or session.get("username") or "1")
    created = []
    create_errors = []
    for item in pending_new_items:
        item_id = _safe_int(item.get("item_id"))
        name = str(item.get("item_name") or "").strip()
        if item_id or not name:
            continue

        unit_name = _normalize_purchase_unit_text(item.get("unit") or "")
        unit_id = _safe_int(item.get("unit_id"))
        if unit_id <= 0:
            if not unit_name:
                create_errors.append(f"Item '{name}': unit is required.")
                continue
            unit_id_resolved, unit_err = _ensure_purchase_unit_master_entry(unit, unit_name)
            if unit_err:
                create_errors.append(f"Item '{name}' unit '{unit_name}': {unit_err}")
                continue
            unit_id = unit_id_resolved

        gst_pct = _safe_float(item.get("gst_pct"))
        store_name = str(item.get("item_code") or item.get("store_name") or "").strip()
        if not store_name and default_store_name:
            store_name = default_store_name
            item["item_code"] = store_name
        item_payload = {
            "name": name,
            "descriptive_name": item.get("descriptive_name") or name,
            "product_code": item.get("product_code") or "",
            "item_type_id": defaults.get("item_type_id"),
            "item_group_id": defaults.get("item_group_id"),
            "sub_group_id": defaults.get("sub_group_id"),
            "unit_id": unit_id,
            "unit_name": unit_name,
            "store_name": store_name,
            "pack_size_id": _safe_int(item.get("pack_size_id"), defaults.get("pack_size_id")),
            "standard_rate": _safe_float(item.get("rate")),
            "sales_price": _safe_float(item.get("mrp")),
            "gst_pct": gst_pct,
            "expiry_required": True,
            "batch_required": False,
            "loose_selling": False,
            "quality_control": False,
            "active": True,
            "vat_on": "P",
            "medicine_type_id": defaults.get("medicine_type_id"),
        }

        params = _build_item_master_params(item_payload, defaults, lookups, user_token, now_str, request.remote_addr)
        result = data_fetch.add_iv_item(unit, params)
        if result.get("error"):
            create_errors.append(f"Item '{name}': {result['error']}")
            continue
        new_id = result.get("item_id")
        if new_id:
            item["item_id"] = int(new_id)
            created.append({"id": int(new_id), "name": name})
    return created, create_errors


@app.route('/api/mis/store/stores')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_store_stores():
    unit, error = _get_store_mis_unit()
    if error:
        return error

    df = data_fetch.fetch_pharmacy_stores(unit)
    if df is None:
        return jsonify({"status": "error", "message": "Failed to fetch stores"}), 500
    if df.empty:
        return jsonify({"status": "success", "unit": unit, "stores": []})

    df = _clean_df_columns(df)
    cols_map = {str(c).strip().lower(): c for c in df.columns}
    id_col = cols_map.get("id") or cols_map.get("storeid") or cols_map.get("store_id")
    name_col = cols_map.get("name") or cols_map.get("storename") or cols_map.get("store_name")
    if not id_col:
        return jsonify({"status": "error", "message": "Store id column missing"}), 500

    stores = []
    for _, row in df.iterrows():
        sid = row.get(id_col)
        if sid is None:
            continue
        try:
            sid = int(sid)
        except Exception:
            continue
        sname = str(row.get(name_col) or "").strip() if name_col else ""
        stores.append({"id": sid, "name": sname})

    stores = sorted(stores, key=lambda s: (s["name"] or "", s["id"]))
    return jsonify({"status": "success", "unit": unit, "stores": stores})


@app.route('/api/mis/store/current_stock')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_mis_store_current_stock():
    unit, error = _get_store_mis_unit()
    if error:
        return error

    store_id_raw = (request.args.get("store_id") or "").strip()
    if not store_id_raw:
        return jsonify({"status": "error", "message": "Please select a store"}), 400
    try:
        store_id = int(store_id_raw)
    except Exception:
        return jsonify({"status": "error", "message": "Invalid store id"}), 400

    df, source, _, store_name = _get_pharmacy_stock_df(unit, store_id, None)
    if df is None:
        return jsonify({"status": "error", "message": "Failed to fetch current stock"}), 500
    if df.empty:
        return jsonify({"status": "success", "unit": unit, "store_id": store_id, "rows": []})

    df = df.replace({pd.NA: None, np.nan: None})
    df = df.where(pd.notna(df), None)
    payload = {
        "status": "success",
        "unit": unit,
        "store_id": store_id,
        "rows": df.to_dict(orient="records"),
        "source": source or "live",
    }
    if store_name:
        payload["store_name"] = store_name
    return jsonify(payload)


def _build_store_current_stock_excel(unit: str, store_id: int, exported_by: str | None):
    import io
    import pandas as pd

    df, source, _, store_name = _get_pharmacy_stock_df(unit, store_id, None)
    if df is None or df.empty:
        return None, None

    store_name = store_name or _lookup_store_name(unit, store_id) or f"Store {store_id}"
    source_label = "Snapshot" if source == "snapshot" else "Live"

    df = df.copy()
    df["ExpiryDate"] = pd.to_datetime(df["ExpiryDate"], errors="coerce")

    export_cols = [
        ("ItemName", "Item Name"),
        ("BatchName", "Batch"),
        ("ExpiryDate", "Expiry"),
        ("Qty", "Qty"),
        ("Rate", "Rate"),
        ("MRP", "MRP"),
        ("PurchaseValue", "Purchase Value"),
        ("SaleValue", "Sale Value"),
        ("GroupName", "Group"),
        ("SubGroupName", "Sub Group"),
    ]
    col_map = {src: label for src, label in export_cols}
    df = df[[c for c, _ in export_cols if c in df.columns]].rename(columns=col_map)

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
        wb = writer.book
        ws_name = "Current Stock"
        df.to_excel(writer, sheet_name=ws_name, index=False, startrow=5)
        ws = writer.sheets[ws_name]

        title_fmt = wb.add_format({
            "bold": True, "font_size": 14, "font_color": "#1E3A8A",
            "align": "center", "valign": "vcenter"
        })
        subtitle_fmt = wb.add_format({
            "bold": True, "font_size": 11, "align": "center", "valign": "vcenter"
        })
        meta_fmt = wb.add_format({"font_size": 9, "align": "center", "valign": "vcenter"})
        header_fmt = wb.add_format({
            "bold": True, "bg_color": "#1E3A8A", "font_color": "white",
            "border": 1, "align": "center", "valign": "vcenter"
        })
        date_fmt = wb.add_format({"num_format": "yyyy-mm-dd", "align": "center", "valign": "vcenter"})
        qty_fmt = wb.add_format({"num_format": "#,##,##0", "align": "right", "valign": "vcenter"})
        money_fmt = wb.add_format({"num_format": "#,##,##0.00", "align": "right", "valign": "vcenter"})

        last_col = len(df.columns) - 1
        ws.merge_range(0, 0, 0, last_col, "General Store Current Stock", title_fmt)
        ws.merge_range(1, 0, 1, last_col, f"Unit: {unit} | Store: {store_name}", subtitle_fmt)
        ws.merge_range(2, 0, 2, last_col, f"Source: {source_label}", meta_fmt)

        exported_by = exported_by or "Unknown"
        exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")
        ws.merge_range(3, 0, 3, last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", meta_fmt)

        for col_num, col_name in enumerate(df.columns):
            ws.write(5, col_num, col_name, header_fmt)
            if col_name == "Expiry":
                ws.set_column(col_num, col_num, 12, date_fmt)
            elif col_name == "Qty":
                ws.set_column(col_num, col_num, 10, qty_fmt)
            elif col_name in {"Rate", "MRP", "Purchase Value", "Sale Value"}:
                ws.set_column(col_num, col_num, 16, money_fmt)
            else:
                ws.set_column(col_num, col_num, 22)

        footer_row = 6 + len(df)
        ws.merge_range(footer_row, 0, footer_row, last_col, "Copyright: (c) ASARFI HOSPITAL", meta_fmt)
        ws.freeze_panes(6, 0)

    output.seek(0)
    filename = f"General_Store_Current_Stock_{unit}_Store{store_id}.xlsx"
    return output, filename


