@app.route('/api/export_occupancy_snapshot')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_export_occupancy_snapshot():
    """Export snapshot data to Excel"""
    try:
        date = request.args.get('date')
        if not date:
            return jsonify({"status": "error", "message": "Date parameter required"}), 400
        
        _ensure_snapshot_detail_table()
        
        allowed_units = _allowed_units_for_session()
        if not allowed_units:
            return jsonify({"status": "error", "message": "No unit access"}), 403

        cache_key = (date, ",".join(sorted(allowed_units)))
        cached = _export_cache_get_bytes("occ_snap_xlsx", cache_key)
        if cached:
            return send_file(
                io.BytesIO(cached),
                as_attachment=True,
                download_name=f"Occupancy_Snapshot_{date}.xlsx",
                mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
            )
        
        with sqlite3.connect(_abs_local_db_path()) as conn:
            placeholders = ','.join('?' * len(allowed_units))
            query = f"""
                SELECT unit, ward, patient_subtype, occupied, clinically_discharged,
                       vacant, total_beds, occupancy_rate, snapshot_time
                FROM occupancy_snapshot_detail
                WHERE snapshot_date = ? AND unit IN ({placeholders})
                ORDER BY unit, ward, patient_subtype
            """
            rows = conn.execute(query, [date] + allowed_units).fetchall()
            doc_query = f"""
                SELECT unit, doctor, occupied
                FROM occupancy_snapshot_doctor
                WHERE snapshot_date = ? AND unit IN ({placeholders})
                ORDER BY unit, occupied DESC, doctor
            """
            doc_rows = conn.execute(doc_query, [date] + allowed_units).fetchall()
        
        if not rows:
            return jsonify({"status": "error", "message": "No data for this date"}), 404
        
        # Prepare data for Excel - FIXED to match frontend
        export_data = []
        for row in rows:
            unit, ward, subtype, occ, disch, vac, total, rate, snap_time = row
            total_active = occ + disch
            export_data.append({
                'Unit': unit,
                'Ward': ward,
                'Patient Sub-Type': subtype,
                'Occupied': occ,
                'Clinically Discharged': disch,
                'Total Active (Beds Used)': total_active,
                'Snapshot Time': snap_time
            })
        
        df = pd.DataFrame(export_data)
        doctor_export = [
            {
                "Unit": (unit or "").upper(),
                "Doctor": doctor or "Unknown Doctor",
                "Occupied Patients": int(occupied or 0)
            }
            for unit, doctor, occupied in doc_rows
        ]
        doctor_df = pd.DataFrame(doctor_export)
        
        # Create Excel file
        export_dir = os.path.join("data", "exports")
        os.makedirs(export_dir, exist_ok=True)
        file_name = f"Occupancy_Snapshot_{date}.xlsx"
        file_path = os.path.join(export_dir, file_name)
        
        with pd.ExcelWriter(file_path, engine="xlsxwriter") as writer:
            wb = writer.book
            
            # Format definitions
            header_fmt = wb.add_format({
                "bold": True, "bg_color": "#1e3a8a",
                "font_color": "white", "align": "center",
                "valign": "vcenter", "border": 1
            })
            
            # Write data
            df.to_excel(writer, index=False, sheet_name="Ward Summary")
            ws = writer.sheets["Ward Summary"]
            
            # Apply header formatting
            for col_num, value in enumerate(df.columns.values):
                ws.write(0, col_num, value, header_fmt)
            
            # Auto-fit columns
            for i, col in enumerate(df.columns):
                col_len = df[col].astype(str).apply(len).max() if not df.empty else 0
                max_len = max(col_len, len(col)) + 2
                ws.set_column(i, i, max_len)
            
            ws.freeze_panes(1, 0)

            if doctor_df.empty:
                doctor_df = pd.DataFrame(columns=["Unit", "Doctor", "Occupied Patients"])
            doctor_df.to_excel(writer, index=False, sheet_name="Doctor Summary")
            ws_doc = writer.sheets["Doctor Summary"]
            for col_num, value in enumerate(doctor_df.columns.values):
                ws_doc.write(0, col_num, value, header_fmt)
            for i, col in enumerate(doctor_df.columns):
                max_len = max(doctor_df[col].astype(str).apply(len).max() if not doctor_df.empty else 0, len(col)) + 2
                ws_doc.set_column(i, i, max_len)
            ws_doc.freeze_panes(1, 0)
        
        try:
            with open(file_path, "rb") as f:
                _export_cache_put_bytes("occ_snap_xlsx", f.read(), cache_key)
        except Exception:
            pass
        return send_file(file_path, as_attachment=True)
        
    except Exception as e:
        print(f"Error exporting snapshot: {e}")
        return jsonify({"status": "error", "message": str(e)}), 500


@app.route('/_clear_snapshots')
@login_required(allowed_roles={"IT"})
def _clear_snapshots():
    """Clear all snapshot data - IT only"""
    try:
        with sqlite3.connect(_abs_local_db_path()) as conn:
            conn.execute("DELETE FROM occupancy_snapshot_detail")
            conn.commit()
        
        return jsonify({
            "status": "success",
            "message": "All snapshots cleared"
        })
    except Exception as e:
        import traceback
        return jsonify({
            "status": "error",
            "message": str(e),
            "traceback": traceback.format_exc()
        }), 500
    

def _build_occupancy_pdf(rows, title_text: str, subtitle_text: str, doctor_summary=None):
    from reportlab.lib import colors
    from reportlab.lib.pagesizes import A4
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.units import inch
    from reportlab.lib.enums import TA_CENTER
    from io import BytesIO
    buffer = BytesIO()
    doc = SimpleDocTemplate(buffer, pagesize=A4, topMargin=0.5*inch, bottomMargin=0.5*inch)
    elements = []

    styles = getSampleStyleSheet()
    title_style = ParagraphStyle(
        'CustomTitle',
        parent=styles['Heading1'],
        fontSize=18,
        textColor=colors.HexColor('#1e3a8a'),
        spaceAfter=12,
        alignment=TA_CENTER,
        fontName='Helvetica-Bold'
    )

    date_style = ParagraphStyle(
        'DateStyle',
        parent=styles['Normal'],
        fontSize=12,
        textColor=colors.HexColor('#475569'),
        spaceAfter=20,
        alignment=TA_CENTER
    )

    unit_style = ParagraphStyle(
        'UnitStyle',
        parent=styles['Heading2'],
        fontSize=14,
        textColor=colors.HexColor('#1e3a8a'),
        spaceAfter=8,
        spaceBefore=12,
        fontName='Helvetica-Bold'
    )

    elements.append(Paragraph(title_text, title_style))
    elements.append(Paragraph(subtitle_text, date_style))

    units_data = {}
    subtype_summary = {}
    grand_active = 0
    grand_total = 0

    for row in rows:
        unit, ward, subtype, occ, disch, vac, total = row
        unit = (unit or "").upper()
        ward = ward or "Unknown Ward"
        subtype_label = subtype or "Unspecified"
        occ_val = (occ or 0) + (disch or 0)
        grand_active += occ_val
        grand_total += total or (occ_val + (vac or 0))
        units_data.setdefault(unit, {}).setdefault(ward, []).append((occ, disch, vac, total))
        subtype_summary.setdefault(unit, {}).setdefault(subtype_label, 0)
        subtype_summary[unit][subtype_label] += occ_val

    summary_style = ParagraphStyle(
        'SummaryStyle',
        parent=styles['Normal'],
        fontSize=12,
        textColor=colors.HexColor('#0f172a'),
        spaceAfter=12,
        alignment=TA_CENTER
    )
    grand_vacant = max(grand_total - grand_active, 0)
    summary_text = f"Total Occupied: {grand_active:,}    \u2022    Total Vacant: {grand_vacant:,}"
    elements.append(Paragraph(summary_text, summary_style))

    for unit in ['AHL', 'ACI', 'BALLIA']:
        if unit not in units_data:
            continue
        unit_display = 'Ballia' if unit == 'BALLIA' else unit
        elements.append(Paragraph(f'{unit_display} Unit', unit_style))

        ward_data = [['Ward Name', 'Occupied Beds', 'Vacant Beds', 'Occupancy %']]
        for ward, ward_rows in sorted(units_data[unit].items()):
            total_occupied = sum((occ or 0) + (disch or 0) for occ, disch, vac, total in ward_rows)
            total_vacant = sum(vac or 0 for occ, disch, vac, total in ward_rows)
            total_beds = sum(total or 0 for occ, disch, vac, total in ward_rows)
            occupancy_pct = round((total_occupied / total_beds * 100), 1) if total_beds else 0
            ward_data.append([ward, str(total_occupied), str(total_vacant), f'{occupancy_pct}%'])

        ward_table = Table(ward_data, colWidths=[3*inch, 1.5*inch, 1.5*inch, 1.5*inch])
        ward_table.setStyle(TableStyle([
            ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#1e3a8a')),
            ('TEXTCOLOR', (0, 0), (-1, 0), colors.whitesmoke),
            ('ALIGN', (0, 0), (-1, 0), 'CENTER'),
            ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
            ('FONTSIZE', (0, 0), (-1, 0), 11),
            ('BOTTOMPADDING', (0, 0), (-1, 0), 12),
            ('TOPPADDING', (0, 0), (-1, 0), 12),
            ('BACKGROUND', (0, 1), (-1, -1), colors.white),
            ('TEXTCOLOR', (0, 1), (-1, -1), colors.HexColor('#0f172a')),
            ('ALIGN', (1, 1), (-1, -1), 'CENTER'),
            ('ALIGN', (0, 1), (0, -1), 'LEFT'),
            ('FONTNAME', (0, 1), (-1, -1), 'Helvetica'),
            ('FONTSIZE', (0, 1), (-1, -1), 10),
            ('BOTTOMPADDING', (0, 1), (-1, -1), 8),
            ('TOPPADDING', (0, 1), (-1, -1), 8),
            ('GRID', (0, 0), (-1, -1), 1, colors.HexColor('#e2e8f0')),
            ('LINEBELOW', (0, 0), (-1, 0), 2, colors.HexColor('#1e3a8a')),
            ('ROWBACKGROUNDS', (0, 1), (-1, -1), [colors.white, colors.HexColor('#f8fafc')]),
        ]))

        elements.append(ward_table)
        elements.append(Spacer(1, 0.3*inch))

    section_style = ParagraphStyle(
        'SectionStyle',
        parent=styles['Heading2'],
        fontSize=14,
        textColor=colors.HexColor('#1e3a8a'),
        spaceAfter=8,
        spaceBefore=16,
        fontName='Helvetica-Bold',
        alignment=TA_CENTER
    )

    table_style = TableStyle([
        ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#0f172a')),
        ('TEXTCOLOR', (0, 0), (-1, 0), colors.whitesmoke),
        ('ALIGN', (0, 0), (-1, 0), 'CENTER'),
        ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
        ('FONTSIZE', (0, 0), (-1, 0), 11),
        ('BOTTOMPADDING', (0, 0), (-1, 0), 10),
        ('TOPPADDING', (0, 0), (-1, 0), 10),
        ('BACKGROUND', (0, 1), (-1, -1), colors.white),
        ('TEXTCOLOR', (0, 1), (-1, -1), colors.HexColor('#0f172a')),
        ('ALIGN', (1, 1), (1, -1), 'CENTER'),
        ('FONTNAME', (0, 1), (-1, -1), 'Helvetica'),
        ('FONTSIZE', (0, 1), (-1, -1), 10),
        ('BOTTOMPADDING', (0, 1), (-1, -1), 8),
        ('TOPPADDING', (0, 1), (-1, -1), 8),
        ('GRID', (0, 0), (-1, -1), 1, colors.HexColor('#e2e8f0')),
        ('ROWBACKGROUNDS', (0, 1), (-1, -1), [colors.white, colors.HexColor('#f8fafc')]),
    ])

    if any(subtype_summary.values()):
        elements.append(Paragraph('Patient Subtype-wise Occupied Beds', section_style))
        for unit in ['AHL', 'ACI', 'BALLIA']:
            summary_map = subtype_summary.get(unit)
            if not summary_map:
                continue
            unit_display = 'Ballia' if unit == 'BALLIA' else unit
            rows_data = [['Patient Subtype', 'Occupied Beds']]
            total_unit = 0
            for subtype_label, count in sorted(summary_map.items(), key=lambda x: (-x[1], x[0])):
                rows_data.append([subtype_label, str(int(count))])
                total_unit += count
            rows_data.append(['Total', str(int(total_unit))])
            elements.append(Paragraph(f'{unit_display} Unit', unit_style))
            table = Table(rows_data, colWidths=[4*inch, 2*inch])
            table.setStyle(table_style)
            elements.append(table)
            elements.append(Spacer(1, 0.2*inch))

    if doctor_summary:
        elements.append(Paragraph('Doctor-wise Occupancy (Occupied Patients)', section_style))
        for unit in ['AHL', 'ACI', 'BALLIA']:
            doctors = doctor_summary.get(unit)
            if not doctors:
                continue
            unit_display = 'Ballia' if unit == 'BALLIA' else unit
            rows_data = [['Doctor', 'Occupied Patients']]
            total_unit = 0
            for doctor_name, count in sorted(doctors, key=lambda x: (-x[1], x[0])):
                rows_data.append([doctor_name, str(int(count))])
                total_unit += count
            rows_data.append(['Total', str(int(total_unit))])
            elements.append(Paragraph(f'{unit_display} Unit', unit_style))
            doc_table = Table(rows_data, colWidths=[4*inch, 2*inch])
            doc_table.setStyle(table_style)
            elements.append(doc_table)
            elements.append(Spacer(1, 0.2*inch))

    doc.build(elements)
    buffer.seek(0)
    return buffer


def _build_occupancy_average_pdf(rows, title_text: str, subtitle_text: str):
    from reportlab.lib import colors
    from reportlab.lib.pagesizes import A4
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.units import inch
    from reportlab.lib.enums import TA_CENTER
    from io import BytesIO

    buffer = BytesIO()
    doc = SimpleDocTemplate(buffer, pagesize=A4, topMargin=0.5*inch, bottomMargin=0.5*inch)
    elements = []

    styles = getSampleStyleSheet()
    title_style = ParagraphStyle(
        'AvgOccTitle',
        parent=styles['Heading1'],
        fontSize=18,
        textColor=colors.HexColor('#1e3a8a'),
        spaceAfter=12,
        alignment=TA_CENTER,
        fontName='Helvetica-Bold'
    )
    subtitle_style = ParagraphStyle(
        'AvgOccSubtitle',
        parent=styles['Normal'],
        fontSize=12,
        textColor=colors.HexColor('#475569'),
        spaceAfter=10,
        alignment=TA_CENTER
    )
    summary_style = ParagraphStyle(
        'AvgOccSummary',
        parent=styles['Normal'],
        fontSize=11,
        textColor=colors.HexColor('#0f172a'),
        spaceAfter=14,
        alignment=TA_CENTER
    )
    unit_style = ParagraphStyle(
        'AvgOccUnit',
        parent=styles['Heading2'],
        fontSize=14,
        textColor=colors.HexColor('#1e3a8a'),
        spaceAfter=8,
        spaceBefore=10,
        fontName='Helvetica-Bold'
    )

    elements.append(Paragraph(title_text, title_style))
    elements.append(Paragraph(subtitle_text, subtitle_style))

    units_data = {}
    total_active = 0
    total_vacant = 0
    total_beds = 0
    rate_sum = 0.0

    for row in rows:
        unit = (row.get("unit") or "").upper()
        units_data.setdefault(unit, []).append(row)
        total_active += int(row.get("occupied") or 0)
        total_vacant += int(row.get("vacant") or 0)
        total_beds += int(row.get("total_beds") or 0)
        rate_sum += float(row.get("rate") or 0)

    simple_avg = (rate_sum / len(rows)) * 100.0 if rows else 0.0
    weighted_avg = (total_active / total_beds) * 100.0 if total_beds else 0.0
    days = len({r.get("date") for r in rows})

    summary_text = (
        f"Weighted Avg: {weighted_avg:.2f}%   |   "
        f"Simple Avg: {simple_avg:.2f}%   |   "
        f"Days: {days}   |   "
        f"Total Occupied: {total_active:,}   |   "
        f"Total Vacant: {total_vacant:,}"
    )
    elements.append(Paragraph(summary_text, summary_style))

    units_order = [u for u in ["AHL", "ACI", "BALLIA"] if u in units_data]
    for u in sorted(units_data.keys()):
        if u not in units_order:
            units_order.append(u)

    table_style = TableStyle([
        ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#1e3a8a')),
        ('TEXTCOLOR', (0, 0), (-1, 0), colors.whitesmoke),
        ('ALIGN', (0, 0), (-1, 0), 'CENTER'),
        ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
        ('FONTSIZE', (0, 0), (-1, 0), 11),
        ('BOTTOMPADDING', (0, 0), (-1, 0), 10),
        ('TOPPADDING', (0, 0), (-1, 0), 10),
        ('BACKGROUND', (0, 1), (-1, -1), colors.white),
        ('TEXTCOLOR', (0, 1), (-1, -1), colors.HexColor('#0f172a')),
        ('ALIGN', (1, 1), (-1, -1), 'CENTER'),
        ('ALIGN', (0, 1), (0, -1), 'LEFT'),
        ('FONTNAME', (0, 1), (-1, -1), 'Helvetica'),
        ('FONTSIZE', (0, 1), (-1, -1), 10),
        ('BOTTOMPADDING', (0, 1), (-1, -1), 8),
        ('TOPPADDING', (0, 1), (-1, -1), 8),
        ('GRID', (0, 0), (-1, -1), 1, colors.HexColor('#e2e8f0')),
        ('LINEBELOW', (0, 0), (-1, 0), 2, colors.HexColor('#1e3a8a')),
        ('ROWBACKGROUNDS', (0, 1), (-1, -1), [colors.white, colors.HexColor('#f8fafc')]),
    ])

    for unit in units_order:
        rows_for_unit = units_data.get(unit)
        if not rows_for_unit:
            continue
        unit_display = 'Ballia' if unit == 'BALLIA' else unit
        elements.append(Paragraph(f'{unit_display} Unit', unit_style))

        table_rows = [['Date', 'Occupied Beds', 'Vacant Beds', 'Total Beds', 'Occupancy %']]
        for r in sorted(rows_for_unit, key=lambda x: x.get("date") or ""):
            date_str = r.get("date") or ""
            try:
                date_str = datetime.strptime(date_str, "%Y-%m-%d").strftime("%d %b %Y")
            except Exception:
                pass
            table_rows.append([
                date_str,
                str(int(r.get("occupied") or 0)),
                str(int(r.get("vacant") or 0)),
                str(int(r.get("total_beds") or 0)),
                f'{float(r.get("rate") or 0) * 100:.1f}%'
            ])

        table = Table(table_rows, colWidths=[1.7*inch, 1.3*inch, 1.3*inch, 1.3*inch, 1.3*inch])
        table.setStyle(table_style)
        elements.append(table)
        elements.append(Spacer(1, 0.25*inch))

    doc.build(elements)
    buffer.seek(0)
    return buffer

def _build_occupancy_snapshot_pdf_buffer(date: str, allowed_units: list[str]):
    if not date or not allowed_units:
        return None

    cache_key = (date, ",".join(sorted(allowed_units)))
    cached = _export_cache_get_bytes("occ_snap_pdf", cache_key)
    if cached:
        return io.BytesIO(cached)

    _ensure_snapshot_detail_table()
    with sqlite3.connect(_abs_local_db_path()) as conn:
        placeholders = ','.join('?' * len(allowed_units))
        query = f"""
            SELECT unit, ward, patient_subtype, occupied, clinically_discharged,
                   vacant, total_beds
            FROM occupancy_snapshot_detail
            WHERE snapshot_date = ? AND unit IN ({placeholders})
            ORDER BY unit, ward, patient_subtype
        """
        rows = conn.execute(query, [date] + allowed_units).fetchall()
        doc_query = f"""
            SELECT unit, doctor, occupied
            FROM occupancy_snapshot_doctor
            WHERE snapshot_date = ? AND unit IN ({placeholders})
            ORDER BY unit, occupied DESC
        """
        doc_rows = conn.execute(doc_query, [date] + allowed_units).fetchall()

    if not rows:
        return None

    doctor_summary = {}
    for unit, doctor_name, occupied in doc_rows:
        doctor_summary.setdefault((unit or "").upper(), []).append((
            doctor_name or "Unknown Doctor",
            int(occupied or 0)
        ))

    subtitle = datetime.strptime(date, '%Y-%m-%d').strftime('%d %B %Y')
    buffer = _build_occupancy_pdf(rows, 'Occupancy Snapshot Report', subtitle, doctor_summary)

    try:
        _export_cache_put_bytes("occ_snap_pdf", buffer.getvalue(), cache_key)
    except Exception:
        pass
    return buffer

@app.route('/api/export_occupancy_snapshot_pdf')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def export_occupancy_snapshot_pdf():
    """Export occupancy snapshot as PDF with ward-level summary"""
    from datetime import datetime

    date = request.args.get('date')
    if not date:
        return jsonify({'status': 'error', 'message': 'Date parameter required'}), 400

    try:
        allowed_units = _allowed_units_for_session()
        if not allowed_units:
            return jsonify({'status': 'error', 'message': 'No unit access'}), 403

        buffer = _build_occupancy_snapshot_pdf_buffer(date, allowed_units)
        if buffer is None:
            return jsonify({'status': 'error', 'message': 'No data found for this date'}), 404
        return send_file(
            buffer,
            mimetype='application/pdf',
            as_attachment=True,
            download_name=f'Occupancy_Snapshot_{date}.pdf'
        )

    except Exception as e:
        print(f"PDF export error: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({'status': 'error', 'message': str(e)}), 500





@app.route('/api/export_occupancy_average_pdf')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def export_occupancy_average_pdf():
    """Export average occupancy between two dates as PDF."""
    from_date = (request.args.get("from") or "").strip()
    to_date = (request.args.get("to") or "").strip()
    unit = (request.args.get("unit") or "").strip().upper()

    if not from_date or not to_date:
        return jsonify({'status': 'error', 'message': 'from/to dates are required'}), 400

    try:
        from_dt = datetime.strptime(from_date, "%Y-%m-%d").date()
        to_dt = datetime.strptime(to_date, "%Y-%m-%d").date()
    except ValueError:
        return jsonify({'status': 'error', 'message': 'Invalid date format (expected YYYY-MM-DD)'}), 400

    if from_dt > to_dt:
        return jsonify({'status': 'error', 'message': 'from date cannot be after to date'}), 400

    allowed_units = _allowed_units_for_session()
    if not allowed_units:
        return jsonify({'status': 'error', 'message': 'No unit access'}), 403

    if unit and unit != "ALL":
        if unit not in allowed_units:
            return jsonify({'status': 'error', 'message': 'Unit not allowed'}), 403
        units_to_use = [unit]
    else:
        units_to_use = allowed_units
    buffer = _build_occupancy_average_pdf_buffer(from_date, to_date, units_to_use)
    if buffer is None:
        return jsonify({'status': 'error', 'message': 'No snapshot data for this range'}), 404

    return send_file(
        buffer,
        mimetype='application/pdf',
        as_attachment=True,
        download_name=f'Average_Occupancy_{from_date}_to_{to_date}.pdf'
    )


def _build_occupancy_average_pdf_buffer(from_date: str, to_date: str, units_to_use: list[str]):
    if not from_date or not to_date or not units_to_use:
        return None

    cache_key = (from_date, to_date, ",".join(sorted(units_to_use)))
    cached = _export_cache_get_bytes("occ_avg_pdf", cache_key)
    if cached:
        return io.BytesIO(cached)

    _ensure_local_store()
    with sqlite3.connect(_abs_local_db_path()) as conn:
        placeholders = ','.join('?' * len(units_to_use))
        query = f"""
            SELECT snapshot_date, unit, occupied, clinically_discharged,
                   vacant, total_beds, occupancy_rate
            FROM occupancy_snapshot
            WHERE snapshot_date BETWEEN ? AND ? AND unit IN ({placeholders})
            ORDER BY unit, snapshot_date
        """
        rows = conn.execute(query, [from_date, to_date] + units_to_use).fetchall()

    if not rows:
        return None

    payload_rows = []
    for snap_date, unit_name, occ, disch, vac, total, rate in rows:
        active = int(occ or 0) + int(disch or 0)
        total_beds = int(total or 0)
        if total_beds <= 0:
            total_beds = active + int(vac or 0)
        rate_val = float(rate) if rate is not None else (active / total_beds if total_beds else 0.0)
        payload_rows.append({
            "date": snap_date,
            "unit": unit_name,
            "occupied": active,
            "vacant": int(vac or 0),
            "total_beds": total_beds,
            "rate": rate_val
        })

    subtitle = f"Period: {from_date} to {to_date}"
    buffer = _build_occupancy_average_pdf(payload_rows, "Average Occupancy Summary", subtitle)

    try:
        _export_cache_put_bytes("occ_avg_pdf", buffer.getvalue(), cache_key)
    except Exception:
        pass
    return buffer



def _collect_current_occupancy_rows(allowed_units: list[str]):
    # Fetch live occupancy rows grouped by ward + patient subtype and doctor totals.
    today = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
    analytics_units = set(_analytics_units_upper())
    allowed_set = {u.upper() for u in (allowed_units or []) if u.upper() in analytics_units} or analytics_units

    db_cfgs = getattr(config, "DB_CONFIGS", {}) or {}
    if db_cfgs and allowed_set:
        db_cfgs = {u: cfg for u, cfg in db_cfgs.items() if u.upper() in allowed_set}
    if not db_cfgs:
        chosen_cfg = _pick_db_cfg_for_proc()
        if not chosen_cfg:
            return [], {}
        db_cfgs = {"_FALLBACK_": chosen_cfg}

    rows = []
    doctor_summary = {}

    for unit_name, cfg in db_cfgs.items():
        unit_key = unit_name.upper()
        if unit_key == "_FALLBACK_" and allowed_units:
            unit_key = allowed_units[0].upper()
        try:
            conn_str = _build_conn_str_from_dbconfig(cfg)
            with pyodbc.connect(conn_str, timeout=30) as conn:
                try:
                    df = pd.read_sql(
                        "EXEC dbo.usp_RptIPDPatient_Occupancy @FromDate=?, @ToDate=?",
                        conn,
                        params=(today, today)
                    )
                except Exception:
                    df = pd.read_sql("EXEC dbo.usp_RptIPDPatient_Occupancy", conn)

            if df is None or df.empty:
                continue

            df = df.where(pd.notna(df), None)

            ward_col = next((c for c in [
                "Ward_Name", "WardName", "Ward", "WardDesc", "WardDescription"
            ] if c in df.columns), None)
            if not ward_col:
                ward_col = "Ward"
                df[ward_col] = "Unknown Ward"

            subtype_col = next((c for c in [
                "PatientSubType", "Patient_SubType", "Patient_Sub_Type",
                "SubType", "Sub_Type", "PatientCategory", "Category"
            ] if c in df.columns), None)

            status_col = next((c for c in [
                "Status", "PatientStatus", "ClinicalStatus",
                "DischargeStatus", "CurrentStatus", "CaseStatus"
            ] if c in df.columns), None)

            if "Bed_ID" not in df.columns:
                continue

            def _get_color(row):
                st = (str(row.get(status_col) or "")).lower() if status_col else ""
                if "clinic" in st and "disch" in st:
                    return "yellow"
                if "occup" in st:
                    return "green"
                if "vac" in st:
                    return "blue"
                has_patient = any([
                    row.get("Patient"),
                    row.get("Patient_Name"),
                    row.get("Regno"),
                    row.get("Visit_ID")
                ])
                return "green" if has_patient else "blue"

            df["_Color"] = df.apply(_get_color, axis=1)
            df["_Ward"] = df[ward_col].fillna("Unknown Ward").astype(str)
            if subtype_col:
                df["_SubType"] = df[subtype_col].fillna("Not Specified").astype(str)
            else:
                df["_SubType"] = "Not Specified"

            cols_map = {str(c).strip().lower(): c for c in df.columns}
            doctor_col = next((cols_map[c.lower()] for c in [
                "Consultant", "ConsultantName", "Consultant_Name",
                "Doctor", "DoctorName", "Doctor_Name",
                "DoctorIncharge", "DoctorInCharge", "TreatingDoctor",
                "Doctor_name"
            ] if c.lower() in cols_map), None)
            if doctor_col:
                df["_Doctor"] = df[doctor_col].fillna("Unknown Doctor").astype(str).str.strip()
                df["_Doctor"] = df["_Doctor"].replace("", "Unknown Doctor")
            else:
                df["_Doctor"] = "Unknown Doctor"

            grouped = df.groupby(["_Ward", "_SubType"])["_Color"].value_counts().unstack(fill_value=0)
            for (ward, subtype), row in grouped.iterrows():
                green = int(row.get("green", 0))
                yellow = int(row.get("yellow", 0))
                blue = int(row.get("blue", 0))
                total = green + yellow + blue
                rows.append((
                    unit_key,
                    str(ward).strip(),
                    str(subtype).strip() or "Not Specified",
                    green, yellow, blue, total
                ))

            active_mask = df["_Color"].isin(["green", "yellow"])
            doc_counts = df[active_mask].groupby("_Doctor")["_Color"].count()
            for doctor_name, count in doc_counts.items():
                doctor_summary.setdefault(unit_key, []).append((
                    str(doctor_name).strip() or "Unknown Doctor",
                    int(count)
                ))

        except Exception as ex:
            print(f"Current occupancy summary failed for {unit_key}: {ex}")
            continue

    for unit in list(doctor_summary.keys()):
        doctor_summary[unit] = sorted(doctor_summary[unit], key=lambda x: x[1], reverse=True)

    return rows, doctor_summary




@app.route('/api/export_current_occupancy_pdf')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def export_current_occupancy_pdf():
    """Export current live occupancy summary to PDF."""
    from datetime import datetime

    allowed_units = _allowed_units_for_session()
    if not allowed_units:
        return jsonify({'status': 'error', 'message': 'No unit access'}), 403

    try:
        buffer = _build_current_occupancy_pdf_buffer(allowed_units)
        if buffer is None:
            return jsonify({'status': 'error', 'message': 'No occupancy data available'}), 404
        today = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
        return send_file(
            buffer,
            mimetype='application/pdf',
            as_attachment=True,
            download_name=f'Current_Occupancy_{today}.pdf'
        )

    except Exception as e:
        print(f"Current occupancy PDF error: {e}")
        return jsonify({'status': 'error', 'message': str(e)}), 500


def _build_current_occupancy_pdf_buffer(allowed_units: list[str]):
    if not allowed_units:
        return None
    cache_key = ",".join(sorted(allowed_units))
    cached = _export_cache_get_bytes("current_occ_pdf", cache_key)
    if cached:
        return io.BytesIO(cached)

    rows_for_pdf, doctor_summary = _collect_current_occupancy_rows(allowed_units)
    if not rows_for_pdf:
        return None

    subtitle = datetime.now(tz=LOCAL_TZ).strftime('As of %d %B %Y, %I:%M %p')
    buffer = _build_occupancy_pdf(rows_for_pdf, 'Current Occupancy Summary', subtitle, doctor_summary)

    try:
        _export_cache_put_bytes("current_occ_pdf", buffer.getvalue(), cache_key)
    except Exception:
        pass
    return buffer





@app.route('/api/export_current_occupancy_excel')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def export_current_occupancy_excel():
    """Export current occupancy summary to Excel (ward + doctor wise)."""
    from datetime import datetime

    allowed_units = _allowed_units_for_session()
    if not allowed_units:
        return jsonify({'status': 'error', 'message': 'No unit access'}), 403

    cache_key = ",".join(sorted(allowed_units))
    cached = _export_cache_get_bytes("current_occ_xlsx", cache_key)
    if cached:
        stamp = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d_%H%M")
        return send_file(
            io.BytesIO(cached),
            mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            as_attachment=True,
            download_name=f"Current_Occupancy_{stamp}.xlsx"
        )

    try:
        rows_for_excel, doctor_summary = _collect_current_occupancy_rows(allowed_units)
        if not rows_for_excel:
            return jsonify({'status': 'error', 'message': 'No occupancy data available'}), 404

        ward_rows = [{
            "Unit": unit,
            "Ward": ward,
            "Patient Sub-Type": subtype,
            "Occupied": occ,
            "Clinically Discharged": disch,
            "Vacant": vac,
            "Total Beds": total
        } for unit, ward, subtype, occ, disch, vac, total in rows_for_excel]

        doctor_rows = []
        for unit, docs in (doctor_summary or {}).items():
            for doctor_name, count in docs:
                doctor_rows.append({
                    "Unit": unit,
                    "Doctor": doctor_name,
                    "Occupied Patients": count
                })

        if not doctor_rows:
            doctor_rows = []

        ward_df = pd.DataFrame(ward_rows)
        doctor_df = pd.DataFrame(doctor_rows)

        buffer = io.BytesIO()
        with pd.ExcelWriter(buffer, engine="xlsxwriter") as writer:
            wb = writer.book
            header_fmt = wb.add_format({
                "bold": True, "bg_color": "#1e3a8a",
                "font_color": "white", "align": "center",
                "valign": "vcenter", "border": 1
            })

            ward_sheet = "Ward Summary"
            ward_df.to_excel(writer, index=False, sheet_name=ward_sheet)
            ws = writer.sheets[ward_sheet]
            for col_num, value in enumerate(ward_df.columns):
                ws.write(0, col_num, value, header_fmt)
            for i, col in enumerate(ward_df.columns):
                col_len = ward_df[col].astype(str).apply(len).max() if not ward_df.empty else 0
                ws.set_column(i, i, max(col_len, len(col)) + 2)
            ws.freeze_panes(1, 0)

            doctor_sheet = "Doctor Summary"
            if doctor_df.empty:
                doctor_df = pd.DataFrame(columns=["Unit", "Doctor", "Occupied Patients"])
            doctor_df.to_excel(writer, index=False, sheet_name=doctor_sheet)
            ws_doc = writer.sheets[doctor_sheet]
            for col_num, value in enumerate(doctor_df.columns):
                ws_doc.write(0, col_num, value, header_fmt)
            for i, col in enumerate(doctor_df.columns):
                col_len = doctor_df[col].astype(str).apply(len).max() if not doctor_df.empty else 0
                ws_doc.set_column(i, i, max(col_len, len(col)) + 2)
            ws_doc.freeze_panes(1, 0)

        buffer.seek(0)
        stamp = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d_%H%M")
        _export_cache_put_bytes("current_occ_xlsx", buffer.getvalue(), cache_key)
        return send_file(
            buffer,
            mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            as_attachment=True,
            download_name=f"Current_Occupancy_{stamp}.xlsx"
        )

    except Exception as e:
        print(f"Current occupancy Excel error: {e}")
        return jsonify({'status': 'error', 'message': str(e)}), 500
    
# ============================================================
# Background revenue warmer + midnight snapshot threads
# ============================================================
BACKGROUND_REFRESH_INTERVAL = int(os.getenv("REV_AUTO_REFRESH_SECS", "300"))  # seconds (default 5 min)

def _background_revenue_warmer():
    while True:
        try:
            today = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d")
            start_prefetch(today, today)
            start_prefetch_breakdowns(today, today)
        except Exception as e:
            print(f"[WARN] Background revenue warmer error: {e}")
        time.sleep(max(60, BACKGROUND_REFRESH_INTERVAL))  # never below 60s

def _midnight_snapshot_daemon():
    """Sleep until local midnight, build & persist occupancy snapshot daily."""
    while True:
        try:
            secs = _seconds_until_next_midnight()
            print(f"Next snapshot in {secs//3600}h {(secs%3600)//60}m")
            time.sleep(secs)
            
            # Save both summary and detailed snapshots
            overall = _build_overall_once()
            if overall:
                _save_occupancy_snapshot(overall)  # Summary
            
            _save_occupancy_snapshot_with_subtype()  # Detailed with PatientSubType
            
            try:
                _save_pharmacy_stock_snapshot()
            except Exception as e:
                print(f"WARNING: Midnight pharmacy stock snapshot error: {e}")

            print("Midnight occupancy snapshot saved (summary + detail).")
            time.sleep(60)
        except Exception as e:
            print(f"[WARN] Midnight snapshot error: {e}")
            time.sleep(120)
            
# --- Start background tasks exactly once per process ---

def _warm_current_occupancy_exports():
    """
    Background pre-warm for current occupancy PDF/Excel; uses all configured units.
    """
    try:
        allowed_units = _analytics_units_upper()
        if not allowed_units:
            return
        rows_for_pdf, doctor_summary = _collect_current_occupancy_rows(allowed_units)
        if not rows_for_pdf:
            return

        subtitle = datetime.now(tz=LOCAL_TZ).strftime('As of %d %B %Y, %I:%M %p')
        pdf_buf = _build_occupancy_pdf(rows_for_pdf, 'Current Occupancy Summary', subtitle, doctor_summary)
        _export_cache_put_bytes("current_occ_pdf", pdf_buf.getvalue(), ",".join(sorted(allowed_units)))

        ward_rows = [{
            "Unit": unit,
            "Ward": ward,
            "Patient Sub-Type": subtype,
            "Occupied": occ,
            "Clinically Discharged": disch,
            "Vacant": vac,
            "Total Beds": total
        } for unit, ward, subtype, occ, disch, vac, total in rows_for_pdf]

        doctor_rows = []
        for unit, docs in (doctor_summary or {}).items():
            for doctor_name, count in docs:
                doctor_rows.append({
                    "Unit": unit,
                    "Doctor": doctor_name,
                    "Occupied Patients": count
                })

        import pandas as _pd
        ward_df = _pd.DataFrame(ward_rows)
        doctor_df = _pd.DataFrame(doctor_rows)

        buffer = io.BytesIO()
        with _pd.ExcelWriter(buffer, engine="xlsxwriter") as writer:
            wb = writer.book
            header_fmt = wb.add_format({"bold": True, "bg_color": "#1e3a8a", "font_color": "white", "align": "center"})
            ward_df.to_excel(writer, index=False, sheet_name="Ward Summary")
            ws = writer.sheets["Ward Summary"]
            for col_num, value in enumerate(ward_df.columns):
                ws.write(0, col_num, value, header_fmt)
            for i, col in enumerate(ward_df.columns):
                col_len = ward_df[col].astype(str).apply(len).max() if not ward_df.empty else 0
                ws.set_column(i, i, max(col_len, len(col)) + 2)
            ws.freeze_panes(1, 0)

            if doctor_df.empty:
                doctor_df = _pd.DataFrame(columns=["Unit", "Doctor", "Occupied Patients"])
            doctor_df.to_excel(writer, index=False, sheet_name="Doctor Summary")
            ws_doc = writer.sheets["Doctor Summary"]
            for col_num, value in enumerate(doctor_df.columns):
                ws_doc.write(0, col_num, value, header_fmt)
            for i, col in enumerate(doctor_df.columns):
                col_len = doctor_df[col].astype(str).apply(len).max() if not doctor_df.empty else 0
                ws_doc.set_column(i, i, max(col_len, len(col)) + 2)
            ws_doc.freeze_panes(1, 0)

        buffer.seek(0)
        _export_cache_put_bytes("current_occ_xlsx", buffer.getvalue(), ",".join(sorted(allowed_units)))
    except Exception as e:
        print(f"Export warm failed: {e}")
        return

_bg_started = False
_bg_lock = Lock()

def _ensure_bg_started():
    """Start background threads (revenue warmer + midnight snapshot) once."""
    global _bg_started
    with _bg_lock:
        if _bg_started:
            return
        # start revenue warmer if enabled
        if BACKGROUND_REFRESH_INTERVAL > 0:
            t = Thread(target=_background_revenue_warmer, daemon=True)
            t.start()
            print(f"Revenue background warmer running every {BACKGROUND_REFRESH_INTERVAL}s")
        # explicit catch-up once at startup if snapshot window was missed
        # run asynchronously so app startup is never blocked by DB latency
        Thread(target=_run_mod_snapshot_startup_catchup, daemon=True).start()
        # start midnight snapshot thread
        Thread(target=_midnight_snapshot_daemon, daemon=True).start()
        # start night report snapshot thread
        Thread(target=_night_report_snapshot_daemon, daemon=True).start()
        # start morning report snapshot thread (08:00)
        Thread(target=_morning_report_snapshot_daemon, daemon=True).start()
        # start scheduled fund-position history mail thread (00:10 IST)
        if FUND_POSITION_SCHEDULE_ENABLED:
            Thread(target=_fund_position_scheduled_mail_daemon, daemon=True).start()
        # warm export caches in background (non-blocking)
        try:
            EXPORT_EXECUTOR.submit(_warm_current_occupancy_exports)
        except Exception:
            pass
        _bg_started = True
        print("Background tasks started (warmer + midnight snapshot)")

# Optionally start threads at import if env requests it
if os.environ.get("START_BG_ON_IMPORT", "0").lower() in ("1", "true", "yes"):
    try:
        _ensure_bg_started()
    except Exception as e:
        print(f"[WARN] Import-time background start failed: {e}")

# Flask 3.x: no before_first_request - use a guarded before_request instead
@app.before_request
def _kickoff_backgrounds():
    if not getattr(app, "_bg_init_done", False):
        _ensure_bg_started()
        app._bg_init_done = True

