@app.route('/api/volume_export')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_volume_export():
    import io
    f = (request.args.get('from') or '').strip()
    t = (request.args.get('to') or '').strip()
    req_unit = (request.args.get('unit') or '').strip().upper()
    if not f or not t:
        return jsonify({"status":"error","message":"Missing date range"}), 400

    allowed_units = _analytics_allowed_units_for_session()
    if not allowed_units:
        return jsonify({"status":"error","message":"No unit access assigned"}), 403

    units_to_use = [req_unit] if (req_unit and req_unit in allowed_units) else allowed_units

    try:
        # First try: whatever your existing function returns
        details_df = _get_or_fetch_volume_details(units_to_use, f, t)

        # Guarantee a real Unit column:
        need_unit = ("Unit" not in details_df.columns) or (details_df["Unit"].astype(str).str.strip().eq("").all())
        if need_unit:
            # If only one unit, stamp it
            if len(units_to_use) == 1:
                details_df = details_df.copy()
                details_df["Unit"] = units_to_use[0].upper()
            else:
                # Multi-unit: fetch per unit separately and tag
                parts = []
                for u in units_to_use:
                    df_u = _get_or_fetch_volume_details([u], f, t)
                    if df_u is not None and not df_u.empty:
                        df_u = df_u.copy()
                        df_u["Unit"] = u.upper()
                        parts.append(df_u)
                if parts:
                    import pandas as pd
                    details_df = pd.concat(parts, ignore_index=True)
                else:
                    # fall back to the original even if empty
                    pass

        xlsx_bytes = build_volume_excel(details_df, from_date=f, to_date=t)  # updated writer below
        fname = f"Volume_Tracker_{('_'+req_unit) if (req_unit and req_unit in allowed_units) else '_ALL'}_{f}_to_{t}.xlsx"
        return send_file(
            io.BytesIO(xlsx_bytes),
            as_attachment=True,
            download_name=fname,
            mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
        )
    except Exception as e:
        print(f"/api/volume_export error: {e}")
        return jsonify({"status":"error","message":"Export failed"}), 500


@app.route('/api/volume_hcv_doctor_export')
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def api_volume_hcv_doctor_export():
    import io

    f = (request.args.get('from') or '').strip()
    t = (request.args.get('to') or '').strip()
    req_unit = (request.args.get('unit') or '').strip().upper()
    search_query = (request.args.get('search') or '').strip()
    if not f or not t:
        return jsonify({"status": "error", "message": "Missing date range"}), 400

    allowed_units = _analytics_allowed_units_for_session()
    if not allowed_units:
        return jsonify({"status": "error", "message": "No unit access assigned"}), 403

    units_to_use = [req_unit] if (req_unit and req_unit in allowed_units) else allowed_units
    if not units_to_use:
        return jsonify({"status": "error", "message": "No valid unit in scope"}), 403

    try:
        raw_df = _get_or_fetch_volume_hcv_doctor_details(units_to_use, f, t)
        if raw_df is None or raw_df.empty:
            return jsonify({"status": "error", "message": "No HCV doctor visit data found for selected range"}), 404

        total_before_filter = int(len(raw_df))
        export_df = _filter_volume_hcv_doctor_rows(raw_df, search_query)
        if export_df is None or export_df.empty:
            return jsonify({"status": "error", "message": "No HCV doctor visit data matches current search filter"}), 404

        export_df = export_df.copy()
        if "Unit" not in export_df.columns:
            export_df["Unit"] = ""
        export_df["Unit"] = export_df["Unit"].astype(str).str.strip().str.upper()
        for col in ["HCVId", "VisitId", "PatientId", "PackageId"]:
            if col in export_df.columns:
                export_df[col] = pd.to_numeric(export_df[col], errors="coerce")

        def _series(col: str, default=""):
            if col in export_df.columns:
                return export_df[col]
            return pd.Series([default] * len(export_df))

        details_export = pd.DataFrame(
            {
                "SL": pd.Series(range(1, len(export_df) + 1), dtype="int64"),
                "Unit": _series("Unit", ""),
                "HCV ID": _series("HCVId", np.nan),
                "Visit ID": _series("VisitId", np.nan),
                "Visit No": _series("VisitNo", ""),
                "Visit Date": _series("VisitDate", ""),
                "Reg No": _series("RegNo", ""),
                "Patient Name": _series("PatientName", ""),
                "Corp Type": _series("CorpType", ""),
                "Department": _series("Dept", ""),
                "Doctor": _series("Consultant", ""),
                "Package ID": _series("PackageId", np.nan),
            }
        )

        patient_count = 0
        if "PatientId" in export_df.columns:
            patient_count = int(pd.to_numeric(export_df["PatientId"], errors="coerce").dropna().nunique())
        if patient_count <= 0:
            patient_count = int(
                details_export["Reg No"]
                .astype(str)
                .str.strip()
                .replace({"": np.nan})
                .dropna()
                .nunique()
            )

        doctor_count = int(
            details_export["Doctor"]
            .astype(str)
            .str.strip()
            .replace({"": np.nan})
            .dropna()
            .nunique()
        )
        department_count = int(
            details_export["Department"]
            .astype(str)
            .str.strip()
            .replace({"": np.nan})
            .dropna()
            .nunique()
        )
        package_count = int(pd.to_numeric(details_export["Package ID"], errors="coerce").dropna().nunique())
        unit_count = int(
            details_export["Unit"]
            .astype(str)
            .str.strip()
            .replace({"": np.nan})
            .dropna()
            .nunique()
        )
        exported_rows = int(len(details_export))
        unit_scope = units_to_use[0] if len(units_to_use) == 1 else "ALL"
        export_mode = "Filtered" if search_query else "Full"
        exported_by = (session.get("username") or session.get("user") or "Unknown").strip() or "Unknown"
        exported_at = datetime.now(tz=LOCAL_TZ).strftime("%Y-%m-%d %H:%M:%S")

        unit_summary = (
            details_export.groupby("Unit", dropna=False)
            .size()
            .reset_index(name="Visit Count")
            .sort_values(["Visit Count", "Unit"], ascending=[False, True])
        )
        dept_summary = (
            details_export.assign(Department=details_export["Department"].astype(str).str.strip().replace({"": "Unknown"}))
            .groupby("Department", dropna=False)
            .size()
            .reset_index(name="Visit Count")
            .sort_values(["Visit Count", "Department"], ascending=[False, True])
        )
        doctor_summary = (
            details_export.assign(Doctor=details_export["Doctor"].astype(str).str.strip().replace({"": "Unknown"}))
            .groupby("Doctor", dropna=False)
            .size()
            .reset_index(name="Visit Count")
            .sort_values(["Visit Count", "Doctor"], ascending=[False, True])
        )
        def _pkg_display(v):
            if pd.isna(v):
                return "N/A"
            txt = str(v).strip()
            if not txt:
                return "N/A"
            try:
                num = float(txt)
                if num.is_integer():
                    return str(int(num))
                return txt
            except Exception:
                return txt

        package_summary = (
            details_export.assign(PackageDisplay=details_export["Package ID"].apply(_pkg_display))
            .groupby("PackageDisplay", dropna=False)
            .size()
            .reset_index(name="Visit Count")
            .rename(columns={"PackageDisplay": "Package ID"})
            .sort_values(["Visit Count", "Package ID"], ascending=[False, True])
        )

        output = io.BytesIO()
        with pd.ExcelWriter(output, engine="xlsxwriter") as writer:
            wb = writer.book
            wb.set_properties(
                {
                    "title": "Volume Tracker - Healthcheckup Doctor Visits",
                    "author": exported_by,
                    "company": "ASARFI HOSPITAL",
                    "comments": "Generated from Volume Tracker",
                }
            )

            title_fmt = wb.add_format(
                {
                    "bold": True,
                    "font_size": 14,
                    "font_color": "#FFFFFF",
                    "bg_color": "#1E3A8A",
                    "align": "center",
                    "valign": "vcenter",
                }
            )
            subtitle_fmt = wb.add_format(
                {
                    "bold": True,
                    "font_size": 10,
                    "font_color": "#334155",
                    "align": "center",
                    "valign": "vcenter",
                }
            )
            meta_label_fmt = wb.add_format(
                {
                    "bold": True,
                    "font_color": "#1F4F7A",
                    "bg_color": "#EAF2FB",
                    "border": 1,
                    "align": "left",
                    "valign": "vcenter",
                }
            )
            meta_value_fmt = wb.add_format(
                {
                    "font_color": "#102A43",
                    "border": 1,
                    "align": "left",
                    "valign": "vcenter",
                }
            )
            section_fmt = wb.add_format(
                {
                    "bold": True,
                    "font_color": "#0F172A",
                    "bg_color": "#DBEAFE",
                    "border": 1,
                    "align": "left",
                }
            )
            header_fmt = wb.add_format(
                {
                    "bold": True,
                    "font_color": "#FFFFFF",
                    "bg_color": "#1F5B8F",
                    "border": 1,
                    "align": "center",
                    "valign": "vcenter",
                    "text_wrap": True,
                }
            )
            text_fmt = wb.add_format({"border": 1, "align": "left", "valign": "vcenter"})
            int_fmt = wb.add_format({"border": 1, "align": "right", "valign": "vcenter", "num_format": "0"})
            id_fmt = wb.add_format({"border": 1, "align": "right", "valign": "vcenter", "num_format": "0"})

            footer_exported_by = exported_by.replace("&", "and")
            footer_exported_at = exported_at.replace("&", "and")
            footer_text = (
                f"&LExported By: {footer_exported_by}"
                f"&CPage &P of &N"
                f"&RExported At: {footer_exported_at} | (c) ASARFI HOSPITAL"
            )

            summary_ws = wb.add_worksheet("Summary")
            writer.sheets["Summary"] = summary_ws
            summary_ws.hide_gridlines(2)
            summary_ws.set_zoom(110)
            summary_last_col = 5
            summary_ws.merge_range(
                0,
                0,
                0,
                summary_last_col,
                "Volume Tracker - Healthcheckup Doctor Visits",
                title_fmt,
            )
            summary_ws.merge_range(
                1,
                0,
                1,
                summary_last_col,
                "Professional Summary Export",
                subtitle_fmt,
            )

            meta_pairs = [
                ("Unit Scope", unit_scope),
                ("Date Range", f"{f} to {t}"),
                ("Search Filter", search_query or "(none)"),
                ("Export Mode", export_mode),
                ("Exported By", exported_by),
                ("Exported At", exported_at),
            ]
            row = 3
            for idx in range(0, len(meta_pairs), 2):
                k1, v1 = meta_pairs[idx]
                summary_ws.write(row, 0, k1, meta_label_fmt)
                summary_ws.merge_range(row, 1, row, 2, str(v1), meta_value_fmt)
                if idx + 1 < len(meta_pairs):
                    k2, v2 = meta_pairs[idx + 1]
                    summary_ws.write(row, 3, k2, meta_label_fmt)
                    summary_ws.merge_range(row, 4, row, 5, str(v2), meta_value_fmt)
                row += 1

            row += 1
            summary_ws.write(row, 0, "KPI Metrics", section_fmt)
            summary_ws.write(row, 1, "", section_fmt)
            row += 1
            summary_ws.write(row, 0, "Metric", header_fmt)
            summary_ws.write(row, 1, "Value", header_fmt)
            row += 1
            metric_rows = [
                ("Total Rows Exported", exported_rows),
                ("Total Rows Before Filter", total_before_filter),
                ("Unique Patients", patient_count),
                ("Unique Doctors", doctor_count),
                ("Unique Departments", department_count),
                ("Unique Packages", package_count),
                ("Unit Count", unit_count),
            ]
            for label, value in metric_rows:
                summary_ws.write(row, 0, label, text_fmt)
                summary_ws.write_number(row, 1, float(value), int_fmt)
                row += 1

            def _write_count_table(ws, start_row: int, title: str, frame: pd.DataFrame):
                col_span = 1
                if frame is not None and not frame.empty:
                    try:
                        col_span = max(1, len(list(frame.columns)) - 1)
                    except Exception:
                        col_span = 1
                ws.merge_range(start_row, 0, start_row, col_span, title, section_fmt)
                start_row += 1
                if frame is None or frame.empty:
                    ws.write(start_row, 0, "No data", text_fmt)
                    return start_row + 2
                headers = list(frame.columns)
                for c, h in enumerate(headers):
                    ws.write(start_row, c, h, header_fmt)
                start_row += 1
                for _, row_vals in frame.iterrows():
                    for c, h in enumerate(headers):
                        val = row_vals.get(h)
                        if str(h).strip().lower().endswith("count"):
                            try:
                                ws.write_number(start_row, c, float(val), int_fmt)
                            except Exception:
                                ws.write(start_row, c, val, text_fmt)
                        else:
                            ws.write(start_row, c, str(val), text_fmt)
                    start_row += 1
                return start_row + 1

            row += 1
            row = _write_count_table(summary_ws, row, "Unit-wise Count", unit_summary)
            row = _write_count_table(summary_ws, row, "Department-wise Count", dept_summary)
            row = _write_count_table(summary_ws, row, "Doctor-wise Count", doctor_summary)
            row = _write_count_table(summary_ws, row, "Package-wise Count", package_summary)

            summary_ws.set_column(0, 0, 32)
            summary_ws.set_column(1, 1, 20)
            summary_ws.set_column(2, 2, 16)
            summary_ws.set_column(3, 3, 22)
            summary_ws.set_column(4, 5, 28)
            summary_ws.set_footer(footer_text)
            summary_ws.set_landscape()
            summary_ws.fit_to_pages(1, 0)
            summary_ws.set_margins(left=0.25, right=0.25, top=0.4, bottom=0.4)

            # Keep row 5 for manual headers; data starts from row 6 (Excel row 7).
            details_export.to_excel(writer, sheet_name="Details", index=False, startrow=6, header=False)
            details_ws = writer.sheets["Details"]
            details_ws.hide_gridlines(2)
            details_ws.set_zoom(105)
            last_col = max(0, len(details_export.columns) - 1)
            details_ws.merge_range(0, 0, 0, last_col, "Volume Tracker - Healthcheckup Doctor Visit Details", title_fmt)
            details_ws.merge_range(1, 0, 1, last_col, f"Unit: {unit_scope} | Date Range: {f} to {t}", subtitle_fmt)
            details_ws.merge_range(2, 0, 2, last_col, f"Search: {search_query or '(none)'} | Mode: {export_mode}", subtitle_fmt)
            details_ws.merge_range(3, 0, 3, last_col, f"Exported By: {exported_by} | Exported At: {exported_at}", subtitle_fmt)
            details_ws.merge_range(4, 0, 4, last_col, "(c) ASARFI HOSPITAL", subtitle_fmt)

            for col_idx, col_name in enumerate(details_export.columns):
                details_ws.write(5, col_idx, col_name, header_fmt)
                if col_name in {"SL", "HCV ID", "Visit ID", "Package ID"}:
                    width = 10 if col_name != "Package ID" else 12
                elif col_name in {"Unit", "Reg No"}:
                    width = 14
                elif col_name == "Patient Name":
                    width = 28
                elif col_name in {"Corp Type", "Department", "Doctor"}:
                    width = 24
                elif col_name == "Visit Date":
                    width = 18
                elif col_name == "Visit No":
                    width = 16
                else:
                    width = 14
                # Width-only to avoid border bleed on empty rows.
                details_ws.set_column(col_idx, col_idx, width)

            data_start = 6
            data_end = data_start + len(details_export) - 1 if len(details_export) else data_start
            details_ws.autofilter(5, 0, max(data_end, 5), last_col)
            details_ws.freeze_panes(6, 0)

            # Apply border/alignment only on actual populated data cells.
            if len(details_export):
                for col_idx, col_name in enumerate(details_export.columns):
                    col_fmt = id_fmt if col_name in {"SL", "HCV ID", "Visit ID", "Package ID"} else text_fmt
                    details_ws.conditional_format(
                        data_start,
                        col_idx,
                        data_end,
                        col_idx,
                        {"type": "no_blanks", "format": col_fmt},
                    )

            details_ws.set_footer(footer_text)
            details_ws.set_landscape()
            details_ws.fit_to_pages(1, 0)
            details_ws.set_margins(left=0.25, right=0.25, top=0.4, bottom=0.4)

        output.seek(0)
        filename = f"Volume_HCV_Doctor_Visits_{unit_scope}_{f}_to_{t}.xlsx"
        return send_file(
            output,
            as_attachment=True,
            download_name=filename,
            mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        )
    except Exception as e:
        print(f"Volume HCV doctor export failed: {e}")
        return jsonify({"status": "error", "message": "Failed to export HCV doctor visits"}), 500

# Temporary storage for chart images (in-memory cache)
CHART_STORAGE = {}
CHART_STORAGE_LOCK = Lock()

def _volume_unit_label(unit: str) -> str:
    unit_val = (unit or "").strip().upper()
    if not unit_val or unit_val in {"__ALL__", "ALL"}:
        return "ALL"
    return unit_val

def _pop_volume_chart_data(token: str, username: str):
    if not token:
        return None
    with CHART_STORAGE_LOCK:
        stored = CHART_STORAGE.get(token)
        if stored:
            if (time.time() - stored.get('timestamp', 0) < 300 and
                stored.get('username') == username):
                chart_data = stored.get('charts', {})
                CHART_STORAGE.pop(token, None)
                return chart_data
    return None

@app.route('/api/volume_store_charts', methods=['POST'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def volume_store_charts():
    """Store chart images temporarily for PDF generation"""
    try:
        data = request.get_json()
        if not data:
            return jsonify({'status': 'error', 'message': 'No data received'}), 400
        
        # Generate unique token
        token = token_hex(16)
        
        # Store charts with timestamp (expire after 5 minutes)
        with CHART_STORAGE_LOCK:
            CHART_STORAGE[token] = {
                'charts': data,
                'timestamp': time.time(),
                'username': session.get('username')
            }
            
            # Clean up old entries (older than 5 minutes)
            current_time = time.time()
            expired = [k for k, v in CHART_STORAGE.items() 
                      if current_time - v.get('timestamp', 0) > 300]
            for k in expired:
                CHART_STORAGE.pop(k, None)
        
        return jsonify({'status': 'success', 'token': token})
        
    except Exception as e:
        print(f"Error storing charts: {e}")
        return jsonify({'status': 'error', 'message': str(e)}), 500


def _build_volume_pdf_buffer(from_date: str, to_date: str, unit: str, chart_data: dict | None, allowed_units: list[str]):
    """Build volume tracker PDF and return a buffer."""
    from reportlab.lib.pagesizes import A4
    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Image, Table, TableStyle, PageBreak, KeepTogether
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.units import inch
    from reportlab.lib import colors
    from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_RIGHT
    from io import BytesIO
    import base64
    from datetime import datetime
    import re
    from xml.sax.saxutils import escape as xml_escape

    unit = (unit or "__ALL__").strip().upper() or "__ALL__"
    cache_key = ("v4_pdf_table_wrap", from_date, to_date, unit, ",".join(sorted(allowed_units or [])))
    cached = _export_cache_get_bytes("volume_pdf", cache_key)
    if cached:
        return io.BytesIO(cached)

    if not chart_data:
        raise ValueError("Chart data expired or not found")
    if not allowed_units:
        raise ValueError("No unit access assigned")

    units_to_use = [unit] if (unit and unit != '__ALL__' and unit in allowed_units) else allowed_units

    # Fetch the data
    details_df = _get_or_fetch_volume_details(units_to_use, from_date, to_date)
    discharge_kpi = data_fetch.get_volume_discharge_kpi(units_to_use, from_date, to_date)

    # === BUILD EXCEL-STYLE SUMMARIES ===
    df = details_df.copy()

    # CRITICAL FIX: Ensure Unit column has actual values
    if "Unit" not in df.columns or df["Unit"].isna().all():
        # If single unit, use it; otherwise try to infer from data
        if len(units_to_use) == 1:
            df["Unit"] = units_to_use[0].upper()
        else:
            df["Unit"] = "ALL"
    else:
        df["Unit"] = df["Unit"].astype(str).str.strip().str.upper()
        # Replace empty strings with "ALL"
        df.loc[df["Unit"] == "", "Unit"] = "ALL"

    # Identify columns
    dep_candidates = ["Dept", "Dept_Name", "Department", "DeptName", "DepartmentName", "Dept Name"]
    dep_col = next((c for c in dep_candidates if c in df.columns), None) or "Dept"

    doc_candidates = ["Consultant", "Doctor", "DoctorIncharge", "DoctorInCharge", "DoctorName"]
    doc_col = next((c for c in doc_candidates if c in df.columns), None) or "Consultant"

    vt_col = "TypeOfVisit" if "TypeOfVisit" in df.columns else next((c for c in df.columns if "Visit" in c), "TypeOfVisit")
    if vt_col not in df.columns:
        df[vt_col] = ""

    pt_col = "PatientType" if "PatientType" in df.columns else "PatientType"
    if pt_col not in df.columns:
        df[pt_col] = ""

    corp_col = "CorpType" if "CorpType" in df.columns else ("PatSubType" if "PatSubType" in df.columns else "CorpType")
    if corp_col not in df.columns:
        df[corp_col] = ""

    if "City" not in df.columns:
        df["City"] = ""

    # Visit-friendly mapping
    def _visit_friendly_pdf(v):
        m = {"HCV": "Health Checkups", "DPV": "Diagnostic Visit",
             "IPD": "In Patient Visits", "OPD": "Out Patient Visits"}
        return m.get(str(v).strip(), str(v).strip())

    # Normalize text for grouping
    def _norm_text_pdf(s):
        t = str(s or "").strip().upper()
        t = re.sub(r"\s+", " ", t)
        return t

    # Normalized keys
    df["_VisitDisp"] = df[vt_col].astype(str).str.strip().apply(_visit_friendly_pdf)
    df["_DeptDisp"] = df[dep_col].fillna("").astype(str).str.strip()
    df["_DocDisp"] = df[doc_col].fillna("").astype(str).str.strip()

    # Normalize city names to prevent duplicates
    df["_CityNorm"] = df["City"].apply(_norm_text_pdf)
    df["_CityDisp"] = df["City"].fillna("").astype(str).str.strip().str.title()

    df["_PTDisp"] = df[pt_col].fillna("").astype(str).str.strip()
    df["_CorpDisp"] = df[corp_col].fillna("").astype(str).str.strip()

    # Build summaries
    visit_sum = (df.groupby(["Unit", "_VisitDisp"], dropna=False)
                   .size().reset_index(name="Count")
                   .rename(columns={"_VisitDisp": "Visit"}))
    visit_sum = visit_sum.sort_values(["Unit", "Count"], ascending=[True, False])

    dept_sum = (df.groupby(["Unit", "_DeptDisp"], dropna=False)
                  .size().reset_index(name="Count")
                  .rename(columns={"_DeptDisp": "Department"}))
    dept_sum = dept_sum.sort_values(["Unit", "Count"], ascending=[True, False])

    unit_dept_visit_sum = (df.groupby(["Unit", "_DeptDisp", "_VisitDisp"], dropna=False)
                             .size().reset_index(name="Count")
                             .rename(columns={"_DeptDisp": "Department", "_VisitDisp": "Visit Type"}))
    unit_dept_visit_sum = unit_dept_visit_sum.sort_values(["Unit", "Department", "Count"],
                                                           ascending=[True, True, False])

    doctor_sum = (df.groupby(["Unit", "_DocDisp"], dropna=False)
                    .size().reset_index(name="Count")
                    .rename(columns={"_DocDisp": "Doctor"}))
    doctor_sum = doctor_sum.sort_values(["Unit", "Count"], ascending=[True, False])

    # Group by normalized city to avoid duplicates, but display proper case
    city_sum = (df.groupby(["Unit", "_CityNorm", "_CityDisp"], dropna=False)
                  .size().reset_index(name="Count"))
    # Use the first occurrence of display name for each normalized city
    city_sum = (city_sum.groupby(["Unit", "_CityNorm"], as_index=False)
                 .agg({"_CityDisp": "first", "Count": "sum"}))
    city_sum = city_sum.rename(columns={"_CityDisp": "City"})[["Unit", "City", "Count"]]
    city_sum = city_sum.sort_values(["Unit", "Count"], ascending=[True, False])

    pt_ct_sum = (df.groupby(["Unit", "_PTDisp", "_CorpDisp"], dropna=False)
                   .size().reset_index(name="Count")
                   .rename(columns={"_PTDisp": "PatientType", "_CorpDisp": "CorpType"}))
    pt_ct_sum = pt_ct_sum.sort_values(["Unit", "PatientType", "Count"], ascending=[True, True, False])

    # Create PDF
    buffer = BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=A4,
        rightMargin=40,
        leftMargin=40,
        topMargin=50,
        bottomMargin=40
    )

    styles = getSampleStyleSheet()
    story = []

    # Custom styles
    title_style = ParagraphStyle(
        'CustomTitle',
        parent=styles['Heading1'],
        fontSize=22,
        textColor=colors.HexColor('#1e40af'),
        spaceAfter=8,
        alignment=TA_CENTER,
        fontName='Helvetica-Bold'
    )

    unit_style = ParagraphStyle(
        'UnitStyle',
        parent=styles['Heading2'],
        fontSize=16,
        textColor=colors.HexColor('#2563eb'),
        spaceAfter=6,
        alignment=TA_CENTER,
        fontName='Helvetica-Bold'
    )

    subtitle_style = ParagraphStyle(
        'Subtitle',
        parent=styles['Normal'],
        fontSize=11,
        textColor=colors.HexColor('#475569'),
        alignment=TA_CENTER,
        spaceAfter=6
    )

    meta_style = ParagraphStyle(
        'Meta',
        parent=styles['Normal'],
        fontSize=9,
        textColor=colors.HexColor('#64748b'),
        alignment=TA_CENTER,
        spaceAfter=12
    )

    section_style = ParagraphStyle(
        'Section',
        parent=styles['Heading3'],
        fontSize=13,
        textColor=colors.HexColor('#1e3a8a'),
        spaceAfter=6,
        backColor=colors.HexColor('#f1f5f9'),
        leftIndent=5,
        leading=16
    )

    # Title section
    story.append(Paragraph("Volume Tracker Summary Report", title_style))
    story.append(Paragraph(f"Period: {from_date} to {to_date}", subtitle_style))
    story.append(Paragraph(f"Units: {', '.join(units_to_use)}", meta_style))
    story.append(Spacer(1, 20))

    # Helper to create summary tables
    def create_summary_table(data_df, title, max_rows=None):
        if data_df is None or data_df.empty:
            return

        # Limit rows if specified
        if max_rows and len(data_df) > max_rows:
            display_df = data_df.head(max_rows).copy()
        else:
            display_df = data_df.copy()

        # Section title
        story.append(Paragraph(title, section_style))
        story.append(Spacer(1, 5))

        cols = [str(c) for c in list(display_df.columns)]
        num_cols = len(cols)
        is_wide = num_cols >= 7
        header_font = 8 if is_wide else 9
        cell_font = 7 if num_cols >= 9 else (8 if is_wide else 9)

        header_style = ParagraphStyle(
            "vt_pdf_header_cell",
            parent=styles["Normal"],
            fontName="Helvetica-Bold",
            fontSize=header_font,
            leading=header_font + 1,
            textColor=colors.white,
            alignment=TA_CENTER,
            wordWrap="CJK",
        )
        cell_left_style = ParagraphStyle(
            "vt_pdf_cell_left",
            parent=styles["Normal"],
            fontName="Helvetica",
            fontSize=cell_font,
            leading=cell_font + 1,
            textColor=colors.HexColor("#1f2937"),
            alignment=TA_LEFT,
            wordWrap="CJK",
        )
        cell_right_style = ParagraphStyle(
            "vt_pdf_cell_right",
            parent=cell_left_style,
            alignment=TA_RIGHT,
        )

        def _is_numeric_col(col_name: str, series: pd.Series) -> bool:
            c = str(col_name or "").strip().lower()
            if any(tok in c for tok in ("count", "%", "ratio", "total", "cases", "value")):
                return True
            s_num = pd.to_numeric(series, errors="coerce")
            if len(series) == 0:
                return False
            return bool(s_num.notna().mean() >= 0.85)

        numeric_col_idx = []
        for idx, col in enumerate(cols):
            try:
                if _is_numeric_col(col, display_df[col]):
                    numeric_col_idx.append(idx)
            except Exception:
                pass

        # Convert to wrapped table data (header + body)
        table_data = [[Paragraph(xml_escape(str(col)), header_style) for col in cols]]
        for _, row in display_df.iterrows():
            row_data = []
            for col_idx, col in enumerate(cols):
                val = row[col]
                if pd.isna(val):
                    txt = ""
                elif isinstance(val, (int, float, np.integer, np.floating)):
                    fval = float(val)
                    txt = f"{int(fval):,}" if fval.is_integer() else f"{fval:,.2f}".rstrip("0").rstrip(".")
                else:
                    txt = str(val)
                style = cell_right_style if col_idx in numeric_col_idx else cell_left_style
                row_data.append(Paragraph(xml_escape(txt), style))
            table_data.append(row_data)

        # Dynamic width allocation using full printable width
        available_width = float(doc.width)
        if num_cols <= 4:
            if num_cols == 2:
                col_widths = [available_width * 0.68, available_width * 0.32]
            elif num_cols == 3:
                col_widths = [available_width * 0.30, available_width * 0.45, available_width * 0.25]
            elif num_cols == 4:
                col_widths = [available_width * 0.20, available_width * 0.34, available_width * 0.28, available_width * 0.18]
            else:
                col_widths = [available_width]
        else:
            text_tokens = ("ward", "department", "doctor", "city", "patient", "discharge", "type", "metric", "corp")
            raw_weights = []
            sample_df = display_df.head(150)
            for idx, col in enumerate(cols):
                c_low = col.lower()
                try:
                    lens = sample_df[col].astype(str).map(len)
                    p85 = int(lens.quantile(0.85)) if not lens.empty else len(col)
                except Exception:
                    p85 = len(col)
                base = max(6, min(30, max(len(col), p85)))
                if idx in numeric_col_idx:
                    base *= 0.90
                elif any(tok in c_low for tok in text_tokens):
                    base *= 1.55
                raw_weights.append(base)
            total_wt = sum(raw_weights) or 1.0
            col_widths = [available_width * (w / total_wt) for w in raw_weights]

        min_w = 0.50 * inch if num_cols >= 8 else 0.62 * inch
        max_w = 2.30 * inch if num_cols <= 5 else 1.95 * inch
        col_widths = [max(min_w, min(max_w, w)) for w in col_widths]
        current_total = sum(col_widths)
        if current_total > available_width and current_total > 0:
            scale = available_width / current_total
            col_widths = [w * scale for w in col_widths]
        elif current_total < available_width and num_cols > 0:
            extra = (available_width - current_total)
            grow_idx = [i for i in range(num_cols) if i not in numeric_col_idx] or list(range(num_cols))
            step = extra / max(1, len(grow_idx))
            for i in grow_idx:
                col_widths[i] += step

        # Create table
        table = Table(table_data, colWidths=col_widths, repeatRows=1)
        header_pad = 5 if is_wide else 8
        body_vpad = 2 if is_wide else 4
        body_hpad = 3 if is_wide else 5
        table.setStyle(TableStyle([
            # Header styling
            ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#1e40af')),
            ('TEXTCOLOR', (0, 0), (-1, 0), colors.whitesmoke),
            ('ALIGN', (0, 0), (-1, 0), 'CENTER'),
            ('BOTTOMPADDING', (0, 0), (-1, 0), header_pad),
            ('TOPPADDING', (0, 0), (-1, 0), header_pad),

            # Data styling
            ('BACKGROUND', (0, 1), (-1, -1), colors.white),
            ('TEXTCOLOR', (0, 1), (-1, -1), colors.HexColor('#1f2937')),
            ('VALIGN', (0, 0), (-1, -1), 'TOP'),
            ('BOTTOMPADDING', (0, 1), (-1, -1), body_vpad),
            ('TOPPADDING', (0, 1), (-1, -1), body_vpad),
            ('LEFTPADDING', (0, 0), (-1, -1), body_hpad),
            ('RIGHTPADDING', (0, 0), (-1, -1), body_hpad),

            # Grid and alternating colors
            ('GRID', (0, 0), (-1, -1), 0.5, colors.HexColor('#e5e7eb')),
            ('ROWBACKGROUNDS', (0, 1), (-1, -1),
             [colors.white, colors.HexColor('#f8fafc')]),
        ]))

        story.append(table)

        # Add note if data was truncated
        if max_rows and len(data_df) > max_rows:
            story.append(Spacer(1, 4))
            story.append(Paragraph(
                f"<i>Showing top {max_rows} of {len(data_df)} entries</i>",
                ParagraphStyle('Note', parent=styles['Normal'],
                             fontSize=8, textColor=colors.HexColor('#64748b'))
            ))

        story.append(Spacer(1, 15))

    # === ADD ALL 6 SUMMARY SECTIONS ===

    # 1. Visit-wise
    create_summary_table(visit_sum, "1. Visit-wise Summary")

    # 2. Department-wise (limit to top 20)
    create_summary_table(dept_sum, "2. Department-wise Summary", max_rows=20)

    story.append(PageBreak())

    # 3. Unit - Department - Visit Type (limit to top 25)
    create_summary_table(unit_dept_visit_sum,
                       "3. Unit - Department - Visit Type Breakdown",
                       max_rows=25)

    story.append(PageBreak())

    # 4. Doctor-wise (limit to top 20)
    create_summary_table(doctor_sum, "4. Doctor-wise Summary", max_rows=20)

    story.append(PageBreak())

    # 5. City-wise (limit to top 20)
    create_summary_table(city_sum, "5. City-wise Summary", max_rows=20)

    story.append(PageBreak())

    # 6. PatientType - CorpType (limit to top 30)
    create_summary_table(pt_ct_sum, "6. PatientType - CorpType Breakdown", max_rows=30)

    # 7. Discharge KPI (IPD)
    overall_discharge = discharge_kpi.get("overall", {}) if isinstance(discharge_kpi, dict) else {}
    overall_discharge_total = int(overall_discharge.get("total_discharges") or 0)
    if overall_discharge_total > 0:
        discharge_overall_df = pd.DataFrame([
            {"Metric": "Total IPD Discharges", "Value": f"{overall_discharge_total:,}"},
            {"Metric": "Cured Cases", "Value": f"{int(overall_discharge.get('cured_cases') or 0):,}"},
            {"Metric": "Cured %", "Value": f"{float(overall_discharge.get('cured_percent') or 0.0):.2f}%"},
            {"Metric": "LAMA Cases", "Value": f"{int(overall_discharge.get('lama_cases') or 0):,}"},
            {"Metric": "LAMA %", "Value": f"{float(overall_discharge.get('lama_percent') or 0.0):.2f}%"},
            {"Metric": "Referred Cases", "Value": f"{int(overall_discharge.get('referred_cases') or 0):,}"},
            {"Metric": "Referred %", "Value": f"{float(overall_discharge.get('referred_percent') or 0.0):.2f}%"},
            {"Metric": "Mortality Cases", "Value": f"{int(overall_discharge.get('death_cases') or 0):,}"},
            {"Metric": "Mortality Ratio", "Value": f"{float(overall_discharge.get('mortality_ratio') or 0.0):.2f}%"},
        ])

        unit_discharge_rows = []
        for unit_row in (discharge_kpi.get("units") or []):
            unit_discharge_rows.append({
                "Unit": str(unit_row.get("unit") or ""),
                "Total Discharges": f"{int(unit_row.get('total_discharges') or 0):,}",
                "Cured Cases": f"{int(unit_row.get('cured_cases') or 0):,}",
                "Cured %": f"{float(unit_row.get('cured_percent') or 0.0):.2f}%",
                "LAMA Cases": f"{int(unit_row.get('lama_cases') or 0):,}",
                "LAMA %": f"{float(unit_row.get('lama_percent') or 0.0):.2f}%",
                "Referred Cases": f"{int(unit_row.get('referred_cases') or 0):,}",
                "Referred %": f"{float(unit_row.get('referred_percent') or 0.0):.2f}%",
                "Mortality Cases": f"{int(unit_row.get('death_cases') or 0):,}",
                "Mortality %": f"{float(unit_row.get('mortality_ratio') or 0.0):.2f}%",
            })
        discharge_units_df = pd.DataFrame(unit_discharge_rows)

        ward_type_rows = []
        for unit_row in (discharge_kpi.get("units") or []):
            unit_name = str(unit_row.get("unit") or "")
            for ward_row in (unit_row.get("ward_breakdown") or []):
                ward_name = str(ward_row.get("ward") or "")
                for type_row in (ward_row.get("type_breakdown") or []):
                    ward_type_rows.append({
                        "Unit": unit_name,
                        "Ward": ward_name,
                        "Discharge Type": str(type_row.get("discharge_type") or "Unknown"),
                        "Count": int(type_row.get("count") or 0),
                        "Cured": "Yes" if type_row.get("is_cured") else "No",
                        "LAMA": "Yes" if type_row.get("is_lama") else "No",
                        "Referred": "Yes" if type_row.get("is_referred") else "No",
                        "Mortality": "Yes" if type_row.get("is_mortality") else "No",
                    })
        discharge_ward_type_df = pd.DataFrame(ward_type_rows)
        if not discharge_ward_type_df.empty:
            discharge_ward_type_df = discharge_ward_type_df.sort_values(
                ["Count", "Unit", "Ward", "Discharge Type"],
                ascending=[False, True, True, True],
            )

        story.append(PageBreak())
        create_summary_table(discharge_overall_df, "7. IPD Discharge KPI Summary")
        create_summary_table(discharge_units_df, "7.1 Unit-wise Discharge KPI")
        create_summary_table(discharge_ward_type_df, "7.2 Ward - Discharge Type Breakdown", max_rows=45)

    story.append(PageBreak())

    # === CHARTS SECTION ===
    story.append(Paragraph("Visual Analytics",
                          ParagraphStyle('ChartSection', parent=section_style,
                                       fontSize=14, backColor=colors.HexColor('#dbeafe'))))
    story.append(Spacer(1, 15))

    def add_chart_with_mini_legend(title, img_base64, legend_data, width=5*inch, height=3.2*inch):
        """Add chart with compact legend"""
        story.append(Paragraph(title,
                             ParagraphStyle('ChartTitle', parent=styles['Heading4'],
                                          fontSize=11, textColor=colors.HexColor('#1e40af'),
                                          spaceAfter=6)))

        if img_base64 and img_base64.startswith('data:image'):
            try:
                img_data = img_base64.split(',')[1]
                img_bytes = base64.b64decode(img_data)
                img_buffer = BytesIO(img_bytes)
                img = Image(img_buffer, width=width, height=height)
                story.append(img)
                story.append(Spacer(1, 8))

                # Compact legend (top 10 only)
                if legend_data:
                    items = legend_data[:10]
                    legend_data_table = [[Paragraph(str(item.get('name', '')), styles['Normal']),
                                        Paragraph(f"{item.get('value', 0):,}", styles['Normal'])]
                                       for item in items]

                    if legend_data_table:
                        legend_table = Table(legend_data_table, colWidths=[3.5*inch, 1*inch])
                        legend_table.setStyle(TableStyle([
                            ('FONTSIZE', (0, 0), (-1, -1), 7),
                            ('TEXTCOLOR', (0, 0), (-1, -1), colors.HexColor('#475569')),
                            ('ALIGN', (1, 0), (1, -1), 'RIGHT'),
                            ('VALIGN', (0, 0), (-1, -1), 'TOP'),
                            ('GRID', (0, 0), (-1, -1), 0.25, colors.HexColor('#e5e7eb')),
                            ('BACKGROUND', (0, 0), (-1, -1), colors.HexColor('#fafafa'))
                        ]))
                        story.append(legend_table)

                    if len(legend_data) > 10:
                        story.append(Spacer(1, 3))
                        story.append(Paragraph(
                            f"<i>+ {len(legend_data) - 10} more entries</i>",
                            ParagraphStyle('MoreNote', parent=styles['Normal'],
                                         fontSize=7, textColor=colors.HexColor('#94a3b8'))
                        ))

                story.append(Spacer(1, 12))

            except Exception as e:
                print(f"Error adding chart: {e}")
                story.append(Paragraph("[Chart unavailable]", styles['Normal']))
                story.append(Spacer(1, 10))

    # Build payload for legend data
    payload = make_volume_payload(details_df)

    # Add charts
    add_chart_with_mini_legend("Visit-wise Volume Distribution",
                              chart_data.get('visitwise', ''),
                              payload.get('visitwise', []))

    add_chart_with_mini_legend("Department-wise Volume",
                              chart_data.get('deptwise', ''),
                              payload.get('deptwise', []))

    story.append(PageBreak())

    add_chart_with_mini_legend("Top Doctors by Volume",
                              chart_data.get('doctorwise', ''),
                              payload.get('doctorwise', []))

    add_chart_with_mini_legend("City-wise Patient Distribution",
                              chart_data.get('citywise', ''),
                              payload.get('citywise', []))

    story.append(PageBreak())

    # Patient type legend
    pt_data = payload.get('patienttype_patsubtype', [])
    pt_legend = []
    for pt in pt_data:
        pt_name = pt.get('name', '')
        children = pt.get('children', [])
        total = sum(c.get('value', 0) for c in children)
        pt_legend.append({'name': pt_name, 'value': total})

    add_chart_with_mini_legend("Patient Type Analysis",
                              chart_data.get('pt', ''),
                              pt_legend)

    # Footer
    story.append(Spacer(1, 30))
    footer_text = f"Generated: {datetime.now().strftime('%d %B %Y at %H:%M:%S')} | Asarfi Hospital Ltd"
    story.append(Paragraph(footer_text, subtitle_style))

    # Build PDF
    doc.build(story)
    buffer.seek(0)

    try:
        _export_cache_put_bytes("volume_pdf", buffer.getvalue(), cache_key)
    except Exception:
        pass
    return buffer


@app.route('/api/volume_export_pdf', methods=['GET'])
@login_required(allowed_roles={"IT", "Management", "Departmental Head"})
def volume_export_pdf():
    """Export volume tracker summary as PDF with charts and complete Excel summary data"""
    from_date = (request.args.get('from') or '').strip()
    to_date = (request.args.get('to') or '').strip()
    unit = (request.args.get('unit') or '__ALL__').strip()
    if not from_date or not to_date:
        return jsonify({'status': 'error', 'message': 'Missing date range'}), 400

    allowed_units = _analytics_allowed_units_for_session()
    if not allowed_units:
        return jsonify({'status': 'error', 'message': 'No unit access assigned'}), 403

    try:
        buffer = _build_volume_pdf_buffer(from_date, to_date, unit, None, allowed_units)
    except ValueError:
        token = (request.args.get('token') or '').strip()
        if not token:
            return jsonify({'status': 'error', 'message': 'Missing chart token'}), 400
        chart_data = _pop_volume_chart_data(token, session.get('username'))
        if not chart_data:
            return jsonify({'status': 'error', 'message': 'Chart data expired or not found'}), 404
        try:
            buffer = _build_volume_pdf_buffer(from_date, to_date, unit, chart_data, allowed_units)
        except Exception as e:
            print(f"PDF export error: {e}")
            import traceback
            traceback.print_exc()
            return jsonify({'status': 'error', 'message': str(e)}), 500
    except Exception as e:
        print(f"PDF export error: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({'status': 'error', 'message': str(e)}), 500

    filename = f"Volume_Summary_{_volume_unit_label(unit)}_{from_date}_to_{to_date}.pdf"
    return send_file(
        buffer,
        mimetype='application/pdf',
        as_attachment=True,
        download_name=filename
    )





